<#
.SYNOPSIS
  NetJump HUD -- unified WPF dashboard for ethernet diagnostics.

.DESCRIPTION
  One window, everything in it:
    * Big colored link-state indicator + session flap counter
    * 60-second live ping chart (gateway + Cloudflare)
    * Diagnostic findings panel (EEE/Green/Power Saving, driver age,
      event-log flap history, NDIS filters, DNS, services, ARP,
      recent updates, hosts tampering, proxy hijack, Defender status)
    * Live events stream -- every link state change, sustained ping
      loss, fix applied, or scan completion is timestamped and logged
      to the right-hand panel in real time
    * One-click "Apply recommended fixes" button with a confirmation
      dialog listing every command before it runs
    * "Save HTML report" button -- writes a timestamped HTML snapshot
      of the current findings to .\Reports\ and opens it in the browser

  Requires Administrator for the Apply-Fix button and a few checks.
  The Run-NetJump.bat launcher self-elevates and starts this directly.
#>

[CmdletBinding()]
param(
    [switch]$Headless,
    [switch]$Json,
    [switch]$DailyDigest,
    [switch]$Monitor
)

$ErrorActionPreference = 'SilentlyContinue'
$script:CliMode = [bool]($Headless -or $Json -or $DailyDigest -or $Monitor)

# WPF is loaded in both modes; CLI just never calls ShowDialog. Cheap and avoids gate spaghetti.
Add-Type -AssemblyName PresentationFramework,PresentationCore,WindowsBase,System.Xaml,System.Windows.Forms,System.Drawing,Microsoft.VisualBasic

# ---------- helpers ----------
function Test-Admin {
    $id = [Security.Principal.WindowsIdentity]::GetCurrent()
    (New-Object Security.Principal.WindowsPrincipal($id)).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
}
$script:IsAdmin = Test-Admin
$script:HasPktmon = [bool](Get-Command pktmon.exe -ErrorAction SilentlyContinue)

# tray icon for Windows toast notifications (GUI only).
# Tier 58: now also exposes a right-click context menu (Show / Scan / Pause / Mute / Quit) and a
# left-click handler that brings the main window forward. The menu items reference functions that
# may not yet exist when this code runs at script-startup, so each menu Click callback resolves
# its target lazily via `if (Get-Command -ErrorAction SilentlyContinue)` or via $window/$controls
# null checks.
if (-not $script:CliMode) {
    $script:TrayIcon = New-Object System.Windows.Forms.NotifyIcon
    $script:TrayIcon.Icon = [System.Drawing.SystemIcons]::Information
    $script:TrayIcon.Text = 'NetJump HUD'
    $script:TrayIcon.Visible = $true

    # Build the context menu (right-click on tray icon)
    $script:TrayMenu = New-Object System.Windows.Forms.ContextMenuStrip
    $script:TrayMenuShow      = $script:TrayMenu.Items.Add('Show NetJump HUD')
    $null = $script:TrayMenu.Items.Add('-')
    $script:TrayMenuScan      = $script:TrayMenu.Items.Add('Run diagnostic scan')
    $script:TrayMenuPause     = $script:TrayMenu.Items.Add('Pause LIVE EVENTS streaming')
    $script:TrayMenuMute      = $script:TrayMenu.Items.Add('Mute notifications')
    $null = $script:TrayMenu.Items.Add('-')
    $script:TrayMenuQuit      = $script:TrayMenu.Items.Add('Quit NetJump')
    $script:TrayIcon.ContextMenuStrip = $script:TrayMenu

    # Show NetJump: bring the window to the front (or restore if minimized to tray)
    $script:TrayMenuShow.Add_Click({
        try {
            if ($window) {
                if ($window.WindowState -eq 'Minimized') { $window.WindowState = 'Normal' }
                $null = $window.Show()
                $null = $window.Activate()
            }
        } catch {}
    })
    # Same action on left-click - matches Windows convention (e.g. Slack, Teams tray icons).
    $script:TrayIcon.Add_MouseClick({
        param($s, $e)
        if ($e.Button -eq [System.Windows.Forms.MouseButtons]::Left) {
            try {
                if ($window) {
                    if ($window.WindowState -eq 'Minimized') { $window.WindowState = 'Normal' }
                    $null = $window.Show()
                    $null = $window.Activate()
                }
            } catch {}
        }
    })
    # Run diagnostic scan - same as clicking the in-window Re-scan button
    $script:TrayMenuScan.Add_Click({
        try { if (Get-Command Update-Findings -ErrorAction SilentlyContinue) { Update-Findings } } catch {}
    })
    # Pause/Resume LIVE EVENTS - mirrors the in-window EventsPauseButton state
    $script:TrayMenuPause.Add_Click({
        try {
            if ($script:State) {
                $script:State.EventsPaused = -not $script:State.EventsPaused
                if ($script:TrayMenuPause) {
                    $script:TrayMenuPause.Text = if ($script:State.EventsPaused) {
                        'Resume LIVE EVENTS streaming'
                    } else {
                        'Pause LIVE EVENTS streaming'
                    }
                }
                # Sync the in-window button label too if it exists
                if ($controls -and $controls.EventsPauseButton) {
                    $controls.EventsPauseButton.Content = if ($script:State.EventsPaused) {
                        ([char]0x25B6) + ' Start'   # ▶ Start
                    } else {
                        ([char]0x23F8) + ' Stop'    # ⏸ Stop
                    }
                }
            }
        } catch {}
    })
    # Mute/Unmute notifications - persists via the existing Settings.NotificationsMuted flag
    $script:TrayMenuMute.Add_Click({
        try {
            if ($script:State -and $script:State.Settings) {
                $cur = [bool]$script:State.Settings.NotificationsMuted
                $script:State.Settings.NotificationsMuted = -not $cur
                Save-Settings $script:State.Settings
                if ($script:TrayMenuMute) {
                    $script:TrayMenuMute.Text = if ($script:State.Settings.NotificationsMuted) {
                        'Unmute notifications'
                    } else {
                        'Mute notifications'
                    }
                }
                # Sync the View > Notifications menu label if it exists
                if ($controls -and $controls.MenuMute) {
                    $controls.MenuMute.Header = if ($script:State.Settings.NotificationsMuted) {
                        'Notifications: OFF'
                    } else {
                        'Notifications: ON'
                    }
                }
            }
        } catch {}
    })
    # Quit - closes the main window which fires its Closed handler (saves session, ledger, settings)
    $script:TrayMenuQuit.Add_Click({
        try { if ($window) { $window.Close() } } catch {}
    })
}

function Show-Toast {
    param(
        [string]$Title,
        [string]$Message,
        [ValidateSet('Info','Warning','Error')] [string]$Icon = 'Info'
    )
    if ($script:CliMode -or -not $script:TrayIcon) { return }
    if ($script:State -and $script:State.Settings -and $script:State.Settings.NotificationsMuted) { return }
    $script:TrayIcon.Icon = switch ($Icon) {
        'Warning' { [System.Drawing.SystemIcons]::Warning }
        'Error'   { [System.Drawing.SystemIcons]::Error }
        default   { [System.Drawing.SystemIcons]::Information }
    }
    $tipIcon = switch ($Icon) {
        'Warning' { [System.Windows.Forms.ToolTipIcon]::Warning }
        'Error'   { [System.Windows.Forms.ToolTipIcon]::Error }
        default   { [System.Windows.Forms.ToolTipIcon]::Info }
    }
    $script:TrayIcon.BalloonTipTitle = $Title
    $script:TrayIcon.BalloonTipText  = $Message
    $script:TrayIcon.BalloonTipIcon  = $tipIcon
    $script:TrayIcon.ShowBalloonTip(6000)
}

function Get-PrimaryEthernet {
    $all = Get-NetAdapter | Where-Object {
        $_.HardwareInterface -and ($_.MediaType -eq '802.3' -or $_.PhysicalMediaType -match 'Ethernet|802.3')
    }
    $up = $all | Where-Object Status -eq 'Up' | Select-Object -First 1
    if ($up) { return $up }
    return $all | Select-Object -First 1
}

# Tier 73: Refresh-AdapterCombo re-queries Get-NetAdapter and rebinds the AdapterCombo's
# ItemsSource. CRITICAL: WPF ComboBox.SelectedItem matches by REFERENCE, not by value. Each call
# to Get-NetAdapter returns new CIM instances with different identity, so picking by
# Get-PrimaryEthernet then setting SelectedItem = $picked silently fails because $picked is not
# the same instance as anything in the combo's items collection. This function resolves the
# selection back to the actual ItemsSource instance by Name. Call it:
#   - On startup (replaces the inline populate logic)
#   - On DropDownOpened (so newly plugged NICs appear without restart, and unplugged ones drop)
# Returns the selected adapter object (the live one in the combo) or $null if no adapters found.
# -PreserveName lets a caller force-select a specific adapter by Name even if it's not the one
# the auto-pick logic would choose; mainly used by the SelectionChanged path to avoid losing
# the user's choice across a refresh.
function Refresh-AdapterCombo {
    [CmdletBinding()]
    param(
        [string]$PreserveName,
        [switch]$Quiet
    )
    if (-not $controls -or -not $controls.AdapterCombo) { return $null }
    try {
        $combo = $controls.AdapterCombo
        # remember which Name was selected so we restore by NAME (not by reference)
        $prevName = if ($PreserveName) { $PreserveName }
                    elseif ($combo.SelectedItem) { [string]$combo.SelectedItem.Name }
                    elseif ($script:State -and $script:State.Adapter) { [string]$script:State.Adapter.Name }
                    else { $null }
        $fresh = @(Get-NetAdapter | Where-Object { $_.HardwareInterface } | Sort-Object Name)
        # Diff-check: if the names+statuses match exactly, skip the rebind to avoid flicker.
        $rebind = $true
        if ($combo.ItemsSource) {
            $oldSig = (@($combo.ItemsSource | ForEach-Object { "{0}|{1}|{2}" -f $_.Name,$_.Status,$_.LinkSpeed }) -join '||')
            $newSig = (@($fresh             | ForEach-Object { "{0}|{1}|{2}" -f $_.Name,$_.Status,$_.LinkSpeed }) -join '||')
            if ($oldSig -eq $newSig) { $rebind = $false }
        }
        if ($rebind) { $combo.ItemsSource = $fresh }
        # find the right item in the (possibly new) ItemsSource by Name
        $match = $null
        if ($prevName) { $match = $fresh | Where-Object Name -eq $prevName | Select-Object -First 1 }
        if (-not $match) {
            $primary = Get-PrimaryEthernet
            if ($primary) { $match = $fresh | Where-Object Name -eq $primary.Name | Select-Object -First 1 }
        }
        if (-not $match -and $fresh.Count -gt 0) { $match = $fresh[0] }
        if ($match) {
            # only assign if different from current to avoid spurious SelectionChanged events
            if (-not $combo.SelectedItem -or $combo.SelectedItem.Name -ne $match.Name -or $rebind) {
                $combo.SelectedItem = $match
            }
            if ($script:State) { $script:State.Adapter = $match }
            if (-not $Quiet -and $rebind) {
                try { Add-Event info ("Adapter list refreshed: {0} adapters, selected '{1}'" -f $fresh.Count, $match.Name) } catch {}
            }
        } else {
            if (-not $Quiet) { try { Add-Event warn 'Adapter list refresh: no hardware adapters found' } catch {} }
        }
        return $match
    } catch {
        if (-not $Quiet) { try { Add-Event warn ("Refresh-AdapterCombo failed: $($_.Exception.Message)") } catch {} }
        return $null
    }
}

function Get-DefaultGateway {
    (Get-NetRoute -DestinationPrefix '0.0.0.0/0' -ErrorAction SilentlyContinue |
        Sort-Object RouteMetric | Select-Object -First 1).NextHop
}

# Fast NIC status via .NET NetworkInterface API (no CIM/WMI overhead, ~5ms vs 30-150ms)
function Get-FastNicStatus {
    param([string]$Name)
    if (-not $Name) { return $null }
    $all = [System.Net.NetworkInformation.NetworkInterface]::GetAllNetworkInterfaces()
    $nic = $all | Where-Object { $_.Name -eq $Name } | Select-Object -First 1
    if (-not $nic) { return $null }
    $bps = [int64]$nic.Speed
    $linkSpeed = if ($bps -ge 1000000000) { ("{0:N0} Gbps" -f ($bps / 1000000000)) }
                 elseif ($bps -ge 1000000) { ("{0:N0} Mbps" -f ($bps / 1000000)) }
                 elseif ($bps -gt 0)        { ("{0} bps" -f $bps) }
                 else                       { '--' }
    $statusStr = switch ($nic.OperationalStatus) {
        'Up' { 'Up' }
        'Down' { 'Disconnected' }
        default { [string]$nic.OperationalStatus }
    }
    [pscustomobject]@{
        Name      = $nic.Name
        Status    = $statusStr
        Speed     = $bps
        LinkSpeed = $linkSpeed
        Stats     = $nic.GetIPv4Statistics()
        Raw       = $nic
    }
}

