function Get-VendorFromMac {
    param([string]$Mac)
    if (-not $Mac) { return $null }
    $oui = ($Mac -replace ':','-' -replace '\.','-').Substring(0, 8).ToUpper()
    if ($script:OuiTable.ContainsKey($oui)) { return $script:OuiTable[$oui] }
    return $null
}

