# Pre-compute integer ranges once
$script:GeoRanges = @(
    foreach ($p in $script:GeoPrefixes) {
        $parts = $p.N.Split('.')
        $base = ([uint32]$parts[0] -shl 24) -bor ([uint32]$parts[1] -shl 16) -bor ([uint32]$parts[2] -shl 8) -bor [uint32]$parts[3]
        $size = if ($p.B -eq 0) { [uint32]::MaxValue } else { [uint32]([Math]::Pow(2, 32 - $p.B)) - 1 }
        @{ Lo = $base; Hi = ($base + $size); L = $p.L }
    }
)
$script:IpLabelCache = @{}

function Get-IpLabel {
    param([string]$Ip)
    if (-not $Ip) { return $null }
    if ($script:IpLabelCache.ContainsKey($Ip)) { return $script:IpLabelCache[$Ip] }
    if ($Ip -notmatch '^(\d+)\.(\d+)\.(\d+)\.(\d+)$') { $script:IpLabelCache[$Ip] = $null; return $null }
    $u = ([uint32]$matches[1] -shl 24) -bor ([uint32]$matches[2] -shl 16) -bor ([uint32]$matches[3] -shl 8) -bor [uint32]$matches[4]
    foreach ($r in $script:GeoRanges) {
        if ($u -ge $r.Lo -and $u -le $r.Hi) {
            $script:IpLabelCache[$Ip] = $r.L
            return $r.L
        }
    }
    # Fall back to the DB-IP Lite country DB when no cloud/CDN cluster matches. Returns just the
    # ISO country code (e.g. "DE", "NL"); cached so subsequent lookups for the same IP are O(1).
    try {
        $cc = Get-IpCountry $Ip
        if ($cc) {
            $script:IpLabelCache[$Ip] = $cc
            return $cc
        }
    } catch {}
    $script:IpLabelCache[$Ip] = $null
    return $null
}

# ---------- Tier 18: threat-intel feed importer ----------
# OPT-IN. Downloads small, free, well-known IP blocklists and cross-references
# them against the connection ledger and active process remotes.
$script:ThreatIntelDir   = Join-Path $PSScriptRoot 'Reports\ThreatIntel'
$script:ThreatIntelCache = Join-Path $script:ThreatIntelDir 'cache.json'
$script:ThreatIntelTtlHours = 24
$script:ThreatIntelRanges  = @()    # IPv4 CIDR ranges: array of @{Lo(uint32);Hi(uint32);Source;Cidr}
$script:ThreatIntelHashSet = @{}    # IPv4 IP-string -> source (for IP-only feeds, fast lookup)
# IPv6 parallel structures. Lo/Hi are System.Numerics.BigInteger (128 bits). Empty by default until
# a feed with IPv6 entries is parsed. Sample-Flows already enumerates v6 via Get-NetTCPConnection,
# so once these get populated the lookup just works.
$script:ThreatIntelRangesV6  = @()
$script:ThreatIntelHashSetV6 = @{}
if (-not (Test-Path $script:ThreatIntelDir)) { New-Item -ItemType Directory -Path $script:ThreatIntelDir -Force | Out-Null }

# Default feeds. Both are FREE, public, frequently-refreshed.
$script:ThreatIntelFeedsDefault = @(
    @{ Name='FireHOL Level1'; Url='https://iplists.firehol.org/files/firehol_level1.netset'; Type='netset' }
    @{ Name='Feodo Tracker';  Url='https://feodotracker.abuse.ch/downloads/ipblocklist.txt'; Type='iplist' }
)
# Active list - mutated by the feeds dialog. Reset from settings at init.
$script:ThreatIntelFeeds = @($script:ThreatIntelFeedsDefault | ForEach-Object { @{ Name=$_.Name; Url=$_.Url; Type=$_.Type; Enabled=$true } })

function Load-ThreatFeedsFromSettings {
    # Reads settings.ThreatIntelFeedList (array of {Name,Url,Type,Enabled}) and stamps $script:ThreatIntelFeeds.
    # If settings has no list, keeps the hardcoded defaults.
    if (-not $script:State -or -not $script:State.Settings) { return }
    $arr = $script:State.Settings.ThreatIntelFeedList
    if (-not $arr -or @($arr).Count -eq 0) { return }
    $list = @()
    foreach ($e in $arr) {
        $name = [string]$e.Name; $url = [string]$e.Url
        if (-not $name -or -not $url) { continue }
        $type = if ($e.Type) { [string]$e.Type } else { 'auto' }
        $enabled = if ($null -ne $e.Enabled) { [bool]$e.Enabled } else { $true }
        $list += @{ Name=$name; Url=$url; Type=$type; Enabled=$enabled }
    }
    if ($list.Count -gt 0) { $script:ThreatIntelFeeds = $list }
}

function Save-ThreatFeedsToSettings {
    if (-not $script:State.Settings) { return }
    $arr = @(
        $script:ThreatIntelFeeds | ForEach-Object {
            [pscustomobject]@{ Name=$_.Name; Url=$_.Url; Type=$_.Type; Enabled=[bool]$_.Enabled }
        }
    )
    $script:State.Settings | Add-Member -NotePropertyName ThreatIntelFeedList -NotePropertyValue $arr -Force
    Save-Settings $script:State.Settings
}

function Get-EnabledThreatFeeds {
    return @($script:ThreatIntelFeeds | Where-Object { $_.Enabled -ne $false })
}

function _IpToUInt32 { param([string]$Ip)
    if ($Ip -notmatch '^(\d+)\.(\d+)\.(\d+)\.(\d+)$') { return $null }
    return ([uint32]$matches[1] -shl 24) -bor ([uint32]$matches[2] -shl 16) -bor ([uint32]$matches[3] -shl 8) -bor [uint32]$matches[4]
}

# IPv6 -> BigInteger. IPv6 is 16 bytes big-endian; BigInteger ctor wants little-endian + sign byte.
# We reverse the bytes and append a zero to guarantee a positive value, then construct BigInteger.
function _IpV6BytesToBigInt {
    param([byte[]]$Bytes)
    if (-not $Bytes -or $Bytes.Length -ne 16) { return $null }
    $rev = [byte[]]::new(17)
    for ($i = 0; $i -lt 16; $i++) { $rev[$i] = $Bytes[15 - $i] }
    $rev[16] = 0
    return [System.Numerics.BigInteger]::new($rev)
}

# Try to parse a string as either IPv4 or IPv6. Returns @{Family='v4'|'v6';Address=System.Net.IPAddress;Canonical=string}
# or $null on failure. Uses .NET's IPAddress.TryParse so weird-but-valid forms (`::ffff:1.2.3.4`,
# `2001:db8::1`, etc.) are normalized to a canonical string we can use as a hashtable key.
function _ParseIpAny {
    param([string]$Ip)
    if (-not $Ip) { return $null }
    $parsed = [System.Net.IPAddress]::None
    if (-not [System.Net.IPAddress]::TryParse($Ip, [ref]$parsed)) { return $null }
    $fam = if ($parsed.AddressFamily -eq [System.Net.Sockets.AddressFamily]::InterNetwork) { 'v4' } else { 'v6' }
    return @{ Family = $fam; Address = $parsed; Canonical = $parsed.ToString() }
}

function Load-ThreatIntel {
    $script:ThreatIntelRanges    = @()
    $script:ThreatIntelHashSet   = @{}
    $script:ThreatIntelRangesV6  = @()
    $script:ThreatIntelHashSetV6 = @{}
    if (-not (Test-Path $script:ThreatIntelCache)) { return $false }
    try {
        $obj = Get-Content $script:ThreatIntelCache -Raw | ConvertFrom-Json
        if ($obj.timestamp) {
            $age = (Get-Date) - [datetime]$obj.timestamp
            if ($age.TotalHours -gt ($script:ThreatIntelTtlHours * 3)) { return $false }   # too stale
        }
        if ($obj.ranges) {
            $script:ThreatIntelRanges = @($obj.ranges | ForEach-Object { @{Lo=[uint32]$_.Lo; Hi=[uint32]$_.Hi; Source=[string]$_.Source; Cidr=[string]$_.Cidr} })
        }
        if ($obj.ips) {
            foreach ($e in $obj.ips) { $script:ThreatIntelHashSet[[string]$e.Ip] = [string]$e.Source }
        }
        # IPv6 ranges - Lo/Hi serialized as decimal strings (BigInteger doesn't JSON-serialize cleanly).
        if ($obj.rangesV6) {
            $script:ThreatIntelRangesV6 = @($obj.rangesV6 | ForEach-Object {
                @{
                    Lo     = [System.Numerics.BigInteger]::Parse([string]$_.Lo)
                    Hi     = [System.Numerics.BigInteger]::Parse([string]$_.Hi)
                    Source = [string]$_.Source
                    Cidr   = [string]$_.Cidr
                }
            })
        }
        if ($obj.ipsV6) {
            foreach ($e in $obj.ipsV6) { $script:ThreatIntelHashSetV6[[string]$e.Ip] = [string]$e.Source }
        }
        return $true
    } catch { return $false }
}

function Save-ThreatIntel {
    try {
        $obj = [pscustomobject]@{
            timestamp = (Get-Date).ToString('o')
            ranges    = @($script:ThreatIntelRanges | ForEach-Object { [pscustomobject]@{Lo=$_.Lo; Hi=$_.Hi; Source=$_.Source; Cidr=$_.Cidr} })
            ips       = @($script:ThreatIntelHashSet.GetEnumerator() | ForEach-Object { [pscustomobject]@{Ip=$_.Key; Source=$_.Value} })
            rangesV6  = @($script:ThreatIntelRangesV6 | ForEach-Object { [pscustomobject]@{Lo=$_.Lo.ToString(); Hi=$_.Hi.ToString(); Source=$_.Source; Cidr=$_.Cidr} })
            ipsV6     = @($script:ThreatIntelHashSetV6.GetEnumerator() | ForEach-Object { [pscustomobject]@{Ip=$_.Key; Source=$_.Value} })
            sourceCount = ($script:ThreatIntelFeeds | Measure-Object).Count
        }
        $obj | ConvertTo-Json -Depth 6 | Set-Content $script:ThreatIntelCache -Encoding UTF8
    } catch {
        # Tier 50: cache write failure (disk full, ACL, locked file) shouldn't be silent - the next
        # launch will re-fetch all feeds wasting bandwidth without any explanation.
        try { Add-Event warn ("Threat-intel cache write failed: {0}" -f $_.Exception.Message) } catch {}
    }
}

function Update-ThreatIntel {
    # Runs asynchronously via Start-Job to avoid blocking UI; feeds list passed in.
    if ($script:State.ThreatIntelJob) {
        Add-Event scan 'Threat-intel update already in progress.'
        return
    }
    $enabled = Get-EnabledThreatFeeds
    if ($enabled.Count -eq 0) {
        Add-Event warn 'Threat-intel: no enabled feeds. Open Settings -> Manage feeds... to add one.'
        return
    }
    Add-Event scan ("Threat-intel: refreshing {0} feed(s)..." -f $enabled.Count)
    $script:State.ThreatIntelJob = Start-Job -Name 'NetJump-ThreatIntel' -ScriptBlock {
        param($Feeds)
        function _Parse-CidrV4 { param([string]$Cidr)
            $parts = $Cidr -split '/'
            if ($parts.Count -ne 2) { return $null }
            $ip = $parts[0]
            if ($ip -notmatch '^(\d+)\.(\d+)\.(\d+)\.(\d+)$') { return $null }
            $base = ([uint32]$matches[1] -shl 24) -bor ([uint32]$matches[2] -shl 16) -bor ([uint32]$matches[3] -shl 8) -bor [uint32]$matches[4]
            $bits = [int]$parts[1]
            $size = if ($bits -le 0) { [uint32]::MaxValue } elseif ($bits -ge 32) { [uint32]0 } else { [uint32]([Math]::Pow(2, 32 - $bits)) - 1 }
            return @{ Lo = $base; Hi = ($base + $size); Cidr = $Cidr }
        }
        # IPv6 CIDR -> (Lo, Hi) as decimal strings (BigInteger doesn't round-trip cleanly across job
        # boundaries; strings are universal). Outer Tick poller calls BigInteger.Parse on these.
        function _V6BytesToBigStr { param([byte[]]$Bytes)
            $rev = [byte[]]::new(17)
            for ($i = 0; $i -lt 16; $i++) { $rev[$i] = $Bytes[15 - $i] }
            $rev[16] = 0
            return ([System.Numerics.BigInteger]::new($rev)).ToString()
        }
        function _Parse-CidrV6 { param([string]$Cidr)
            $parts = $Cidr -split '/'
            if ($parts.Count -ne 2) { return $null }
            $addr = [System.Net.IPAddress]::None
            if (-not [System.Net.IPAddress]::TryParse($parts[0], [ref]$addr)) { return $null }
            if ($addr.AddressFamily -ne [System.Net.Sockets.AddressFamily]::InterNetworkV6) { return $null }
            $bits = 0
            if (-not [int]::TryParse($parts[1], [ref]$bits) -or $bits -lt 0 -or $bits -gt 128) { return $null }
            $b = $addr.GetAddressBytes()   # 16 bytes big-endian
            $loBytes = [byte[]]::new(16); $hiBytes = [byte[]]::new(16)
            for ($i = 0; $i -lt 16; $i++) {
                $byteBits = [Math]::Max(0, [Math]::Min(8, $bits - $i * 8))
                if ($byteBits -eq 8) {
                    $loBytes[$i] = $b[$i]; $hiBytes[$i] = $b[$i]
                } elseif ($byteBits -eq 0) {
                    $loBytes[$i] = 0; $hiBytes[$i] = 255
                } else {
                    $maskInt = (-bnot ((1 -shl (8 - $byteBits)) - 1)) -band 255
                    $loBytes[$i] = [byte]($b[$i] -band $maskInt)
                    $hiBytes[$i] = [byte]($loBytes[$i] -bor (255 -bxor $maskInt))
                }
            }
            return @{ Lo = (_V6BytesToBigStr $loBytes); Hi = (_V6BytesToBigStr $hiBytes); Cidr = $Cidr }
        }
        $ranges   = @()
        $ips      = @{}
        $rangesV6 = @()
        $ipsV6    = @{}
        foreach ($feed in $Feeds) {
            try {
                $r = Invoke-WebRequest -Uri $feed.Url -TimeoutSec 30 -UseBasicParsing
                $lines = $r.Content -split "`r?`n" | Where-Object { $_ -and ($_.Trim() -ne '') -and $_ -notmatch '^\s*#' -and $_ -notmatch '^\s*//' }
                $cnt = 0
                foreach ($l in $lines) {
                    $l = $l.Trim()
                    if ($l -match '^(\d+\.\d+\.\d+\.\d+)/(\d+)') {
                        $cidr = "$($matches[1])/$($matches[2])"
                        $rng = _Parse-CidrV4 $cidr
                        if ($rng) { $ranges += @{ Lo=$rng.Lo; Hi=$rng.Hi; Source=$feed.Name; Cidr=$cidr }; $cnt++ }
                    } elseif ($l -match '^(\d+\.\d+\.\d+\.\d+)$') {
                        $ips[$matches[1]] = $feed.Name
                        $cnt++
                    } elseif ($l -match ':' -and $l -match '^[0-9a-fA-F:/.]+(/\d+)?$') {
                        # IPv6 line - CIDR or bare address. Defer to .NET TryParse for validation.
                        if ($l -match '^([0-9a-fA-F:.]+)/(\d{1,3})$') {
                            $rng = _Parse-CidrV6 $l
                            if ($rng) { $rangesV6 += @{ Lo=$rng.Lo; Hi=$rng.Hi; Source=$feed.Name; Cidr=$l }; $cnt++ }
                        } else {
                            $addr = [System.Net.IPAddress]::None
                            if ([System.Net.IPAddress]::TryParse($l, [ref]$addr) -and $addr.AddressFamily -eq [System.Net.Sockets.AddressFamily]::InterNetworkV6) {
                                $ipsV6[$addr.ToString()] = $feed.Name
                                $cnt++
                            }
                        }
                    }
                }
                Write-Output @{ Feed=$feed.Name; Count=$cnt; Status='ok' }
            } catch {
                Write-Output @{ Feed=$feed.Name; Count=0; Status='fail'; Error="$_" }
            }
        }
        return @{ Ranges = $ranges; Ips = $ips; RangesV6 = $rangesV6; IpsV6 = $ipsV6 }
    } -ArgumentList (,$enabled)
}

function Test-ThreatFeedReachable {
    # Quick HTTP probe against a feed URL. Returns @{Ok;Status;Latency;Bytes;Error;Sample}.
    param([string]$Url)
    $result = @{ Ok=$false; Status=0; Latency=0; Bytes=0; Error=$null; Sample=$null }
    if (-not $Url) { $result.Error = 'empty url'; return $result }
    $sw = [System.Diagnostics.Stopwatch]::StartNew()
    try {
        $resp = Invoke-WebRequest -Uri $Url -TimeoutSec 8 -UseBasicParsing -ErrorAction Stop
        $sw.Stop()
        $result.Ok      = $true
        $result.Status  = [int]$resp.StatusCode
        $result.Latency = [int]$sw.ElapsedMilliseconds
        $result.Bytes   = if ($resp.RawContentLength) { [long]$resp.RawContentLength } else { ([string]$resp.Content).Length }
        # extract a small sample of parseable lines so the user can see it really is a blocklist
        $sample = ($resp.Content -split "`r?`n" | Where-Object { $_ -and $_ -notmatch '^\s*#' -and $_.Trim() } | Select-Object -First 3) -join "`n"
        $result.Sample = $sample
    } catch {
        $sw.Stop()
        $result.Latency = [int]$sw.ElapsedMilliseconds
        $result.Error   = "$_"
    }
    return $result
}

# ---------- GeoIP (DB-IP Lite Country) ----------
# Source: https://download.db-ip.com/free/dbip-country-lite-YYYY-MM.csv.gz (no auth, monthly).
# Replaces the hardcoded $script:CountryCoords 40-entry table for actual country attribution.
# IPv4 only for now; v6 lookup falls through to $null gracefully.
$script:GeoIpDbPath        = Join-Path $script:ThreatIntelDir 'geoip-country.csv'
$script:GeoIpFeedUrlFormat = 'https://download.db-ip.com/free/dbip-country-lite-{0}.csv.gz'
$script:GeoIpTtlHours      = 720    # 30-day refresh; the data only changes meaningfully each month.
$script:GeoIpRangesV4      = $null  # array of [pscustomobject]@{Lo;Hi;CC} sorted by Lo
$script:GeoIpLoaded        = $false
$script:GeoIpLastRefresh   = $null

function Load-GeoIpDatabase {
    $script:GeoIpRangesV4 = $null
    $script:GeoIpLoaded   = $false
    if (-not (Test-Path $script:GeoIpDbPath)) { return $false }
    try {
        $age = (Get-Date) - (Get-Item $script:GeoIpDbPath).LastWriteTime
        # Allow up to 2x TTL before discarding - 60-day-old country data is still mostly accurate.
        if ($age.TotalHours -gt ($script:GeoIpTtlHours * 2)) { return $false }
        $script:GeoIpLastRefresh = (Get-Item $script:GeoIpDbPath).LastWriteTime
        $v4 = New-Object System.Collections.Generic.List[psobject]
        $reader = [System.IO.File]::OpenText($script:GeoIpDbPath)
        try {
            while ($null -ne ($line = $reader.ReadLine())) {
                if (-not $line) { continue }
                # CSV format: start_ip,end_ip,country_code (DB-IP Lite). No header, no quoting.
                # IPv6 rows have ':' in the addresses - skip them (v6 lookup falls through to null).
                if ($line.IndexOf(':') -ge 0) { continue }
                $parts = $line -split ','
                if ($parts.Count -lt 3) { continue }
                $s = $parts[0]; $e = $parts[1]; $cc = $parts[2].Trim()
                if ($s -notmatch '^(\d+)\.(\d+)\.(\d+)\.(\d+)$') { continue }
                $lo = ([uint32]$matches[1] -shl 24) -bor ([uint32]$matches[2] -shl 16) -bor ([uint32]$matches[3] -shl 8) -bor [uint32]$matches[4]
                if ($e -notmatch '^(\d+)\.(\d+)\.(\d+)\.(\d+)$') { continue }
                $hi = ([uint32]$matches[1] -shl 24) -bor ([uint32]$matches[2] -shl 16) -bor ([uint32]$matches[3] -shl 8) -bor [uint32]$matches[4]
                $v4.Add([pscustomobject]@{ Lo=$lo; Hi=$hi; CC=$cc })
            }
        } finally { $reader.Close() }
        # DB-IP Lite is already sorted by start_ip; sort again defensively (cheap on already-sorted).
        $script:GeoIpRangesV4 = @($v4 | Sort-Object Lo)
        $script:GeoIpLoaded = $true
        return $true
    } catch {
        try { Add-Event warn ("GeoIP load failed: $($_.Exception.Message)") } catch {}
        return $false
    }
}

function Update-GeoIpDatabase {
    # Async fetch via Start-Job. Decompresses inline to the destination CSV.
    if ($script:State -and $script:State.GeoIpJob) {
        Add-Event scan 'GeoIP database update already in progress.'
        return
    }
    $now = Get-Date
    $month1 = $now.ToString('yyyy-MM')
    $month2 = $now.AddMonths(-1).ToString('yyyy-MM')
    Add-Event scan ("GeoIP: fetching db-ip.com country-lite ({0})..." -f $month1)
    $url1 = $script:GeoIpFeedUrlFormat -f $month1
    $url2 = $script:GeoIpFeedUrlFormat -f $month2
    $dest = $script:GeoIpDbPath
    $job = Start-Job -Name 'NetJump-GeoIp' -ScriptBlock {
        param($Url1, $Url2, $Dest)
        $tmp = "$Dest.gz"
        try {
            try { Invoke-WebRequest -Uri $Url1 -OutFile $tmp -TimeoutSec 180 -UseBasicParsing -ErrorAction Stop }
            catch { Invoke-WebRequest -Uri $Url2 -OutFile $tmp -TimeoutSec 180 -UseBasicParsing -ErrorAction Stop }
            $inF  = [System.IO.File]::OpenRead($tmp)
            $gz   = New-Object System.IO.Compression.GZipStream($inF, [System.IO.Compression.CompressionMode]::Decompress)
            $outF = [System.IO.File]::Create($Dest)
            $gz.CopyTo($outF)
            $outF.Close(); $gz.Close(); $inF.Close()
            Remove-Item $tmp -Force -ErrorAction SilentlyContinue
            return @{ Ok=$true; SizeKB = [int]((Get-Item $Dest).Length / 1024) }
        } catch {
            try { Remove-Item $tmp -Force -ErrorAction SilentlyContinue } catch {}
            return @{ Ok=$false; Error="$_" }
        }
    } -ArgumentList $url1, $url2, $dest
    if ($script:State) { $script:State.GeoIpJob = $job }
}

function Get-IpCountry {
    param([string]$Ip)
    if (-not $Ip -or -not $script:GeoIpLoaded -or -not $script:GeoIpRangesV4) { return $null }
    if ($Ip -notmatch '^(\d+)\.(\d+)\.(\d+)\.(\d+)$') { return $null }
    $u = ([uint32]$matches[1] -shl 24) -bor ([uint32]$matches[2] -shl 16) -bor ([uint32]$matches[3] -shl 8) -bor [uint32]$matches[4]
    # Binary search: find the range where Lo <= u <= Hi.
    $lo = 0
    $hi = $script:GeoIpRangesV4.Count - 1
    while ($lo -le $hi) {
        $mid = [int](($lo + $hi) / 2)
        $r = $script:GeoIpRangesV4[$mid]
        if ($u -lt $r.Lo)      { $hi = $mid - 1 }
        elseif ($u -gt $r.Hi)  { $lo = $mid + 1 }
        else                   { return $r.CC }
    }
    return $null
}

function Test-IpThreat {
    param([string]$Ip)
    if (-not $Ip) { return $null }
    # Fast path: exact string match against either hashset (cheap, no parse).
    if ($script:ThreatIntelHashSet.ContainsKey($Ip)) { return $script:ThreatIntelHashSet[$Ip] }
    if ($script:ThreatIntelHashSetV6 -and $script:ThreatIntelHashSetV6.ContainsKey($Ip)) { return $script:ThreatIntelHashSetV6[$Ip] }
    # Parse to determine family - small extra cost but handles the IPv6 case correctly.
    $info = _ParseIpAny $Ip
    if (-not $info) { return $null }
    if ($info.Family -eq 'v4') {
        if ($script:ThreatIntelRanges.Count -eq 0) { return $null }
        $u = _IpToUInt32 $Ip
        if ($null -eq $u) { return $null }
        foreach ($r in $script:ThreatIntelRanges) {
            if ($u -ge $r.Lo -and $u -le $r.Hi) { return $r.Source }
        }
        return $null
    }
    # IPv6 path - canonical form key + BigInteger range check.
    if (-not $script:ThreatIntelHashSetV6) { $script:ThreatIntelHashSetV6 = @{} }
    if ($script:ThreatIntelHashSetV6.ContainsKey($info.Canonical)) { return $script:ThreatIntelHashSetV6[$info.Canonical] }
    if (-not $script:ThreatIntelRangesV6 -or $script:ThreatIntelRangesV6.Count -eq 0) { return $null }
    $b = _IpV6BytesToBigInt ($info.Address.GetAddressBytes())
    if ($null -eq $b) { return $null }
    foreach ($r in $script:ThreatIntelRangesV6) {
        if ($b -ge $r.Lo -and $b -le $r.Hi) { return $r.Source }
    }
    return $null
}

# ---------- Tier 11: Action audit log + action helpers ----------
$script:ActionsDir = Join-Path $PSScriptRoot 'Reports\Actions'
if (-not (Test-Path $script:ActionsDir)) { New-Item -ItemType Directory -Path $script:ActionsDir -Force | Out-Null }

function Write-ActionAudit {
    param($Action, $Target, $Result, $Details = $null)
    $entry = [ordered]@{
        timestamp = (Get-Date).ToString('o')
        hostName  = $env:COMPUTERNAME
        action    = $Action
        target    = $Target
        result    = $Result
        details   = $Details
    }
    try {
        $stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
        $path = Join-Path $script:ActionsDir ("action-{0}-{1}.json" -f $stamp, [guid]::NewGuid().ToString().Substring(0,8))
        $entry | ConvertTo-Json -Depth 5 | Set-Content $path -Encoding UTF8
    } catch {
        # Tier 51: action-audit log is the forensic trail. Silently dropping it means a kill /
        # block / lockdown leaves no record on disk. Rate-limit to once per 10 minutes so a
        # disk-full condition doesn't spam the events feed.
        try {
            if (-not $script:_AuditWriteErrAt -or ((Get-Date) - $script:_AuditWriteErrAt).TotalMinutes -gt 10) {
                $script:_AuditWriteErrAt = Get-Date
                Add-Event warn ("Action audit write failed ('{0}' on '{1}' not logged to disk): {2}" -f $Action, $Target, $_.Exception.Message)
            }
        } catch {}
    }
}

function Invoke-KillProcessAction {
    param([int]$Pid, [string]$Name)
    if (-not $Pid -or $Pid -le 4) {
        [System.Windows.MessageBox]::Show($window, "Refusing to kill protected process (pid $Pid).", 'Not allowed', 'OK', 'Warning') | Out-Null
        return
    }
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, 'Killing some processes requires Administrator. Re-launch via Run-NetJump.bat.', 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    $msg = "Kill '$Name' (pid $Pid) ?`n`nThis is irreversible. The process will receive SIGTERM-equivalent and be terminated. Use only for verified suspect processes."
    $r = [System.Windows.MessageBox]::Show($window, $msg, 'Kill process', 'YesNo', 'Warning')
    if ($r -ne 'Yes') { return }
    try {
        $p = Get-Process -Id $Pid -ErrorAction Stop
        $snap = @{ Name=$p.ProcessName; Path=$p.Path; StartTime=$p.StartTime.ToString('o') }
        Stop-Process -Id $Pid -Force -ErrorAction Stop
        Write-ActionAudit 'kill-process' "pid=$Pid name=$Name" 'success' $snap
        Add-Event fix "Killed process: $Name (pid $Pid)" -Source 'processes'
        Add-ActivityMark fix
        Show-Toast -Title 'NetJump: process killed' -Message "$Name (pid $Pid) terminated." -Icon Info
    } catch {
        Write-ActionAudit 'kill-process' "pid=$Pid name=$Name" 'failure' "$_"
        Add-Event warn "Kill failed: $_" -Source 'processes'
        [System.Windows.MessageBox]::Show($window, "Kill failed:`n$_", 'Error', 'OK', 'Error') | Out-Null
    }
}

function Invoke-BlockIpAction {
    param([string]$Ip, [string]$Reason = 'NetJump manual block')
    if (-not $Ip -or $Ip -notmatch '^\d+\.\d+\.\d+\.\d+$') {
        [System.Windows.MessageBox]::Show($window, "Invalid IPv4: '$Ip'", 'Bad input', 'OK', 'Warning') | Out-Null
        return
    }
    if ($Ip -match '^(127\.|192\.168\.|10\.|172\.(1[6-9]|2\d|3[01])\.|169\.254\.|0\.0\.0\.0|255\.)') {
        $r = [System.Windows.MessageBox]::Show($window, "$Ip is on the local network. Blocking it will likely break LAN connectivity. Proceed anyway?", 'Local IP', 'YesNo', 'Warning')
        if ($r -ne 'Yes') { return }
    }
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, 'Firewall rule creation requires Administrator.', 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    $ruleName = "NetJump block $Ip"
    $msg = "Create an outbound DENY rule for $Ip in Windows Defender Firewall?`n`nReason: $Reason`n`nReversible. The rule is named '$ruleName' and can be removed in wf.msc or via:`nRemove-NetFirewallRule -DisplayName '$ruleName'"
    $r = [System.Windows.MessageBox]::Show($window, $msg, 'Block IP at firewall', 'YesNo', 'Question')
    if ($r -ne 'Yes') { return }
    try {
        New-NetFirewallRule -DisplayName $ruleName -Direction Outbound -Action Block -RemoteAddress $Ip -Description $Reason -ErrorAction Stop | Out-Null
        Write-ActionAudit 'block-ip' "ip=$Ip rule=$ruleName" 'success' @{ reason=$Reason }
        Add-Event fix "Blocked $Ip at firewall (rule: $ruleName)"
        Add-ActivityMark fix
        Show-Toast -Title 'NetJump: IP blocked' -Message "$Ip blocked outbound. Rule '$ruleName' created (reversible)." -Icon Info
    } catch {
        Write-ActionAudit 'block-ip' "ip=$Ip rule=$ruleName" 'failure' "$_"
        Add-Event warn "Block-IP failed: $_"
        [System.Windows.MessageBox]::Show($window, "Block failed:`n$_", 'Error', 'OK', 'Error') | Out-Null
    }
}

function Invoke-OpenLocationAction {
    param([string]$Path)
    if (-not $Path) {
        [System.Windows.MessageBox]::Show($window, "No binary path recorded for this row.", 'No path', 'OK', 'Information') | Out-Null
        return
    }
    if (-not (Test-Path $Path)) {
        [System.Windows.MessageBox]::Show($window, "Path not found on disk: '$Path'`n`nThe binary may have been moved, renamed, or deleted since the last process scan.", 'Not found', 'OK', 'Warning') | Out-Null
        try { Add-Event warn ("Open-location: path missing: $Path") } catch {}
        return
    }
    # Tier 63: surface success / failure to events feed. Start-Process can fail if explorer.exe is
    # blocked (uncommon - GPO restrictions, broken Shell registration, etc.). Without surfacing the
    # error, the user just sees nothing happen and assumes the click didn't register.
    try {
        Start-Process explorer.exe ('/select,"' + $Path + '"') -ErrorAction Stop
        Write-ActionAudit 'open-location' $Path 'opened'
        try { Add-Event info ("Opened in Explorer: $Path") } catch {}
    } catch {
        Write-ActionAudit 'open-location' $Path 'failure' "$_"
        try { Add-Event warn ("Open-location failed for '$Path': $($_.Exception.Message)") } catch {}
        [System.Windows.MessageBox]::Show($window, "Failed to open Explorer to '$Path':`n$_", 'Error', 'OK', 'Error') | Out-Null
    }
}

function Invoke-CopyToClipboard {
    param([string]$Text)
    if (-not $Text) { return }
    try {
        Set-Clipboard -Value $Text
        Add-Event info ("Copied to clipboard: {0}" -f ($Text.Substring(0, [Math]::Min(80, $Text.Length))))
    } catch {
        # Tier 51: clipboard fails when another process is holding the OS clipboard exclusively
        # (Remote Desktop, password managers, certain VMs). User clicks Copy, expects paste to work,
        # nothing happens. Surface so they know.
        try { Add-Event warn ("Clipboard copy failed: {0}" -f $_.Exception.Message) } catch {}
    }
}

# ---------- DNS row actions ----------
$script:HostsPath = Join-Path $env:SystemRoot 'System32\drivers\etc\hosts'

function Invoke-DnsBlock {
    param([string]$Domain)
    if (-not $Domain) { return }
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, 'Editing the hosts file requires Administrator. Re-launch via Run-NetJump.bat.', 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    $domain = $Domain.TrimEnd('.').ToLower()
    if (-not $domain -or $domain -match '^\s*$') { return }
    # Reject obvious "do not block" domains
    $protected = @('localhost','windowsupdate.com','microsoft.com','google.com','cloudflare.com','1.1.1.1','8.8.8.8')
    foreach ($p in $protected) {
        if ($domain -eq $p -or $domain -like "*.$p") {
            $resp = [System.Windows.MessageBox]::Show($window, ("'{0}' looks like critical infrastructure - blocking it may break your system or this app. Block anyway?" -f $domain), 'Are you sure?', 'YesNo', 'Warning')
            if ($resp -ne 'Yes') { return }
            break
        }
    }
    $confirm = [System.Windows.MessageBox]::Show($window, ("Add '{0}' to the hosts file as a blackhole entry?`n`n0.0.0.0  {0}`n0.0.0.0  www.{0}`n`nThis blocks ALL applications from resolving the domain. To undo, use 'Unblock' or remove the line manually." -f $domain), 'Block domain', 'YesNo', 'Question')
    if ($confirm -ne 'Yes') { return }
    try {
        # Backup hosts file once per session before first edit
        $bak = "$script:HostsPath.netjump.bak"
        if (-not (Test-Path $bak)) {
            Copy-Item -LiteralPath $script:HostsPath -Destination $bak -ErrorAction SilentlyContinue
        }
        # Avoid duplicate entries
        $existing = Get-Content $script:HostsPath -ErrorAction SilentlyContinue
        $alreadyHas = $existing | Where-Object { $_ -match "(?i)\b$([regex]::Escape($domain))\b" -and $_ -notmatch '^\s*#' }
        if ($alreadyHas) {
            [System.Windows.MessageBox]::Show($window, ("'{0}' already appears in the hosts file:`n`n{1}" -f $domain, ($alreadyHas -join "`n")), 'Already there', 'OK', 'Information') | Out-Null
            return
        }
        $stamp = Get-Date -Format 'yyyy-MM-dd HH:mm'
        $append = @(
            ""
            "# NetJump-blocked $stamp"
            "0.0.0.0  $domain"
            "0.0.0.0  www.$domain"
        )
        Add-Content -LiteralPath $script:HostsPath -Value $append -Encoding UTF8 -ErrorAction Stop
        # Flush so the block takes effect immediately
        & ipconfig /flushdns | Out-Null
        Add-Event fix ("Blocked domain via hosts: {0}" -f $domain) -Source 'dns'
        [System.Windows.MessageBox]::Show($window, ("Blocked '{0}' (and www variant). DNS cache flushed.`n`nBackup of hosts saved to:`n{1}" -f $domain, $bak), 'Blocked', 'OK', 'Information') | Out-Null
    } catch {
        Add-Event warn ("DNS block failed: $_") -Source 'dns'
        [System.Windows.MessageBox]::Show($window, "Block failed:`n`n$_", 'Error', 'OK', 'Error') | Out-Null
    }
}

function Invoke-DnsUnblock {
    param([string]$Domain)
    if (-not $Domain) { return }
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, 'Editing the hosts file requires Administrator.', 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    $domain = $Domain.TrimEnd('.').ToLower()
    try {
        $lines = @(Get-Content $script:HostsPath -ErrorAction SilentlyContinue)
        $matchingLines = $lines | Where-Object { $_ -match "(?i)\s$([regex]::Escape($domain))\s*$" -and $_ -notmatch '^\s*#' }
        if (-not $matchingLines) {
            [System.Windows.MessageBox]::Show($window, ("'{0}' is not currently blocked in hosts file." -f $domain), 'Not blocked', 'OK', 'Information') | Out-Null
            return
        }
        $confirm = [System.Windows.MessageBox]::Show($window, ("Remove these lines from hosts?`n`n{0}" -f ($matchingLines -join "`n")), 'Unblock domain', 'YesNo', 'Question')
        if ($confirm -ne 'Yes') { return }
        $kept = $lines | Where-Object { -not ($_ -match "(?i)\s$([regex]::Escape($domain))\s*$" -and $_ -notmatch '^\s*#') }
        Set-Content -LiteralPath $script:HostsPath -Value $kept -Encoding UTF8 -ErrorAction Stop
        & ipconfig /flushdns | Out-Null
        Add-Event fix ("Unblocked domain (hosts entry removed): {0}" -f $domain) -Source 'dns'
        [System.Windows.MessageBox]::Show($window, ("Unblocked '{0}'. DNS cache flushed." -f $domain), 'Unblocked', 'OK', 'Information') | Out-Null
    } catch {
        Add-Event warn ("DNS unblock failed: $_") -Source 'dns'
        [System.Windows.MessageBox]::Show($window, "Unblock failed:`n`n$_", 'Error', 'OK', 'Error') | Out-Null
    }
}

function Find-DnsResolvingProcess {
    param([string]$Domain)
    if (-not $Domain) { return }
    $domain = $Domain.TrimEnd('.').ToLower()
    # Step 1: resolve current IP for the domain
    $ips = @()
    try {
        $r = Resolve-DnsName -Name $domain -Type A -ErrorAction SilentlyContinue
        if ($r) { $ips = @($r | Where-Object { $_.IPAddress } | ForEach-Object IPAddress) }
    } catch {
        # Tier 51: surface DNS resolve failure so user knows WHY no process is found
        Add-Event warn ("DNS resolve for '{0}' failed: {1}" -f $domain, $_.Exception.Message) -Source 'dns'
    }
    if (-not $ips -or $ips.Count -eq 0) {
        [System.Windows.MessageBox]::Show($window, ("Couldn't resolve '{0}' to an IP. Make sure the PROCESSES tab has been refreshed." -f $domain), 'No IP', 'OK', 'Information') | Out-Null
        return
    }
    # Step 2: search active TCP/UDP connections for any process talking to those IPs
    $hits = New-Object System.Collections.ArrayList
    try {
        $tcp = Get-NetTCPConnection -State Established -ErrorAction SilentlyContinue
        foreach ($c in $tcp) {
            if ($ips -contains $c.RemoteAddress) {
                $p = Get-Process -Id $c.OwningProcess -ErrorAction SilentlyContinue
                $name = if ($p) { $p.ProcessName } else { '?' }
                [void]$hits.Add(("{0} (pid {1}) -> {2}:{3}" -f $name, $c.OwningProcess, $c.RemoteAddress, $c.RemotePort))
            }
        }
    } catch {
        # Tier 51: TCP enumeration failure (rare - only happens when network stack is being reset)
        Add-Event warn ("TCP connection enum failed during DNS process lookup: {0}" -f $_.Exception.Message)
    }
    # Also check ledger for historical evidence
    $ledgerHits = New-Object System.Collections.ArrayList
    try {
        foreach ($v in $script:Ledger.Values) {
            if ($ips -contains $v.ip) {
                [void]$ledgerHits.Add(("{0} -> {1}:{2} (ledger, {3} samples)" -f $v.proc, $v.ip, $v.port, $v.samples))
            }
        }
    } catch {}
    $allHits = @(($hits + $ledgerHits) | Select-Object -Unique)
    if ($allHits.Count -eq 0) {
        [System.Windows.MessageBox]::Show($window, ("'{0}' resolves to {1}, but no active or historical process is currently connected to those IPs.`n`nThe DNS lookup may have been a passive resolution (browser preview, OS service) without a TCP connection." -f $domain, ($ips -join ', ')), 'No process found', 'OK', 'Information') | Out-Null
    } else {
        [System.Windows.MessageBox]::Show($window, ("Processes hitting '{0}' ({1}):`n`n{2}`n`nUse the PROCESSES tab to right-click any of these and Block IP / Kill." -f $domain, ($ips -join ', '), ($allHits -join "`n")), 'Processes found', 'OK', 'Information') | Out-Null
    }
}

function Show-DnsBlocklistDialog {
    if (-not (Test-Path $script:HostsPath)) {
        [System.Windows.MessageBox]::Show($window, "Hosts file not found at:`n$script:HostsPath", 'Missing', 'OK', 'Warning') | Out-Null
        return
    }
    $lines = @(Get-Content $script:HostsPath -ErrorAction SilentlyContinue)
    # Match lines like "0.0.0.0  domain.tld" or "127.0.0.1  domain.tld" - the standard blackhole patterns
    $blocked = $lines | Where-Object { $_ -match '^\s*(0\.0\.0\.0|127\.0\.0\.1)\s+\S+' -and $_ -notmatch '^\s*#' }
    if (-not $blocked -or $blocked.Count -eq 0) {
        [System.Windows.MessageBox]::Show($window, "No domains are currently blocked via the hosts file (no 0.0.0.0 or 127.0.0.1 entries).", 'Empty blocklist', 'OK', 'Information') | Out-Null
        return
    }
    $list = ($blocked -join "`n")
    $msg = "Currently blocked domains in hosts file ({0}):`n`n{1}`n`nTo unblock individually, right-click the domain in the DNS list and choose Unblock.`nTo edit manually, click 'Open hosts file' on the DNS toolbar." -f $blocked.Count, $list
    [System.Windows.MessageBox]::Show($window, $msg, 'DNS blocklist', 'OK', 'Information') | Out-Null
}

# ---------- per-finding fix lookup + apply ----------
# Findings have a free-text Fix string (informational); the actual runnable Commands live in
# $script:State.RecommendedFixes as @{Description; Command}. Match by quoted phrase or shared
# keywords between the finding's message and the fix's description.
function Find-FindingFix {
    param($Finding)
    if (-not $Finding -or -not $script:State.RecommendedFixes) { return $null }
    $msg = [string]$Finding.Message
    if (-not $msg) { return $null }
    foreach ($f in $script:State.RecommendedFixes) {
        if (-not $f.Description) { continue }
        $desc = [string]$f.Description
        # Strategy 1: quoted phrase in description (e.g. 'Energy-Efficient Ethernet') matches the finding message
        $m = [regex]::Match($desc, "'([^']+)'")
        if ($m.Success -and $msg -like "*$($m.Groups[1].Value)*") { return $f }
        # Strategy 2: any 4+-char token from the finding message appears in the fix description
        $tokens = ($msg -split '[\s=\.,;:()]+' | Where-Object { $_.Length -ge 4 } | Select-Object -First 5)
        foreach ($tok in $tokens) {
            if ($desc -like "*$tok*") { return $f }
        }
    }
    return $null
}

function Invoke-CauseFix {
    param($Cause)
    if (-not $Cause) { return }
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, 'Applying fixes requires Administrator. Re-launch via Run-NetJump.bat.', 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    # Prefer the cause's directly-attached Fixes array (deterministic, built by Compute-RootCauses)
    $matched = New-Object System.Collections.Generic.List[object]
    if ($Cause.PSObject.Properties['Fixes'] -and $Cause.Fixes -and @($Cause.Fixes).Count -gt 0) {
        foreach ($fx in $Cause.Fixes) { [void]$matched.Add($fx) }
    } else {
        # Fallback: fuzzy match against the global RecommendedFixes list (older behavior)
        if ($script:State.RecommendedFixes -and $script:State.RecommendedFixes.Count -gt 0) {
            $causeText = "$($Cause.Cause) $($Cause.Evidence) $($Cause.Recommendation)"
            foreach ($f in $script:State.RecommendedFixes) {
                if (-not $f.Description) { continue }
                $desc = [string]$f.Description
                $hit  = $false
                $m = [regex]::Match($desc, "'([^']+)'")
                if ($m.Success -and $causeText -like "*$($m.Groups[1].Value)*") { $hit = $true }
                if (-not $hit) {
                    $tokens = ($causeText -split '[\s=\.,;:()]+' | Where-Object { $_.Length -ge 4 } | Select-Object -First 8)
                    foreach ($tok in $tokens) { if ($desc -like "*$tok*") { $hit = $true; break } }
                }
                if ($hit) { [void]$matched.Add($f) }
            }
        }
    }
    if ($matched.Count -eq 0) {
        [System.Windows.MessageBox]::Show($window, ("No auto-fix is available for this cause.`n`nManual remediation:`n`n{0}" -f $Cause.Recommendation), 'Manual fix needed', 'OK', 'Information') | Out-Null
        return
    }
    $cmdList = ($matched | ForEach-Object { "  * $($_.Description)" }) -join "`n"
    $prompt = "Apply {0} auto-fix(es) for this cause?`n`n{1}`n`n{2}`n`nMost fixes are reversible (re-run with the opposite value).`n`nDetails of each command can be reviewed in the Events ribbon after." -f $matched.Count, $Cause.Cause, $cmdList
    $res = [System.Windows.MessageBox]::Show($window, $prompt, 'Apply cause fixes', 'YesNo', 'Question')
    if ($res -ne 'Yes') { return }
    Add-Event fix ("Applying {0} fix(es) for cause: {1}" -f $matched.Count, $Cause.Cause)
    $errors = @()
    $okCount = 0
    foreach ($fx in $matched) {
        try {
            Add-Event fix ("> {0}" -f $fx.Description)
            Invoke-Expression $fx.Command
            Add-Event fix ("  OK: {0}" -f $fx.Description)
            $okCount++
        } catch {
            $errMsg = $_.Exception.Message
            $errors += "$($fx.Description): $errMsg"
            Add-Event warn ("  FAILED: {0} - {1}" -f $fx.Description, $errMsg)
        }
    }
    if ($errors.Count -gt 0) {
        [System.Windows.MessageBox]::Show($window, ("{0} fix(es) applied, {1} failed.`n`nFailures:`n{2}`n`nRe-scan to see updated status." -f $okCount, $errors.Count, ($errors -join "`n")), 'Partial result', 'OK', 'Warning') | Out-Null
    } else {
        [System.Windows.MessageBox]::Show($window, ("Done. {0} fix(es) applied. Re-scan to confirm." -f $okCount), 'Cause fixed', 'OK', 'Information') | Out-Null
    }
}

function Invoke-FindingFix {
    param($Finding)
    if (-not $Finding) { return }
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, 'Applying a fix requires Administrator. Re-launch via Run-NetJump.bat.', 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    $fix = Find-FindingFix $Finding
    if (-not $fix) {
        $fmsg = "No automatic fix is available for this finding.`n`n[$($Finding.Level)] $($Finding.Category) - $($Finding.Message)`n`nThe Fix hint shown on the row is informational. Try the suggested action manually, or run a fresh scan first."
        [System.Windows.MessageBox]::Show($window, $fmsg, 'No fix available', 'OK', 'Information') | Out-Null
        return
    }
    $prompt = "Apply this fix?`n`n$($fix.Description)`n`nThis will run:`n  $($fix.Command)`n`nMost flap-related fixes are reversible by repeating the same command with the opposite value (Enabled vs Disabled)."
    $res = [System.Windows.MessageBox]::Show($window, $prompt, 'Apply fix', 'YesNo', 'Question')
    if ($res -ne 'Yes') { return }
    Add-Event fix ("Applying fix: $($fix.Description)")
    try {
        Invoke-Expression $fix.Command
        Add-Event fix ("Applied: $($fix.Description)")
        [System.Windows.MessageBox]::Show($window, "Done. The change is live now. Re-scan to confirm the finding is gone.", 'Fix applied', 'OK', 'Information') | Out-Null
    } catch {
        Add-Event warn ("Fix FAILED: $($fix.Description) - $($_.Exception.Message)")
        [System.Windows.MessageBox]::Show($window, "Fix failed:`n`n$($_.Exception.Message)", 'Error', 'OK', 'Error') | Out-Null
    }
}

# Tier 67: reusable auto-apply-SAFE-fixes pipeline. Mirrors the AUTO-APPLY ALL SAFE button inside
# Show-FixPickerDialog but operates headlessly - no dialog, no per-row checkboxes - so it can be
# called immediately after a scan completes, from a keyboard shortcut, or from the new one-click
# "Run scan + auto-fix" button on the hero card.
#
# Returns a hashtable @{ AppliedCount; FailedCount; Errors; SafeFound } so the caller can decide
# what UI feedback to show. Callers SHOULD pass -Confirm:$false only when they've already gathered
# user consent (e.g. via a confirmation dialog that previewed the fix list).
function Invoke-ApplySafeFixes {
    param(
        [switch]$Confirm,           # if set, show a Yes/No dialog with the fix list before applying
        [switch]$StartVerifyWatch   # if set, kick off the 10-min post-fix verify-watch timer
    )
    $result = @{ AppliedCount = 0; FailedCount = 0; Errors = @(); SafeFound = 0; Cancelled = $false }
    if (-not $script:IsAdmin) {
        try { Add-Event warn 'Auto-apply skipped: Administrator required.' } catch {}
        $result.Cancelled = $true
        return $result
    }
    # Aggregate fixes the same way Show-FixPickerDialog does (Diagnostics + Causes, dedup by Command).
    $allFixes = New-Object System.Collections.Generic.List[object]
    $seenCommands = @{}
    if ($script:State.RecommendedFixes) {
        foreach ($f in $script:State.RecommendedFixes) {
            $cmdKey = [string]$f.Command
            if (-not $cmdKey -or $seenCommands.ContainsKey($cmdKey)) { continue }
            $seenCommands[$cmdKey] = $true
            [void]$allFixes.Add(@{ Description = [string]$f.Description; Command = $cmdKey })
        }
    }
    if ($script:Causes) {
        foreach ($c in $script:Causes) {
            if (-not $c.PSObject.Properties['Fixes'] -or -not $c.Fixes) { continue }
            foreach ($f in $c.Fixes) {
                $cmdKey = [string]$f.Command
                if (-not $cmdKey -or $seenCommands.ContainsKey($cmdKey)) { continue }
                $seenCommands[$cmdKey] = $true
                [void]$allFixes.Add(@{ Description = [string]$f.Description; Command = $cmdKey })
            }
        }
    }
    if ($allFixes.Count -eq 0) {
        try { Add-Event info 'Auto-apply: no fixes recommended after the scan.' } catch {}
        return $result
    }
    # Filter to SAFE-tier only (uses the same _FixRisk classifier the picker uses, inlined here so
    # we don't depend on the picker dialog being open).
    $disruptivePatterns = @(
        'Disable-NetAdapterBinding','Disable-WindowsOptionalFeature','ipconfig\s+/release',
        'Set-DnsClientServerAddress.*-ServerAddresses','Stop-Service','Remove-Service','Disable-Service',
        'Set-Service.*-StartupType\s+Disabled','Remove-NetFirewallRule','Set-MpPreference.*-DisableRealtimeMonitoring',
        'Set-ExecutionPolicy','Disable-ScheduledTask','Unregister-ScheduledTask','Stop-Process','shutdown','Restart-Computer'
    )
    $moderatePatterns = @(
        'Set-NetAdapterAdvancedProperty','Disable-NetAdapterPowerManagement','Update-MpSignature',
        'Start-MpScan','Set-ItemProperty.*ProxyEnable','New-NetFirewallRule','Add-Content.*hosts'
    )
    $safeFixes = @($allFixes | Where-Object {
        $cmd = [string]$_.Command
        $isDisruptive = $false; $isModerate = $false
        foreach ($p in $disruptivePatterns) { if ($cmd -match $p) { $isDisruptive = $true; break } }
        if ($isDisruptive) { return $false }
        foreach ($p in $moderatePatterns)   { if ($cmd -match $p) { $isModerate = $true; break } }
        return -not $isModerate
    })
    $result.SafeFound = $safeFixes.Count
    if ($safeFixes.Count -eq 0) {
        try { Add-Event info ("Auto-apply: scan recommended {0} fix(es) but NONE are classified SAFE - manual review required." -f $allFixes.Count) } catch {}
        return $result
    }
    # Optional: confirmation dialog with full preview of what will run
    if ($Confirm) {
        $preview = ($safeFixes | ForEach-Object { '  - ' + $_.Description }) -join "`n"
        $msg = "Auto-apply $($safeFixes.Count) SAFE fix(es)?`n`n$preview`n`n(MODERATE and DISRUPTIVE fixes were SKIPPED. They require manual review via 'Apply recommended fixes' button.)"
        $r = [System.Windows.MessageBox]::Show($window, $msg, 'Confirm auto-fix', 'OKCancel', 'Question')
        if ($r -ne 'OK') {
            try { Add-Event info 'Auto-apply cancelled by user.' } catch {}
            $result.Cancelled = $true
            return $result
        }
    }
    Add-Event fix ("Auto-applying {0} SAFE fix(es)..." -f $safeFixes.Count)
    foreach ($fx in $safeFixes) {
        try {
            Add-Event fix ("> {0}" -f $fx.Description)
            Invoke-Expression $fx.Command
            Add-Event fix ("  OK: {0}" -f $fx.Description)
            $result.AppliedCount++
            Write-ActionAudit 'auto-fix' $fx.Description 'success' @{ command = $fx.Command }
        } catch {
            $errMsg = "{0}: {1}" -f $fx.Description, $_.Exception.Message
            $result.Errors += $errMsg
            $result.FailedCount++
            Add-Event warn ("  FAILED: {0}" -f $errMsg)
            Write-ActionAudit 'auto-fix' $fx.Description 'failure' "$($_.Exception.Message)"
        }
    }
    # Optionally start the 10-min verify watch so the dashboard observes whether the fixes hold
    if ($StartVerifyWatch -and $result.AppliedCount -gt 0) {
        try {
            $script:State.VerifyMode = $true
            $script:State.VerifyEndTime = (Get-Date).AddMinutes(10)
            $script:State.VerifyBaseline = $script:State.FlapCount
            if ($controls.VerifyBadge) { $controls.VerifyBadge.Visibility = 'Visible' }
            if ($controls.VerifyText)  { $controls.VerifyText.Text = 'verifying fix... 600s left' }
            Add-Event fix 'Verify watch started (10 min) - will report PASS / FAIL via toast.'
        } catch {}
    }
    return $result
}

# Tier 67: combined "scan + auto-fix" workflow. Sets a pending flag, triggers the scan, lets
# Update-Findings' finally-block hook pick up the flag and run Invoke-ApplySafeFixes after the scan
# completes. This is the one-click flow surfaced via the Auto-fix button on the hero card.
function Invoke-ScanAndAutoFix {
    if ($script:_ScanInProgress) {
        try { Add-Event info 'Auto-fix scan ignored - a scan is already running.' } catch {}
        return
    }
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, 'Auto-fix requires Administrator. Re-launch via Run-NetJump.bat.', 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    $script:State.PendingAutoApply = $true
    Add-Event fix '--- AUTO-FIX WORKFLOW: scan starting, SAFE fixes will apply on completion ---'
    $window.Dispatcher.InvokeAsync({ Update-Findings }) | Out-Null
}

# ---------- Tier 12: hardening posture checks ----------
function Invoke-HardeningChecks {
    $out = New-Object System.Collections.Generic.List[object]

    function _add($lvl, $msg, $fix='', $detail='', $mitre='') {
        $out.Add((Add-Finding $lvl 'Posture' $msg $fix $detail $mitre))
    }

    # SMBv1 - EternalBlue / WannaCry / NotPetya
    try {
        $smb = Get-SmbServerConfiguration -ErrorAction Stop
        if ($smb.EnableSMB1Protocol) {
            _add 'FAIL' 'SMBv1 is enabled (EternalBlue / WannaCry exposure).' `
                "Disable-WindowsOptionalFeature -Online -FeatureName SMB1Protocol -NoRestart" `
                'SMBv1 is the protocol exploited by EternalBlue (WannaCry, NotPetya). Deprecated since 2014. Modern Windows ships it disabled - if it is on, legacy software re-enabled it.'
        } else {
            _add 'OK' 'SMBv1 disabled.'
        }
    } catch {}

    # LLMNR - Responder.py credential capture
    $llmnr = Get-ItemProperty -Path 'HKLM:\SOFTWARE\Policies\Microsoft\Windows NT\DNSClient' -Name EnableMulticast -ErrorAction SilentlyContinue
    if ($null -eq $llmnr -or $llmnr.EnableMulticast -ne 0) {
        _add 'WARN' 'LLMNR enabled (Responder credential-capture exposure).' `
            "New-Item -Path 'HKLM:\SOFTWARE\Policies\Microsoft\Windows NT\DNSClient' -Force; New-ItemProperty -Path 'HKLM:\SOFTWARE\Policies\Microsoft\Windows NT\DNSClient' -Name EnableMulticast -Value 0 -PropertyType DWord -Force" `
            "Link-Local Multicast Name Resolution lets attackers on the same broadcast domain capture NTLMv2 hashes via the public Responder.py tool. There is essentially no legitimate use on a properly DNS-configured network."
    } else {
        _add 'OK' 'LLMNR disabled (Responder closed).'
    }

    # NBT-NS - similar to LLMNR
    $nbt = Get-ChildItem 'HKLM:\SYSTEM\CurrentControlSet\services\NetBT\Parameters\Interfaces' -ErrorAction SilentlyContinue
    $nbtBad = @($nbt | ForEach-Object {
        $v = (Get-ItemProperty -Path $_.PSPath -Name NetbiosOptions -ErrorAction SilentlyContinue).NetbiosOptions
        if ($v -ne 2) { 1 }   # 2 = disabled
    } | Where-Object { $_ }).Count
    if ($nbtBad -gt 0) {
        _add 'WARN' ("NBT-NS active on {0} adapter(s)." -f $nbtBad) `
            "Set-ItemProperty -Path 'HKLM:\SYSTEM\CurrentControlSet\services\NetBT\Parameters\Interfaces\Tcpip_*' -Name NetbiosOptions -Value 2" `
            'NetBIOS over TCP/IP is the older sibling of LLMNR and falls to the same Responder attack. Set NetbiosOptions=2 on each adapter interface key.'
    } else {
        _add 'OK' 'NBT-NS disabled on all adapters.'
    }

    # WDigest - clear-text credential cache
    $wd = (Get-ItemProperty 'HKLM:\SYSTEM\CurrentControlSet\Control\SecurityProviders\WDigest' -Name UseLogonCredential -ErrorAction SilentlyContinue).UseLogonCredential
    if ($wd -eq 1) {
        _add 'FAIL' 'WDigest UseLogonCredential=1 (plaintext creds in LSASS!).' `
            "Set-ItemProperty -Path 'HKLM:\SYSTEM\CurrentControlSet\Control\SecurityProviders\WDigest' -Name UseLogonCredential -Value 0" `
            'WDigest with UseLogonCredential=1 caches plain-text passwords in LSASS, where Mimikatz can dump them. Should always be 0.'
    } else {
        _add 'OK' 'WDigest plain-text caching off.'
    }

    # PowerShell v2 - no scriptblock logging available
    try {
        $psv2 = Get-WindowsOptionalFeature -Online -FeatureName MicrosoftWindowsPowerShellV2 -ErrorAction Stop
        if ($psv2.State -eq 'Enabled') {
            _add 'WARN' 'PowerShell v2 engine still installed (logging-bypass surface).' `
                "Disable-WindowsOptionalFeature -Online -FeatureName MicrosoftWindowsPowerShellV2Root -NoRestart" `
                'PowerShell v2 has no AMSI integration and bypasses scriptblock logging. Attackers downgrade to PSv2 to evade EDR. Remove unless legacy code requires it.'
        } else {
            _add 'OK' 'PowerShell v2 engine removed.'
        }
    } catch {}

    # Defender Tamper Protection
    $mp = Get-MpComputerStatus -ErrorAction SilentlyContinue
    if ($mp) {
        if (-not $mp.IsTamperProtected) {
            _add 'WARN' 'Defender Tamper Protection is OFF.' `
                "Open Windows Security -> Virus & threat protection -> Manage settings -> turn on Tamper Protection (cannot be done from PowerShell)." `
                'Without Tamper Protection an attacker with admin rights can disable Defender via registry/PowerShell. With it on, those changes are blocked at the kernel.' `
                'defender-off'
        } else {
            _add 'OK' 'Defender Tamper Protection on.'
        }
        if (-not $mp.AntispywareEnabled -or -not $mp.RealTimeProtectionEnabled) {
            _add 'WARN' 'Defender real-time / anti-spyware disabled.' '' '' 'defender-off'
        }
    }

    # BitLocker on system drive
    try {
        $bl = Get-BitLockerVolume -MountPoint $env:SystemDrive -ErrorAction Stop
        if ($bl.ProtectionStatus -ne 'On') {
            _add 'WARN' ("BitLocker NOT protecting {0}." -f $env:SystemDrive) `
                "Manage-bde -on $env:SystemDrive  (configure key protectors first)" `
                'Without BitLocker, anyone with physical access can mount the drive on another OS and read everything. Enable for the system drive at minimum.'
        } else {
            _add 'OK' ("BitLocker active on {0}." -f $env:SystemDrive)
        }
    } catch {}

    # Secure Boot
    try {
        $sb = Confirm-SecureBootUEFI -ErrorAction Stop
        if ($sb) { _add 'OK' 'Secure Boot enabled.' }
        else      { _add 'WARN' 'Secure Boot disabled.' '' 'Secure Boot prevents pre-OS rootkits/bootkits from running. Enable in firmware (UEFI BIOS).' }
    } catch {}

    # NTLM v1 / LmCompatibilityLevel
    $lmcl = (Get-ItemProperty 'HKLM:\SYSTEM\CurrentControlSet\Control\Lsa' -Name LmCompatibilityLevel -ErrorAction SilentlyContinue).LmCompatibilityLevel
    if ($null -eq $lmcl -or $lmcl -lt 5) {
        $lmclShown = if ($null -eq $lmcl) { 'default' } else { $lmcl }
        _add 'WARN' ("LmCompatibilityLevel = {0} (NTLMv1 still possible)." -f $lmclShown) `
            "Set-ItemProperty -Path 'HKLM:\SYSTEM\CurrentControlSet\Control\Lsa' -Name LmCompatibilityLevel -Value 5" `
            'LmCompatibilityLevel < 5 lets the system fall back to NTLMv1, trivially crackable. Set to 5 (NTLMv2 only, refuse LM/NTLMv1).'
    } else {
        _add 'OK' "LmCompatibilityLevel = $lmcl (NTLMv2 enforced)."
    }

    # AutoRun on removable drives
    $ar = (Get-ItemProperty 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\Explorer' -Name NoDriveTypeAutoRun -ErrorAction SilentlyContinue).NoDriveTypeAutoRun
    if ($null -eq $ar -or $ar -lt 0xff) {
        _add 'INFO' 'AutoRun policy not maximally restrictive.' `
            "Set-ItemProperty -Path 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\Explorer' -Name NoDriveTypeAutoRun -Value 255" `
            'NoDriveTypeAutoRun=255 (0xFF) disables AutoRun on every drive type. Stuxnet-style USB attacks rely on AutoRun being permissive.'
    } else {
        _add 'OK' 'AutoRun fully disabled.'
    }

    # Restrict Anonymous SAM
    $ras = (Get-ItemProperty 'HKLM:\SYSTEM\CurrentControlSet\Control\Lsa' -Name RestrictAnonymousSAM -ErrorAction SilentlyContinue).RestrictAnonymousSAM
    if ($ras -ne 1) {
        _add 'WARN' "RestrictAnonymousSAM != 1 (anonymous SAM enumeration possible)." `
            "Set-ItemProperty -Path 'HKLM:\SYSTEM\CurrentControlSet\Control\Lsa' -Name RestrictAnonymousSAM -Value 1" `
            'Allows null-session enumeration of local accounts - a classic recon technique. Should be 1.'
    } else {
        _add 'OK' 'Anonymous SAM access restricted.'
    }

    return $out
}

