    'iqvw32e.sys'     = @{ Vendor='Intel';            CVE='CVE-2015-2291'; Note='Intel ethernet diag (32-bit)' }
    'speedfan.sys'    = @{ Vendor='Almico';           CVE='CVE-2007-5633'; Note='SpeedFan' }
    'gdrv.sys'        = @{ Vendor='Gigabyte';         CVE='CVE-2018-19320'; Note='Gigabyte hw monitor - RobbinHood' }
    'asio.sys'        = @{ Vendor='ASUS';             CVE='CVE-2018-18537'; Note='ASUS WMI utility' }
    'asio2.sys'       = @{ Vendor='ASUS';             CVE='multiple';       Note='ASUS WMI utility v2' }
    'asio3.sys'       = @{ Vendor='ASUS';             CVE='multiple';       Note='ASUS WMI utility v3' }
    'atillk64.sys'    = @{ Vendor='ASUS';             CVE='CVE-2018-18537'; Note='ASUS Aura/AtillK' }
    'asrdrv101.sys'   = @{ Vendor='ASRock';           CVE='multiple';       Note='ASRock RGB' }
    'asrdrv102.sys'   = @{ Vendor='ASRock';           CVE='multiple';       Note='ASRock' }
    'amifldrv64.sys'  = @{ Vendor='AMI';              CVE='CVE-2021-21551'; Note='AMI flash driver' }
    'aswarpot.sys'    = @{ Vendor='Avast';            CVE='CVE-2022-26522'; Note='Avast antirootkit (older)' }
    'bsmi.sys'        = @{ Vendor='MSI';              CVE='multiple';       Note='MSI driver' }
    'cpuz.sys'        = @{ Vendor='CPUID';            CVE='multiple';       Note='CPU-Z driver' }
    'cpuz141.sys'     = @{ Vendor='CPUID';            CVE='multiple';       Note='CPU-Z driver v141' }
    'gmer.sys'        = @{ Vendor='GMER';             CVE='multiple';       Note='GMER anti-rootkit' }
    'hwiddrvr.sys'    = @{ Vendor='Asus';             CVE='multiple';       Note='Asus hardware ID' }
    'kprocesshacker.sys' = @{ Vendor='Process Hacker'; CVE='multiple';      Note='Process Hacker driver - signed but abuseable' }
    'mhyprot2.sys'    = @{ Vendor='miHoYo / Genshin'; CVE='multiple';       Note='Anti-cheat driver - widely abused 2022+' }
    'msio64.sys'      = @{ Vendor='MSI';              CVE='multiple';       Note='MSI Center driver' }
    'nal.sys'         = @{ Vendor='Intel';            CVE='multiple';       Note='Intel NAL driver' }
    'piddrv64.sys'    = @{ Vendor='ASRock';           CVE='multiple';       Note='ASRock driver' }
    'rtkio64.sys'     = @{ Vendor='Realtek';          CVE='multiple';       Note='Realtek I/O driver' }
    'segwindrvx64.sys'= @{ Vendor='Segwin';           CVE='multiple';       Note='Segwin driver' }
    'winring0.sys'    = @{ Vendor='OpenLibSys';       CVE='CVE-2020-14979'; Note='WinRing0 - read/write MSRs - cryptominers' }
    'winring0x64.sys' = @{ Vendor='OpenLibSys';       CVE='CVE-2020-14979'; Note='WinRing0 64-bit - cryptominers' }
