# ---------- Dynamic vulnerable-driver list (loldrivers.io) ----------
# Augments the curated $script:ByovdBlocklist above with a regularly-refreshed list pulled from
# https://www.loldrivers.io/api/drivers.json (the README has been advertising this since launch).
# Curated entries always win on name collision because their Vendor/CVE/Note text is hand-written
# and richer. Dynamic list adds long-tail entries (4-500 typically) we don't want to hand-maintain.
$script:VulnDriverCache      = Join-Path $script:ThreatIntelDir 'loldrivers.json'
$script:VulnDriverTtlHours   = 168    # 7-day TTL - the list moves slowly; weekly refresh is plenty.
$script:VulnDriverFeedUrl    = 'https://www.loldrivers.io/api/drivers.json'
$script:VulnDriverDynamic    = @{}    # filename(lowercase .sys) -> @{Vendor;CVE;Note;Source}
$script:VulnDriverLoaded     = $false
$script:VulnDriverLastRefresh = $null

function Load-VulnerableDriverList {
    $script:VulnDriverDynamic = @{}
    $script:VulnDriverLoaded  = $false
    if (-not (Test-Path $script:VulnDriverCache)) { return $false }
    try {
        $obj = Get-Content $script:VulnDriverCache -Raw | ConvertFrom-Json
        if ($obj.timestamp) {
            $age = (Get-Date) - [datetime]$obj.timestamp
            # Allow up to 2x TTL for stale cache (i.e. 14 days) before we discard - the curated list
            # remains useful past TTL, we just won't have the latest entries.
            if ($age.TotalHours -gt ($script:VulnDriverTtlHours * 2)) { return $false }
            $script:VulnDriverLastRefresh = [datetime]$obj.timestamp
        }
        if ($obj.drivers) {
            foreach ($d in $obj.drivers) {
                $name = ([string]$d.Filename).ToLower()
                if (-not $name) { continue }
                $script:VulnDriverDynamic[$name] = @{
                    Vendor = [string]$d.Vendor
                    CVE    = [string]$d.CVE
                    Note   = [string]$d.Note
                    Source = 'loldrivers'
                }
            }
        }
        $script:VulnDriverLoaded = $true
        return $true
    } catch { return $false }
}

function Save-VulnerableDriverList {
    try {
        $rows = @($script:VulnDriverDynamic.GetEnumerator() | ForEach-Object {
            [pscustomobject]@{
                Filename = $_.Key
                Vendor   = $_.Value.Vendor
                CVE      = $_.Value.CVE
                Note     = $_.Value.Note
            }
        })
        $obj = [pscustomobject]@{
            timestamp = (Get-Date).ToString('o')
            source    = $script:VulnDriverFeedUrl
            count     = $rows.Count
            drivers   = $rows
        }
        $obj | ConvertTo-Json -Depth 4 | Set-Content $script:VulnDriverCache -Encoding UTF8
    } catch {
        try { Add-Event warn ("Vulnerable-driver cache write failed: {0}" -f $_.Exception.Message) } catch {}
    }
}

function Update-VulnerableDriverList {
    # Async fetch (~600 KB JSON) via Start-Job to avoid blocking UI. Job parses each entry's
    # KnownVulnerableSamples[].Filename and returns a hashtable. Tick polls for completion the
    # same way it polls ThreatIntelJob, then calls Save-VulnerableDriverList.
    if ($script:State -and $script:State.VulnDriverJob) {
        Add-Event scan 'Vulnerable-driver list update already in progress.'
        return
    }
    Add-Event scan 'Vulnerable-driver list: refreshing from loldrivers.io...'
    $job = Start-Job -Name 'NetJump-VulnDrivers' -ScriptBlock {
        param($Url)
        try {
            $r = Invoke-WebRequest -Uri $Url -TimeoutSec 60 -UseBasicParsing -ErrorAction Stop
            # loldrivers.io JSON contains case-collision keys (e.g. 'init' AND 'INIT') that the
            # default ConvertFrom-Json refuses to parse. JavaScriptSerializer is case-sensitive and
            # ships in System.Web.Extensions on every Windows PowerShell install.
            Add-Type -AssemblyName System.Web.Extensions
            $ser = New-Object System.Web.Script.Serialization.JavaScriptSerializer
            $ser.MaxJsonLength = [int]::MaxValue   # default 2 MB; the feed is ~30 MB.
            $list = $ser.DeserializeObject($r.Content)
            $out = @{}
            foreach ($entry in @($list)) {
                # CVE: pick first CVE-prefixed tag if present, else fall back to per-sample CVEs
                $cveTag = $null
                if ($entry['Tags']) {
                    $cveTag = (@($entry['Tags']) | Where-Object { $_ -match '^CVE-' } | Select-Object -First 1)
                }
                if (-not $cveTag) {
                    foreach ($s in @($entry['KnownVulnerableSamples'])) {
                        if ($s -and $s['CVEs']) {
                            $first = @($s['CVEs']) | Where-Object { $_ -match '^CVE-' } | Select-Object -First 1
                            if ($first) { $cveTag = $first; break }
                        }
                    }
                }
                foreach ($s in @($entry['KnownVulnerableSamples'])) {
                    if (-not $s -or -not $s['Filename']) { continue }
                    $fn = ([string]$s['Filename']).ToLower().Trim()
                    if ($fn -notmatch '\.sys$') { continue }   # kernel drivers only
                    $vendor = if ($s['Company'])              { [string]$s['Company'] }
                              elseif ($s['Product'])          { [string]$s['Product'] }
                              elseif ($s['OriginalFilename']) { [string]$s['OriginalFilename'] }
                              else { '' }
                    $desc = if ($s['Description'])         { [string]$s['Description'] }
                            elseif ($s['FileDescription']) { [string]$s['FileDescription'] }
                            elseif ($entry['Category'])    { [string]$entry['Category'] }
                            else { 'vulnerable driver (loldrivers.io)' }
                    if ($desc.Length -gt 140) { $desc = $desc.Substring(0,140) + '...' }
                    if (-not $out.ContainsKey($fn)) {
                        $out[$fn] = @{
                            Vendor = $vendor
                            CVE    = if ($cveTag) { [string]$cveTag } else { 'multiple' }
                            Note   = $desc
                            Source = 'loldrivers'
                        }
                    }
                }
            }
            return @{ Ok=$true; Drivers=$out; Count=$out.Count }
        } catch {
            return @{ Ok=$false; Error="$_"; Count=0 }
        }
    } -ArgumentList $script:VulnDriverFeedUrl
    if ($script:State) { $script:State.VulnDriverJob = $job }
}

function Scan-ByovdDrivers {
    $hits = New-Object System.Collections.ArrayList
    try {
        $running = Get-CimInstance Win32_SystemDriver -Filter "State='Running'" -ErrorAction SilentlyContinue
        foreach ($d in $running) {
            if (-not $d.PathName) { continue }
            $name = (Split-Path $d.PathName -Leaf).ToLower() -replace '^\\\?\?\\',''
            # Curated hardcoded list wins on collision - its Vendor/CVE/Note metadata is richer.
            $info = $null
            if ($script:ByovdBlocklist.ContainsKey($name)) {
                $info = $script:ByovdBlocklist[$name]
            } elseif ($script:VulnDriverDynamic -and $script:VulnDriverDynamic.ContainsKey($name)) {
                $info = $script:VulnDriverDynamic[$name]
            }
            if ($info) {
                [void]$hits.Add([pscustomobject]@{
                    DriverName  = $name
                    Path        = $d.PathName
                    DisplayName = $d.DisplayName
                    Info        = $info
                })
            }
        }
    } catch {}
    return $hits
}

# ---------- Tier 13: auth-event monitor (Security log) ----------
# Samples Security log on a slow timer (>=30s between checks).
# Surfaces brute-force, Kerberoasting (RC4 service tickets), explicit credential use, privileged logon.
$script:AuthLastCheck     = $null
$script:AuthFailedRecent  = 0   # rolling count for findings panel
$script:AuthKerbRC4Recent = 0
$script:AuthPrivilegedRecent = 0

function Sample-AuthEvents {
    if (-not $script:IsAdmin) { return }
    $now = Get-Date
    if ($script:AuthLastCheck -and ($now - $script:AuthLastCheck).TotalSeconds -lt 30) { return }
    $since = if ($script:AuthLastCheck) { $script:AuthLastCheck } else { (Get-Date).AddMinutes(-5) }
    $script:AuthLastCheck = $now
    try {
        $events = Get-WinEvent -FilterHashtable @{LogName='Security'; StartTime=$since; Id=4624,4625,4648,4672,4768,4769} -MaxEvents 500 -ErrorAction SilentlyContinue
        if (-not $events) { return }

        # Failed logons (4625) - aggregate by source/account
        $failed = @($events | Where-Object Id -eq 4625)
        if ($failed.Count -gt 0) {
            $script:AuthFailedRecent = $failed.Count
            if ($failed.Count -ge 5) {
                $accounts = ($failed | ForEach-Object {
                    if ($_.Message -match 'Account Name:\s+(\S+)') { $matches[1] }
                } | Where-Object { $_ -and $_ -ne '-' } | Select-Object -Unique) -join ', '
                Add-Event warn ("Auth: {0} failed logon(s) since last check (accounts: {1})" -f $failed.Count, $accounts)
            }
        }

        # Kerberoasting / AS-REP roasting hint - 4769 with RC4 ticket encryption (0x17)
        $kerb = @($events | Where-Object { $_.Id -eq 4769 -and ($_.Message -match 'Ticket Encryption Type:\s+0x17') })
        if ($kerb.Count -gt 0) {
            $script:AuthKerbRC4Recent = $kerb.Count
            $svcs = ($kerb | ForEach-Object {
                if ($_.Message -match 'Service Name:\s+(\S+)') { $matches[1] }
            } | Where-Object { $_ } | Select-Object -Unique) -join ', '
            Add-Event warn ("Auth: {0} Kerberos service ticket(s) with RC4 (potential Kerberoasting): {1}" -f $kerb.Count, $svcs)
        }

        # Special privileges assigned (4672) - sudden privileged logon
        $priv = @($events | Where-Object Id -eq 4672)
        if ($priv.Count -gt 0) { $script:AuthPrivilegedRecent = $priv.Count }

        # Explicit credential use (4648) - lateral movement / pass-the-hash hint
        $expl = @($events | Where-Object Id -eq 4648)
        if ($expl.Count -ge 3) {
            Add-Event warn ("Auth: {0} explicit credential logons - possible lateral movement / pass-the-hash" -f $expl.Count)
        }
    } catch {}
}

# Findings-panel summary of recent auth health (called from Update-Findings)
function Get-AuthFindings {
    $r = New-Object System.Collections.Generic.List[object]
    if (-not $script:IsAdmin) {
        $r.Add((Add-Finding 'INFO' 'Auth' 'Auth event monitor disabled (HUD is not elevated). Re-launch via Run-NetJump.bat.' '' 'The Security event log requires Administrator to read. Without it we cannot detect failed logons, Kerberoasting, or privilege escalation.'))
        return $r
    }
    if ($script:AuthFailedRecent -ge 10) {
        $r.Add((Add-Finding 'FAIL' 'Auth' ("{0} failed logons observed in the last sample window - possible brute force." -f $script:AuthFailedRecent) `
            'Open Event Viewer -> Security log -> Event 4625 to identify source. Block source IP at firewall if remote.' `
            'Sustained 4625 events at this rate are usually a brute-force attempt against a service or RDP. The Account Name + Source Network Address fields in the event identify who.' `
            'unsigned-extern'))
    } elseif ($script:AuthFailedRecent -ge 3) {
        $r.Add((Add-Finding 'WARN' 'Auth' ("{0} failed logons since last sample." -f $script:AuthFailedRecent)))
    } else {
        $r.Add((Add-Finding 'OK' 'Auth' 'No abnormal failed-logon volume.'))
    }
    if ($script:AuthKerbRC4Recent -gt 0) {
        $r.Add((Add-Finding 'WARN' 'Auth' ("Kerberos service tickets with RC4 encryption: {0} (Kerberoasting indicator)." -f $script:AuthKerbRC4Recent) `
            'Verify that no service account is being attacked. Long-term: enforce AES-only via msDS-SupportedEncryptionTypes on service accounts.' `
            'Modern Kerberos uses AES. Attackers requesting service tickets with RC4 (0x17) are typically running Rubeus / Invoke-Kerberoast to extract a hash crackable offline.' `
            'unsigned-extern'))
    }
    return $r
}

# ---------- Tier 12: lockdown mode (firewall panic button) ----------
$script:LockdownDir = Join-Path $PSScriptRoot 'Reports\Lockdown'
if (-not (Test-Path $script:LockdownDir)) { New-Item -ItemType Directory -Path $script:LockdownDir -Force | Out-Null }

function Get-LockdownState {
    # Returns hashtable with .Active, .BackupPath
    $marker = Join-Path $script:LockdownDir 'lockdown-active.json'
    if (Test-Path $marker) {
        try {
            $s = Get-Content $marker -Raw | ConvertFrom-Json
            return @{ Active = $true; BackupPath = $s.backupPath; Started = $s.started }
        } catch {}
    }
    return @{ Active = $false; BackupPath = $null; Started = $null }
}

function Enable-Lockdown {
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, 'Lockdown requires Administrator.', 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    $cur = Get-LockdownState
    if ($cur.Active) {
        [System.Windows.MessageBox]::Show($window, 'Lockdown is already active.', 'Already on', 'OK', 'Information') | Out-Null
        return
    }
    $msg = "PANIC LOCKDOWN MODE`n`nThis will:`n  1. Back up your current Windows Defender Firewall ruleset`n  2. Set DefaultOutboundAction = BLOCK on Domain/Private/Public profiles`n  3. Add narrow allow rules for DNS, DHCP, Defender, ICMP and common browsers`n`nAfter this, ONLY whitelisted programs can reach the internet. Browsing inside Windows itself, file downloads, telemetry, anything else - all stopped until you click 'Disable lockdown'.`n`nYour current firewall ruleset is saved and will be fully restored on disable. Proceed?"
    $r = [System.Windows.MessageBox]::Show($window, $msg, 'Enable lockdown mode', 'YesNo', 'Warning')
    if ($r -ne 'Yes') { return }

    $stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
    $backup = Join-Path $script:LockdownDir ("firewall-backup-$stamp.wfw")
    try {
        & netsh advfirewall export "$backup" 2>&1 | Out-Null
        if (-not (Test-Path $backup)) { throw "netsh did not produce a backup file" }
    } catch {
        [System.Windows.MessageBox]::Show($window, "Firewall backup failed; aborting lockdown:`n$_", 'Error', 'OK', 'Error') | Out-Null
        return
    }

    try {
        Set-NetFirewallProfile -Profile Domain,Private,Public -DefaultOutboundAction Block -ErrorAction Stop

        # Allow DNS to current servers
        $dnsServers = @()
        Get-DnsClientServerAddress -AddressFamily IPv4 -ErrorAction SilentlyContinue |
            ForEach-Object { $dnsServers += $_.ServerAddresses } | Out-Null
        $dnsServers = $dnsServers | Sort-Object -Unique
        if ($dnsServers.Count -eq 0) { $dnsServers = @('1.1.1.1','8.8.8.8') }
        New-NetFirewallRule -DisplayName 'NetJump-Lockdown allow DNS' -Direction Outbound -Action Allow -Protocol UDP -RemotePort 53 -RemoteAddress $dnsServers | Out-Null

        # DHCP
        New-NetFirewallRule -DisplayName 'NetJump-Lockdown allow DHCP' -Direction Outbound -Action Allow -Protocol UDP -LocalPort 68 -RemotePort 67 | Out-Null

        # ICMP
        New-NetFirewallRule -DisplayName 'NetJump-Lockdown allow ICMPv4' -Direction Outbound -Action Allow -Protocol ICMPv4 | Out-Null

        # Defender + Windows Update via service-binary allowance
        $svchost = Join-Path $env:SystemRoot 'System32\svchost.exe'
        if (Test-Path $svchost) {
            New-NetFirewallRule -DisplayName 'NetJump-Lockdown allow svchost (Defender/Update)' -Direction Outbound -Action Allow -Program $svchost | Out-Null
        }

        # Common browsers (so the user isn't trapped offline)
        $browserPaths = @(
            (Join-Path $env:ProgramFiles 'Google\Chrome\Application\chrome.exe'),
            (Join-Path ${env:ProgramFiles(x86)} 'Google\Chrome\Application\chrome.exe'),
            (Join-Path $env:ProgramFiles 'Mozilla Firefox\firefox.exe'),
            (Join-Path ${env:ProgramFiles(x86)} 'Microsoft\Edge\Application\msedge.exe'),
            (Join-Path $env:ProgramFiles 'Microsoft\Edge\Application\msedge.exe')
        ) | Where-Object { $_ -and (Test-Path $_) } | Select-Object -Unique
        foreach ($b in $browserPaths) {
            New-NetFirewallRule -DisplayName ("NetJump-Lockdown allow {0}" -f (Split-Path $b -Leaf)) -Direction Outbound -Action Allow -Program $b | Out-Null
        }

        $marker = Join-Path $script:LockdownDir 'lockdown-active.json'
        @{ backupPath = $backup; started = (Get-Date).ToString('o'); allowedBrowsers = $browserPaths } | ConvertTo-Json | Set-Content $marker -Encoding UTF8

        Write-ActionAudit 'lockdown-enable' "backup=$backup" 'success' @{ browsers=$browserPaths; dns=$dnsServers }
        Add-Event fix "LOCKDOWN ACTIVE - backup at $(Split-Path $backup -Leaf), browsers + DNS allowed."
        Show-Toast -Title 'NetJump: lockdown ENABLED' -Message 'Outbound traffic is blocked except DNS, DHCP, ICMP, svchost and browsers. Click Disable lockdown to restore.' -Icon Warning
        Update-LockdownBadge
    } catch {
        Write-ActionAudit 'lockdown-enable' "backup=$backup" 'failure' "$_"
        Add-Event warn ("Lockdown enable failed: {0}" -f $_.Exception.Message)
        [System.Windows.MessageBox]::Show($window, "Lockdown enable failed:`n$_`n`nAttempting to restore from backup...", 'Error', 'OK', 'Error') | Out-Null
        # Tier 51: surface restore success/failure - if BOTH the enable AND the restore fail, the
        # firewall is in an unknown state and the user MUST be told to manually verify rules. Was
        # silent before, leaving users with potentially blocked browsers and no idea why.
        try {
            & netsh advfirewall import "$backup" 2>&1 | Out-Null
            if ($LASTEXITCODE -ne 0) {
                Add-Event warn ("Lockdown rollback FAILED (firewall left in indeterminate state) - manually verify rules: netsh advfirewall show currentprofile")
                [System.Windows.MessageBox]::Show($window, "ROLLBACK FAILED. Firewall rules may be in an inconsistent state.`n`nManually verify with:`n  netsh advfirewall show currentprofile`n`nIf needed, restore from:`n  $backup", 'Rollback failed', 'OK', 'Error') | Out-Null
            } else {
                Add-Event recovery 'Lockdown rollback OK - firewall restored from backup.'
            }
        } catch {
            Add-Event warn ("Lockdown rollback exception (firewall state unknown): {0}" -f $_.Exception.Message)
        }
    }
}

function Disable-Lockdown {
    if (-not $script:IsAdmin) { return }
    $cur = Get-LockdownState
    if (-not $cur.Active) {
        [System.Windows.MessageBox]::Show($window, 'Lockdown is not currently active.', 'Not active', 'OK', 'Information') | Out-Null
        return
    }
    $r = [System.Windows.MessageBox]::Show($window, "Restore firewall ruleset from`n$($cur.BackupPath)`n`nAll NetJump-Lockdown rules will be removed and your previous configuration restored. Proceed?", 'Disable lockdown', 'YesNo', 'Question')
    if ($r -ne 'Yes') { return }
    try {
        Get-NetFirewallRule -DisplayName 'NetJump-Lockdown*' -ErrorAction SilentlyContinue | Remove-NetFirewallRule -ErrorAction SilentlyContinue
        if (Test-Path $cur.BackupPath) {
            & netsh advfirewall import "$($cur.BackupPath)" 2>&1 | Out-Null
        }
        $marker = Join-Path $script:LockdownDir 'lockdown-active.json'
        if (Test-Path $marker) { Remove-Item $marker -Force }
        Write-ActionAudit 'lockdown-disable' "backup=$($cur.BackupPath)" 'success'
        Add-Event recovery 'Lockdown lifted - firewall ruleset restored.'
        Show-Toast -Title 'NetJump: lockdown DISABLED' -Message 'Firewall ruleset restored from backup.' -Icon Info
        Update-LockdownBadge
    } catch {
        Write-ActionAudit 'lockdown-disable' "backup=$($cur.BackupPath)" 'failure' "$_"
        [System.Windows.MessageBox]::Show($window, "Lockdown restore failed:`n$_", 'Error', 'OK', 'Error') | Out-Null
    }
}

# ---------- Tier 24: LOCAL NET INFO sidebar (IP/MAC/DHCP/lease + reset actions) ----------
# Pulls everything off the currently selected adapter via Get-NetAdapter / Get-NetIPAddress /
# Get-NetIPConfiguration. PUBLIC IP is fetched lazily (HTTP call) and cached for 60s so we
# don't hammer api.ipify on every refresh.
$script:PublicIpCache = @{ Value = $null; Fetched = $null }

function Get-PublicIpCached {
    # Return cached value if <60s old, otherwise refresh once
    if ($script:PublicIpCache.Fetched -and ((Get-Date) - $script:PublicIpCache.Fetched).TotalSeconds -lt 60 -and $script:PublicIpCache.Value) {
        return $script:PublicIpCache.Value
    }
    try {
        $r = Invoke-RestMethod 'https://api.ipify.org?format=json' -TimeoutSec 3 -ErrorAction Stop
        $ip = [string]$r.ip
        if ($ip) {
            $script:PublicIpCache.Value = $ip
            $script:PublicIpCache.Fetched = Get-Date
            return $ip
        }
    } catch {
        # Tier 50: surface the lookup failure to LIVE EVENTS so the user knows why "Public" stays
        # blank. Rate-limited via $script:LastPublicIpErrorAt so a network outage doesn't spam.
        try {
            if (-not $script:LastPublicIpErrorAt -or ((Get-Date) - $script:LastPublicIpErrorAt).TotalMinutes -gt 5) {
                $script:LastPublicIpErrorAt = Get-Date
                Add-Event warn ("Public IP lookup failed: {0}" -f $_.Exception.Message)
            }
        } catch {}
    }
    return $null
}

# ---------- Wi-Fi metrics ----------
# Parses `netsh wlan show interfaces` output for the connected wireless interface that matches
# $AdapterName. Returns a hashtable with SSID/BSSID/Channel/Signal/Auth/Radio/Rx/Tx fields, or
# $null if no matching wireless interface is connected. Cheap enough to call on the same cadence
# as Update-LocalNetInfo (every few seconds when the sidebar is visible).
function Get-WifiInfo {
    param([string]$AdapterName)
    if (-not $AdapterName) { return $null }
    try {
        $out = (& netsh wlan show interfaces 2>$null | Out-String)
        if (-not $out -or $out -match 'There is no wireless interface') { return $null }
        # Split into per-interface blocks; each block starts at a "Name : ..." line.
        $blocks = $out -split '(?m)^\s*Name\s*:\s*'
        $info = $null
        foreach ($b in $blocks) {
            if (-not $b -or $b -notmatch ':') { continue }
            $firstLine = ($b -split '\r?\n')[0].Trim()
            if (-not $firstLine) { continue }
            if ($AdapterName -and $firstLine -ne $AdapterName) { continue }
            $info = @{ Name = $firstLine }
            $fields = @{
                SSID    = 'SSID'
                BSSID   = 'BSSID'
                State   = 'State'
                Radio   = 'Radio type'
                Auth    = 'Authentication'
                Cipher  = 'Cipher'
                Channel = 'Channel'
                Signal  = 'Signal'
                RxMbps  = 'Receive rate \(Mbps\)'
                TxMbps  = 'Transmit rate \(Mbps\)'
                Profile = 'Profile'
            }
            foreach ($k in $fields.Keys) {
                $pat = '(?m)^\s*' + $fields[$k] + '\s*:\s*(.+?)\s*$'
                if ($b -match $pat) { $info[$k] = $matches[1].Trim() }
            }
            break
        }
        if ($info -and $info.Signal -and $info.Signal -match '(\d+)%') {
            $pct = [int]$matches[1]
            $info.SignalPct = $pct
            # Rough dBm conversion: Microsoft maps -100 dBm => 0%, -50 dBm => 100% linearly.
            $info.SignalDbm = [int](($pct / 2.0) - 100)
            # 4-bar gauge for the UI
            $info.Bars = if ($pct -ge 76) { 4 } elseif ($pct -ge 51) { 3 } elseif ($pct -ge 26) { 2 } else { 1 }
        }
        return $info
    } catch { return $null }
}

# Cached because netsh wlan can take 100-300ms; refresh once per ~3 sec is plenty for the UI.
$script:WifiCache = @{ At = [DateTime]::MinValue; Info = $null }
function Get-WifiInfoCached {
    param([string]$AdapterName)
    if (((Get-Date) - $script:WifiCache.At).TotalSeconds -lt 3) { return $script:WifiCache.Info }
    $info = Get-WifiInfo -AdapterName $AdapterName
    $script:WifiCache.At = Get-Date
    $script:WifiCache.Info = $info
    return $info
}

function Update-LocalNetInfo {
    if (-not $controls -or -not $controls.LocalIpv4Text) { return }
    $a = $script:State.Adapter
    if (-not $a) {
        $controls.LocalAdapterText.Text = '(no adapter selected)'
        return
    }
    $controls.LocalAdapterText.Text = [string]$a.Name

    # MAC address - normalise dashes -> colons for readability
    try {
        $mac = [string]$a.MacAddress
        if ($mac) { $mac = $mac.Replace('-', ':') }
        $controls.LocalMacText.Text = if ($mac) { $mac } else { '--' }
    } catch { $controls.LocalMacText.Text = '--' }

    # IPv4 + mask via prefix length
    try {
        $ipObj = Get-NetIPAddress -InterfaceIndex $a.ifIndex -AddressFamily IPv4 -ErrorAction SilentlyContinue |
                 Where-Object { $_.AddressState -eq 'Preferred' -and $_.IPAddress -notlike '169.254.*' } |
                 Select-Object -First 1
        if ($ipObj) {
            $controls.LocalIpv4Text.Text = [string]$ipObj.IPAddress
            $prefix = [int]$ipObj.PrefixLength
            $maskInt = ([uint32]4294967295) -shl (32 - $prefix)
            $b1 = ($maskInt -shr 24) -band 0xff
            $b2 = ($maskInt -shr 16) -band 0xff
            $b3 = ($maskInt -shr 8)  -band 0xff
            $b4 = $maskInt           -band 0xff
            $controls.LocalMaskText.Text = ("{0}.{1}.{2}.{3} (/{4})" -f $b1, $b2, $b3, $b4, $prefix)
        } else {
            $controls.LocalIpv4Text.Text = '(none)'
            $controls.LocalMaskText.Text = '--'
        }
    } catch {
        $controls.LocalIpv4Text.Text = '(error)'
        $controls.LocalMaskText.Text = '--'
    }

    # Gateway + DNS via Get-NetIPConfiguration (single call gives both)
    try {
        $cfg = Get-NetIPConfiguration -InterfaceIndex $a.ifIndex -ErrorAction SilentlyContinue
        $gw = $null
        if ($cfg -and $cfg.IPv4DefaultGateway) {
            $gw = ($cfg.IPv4DefaultGateway | Select-Object -First 1).NextHop
        }
        $controls.LocalGwText.Text = if ($gw) { [string]$gw } else { '(none)' }

        if ($cfg -and $cfg.DNSServer) {
            $dns = @($cfg.DNSServer | Where-Object { $_.AddressFamily -eq 2 } | ForEach-Object { $_.ServerAddresses } | Where-Object { $_ })
            if ($dns.Count -eq 0) { $dns = @($cfg.DNSServer | ForEach-Object { $_.ServerAddresses } | Where-Object { $_ -match '^\d+\.\d+\.\d+\.\d+$' }) }
            $controls.LocalDnsText.Text = if ($dns.Count -gt 0) { ($dns -join ', ') } else { '(none)' }
        } else {
            $controls.LocalDnsText.Text = '--'
        }
    } catch {
        $controls.LocalGwText.Text = '(error)'
        $controls.LocalDnsText.Text = '(error)'
    }

    # DHCP server + lease via WMI Win32_NetworkAdapterConfiguration (CIM)
    try {
        $cim = Get-CimInstance -ClassName Win32_NetworkAdapterConfiguration -ErrorAction SilentlyContinue |
               Where-Object { $_.InterfaceIndex -eq $a.ifIndex } | Select-Object -First 1
        if ($cim) {
            if ([bool]$cim.DHCPEnabled) {
                $controls.LocalDhcpText.Text = if ($cim.DHCPServer) { [string]$cim.DHCPServer } else { '(enabled)' }
                # Lease = expiry - now
                if ($cim.DHCPLeaseExpires) {
                    try {
                        $exp = $cim.DHCPLeaseExpires
                        $remain = $exp - (Get-Date)
                        if ($remain.TotalSeconds -le 0) {
                            $controls.LocalLeaseText.Text = 'expired'
                        } elseif ($remain.TotalDays -ge 1) {
                            $controls.LocalLeaseText.Text = ("{0}d {1}h" -f [int]$remain.TotalDays, $remain.Hours)
                        } elseif ($remain.TotalHours -ge 1) {
                            $controls.LocalLeaseText.Text = ("{0}h {1}m" -f [int]$remain.TotalHours, $remain.Minutes)
                        } else {
                            $controls.LocalLeaseText.Text = ("{0}m" -f [int]$remain.TotalMinutes)
                        }
                    } catch { $controls.LocalLeaseText.Text = '--' }
                } else {
                    $controls.LocalLeaseText.Text = '--'
                }
            } else {
                $controls.LocalDhcpText.Text = 'static'
                $controls.LocalLeaseText.Text = 'n/a'
            }
        }
    } catch {
        $controls.LocalDhcpText.Text = '(error)'
        $controls.LocalLeaseText.Text = '--'
    }

    # Public IP - cached, refreshed lazily
    try {
        $pub = Get-PublicIpCached
        $controls.LocalPublicIpText.Text = if ($pub) { $pub } else { '(checking...)' }
    } catch { $controls.LocalPublicIpText.Text = '--' }

    # Tier 31: link MTU + computed MSS + last path-MTU probe result
    try {
        $linkMtu = $null
        try {
            $iface = Get-NetIPInterface -InterfaceIndex $a.ifIndex -AddressFamily IPv4 -ErrorAction SilentlyContinue | Select-Object -First 1
            if ($iface -and $iface.NlMtu) { $linkMtu = [int]$iface.NlMtu }
        } catch {}

        if ($linkMtu) {
            # Path MTU annotation - if we've probed, show "1500 link / 1492 path"
            $lp = $script:State.LastPathMtu
            if ($lp -and $lp.Success -and $lp.Mtu) {
                $delta = $linkMtu - [int]$lp.Mtu
                if ($delta -gt 0) {
                    $controls.LocalMtuText.Text = ("{0} link / {1} path  (-{2})" -f $linkMtu, $lp.Mtu, $delta)
                } else {
                    $controls.LocalMtuText.Text = ("{0} link / {1} path" -f $linkMtu, $lp.Mtu)
                }
            } else {
                $controls.LocalMtuText.Text = ("{0} link  (no path probe yet)" -f $linkMtu)
            }
            # MSS = MTU - 40 (IPv4 header 20 + TCP header 20). Use whichever is lower of link/path.
            $mssBaseMtu = $linkMtu
            if ($lp -and $lp.Success -and $lp.Mtu -and [int]$lp.Mtu -lt $linkMtu) { $mssBaseMtu = [int]$lp.Mtu }
            $mss = $mssBaseMtu - 40
            $controls.LocalMssText.Text = ("{0} bytes  (= {1} - 40)" -f $mss, $mssBaseMtu)
        } else {
            $controls.LocalMtuText.Text = '(unknown)'
            $controls.LocalMssText.Text = '--'
        }
    } catch {
        $controls.LocalMtuText.Text = '(error)'
        $controls.LocalMssText.Text = '--'
    }

    # ---- Wi-Fi block. Shown only when the adapter is wireless. ----
    if ($controls.LocalWifiPanel) {
        $isWireless = $false
        try {
            if ($a.PhysicalMediaType -and ($a.PhysicalMediaType -match 'Wireless|802\.11')) { $isWireless = $true }
            elseif ($a.InterfaceType -and ($a.InterfaceType -eq 71)) { $isWireless = $true }   # 71 = IEEE 802.11
        } catch {}
        if ($isWireless) {
            $wifi = Get-WifiInfoCached -AdapterName ([string]$a.Name)
            if ($wifi) {
                $controls.LocalWifiSsidText.Text  = if ($wifi.SSID)    { [string]$wifi.SSID }    else { '(not associated)' }
                $controls.LocalWifiBssidText.Text = if ($wifi.BSSID)   { [string]$wifi.BSSID }   else { '--' }
                $chParts = @()
                if ($wifi.Channel) { $chParts += [string]$wifi.Channel }
                if ($wifi.Radio)   { $chParts += [string]$wifi.Radio }
                $controls.LocalWifiChanText.Text = if ($chParts.Count -gt 0) { $chParts -join ' / ' } else { '--' }
                if ($wifi.SignalPct) {
                    $bars = '▮' * [int]$wifi.Bars + '▯' * (4 - [int]$wifi.Bars)
                    $controls.LocalWifiSignalText.Text = ("{0}  ({1}% / ~{2} dBm)" -f $bars, $wifi.SignalPct, $wifi.SignalDbm)
                    # Color-code: green >=76%, amber 51-75%, red <=50%
                    $sigColor = if ($wifi.SignalPct -ge 76) { '#3fb950' } elseif ($wifi.SignalPct -ge 51) { '#d29922' } else { '#f85149' }
                    try { $controls.LocalWifiSignalText.Foreground = $window.Resources['BrushFgPrimary'] } catch {}
                    try { $controls.LocalWifiSignalText.Foreground = (New-Object System.Windows.Media.SolidColorBrush ([System.Windows.Media.ColorConverter]::ConvertFromString($sigColor))) } catch {}
                } else {
                    $controls.LocalWifiSignalText.Text = '--'
                }
                $authParts = @()
                if ($wifi.Auth)   { $authParts += [string]$wifi.Auth }
                if ($wifi.Cipher) { $authParts += [string]$wifi.Cipher }
                $controls.LocalWifiAuthText.Text = if ($authParts.Count -gt 0) { $authParts -join ' / ' } else { '--' }
            } else {
                $controls.LocalWifiSsidText.Text  = '(no data - run as admin?)'
                $controls.LocalWifiBssidText.Text = '--'
                $controls.LocalWifiChanText.Text  = '--'
                $controls.LocalWifiSignalText.Text= '--'
                $controls.LocalWifiAuthText.Text  = '--'
            }
            $controls.LocalWifiPanel.Visibility = 'Visible'
        } else {
            $controls.LocalWifiPanel.Visibility = 'Collapsed'
        }
    }
}

function Invoke-RenewDhcpLease {
    if (-not $script:State.Adapter) { return }
    $aname = $script:State.Adapter.Name
    $msg = "RENEW DHCP LEASE on '$aname'`n`nThis will:`n  1. ipconfig /release  (drops your current IPv4)`n  2. ipconfig /renew   (requests a new lease from DHCP)`n`nNetwork connectivity briefly drops (~2-5 sec). Active TCP connections to LAN/WAN may reset.`n`nProceed?"
    $r = [System.Windows.MessageBox]::Show($window, $msg, 'Renew DHCP lease', 'YesNo', 'Question')
    if ($r -ne 'Yes') { return }
    if ($controls.LocalInfoStatus) { $controls.LocalInfoStatus.Text = 'Renewing... (network briefly down)' }
    try {
        & ipconfig /release "$aname" 2>&1 | Out-Null
        Start-Sleep -Milliseconds 500
        & ipconfig /renew "$aname" 2>&1 | Out-Null
        Add-Event fix ("DHCP lease renewed on '{0}' (release+renew)" -f $aname)
        Write-ActionAudit 'dhcp-renew' "adapter=$aname" 'success'
        if ($controls.LocalInfoStatus) { $controls.LocalInfoStatus.Text = ("Renewed at {0}" -f (Get-Date -Format 'HH:mm:ss')) }
    } catch {
        Add-Event warn ("DHCP renew failed: {0}" -f $_.Exception.Message)
        Write-ActionAudit 'dhcp-renew' "adapter=$aname" 'failure' "$_"
        if ($controls.LocalInfoStatus) { $controls.LocalInfoStatus.Text = "Renew failed: $($_.Exception.Message)" }
    }
    Update-LocalNetInfo
}

function Invoke-FlushArpCache {
    $msg = "FLUSH ARP CACHE`n`nThis clears the kernel's ARP table - the IPv4 -> MAC mappings cached for the LAN. Forces re-discovery of every neighbour on the next packet to them.`n`nUseful when:`n  * Switching VLANs / VPNs and old MAC mappings are stale`n  * Suspecting ARP poisoning`n  * After replacing a router/switch`n`nNo connectivity drop. Quick (~50ms). Proceed?"
    $r = [System.Windows.MessageBox]::Show($window, $msg, 'Flush ARP cache', 'YesNo', 'Question')
    if ($r -ne 'Yes') { return }
    try {
        & netsh interface ip delete arpcache 2>&1 | Out-Null
        Add-Event fix 'ARP cache flushed (netsh interface ip delete arpcache)'
        Write-ActionAudit 'arp-flush' '' 'success'
        if ($controls.LocalInfoStatus) { $controls.LocalInfoStatus.Text = ("ARP flushed at {0}" -f (Get-Date -Format 'HH:mm:ss')) }
    } catch {
        Add-Event warn ("ARP flush failed: {0}" -f $_.Exception.Message)
        if ($controls.LocalInfoStatus) { $controls.LocalInfoStatus.Text = "ARP flush failed: $($_.Exception.Message)" }
    }
}

function Invoke-ResetTcpIpStack {
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, 'Resetting the TCP/IP stack requires Administrator.', 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    $msg = @"
RESET TCP/IP STACK

This is the heaviest reset short of re-imaging:
  1. netsh int ip reset       (resets TCP/IP registry config to defaults)
  2. netsh winsock reset      (resets the Winsock catalog - removes 3rd-party LSPs)

EFFECTS:
  * Custom static IPs are LOST (DHCP becomes the new default)
  * 3rd-party LSPs (some VPN, AV, parental controls) are unhooked
  * REBOOT REQUIRED for changes to take full effect
  * Use this only after pinpoint fixes (ipconfig /flushdns, /renew) have failed

Proceed?
"@
    $r = [System.Windows.MessageBox]::Show($window, $msg, 'Reset TCP/IP stack (heavy)', 'YesNo', 'Warning')
    if ($r -ne 'Yes') { return }
    try {
        & netsh int ip reset 2>&1 | Out-Null
        & netsh winsock reset 2>&1 | Out-Null
        Add-Event fix 'TCP/IP stack reset (netsh int ip reset + winsock reset). REBOOT REQUIRED.'
        Write-ActionAudit 'tcpip-reset' '' 'success'
        [System.Windows.MessageBox]::Show($window, 'Reset complete. REBOOT REQUIRED for changes to take effect.', 'Reset complete', 'OK', 'Information') | Out-Null
        if ($controls.LocalInfoStatus) { $controls.LocalInfoStatus.Text = 'Reset complete - reboot required.' }
    } catch {
        Add-Event warn ("TCP/IP reset failed: {0}" -f $_.Exception.Message)
        Write-ActionAudit 'tcpip-reset' '' 'failure' "$_"
        [System.Windows.MessageBox]::Show($window, "Reset failed:`n$_", 'Error', 'OK', 'Error') | Out-Null
    }
}

function Update-LockdownBadge {
    if (-not $controls -or -not $controls.LockdownBadge) { return }
    $cur = Get-LockdownState
    if ($cur.Active) {
        $controls.LockdownBadge.Visibility = 'Visible'
        $controls.LockdownText.Text = 'LOCKDOWN ACTIVE'
    } else {
        $controls.LockdownBadge.Visibility = 'Collapsed'
    }
}

# ---------- Tier 23: NETWORK KILL-SWITCH (true nuclear option) ----------
# Difference vs Lockdown:
#   * Lockdown uses Windows Firewall to BLOCK outbound but ALLOWS DNS/DHCP/ICMP/svchost/browsers.
#   * Kill-switch DISABLES ALL NETWORK ADAPTERS - no traffic of any kind, no exceptions.
#     Adapter disable is enforced at the NDIS layer so even firewall-bypassing tunnels (raw sockets,
#     kernel drivers like VPN clients) cannot reach the network. This is the "rip the cable out"
#     equivalent in software, with a one-click revert.
$script:KillSwitchMarker = Join-Path $script:LockdownDir 'killswitch-active.json'

function Get-KillSwitchState {
    if (Test-Path $script:KillSwitchMarker) {
        try {
            $s = Get-Content $script:KillSwitchMarker -Raw -Encoding UTF8 | ConvertFrom-Json
            return @{
                Active            = $true
                Started           = $s.started
                DisabledAdapters  = @($s.disabledAdapters)
                FirewallBackup    = $s.firewallBackup
                PrevDefaultOut    = $s.prevDefaultOut
                PrevDefaultIn     = $s.prevDefaultIn
            }
        } catch {}
    }
    return @{ Active = $false }
}

function Invoke-NetworkKillSwitch {
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, "NETWORK KILL-SWITCH requires Administrator.`n`nRe-launch via Run-NetJump.bat (which prompts for elevation).", 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    $cur = Get-KillSwitchState
    if ($cur.Active) {
        [System.Windows.MessageBox]::Show($window, 'Kill-switch is already active. Click REVERT to restore connectivity.', 'Already active', 'OK', 'Information') | Out-Null
        return
    }

    # Snapshot which adapters are currently UP (those are the ones we'll disable + revert)
    $upAdapters = @(Get-NetAdapter -ErrorAction SilentlyContinue | Where-Object { $_.Status -eq 'Up' })
    if ($upAdapters.Count -eq 0) {
        [System.Windows.MessageBox]::Show($window, 'No active network adapters detected. Nothing to disable.', 'Already offline', 'OK', 'Information') | Out-Null
        return
    }
    $adapterList = ($upAdapters | ForEach-Object { "  - $($_.Name)  ($($_.InterfaceDescription))" }) -join "`n"

    # Big two-stage warning - first dialog explains what happens, second is the final go/no-go
    $msg1 = @"
NETWORK KILL-SWITCH

You are about to:

  1. DISABLE every active network adapter on this PC:
$adapterList

  2. SET the Windows Firewall outbound default to BLOCK on every profile (belt-and-suspenders).

  3. BACK UP your firewall ruleset to a .wfw file so REVERT can restore it.

EFFECTS:
  * ALL network traffic stops instantly: web, email, Slack/Teams, OneDrive sync, VPN tunnels,
    background telemetry, Windows Update, remote desktop sessions, network shares - everything.
  * Streaming media disconnects mid-stream. Unsaved work in cloud apps may be lost.
  * Any active SSH / RDP session you are using to reach this machine WILL DROP. If this is your
    only access path, do NOT proceed.
  * Software that depends on a license server check-in (some Adobe, AutoDesk, etc.) may go
    offline-restricted until you revert.
  * BitLocker-To-Go and EFS file access are unaffected (those are local).

REVERT:
  Click the green REVERT button. Adapters re-enable, firewall restores from backup. Tested
  recovery time: ~2-5 seconds.

Proceed to the final confirmation?
"@
    $r1 = [System.Windows.MessageBox]::Show($window, $msg1, 'Network kill-switch (1/2)', 'OKCancel', 'Warning')
    if ($r1 -ne 'OK') { Add-Event info 'Kill-switch cancelled at first prompt.'; return }

    $r2 = [System.Windows.MessageBox]::Show($window, "FINAL CONFIRMATION`n`nClick YES to disable all network adapters NOW.`n`nClick NO to abort.", 'Network kill-switch (2/2)', 'YesNo', 'Stop')
    if ($r2 -ne 'Yes') { Add-Event info 'Kill-switch cancelled at final prompt.'; return }

    # Snapshot firewall default actions BEFORE we change anything
    $prevDefaultOut = $null
    $prevDefaultIn  = $null
    try {
        $profiles = Get-NetFirewallProfile -ErrorAction SilentlyContinue
        $prevDefaultOut = @{}
        $prevDefaultIn  = @{}
        foreach ($p in $profiles) {
            $prevDefaultOut[$p.Name] = [string]$p.DefaultOutboundAction
            $prevDefaultIn[$p.Name]  = [string]$p.DefaultInboundAction
        }
    } catch {}

    # Backup firewall config to .wfw
    $stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
    $backup = Join-Path $script:LockdownDir ("killswitch-fw-backup-$stamp.wfw")
    try {
        & netsh advfirewall export "$backup" 2>&1 | Out-Null
        if (-not (Test-Path $backup)) { throw "netsh did not produce a backup file at $backup" }
    } catch {
        [System.Windows.MessageBox]::Show($window, "Firewall backup failed; ABORTING kill-switch:`n$_", 'Error', 'OK', 'Error') | Out-Null
        return
    }

    $disabledAdapters = @()
    $errors = @()

    # Belt-and-suspenders: set firewall outbound to block FIRST. If adapter disable fails for some
    # reason (e.g. DC-Wi-Fi card refuses), at least firewall is already cutting traffic.
    try {
        Set-NetFirewallProfile -Profile Domain,Private,Public -DefaultOutboundAction Block -DefaultInboundAction Block -ErrorAction Stop
        Add-Event fix 'Firewall set to BLOCK on all profiles (belt-and-suspenders).'
    } catch {
        $errors += "Firewall block: $($_.Exception.Message)"
    }

    # Disable each adapter
    foreach ($a in $upAdapters) {
        try {
            Disable-NetAdapter -Name $a.Name -Confirm:$false -ErrorAction Stop
            $disabledAdapters += $a.Name
            Add-Event fix ("Adapter disabled: {0}" -f $a.Name)
        } catch {
            $errors += "Disable '$($a.Name)': $($_.Exception.Message)"
        }
    }

    # Persist state for revert
    $state = @{
        active            = $true
        started           = (Get-Date).ToString('o')
        disabledAdapters  = $disabledAdapters
        firewallBackup    = $backup
        prevDefaultOut    = $prevDefaultOut
        prevDefaultIn     = $prevDefaultIn
    }
    try {
        $state | ConvertTo-Json -Depth 5 | Set-Content -LiteralPath $script:KillSwitchMarker -Encoding UTF8 -ErrorAction Stop
    } catch {
        # Even if marker write fails, adapters are already off - tell user via BOTH a MessageBox
        # AND the events feed (Tier 51) so the warning is preserved if the user dismisses the box
        # without reading it. Critical: without the marker, REVERT can't auto-restore.
        try { Add-Event warn ("KILL-SWITCH state file failed to save - REVERT may need manual recovery: {0}" -f $_.Exception.Message) } catch {}
        [System.Windows.MessageBox]::Show($window, "WARNING: kill-switch state file failed to save.`nAdapters are disabled but REVERT may need to be done manually:`n  Get-NetAdapter | Enable-NetAdapter`n`nError: $_", 'State save failed', 'OK', 'Warning') | Out-Null
    }

    Write-ActionAudit 'killswitch-enable' ("adapters={0} backup={1}" -f ($disabledAdapters -join ','), $backup) `
        $(if ($errors.Count -eq 0) { 'success' } else { 'partial' }) `
        @{ adapters = $disabledAdapters; errors = $errors }

    Add-Event fix ("KILL-SWITCH ACTIVE - {0} adapter(s) disabled, firewall blocked. Click REVERT to restore." -f $disabledAdapters.Count)
    Show-Toast -Title 'NetJump: NETWORK KILL-SWITCH ENGAGED' -Message ("{0} adapter(s) disabled. Click REVERT in the dashboard to restore." -f $disabledAdapters.Count) -Icon Warning

    if ($errors.Count -gt 0) {
        [System.Windows.MessageBox]::Show($window, ("Kill-switch engaged with {0} error(s):`n`n{1}" -f $errors.Count, ($errors -join "`n")), 'Partial result', 'OK', 'Warning') | Out-Null
    }

    Update-KillSwitchUI
}

function Revert-NetworkKillSwitch {
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, 'Revert requires Administrator.', 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    $cur = Get-KillSwitchState
    if (-not $cur.Active) {
        [System.Windows.MessageBox]::Show($window, 'Kill-switch is not currently active.', 'Nothing to revert', 'OK', 'Information') | Out-Null
        Update-KillSwitchUI
        return
    }

    $errors = @()

    # Re-enable adapters first so connectivity returns ASAP
    foreach ($name in @($cur.DisabledAdapters)) {
        try {
            Enable-NetAdapter -Name $name -Confirm:$false -ErrorAction Stop
            Add-Event recovery ("Adapter re-enabled: {0}" -f $name)
        } catch {
            $errors += "Enable '$name': $($_.Exception.Message)"
        }
    }

    # Restore firewall: prefer the backup (most reliable), fall back to setting defaults
    if ($cur.FirewallBackup -and (Test-Path $cur.FirewallBackup)) {
        try {
            & netsh advfirewall import "$($cur.FirewallBackup)" 2>&1 | Out-Null
            Add-Event recovery ("Firewall restored from backup: {0}" -f (Split-Path $cur.FirewallBackup -Leaf))
        } catch {
            $errors += "Firewall import: $($_.Exception.Message)"
            # Fallback - reset to defaults
            try {
                if ($cur.PrevDefaultOut) {
                    foreach ($prof in $cur.PrevDefaultOut.PSObject.Properties) {
                        Set-NetFirewallProfile -Profile $prof.Name -DefaultOutboundAction $prof.Value -ErrorAction SilentlyContinue
                    }
                }
                if ($cur.PrevDefaultIn) {
                    foreach ($prof in $cur.PrevDefaultIn.PSObject.Properties) {
                        Set-NetFirewallProfile -Profile $prof.Name -DefaultInboundAction $prof.Value -ErrorAction SilentlyContinue
                    }
                }
            } catch { $errors += "Firewall fallback: $($_.Exception.Message)" }
        }
    } else {
        # No backup - reset firewall to allow outbound (the safe default)
        try {
            Set-NetFirewallProfile -Profile Domain,Private,Public -DefaultOutboundAction Allow -ErrorAction Stop
            Add-Event recovery 'Firewall outbound restored to Allow (no backup file found).'
        } catch { $errors += "Firewall reset: $($_.Exception.Message)" }
    }

    # Clear state file
    try {
        if (Test-Path $script:KillSwitchMarker) { Remove-Item $script:KillSwitchMarker -Force -ErrorAction Stop }
    } catch { $errors += "State file cleanup: $($_.Exception.Message)" }

    Write-ActionAudit 'killswitch-revert' ("adapters={0}" -f (@($cur.DisabledAdapters) -join ',')) `
        $(if ($errors.Count -eq 0) { 'success' } else { 'partial' }) `
        @{ errors = $errors }

    if ($errors.Count -eq 0) {
        Add-Event recovery ("Kill-switch reverted - {0} adapter(s) re-enabled, firewall restored." -f @($cur.DisabledAdapters).Count)
        Show-Toast -Title 'NetJump: kill-switch REVERTED' -Message 'Network connectivity restored.' -Icon Info
    } else {
        Add-Event warn ("Kill-switch revert had {0} error(s). Manual cleanup may be needed." -f $errors.Count)
        [System.Windows.MessageBox]::Show($window, ("Revert completed with {0} error(s):`n`n{1}" -f $errors.Count, ($errors -join "`n")), 'Partial result', 'OK', 'Warning') | Out-Null
    }

    Update-KillSwitchUI
}

# Tri-state kill-switch panel (Tier 34 redesign):
#   - GREYED (no scan run yet)              -> ARM strip visible, button disabled, all greys
#   - RED ARMED (scan complete, kill off)   -> ARM strip visible, button enabled, red theme
#   - GREEN ACTIVE (kill switch on)         -> REVERT strip visible, green DISENGAGE button
# The whole strip stays visible at all times now (was previously hidden until first scan) so
# the user always sees the kill switch is part of the workflow.
function Update-KillSwitchUI {
    if (-not $controls -or -not $controls.KillSwitchPanel) { return }
    $cur = Get-KillSwitchState
    $controls.KillSwitchPanel.Visibility = 'Visible'

    if ($cur.Active) {
        # GREEN ACTIVE - kill switch is engaged, show DISENGAGE button
        $controls.KillSwitchArmHost.Visibility = 'Collapsed'
        $controls.KillSwitchRevertHost.Visibility = 'Visible'
        try {
            $stamp = if ($cur.Started) { ([DateTime]$cur.Started).ToString('HH:mm:ss') } else { '?' }
            $adCount = @($cur.DisabledAdapters).Count
            $adNames = if ($adCount -gt 0) { @($cur.DisabledAdapters) -join ', ' } else { '?' }
            $controls.KillSwitchRevertSubtext.Text = ("Engaged at {0}. Disabled: {1}. Firewall: BLOCK." -f $stamp, $adNames)
        } catch {}
        return
    }

    # ARM strip visible
    $controls.KillSwitchArmHost.Visibility = 'Visible'
    $controls.KillSwitchRevertHost.Visibility = 'Collapsed'

    if ([bool]$script:State.HasScanned) {
        # RED ARMED - scan has completed, enable the button and apply red theme
        $controls.KillSwitchArmHost.Background  = (B '#3a0a0c')
        $controls.KillSwitchArmHost.BorderBrush = (B '#f85149')
        if ($controls.KillSwitchIcon) {
            $controls.KillSwitchIcon.Foreground = (B '#f85149')
        }
        if ($controls.KillSwitchLabel) {
            $controls.KillSwitchLabel.Text       = 'KILL-SWITCH ARMED'
            $controls.KillSwitchLabel.Foreground = (B '#f85149')
        }
        if ($controls.KillSwitchSubtext) {
            $controls.KillSwitchSubtext.Text       = 'Scan complete - click ENGAGE to cut all network traffic. DISENGAGE restores it.'
            $controls.KillSwitchSubtext.Foreground = (B '#ffd6d6')
        }
        if ($controls.KillSwitchArmBtn) {
            $controls.KillSwitchArmBtn.IsEnabled  = $true
            $controls.KillSwitchArmBtn.Background = (B '#b91c1c')
            $controls.KillSwitchArmBtn.Foreground = (B '#ffffff')
            $controls.KillSwitchArmBtn.BorderBrush = (B '#f85149')
        }
    } else {
        # GREYED - no scan yet, disable the button and apply muted theme
        $controls.KillSwitchArmHost.Background  = (B '#1a1a1a')
        $controls.KillSwitchArmHost.BorderBrush = (B '#3a3a3a')
        if ($controls.KillSwitchIcon) {
            $controls.KillSwitchIcon.Foreground = (B '#6a7380')
        }
        if ($controls.KillSwitchLabel) {
            $controls.KillSwitchLabel.Text       = 'KILL-SWITCH'
            $controls.KillSwitchLabel.Foreground = (B '#6a7380')
        }
        if ($controls.KillSwitchSubtext) {
            $controls.KillSwitchSubtext.Text       = 'Run a diagnostic scan first to arm'
            $controls.KillSwitchSubtext.Foreground = (B '#6a7380')
        }
        if ($controls.KillSwitchArmBtn) {
            $controls.KillSwitchArmBtn.IsEnabled  = $false
            $controls.KillSwitchArmBtn.Background = (B '#3a3a3a')
            $controls.KillSwitchArmBtn.Foreground = (B '#6a7380')
            $controls.KillSwitchArmBtn.BorderBrush = (B '#4a4a4a')
        }
    }
}

# ---------- Tier 17: unattended background monitor ----------
$script:MonitorDir = Join-Path $PSScriptRoot 'Reports\Monitor'
if (-not (Test-Path $script:MonitorDir)) { New-Item -ItemType Directory -Path $script:MonitorDir -Force | Out-Null }
$script:DigestsDir = Join-Path $PSScriptRoot 'Reports\Digests'
if (-not (Test-Path $script:DigestsDir)) { New-Item -ItemType Directory -Path $script:DigestsDir -Force | Out-Null }

function Write-ScheduledScanDigest {
    # Compact HTML + CSV summary of the latest scan, written to Reports\Digests\ with a UTC stamp.
    # Called from the Tier 8 scheduled-scan path - keeps the artifacts separate from the on-demand
    # daily digest (Generate-DailyDigest) so cleanup is easy: delete Reports\Digests\* without
    # touching the user-facing digests in Reports\.
    try {
        $stamp = (Get-Date).ToString('yyyyMMdd-HHmmss')
        $htmlPath = Join-Path $script:DigestsDir ("digest-$stamp.html")
        $csvPath  = Join-Path $script:DigestsDir ("findings-$stamp.csv")
        $a = $script:State.Adapter
        $sevCounts = @{ FAIL=0; WARN=0; INFO=0; OK=0 }
        foreach ($f in @($script:AllFindings)) {
            $lvl = [string]$f.Level
            if ($sevCounts.ContainsKey($lvl)) { $sevCounts[$lvl]++ }
        }
        # CSV first - cheap, lets analysts ingest scan-over-scan trends in Excel/Pandas.
        $csvLines = New-Object System.Collections.Generic.List[string]
        $csvLines.Add('Level,Category,Message,Fix,MitreId')
        foreach ($f in @($script:AllFindings)) {
            $esc = { param($s) if ($null -eq $s) { '' } else { '"' + (([string]$s) -replace '"','""') + '"' } }
            $csvLines.Add(('{0},{1},{2},{3},{4}' -f (& $esc $f.Level), (& $esc $f.Category), (& $esc $f.Message), (& $esc $f.Fix), (& $esc $f.MitreId)))
        }
        Set-Content -LiteralPath $csvPath -Value ($csvLines -join "`r`n") -Encoding UTF8
        # Minimal HTML - dark theme matches the Generate-DailyDigest aesthetic.
        $rows = New-Object System.Text.StringBuilder
        $shown = 0
        foreach ($f in @($script:AllFindings) | Where-Object { $_.Level -ne 'OK' } | Sort-Object Level) {
            if ($shown -ge 100) { break }
            $shown++
            $color = switch ([string]$f.Level) { 'FAIL' {'#f85149'} 'WARN' {'#d29922'} 'INFO' {'#58a6ff'} default {'#3fb950'} }
            [void]$rows.Append("<tr><td style='color:$color;font-weight:bold'>$([System.Net.WebUtility]::HtmlEncode([string]$f.Level))</td>")
            [void]$rows.Append("<td>$([System.Net.WebUtility]::HtmlEncode([string]$f.Category))</td>")
            [void]$rows.Append("<td>$([System.Net.WebUtility]::HtmlEncode([string]$f.Message))</td></tr>")
        }
        $html = @"
<!doctype html><html><head><meta charset='utf-8'><title>NetJump scheduled scan $stamp</title>
<style>body{font:14px Segoe UI,Arial;background:#0f1420;color:#d7dde6;margin:24px}
h1{color:#58a6ff;margin:0 0 8px} .sub{color:#8b95a8;font-size:12px}
.kpi{display:inline-block;background:#1a2030;border:1px solid #2a3142;border-radius:8px;padding:10px 16px;margin:12px 12px 0 0}
.kpi .l{color:#8b95a8;font-size:11px;text-transform:uppercase} .kpi .v{font-size:20px;font-weight:bold}
table{border-collapse:collapse;width:100%;margin-top:16px;background:#1a2030;border-radius:8px;overflow:hidden}
th,td{padding:6px 10px;border-bottom:1px solid #2a3142;text-align:left;font-size:12px}
th{background:#2a3142;color:#8b95a8;font-size:11px;text-transform:uppercase}</style></head><body>
<h1>NetJump scheduled scan digest</h1>
<div class='sub'>Generated $(Get-Date) - Host <code>$env:COMPUTERNAME</code> - Adapter <code>$(if ($a) { $a.Name } else { 'n/a' })</code></div>
<div class='kpi'><div class='l'>FAIL</div><div class='v' style='color:#f85149'>$($sevCounts.FAIL)</div></div>
<div class='kpi'><div class='l'>WARN</div><div class='v' style='color:#d29922'>$($sevCounts.WARN)</div></div>
<div class='kpi'><div class='l'>INFO</div><div class='v' style='color:#58a6ff'>$($sevCounts.INFO)</div></div>
<div class='kpi'><div class='l'>OK</div><div class='v' style='color:#3fb950'>$($sevCounts.OK)</div></div>
<div class='kpi'><div class='l'>Flaps (session)</div><div class='v'>$($script:State.FlapCount)</div></div>
<table><thead><tr><th>Level</th><th>Category</th><th>Finding</th></tr></thead>
<tbody>$($rows.ToString())</tbody></table>
<div class='sub' style='margin-top:12px'>CSV: $(Split-Path $csvPath -Leaf)</div>
</body></html>
"@
        Set-Content -LiteralPath $htmlPath -Value $html -Encoding UTF8
        return @{ Html = $htmlPath; Csv = $csvPath; Shown = $shown }
    } catch {
        try { Add-Event warn ("Scheduled digest write failed: {0}" -f $_.Exception.Message) } catch {}
        return $null
    }
}

function Write-MonitorLog {
    param([string]$Msg, [string]$Level = 'info')
    $line = '{0}  [{1,-5}] {2}' -f (Get-Date).ToString('yyyy-MM-dd HH:mm:ss'), $Level.ToUpper(), $Msg
    Write-Host $line
    try {
        $logPath = Join-Path $script:MonitorDir ("monitor-{0}.log" -f (Get-Date -Format 'yyyyMMdd'))
        Add-Content -Path $logPath -Value $line -Encoding UTF8
    } catch {}
}

function Run-MonitorLoop {
    Write-MonitorLog "NetJump background monitor starting. Admin=$($script:IsAdmin) PID=$PID" 'start'
    # Init state minimally
    $script:State.Settings = Load-Settings
    $script:State.Adapter  = Get-PrimaryEthernet
    $script:State.Gateway  = Get-DefaultGateway
    if (-not $script:State.Adapter) {
        Write-MonitorLog 'No ethernet adapter found. Exiting.' 'fatal'
        return
    }
    Write-MonitorLog "Monitoring $($script:State.Adapter.Name) ($($script:State.Adapter.InterfaceDescription))"
    # session file (reuse same Tier 4 helpers)
    $script:State.SessionFile = Join-Path $script:SessionsDir ("session-monitor-{0}.json" -f (Get-Date -Format 'yyyyMMdd-HHmmss'))
    Save-CurrentSession
    # ledger
    Load-Ledger
    Write-MonitorLog "Ledger loaded: $($script:Ledger.Count) entries"
    # pktmon if elevated
    if ($script:HasPktmon -and $script:IsAdmin) {
        if (Start-PktmonCapture) { Write-MonitorLog 'pktmon rolling capture started' }
        else { Write-MonitorLog 'pktmon failed to start (non-fatal)' 'warn' }
    }
    $statePath = Join-Path $script:MonitorDir 'state.json'
    $iter = 0
    $prevStatus = $null
    while ($true) {
        try {
            $iter++
            $live = Get-FastNicStatus $script:State.Adapter.Name
            if (-not $live) {
                Start-Sleep -Seconds 10
                continue
            }
            # flap detection
            if ($prevStatus -and $prevStatus -eq 'Up' -and $live.Status -ne 'Up') {
                $script:State.FlapCount++
                $script:State.DownSince = Get-Date
                Write-MonitorLog ("LINK DOWN - flap #{0} (was {1}, now {2})" -f $script:State.FlapCount, $prevStatus, $live.Status) 'warn'
                # refresh metadata for dossier
                try { $fresh = Get-NetAdapter -Name $live.Name -ErrorAction SilentlyContinue; if ($fresh) { $script:State.Adapter = $fresh } } catch {}
                # save dossier
                try {
                    $d = Save-FlapDossier -FlapNumber $script:State.FlapCount -Reason 'link-down'
                    if ($d) { Write-MonitorLog ("Dossier saved: $(Split-Path $d -Leaf)") }
                } catch { Write-MonitorLog "Dossier save failed: $_" 'warn' }
                # webhook
                Send-FlapWebhook -FlapNumber $script:State.FlapCount -Adapter $live.Name -Speed $live.LinkSpeed -LanResult $null
                # session
                $script:State.SessionFlaps.Add([pscustomobject]@{
                    time = (Get-Date).ToString('o')
                    speed = [string]$live.LinkSpeed
                    number = $script:State.FlapCount
                })
                Save-CurrentSession
            }
            if ($prevStatus -and $prevStatus -ne 'Up' -and $live.Status -eq 'Up') {
                $dur = if ($script:State.DownSince) { ((Get-Date) - $script:State.DownSince).TotalSeconds } else { 0 }
                Write-MonitorLog ("LINK UP - was down {0:N0}s" -f $dur) 'info'
                $script:State.DownSince = $null
                if ($script:State.SessionFlaps.Count -gt 0) {
                    $last = $script:State.SessionFlaps[$script:State.SessionFlaps.Count - 1]
                    Add-Member -InputObject $last -NotePropertyName downSec -NotePropertyValue ([int]$dur) -Force
                    Save-CurrentSession
                }
            }
            $prevStatus = $live.Status
            # sample beacons + ledger every 3rd iteration (~30s)
            if ($iter % 3 -eq 0) {
                Sample-Beacons
                Update-Ledger
                # surface beacons as monitor log entries (newly detected only)
                $beacons = @(Detect-Beacons)
                foreach ($b in $beacons) {
                    if (-not $script:BeaconAlerted.ContainsKey($b.Key)) {
                        $msg = ("Beacon: {0} (pid {1}) -> {2}:{3} every ~{4}s (+/-{5}s, {6} samples)" -f $b.ProcessName, $b.Pid, $b.IP, $b.Port, $b.Period, $b.Jitter, $b.Samples)
                        Write-MonitorLog $msg 'warn'
                        # webhook for beacon detection
                        $url = if ($script:State.Settings) { [string]$script:State.Settings.WebhookUrl } else { '' }
                        if ($url) {
                            $body = @{
                                type='beacon'; host=$env:COMPUTERNAME
                                process=$b.ProcessName; pid=$b.Pid
                                remoteIp=$b.IP; remotePort=$b.Port
                                periodSec=$b.Period; jitterSec=$b.Jitter
                                samples=$b.Samples; timestamp=(Get-Date).ToString('o')
                            } | ConvertTo-Json -Compress
                            Start-Job -ScriptBlock { param($u,$b) try { Invoke-RestMethod -Uri $u -Method POST -Body $b -ContentType 'application/json' -TimeoutSec 5 } catch {} } -ArgumentList $url, $body | Out-Null
                        }
                        $script:BeaconAlerted[$b.Key] = $true
                    }
                }
            }
            # state.json write every loop
            try {
                $payload = [ordered]@{
                    timestamp     = (Get-Date).ToString('o')
                    hostName      = $env:COMPUTERNAME
                    pid           = $PID
                    adapter       = $live.Name
                    status        = $live.Status
                    linkSpeed     = $live.LinkSpeed
                    gateway       = $script:State.Gateway
                    flapCount     = $script:State.FlapCount
                    sessionStart  = $script:State.SessionStart.ToString('o')
                    ledgerSize    = $script:Ledger.Count
                    beaconAlerted = $script:BeaconAlerted.Count
                }
                $payload | ConvertTo-Json | Set-Content $statePath -Encoding UTF8
            } catch {}
            # ledger save every ~5 min
            if ($iter % 30 -eq 0) { Save-Ledger }
            Start-Sleep -Seconds 10
        } catch {
            Write-MonitorLog "Loop error: $_" 'warn'
            Start-Sleep -Seconds 30
        }
    }
}

# ---------- Tier 17: Task Scheduler integration ----------
$script:MonitorTaskName = 'NetJump-BackgroundMonitor'

function Get-MonitorTask {
    Get-ScheduledTask -TaskName $script:MonitorTaskName -ErrorAction SilentlyContinue
}

function Install-BackgroundMonitor {
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, 'Installing a scheduled task requires Administrator. Re-launch via Run-NetJump.bat.', 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    if (Get-MonitorTask) {
        $r = [System.Windows.MessageBox]::Show($window, 'Background monitor task already installed. Reinstall (overwrites)?', 'Already installed', 'YesNo', 'Question')
        if ($r -ne 'Yes') { return }
        Uninstall-BackgroundMonitor -Quiet
    }
    $ps  = (Get-Command powershell.exe).Source
    $script_ = $PSCommandPath
    $msg = "Install Task Scheduler entry?`n`n  Task: $($script:MonitorTaskName)`n  Trigger: at user logon`n  Action: $ps -NoProfile -ExecutionPolicy Bypass -WindowStyle Hidden -File `"$script_`" -Monitor`n  Run as: $env:USERNAME`n  Privilege: highest`n`nThe task will start NetJump-Dashboard.ps1 -Monitor (long-running headless background watcher) on every logon. Webhook + status.json + dossiers all keep working unattended.`n`nProceed?"
    $r = [System.Windows.MessageBox]::Show($window, $msg, 'Install background monitor', 'YesNo', 'Question')
    if ($r -ne 'Yes') { return }
    try {
        $action  = New-ScheduledTaskAction  -Execute $ps -Argument "-NoProfile -ExecutionPolicy Bypass -WindowStyle Hidden -File `"$script_`" -Monitor"
        $trigger = New-ScheduledTaskTrigger -AtLogOn -User $env:USERNAME
        $set     = New-ScheduledTaskSettingsSet -AllowStartIfOnBatteries -DontStopIfGoingOnBatteries -StartWhenAvailable -ExecutionTimeLimit ([TimeSpan]::Zero) -RestartCount 3 -RestartInterval (New-TimeSpan -Minutes 5)
        $princ   = New-ScheduledTaskPrincipal -UserId $env:USERNAME -RunLevel Highest -LogonType Interactive
        Register-ScheduledTask -TaskName $script:MonitorTaskName -Action $action -Trigger $trigger -Settings $set -Principal $princ -Description 'NetJump background ethernet/security monitor' -Force | Out-Null
        Write-ActionAudit 'install-monitor' "task=$($script:MonitorTaskName)" 'success' @{ script=$script_ }
        Add-Event fix "Background monitor installed (scheduled task '$($script:MonitorTaskName)' - runs at logon)."
        Show-Toast -Title 'NetJump: monitor installed' -Message "Will start at next logon. Run 'schtasks /run /tn $($script:MonitorTaskName)' to start now." -Icon Info
    } catch {
        Write-ActionAudit 'install-monitor' "task=$($script:MonitorTaskName)" 'failure' "$_"
        [System.Windows.MessageBox]::Show($window, "Install failed:`n$_", 'Error', 'OK', 'Error') | Out-Null
    }
}

function Uninstall-BackgroundMonitor {
    param([switch]$Quiet)
    if (-not $script:IsAdmin) {
        if (-not $Quiet) { [System.Windows.MessageBox]::Show($window, 'Uninstalling a scheduled task requires Administrator.', 'Not elevated', 'OK', 'Warning') | Out-Null }
        return
    }
    $t = Get-MonitorTask
    if (-not $t) {
        if (-not $Quiet) { [System.Windows.MessageBox]::Show($window, 'Background monitor task is not installed.', 'Nothing to remove', 'OK', 'Information') | Out-Null }
        return
    }
    if (-not $Quiet) {
        $r = [System.Windows.MessageBox]::Show($window, "Remove scheduled task '$($script:MonitorTaskName)' and stop any running instance?", 'Uninstall background monitor', 'YesNo', 'Question')
        if ($r -ne 'Yes') { return }
    }
    try {
        Stop-ScheduledTask -TaskName $script:MonitorTaskName -ErrorAction SilentlyContinue
        Unregister-ScheduledTask -TaskName $script:MonitorTaskName -Confirm:$false -ErrorAction Stop
        Write-ActionAudit 'uninstall-monitor' "task=$($script:MonitorTaskName)" 'success'
        if (-not $Quiet) {
            Add-Event fix "Background monitor task removed."
            Show-Toast -Title 'NetJump: monitor uninstalled' -Message "Scheduled task removed." -Icon Info
        }
    } catch {
        Write-ActionAudit 'uninstall-monitor' "task=$($script:MonitorTaskName)" 'failure' "$_"
        if (-not $Quiet) { [System.Windows.MessageBox]::Show($window, "Uninstall failed:`n$_", 'Error', 'OK', 'Error') | Out-Null }
    }
}

