function Get-CountryFromLabel {
    param([string]$Label)
    if (-not $Label) { return $null }
    # Most cloud/CDN labels are US-anchored
    if ($Label -match '^(Cloudflare|Google|Apple|GitHub|AWS|Microsoft|Azure|Fastly|Akamai|Meta|X/Twitter|Automattic|Quad9|Microsoft 365)') { return 'US' }
    # Country-tagged labels like "RU (Yandex)" or "CN/HK/TW" or "KP (North Korea)"
    if ($Label -match '^([A-Z]{2})(?:[/\s]|$)') { return $matches[1] }
    return $null
}

