    '185.228.168.168' = 'CleanBrowsing DoH'
    '208.67.222.222'  = 'OpenDNS DoH'
    '208.67.220.220'  = 'OpenDNS DoH'
}
# Processes legitimately allowed to do DoH (browsers + OS resolver shims)
$script:DohAllowedProcs = @{
    'chrome'='Chrome';'msedge'='Edge';'firefox'='Firefox';'brave'='Brave';
    'opera'='Opera';'vivaldi'='Vivaldi';'safari'='Safari';'librewolf'='LibreWolf';
    'svchost'='Windows DNS service';'dnscache'='Windows DNS service';
    'mdnsresponder'='Bonjour';'tor'='Tor'
}

function Detect-DohConnections {
    $hits = New-Object System.Collections.ArrayList
    if (-not $script:Ledger -or $script:Ledger.Count -eq 0) { return $hits }
    foreach ($v in $script:Ledger.Values) {
        if ($v.port -ne 443) { continue }
        if (-not $script:DohEndpoints.ContainsKey($v.ip)) { continue }
        $procLower = ($v.proc + '').ToLower()
        if ($script:DohAllowedProcs.ContainsKey($procLower)) { continue }
        [void]$hits.Add([pscustomobject]@{
            Process = $v.proc; Ip = $v.ip; Port = $v.port
            Provider = $script:DohEndpoints[$v.ip]
            FirstSeen = $v.firstSeen; Samples = $v.samples
        })
    }
    return $hits
}

# ---------- Tier 15: STIX 2.1 bundle export ----------
function New-StixBundle {
    param($Findings, $Causes)
    $now = (Get-Date).ToUniversalTime().ToString('o')
    $hostName = $env:COMPUTERNAME
    $bundleId = "bundle--" + [guid]::NewGuid()
    $identityId = "identity--" + [guid]::NewGuid()
    $objects = New-Object System.Collections.ArrayList

    # producer identity
    [void]$objects.Add(@{
        type='identity'; spec_version='2.1'; id=$identityId
        created=$now; modified=$now
        name="NetJump HUD on $hostName"
        identity_class='system'
    })

    foreach ($f in $Findings) {
        if ($f.Level -eq 'OK' -or $f.Level -eq 'INFO') { continue }
        $indId = "indicator--" + [guid]::NewGuid()
        $sev = switch ($f.Level) { 'FAIL'{'high'} 'WARN'{'medium'} default{'low'} }
        $msg = if ($f.PSObject.Properties['Message']) { [string]$f.Message } else { '' }
        $cat = if ($f.PSObject.Properties['Category']) { [string]$f.Category } else { '' }
        [void]$objects.Add(@{
            type='indicator'; spec_version='2.1'; id=$indId
            created=$now; modified=$now; created_by_ref=$identityId
            name="[$cat] $msg"
            description= ([string]$f.Detail)
            indicator_types=@('malicious-activity')
            pattern="[host:name = '$hostName']"
            pattern_type='stix'
            valid_from=$now
            labels=@($sev)
        })
        if ($f.PSObject.Properties['MitreId'] -and $f.MitreId) {
            $apId = "attack-pattern--" + [guid]::NewGuid()
            [void]$objects.Add(@{
                type='attack-pattern'; spec_version='2.1'; id=$apId
                created=$now; modified=$now; created_by_ref=$identityId
                name="$([string]$f.MitreName)"
                external_references=@(@{
                    source_name='mitre-attack'
                    external_id=[string]$f.MitreId
                    url="https://attack.mitre.org/techniques/$([string]$f.MitreId -replace '\.','/')"
                })
            })
            [void]$objects.Add(@{
                type='relationship'; spec_version='2.1'
                id="relationship--" + [guid]::NewGuid()
                created=$now; modified=$now; created_by_ref=$identityId
                relationship_type='indicates'
                source_ref=$indId
                target_ref=$apId
            })
        }
    }
    # top-cause notes
    foreach ($c in @($Causes)) {
        [void]$objects.Add(@{
            type='note'; spec_version='2.1'
            id="note--" + [guid]::NewGuid()
            created=$now; modified=$now; created_by_ref=$identityId
            content="Likely cause ($($c.ConfidenceLabel)): $($c.Cause). Evidence: $($c.Evidence). Recommendation: $($c.Recommendation)"
            object_refs=@($identityId)
        })
    }

    @{ type='bundle'; id=$bundleId; objects=$objects.ToArray() }
}

function Export-StixBundle {
    if (-not $script:Findings -or $script:Findings.Count -eq 0) {
        [System.Windows.MessageBox]::Show($window, 'No findings to export. Run a scan first.', 'Empty', 'OK', 'Information') | Out-Null
        return
    }
    $stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
    $path = Join-Path $script:PktmonReportRoot ("NetJump-stix-$stamp.json")
    try {
        $bundle = New-StixBundle -Findings $script:Findings -Causes $script:Causes
        $bundle | ConvertTo-Json -Depth 8 | Set-Content $path -Encoding UTF8
        Add-Event scan ("STIX bundle exported: {0} ({1} objects)" -f (Split-Path $path -Leaf), $bundle.objects.Count)
        Start-Process explorer.exe ('/select,"' + $path + '"')
    } catch {
        Add-Event warn "STIX export failed: $_"
        [System.Windows.MessageBox]::Show($window, "STIX export failed:`n$_", 'Error', 'OK', 'Error') | Out-Null
    }
}

# ---------- Tier 20: visual HUD helpers (health score, trends, activity ribbon) ----------
$script:ActivityEvents = New-Object System.Collections.Generic.List[object]   # last 60 min of marks

function Add-ActivityMark {
    param([ValidateSet('flap','recovery','fix','scan','alert')] $Type)
    $script:ActivityEvents.Add([pscustomobject]@{ Time = Get-Date; Type = $Type })
    # prune older than 60 min
    $cutoff = (Get-Date).AddMinutes(-60)
    while ($script:ActivityEvents.Count -gt 0 -and $script:ActivityEvents[0].Time -lt $cutoff) { $script:ActivityEvents.RemoveAt(0) }
}

function Compute-HealthScore {
    # Tier 77: per-category-capped scoring. The old logic (-12 per FAIL, -4 per WARN, flat) hit
    # zero with just 9 FAILs or 25 WARNs - way too brutal for a typical Windows hardening scan
    # that surfaces 20+ findings on a HEALTHY system: LLMNR enabled, NIC power saves, Defender
    # tweaks, NBT-NS, hosts-file entries, etc. Most of these are best-practice hardening hints,
    # NOT "your network is broken" red alarms.
    #
    # New rules:
    #   - Each CATEGORY contributes a capped deduction. Multiple findings in the same category
    #     cluster (e.g. 5 NIC power warnings) can't crater the grade beyond the cap.
    #   - CRITICAL categories (link/adapter actually broken, BYOVD vulnerable driver, malicious
    #     C2 beacon, threat-intel match, NIC BSOD) carry per-finding weights big enough that one
    #     hit drops the grade.
    #   - POSTURE/HARDENING categories (Power, Driver, Services, Malware-misc, DoH, Sysmon,
    #     Baseline) have small per-finding weights and tight caps so they're hints, not
    #     score-killers.
    #
    # Calibration target:
    #   - Healthy system with only hardening warnings   -> 80-90 (B-A)
    #   - Same + 1-2 operational FAILs                  -> 60-75 (C-D)
    #   - Link down or active threat                    -> 0-50  (F-D)
    $score = 100.0

    # Category weights: F = per-FAIL deduction, W = per-WARN deduction,
    # CapF = max FAIL deduction for this category, CapW = max WARN deduction.
    $catW = @{
        # CRITICAL OPERATIONAL - link/adapter actually broken or hardware crashing
        'Adapter'     = @{ F = 60; W = 10; CapF = 60; CapW = 10 }
        'Link'        = @{ F = 50; W = 8;  CapF = 50; CapW = 8  }
        'Crashes'     = @{ F = 20; W = 5;  CapF = 25; CapW = 8  }
        # CRITICAL SECURITY - active or imminent threat
        'BYOVD'       = @{ F = 25; W = 8;  CapF = 30; CapW = 10 }
        'ThreatIntel' = @{ F = 20; W = 6;  CapF = 25; CapW = 10 }
        'Beacon'      = @{ F = 15; W = 5;  CapF = 20; CapW = 10 }
        # OPERATIONAL - degraded service but link still up
        'Counters'    = @{ F = 12; W = 3;  CapF = 18; CapW = 7  }
        'DNS'         = @{ F = 10; W = 3;  CapF = 15; CapW = 7  }
        'Auth'        = @{ F = 10; W = 3;  CapF = 15; CapW = 7  }
        'History'     = @{ F = 8;  W = 2;  CapF = 12; CapW = 5  }
        'ARP'         = @{ F = 8;  W = 2;  CapF = 10; CapW = 5  }
        # POSTURE / HARDENING - best-practice hints, low individual impact
        'Driver'      = @{ F = 4;  W = 1;  CapF = 6;  CapW = 4  }
        'Services'    = @{ F = 3;  W = 1;  CapF = 5;  CapW = 4  }
        'Malware'     = @{ F = 4;  W = 1;  CapF = 7;  CapW = 5  }   # Defender state, hosts file etc; not active malware
        'Power'       = @{ F = 1;  W = 1;  CapF = 3;  CapW = 3  }   # MANY NIC findings, individually trivial
        'Baseline'    = @{ F = 2;  W = 1;  CapF = 4;  CapW = 4  }
        'CustomRule'  = @{ F = 3;  W = 1;  CapF = 6;  CapW = 5  }
        'Sysmon'      = @{ F = 1;  W = 1;  CapF = 2;  CapW = 2  }
        'DoH'         = @{ F = 1;  W = 1;  CapF = 2;  CapW = 2  }
        'Updates'     = @{ F = 2;  W = 1;  CapF = 4;  CapW = 3  }
        'Filters'     = @{ F = 2;  W = 1;  CapF = 4;  CapW = 3  }
    }
    $defaultW = @{ F = 5; W = 2; CapF = 10; CapW = 6 }

    # Group findings by category so we can cap per group.
    $byCat = @{}
    foreach ($f in $script:Findings) {
        $lvl = [string]$f.Level
        if ($lvl -ne 'FAIL' -and $lvl -ne 'WARN') { continue }
        $cat = [string]$f.Category
        if ([string]::IsNullOrWhiteSpace($cat)) { $cat = '_' }
        if (-not $byCat.ContainsKey($cat)) {
            $byCat[$cat] = [pscustomobject]@{ Fails = 0; Warns = 0 }
        }
        if ($lvl -eq 'FAIL') { $byCat[$cat].Fails++ } else { $byCat[$cat].Warns++ }
    }
    foreach ($cat in $byCat.Keys) {
        $w = if ($catW.ContainsKey($cat)) { $catW[$cat] } else { $defaultW }
        $deductF = [Math]::Min([double]$w.CapF, [double]($byCat[$cat].Fails * $w.F))
        $deductW = [Math]::Min([double]$w.CapW, [double]($byCat[$cat].Warns * $w.W))
        $score -= ($deductF + $deductW)
    }

    # Existing global penalties (kept, but they were never the main culprit).
    if ($script:State -and $script:State.FlapCount -gt 0) {
        $score -= [Math]::Min(20, $script:State.FlapCount * 3)
    }
    if ($script:Causes -and $script:Causes.Count -gt 0) {
        $top = $script:Causes[0]
        if ($top.PSObject.Properties['Confidence'] -and [int]$top.Confidence -ge 70) { $score -= 5 }
    }

    if ($score -lt 0)   { $score = 0 }
    if ($score -gt 100) { $score = 100 }
    $score = [int][Math]::Round($score)

    $grade   = if ($score -ge 90) { 'A' } elseif ($score -ge 80) { 'B' } elseif ($score -ge 70) { 'C' } elseif ($score -ge 60) { 'D' } else { 'F' }
    $color   = if ($score -ge 80) { '#3fb950' } elseif ($score -ge 60) { '#d29922' } else { '#f85149' }
    $glow    = if ($score -ge 80) { '#1a4a26' } elseif ($score -ge 60) { '#5a3a10' } else { '#5a1018' }

    # Verdict text now includes finding counts so the user can see what's driving the grade.
    $totalF = (@($script:Findings | Where-Object { $_.Level -eq 'FAIL' })).Count
    $totalW = (@($script:Findings | Where-Object { $_.Level -eq 'WARN' })).Count
    $countTail = if ($totalF -or $totalW) {
        " ($totalF fail$(if ($totalF -ne 1){'s'}), $totalW warn$(if ($totalW -ne 1){'s'}))"
    } else { '' }
    $verdict = if ($script:State -and -not $script:State.Adapter) { 'No ethernet adapter detected.' }
               elseif ($script:State -and $script:State.PrevStatus -and $script:State.PrevStatus -ne 'Up') { 'Link DOWN - investigating.' }
               elseif ($score -ge 90) { if ($totalW -gt 0) { "Healthy - hardening hints optional.$countTail" } else { 'All systems healthy.' } }
               elseif ($score -ge 80) { "Healthy with minor warnings.$countTail" }
               elseif ($score -ge 70) { "Some issues to review.$countTail" }
               elseif ($score -ge 60) { "Multiple issues - investigate.$countTail" }
               else                   { "Critical issues detected.$countTail" }

    return [pscustomobject]@{
        Score = $score; Grade = $grade; Color = $color; Glow = $glow; Verdict = $verdict
    }
}

# Tier 80: PERIODICITY analyzer for retransmit events. Scans $script:Events for retrans-class
# entries, computes the interval between consecutive ones, and detects whether the rhythm is
# regular (caused by a recurring scheduled job or fixed-interval poller) vs reactive (a real
# network issue firing burst-y when traffic spikes). Also pulls per-process attribution out of
# the message text so we can flag "all retrans events involve chrome(1234)" if one process is
# consistently the source.
#
# Returns an ordered hashtable consumed by:
#   - Show-RetransInvestigatorDialog (renders the result in the PERIODICITY card)
#   - Tick-RetransCpuMemory (auto-emits a one-line info event when the pattern changes)
#
# Result keys:
#   Status:           'ok' or 'insufficient'
#   EventCount:       number of retrans events analyzed
#   MeanIntervalSec:  average seconds between consecutive retrans events
#   StdDevSec:        standard deviation
#   CV:               coefficient of variation (stddev/mean) - the "regularity" metric
#   Regularity:       'clockwork' | 'periodic' | 'loosely periodic' | 'irregular'
#   PatternHint:      english interpretation matched against well-known Windows recurring intervals
#   ProcAttribution:  english summary of which process(es) keep showing up
#   TopProc:          top process line (e.g. "chrome(pid 1234) - in 8/10 retrans events")
#   Headline:         one-line bottom summary used by both consumers
function Analyze-RetransPeriodicity {
    if (-not $script:Events -or $script:Events.Count -eq 0) {
        return [ordered]@{ Status = 'insufficient'; EventCount = 0 }
    }
    $events = @($script:Events | Where-Object { [string]$_.Text -match '(?i)\bTCP retrans\b' })
    if (@($events).Count -lt 4) {
        return [ordered]@{
            Status     = 'insufficient'
            EventCount = @($events).Count
            Reason     = 'Need at least 4 retrans events in the buffer to compute a pattern.'
        }
    }
    # Parse HH:mm:ss into datetimes anchored to today, handling midnight wrap.
    $today = (Get-Date).Date
    $stamps = New-Object System.Collections.Generic.List[datetime]
    $prev = $null
    foreach ($e in $events) {
        try {
            $ts = [datetime]::ParseExact([string]$e.Time, 'HH:mm:ss', [Globalization.CultureInfo]::InvariantCulture)
            $dt = $today.Add($ts.TimeOfDay)
            if ($prev -and $dt -lt $prev) { $dt = $dt.AddDays(1) }
            $stamps.Add($dt)
            $prev = $dt
        } catch {}
    }
    if ($stamps.Count -lt 4) {
        return [ordered]@{ Status = 'insufficient'; EventCount = $stamps.Count }
    }
    $deltas = New-Object System.Collections.Generic.List[double]
    for ($i = 1; $i -lt $stamps.Count; $i++) {
        $deltas.Add(($stamps[$i] - $stamps[$i-1]).TotalSeconds)
    }
    $mean = ($deltas | Measure-Object -Average).Average
    $variance = 0.0
    foreach ($d in $deltas) { $variance += [Math]::Pow($d - $mean, 2) }
    $variance /= $deltas.Count
    $stdDev = [Math]::Sqrt($variance)
    $cv = if ($mean -gt 0) { $stdDev / $mean } else { 0 }
    $regularity = if     ($cv -lt 0.15) { 'clockwork' }
                  elseif ($cv -lt 0.30) { 'periodic' }
                  elseif ($cv -lt 0.55) { 'loosely periodic' }
                  else                  { 'irregular' }
    $patternHint = if ($regularity -eq 'irregular') {
        'Irregular timing - retransmits are reactive to traffic bursts, not driven by a fixed schedule. Look for correlation with workload spikes (downloads, video calls, backups) rather than a periodic poller.'
    } elseif ($mean -lt 8) {
        'Sub-8s spikes - very tight cycle. Likely a buggy reconnect loop, TCP SYN storm, or socket-leaking app retrying continuously.'
    } elseif ($mean -lt 20) {
        "~$([int][Math]::Round($mean))s cycle - matches Windows DHCP confirm timer, browser auto-refresh, or app-level keep-alive ping."
    } elseif ($mean -lt 40) {
        "~$([int][Math]::Round($mean))s cycle - matches NetBIOS name broadcasts (every 30s), mDNS, or LLMNR discovery probes."
    } elseif ($mean -lt 80) {
        "~$([int][Math]::Round($mean))s cycle - matches a 1-minute scheduled task, telemetry beacon, OneDrive/Dropbox sync poll, or Defender lightweight scan trigger."
    } elseif ($mean -lt 140) {
        "~$([int][Math]::Round($mean))s cycle - matches default TCP keepalive interval (~120s) or a 2-minute monitoring agent heartbeat."
    } elseif ($mean -lt 220) {
        "~$([int][Math]::Round($mean))s cycle - matches SCCM client check-in default (180s), AV scan throttle, or a 3-minute heartbeat."
    } elseif ($mean -lt 350) {
        "~$([int][Math]::Round($mean))s cycle - matches Windows Update detect (300s default), browser session ping, or Group Policy refresh on workstations."
    } elseif ($mean -lt 700) {
        "~$([int][Math]::Round($mean))s cycle - matches a 10-minute heartbeat: Windows Time Service, AAD Connect, or DHCP lease renewal at 50% of an 8-hour lease."
    } elseif ($mean -lt 2000) {
        "~$([int][Math]::Round($mean))s cycle (~$([int][Math]::Round($mean/60))min) - matches Group Policy refresh on DCs (15min), WSUS scan, or scheduled antivirus scan."
    } elseif ($mean -lt 3800) {
        "~$([int][Math]::Round($mean/60))min cycle - matches scheduled maintenance window or hourly task."
    } else {
        "~$([int][Math]::Round($mean/60))min cycle - infrequent recurring event. Check Task Scheduler for any task whose interval is roughly $([int][Math]::Round($mean/60)) minutes."
    }
    $procRegex = [regex]'(?<name>[A-Za-z0-9_.-]+)\((?<pid>\d+)\)'
    $procCounts = @{}
    foreach ($e in $events) {
        $seenInThisEvent = @{}
        foreach ($m in $procRegex.Matches([string]$e.Text)) {
            $key = "{0}(pid {1})" -f $m.Groups['name'].Value, $m.Groups['pid'].Value
            if ($seenInThisEvent[$key]) { continue }
            $seenInThisEvent[$key] = $true
            if ($procCounts.ContainsKey($key)) { $procCounts[$key]++ } else { $procCounts[$key] = 1 }
        }
    }
    $procRanked = @($procCounts.GetEnumerator() | Sort-Object Value -Descending)
    $topProc = if ($procRanked.Count -gt 0) {
        "{0} - in {1}/{2} retrans events" -f $procRanked[0].Key, $procRanked[0].Value, $events.Count
    } else { '' }
    $procAttribution = if ($procRanked.Count -gt 0 -and $procRanked[0].Value -ge ($events.Count * 0.7)) {
        "Process consistently implicated: $topProc. This is the single dominant cause - investigate or restart that process before chasing network-side fixes."
    } elseif ($procRanked.Count -ge 3) {
        "Multiple processes involved: $($procRanked[0].Key), $($procRanked[1].Key), $($procRanked[2].Key). No single dominant offender - the trigger is network-side, not app-side."
    } elseif ($procRanked.Count -gt 0) {
        "Top process: $topProc."
    } else {
        'No per-process attribution captured in the event text (offender sampler may have been disabled).'
    }
    $headline = "{0}. Mean interval {1:N1}s, std-dev {2:N1}s ({3}), {4} samples." -f `
                (([string]$regularity).ToUpperInvariant()), $mean, $stdDev, ('CV ' + ('{0:N2}' -f $cv)), $stamps.Count
    return [ordered]@{
        Status            = 'ok'
        EventCount        = $stamps.Count
        DeltaCount        = $deltas.Count
        FirstAt           = $stamps[0]
        LastAt            = $stamps[$stamps.Count - 1]
        MeanIntervalSec   = [Math]::Round($mean, 1)
        StdDevSec         = [Math]::Round($stdDev, 1)
        CV                = [Math]::Round($cv, 2)
        Regularity        = $regularity
        PatternHint       = $patternHint
        ProcAttribution   = $procAttribution
        TopProc           = $topProc
        Headline          = $headline
    }
}

function Get-LastIncidentText {
    if (-not $script:State -or $script:State.SessionFlaps.Count -eq 0) { return 'no incidents' }
    $last = $script:State.SessionFlaps[$script:State.SessionFlaps.Count - 1]
    $when = $null
    try { $when = [datetime]$last.time } catch { return '?' }
    $d = (Get-Date) - $when
    if     ($d.TotalSeconds -lt 60)   { return 'just now' }
    elseif ($d.TotalMinutes -lt 60)   { return ("{0}m ago" -f [int]$d.TotalMinutes) }
    elseif ($d.TotalHours   -lt 24)   { return ("{0}h ago" -f [int]$d.TotalHours) }
    else                              { return ("{0}d ago" -f [int]$d.TotalDays) }
}

# Returns one of: ▲ (up), ▼ (down), ─ (flat), '' (insufficient data).
function Get-TrendArrow {
    param([System.Collections.Generic.List[double]]$Series, [double]$ChangeThreshold = 0.15)
    if (-not $Series -or $Series.Count -lt 6) { return '' }
    $n = $Series.Count
    $halfSize = [int][Math]::Min($n / 2, 30)
    $recent  = 0.0; for ($i = $n - $halfSize; $i -lt $n; $i++) { $recent += [double]$Series[$i] }
    $recent  /= $halfSize
    $earlier = 0.0; for ($i = 0; $i -lt $halfSize; $i++) { $earlier += [double]$Series[$i] }
    $earlier /= $halfSize
    if ($earlier -le 0.0001) {
        if ($recent -gt 0.5) { return [char]9650 }   # ▲
        return [char]9472                            # ─
    }
    $delta = ($recent - $earlier) / $earlier
    if ($delta -gt  $ChangeThreshold) { return [char]9650 }   # ▲
    if ($delta -lt -$ChangeThreshold) { return [char]9660 }   # ▼
    return [char]9472                                          # ─
}

function Get-TrendColor {
    param([string]$Arrow, [bool]$LowerIsBetter = $true)
    if ($Arrow -eq [char]9650) { if ($LowerIsBetter) { return '#f85149' } else { return '#3fb950' } }   # ▲
    if ($Arrow -eq [char]9660) { if ($LowerIsBetter) { return '#3fb950' } else { return '#f85149' } }   # ▼
    if ($Arrow -eq [char]9472) { return '#8b95a8' }                                                       # ─
    return '#6a7380'
}

# ---------- Tier 21: diagnostic productivity (filter + diff + suppress + empty states) ----------
$script:AllFindings     = New-Object System.Collections.Generic.List[object]   # master pre-filter
$script:PrevFindingKeys = @{}                                                    # last scan keys
$script:FilterText      = ''
$script:HideHealthy     = $false
# Differential-scan filter. One of: 'all' (default) | 'new' (only findings new this scan) |
# 'resolved' (only items that disappeared since last scan, rendered as ghost entries) | 'changed'
# (NEW + RESOLVED combined). Driven by the DiffModeCombo on the DIAGNOSTICS tab.
$script:DiffMode        = 'all'
# Tracks the FULL previous-scan finding objects so we can synthesize 'resolved' ghost rows.
# Populated by Update-Findings; consumed by Apply-FindingsFilter.
$script:PrevFindingsByKey = @{}
$script:ResolvedFindings  = New-Object System.Collections.Generic.List[object]
$script:SuppressedKeys  = @{}                                                    # key -> @{Mode; Expires}

function Get-FindingKey {
    param($Finding)
    if (-not $Finding) { return '' }
    return ("{0}|{1}" -f ([string]$Finding.Category), ([string]$Finding.Message).ToLower())
}

function Load-Suppressed {
    if (-not $script:State -or -not $script:State.Settings) { return }
    $arr = $script:State.Settings.SuppressedFindings
    if (-not $arr) { return }
    $now = Get-Date
    foreach ($e in $arr) {
        $exp = $null
        if ($e.Expires) { try { $exp = [datetime]$e.Expires } catch {} }
        if ($exp -and $exp -lt $now) { continue }
        $script:SuppressedKeys[[string]$e.Key] = @{ Mode = [string]$e.Mode; Expires = $exp }
    }
}

function Save-Suppressed {
    if (-not $script:State.Settings) { return }
    $arr = @(
        $script:SuppressedKeys.GetEnumerator() | Where-Object { $_.Value.Mode -ne 'session' } | ForEach-Object {
            [pscustomobject]@{
                Key     = $_.Key
                Mode    = $_.Value.Mode
                Expires = if ($_.Value.Expires) { $_.Value.Expires.ToString('o') } else { $null }
            }
        }
    )
    $script:State.Settings | Add-Member -NotePropertyName SuppressedFindings -NotePropertyValue $arr -Force
    Save-Settings $script:State.Settings
}

function Test-IsSuppressed {
    param([string]$Key)
    if (-not $script:SuppressedKeys.ContainsKey($Key)) { return $false }
    $entry = $script:SuppressedKeys[$Key]
    if ($entry.Expires -and (Get-Date) -gt $entry.Expires) {
        [void]$script:SuppressedKeys.Remove($Key)
        return $false
    }
    return $true
}

function Suppress-Finding {
    param([string]$Key, [ValidateSet('24h','session','permanent')] $Mode)
    if (-not $Key) { return }
    $script:SuppressedKeys[$Key] = @{
        Mode    = $Mode
        Expires = if ($Mode -eq '24h') { (Get-Date).AddHours(24) } else { $null }
    }
    if ($Mode -ne 'session') { Save-Suppressed }
    Add-Event info "Suppressed finding ($Mode): $Key"
}

function Unsuppress-Finding {
    param([string]$Key)
    if (-not $Key) { return }
    [void]$script:SuppressedKeys.Remove($Key)
    Save-Suppressed
    Add-Event info "Un-suppressed finding: $Key"
}

function Apply-FindingsFilter {
    # New strategy: build fresh List[object] for each bucket, then DIRECTLY assign ItemsSource
    # on each ItemsControl. This bypasses the ObservableCollection-binding propagation issue
    # that was leaving buckets empty even when AllFindings had data.
    $fail  = New-Object System.Collections.Generic.List[object]
    $warn  = New-Object System.Collections.Generic.List[object]
    $info  = New-Object System.Collections.Generic.List[object]
    $ok    = New-Object System.Collections.Generic.List[object]
    $muted = New-Object System.Collections.Generic.List[object]

    $filter = ([string]$script:FilterText).Trim().ToLower()
    $diff   = [string]$script:DiffMode
    if (-not $diff) { $diff = 'all' }
    # Diagnostic counters
    $stats = @{ In=0; FilteredOut=0; Suppressed=0; FAIL=0; WARN=0; INFO=0; OK=0; OKHidden=0; Resolved=0; DiffSkipped=0; OtherLevel=@() }
    if ($script:AllFindings) {
        foreach ($f in $script:AllFindings) {
            $stats.In++
            try {
                $key = Get-FindingKey $f
                $passesFilter = if (-not $filter) { $true } else {
                    ([string]$f.Category).ToLower().Contains($filter) -or ([string]$f.Message).ToLower().Contains($filter) -or ([string]$f.MitreId).ToLower().Contains($filter)
                }
                if (-not $passesFilter) { $stats.FilteredOut++; continue }
                # Diff-mode filter: skip non-new entries when diff='new'; skip everything when diff='resolved'
                # (resolved ghosts are appended separately below).
                if ($diff -eq 'new' -and -not [bool]$f.IsNew) { $stats.DiffSkipped++; continue }
                if ($diff -eq 'resolved') { $stats.DiffSkipped++; continue }
                if ($diff -eq 'changed' -and -not [bool]$f.IsNew) { $stats.DiffSkipped++; continue }
                if (Test-IsSuppressed $key) {
                    $stats.Suppressed++
                    [void]$muted.Add($f)
                    continue
                }
                $lvl = [string]$f.Level
                switch ($lvl) {
                    'FAIL' { [void]$fail.Add($f); $stats.FAIL++ }
                    'WARN' { [void]$warn.Add($f); $stats.WARN++ }
                    'INFO' { [void]$info.Add($f); $stats.INFO++ }
                    default {
                        if (-not $script:HideHealthy) { [void]$ok.Add($f); $stats.OK++ }
                        else { $stats.OKHidden++ }
                        if ($lvl -ne 'OK' -and $lvl -ne '') { $stats.OtherLevel += $lvl }
                    }
                }
            } catch {
                try { Add-Event warn ("Filter loop error on a finding: $($_.Exception.Message)") } catch {}
            }
        }
    }
    # Append RESOLVED ghost rows when diff mode is 'resolved' or 'changed'. These show up in the
    # OK bucket with green coloring and a "RESOLVED:" prefix so they're visually distinct.
    if (($diff -eq 'resolved' -or $diff -eq 'changed') -and $script:ResolvedFindings) {
        foreach ($r in $script:ResolvedFindings) {
            try {
                $msgLower = ([string]$r.Message).ToLower()
                $catLower = ([string]$r.Category).ToLower()
                if ($filter -and -not ($msgLower.Contains($filter) -or $catLower.Contains($filter))) { continue }
                [void]$ok.Add($r)
                $stats.Resolved++
            } catch {}
        }
    }

    # Direct assignment - works regardless of ObservableCollection vs List, regardless of which
    # thread we're on, regardless of whether the binding was set up correctly at startup.
    try {
        if ($controls.FindingsListFail)  { $controls.FindingsListFail.ItemsSource  = $fail }
        if ($controls.FindingsListWarn)  { $controls.FindingsListWarn.ItemsSource  = $warn }
        if ($controls.FindingsListInfo)  { $controls.FindingsListInfo.ItemsSource  = $info }
        if ($controls.FindingsListOk)    { $controls.FindingsListOk.ItemsSource    = $ok }
        if ($controls.FindingsListMuted) { $controls.FindingsListMuted.ItemsSource = $muted }
    } catch {
        try { Add-Event warn ("Failed to assign bucket ItemsSource: $($_.Exception.Message)") } catch {}
    }

    # Keep the script-scope ObservableCollections mirrored in case other code reads from them.
    # (e.g. CSV export, suppress menu count). They're no longer the source of UI truth.
    try {
        if ($script:FindingsFail)  { $script:FindingsFail.Clear();  foreach ($x in $fail)  { [void]$script:FindingsFail.Add($x) } }
        if ($script:FindingsWarn)  { $script:FindingsWarn.Clear();  foreach ($x in $warn)  { [void]$script:FindingsWarn.Add($x) } }
        if ($script:FindingsInfo)  { $script:FindingsInfo.Clear();  foreach ($x in $info)  { [void]$script:FindingsInfo.Add($x) } }
        if ($script:FindingsOk)    { $script:FindingsOk.Clear();    foreach ($x in $ok)    { [void]$script:FindingsOk.Add($x) } }
        if ($script:FindingsMuted) { $script:FindingsMuted.Clear(); foreach ($x in $muted) { [void]$script:FindingsMuted.Add($x) } }
    } catch {}

    # update bucket counts + empty-state visibility
    $emptyVis = { param($n) if ($n -eq 0) { 'Visible' } else { 'Collapsed' } }
    try {
        if ($controls.FailCountText)  { $controls.FailCountText.Text  = [string]$fail.Count }
        if ($controls.WarnCountText)  { $controls.WarnCountText.Text  = [string]$warn.Count }
        if ($controls.InfoCountText)  { $controls.InfoCountText.Text  = [string]$info.Count }
        if ($controls.OkCountText)    { $controls.OkCountText.Text    = [string]$ok.Count }
        if ($controls.MutedCountText) { $controls.MutedCountText.Text = [string]$muted.Count }
        if ($controls.EmptyFail) { $controls.EmptyFail.Visibility = & $emptyVis $fail.Count }
        if ($controls.EmptyWarn) { $controls.EmptyWarn.Visibility = & $emptyVis $warn.Count }
        if ($controls.EmptyInfo) { $controls.EmptyInfo.Visibility = & $emptyVis $info.Count }
        if ($controls.EmptyOk)   { $controls.EmptyOk.Visibility   = & $emptyVis $ok.Count }
        if ($controls.ExpMuted)  { $controls.ExpMuted.Visibility  = $(if ($muted.Count -gt 0) { 'Visible' } else { 'Collapsed' }) }
    } catch {}

    # Diagnostic event so we can see what happened to all findings
    try {
        $diagMsg = "Filter: in={0} out={1} suppressed={2} -> FAIL={3} WARN={4} INFO={5} OK={6} HiddenOK={7} HideHealthy={8} Filter='{9}'" -f `
            $stats.In, $stats.FilteredOut, $stats.Suppressed, $stats.FAIL, $stats.WARN, $stats.INFO, `
            $stats.OK, $stats.OKHidden, $script:HideHealthy, $filter
        if ($stats.OtherLevel.Count -gt 0) {
            $diagMsg += " UnexpectedLevels=[$(($stats.OtherLevel | Select-Object -Unique) -join ',')]"
        }
        Add-Event scan $diagMsg
    } catch {}
}

function Update-TabBadges {
    if (-not $controls -or -not $controls.LeftTabs) { return }
    # Count high-risk items per tab
    $procRisk    = @($script:Procs       | Where-Object { $_.Risk -in 'HIGH','WARN' }).Count
    $persistRisk = @($script:PersistItems | Where-Object { $_.Risk -in 'HIGH','WARN' }).Count
    $dnsRisk     = @($script:DnsItems    | Where-Object { $_.Risk -in 'HIGH','WARN' }).Count
    $diagFail    = $script:FindingsFail.Count + $script:FindingsWarn.Count
    $sessionN    = $script:Sessions.Count

    # Tab Header is now a StackPanel (Rectangle + label TextBlock + badge TextBlock).
    # Identify each tab by its Tag attribute (the logical name like 'DIAGNOSTICS') and update
    # ONLY the third child (the badge TextBlock) - DO NOT overwrite Header itself or it'll
    # become the string "System.Windows.Controls.StackPanel" via implicit ToString().
    foreach ($tab in $controls.LeftTabs.Items) {
        $name = [string]$tab.Tag
        if (-not $name) { continue }
        $count = switch ($name) {
            'DIAGNOSTICS' { $diagFail }
            'PROCESSES'   { $procRisk }
            'PERSISTENCE' { $persistRisk }
            'DNS'         { $dnsRisk }
            'HISTORY'     { $sessionN }
            default       { 0 }
        }
        try {
            # Header is the StackPanel; children are [Rectangle, label TextBlock, badge TextBlock]
            $sp = $tab.Header
            if ($sp -and $sp.Children.Count -ge 3) {
                $badgeTb = $sp.Children[2]
                if ($badgeTb -is [System.Windows.Controls.TextBlock]) {
                    if ($count -gt 0) {
                        $badgeTb.Text = "($count)"
                        # Color the badge red if there are warning-level items, otherwise muted
                        $badgeTb.Foreground = if ($count -ge 3) { (B '#f85149') } else { (B '#d29922') }
                    } else {
                        $badgeTb.Text = ''
                    }
                }
            }
        } catch {}
    }
}

function Render-ActivityRibbon {
    param($Canvas)
    if (-not $Canvas) { return }
    $Canvas.Children.Clear()
    $w = [double]$Canvas.ActualWidth;  if ($w -le 0) { return }
    $h = [double]$Canvas.ActualHeight; if ($h -le 0) { return }
    $now = Get-Date

    # Position labels along the BOTTOM of the canvas instead of above the baseline -
    # the previous code placed them at h/2 - 16 which clipped above the canvas at small heights.
    $labelY = [Math]::Max(0, $h - 12)
    $baselineY = if ($h -lt 26) { $h / 2 - 1 } else { $h / 2 }   # nudge baseline up slightly when ribbon is tall enough to fit labels above

    # baseline
    $base = New-Object System.Windows.Shapes.Line -Property @{
        X1 = 0; X2 = $w; Y1 = $baselineY; Y2 = $baselineY
        Stroke = (B '#2a3142'); StrokeThickness = 1.2
    }
    [void]$Canvas.Children.Add($base)
    # 10-minute tick marks
    for ($m = 0; $m -le 60; $m += 10) {
        $x = $w - ($w * ($m / 60))
        $tick = New-Object System.Windows.Shapes.Line -Property @{
            X1 = $x; X2 = $x; Y1 = ($baselineY - 3); Y2 = ($baselineY + 3)
            Stroke = (B '#3a4152'); StrokeThickness = 0.6
        }
        [void]$Canvas.Children.Add($tick)
        if ($m -eq 0 -or $m -eq 60) {
            $lbl = New-Object System.Windows.Controls.TextBlock
            $lbl.Text = if ($m -eq 0) { 'NOW' } else { '60m ago' }
            $lbl.Foreground = (B '#6a7380')
            $lbl.FontSize = 9
            [System.Windows.Controls.Canvas]::SetLeft($lbl, $(if ($m -eq 0) { [Math]::Max(0, $w - 30) } else { 2 }))
            [System.Windows.Controls.Canvas]::SetTop($lbl, 0)
            [void]$Canvas.Children.Add($lbl)
        }
    }
    # If no events yet, surface a hint so the user knows the ribbon IS working - just empty.
    if ($script:ActivityEvents.Count -eq 0) {
        $hint = New-Object System.Windows.Controls.TextBlock
        $hint.Text = '(no activity in the last 60 min - flaps / scans / fixes / alerts will appear as dots here)'
        $hint.Foreground = (B '#3a4152')
        $hint.FontSize = 9
        $hint.FontStyle = 'Italic'
        [System.Windows.Controls.Canvas]::SetLeft($hint, 36)
        [System.Windows.Controls.Canvas]::SetTop($hint, [Math]::Max(0, $baselineY - 6))
        [void]$Canvas.Children.Add($hint)
    }
    # event ticks
    foreach ($e in $script:ActivityEvents) {
        $age = ($now - $e.Time).TotalMinutes
        if ($age -gt 60 -or $age -lt 0) { continue }
        $x = $w - ($w * ($age / 60))
        $color = switch ($e.Type) {
            'flap'     { '#f85149' }
            'recovery' { '#3fb950' }
            'fix'      { '#1f6feb' }
            'scan'     { '#bf6dff' }
            'alert'    { '#d29922' }
            default    { '#8b95a8' }
        }
        $halo = New-Object System.Windows.Shapes.Ellipse -Property @{
            Width = 12; Height = 12; Fill = (B $color); Opacity = 0.25
        }
        [System.Windows.Controls.Canvas]::SetLeft($halo, $x - 6)
        [System.Windows.Controls.Canvas]::SetTop($halo, $baselineY - 6)
        [void]$Canvas.Children.Add($halo)
        $dot = New-Object System.Windows.Shapes.Ellipse -Property @{
            Width = 6; Height = 6; Fill = (B $color)
        }
        $dot.ToolTip = "{0} at {1:HH:mm:ss} ({2:N0}m ago)" -f $e.Type, $e.Time, $age
        [System.Windows.Controls.Canvas]::SetLeft($dot, $x - 3)
        [System.Windows.Controls.Canvas]::SetTop($dot, $baselineY - 3)
        [void]$Canvas.Children.Add($dot)
    }
}

# ---------- Tier 19: in-window flap-capture timeline viewer ----------
# Parses the dossier's capture.txt (etl2txt output) into per-second protocol buckets
# and renders a multi-track timeline you can scrub in-window without leaving the HUD.
$script:TimelineProtocols = @(
    @{ Key='Arp';   Label='ARP';     Color='#7ee787' }
    @{ Key='Dhcp';  Label='DHCP';    Color='#58a6ff' }
    @{ Key='Dns';   Label='DNS';     Color='#bf6dff' }
    @{ Key='Icmp';  Label='ICMP';    Color='#d29922' }
    @{ Key='Rst';   Label='TCP RST'; Color='#f85149' }
    @{ Key='Other'; Label='OTHER';   Color='#8b95a8' }
)

function Parse-CaptureTimeline {
    param([string]$Path)
    if (-not (Test-Path $Path)) { return $null }
    try {
        $lines = Get-Content $Path -Tail 30000 -ErrorAction Stop
    } catch { return $null }
    if (-not $lines) { return $null }
    $buckets = [ordered]@{}
    foreach ($l in $lines) {
        if ($l -notmatch '^\s*(\d{2}:\d{2}:\d{2})') { continue }
        $sec = $matches[1]
        if (-not $buckets.Contains($sec)) {
            $buckets[$sec] = @{ Arp=0; Dhcp=0; Dns=0; Icmp=0; Rst=0; Other=0 }
        }
        if ($l -match '\b(ARP|0x0806)\b') { $buckets[$sec].Arp++; continue }
        if ($l -match '\b(DHCP|bootp)\b' -or $l -match '\bport\s*(67|68)\b' -or $l -match '\b(67|68)\s*->\s*(67|68)\b') { $buckets[$sec].Dhcp++; continue }
        if ($l -match '\bDNS\b' -or $l -match '\bport\s*53\b' -or $l -match '\b53\s*->\b' -or $l -match '\bdoh\b') { $buckets[$sec].Dns++; continue }
        if ($l -match '\bICMP\b' -or $l -match '\b0x0001\b') { $buckets[$sec].Icmp++; continue }
        if ($l -match '\b\[RST\]' -or ($l -match '\bTCP\b' -and $l -match '\bRST\b')) { $buckets[$sec].Rst++; continue }
        $buckets[$sec].Other++
    }
    if ($buckets.Count -eq 0) { return $null }
    $secs = @($buckets.Keys)
    $rows = foreach ($s in $secs) { [pscustomobject]@{
        Sec=$s; Arp=$buckets[$s].Arp; Dhcp=$buckets[$s].Dhcp; Dns=$buckets[$s].Dns
        Icmp=$buckets[$s].Icmp; Rst=$buckets[$s].Rst; Other=$buckets[$s].Other
        Total=$buckets[$s].Arp + $buckets[$s].Dhcp + $buckets[$s].Dns + $buckets[$s].Icmp + $buckets[$s].Rst + $buckets[$s].Other
    } }
    return @{ Rows = @($rows); First = $secs[0]; Last = $secs[-1]; LineCount = $lines.Count }
}

function Render-TimelineCanvas {
    param($Canvas, $Data, $StatusText)
    $Canvas.Children.Clear()
    if (-not $Data -or $Data.Rows.Count -eq 0) { $StatusText.Text = 'No data parsed (capture.txt empty or still being generated).'; return }
    $w = [double]$Canvas.ActualWidth;  if ($w -le 0) { return }
    $h = [double]$Canvas.ActualHeight; if ($h -le 0) { return }
    $rows = $Data.Rows
    $n = $rows.Count
    $marginLeft = 70
    $marginBottom = 22
    $trackH = ($h - $marginBottom) / $script:TimelineProtocols.Count
    $cellW = ($w - $marginLeft) / $n
    if ($cellW -lt 1) { $cellW = 1 }
    # per-protocol max for normalized bar heights
    $perMax = @{}
    foreach ($p in $script:TimelineProtocols) {
        $vals = $rows | ForEach-Object { [int]$_.($p.Key) }
        $m = ($vals | Measure-Object -Maximum).Maximum
        if ($m -le 0) { $m = 1 }
        $perMax[$p.Key] = $m
    }
    # track label + bars
    for ($t = 0; $t -lt $script:TimelineProtocols.Count; $t++) {
        $p = $script:TimelineProtocols[$t]
        $yTop = $t * $trackH
        $yBot = $yTop + $trackH - 2
        $brush = (B $p.Color)
        # label
        $lbl = New-Object System.Windows.Controls.TextBlock
        $lbl.Text = $p.Label
        $lbl.Foreground = $brush
        $lbl.FontSize = 10
        $lbl.FontWeight = 'SemiBold'
        [System.Windows.Controls.Canvas]::SetLeft($lbl, 6)
        [System.Windows.Controls.Canvas]::SetTop($lbl, $yTop + ($trackH/2) - 7)
        [void]$Canvas.Children.Add($lbl)
        # baseline track strip (very faint)
        $strip = New-Object System.Windows.Shapes.Rectangle -Property @{
            Width=($w - $marginLeft); Height=($trackH - 2)
            Fill=$brush; Opacity=0.05
        }
        [System.Windows.Controls.Canvas]::SetLeft($strip, $marginLeft)
        [System.Windows.Controls.Canvas]::SetTop($strip, $yTop)
        [void]$Canvas.Children.Add($strip)
        # bars
        $max = $perMax[$p.Key]
        for ($i = 0; $i -lt $n; $i++) {
            $v = [int]$rows[$i].($p.Key)
            if ($v -le 0) { continue }
            $barH = ($trackH - 4) * ($v / $max)
            $bar = New-Object System.Windows.Shapes.Rectangle -Property @{
                Width=[Math]::Max(1, $cellW - 0.5); Height=$barH
                Fill=$brush
            }
            $bar.ToolTip = "{0} @ {1}: {2}" -f $p.Label, $rows[$i].Sec, $v
            [System.Windows.Controls.Canvas]::SetLeft($bar, $marginLeft + $i * $cellW)
            [System.Windows.Controls.Canvas]::SetTop($bar, $yBot - $barH)
            [void]$Canvas.Children.Add($bar)
        }
    }
    # x-axis time ticks every ~10 cells
    $tickStep = [Math]::Max(1, [Math]::Floor($n / 10))
    for ($i = 0; $i -lt $n; $i += $tickStep) {
        $tx = $marginLeft + $i * $cellW
        $tk = New-Object System.Windows.Controls.TextBlock
        $tk.Text = $rows[$i].Sec
        $tk.Foreground = (B '#8b95a8')
        $tk.FontSize = 9
        $tk.FontFamily = 'Consolas'
        [System.Windows.Controls.Canvas]::SetLeft($tk, $tx - 24)
        [System.Windows.Controls.Canvas]::SetTop($tk, $h - $marginBottom + 4)
        [void]$Canvas.Children.Add($tk)
        $tline = New-Object System.Windows.Shapes.Line -Property @{
            X1=$tx; X2=$tx; Y1=0; Y2=($h - $marginBottom)
            Stroke=(B '#2a3142'); StrokeThickness=0.4; Opacity=0.5
        }
        [void]$Canvas.Children.Add($tline)
    }
    $totalEvents = ($rows | Measure-Object -Property Total -Sum).Sum
    $StatusText.Text = ("{0} seconds, {1} events parsed (window {2} - {3}, capture.txt {4} lines tail)" -f $n, $totalEvents, $Data.First, $Data.Last, $Data.LineCount)
}

function Show-FlapTimeline {
    $dossiers = @(Get-ChildItem -Path $script:FlapsRoot -Directory -ErrorAction SilentlyContinue |
        Sort-Object LastWriteTime -Descending |
        Where-Object { Test-Path (Join-Path $_.FullName 'capture.txt') } |
        Select-Object -First 30)
    if ($dossiers.Count -eq 0) {
        [System.Windows.MessageBox]::Show($window, 'No flap dossiers with a capture.txt found yet. The HUD writes one every time the link drops; if pktmon is unavailable or the etl2txt job hasn''t finished yet, no capture is available.', 'No data', 'OK', 'Information') | Out-Null
        return
    }
    [xml]$x = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="NetJump - Flap timeline" Width="1080" Height="640" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BrushWindowBg}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Segoe UI">
    <Grid Margin="16">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>
        <StackPanel Grid.Row="0" Orientation="Horizontal" Margin="0,0,0,8">
            <TextBlock Text="Dossier:" Foreground="{DynamicResource BrushFgMuted}" FontSize="12" VerticalAlignment="Center" Margin="0,0,8,0"/>
            <ComboBox x:Name="DossierCombo" Style="{StaticResource DarkCombo}" Width="420" FontSize="12" FontFamily="Consolas"/>
            <Button x:Name="OpenFolderBtn" Content="Open dossier folder" Padding="10,4" FontSize="11" Margin="12,0,0,0" Background="{DynamicResource BrushBorder}" Foreground="{DynamicResource BrushFgPrimary}" BorderBrush="{DynamicResource BrushHoverBg}"/>
        </StackPanel>
        <TextBlock Grid.Row="1" x:Name="StatusText" Text="Loading..." Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,0,0,4"/>
        <StackPanel Grid.Row="2" Orientation="Horizontal" Margin="0,0,0,6">
            <TextBlock Text="LEGEND:" Foreground="{DynamicResource BrushFgMuted}" FontSize="10" VerticalAlignment="Center" Margin="0,0,8,0"/>
            <Rectangle Width="10" Height="10" Fill="#7ee787" Margin="0,0,4,0" VerticalAlignment="Center"/>
            <TextBlock Text="ARP" FontSize="10" Foreground="#7ee787" Margin="0,0,12,0" VerticalAlignment="Center"/>
            <Rectangle Width="10" Height="10" Fill="#58a6ff" Margin="0,0,4,0" VerticalAlignment="Center"/>
            <TextBlock Text="DHCP" FontSize="10" Foreground="#58a6ff" Margin="0,0,12,0" VerticalAlignment="Center"/>
            <Rectangle Width="10" Height="10" Fill="#bf6dff" Margin="0,0,4,0" VerticalAlignment="Center"/>
            <TextBlock Text="DNS" FontSize="10" Foreground="#bf6dff" Margin="0,0,12,0" VerticalAlignment="Center"/>
            <Rectangle Width="10" Height="10" Fill="#d29922" Margin="0,0,4,0" VerticalAlignment="Center"/>
            <TextBlock Text="ICMP" FontSize="10" Foreground="#d29922" Margin="0,0,12,0" VerticalAlignment="Center"/>
            <Rectangle Width="10" Height="10" Fill="#f85149" Margin="0,0,4,0" VerticalAlignment="Center"/>
            <TextBlock Text="TCP RST" FontSize="10" Foreground="#f85149" Margin="0,0,12,0" VerticalAlignment="Center"/>
            <Rectangle Width="10" Height="10" Fill="#8b95a8" Margin="0,0,4,0" VerticalAlignment="Center"/>
            <TextBlock Text="OTHER" FontSize="10" Foreground="#8b95a8" VerticalAlignment="Center"/>
        </StackPanel>
        <Border Grid.Row="3" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6">
            <Canvas x:Name="TimelineCanvas" ClipToBounds="True"/>
        </Border>
        <Button Grid.Row="4" x:Name="CloseBtn" Content="Close" Padding="14,5" HorizontalAlignment="Right" Margin="0,12,0,0" Background="{DynamicResource BrushBorder}" Foreground="{DynamicResource BrushFgPrimary}" BorderBrush="{DynamicResource BrushHoverBg}"/>
    </Grid>
</Window>
'@
    $rdr = New-Object System.Xml.XmlNodeReader $x
    $w = [Windows.Markup.XamlReader]::Load($rdr)
    $w.Owner = $window
    Wire-DialogEscClose $w   # Tier 55: ESC closes the dialog
    Apply-ThemeToChild $w
    $combo = $w.FindName('DossierCombo')
    $canvas = $w.FindName('TimelineCanvas')
    $status = $w.FindName('StatusText')
    $combo.ItemsSource = @($dossiers | ForEach-Object { $_.Name })
    $combo.SelectedIndex = 0
    $loadAndRender = {
        $idx = $combo.SelectedIndex
        if ($idx -lt 0) { return }
        $dossier = $dossiers[$idx]
        $status.Text = "Parsing $($dossier.Name)/capture.txt..."
        $w.Dispatcher.InvokeAsync({
            $data = Parse-CaptureTimeline (Join-Path $dossier.FullName 'capture.txt')
            Render-TimelineCanvas -Canvas $canvas -Data $data -StatusText $status
        }) | Out-Null
    }
    $combo.Add_SelectionChanged($loadAndRender)
    $w.FindName('OpenFolderBtn').Add_Click({
        $idx = $combo.SelectedIndex
        if ($idx -ge 0) { Start-Process explorer.exe $dossiers[$idx].FullName }
    })
    $w.FindName('CloseBtn').Add_Click({ $w.Close() })
    $w.Add_Loaded({ & $loadAndRender })
    $w.Add_SizeChanged({ & $loadAndRender })
    $w.ShowDialog() | Out-Null
}

# ---------- Tier 16: connection world-map popup ----------
function Show-ConnectionMap {
    if (-not $script:Ledger -or $script:Ledger.Count -eq 0) {
        [System.Windows.MessageBox]::Show($window, 'Connection ledger is empty - leave the HUD running for a few minutes to accumulate samples.', 'No data', 'OK', 'Information') | Out-Null
        return
    }
    # aggregate ledger entries by country
    $byCountry = @{}
    foreach ($v in $script:Ledger.Values) {
        $cc = Get-CountryFromLabel $v.label
        if (-not $cc) { continue }
        if (-not $script:CountryCoords.ContainsKey($cc)) { continue }
        if (-not $byCountry.ContainsKey($cc)) { $byCountry[$cc] = @{ Count=0; Samples=0; Procs=@{} } }
        $byCountry[$cc].Count   = $byCountry[$cc].Count + 1
        $byCountry[$cc].Samples = $byCountry[$cc].Samples + [int]$v.samples
        $byCountry[$cc].Procs[$v.proc] = $true
    }

    [xml]$x = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="NetJump - Connection map" Width="900" Height="600" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BrushWindowBg}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Segoe UI">
    <Grid Margin="16">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>
        <TextBlock Grid.Row="0" x:Name="MapHeader" Text="Connections by country" FontSize="13" FontWeight="SemiBold" Foreground="#58a6ff" Margin="0,0,0,8"/>
        <Border Grid.Row="1" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6">
            <Canvas x:Name="MapCanvas" ClipToBounds="True"/>
        </Border>
        <Button Grid.Row="2" x:Name="CloseBtn" Content="Close" Padding="14,5" HorizontalAlignment="Right" Margin="0,12,0,0" Background="{DynamicResource BrushBorder}" Foreground="{DynamicResource BrushFgPrimary}" BorderBrush="{DynamicResource BrushHoverBg}"/>
    </Grid>
</Window>
'@
    $rdr = New-Object System.Xml.XmlNodeReader $x
    $w = [Windows.Markup.XamlReader]::Load($rdr)
    $w.Owner = $window
    Wire-DialogEscClose $w   # Tier 55: ESC closes the dialog
    Apply-ThemeToChild $w
    $canvas = $w.FindName('MapCanvas')
    $w.FindName('MapHeader').Text = "Connections by country  ({0} countries identified, {1} ledger entries with known geo)" -f $byCountry.Count, ($byCountry.Values | Measure-Object -Property Count -Sum).Sum
    $w.FindName('CloseBtn').Add_Click({ $w.Close() })

    $w.Add_Loaded({
        $cw = [double]$canvas.ActualWidth
        $ch = [double]$canvas.ActualHeight
        if ($cw -le 0 -or $ch -le 0) { return }
        # Mercator-ish equirectangular projection
        $proj = {
            param($lat, $lon)
            $x = ($lon + 180) * ($cw / 360)
            $y = (90 - $lat) * ($ch / 180)
            return @{ X=$x; Y=$y }
        }
        # grid lines every 30 degrees
        for ($lon = -180; $lon -le 180; $lon += 30) {
            $p = & $proj 0 $lon
            $line = New-Object System.Windows.Shapes.Line -Property @{
                X1=$p.X; X2=$p.X; Y1=0; Y2=$ch
                Stroke=[System.Windows.Media.Brushes]::DimGray
                StrokeThickness=0.4; Opacity=0.3
            }
            [void]$canvas.Children.Add($line)
        }
        for ($lat = -60; $lat -le 60; $lat += 30) {
            $p = & $proj $lat 0
            $line = New-Object System.Windows.Shapes.Line -Property @{
                X1=0; X2=$cw; Y1=$p.Y; Y2=$p.Y
                Stroke=[System.Windows.Media.Brushes]::DimGray
                StrokeThickness=0.4; Opacity=0.3
            }
            [void]$canvas.Children.Add($line)
        }
        # equator label
        $equator = New-Object System.Windows.Controls.TextBlock
        $equator.Text = '0 deg'
        $equator.Foreground = [System.Windows.Media.Brushes]::DimGray
        $equator.FontSize = 9
        $eqp = & $proj 0 -178
        [System.Windows.Controls.Canvas]::SetLeft($equator, $eqp.X)
        [System.Windows.Controls.Canvas]::SetTop($equator, $eqp.Y - 12)
        [void]$canvas.Children.Add($equator)

        # country dots
        $maxCount = ($byCountry.Values | Measure-Object -Property Count -Maximum).Maximum
        if ($maxCount -le 0) { $maxCount = 1 }
        foreach ($cc in $byCountry.Keys) {
            $coord = $script:CountryCoords[$cc]
            $p = & $proj $coord.Lat $coord.Lon
            $info = $byCountry[$cc]
            $size = [Math]::Min(36, 8 + ($info.Count / $maxCount) * 22)
            # Color: red for high-risk countries, amber for unknown, blue for normal
            $hex = switch ($cc) {
                'KP' { '#f85149' }
                'IR' { '#f85149' }
                'RU' { '#d29922' }
                'CN' { '#d29922' }
                default { '#58a6ff' }
            }
            $glow = New-Object System.Windows.Shapes.Ellipse -Property @{
                Width=($size + 12); Height=($size + 12)
                Fill=(B $hex); Opacity=0.18
            }
            [System.Windows.Controls.Canvas]::SetLeft($glow, $p.X - ($size + 12) / 2)
            [System.Windows.Controls.Canvas]::SetTop($glow, $p.Y - ($size + 12) / 2)
            [void]$canvas.Children.Add($glow)
            $dot = New-Object System.Windows.Shapes.Ellipse -Property @{
                Width=$size; Height=$size
                Fill=(B $hex); Stroke=[System.Windows.Media.Brushes]::White; StrokeThickness=1
            }
            $procList = ($info.Procs.Keys | Sort-Object | Select-Object -First 5) -join ', '
            $dot.ToolTip = ("{0} - {1} endpoint(s), {2} samples`nProcesses: {3}" -f $cc, $info.Count, $info.Samples, $procList)
            [System.Windows.Controls.Canvas]::SetLeft($dot, $p.X - $size / 2)
            [System.Windows.Controls.Canvas]::SetTop($dot, $p.Y - $size / 2)
            [void]$canvas.Children.Add($dot)
            # country label
            $lbl = New-Object System.Windows.Controls.TextBlock
            $lbl.Text = $cc
            $lbl.Foreground = (B '#d7dde6')
            $lbl.FontSize = 11
            $lbl.FontWeight = 'SemiBold'
            [System.Windows.Controls.Canvas]::SetLeft($lbl, $p.X + $size/2 + 4)
            [System.Windows.Controls.Canvas]::SetTop($lbl, $p.Y - 8)
            [void]$canvas.Children.Add($lbl)
        }
    })
    $w.ShowDialog() | Out-Null
}

# ---------- Tier 16: TLS certificate inspector ----------
function Get-TlsCert {
    param([string]$Host, [int]$Port = 443, [int]$TimeoutMs = 2000)
    try {
        $tcp = New-Object System.Net.Sockets.TcpClient
        $iar = $tcp.BeginConnect($Host, $Port, $null, $null)
        if (-not $iar.AsyncWaitHandle.WaitOne($TimeoutMs, $false)) { try { $tcp.Close() } catch {}; return $null }
        try { $tcp.EndConnect($iar) } catch { return $null }
        $cb = [System.Net.Security.RemoteCertificateValidationCallback]{ param($s,$c,$ch,$err) $true }
        $ssl = New-Object System.Net.Security.SslStream($tcp.GetStream(), $false, $cb)
        try { $ssl.AuthenticateAsClient($Host) } catch { try { $ssl.Close(); $tcp.Close() } catch {}; return $null }
        $cert = New-Object System.Security.Cryptography.X509Certificates.X509Certificate2($ssl.RemoteCertificate)
        $sans = @()
        try { $sans = @($cert.DnsNameList | Select-Object -ExpandProperty Unicode) } catch {}
        try { $ssl.Close(); $tcp.Close() } catch {}
        $issuerCN = ($cert.Issuer -split ',' | Where-Object { $_ -match '^\s*CN=' } | Select-Object -First 1) -replace '^\s*CN=',''
        [pscustomobject]@{
            Host       = $Host
            Subject    = $cert.Subject
            Issuer     = $cert.Issuer
            IssuerCN   = $issuerCN
            NotAfter   = $cert.NotAfter
            DaysValid  = [int](($cert.NotAfter - (Get-Date)).TotalDays)
            Thumbprint = $cert.Thumbprint
            SANs       = ($sans -join ', ')
            SelfSigned = ($cert.Subject -eq $cert.Issuer)
        }
    } catch { return $null }
}

function Inspect-TlsCertsAsync {
    if ($script:State.TlsJob) {
        [System.Windows.MessageBox]::Show($window, 'A TLS inspection is already running.', 'Already running', 'OK', 'Information') | Out-Null
        return
    }
    $tcps = Get-NetTCPConnection -State Established -ErrorAction SilentlyContinue |
            Where-Object { $_.RemotePort -eq 443 -and $_.RemoteAddress -and
                $_.RemoteAddress -notmatch '^(127\.|::1|192\.168\.|10\.|172\.(1[6-9]|2\d|3[01])\.|169\.254\.|0\.0\.0\.0|fe80:)' } |
            Select-Object -ExpandProperty RemoteAddress -Unique | Select-Object -First 30
    if (-not $tcps) {
        [System.Windows.MessageBox]::Show($window, 'No active outbound TLS (443) connections to inspect.', 'Nothing to scan', 'OK', 'Information') | Out-Null
        return
    }
    Add-Event scan ("TLS inspect: probing {0} active 443 endpoints..." -f $tcps.Count)
    $script:State.TlsJob = Start-Job -Name 'NetJump-TLS' -ScriptBlock {
        param($targets)
        $results = @()
        foreach ($h in $targets) {
            try {
                $tcp = New-Object System.Net.Sockets.TcpClient
                $iar = $tcp.BeginConnect($h, 443, $null, $null)
                if (-not $iar.AsyncWaitHandle.WaitOne(2000, $false)) { try { $tcp.Close() } catch {}; continue }
                try { $tcp.EndConnect($iar) } catch { continue }
                $cb = [System.Net.Security.RemoteCertificateValidationCallback]{ param($s,$c,$ch,$err) $true }
                $ssl = New-Object System.Net.Security.SslStream($tcp.GetStream(), $false, $cb)
                try { $ssl.AuthenticateAsClient($h) } catch { try { $ssl.Close(); $tcp.Close() } catch {}; continue }
                $cert = New-Object System.Security.Cryptography.X509Certificates.X509Certificate2($ssl.RemoteCertificate)
                $sans = @(); try { $sans = @($cert.DnsNameList | Select-Object -ExpandProperty Unicode) } catch {}
                try { $ssl.Close(); $tcp.Close() } catch {}
                $issuerCN = ($cert.Issuer -split ',' | Where-Object { $_ -match '^\s*CN=' } | Select-Object -First 1) -replace '^\s*CN=',''
                $results += [pscustomobject]@{
                    Host=$h; Subject=$cert.Subject; Issuer=$cert.Issuer; IssuerCN=$issuerCN
                    NotAfter=$cert.NotAfter; DaysValid=[int](($cert.NotAfter - (Get-Date)).TotalDays)
                    Thumbprint=$cert.Thumbprint; SANs=($sans -join ', ')
                    SelfSigned=($cert.Subject -eq $cert.Issuer)
                }
            } catch {}
        }
        $results
    } -ArgumentList (,$tcps)
}

function Show-TlsResults {
    param($Rows)
    if (-not $Rows -or @($Rows).Count -eq 0) {
        [System.Windows.MessageBox]::Show($window, 'TLS inspection returned no results (all probes timed out or were rejected).', 'No certs', 'OK', 'Information') | Out-Null
        return
    }
    [xml]$x = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="NetJump - TLS certificates" Width="900" Height="560" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BrushWindowBg}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Segoe UI">
    <Grid Margin="16">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>
        <TextBlock Grid.Row="0" x:Name="TlsHeader" Text="TLS certificates from active 443 connections" FontSize="13" FontWeight="SemiBold" Foreground="#58a6ff" Margin="0,0,0,12"/>
        <ScrollViewer Grid.Row="1" VerticalScrollBarVisibility="Auto">
            <ItemsControl x:Name="TlsList">
                <ItemsControl.ItemTemplate>
                    <DataTemplate>
                        <Border Background="{DynamicResource BrushCardBg}" BorderBrush="{Binding BorderColor}" BorderThickness="1" CornerRadius="6" Padding="12,10" Margin="0,0,0,6">
                            <StackPanel>
                                <StackPanel Orientation="Horizontal">
                                    <TextBlock Text="{Binding Host}" FontWeight="SemiBold" FontFamily="Consolas" Foreground="{DynamicResource BrushFgPrimary}"/>
                                    <Border Background="{Binding ChipColor}" CornerRadius="3" Padding="6,1" Margin="10,0,0,0">
                                        <TextBlock Text="{Binding ChipText}" Foreground="White" FontSize="10" FontWeight="Bold"/>
                                    </Border>
                                </StackPanel>
                                <TextBlock Text="{Binding IssuerLine}"  Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,4,0,0"/>
                                <TextBlock Text="{Binding ValidLine}"   Foreground="{DynamicResource BrushFgMuted}" FontSize="11"/>
                                <TextBlock Text="{Binding SansLine}"    Foreground="{DynamicResource BrushFgFaint}" FontSize="10" TextWrapping="Wrap"/>
                            </StackPanel>
                        </Border>
                    </DataTemplate>
                </ItemsControl.ItemTemplate>
            </ItemsControl>
        </ScrollViewer>
        <Button Grid.Row="2" x:Name="CloseBtn" Content="Close" Padding="14,5" HorizontalAlignment="Right" Margin="0,12,0,0" Background="{DynamicResource BrushBorder}" Foreground="{DynamicResource BrushFgPrimary}" BorderBrush="{DynamicResource BrushHoverBg}"/>
    </Grid>
</Window>
'@
    $rdr = New-Object System.Xml.XmlNodeReader $x
    $w = [Windows.Markup.XamlReader]::Load($rdr)
    $w.Owner = $window
    Wire-DialogEscClose $w   # Tier 55: ESC closes the dialog
    Apply-ThemeToChild $w
    $items = @($Rows | ForEach-Object {
        $chip = if ($_.SelfSigned) { 'SELF-SIGNED'; $hex='#f85149' }
                elseif ($_.DaysValid -lt 0) { 'EXPIRED'; $hex='#f85149' }
                elseif ($_.DaysValid -lt 14) { 'EXPIRING'; $hex='#d29922' }
                else { 'OK'; $hex='#3fb950' }
        if ($_.SelfSigned) { $hex = '#f85149'; $chip = 'SELF-SIGNED' }
        elseif ($_.DaysValid -lt 0) { $hex = '#f85149'; $chip = 'EXPIRED' }
        elseif ($_.DaysValid -lt 14) { $hex = '#d29922'; $chip = ("EXPIRES {0}d" -f $_.DaysValid) }
        else { $hex = '#3fb950'; $chip = ("OK ({0}d left)" -f $_.DaysValid) }
        [pscustomobject]@{
            Host        = $_.Host
            ChipText    = $chip
            ChipColor   = (B $hex)
            BorderColor = (B $hex)
            IssuerLine  = "Issuer: $($_.IssuerCN)"
            ValidLine   = "Valid until: $($_.NotAfter)   Subject: $($_.Subject)"
            SansLine    = if ($_.SANs) { "SANs: $($_.SANs)" } else { '' }
        }
    })
    $list = $w.FindName('TlsList')
    $list.ItemsSource = $items
    $w.FindName('TlsHeader').Text = ("TLS certificates from active 443 connections  ({0} probed)" -f @($Rows).Count)
    $w.FindName('CloseBtn').Add_Click({ $w.Close() })
    $w.ShowDialog() | Out-Null
}

# ---------- Tier 16: pluggable detection rules ----------
$script:RulesDir = Join-Path $PSScriptRoot 'Reports\Rules'
if (-not (Test-Path $script:RulesDir)) {
    New-Item -ItemType Directory -Path $script:RulesDir -Force | Out-Null
    # seed README on first run so users know what goes here
    $readme = @"
NetJump custom detection rules
==============================

Drop .ps1 files in this folder. Each must define a function named Test-NetJumpRule
that returns one or more pscustomobject findings:

    function Test-NetJumpRule {
        # available in scope: `$script:Procs, `$script:Ledger, `$script:Findings,
        # `$script:State.Adapter, `$script:State.Gateway, etc.
        if ((Get-Process -Name 'mimikatz' -ErrorAction SilentlyContinue)) {
            [pscustomobject]@{
                Level    = 'FAIL'
                Category = 'CustomRule'
                Message  = 'mimikatz process is running'
                Fix      = 'Kill it. Investigate parent process. Rotate creds.'
                Detail   = 'A process literally named mimikatz is running. This is the textbook credential-dumping tool.'
                Mitre    = 'unsigned-extern'
            }
        }
    }

Each .ps1 in this folder is dot-sourced on every Re-scan; output flows into the
DIAGNOSTICS tab alongside built-in findings.
"@
    Set-Content -Path (Join-Path $script:RulesDir 'README.txt') -Value $readme -Encoding UTF8
}

function Invoke-CustomRules {
    # Sandboxed custom-rule runner. Each .ps1 in $script:RulesDir is:
    #   1. PARSE-VALIDATED in the main thread before doing anything else (a syntax error in one rule
    #      file can no longer crash the scan).
    #   2. RUN IN A CHILD RUNSPACE so an exception, infinite loop, or runaway Write-Host can't
    #      damage scan state. Hard timeout: $script:CustomRuleTimeoutSec (default 5).
    #   3. RESULT-VALIDATED for the expected schema before being adopted as findings.
    # The script still exposes the Test-NetJumpRule contract: each rule file must export that
    # function returning zero or more objects with {Level, Category, Message, Fix, Detail, Mitre}.
    $out = New-Object System.Collections.Generic.List[object]
    $files = Get-ChildItem -Path $script:RulesDir -Filter '*.ps1' -ErrorAction SilentlyContinue
    if (-not $files) { return $out }
    $timeoutSec = if ($script:CustomRuleTimeoutSec) { [int]$script:CustomRuleTimeoutSec } else { 5 }
    if ($timeoutSec -lt 1)   { $timeoutSec = 1 }
    if ($timeoutSec -gt 60)  { $timeoutSec = 60 }
    foreach ($f in $files) {
        # Phase 1: parse-validate. A syntax error here means the rule file is broken; surface it
        # as a WARN finding and skip the actual execution. This is what stops "one bad rule crashes
        # the whole scan" from being possible.
        $parseErrors = $null
        try {
            $null = [System.Management.Automation.Language.Parser]::ParseFile($f.FullName, [ref]$null, [ref]$parseErrors)
        } catch {
            $out.Add((Add-Finding 'WARN' 'CustomRule' ("Rule '{0}' failed to parse: {1}" -f $f.Name, $_.Exception.Message)))
            continue
        }
        if ($parseErrors -and @($parseErrors).Count -gt 0) {
            $first = @($parseErrors)[0]
            $out.Add((Add-Finding 'WARN' 'CustomRule' ("Rule '{0}' has {1} parse error(s); first at line {2}: {3}" -f $f.Name, @($parseErrors).Count, $first.Extent.StartLineNumber, $first.Message)))
            continue
        }
        # Phase 2: run in child runspace with timeout. The runspace is fresh; if a rule defines
        # global variables, they don't leak back to the host. Output captured via Invoke-Command.
        $rs = $null; $ps = $null; $async = $null
        $results = $null
        try {
            $rs = [runspacefactory]::CreateRunspace()
            $rs.Open()
            $ps = [PowerShell]::Create()
            $ps.Runspace = $rs
            $sb = @"
. '$($f.FullName.Replace("'","''"))'
if (-not (Get-Command Test-NetJumpRule -ErrorAction SilentlyContinue)) {
    throw 'Rule did not export Test-NetJumpRule.'
}
@(Test-NetJumpRule)
"@
            [void]$ps.AddScript($sb)
            $async = $ps.BeginInvoke()
            if (-not $async.AsyncWaitHandle.WaitOne([TimeSpan]::FromSeconds($timeoutSec))) {
                # Timed out - kill the runspace and warn.
                try { $ps.Stop() } catch {}
                $out.Add((Add-Finding 'WARN' 'CustomRule' ("Rule '{0}' exceeded {1}s timeout - skipped." -f $f.Name, $timeoutSec)))
                continue
            }
            $results = $ps.EndInvoke($async)
            if ($ps.HadErrors -and $ps.Streams.Error.Count -gt 0) {
                $errMsg = ($ps.Streams.Error | Select-Object -First 1).Exception.Message
                $out.Add((Add-Finding 'WARN' 'CustomRule' ("Rule '{0}' threw: {1}" -f $f.Name, $errMsg)))
                continue
            }
        } catch {
            $out.Add((Add-Finding 'WARN' 'CustomRule' ("Rule '{0}' sandbox failure: {1}" -f $f.Name, $_.Exception.Message)))
            continue
        } finally {
            try { if ($ps) { $ps.Dispose() } } catch {}
            try { if ($rs) { $rs.Close(); $rs.Dispose() } } catch {}
        }
        # Phase 3: result-validate + adopt as findings. Each returned object must have a Level
        # field in the legal set; the rest are best-effort.
        $validLevels = @('OK','INFO','WARN','FAIL')
        $adopted = 0
        foreach ($entry in @($results)) {
            if (-not $entry) { continue }
            try {
                $level = if ($entry.PSObject.Properties['Level']) { [string]$entry.Level } else { 'INFO' }
                if ($validLevels -notcontains $level) { $level = 'INFO' }
                $cat = if ($entry.PSObject.Properties['Category']) { [string]$entry.Category } else { 'CustomRule' }
                $msg = if ($entry.PSObject.Properties['Message']) { [string]$entry.Message } else { 'rule fired (no message)' }
                $fix = if ($entry.PSObject.Properties['Fix']) { [string]$entry.Fix } else { '' }
                $det = if ($entry.PSObject.Properties['Detail']) { [string]$entry.Detail } else { ("Custom rule: {0}" -f $f.Name) }
                $mit = if ($entry.PSObject.Properties['Mitre']) { [string]$entry.Mitre } else { '' }
                $out.Add((Add-Finding $level $cat $msg $fix $det $mit))
                $adopted++
            } catch {}
        }
        # When the rule returned zero entries, still emit an INFO so the user can see it ran cleanly.
        if ($adopted -eq 0) {
            $out.Add((Add-Finding 'OK' 'CustomRule' ("Rule '{0}' ran cleanly, no findings." -f $f.Name)))
        }
    }
    return $out
}

# ---------- Tier 15: process tree popup ----------
function Show-FixPickerDialog {
    # Determine severity for each fix by matching to its originating finding.
    function script:_FixSeverity {
        param($Fix, $Findings)
        $desc = [string]$Fix.Description
        if (-not $desc) { return 'WARN' }
        foreach ($f in $Findings) {
            $msg = [string]$f.Message
            if (-not $msg) { continue }
            # Strategy 1: quoted phrase in description matches the message
            $m = [regex]::Match($desc, "'([^']+)'")
            if ($m.Success -and $msg -like "*$($m.Groups[1].Value)*") { return [string]$f.Level }
            # Strategy 2: token overlap
            $tokens = ($msg -split '[\s=\.,;:()]+' | Where-Object { $_.Length -ge 4 } | Select-Object -First 5)
            foreach ($tok in $tokens) {
                if ($desc -like "*$tok*") { return [string]$f.Level }
            }
        }
        return 'WARN'   # default for unmatched fixes
    }

    # Risk classifier: pattern-match the command to flag potentially-disruptive ones.
    # 'Disruptive' actions are unchecked by default and rendered with a warning chip.
    function script:_FixRisk {
        param([string]$Cmd)
        if (-not $Cmd) { return 'Safe' }
        $disruptivePatterns = @(
            'Disable-NetAdapterBinding'              # could break VPN/AV/3rd-party stack
            'Disable-WindowsOptionalFeature'         # often requires reboot
            'ipconfig\s+/release'                    # temporary disconnect
            'Set-DnsClientServerAddress.*-ServerAddresses'  # changes DNS resolver
            'Stop-Service'                           # could break depending on service
            'Remove-Service'
            'Disable-Service'
            'Set-Service.*-StartupType\s+Disabled'
            'Remove-NetFirewallRule'
            'Set-MpPreference.*-DisableRealtimeMonitoring'   # disables Defender RT
            'Set-ExecutionPolicy'
            'Disable-ScheduledTask'
            'Unregister-ScheduledTask'
            'Stop-Process'
            'shutdown'
            'Restart-Computer'
        )
        $moderatePatterns = @(
            'Set-NetAdapterAdvancedProperty'         # changes NIC props - rare break risk
            'Disable-NetAdapterPowerManagement'
            'Update-MpSignature'
            'Start-MpScan'                           # CPU spike
            'Set-ItemProperty.*ProxyEnable'          # proxy toggle
            'New-NetFirewallRule'                    # firewall additions
            'Add-Content.*hosts'
        )
        foreach ($p in $disruptivePatterns) { if ($Cmd -match $p) { return 'Disruptive' } }
        foreach ($p in $moderatePatterns)   { if ($Cmd -match $p) { return 'Moderate' } }
        return 'Safe'
    }

    # Aggregate fixes from multiple sources:
    # 1. $script:State.RecommendedFixes (built by Invoke-Diagnostics for power-saving etc.)
    # 2. Each cause's $cause.Fixes (added by Compute-RootCauses with cause-specific commands)
    # Dedup by Command string so the same fix doesn't appear twice.
    $allFixes = New-Object System.Collections.Generic.List[object]
    $seenCommands = @{}
    if ($script:State.RecommendedFixes) {
        foreach ($f in $script:State.RecommendedFixes) {
            $cmdKey = [string]$f.Command
            if (-not $cmdKey -or $seenCommands.ContainsKey($cmdKey)) { continue }
            $seenCommands[$cmdKey] = $true
            [void]$allFixes.Add(@{ Description = [string]$f.Description; Command = $cmdKey; Source = 'Diagnostics' })
        }
    }
    if ($script:Causes) {
        foreach ($c in $script:Causes) {
            if (-not $c.PSObject.Properties['Fixes'] -or -not $c.Fixes) { continue }
            foreach ($f in $c.Fixes) {
                $cmdKey = [string]$f.Command
                if (-not $cmdKey -or $seenCommands.ContainsKey($cmdKey)) { continue }
                $seenCommands[$cmdKey] = $true
                [void]$allFixes.Add(@{ Description = [string]$f.Description; Command = $cmdKey; Source = ('Cause: ' + ($c.Cause -split ' \(')[0]) })
            }
        }
    }

    if ($allFixes.Count -eq 0) {
        [System.Windows.MessageBox]::Show($window, "No automatic fixes are available right now.`n`nThis usually means:`n  - No diagnostic scan has run yet (click RUN NET DIAGNOSTIC), or`n  - All findings are informational/healthy and need no action, or`n  - The detected issues require manual remediation (cable swap, driver download, ISP call).`n`nCheck the TOP LIKELY CAUSES card - causes with no auto-fix have manual instructions in their Recommendation text.", 'No automatic fixes', 'OK', 'Information') | Out-Null
        return
    }

    # Group fixes by severity
    $groups = [ordered]@{
        FAIL = New-Object System.Collections.Generic.List[object]
        WARN = New-Object System.Collections.Generic.List[object]
        INFO = New-Object System.Collections.Generic.List[object]
        OK   = New-Object System.Collections.Generic.List[object]
    }
    $checkboxRefs = New-Object System.Collections.Generic.List[object]   # ref tracking for select-all
    foreach ($fx in $allFixes) {
        $sev = _FixSeverity $fx $script:Findings
        if (-not $groups.Contains($sev)) { $sev = 'WARN' }
        # Stash risk classification on the fix object for the row template to read
        $fx['Risk'] = _FixRisk $fx.Command
        $fx['Severity'] = $sev
        [void]$groups[$sev].Add($fx)
    }
    $totalFixes = ($groups.Values | ForEach-Object { $_.Count } | Measure-Object -Sum).Sum
    $disruptiveCount = @($allFixes | Where-Object { $_.Risk -eq 'Disruptive' }).Count
    $moderateCount = @($allFixes | Where-Object { $_.Risk -eq 'Moderate' }).Count
    $safeCount = $totalFixes - $disruptiveCount - $moderateCount

    [xml]$x = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="Apply Recommended Fixes" Width="820" Height="640" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BrushWindowBg}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Segoe UI">
  <Grid Margin="14">
    <Grid.RowDefinitions>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="*"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
    </Grid.RowDefinitions>
    <StackPanel Grid.Row="0" Margin="0,0,0,4">
      <TextBlock Text="APPLY RECOMMENDED FIXES" Foreground="#58a6ff" FontSize="11" FontWeight="Bold"/>
      <TextBlock x:Name="HeaderInfo" Text="" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,4,0,0" TextWrapping="Wrap"/>
    </StackPanel>
    <StackPanel Grid.Row="1" Orientation="Horizontal" Margin="0,8,0,8">
      <Button x:Name="AutoApplySafeBtn" Content="🚀 AUTO-APPLY ALL SAFE" Padding="10,4" FontSize="11" FontWeight="Bold" Margin="0,0,12,0" Background="#15803d" Foreground="#ffffff" BorderBrush="#3fb950" ToolTip="One-click: select every SAFE-tier fix across all severity buckets and apply them in sequence with a single confirmation. Skips MODERATE and DISRUPTIVE fixes."/>
      <Button x:Name="SelectAllBtn"  Content="Select all" Padding="8,3" FontSize="11" Margin="0,0,6,0"/>
      <Button x:Name="SelectNoneBtn" Content="Select none" Padding="8,3" FontSize="11" Margin="0,0,6,0"/>
      <Button x:Name="SelectFailBtn" Content="Critical only" Padding="8,3" FontSize="11" Margin="0,0,6,0" Background="#5a1018" Foreground="#ffffff" BorderBrush="#f85149"/>
      <Button x:Name="SelectWarnBtn" Content="Warnings only" Padding="8,3" FontSize="11" Margin="0,0,0,0" Background="#3d2c0a" Foreground="#ffffff" BorderBrush="#d29922"/>
    </StackPanel>
    <Border Grid.Row="2" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="4" Background="{DynamicResource BrushDeepBg}">
      <ScrollViewer VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Disabled" Padding="8">
        <StackPanel x:Name="GroupHost"/>
      </ScrollViewer>
    </Border>
    <TextBlock Grid.Row="3" x:Name="StatusLine" Text="" Foreground="{DynamicResource BrushFgFaint}" FontSize="11" Margin="0,8,0,0" TextWrapping="Wrap"/>
    <StackPanel Grid.Row="4" Orientation="Horizontal" HorizontalAlignment="Right" Margin="0,12,0,0">
      <Button x:Name="ApplyBtn"  Content="Apply selected" Padding="14,5" Margin="0,0,8,0" Background="#1f6feb" Foreground="#ffffff" BorderBrush="#2f7fff" FontWeight="Bold" IsDefault="True"/>
      <Button x:Name="CancelBtn" Content="Cancel" Padding="10,5" Background="{DynamicResource BrushBorder}" Foreground="{DynamicResource BrushFgPrimary}" BorderBrush="{DynamicResource BrushHoverBg}"/>
    </StackPanel>
  </Grid>
</Window>
'@
    $rdr = New-Object System.Xml.XmlNodeReader $x
    $w = [Windows.Markup.XamlReader]::Load($rdr)
    if ($window) { $w.Owner = $window }
    Wire-DialogEscClose $w   # Tier 55: ESC closes the dialog
    Apply-ThemeToChild $w

    $headerInfo = $w.FindName('HeaderInfo')
    $headerInfo.Text = ("{0} fix(es) available - by severity: CRITICAL {1} / WARNINGS {2} / INFO {3} / HEALTHY {4}.   Risk: {5} safe, {6} moderate, {7} disruptive (disruptive items pre-unchecked - opt in by ticking)." -f `
        $totalFixes, $groups['FAIL'].Count, $groups['WARN'].Count, $groups['INFO'].Count, $groups['OK'].Count, $safeCount, $moderateCount, $disruptiveCount)

    $groupHost = $w.FindName('GroupHost')
    $statusLine = $w.FindName('StatusLine')

    # Build sections per severity
    $sevConfigs = @(
        @{ Key='FAIL'; Title='CRITICAL'; Color='#f85149'; Bg='#3a0a0c' }
        @{ Key='WARN'; Title='WARNINGS'; Color='#d29922'; Bg='#3a2c0a' }
        @{ Key='INFO'; Title='INFO';     Color='#58a6ff'; Bg='#0d2540' }
        @{ Key='OK';   Title='HEALTHY';  Color='#3fb950'; Bg='#0e2a16' }
    )
    foreach ($cfg in $sevConfigs) {
        $list = $groups[$cfg.Key]
        if ($list.Count -eq 0) { continue }

        # Section header
        $header = New-Object System.Windows.Controls.Border
        $header.Background = (B $cfg.Bg)
        $header.BorderBrush = (B $cfg.Color)
        $header.BorderThickness = '0,0,0,2'
        $header.Padding = '10,6'
        $header.Margin = '0,8,0,0'
        $hStack = New-Object System.Windows.Controls.StackPanel
        $hStack.Orientation = 'Horizontal'
        $countBadge = New-Object System.Windows.Controls.Border
        $countBadge.Background = (B $cfg.Color)
        $countBadge.CornerRadius = '3'
        $countBadge.Padding = '6,1'
        $countBadge.MinWidth = 30
        $countTb = New-Object System.Windows.Controls.TextBlock
        $countTb.Text = [string]$list.Count
        $countTb.Foreground = (B '#ffffff')
        $countTb.FontWeight = 'Bold'
        $countTb.FontSize = 10
        $countTb.HorizontalAlignment = 'Center'
        $countBadge.Child = $countTb
        $titleTb = New-Object System.Windows.Controls.TextBlock
        $titleTb.Text = $cfg.Title
        $titleTb.Foreground = (B $cfg.Color)
        $titleTb.FontWeight = 'Bold'
        $titleTb.FontSize = 12
        $titleTb.Margin = '8,0,0,0'
        $titleTb.VerticalAlignment = 'Center'
        [void]$hStack.Children.Add($countBadge)
        [void]$hStack.Children.Add($titleTb)
        $header.Child = $hStack
        [void]$groupHost.Children.Add($header)

        # Fix rows
        foreach ($fx in $list) {
            $row = New-Object System.Windows.Controls.Border
            $row.BorderBrush = $window.Resources['BrushBorder']
            $row.BorderThickness = '0,0,0,1'
            $row.Padding = '10,8'
            # Subtle background tint for disruptive rows so the warning is visible at a glance
            if ($fx.Risk -eq 'Disruptive') {
                $row.Background = (B '#2a1414')
            } elseif ($fx.Risk -eq 'Moderate') {
                $row.Background = (B '#1f1a14')
            }
            $rowGrid = New-Object System.Windows.Controls.Grid
            $col1 = New-Object System.Windows.Controls.ColumnDefinition; $col1.Width = 'Auto'
            $col2 = New-Object System.Windows.Controls.ColumnDefinition; $col2.Width = New-Object System.Windows.GridLength 1, 'Star'
            [void]$rowGrid.ColumnDefinitions.Add($col1)
            [void]$rowGrid.ColumnDefinitions.Add($col2)

            $cb = New-Object System.Windows.Controls.CheckBox
            # Default-check: SAFE+MODERATE in CRITICAL/WARNINGS sections only.
            # Disruptive items are NEVER pre-checked - user must opt in explicitly.
            # INFO/HEALTHY sections also pre-unchecked.
            $cb.IsChecked = (
                ($cfg.Key -eq 'FAIL' -or $cfg.Key -eq 'WARN') -and
                ($fx.Risk -ne 'Disruptive')
            )
            $cb.VerticalAlignment = 'Top'
            $cb.Margin = '0,2,10,0'
            $cb.Tag = $fx   # stash the fix object on the checkbox
            [System.Windows.Controls.Grid]::SetColumn($cb, 0)
            [void]$rowGrid.Children.Add($cb)
            [void]$checkboxRefs.Add($cb)

            $infoStack = New-Object System.Windows.Controls.StackPanel

            # Top line: description + risk badge + source chip
            $topLine = New-Object System.Windows.Controls.StackPanel
            $topLine.Orientation = 'Horizontal'
            $descTb = New-Object System.Windows.Controls.TextBlock
            $descTb.Text = [string]$fx.Description
            $descTb.Foreground = $window.Resources['BrushFgPrimary']
            $descTb.FontSize = 12
            $descTb.FontWeight = 'SemiBold'
            $descTb.TextWrapping = 'Wrap'
            [void]$topLine.Children.Add($descTb)
            # Risk badge
            $riskBadge = New-Object System.Windows.Controls.Border
            $riskBadge.CornerRadius = '3'
            $riskBadge.Padding = '5,1'
            $riskBadge.Margin = '8,0,0,0'
            $riskBadge.VerticalAlignment = 'Center'
            $riskBadgeTb = New-Object System.Windows.Controls.TextBlock
            $riskBadgeTb.FontSize = 9
            $riskBadgeTb.FontWeight = 'Bold'
            switch ($fx.Risk) {
                'Disruptive' {
                    $riskBadge.Background = (B '#5a1018')
                    $riskBadge.BorderBrush = (B '#f85149'); $riskBadge.BorderThickness = '1'
                    $riskBadgeTb.Text = '⚠ DISRUPTIVE'; $riskBadgeTb.Foreground = (B '#f85149')
                    $riskBadge.ToolTip = 'May break VPN/AV, require reboot, or temporarily disconnect. Opt in only if you understand the change.'
                }
                'Moderate' {
                    $riskBadge.Background = (B '#3d2c0a')
                    $riskBadge.BorderBrush = (B '#d29922'); $riskBadge.BorderThickness = '1'
                    $riskBadgeTb.Text = 'MODERATE'; $riskBadgeTb.Foreground = (B '#d29922')
                    $riskBadge.ToolTip = 'Changes a system setting. Reversible but worth reviewing the command.'
                }
                default {
                    $riskBadge.Background = (B '#0e2a16')
                    $riskBadge.BorderBrush = (B '#3fb950'); $riskBadge.BorderThickness = '1'
                    $riskBadgeTb.Text = 'SAFE'; $riskBadgeTb.Foreground = (B '#3fb950')
                    $riskBadge.ToolTip = 'Low-risk action. Easily reversible.'
                }
            }
            $riskBadge.Child = $riskBadgeTb
            [void]$topLine.Children.Add($riskBadge)
            # Source chip
            if ($fx.Source) {
                $srcTb = New-Object System.Windows.Controls.TextBlock
                $srcTb.Text = "  $($fx.Source)"
                $srcTb.Foreground = $window.Resources['BrushFgFaint']
                $srcTb.FontSize = 10
                $srcTb.VerticalAlignment = 'Center'
                $srcTb.Margin = '6,0,0,0'
                [void]$topLine.Children.Add($srcTb)
            }
            [void]$infoStack.Children.Add($topLine)

            # Command preview (Consolas font)
            $cmdTb = New-Object System.Windows.Controls.TextBlock
            $cmdTb.Text = "  " + [string]$fx.Command
            $cmdTb.Foreground = $window.Resources['BrushFgMuted']
            $cmdTb.FontSize = 10
            $cmdTb.FontFamily = 'Consolas'
            $cmdTb.Margin = '0,3,0,0'
            $cmdTb.TextWrapping = 'Wrap'
            [void]$infoStack.Children.Add($cmdTb)

            [System.Windows.Controls.Grid]::SetColumn($infoStack, 1)
            [void]$rowGrid.Children.Add($infoStack)

            $row.Child = $rowGrid
            [void]$groupHost.Children.Add($row)
        }
    }

    $updateStatus = {
        $checked = @($checkboxRefs | Where-Object { $_.IsChecked }).Count
        $statusLine.Text = ("{0} of {1} selected" -f $checked, $checkboxRefs.Count)
    }.GetNewClosure()
    foreach ($cb in $checkboxRefs) {
        $cb.Add_Checked({ & $updateStatus }.GetNewClosure())
        $cb.Add_Unchecked({ & $updateStatus }.GetNewClosure())
    }
    & $updateStatus

    $w.FindName('SelectAllBtn').Add_Click({
        foreach ($cb in $checkboxRefs) { $cb.IsChecked = $true }
        & $updateStatus
    }.GetNewClosure())
    $w.FindName('SelectNoneBtn').Add_Click({
        foreach ($cb in $checkboxRefs) { $cb.IsChecked = $false }
        & $updateStatus
    }.GetNewClosure())
    $w.FindName('SelectFailBtn').Add_Click({
        foreach ($cb in $checkboxRefs) {
            $sev = _FixSeverity $cb.Tag $script:Findings
            $cb.IsChecked = ($sev -eq 'FAIL')
        }
        & $updateStatus
    }.GetNewClosure())
    $w.FindName('SelectWarnBtn').Add_Click({
        foreach ($cb in $checkboxRefs) {
            $sev = _FixSeverity $cb.Tag $script:Findings
            $cb.IsChecked = ($sev -eq 'FAIL' -or $sev -eq 'WARN')
        }
        & $updateStatus
    }.GetNewClosure())

    # AUTO-APPLY ALL SAFE: select every SAFE-tier fix across ALL severity buckets and apply them
    # in sequence with a single confirmation. Skips MODERATE and DISRUPTIVE fixes - those still
    # require explicit per-row opt-in.
    $w.FindName('AutoApplySafeBtn').Add_Click({
        # First select only the safe items
        foreach ($cb in $checkboxRefs) {
            $cb.IsChecked = ($cb.Tag.Risk -eq 'Safe')
        }
        & $updateStatus
        $safeSelected = @($checkboxRefs | Where-Object { $_.IsChecked } | ForEach-Object { $_.Tag })
        if ($safeSelected.Count -eq 0) {
            [System.Windows.MessageBox]::Show($w, "No SAFE fixes available right now.`n`nThe picker found no fixes classified as SAFE. There may be MODERATE or DISRUPTIVE fixes you can opt into manually by checking specific rows.", 'Nothing to auto-apply', 'OK', 'Information') | Out-Null
            return
        }
        $confirmText = ("AUTO-APPLY {0} SAFE FIX{1}`n`n{2}`n`n(MODERATE and DISRUPTIVE fixes were NOT selected. Apply now?)" -f $safeSelected.Count, $(if ($safeSelected.Count -eq 1){''}else{'ES'}), (($safeSelected | ForEach-Object { '  - ' + $_.Description }) -join "`n"))
        $r = [System.Windows.MessageBox]::Show($w, $confirmText, 'Confirm auto-apply', 'OKCancel', 'Question')
        if ($r -ne 'OK') { $statusLine.Text = 'Auto-apply cancelled.'; return }

        Add-Event fix ("Auto-applying {0} SAFE fix(es)..." -f $safeSelected.Count)
        $errors = @()
        $okCount = 0
        foreach ($fx in $safeSelected) {
            try {
                Add-Event fix ("> {0}" -f $fx.Description)
                Invoke-Expression $fx.Command
                Add-Event fix ("  OK: {0}" -f $fx.Description)
                $okCount++
            } catch {
                $errors += "$($fx.Description): $($_.Exception.Message)"
                Add-Event warn ("  FAILED: {0} - {1}" -f $fx.Description, $_.Exception.Message)
            }
        }
        if ($errors.Count -gt 0) {
            [System.Windows.MessageBox]::Show($w, ("Auto-apply complete: {0} OK, {1} failed.`n`n{2}" -f $okCount, $errors.Count, ($errors -join "`n")), 'Partial result', 'OK', 'Warning') | Out-Null
        } else {
            [System.Windows.MessageBox]::Show($w, ("Auto-apply complete: all {0} SAFE fix(es) applied. The HUD will re-scan automatically." -f $okCount), 'Auto-apply done', 'OK', 'Information') | Out-Null
        }
        try {
            Start-Sleep -Milliseconds 1000
            Update-Findings
            $script:State.VerifyMode = $true
            $script:State.VerifyEndTime = (Get-Date).AddMinutes(10)
            $script:State.VerifyBaseline = $script:State.FlapCount
            if ($controls.VerifyBadge) { $controls.VerifyBadge.Visibility = 'Visible' }
            if ($controls.VerifyText)  { $controls.VerifyText.Text = 'verifying fix... 600s left' }
            Add-Event fix 'Verify watch started (10 min) after auto-apply.'
        } catch {}
        $w.Close()
    }.GetNewClosure())

    $w.FindName('ApplyBtn').Add_Click({
        $selected = @($checkboxRefs | Where-Object { $_.IsChecked } | ForEach-Object { $_.Tag })
        if ($selected.Count -eq 0) {
            $statusLine.Text = 'Nothing selected. Check at least one item or click Cancel.'
            $statusLine.Foreground = (B '#d29922')
            return
        }
        Add-Event fix ("Applying {0} selected fix(es)..." -f $selected.Count)
        $errors = @()
        $okCount = 0
        foreach ($fx in $selected) {
            try {
                Add-Event fix ("> {0}" -f $fx.Description)
                Invoke-Expression $fx.Command
                Add-Event fix ("  OK: {0}" -f $fx.Description)
                $okCount++
            } catch {
                $errors += "$($fx.Description): $($_.Exception.Message)"
                Add-Event warn ("  FAILED: {0} - {1}" -f $fx.Description, $_.Exception.Message)
            }
        }
        if ($errors.Count -gt 0) {
            [System.Windows.MessageBox]::Show($w, ("{0} fix(es) applied, {1} failed.`n`n{2}" -f $okCount, $errors.Count, ($errors -join "`n")), 'Partial result', 'OK', 'Warning') | Out-Null
        } else {
            [System.Windows.MessageBox]::Show($w, ("Done. {0} fix(es) applied. The HUD will re-scan automatically." -f $okCount), 'Fixes applied', 'OK', 'Information') | Out-Null
        }
        # Kick off a re-scan + verify watch
        try {
            Start-Sleep -Milliseconds 1000
            Update-Findings
            $script:State.VerifyMode = $true
            $script:State.VerifyEndTime = (Get-Date).AddMinutes(10)
            $script:State.VerifyBaseline = $script:State.FlapCount
            if ($controls.VerifyBadge) { $controls.VerifyBadge.Visibility = 'Visible' }
            if ($controls.VerifyText)  { $controls.VerifyText.Text = 'verifying fix... 600s left' }
            Add-Event fix 'Verify watch started (10 min). I will toast you with the result.'
        } catch {}
        $w.Close()
    }.GetNewClosure())

    $w.FindName('CancelBtn').Add_Click({ $w.Close() })
    $w.ShowDialog() | Out-Null
}

# ---------- Tier 26: per-connection drill-down dialog ----------
# Shows everything we can know about a single (process, local, remote) tuple without P/Invoke.
# Inputs: a row from PROCESSES / TRAFFIC / RETRANS context menus. We normalise the row shape
# (different lists use different property names: Pid/PrimaryRemoteIp vs Pid/RemoteAddress).
# Async actions (trace route, latency probe) run on background runspaces so the dialog stays
# interactive. Results are copied back via the dispatcher when the runspace finishes.
function Show-ConnectionDetailsDialog {
    param($Row)
    if (-not $Row) {
        [System.Windows.MessageBox]::Show($window, 'No row data passed to connection-details dialog.', 'Error', 'OK', 'Error') | Out-Null
        return
    }

    # Normalise row -> hashtable. Different list types expose different property names.
    $procPid = $null
    $procName = $null
    $procPath = $null
    $remoteIp = $null
    $remotePort = $null
    try {
        if ($Row.PSObject.Properties['Pid'] -and $Row.Pid) { $procPid = [int]$Row.Pid }
        if ($Row.PSObject.Properties['Name']        -and $Row.Name)        { $procName = [string]$Row.Name }
        if ($Row.PSObject.Properties['ProcessName'] -and $Row.ProcessName) { $procName = [string]$Row.ProcessName }
        if ($Row.PSObject.Properties['Path']          -and $Row.Path)          { $procPath = [string]$Row.Path }
        if ($Row.PSObject.Properties['PrimaryRemoteIp'] -and $Row.PrimaryRemoteIp) { $remoteIp = [string]$Row.PrimaryRemoteIp }
        if ($Row.PSObject.Properties['PrimaryRemote']   -and $Row.PrimaryRemote)   { $remoteIp = [string]$Row.PrimaryRemote }
        if ($Row.PSObject.Properties['RemoteAddress']   -and $Row.RemoteAddress)   { $remoteIp = [string]$Row.RemoteAddress }
        if ($Row.PSObject.Properties['RemotePort']      -and $Row.RemotePort)      { $remotePort = [int]$Row.RemotePort }
    } catch {}

    if (-not $procPid) {
        [System.Windows.MessageBox]::Show($window, 'Row has no PID - cannot open connection details.', 'Error', 'OK', 'Warning') | Out-Null
        return
    }

    # Pull live process metadata
    $procObj = $null
    try { $procObj = Get-Process -Id $procPid -ErrorAction Stop } catch {}
    if ($procObj) {
        if (-not $procName) { $procName = $procObj.ProcessName }
        if (-not $procPath) { try { $procPath = $procObj.Path } catch {} }
    }
    if (-not $procName) { $procName = "(pid $procPid)" }

    # Signer (best-effort, fast path)
    $signerLabel = '(unsigned/unknown)'
    if ($procPath -and (Test-Path $procPath)) {
        try {
            $sig = Get-AuthenticodeSignature -LiteralPath $procPath -ErrorAction SilentlyContinue
            if ($sig) {
                $subj = [string]$sig.SignerCertificate.Subject
                if ($subj) {
                    if ($subj -match 'CN=([^,]+)') { $signerLabel = $matches[1].Trim() }
                    else { $signerLabel = $subj }
                }
                $signerLabel = ("{0}  [{1}]" -f $signerLabel, $sig.Status)
            }
        } catch {}
    }

    # Enumerate all this PID's TCP+UDP connections
    $allConns = @()
    try {
        Get-NetTCPConnection -OwningProcess $procPid -ErrorAction SilentlyContinue | ForEach-Object {
            $age = '--'
            try { if ($_.CreationTime) { $age = ((Get-Date) - $_.CreationTime).ToString('hh\:mm\:ss') } } catch {}
            $allConns += [pscustomobject]@{
                Proto         = 'TCP'
                State         = [string]$_.State
                LocalAddress  = [string]$_.LocalAddress
                LocalPort     = [int]$_.LocalPort
                RemoteAddress = [string]$_.RemoteAddress
                RemotePort    = [int]$_.RemotePort
                CreationTime  = $_.CreationTime
                Age           = $age
                Label         = ("[TCP {0}]  {1}:{2} -> {3}:{4}  age {5}" -f $_.State, $_.LocalAddress, $_.LocalPort, $_.RemoteAddress, $_.RemotePort, $age)
            }
        }
        Get-NetUDPEndpoint -OwningProcess $procPid -ErrorAction SilentlyContinue | ForEach-Object {
            $age = '--'
            try { if ($_.CreationTime) { $age = ((Get-Date) - $_.CreationTime).ToString('hh\:mm\:ss') } } catch {}
            $allConns += [pscustomobject]@{
                Proto         = 'UDP'
                State         = '(listening)'
                LocalAddress  = [string]$_.LocalAddress
                LocalPort     = [int]$_.LocalPort
                RemoteAddress = ''
                RemotePort    = 0
                CreationTime  = $_.CreationTime
                Age           = $age
                Label         = ("[UDP listen]  {0}:{1}  age {2}" -f $_.LocalAddress, $_.LocalPort, $age)
            }
        }
    } catch {}

    # Pick the focus connection: prefer one matching ($remoteIp, $remotePort), else the first Established TCP, else first
    $focusConn = $null
    if ($remoteIp) {
        $focusConn = $allConns | Where-Object { $_.RemoteAddress -eq $remoteIp -and ($remotePort -eq 0 -or $_.RemotePort -eq $remotePort) } | Select-Object -First 1
    }
    if (-not $focusConn) {
        $focusConn = $allConns | Where-Object { $_.State -eq 'Established' } | Select-Object -First 1
    }
    if (-not $focusConn) {
        $focusConn = $allConns | Select-Object -First 1
    }
    if (-not $focusConn -and $remoteIp) {
        # We were called with a remote IP that no longer has a live socket - synthesise a stub
        $focusConn = [pscustomobject]@{
            Proto         = 'TCP'
            State         = '(no longer active)'
            LocalAddress  = ''
            LocalPort     = 0
            RemoteAddress = $remoteIp
            RemotePort    = if ($remotePort) { $remotePort } else { 0 }
            CreationTime  = $null
            Age           = '--'
            Label         = ("(historical)  -> {0}:{1}" -f $remoteIp, $remotePort)
        }
    }

    function script:_PortToProtocol([int]$p) {
        switch ($p) {
            53    { return 'DNS' }
            67    { return 'DHCP' }
            68    { return 'DHCP' }
            80    { return 'HTTP' }
            123   { return 'NTP' }
            143   { return 'IMAP' }
            443   { return 'HTTPS' }
            465   { return 'SMTPS' }
            587   { return 'SMTP-submission' }
            993   { return 'IMAPS' }
            995   { return 'POP3S' }
            22    { return 'SSH' }
            23    { return 'TELNET' }
            25    { return 'SMTP' }
            3389  { return 'RDP' }
            5223  { return 'iCloud / APNS' }
            5228  { return 'GCM (Google Push)' }
            8443  { return 'HTTPS-alt' }
            default { return ('port ' + $p) }
        }
    }

    [xml]$x = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="NetJump - Connection details" Width="900" Height="700" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BrushWindowBg}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Segoe UI">
  <Grid Margin="14">
    <Grid.RowDefinitions>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="*"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
    </Grid.RowDefinitions>

    <!-- Header: process line -->
    <Border Grid.Row="0" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="12,8" Margin="0,0,0,8">
      <StackPanel>
        <TextBlock x:Name="ProcLine" Foreground="{DynamicResource BrushFgPrimary}" FontSize="14" FontWeight="Bold" TextWrapping="Wrap"/>
        <TextBlock x:Name="ProcSubLine" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" TextWrapping="Wrap" Margin="0,3,0,0"/>
        <TextBlock x:Name="ProcSignerLine" Foreground="{DynamicResource BrushFgFaint}" FontSize="11" TextWrapping="Wrap" Margin="0,2,0,0"/>
      </StackPanel>
    </Border>

    <!-- Focus connection card -->
    <Border Grid.Row="1" Background="{DynamicResource BrushDeepBg}" BorderBrush="#58a6ff" BorderThickness="1" CornerRadius="6" Padding="12,8" Margin="0,0,0,8">
      <StackPanel>
        <Grid Margin="0,0,0,4">
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="*"/>
            <ColumnDefinition Width="Auto"/>
          </Grid.ColumnDefinitions>
          <TextBlock Grid.Column="0" Text="FOCUS CONNECTION" Foreground="#58a6ff" FontWeight="Bold" FontSize="11"/>
          <TextBlock Grid.Column="1" x:Name="ConnState" Text="--" Foreground="#3fb950" FontWeight="Bold" FontSize="11"/>
        </Grid>
        <Grid>
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="100"/>
            <ColumnDefinition Width="*"/>
          </Grid.ColumnDefinitions>
          <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
          </Grid.RowDefinitions>
          <TextBlock Grid.Row="0" Grid.Column="0" Text="Protocol"  Foreground="{DynamicResource BrushFgMuted}" FontSize="11"/>
          <TextBlock Grid.Row="0" Grid.Column="1" x:Name="ConnProto" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11"/>
          <TextBlock Grid.Row="1" Grid.Column="0" Text="Local"     Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="1" Grid.Column="1" x:Name="ConnLocal" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="2" Grid.Column="0" Text="Remote"    Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="2" Grid.Column="1" x:Name="ConnRemote" Text="--" Foreground="#79c0ff" FontFamily="Consolas" FontSize="12" FontWeight="Bold" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="3" Grid.Column="0" Text="Geo"       Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="3" Grid.Column="1" x:Name="ConnGeo"  Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" TextWrapping="Wrap" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="4" Grid.Column="0" Text="Reverse DNS" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="4" Grid.Column="1" x:Name="ConnRdns" Text="(click Reverse DNS to resolve)" Foreground="{DynamicResource BrushFgFaint}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="5" Grid.Column="0" Text="Age"       Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="5" Grid.Column="1" x:Name="ConnAge" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
        </Grid>
      </StackPanel>
    </Border>

    <!-- Live metrics card -->
    <Border Grid.Row="2" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="12,8" Margin="0,0,0,8">
      <StackPanel>
        <TextBlock Text="LIVE METRICS  (click action buttons below to populate)" Foreground="#d29922" FontWeight="Bold" FontSize="11" Margin="0,0,0,4"/>
        <Grid>
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="100"/>
            <ColumnDefinition Width="*"/>
          </Grid.ColumnDefinitions>
          <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
          </Grid.RowDefinitions>
          <TextBlock Grid.Row="0" Grid.Column="0" Text="Latency"   Foreground="{DynamicResource BrushFgMuted}" FontSize="11"/>
          <TextBlock Grid.Row="0" Grid.Column="1" x:Name="MetricLatency" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11"/>
          <TextBlock Grid.Row="1" Grid.Column="0" Text="Trace hops" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="1" Grid.Column="1" x:Name="MetricHops" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" TextWrapping="Wrap" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="2" Grid.Column="0" Text="TLS cert"  Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="2" Grid.Column="1" x:Name="MetricTls" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" TextWrapping="Wrap" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="3" Grid.Column="0" Text="Ledger"    Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="3" Grid.Column="1" x:Name="MetricLedger" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" TextWrapping="Wrap" Margin="0,2,0,0"/>
        </Grid>
      </StackPanel>
    </Border>

    <!-- All connections from this PID list -->
    <Border Grid.Row="3" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="0">
      <Grid>
        <Grid.RowDefinitions>
          <RowDefinition Height="Auto"/>
          <RowDefinition Height="*"/>
        </Grid.RowDefinitions>
        <TextBlock Grid.Row="0" x:Name="AllConnsHeader" Text="OTHER CONNECTIONS FROM THIS PROCESS" Foreground="#58a6ff" FontWeight="Bold" FontSize="11" Padding="12,8"/>
        <ScrollViewer Grid.Row="1" VerticalScrollBarVisibility="Auto" Padding="4,0,4,4">
          <ItemsControl x:Name="AllConnsList">
            <ItemsControl.ItemTemplate>
              <DataTemplate>
                <Border BorderThickness="0,0,0,1" BorderBrush="{DynamicResource BrushBorder}" Padding="8,4" Cursor="Hand">
                  <Grid>
                    <Grid.ColumnDefinitions>
                      <ColumnDefinition Width="60"/>
                      <ColumnDefinition Width="120"/>
                      <ColumnDefinition Width="*"/>
                      <ColumnDefinition Width="80"/>
                    </Grid.ColumnDefinitions>
                    <TextBlock Grid.Column="0" Text="{Binding Proto}" Foreground="#79c0ff" FontWeight="Bold" FontSize="10" VerticalAlignment="Center"/>
                    <TextBlock Grid.Column="1" Text="{Binding State}" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" VerticalAlignment="Center"/>
                    <TextBlock Grid.Column="2" Text="{Binding Label}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" VerticalAlignment="Center" TextTrimming="CharacterEllipsis"/>
                    <TextBlock Grid.Column="3" Text="{Binding Age}" Foreground="{DynamicResource BrushFgFaint}" FontFamily="Consolas" FontSize="10" VerticalAlignment="Center"/>
                  </Grid>
                </Border>
              </DataTemplate>
            </ItemsControl.ItemTemplate>
          </ItemsControl>
        </ScrollViewer>
      </Grid>
    </Border>

    <!-- Status line for async actions -->
    <TextBlock Grid.Row="4" x:Name="StatusLine" Text="" Foreground="{DynamicResource BrushFgFaint}" FontSize="11" Margin="0,8,0,4" TextWrapping="Wrap"/>

    <!-- Action toolbar -->
    <WrapPanel Grid.Row="5" Orientation="Horizontal" HorizontalAlignment="Right" Margin="0,4,0,0">
      <Button x:Name="LatencyBtn" Content="Test latency"   Padding="8,4" FontSize="11" Margin="0,0,6,0"/>
      <Button x:Name="TraceBtn"   Content="Trace route"    Padding="8,4" FontSize="11" Margin="0,0,6,0"/>
      <Button x:Name="RdnsBtn"    Content="Reverse DNS"    Padding="8,4" FontSize="11" Margin="0,0,6,0"/>
      <Button x:Name="TlsBtn"     Content="Inspect TLS"    Padding="8,4" FontSize="11" Margin="0,0,6,0"/>
      <Button x:Name="WhoisBtn"   Content="WHOIS"          Padding="8,4" FontSize="11" Margin="0,0,6,0"/>
      <Button x:Name="VtBtn"      Content="VirusTotal"     Padding="8,4" FontSize="11" Margin="0,0,6,0"/>
      <Button x:Name="KillBtn"    Content="Kill process"   Padding="8,4" FontSize="11" Margin="0,0,6,0" Background="#5a1018" Foreground="#ffffff" BorderBrush="#f85149"/>
      <Button x:Name="BlockBtn"   Content="Block remote"   Padding="8,4" FontSize="11" Margin="0,0,6,0" Background="#3d2c0a" Foreground="#ffffff" BorderBrush="#d29922"/>
      <Button x:Name="CopyBtn"    Content="Copy details"   Padding="8,4" FontSize="11" Margin="0,0,6,0"/>
      <Button x:Name="CloseBtn"   Content="Close"          Padding="14,4" FontSize="11" Background="#1f6feb" Foreground="#ffffff" BorderBrush="#2f7fff" FontWeight="Bold"/>
    </WrapPanel>
  </Grid>
</Window>
'@
    $rdr = New-Object System.Xml.XmlNodeReader $x
    $w = [Windows.Markup.XamlReader]::Load($rdr)
    if ($window) { $w.Owner = $window }
    Wire-DialogEscClose $w   # Tier 55: ESC closes the dialog
    Apply-ThemeToChild $w

    # Populate header lines
    $w.FindName('ProcLine').Text = ("{0}    pid {1}" -f $procName, $procPid)
    $w.FindName('ProcSubLine').Text = if ($procPath) { "Path: $procPath" } else { 'Path: (unavailable - process may have exited)' }
    $w.FindName('ProcSignerLine').Text = "Signer: $signerLabel"

    # Populate focus connection
    $localStr = if ($focusConn.LocalPort -gt 0) { ("{0}:{1}" -f $focusConn.LocalAddress, $focusConn.LocalPort) } else { '--' }
    $remoteStr = if ($focusConn.RemoteAddress) { ("{0}:{1}" -f $focusConn.RemoteAddress, $focusConn.RemotePort) } else { '(none)' }
    $protoLabel = if ($focusConn.RemotePort -gt 0) { ("{0}  ({1})" -f $focusConn.Proto, (_PortToProtocol $focusConn.RemotePort)) } else { [string]$focusConn.Proto }
    $w.FindName('ConnState').Text = [string]$focusConn.State
    $w.FindName('ConnProto').Text = $protoLabel
    $w.FindName('ConnLocal').Text = $localStr
    $w.FindName('ConnRemote').Text = $remoteStr
    $w.FindName('ConnAge').Text = [string]$focusConn.Age

    # Geo
    $geo = ''
    if ($focusConn.RemoteAddress) {
        try { $geo = Get-IpLabel $focusConn.RemoteAddress } catch {}
    }
    $w.FindName('ConnGeo').Text = if ($geo) { $geo } else { '(no geo info)' }

    # Ledger lookup - find any matching entries
    $ledgerLabel = '(no ledger entries)'
    if ($script:Ledger -and $procName -and $focusConn.RemoteAddress -and $focusConn.RemotePort) {
        $key = ('{0}|{1}|{2}' -f $procName, $focusConn.RemoteAddress, $focusConn.RemotePort)
        if ($script:Ledger.ContainsKey($key)) {
            $e = $script:Ledger[$key]
            $ledgerLabel = ("first seen {0}, last seen {1}, samples {2}" -f $e.firstSeen, $e.lastSeen, $e.samples)
        } else {
            # Maybe entries with different process name (svchost variants etc) match the same remote
            $matches = @($script:Ledger.Values | Where-Object { $_.ip -eq $focusConn.RemoteAddress -and $_.port -eq $focusConn.RemotePort })
            if ($matches.Count -gt 0) {
                $oldest = ($matches | Sort-Object firstSeen | Select-Object -First 1)
                $ledgerLabel = ("seen {0}x via different proc(s); earliest first-seen {1}" -f $matches.Count, $oldest.firstSeen)
            }
        }
    }
    $w.FindName('MetricLedger').Text = $ledgerLabel

    # Other connections list - exclude focus row
    $allConnsList = $w.FindName('AllConnsList')
    $remainder = @($allConns | Where-Object { -not ($_.LocalPort -eq $focusConn.LocalPort -and $_.RemoteAddress -eq $focusConn.RemoteAddress -and $_.RemotePort -eq $focusConn.RemotePort) })
    $w.FindName('AllConnsHeader').Text = if ($remainder.Count -eq 0) { 'OTHER CONNECTIONS FROM THIS PROCESS  (none active)' } else { ("OTHER CONNECTIONS FROM THIS PROCESS  ({0} more)" -f $remainder.Count) }
    $allConnsList.ItemsSource = $remainder

    # Wire actions
    $statusLine = $w.FindName('StatusLine')
    $metricLat  = $w.FindName('MetricLatency')
    $metricHops = $w.FindName('MetricHops')
    $metricTls  = $w.FindName('MetricTls')
    $rdnsLine   = $w.FindName('ConnRdns')

    # Latency probe (sync, fast - 5 pings)
    $w.FindName('LatencyBtn').Add_Click({
        if (-not $focusConn.RemoteAddress) { $statusLine.Text = 'No remote IP to probe.'; return }
        $statusLine.Text = ("Probing latency to {0}..." -f $focusConn.RemoteAddress)
        $metricLat.Text = '...'
        try {
            $ping = Test-Connection -ComputerName $focusConn.RemoteAddress -Count 5 -ErrorAction SilentlyContinue
            if ($ping) {
                $rtts = $ping | ForEach-Object { [int]$_.ResponseTime } | Where-Object { $_ -gt 0 }
                if ($rtts.Count -gt 0) {
                    $min = ($rtts | Measure-Object -Minimum).Minimum
                    $max = ($rtts | Measure-Object -Maximum).Maximum
                    $avg = [int](($rtts | Measure-Object -Average).Average)
                    $loss = ((5 - $rtts.Count) / 5.0) * 100
                    $metricLat.Text = ("min {0}ms / avg {1}ms / max {2}ms ({3} of 5 replied{4})" -f $min, $avg, $max, $rtts.Count, $(if ($loss -gt 0) { ", $loss% loss" } else { '' }))
                } else {
                    $metricLat.Text = '(all 5 timed out - host unreachable or ICMP filtered)'
                }
            } else {
                $metricLat.Text = '(probe failed)'
            }
            $statusLine.Text = ('Latency probe complete at ' + (Get-Date -Format 'HH:mm:ss'))
        } catch {
            $metricLat.Text = ("error: " + $_.Exception.Message)
            $statusLine.Text = 'Latency probe failed.'
        }
    }.GetNewClosure())

    # Trace route - open the rich Path Inspection modal (per-hop sparklines, multi-pass sampling)
    $w.FindName('TraceBtn').Add_Click({
        if (-not $focusConn.RemoteAddress) { $statusLine.Text = 'No remote IP to trace.'; return }
        $metricHops.Text = ('(open path inspector...)')
        $statusLine.Text = ('Opening path inspector for {0}...' -f $focusConn.RemoteAddress)
        try {
            Show-PathInspectionDialog -Target $focusConn.RemoteAddress
            $statusLine.Text = ('Path inspector closed at ' + (Get-Date -Format 'HH:mm:ss'))
        } catch {
            $metricHops.Text = ("error: " + $_.Exception.Message)
            $statusLine.Text = 'Path inspector failed: ' + $_.Exception.Message
        }
    }.GetNewClosure())

    # Reverse DNS (fast)
    $w.FindName('RdnsBtn').Add_Click({
        if (-not $focusConn.RemoteAddress) { $statusLine.Text = 'No remote IP to resolve.'; return }
        $rdnsLine.Text = '...'
        try {
            $entry = [System.Net.Dns]::GetHostEntry($focusConn.RemoteAddress)
            if ($entry -and $entry.HostName) {
                $rdnsLine.Text = $entry.HostName
                $rdnsLine.Foreground = $window.Resources['BrushFgPrimary']
                $statusLine.Text = ('Reverse DNS: ' + $entry.HostName)
            } else {
                $rdnsLine.Text = '(no PTR record)'
            }
        } catch {
            $rdnsLine.Text = '(resolution failed)'
            $statusLine.Text = 'Reverse DNS failed: ' + $_.Exception.Message
        }
    }.GetNewClosure())

    # Inspect TLS - opens the rich TLS Probe modal (per-stage timing + cert details + chain validation).
    $w.FindName('TlsBtn').Add_Click({
        if (-not $focusConn.RemoteAddress -or -not $focusConn.RemotePort) {
            $metricTls.Text = '(need remote IP+port to probe TLS)'
            return
        }
        $metricTls.Text = '(open TLS probe...)'
        $statusLine.Text = ("Opening TLS probe for {0}:{1}..." -f $focusConn.RemoteAddress, $focusConn.RemotePort)
        try {
            Show-TlsProbeDialog -HostName $focusConn.RemoteAddress -Port $focusConn.RemotePort
            $statusLine.Text = ('TLS probe closed at ' + (Get-Date -Format 'HH:mm:ss'))
        } catch {
            $metricTls.Text = ("error: " + $_.Exception.Message)
            $statusLine.Text = 'TLS probe failed: ' + $_.Exception.Message
        }
    }.GetNewClosure())

    # WHOIS / VirusTotal / Kill / Block / Copy / Close
    $w.FindName('WhoisBtn').Add_Click({
        if (-not $focusConn.RemoteAddress) { $statusLine.Text = 'No remote IP for WHOIS.'; return }
        try {
            Start-Process ("https://who.is/whois-ip/ip-address/" + $focusConn.RemoteAddress) -ErrorAction Stop | Out-Null
            $statusLine.Text = 'WHOIS opened in browser.'
        } catch { $statusLine.Text = 'WHOIS open failed: ' + $_.Exception.Message }
    }.GetNewClosure())
    $w.FindName('VtBtn').Add_Click({
        if (-not $focusConn.RemoteAddress) { $statusLine.Text = 'No remote IP for VirusTotal.'; return }
        try {
            Start-Process ("https://www.virustotal.com/gui/ip-address/" + $focusConn.RemoteAddress) -ErrorAction Stop | Out-Null
            $statusLine.Text = 'VirusTotal opened in browser.'
        } catch { $statusLine.Text = 'VirusTotal open failed: ' + $_.Exception.Message }
    }.GetNewClosure())
    $w.FindName('KillBtn').Add_Click({
        Invoke-KillProcessAction -Pid $procPid -Name $procName
        $statusLine.Text = ('Kill action invoked for pid {0}' -f $procPid)
    }.GetNewClosure())
    $w.FindName('BlockBtn').Add_Click({
        if (-not $focusConn.RemoteAddress) { $statusLine.Text = 'No remote IP to block.'; return }
        Invoke-BlockIpAction -Ip $focusConn.RemoteAddress -Reason ("Connection details blocked from {0} (pid {1})" -f $procName, $procPid)
    }.GetNewClosure())
    $w.FindName('CopyBtn').Add_Click({
        $txt = @"
Process: $procName  (pid $procPid)
Path:    $procPath
Signer:  $signerLabel
Connection: $($focusConn.Proto) $($focusConn.State)
  Local:  $localStr
  Remote: $remoteStr
  Geo:    $geo
  Age:    $($focusConn.Age)
  Ledger: $ledgerLabel
Latency:    $($metricLat.Text)
TraceRoute: $($metricHops.Text)
TLS:        $($metricTls.Text)
Reverse DNS: $($rdnsLine.Text)
"@
        Invoke-CopyToClipboard $txt
        $statusLine.Text = ('Details copied to clipboard at ' + (Get-Date -Format 'HH:mm:ss'))
    }.GetNewClosure())
    $w.FindName('CloseBtn').Add_Click({ $w.Close() })

    $w.ShowDialog() | Out-Null
}

# ---------- Tier 29: Path Inspection modal ----------
# Per-hop traceroute with multi-pass sampling. Uses System.Net.NetworkInformation.Ping with
# manually-stepped TTL (1..30) - that's how traceroute works at the wire level. Each pass adds
# a sample to every hop's history, building per-hop sparklines so the user can see WHICH hop
# is actually the latency culprit (not just the cumulative end-to-end RTT).
# UI stays responsive during a trace by pumping the dispatcher between hops.
function Show-PathInspectionDialog {
    param([string]$Target)
    if (-not $Target) {
        [System.Windows.MessageBox]::Show($window, 'No target specified for path inspection.', 'Error', 'OK', 'Warning') | Out-Null
        return
    }
    # Resolve host -> IP if needed (for the actual trace) but keep the original label for display
    $targetLabel = $Target
    $targetIp    = $Target
    try {
        $tmp = [System.Net.IPAddress]::None
        if (-not [System.Net.IPAddress]::TryParse($Target, [ref]$tmp)) {
            $resolved = [System.Net.Dns]::GetHostAddresses($Target) | Where-Object { $_.AddressFamily -eq 'InterNetwork' } | Select-Object -First 1
            if ($resolved) { $targetIp = $resolved.IPAddressToString }
        }
    } catch {
        [System.Windows.MessageBox]::Show($window, ("Could not resolve '{0}' to an IP address." -f $Target), 'Resolve failed', 'OK', 'Warning') | Out-Null
        return
    }

    # Per-hop state - keyed by hop number (1..30). Survives multiple trace passes within the same dialog instance.
    $hops = @{}
    function script:_AddHopSample {
        param([int]$Num, [string]$Address, [bool]$IsLoss, [double]$Rtt = 0)
        if (-not $hops.ContainsKey($Num)) {
            $hops[$Num] = @{
                Num          = $Num
                Address      = ''
                Hostname     = ''
                Samples      = New-Object System.Collections.Generic.List[double]
                LossCount    = 0
                AttemptCount = 0
            }
        }
        $h = $hops[$Num]
        $h.AttemptCount++
        if (-not $IsLoss -and $Address) {
            $h.Address = $Address
            $h.Samples.Add([double]$Rtt)
        } elseif ($IsLoss) {
            $h.LossCount++
        }
    }

    # _FormatMiniSpark is now extracted to top-level Format-MiniSpark so the TLS probe dialog
    # can share it without duplicating code.

    [xml]$x = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="NetJump - Path inspection" Width="880" Height="680" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BrushWindowBg}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Segoe UI">
  <Grid Margin="14">
    <Grid.RowDefinitions>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="*"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
    </Grid.RowDefinitions>

    <TextBlock Grid.Row="0" Text="PATH INSPECTION" Foreground="#58a6ff" FontSize="11" FontWeight="Bold"/>
    <TextBlock Grid.Row="1" x:Name="TargetLine" Foreground="{DynamicResource BrushFgPrimary}" FontSize="14" FontWeight="SemiBold" Margin="0,4,0,0"/>
    <TextBlock Grid.Row="2" x:Name="StatusLine" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" TextWrapping="Wrap" Margin="0,4,0,4"/>

    <!-- Column header strip -->
    <Border Grid.Row="3" Background="{DynamicResource BrushCardBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1,1,1,0" CornerRadius="6,6,0,0">
      <Grid>
        <Grid.ColumnDefinitions>
          <ColumnDefinition Width="40"/>
          <ColumnDefinition Width="130"/>
          <ColumnDefinition Width="*"/>
          <ColumnDefinition Width="60"/>
          <ColumnDefinition Width="60"/>
          <ColumnDefinition Width="60"/>
          <ColumnDefinition Width="120"/>
          <ColumnDefinition Width="60"/>
        </Grid.ColumnDefinitions>
        <TextBlock Grid.Column="0" Text="HOP"      FontSize="9" FontWeight="Bold" Foreground="{DynamicResource BrushFgMuted}" Padding="6,4"/>
        <TextBlock Grid.Column="1" Text="ADDRESS"  FontSize="9" FontWeight="Bold" Foreground="{DynamicResource BrushFgMuted}" Padding="0,4"/>
        <TextBlock Grid.Column="2" Text="HOSTNAME / GEO" FontSize="9" FontWeight="Bold" Foreground="{DynamicResource BrushFgMuted}" Padding="0,4"/>
        <TextBlock Grid.Column="3" Text="LAST"     FontSize="9" FontWeight="Bold" Foreground="{DynamicResource BrushFgMuted}" Padding="0,4"/>
        <TextBlock Grid.Column="4" Text="AVG"      FontSize="9" FontWeight="Bold" Foreground="{DynamicResource BrushFgMuted}" Padding="0,4"/>
        <TextBlock Grid.Column="5" Text="JITTER"   FontSize="9" FontWeight="Bold" Foreground="{DynamicResource BrushFgMuted}" Padding="0,4"/>
        <TextBlock Grid.Column="6" Text="HISTORY"  FontSize="9" FontWeight="Bold" Foreground="{DynamicResource BrushFgMuted}" Padding="0,4"/>
        <TextBlock Grid.Column="7" Text="LOSS"     FontSize="9" FontWeight="Bold" Foreground="{DynamicResource BrushFgMuted}" Padding="0,4,8,4"/>
      </Grid>
    </Border>

    <!-- Hop list -->
    <Border Grid.Row="4" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1,0,1,1" CornerRadius="0,0,6,6">
      <ScrollViewer VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Disabled" Padding="0,0,4,0">
        <ItemsControl x:Name="HopList">
          <ItemsControl.ItemTemplate>
            <DataTemplate>
              <Border BorderThickness="0,0,0,1" BorderBrush="{DynamicResource BrushBorder}" Padding="0,4">
                <Grid>
                  <Grid.ColumnDefinitions>
                    <ColumnDefinition Width="40"/>
                    <ColumnDefinition Width="130"/>
                    <ColumnDefinition Width="*"/>
                    <ColumnDefinition Width="60"/>
                    <ColumnDefinition Width="60"/>
                    <ColumnDefinition Width="60"/>
                    <ColumnDefinition Width="120"/>
                    <ColumnDefinition Width="60"/>
                  </Grid.ColumnDefinitions>
                  <Border Grid.Column="0" Background="{Binding StatusBrush}" CornerRadius="3" Padding="2,1" Margin="6,0,0,0" HorizontalAlignment="Left" VerticalAlignment="Center" MinWidth="24">
                    <TextBlock Text="{Binding Num}" Foreground="#ffffff" FontSize="10" FontWeight="Bold" HorizontalAlignment="Center"/>
                  </Border>
                  <TextBlock Grid.Column="1" Text="{Binding Address}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" VerticalAlignment="Center" TextTrimming="CharacterEllipsis"/>
                  <TextBlock Grid.Column="2" Text="{Binding HostLabel}" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" VerticalAlignment="Center" TextWrapping="NoWrap" TextTrimming="CharacterEllipsis"/>
                  <TextBlock Grid.Column="3" Text="{Binding LastLabel}" Foreground="{Binding RttBrush}" FontFamily="Consolas" FontSize="11" VerticalAlignment="Center"/>
                  <TextBlock Grid.Column="4" Text="{Binding AvgLabel}"  Foreground="{Binding RttBrush}" FontFamily="Consolas" FontSize="11" VerticalAlignment="Center"/>
                  <TextBlock Grid.Column="5" Text="{Binding JitterLabel}" Foreground="{DynamicResource BrushFgMuted}" FontFamily="Consolas" FontSize="11" VerticalAlignment="Center"/>
                  <TextBlock Grid.Column="6" Text="{Binding Spark}" Foreground="{Binding RttBrush}" FontFamily="Consolas" FontSize="13" VerticalAlignment="Center" ToolTip="Last 12 RTT samples"/>
                  <TextBlock Grid.Column="7" Text="{Binding LossLabel}" Foreground="{Binding LossBrush}" FontFamily="Consolas" FontSize="11" VerticalAlignment="Center" Padding="0,0,8,0"/>
                </Grid>
              </Border>
            </DataTemplate>
          </ItemsControl.ItemTemplate>
        </ItemsControl>
      </ScrollViewer>
    </Border>

    <TextBlock Grid.Row="5" x:Name="HintLine" Foreground="{DynamicResource BrushFgFaint}" FontSize="10" Margin="0,8,0,4" TextWrapping="Wrap"
               Text="Each row shows one network hop on the path. Color: green=fast (avg&lt;30ms), amber=variable, red=slow/loss, gray=timeout. The hop where RTT jumps significantly is usually where latency is being added. Click 'Trace again' to add another sample to every hop's history."/>

    <!-- Action toolbar -->
    <WrapPanel Grid.Row="6" Orientation="Horizontal" HorizontalAlignment="Right" Margin="0,4,0,0">
      <Button x:Name="TraceBtn"      Content="Trace again"   Padding="10,5" FontSize="11" Margin="0,0,6,0" Background="#1f6feb" Foreground="#ffffff" BorderBrush="#2f7fff" FontWeight="Bold"/>
      <Button x:Name="ContinuousBtn" Content="Continuous (5s)" Padding="10,5" FontSize="11" Margin="0,0,6,0"/>
      <Button x:Name="StopBtn"       Content="Stop"          Padding="10,5" FontSize="11" Margin="0,0,6,0" IsEnabled="False"/>
      <Button x:Name="CopyBtn"       Content="Copy report"   Padding="10,5" FontSize="11" Margin="0,0,6,0"/>
      <Button x:Name="CloseBtn"      Content="Close"         Padding="14,5" FontSize="11"/>
    </WrapPanel>
  </Grid>
</Window>
'@
    $rdr = New-Object System.Xml.XmlNodeReader $x
    $w = [Windows.Markup.XamlReader]::Load($rdr)
    if ($window) { $w.Owner = $window }
    Wire-DialogEscClose $w   # Tier 55: ESC closes the dialog
    Apply-ThemeToChild $w

    $w.FindName('TargetLine').Text = if ($targetLabel -ne $targetIp) { ("Target: {0}  ({1})" -f $targetLabel, $targetIp) } else { ("Target: {0}" -f $targetIp) }
    $statusLine = $w.FindName('StatusLine')
    $hopList    = $w.FindName('HopList')
    $traceBtn   = $w.FindName('TraceBtn')
    $contBtn    = $w.FindName('ContinuousBtn')
    $stopBtn    = $w.FindName('StopBtn')

    # Continuous-mode timer (created up-front; started/stopped by buttons)
    $contTimer = New-Object System.Windows.Threading.DispatcherTimer
    $contTimer.Interval = [TimeSpan]::FromSeconds(5)

    function script:_RebuildHopUI {
        $rows = New-Object System.Collections.Generic.List[object]
        foreach ($n in ($hops.Keys | Sort-Object)) {
            $h = $hops[$n]
            $samples = @($h.Samples)
            $hasData = $samples.Count -gt 0
            # Stats
            $last = if ($hasData) { $samples[-1] } else { 0 }
            $avg  = if ($hasData) { ($samples | Measure-Object -Average).Average } else { 0 }
            $min  = if ($hasData) { ($samples | Measure-Object -Minimum).Minimum } else { 0 }
            $max  = if ($hasData) { ($samples | Measure-Object -Maximum).Maximum } else { 0 }
            $jitter = if ($hasData) { $max - $min } else { 0 }
            $loss = if ($h.AttemptCount -gt 0) { ($h.LossCount / $h.AttemptCount) * 100 } else { 0 }

            # RTT color band
            $rttHex = if (-not $hasData) { '#6a7380' } elseif ($avg -lt 30) { '#3fb950' } elseif ($avg -lt 100) { '#d29922' } else { '#f85149' }
            # Loss color
            $lossHex = if ($loss -ge 30) { '#f85149' } elseif ($loss -ge 5) { '#d29922' } else { '#3fb950' }
            # Status badge color (overall hop health)
            $statusHex = if ($loss -ge 50) { '#5a1018' } elseif ($loss -ge 20) { '#3d2c0a' } elseif (-not $hasData) { '#2a3142' } else { '#1f3a26' }

            # Hostname / geo
            $hostLabel = ''
            if ($h.Hostname) { $hostLabel = $h.Hostname }
            if (-not $hostLabel -and $h.Address) {
                # Try geo label first (existing helper)
                try { $geo = Get-IpLabel $h.Address; if ($geo) { $hostLabel = "[$geo]" } } catch {}
            }
            if (-not $hostLabel) { $hostLabel = '' }

            # Format display strings
            $addr = if ($h.Address) { $h.Address } else { '*  (no reply)' }
            $lastLabel = if ($hasData) { ('{0:N0}ms' -f $last) } else { '--' }
            $avgLabel  = if ($hasData) { ('{0:N0}ms' -f $avg) } else { '--' }
            $jitterLabel = if ($hasData -and $samples.Count -gt 1) { ('{0:N0}ms' -f $jitter) } else { '--' }
            $lossLabel = if ($h.AttemptCount -gt 0) { ('{0:N0}%' -f $loss) } else { '--' }
            $sparkText = Format-MiniSpark -Samples $samples -Width 12

            $rows.Add([pscustomobject]@{
                Num         = $n
                Address     = $addr
                HostLabel   = $hostLabel
                LastLabel   = $lastLabel
                AvgLabel    = $avgLabel
                JitterLabel = $jitterLabel
                LossLabel   = $lossLabel
                Spark       = $sparkText
                RttBrush    = (B $rttHex)
                LossBrush   = (B $lossHex)
                StatusBrush = (B $statusHex)
            })
        }
        $hopList.ItemsSource = $rows
    }

    # Pump dispatcher one cycle so UI redraws (DoEvents-equivalent for WPF).
    function script:_PumpDispatcher {
        $frame = New-Object System.Windows.Threading.DispatcherFrame
        [System.Windows.Threading.Dispatcher]::CurrentDispatcher.BeginInvoke([System.Windows.Threading.DispatcherPriority]::ContextIdle, [Action]{ $frame.Continue = $false }) | Out-Null
        [System.Windows.Threading.Dispatcher]::PushFrame($frame)
    }

    function script:_RunTracePass {
        $statusLine.Text = ("Tracing path to {0}... (max 30 hops, ~1s per hop)" -f $targetIp)
        $traceBtn.IsEnabled = $false
        $w.Cursor = [System.Windows.Input.Cursors]::Wait
        try {
            $maxHops = 30
            $buffer = New-Object byte[] 32
            for ($ttl = 1; $ttl -le $maxHops; $ttl++) {
                $ping = New-Object System.Net.NetworkInformation.Ping
                $opts = New-Object System.Net.NetworkInformation.PingOptions($ttl, $true)
                try {
                    $reply = $ping.Send($targetIp, 1000, $buffer, $opts)
                    if ($reply.Status -eq [System.Net.NetworkInformation.IPStatus]::TtlExpired -or
                        $reply.Status -eq [System.Net.NetworkInformation.IPStatus]::Success) {
                        _AddHopSample -Num $ttl -Address ([string]$reply.Address) -IsLoss:$false -Rtt ([double]$reply.RoundtripTime)
                        if ($reply.Status -eq [System.Net.NetworkInformation.IPStatus]::Success) {
                            _RebuildHopUI; _PumpDispatcher
                            break  # reached the target
                        }
                    } else {
                        _AddHopSample -Num $ttl -Address '' -IsLoss:$true
                    }
                } catch {
                    _AddHopSample -Num $ttl -Address '' -IsLoss:$true
                } finally {
                    try { $ping.Dispose() } catch {}
                }
                _RebuildHopUI
                _PumpDispatcher
            }
            $statusLine.Text = ("Trace complete at {0}.  {1} hop(s).  Click 'Trace again' to accumulate more samples." -f (Get-Date -Format 'HH:mm:ss'), @($hops.Keys).Count)
        } catch {
            $statusLine.Text = ("Trace failed: {0}" -f $_.Exception.Message)
        } finally {
            $w.Cursor = [System.Windows.Input.Cursors]::Arrow
            $traceBtn.IsEnabled = $true
        }
    }

    # Wire actions
    $traceBtn.Add_Click({ _RunTracePass }.GetNewClosure())
    $contBtn.Add_Click({
        $contTimer.Start()
        $statusLine.Text = 'Continuous mode ON - re-tracing every 5 seconds. Click STOP to halt.'
        $contBtn.IsEnabled = $false
        $stopBtn.IsEnabled = $true
        # Run once immediately so user sees fresh data in 5s, not after first 5s gap
        _RunTracePass
    }.GetNewClosure())
    $stopBtn.Add_Click({
        $contTimer.Stop()
        $statusLine.Text = ('Continuous mode OFF (stopped at ' + (Get-Date -Format 'HH:mm:ss') + ').')
        $contBtn.IsEnabled = $true
        $stopBtn.IsEnabled = $false
    }.GetNewClosure())
    $contTimer.Add_Tick({ _RunTracePass }.GetNewClosure())

    $w.FindName('CopyBtn').Add_Click({
        $sb = New-Object System.Text.StringBuilder
        [void]$sb.AppendLine("PATH INSPECTION: $targetLabel")
        [void]$sb.AppendLine("Generated: $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')")
        [void]$sb.AppendLine('-' * 80)
        foreach ($n in ($hops.Keys | Sort-Object)) {
            $h = $hops[$n]
            $samples = @($h.Samples)
            $avg = if ($samples.Count -gt 0) { ($samples | Measure-Object -Average).Average } else { 0 }
            $loss = if ($h.AttemptCount -gt 0) { ($h.LossCount / $h.AttemptCount) * 100 } else { 0 }
            $addrStr = if ($h.Address) { $h.Address } else { '*' }
            $line = ("{0,3}  {1,-15}  avg {2,5:N0}ms  loss {3,4:N0}%  attempts {4,3}  samples {5,3}" -f `
                    $n, $addrStr, $avg, $loss, $h.AttemptCount, $samples.Count)
            [void]$sb.AppendLine($line)
        }
        Invoke-CopyToClipboard $sb.ToString()
        $statusLine.Text = ('Path report copied to clipboard at ' + (Get-Date -Format 'HH:mm:ss'))
    }.GetNewClosure())

    $w.FindName('CloseBtn').Add_Click({
        try { $contTimer.Stop() } catch {}
        $w.Close()
    }.GetNewClosure())

    # Auto-run the first trace as soon as the dialog opens
    $w.Add_Loaded({ _RunTracePass }.GetNewClosure())

    $w.ShowDialog() | Out-Null
}

# ---------- Tier 30: TLS Probe modal ----------
# Per-host TLS handshake probe with stage timing breakdown:
#   1. DNS lookup       (only if hostname; skipped for IP literals)
#   2. TCP connect      (3-way handshake)
#   3. TLS handshake    (full ClientHello -> Finished, exposed by .NET as a single AuthenticateAsClient call)
#   4. Total            (sum)
# Multi-pass: each "Probe again" appends a sample to every stage's history, building per-stage
# sparklines so the user can see WHICH stage is slow / variable on this particular host.
# Also surfaces negotiated protocol/cipher and the server cert chain - useful for diagnosing
# 'this site is slow' (TLS issue) vs 'the network is slow' (DNS or TCP issue).
function Show-TlsProbeDialog {
    param([string]$HostName, [int]$Port = 443)

    if (-not $HostName) {
        # Prompt user via a simple input dialog
        $input = [Microsoft.VisualBasic.Interaction]::InputBox('Enter host:port for TLS probe (e.g. github.com or example.com:443):', 'TLS probe', 'cloudflare.com:443') 2>$null
        if (-not $input) { return }
        $parts = $input -split ':'
        $HostName = $parts[0].Trim()
        if ($parts.Count -gt 1 -and $parts[1] -match '^\d+$') { $Port = [int]$parts[1] }
    }
    if (-not $HostName) { return }

    # Per-stage sample history (drives the sparklines)
    $stages = @{
        Dns   = New-Object System.Collections.Generic.List[double]
        Tcp   = New-Object System.Collections.Generic.List[double]
        Tls   = New-Object System.Collections.Generic.List[double]
        Total = New-Object System.Collections.Generic.List[double]
    }
    # Most-recent probe artifacts (cert + negotiated info)
    $probeInfo = @{
        Cert            = $null
        Protocol        = ''
        CipherAlgo      = ''
        CipherStrength  = 0
        KeyExchange     = ''
        HashAlgo        = ''
        ResolvedIp      = ''
        ChainStatus     = ''
        ChainOk         = $false
        Error           = ''
    }

    [xml]$x = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="NetJump - TLS probe" Width="900" Height="720" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BrushWindowBg}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Segoe UI">
  <Grid Margin="14">
    <Grid.RowDefinitions>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="*"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
    </Grid.RowDefinitions>

    <TextBlock Grid.Row="0" Text="TLS PROBE" Foreground="#58a6ff" FontSize="11" FontWeight="Bold"/>
    <TextBlock Grid.Row="1" x:Name="TargetLine" Foreground="{DynamicResource BrushFgPrimary}" FontSize="14" FontWeight="SemiBold" Margin="0,4,0,0"/>
    <TextBlock Grid.Row="2" x:Name="StatusLine" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" TextWrapping="Wrap" Margin="0,4,0,8"/>

    <!-- STAGE TIMINGS card -->
    <Border Grid.Row="3" Background="{DynamicResource BrushDeepBg}" BorderBrush="#58a6ff" BorderThickness="1" CornerRadius="6" Padding="12,8" Margin="0,0,0,8">
      <StackPanel>
        <TextBlock Text="STAGE TIMINGS  (last / avg / min / max in ms - sparkline shows last 12 probes)" Foreground="#58a6ff" FontWeight="Bold" FontSize="11" Margin="0,0,0,6"/>
        <Grid>
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="120"/>
            <ColumnDefinition Width="60"/>
            <ColumnDefinition Width="60"/>
            <ColumnDefinition Width="60"/>
            <ColumnDefinition Width="60"/>
            <ColumnDefinition Width="*"/>
          </Grid.ColumnDefinitions>
          <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
          </Grid.RowDefinitions>
          <TextBlock Grid.Row="0" Grid.Column="0" Text="Stage"  Foreground="{DynamicResource BrushFgFaint}" FontSize="9" FontWeight="Bold"/>
          <TextBlock Grid.Row="0" Grid.Column="1" Text="Last"   Foreground="{DynamicResource BrushFgFaint}" FontSize="9" FontWeight="Bold"/>
          <TextBlock Grid.Row="0" Grid.Column="2" Text="Avg"    Foreground="{DynamicResource BrushFgFaint}" FontSize="9" FontWeight="Bold"/>
          <TextBlock Grid.Row="0" Grid.Column="3" Text="Min"    Foreground="{DynamicResource BrushFgFaint}" FontSize="9" FontWeight="Bold"/>
          <TextBlock Grid.Row="0" Grid.Column="4" Text="Max"    Foreground="{DynamicResource BrushFgFaint}" FontSize="9" FontWeight="Bold"/>
          <TextBlock Grid.Row="0" Grid.Column="5" Text="History" Foreground="{DynamicResource BrushFgFaint}" FontSize="9" FontWeight="Bold"/>

          <TextBlock Grid.Row="1" Grid.Column="0" Text="DNS lookup"      Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="1" Grid.Column="1" x:Name="DnsLast" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="1" Grid.Column="2" x:Name="DnsAvg"  Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="1" Grid.Column="3" x:Name="DnsMin"  Foreground="{DynamicResource BrushFgFaint}"   FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="1" Grid.Column="4" x:Name="DnsMax"  Foreground="{DynamicResource BrushFgFaint}"   FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="1" Grid.Column="5" x:Name="DnsSpark" Foreground="#79c0ff" FontFamily="Consolas" FontSize="13" Margin="6,2,0,0"/>

          <TextBlock Grid.Row="2" Grid.Column="0" Text="TCP connect"    Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="2" Grid.Column="1" x:Name="TcpLast" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="2" Grid.Column="2" x:Name="TcpAvg"  Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="2" Grid.Column="3" x:Name="TcpMin"  Foreground="{DynamicResource BrushFgFaint}"   FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="2" Grid.Column="4" x:Name="TcpMax"  Foreground="{DynamicResource BrushFgFaint}"   FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="2" Grid.Column="5" x:Name="TcpSpark" Foreground="#3fb950" FontFamily="Consolas" FontSize="13" Margin="6,2,0,0"/>

          <TextBlock Grid.Row="3" Grid.Column="0" Text="TLS handshake"  Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="3" Grid.Column="1" x:Name="TlsLast" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="3" Grid.Column="2" x:Name="TlsAvg"  Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="3" Grid.Column="3" x:Name="TlsMin"  Foreground="{DynamicResource BrushFgFaint}"   FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="3" Grid.Column="4" x:Name="TlsMax"  Foreground="{DynamicResource BrushFgFaint}"   FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="3" Grid.Column="5" x:Name="TlsSpark" Foreground="#bf6dff" FontFamily="Consolas" FontSize="13" Margin="6,2,0,0"/>

          <TextBlock Grid.Row="4" Grid.Column="0" Text="TOTAL"          Foreground="#d29922" FontSize="11" FontWeight="Bold" Margin="0,4,0,0"/>
          <TextBlock Grid.Row="4" Grid.Column="1" x:Name="TotLast" Foreground="#d29922" FontFamily="Consolas" FontSize="11" FontWeight="Bold" Margin="0,4,0,0"/>
          <TextBlock Grid.Row="4" Grid.Column="2" x:Name="TotAvg"  Foreground="#d29922" FontFamily="Consolas" FontSize="11" FontWeight="Bold" Margin="0,4,0,0"/>
          <TextBlock Grid.Row="4" Grid.Column="3" x:Name="TotMin"  Foreground="{DynamicResource BrushFgFaint}" FontFamily="Consolas" FontSize="11" Margin="0,4,0,0"/>
          <TextBlock Grid.Row="4" Grid.Column="4" x:Name="TotMax"  Foreground="{DynamicResource BrushFgFaint}" FontFamily="Consolas" FontSize="11" Margin="0,4,0,0"/>
          <TextBlock Grid.Row="4" Grid.Column="5" x:Name="TotSpark" Foreground="#d29922" FontFamily="Consolas" FontSize="13" Margin="6,4,0,0"/>
        </Grid>
      </StackPanel>
    </Border>

    <!-- NEGOTIATED card -->
    <Border Grid.Row="4" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="12,8" Margin="0,0,0,8">
      <StackPanel>
        <TextBlock Text="NEGOTIATED" Foreground="#58a6ff" FontWeight="Bold" FontSize="11" Margin="0,0,0,4"/>
        <Grid>
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="120"/>
            <ColumnDefinition Width="*"/>
          </Grid.ColumnDefinitions>
          <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="Auto"/>
          </Grid.RowDefinitions>
          <TextBlock Grid.Row="0" Grid.Column="0" Text="Resolved IP"  Foreground="{DynamicResource BrushFgMuted}" FontSize="11"/>
          <TextBlock Grid.Row="0" Grid.Column="1" x:Name="NegIp"      Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11"/>
          <TextBlock Grid.Row="1" Grid.Column="0" Text="Protocol"     Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="1" Grid.Column="1" x:Name="NegProto"   Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="2" Grid.Column="0" Text="Cipher"       Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="2" Grid.Column="1" x:Name="NegCipher"  Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="3" Grid.Column="0" Text="Key exchange" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="3" Grid.Column="1" x:Name="NegKex"     Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="4" Grid.Column="0" Text="Hash"         Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
          <TextBlock Grid.Row="4" Grid.Column="1" x:Name="NegHash"    Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
        </Grid>
      </StackPanel>
    </Border>

    <!-- CERTIFICATE card -->
    <Border Grid.Row="5" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="12,8" Margin="0,0,0,8">
      <ScrollViewer VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Disabled">
        <StackPanel>
          <Grid Margin="0,0,0,4">
            <Grid.ColumnDefinitions>
              <ColumnDefinition Width="*"/>
              <ColumnDefinition Width="Auto"/>
            </Grid.ColumnDefinitions>
            <TextBlock Grid.Column="0" Text="CERTIFICATE" Foreground="#58a6ff" FontWeight="Bold" FontSize="11"/>
            <TextBlock Grid.Column="1" x:Name="CertChainStatus" Text="" FontSize="10" FontWeight="Bold"/>
          </Grid>
          <Grid>
            <Grid.ColumnDefinitions>
              <ColumnDefinition Width="120"/>
              <ColumnDefinition Width="*"/>
            </Grid.ColumnDefinitions>
            <Grid.RowDefinitions>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
            </Grid.RowDefinitions>
            <TextBlock Grid.Row="0" Grid.Column="0" Text="Subject"     Foreground="{DynamicResource BrushFgMuted}" FontSize="11"/>
            <TextBlock Grid.Row="0" Grid.Column="1" x:Name="CertSubj"  Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" TextWrapping="Wrap"/>
            <TextBlock Grid.Row="1" Grid.Column="0" Text="Issuer"      Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="1" Grid.Column="1" x:Name="CertIssuer" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" TextWrapping="Wrap" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="2" Grid.Column="0" Text="Valid from"  Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="2" Grid.Column="1" x:Name="CertFrom"  Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="3" Grid.Column="0" Text="Valid to"    Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="3" Grid.Column="1" x:Name="CertTo"    Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="4" Grid.Column="0" Text="Key"         Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="4" Grid.Column="1" x:Name="CertKey"   Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="5" Grid.Column="0" Text="Serial"      Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="5" Grid.Column="1" x:Name="CertSerial" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="10" TextWrapping="Wrap" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="6" Grid.Column="0" Text="Thumbprint"  Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="6" Grid.Column="1" x:Name="CertThumb" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="10" TextWrapping="Wrap" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="7" Grid.Column="0" Text="SANs"        Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="7" Grid.Column="1" x:Name="CertSans"  Foreground="{DynamicResource BrushFgFaint}" FontSize="10" TextWrapping="Wrap" Margin="0,2,0,0"/>
          </Grid>
        </StackPanel>
      </ScrollViewer>
    </Border>

    <TextBlock Grid.Row="6" x:Name="HintLine" Foreground="{DynamicResource BrushFgFaint}" FontSize="10" Margin="0,4,0,4" TextWrapping="Wrap"
               Text="Stage timings tell you whether a slow site is DNS-bound, TCP-bound, or TLS-bound. .NET exposes the TLS handshake as a single timed call - sub-stage breakdown (ClientHello / ServerHello / Finished) requires ETW and isn't shown here."/>

    <!-- Action toolbar -->
    <WrapPanel Grid.Row="7" Orientation="Horizontal" HorizontalAlignment="Right" Margin="0,4,0,0">
      <Button x:Name="ProbeBtn"   Content="Probe again"     Padding="10,5" FontSize="11" Margin="0,0,6,0" Background="#1f6feb" Foreground="#ffffff" BorderBrush="#2f7fff" FontWeight="Bold"/>
      <Button x:Name="CertBtn"    Content="Open cert in MMC" Padding="10,5" FontSize="11" Margin="0,0,6,0"/>
      <Button x:Name="CopyBtn"    Content="Copy report"     Padding="10,5" FontSize="11" Margin="0,0,6,0"/>
      <Button x:Name="CloseBtn"   Content="Close"           Padding="14,5" FontSize="11"/>
    </WrapPanel>
  </Grid>
</Window>
'@
    $rdr = New-Object System.Xml.XmlNodeReader $x
    $w = [Windows.Markup.XamlReader]::Load($rdr)
    if ($window) { $w.Owner = $window }
    Wire-DialogEscClose $w   # Tier 55: ESC closes the dialog
    Apply-ThemeToChild $w

    $w.FindName('TargetLine').Text = ("Target: {0}:{1}" -f $HostName, $Port)
    $statusLine = $w.FindName('StatusLine')
    $probeBtn   = $w.FindName('ProbeBtn')

    function script:_RunTlsProbe {
        $statusLine.Text = ("Probing TLS handshake to {0}:{1}..." -f $HostName, $Port)
        $probeBtn.IsEnabled = $false
        $w.Cursor = [System.Windows.Input.Cursors]::Wait
        $tcpClient = $null
        $ssl = $null
        try {
            $totalSw = [System.Diagnostics.Stopwatch]::StartNew()

            # 1. DNS
            $dnsSw = [System.Diagnostics.Stopwatch]::StartNew()
            $resolvedIp = $HostName
            $tmp = [System.Net.IPAddress]::None
            if (-not [System.Net.IPAddress]::TryParse($HostName, [ref]$tmp)) {
                $addrs = [System.Net.Dns]::GetHostAddresses($HostName)
                $first = $addrs | Where-Object { $_.AddressFamily -eq [System.Net.Sockets.AddressFamily]::InterNetwork } | Select-Object -First 1
                if (-not $first) { $first = $addrs | Select-Object -First 1 }
                if ($first) { $resolvedIp = $first.IPAddressToString }
            }
            $dnsSw.Stop()

            # 2. TCP connect (with 8s timeout via async wait)
            $tcpSw = [System.Diagnostics.Stopwatch]::StartNew()
            $tcpClient = New-Object System.Net.Sockets.TcpClient
            $tcpClient.ReceiveTimeout = 8000
            $tcpClient.SendTimeout = 8000
            $async = $tcpClient.BeginConnect($resolvedIp, $Port, $null, $null)
            $waited = $async.AsyncWaitHandle.WaitOne(8000, $false)
            if (-not $waited) { throw 'TCP connect timed out (8s)' }
            $tcpClient.EndConnect($async)
            $tcpSw.Stop()

            # 3. TLS handshake. SslStream.AuthenticateAsClient is a single .NET call that
            # spans ClientHello -> ServerHello -> cert exchange -> key exchange -> Finished.
            # Sub-stage timing requires ETW (Microsoft-Windows-WinHttp / System.Net.Security source) - skipped.
            $tlsSw = [System.Diagnostics.Stopwatch]::StartNew()
            $stream = $tcpClient.GetStream()
            $ssl = New-Object System.Net.Security.SslStream($stream, $false, ([System.Net.Security.RemoteCertificateValidationCallback]{ param($s,$c,$ch,$e) $true }))
            # Use $HostName (not IP) for SNI - server may serve different certs by name
            $ssl.AuthenticateAsClient($HostName)
            $tlsSw.Stop()
            $totalSw.Stop()

            # Sample the stages
            $stages.Dns.Add([double]$dnsSw.ElapsedMilliseconds)
            $stages.Tcp.Add([double]$tcpSw.ElapsedMilliseconds)
            $stages.Tls.Add([double]$tlsSw.ElapsedMilliseconds)
            $stages.Total.Add([double]$totalSw.ElapsedMilliseconds)

            # Negotiated info
            $probeInfo.Protocol       = [string]$ssl.SslProtocol
            $probeInfo.CipherAlgo     = [string]$ssl.CipherAlgorithm
            $probeInfo.CipherStrength = [int]$ssl.CipherStrength
            $probeInfo.KeyExchange    = [string]$ssl.KeyExchangeAlgorithm
            $probeInfo.HashAlgo       = [string]$ssl.HashAlgorithm
            $probeInfo.ResolvedIp     = $resolvedIp

            # Server cert + chain validation
            $rawCert = $ssl.RemoteCertificate
            if ($rawCert) {
                $cert2 = New-Object System.Security.Cryptography.X509Certificates.X509Certificate2 $rawCert
                $probeInfo.Cert = $cert2

                # Validate the chain so we know if it's trusted
                try {
                    $chain = New-Object System.Security.Cryptography.X509Certificates.X509Chain
                    $chain.ChainPolicy.RevocationMode = [System.Security.Cryptography.X509Certificates.X509RevocationMode]::NoCheck
                    $chainOk = $chain.Build($cert2)
                    $probeInfo.ChainOk = $chainOk
                    if ($chainOk) {
                        $probeInfo.ChainStatus = ("✓ Valid ({0} link{1})" -f $chain.ChainElements.Count, $(if ($chain.ChainElements.Count -eq 1) {''} else {'s'}))
                    } else {
                        $probs = @($chain.ChainStatus | ForEach-Object { $_.StatusInformation.Trim() } | Where-Object { $_ })
                        $probeInfo.ChainStatus = ("✗ {0}" -f ($probs -join '; '))
                    }
                } catch {
                    $probeInfo.ChainStatus = "(chain validation error: $($_.Exception.Message))"
                }
            }

            $statusLine.Text = ("Probe complete in {0:N0}ms at {1}.  Click 'Probe again' to add another sample." -f $totalSw.ElapsedMilliseconds, (Get-Date -Format 'HH:mm:ss'))
            $probeInfo.Error = ''
        } catch {
            $probeInfo.Error = $_.Exception.Message
            $statusLine.Text = ("Probe failed: {0}" -f $_.Exception.Message)
        } finally {
            try { if ($ssl) { $ssl.Close() } } catch {}
            try { if ($tcpClient) { $tcpClient.Close() } } catch {}
            $probeBtn.IsEnabled = $true
            $w.Cursor = [System.Windows.Input.Cursors]::Arrow
        }

        # Refresh the UI with the new sample + cert info
        _RefreshTlsUi
    }

    function script:_StageStats {
        param([System.Collections.Generic.List[double]]$Samples)
        if (-not $Samples -or $Samples.Count -eq 0) { return @{ Last='--'; Avg='--'; Min='--'; Max='--'; Spark=('-' * 12) } }
        $arr = @($Samples)
        $last = $arr[-1]
        $avg  = ($arr | Measure-Object -Average).Average
        $min  = ($arr | Measure-Object -Minimum).Minimum
        $max  = ($arr | Measure-Object -Maximum).Maximum
        return @{
            Last  = ('{0:N0}ms' -f $last)
            Avg   = ('{0:N0}ms' -f $avg)
            Min   = ('{0:N0}ms' -f $min)
            Max   = ('{0:N0}ms' -f $max)
            Spark = (Format-MiniSpark -Samples $arr -Width 12)
        }
    }

    function script:_RefreshTlsUi {
        # Stage timing rows
        $d = _StageStats $stages.Dns
        $w.FindName('DnsLast').Text = $d.Last; $w.FindName('DnsAvg').Text = $d.Avg
        $w.FindName('DnsMin').Text  = $d.Min;  $w.FindName('DnsMax').Text = $d.Max
        $w.FindName('DnsSpark').Text = $d.Spark
        $t = _StageStats $stages.Tcp
        $w.FindName('TcpLast').Text = $t.Last; $w.FindName('TcpAvg').Text = $t.Avg
        $w.FindName('TcpMin').Text  = $t.Min;  $w.FindName('TcpMax').Text = $t.Max
        $w.FindName('TcpSpark').Text = $t.Spark
        $l = _StageStats $stages.Tls
        $w.FindName('TlsLast').Text = $l.Last; $w.FindName('TlsAvg').Text = $l.Avg
        $w.FindName('TlsMin').Text  = $l.Min;  $w.FindName('TlsMax').Text = $l.Max
        $w.FindName('TlsSpark').Text = $l.Spark
        $tot = _StageStats $stages.Total
        $w.FindName('TotLast').Text = $tot.Last; $w.FindName('TotAvg').Text = $tot.Avg
        $w.FindName('TotMin').Text  = $tot.Min;  $w.FindName('TotMax').Text = $tot.Max
        $w.FindName('TotSpark').Text = $tot.Spark

        # Negotiated info
        $w.FindName('NegIp').Text     = if ($probeInfo.ResolvedIp) { $probeInfo.ResolvedIp } else { '--' }
        $w.FindName('NegProto').Text  = if ($probeInfo.Protocol)   { $probeInfo.Protocol }   else { '--' }
        $cipherLabel = if ($probeInfo.CipherAlgo) { ("{0} ({1}-bit)" -f $probeInfo.CipherAlgo, $probeInfo.CipherStrength) } else { '--' }
        $w.FindName('NegCipher').Text = $cipherLabel
        $w.FindName('NegKex').Text    = if ($probeInfo.KeyExchange) { $probeInfo.KeyExchange } else { '--' }
        $w.FindName('NegHash').Text   = if ($probeInfo.HashAlgo)    { $probeInfo.HashAlgo }    else { '--' }

        # Certificate
        if ($probeInfo.Cert) {
            $c = $probeInfo.Cert
            $w.FindName('CertSubj').Text   = [string]$c.Subject
            $w.FindName('CertIssuer').Text = [string]$c.Issuer
            $w.FindName('CertFrom').Text   = $c.NotBefore.ToString('yyyy-MM-dd HH:mm')
            $daysLeft = ($c.NotAfter - (Get-Date)).TotalDays
            $expiryColor = if ($daysLeft -lt 0) { '#f85149' } elseif ($daysLeft -lt 30) { '#d29922' } else { '#3fb950' }
            $w.FindName('CertTo').Text = ("{0}  ({1:N0} days {2})" -f $c.NotAfter.ToString('yyyy-MM-dd HH:mm'), [Math]::Abs($daysLeft), $(if ($daysLeft -lt 0) {'EXPIRED'} else {'remaining'}))
            $w.FindName('CertTo').Foreground = (B $expiryColor)
            # Key info
            try {
                $keyAlg = $c.PublicKey.Oid.FriendlyName
                $keySize = $c.PublicKey.Key.KeySize
                $w.FindName('CertKey').Text = ("{0} {1}-bit" -f $keyAlg, $keySize)
            } catch { $w.FindName('CertKey').Text = '?' }
            $w.FindName('CertSerial').Text = [string]$c.SerialNumber
            $w.FindName('CertThumb').Text  = [string]$c.Thumbprint
            # SANs from extensions
            $sans = ''
            try {
                $sanExt = $c.Extensions | Where-Object { $_.Oid.Value -eq '2.5.29.17' } | Select-Object -First 1
                if ($sanExt) {
                    $sans = $sanExt.Format($true) -replace '\s+', ' '
                    if ($sans.Length -gt 240) { $sans = $sans.Substring(0,240) + '...' }
                }
            } catch {}
            $w.FindName('CertSans').Text = if ($sans) { $sans } else { '(none)' }
            # Chain status
            $w.FindName('CertChainStatus').Text = $probeInfo.ChainStatus
            $w.FindName('CertChainStatus').Foreground = if ($probeInfo.ChainOk) { (B '#3fb950') } else { (B '#f85149') }
        } else {
            $w.FindName('CertSubj').Text = '(no certificate retrieved)'
        }
    }

    # Wire actions
    $probeBtn.Add_Click({ _RunTlsProbe }.GetNewClosure())

    $w.FindName('CertBtn').Add_Click({
        if (-not $probeInfo.Cert) { $statusLine.Text = 'No cert retrieved yet - probe first.'; return }
        # Save cert to temp file and open in default handler (certmgr / mmc)
        try {
            $tmp = Join-Path $env:TEMP ("netjump-probe-{0}.cer" -f (Get-Date -Format 'yyyyMMddHHmmss'))
            [System.IO.File]::WriteAllBytes($tmp, $probeInfo.Cert.RawData)
            Start-Process $tmp -ErrorAction Stop | Out-Null
            $statusLine.Text = ("Cert exported and opened: {0}" -f $tmp)
        } catch {
            $statusLine.Text = ("Cert open failed: {0}" -f $_.Exception.Message)
        }
    }.GetNewClosure())

    $w.FindName('CopyBtn').Add_Click({
        $sb = New-Object System.Text.StringBuilder
        [void]$sb.AppendLine(("TLS PROBE: {0}:{1}" -f $HostName, $Port))
        [void]$sb.AppendLine("Generated: $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')")
        [void]$sb.AppendLine('-' * 80)
        $d = _StageStats $stages.Dns;   [void]$sb.AppendLine("DNS lookup     last={0}  avg={1}  min={2}  max={3}  samples={4}" -f $d.Last, $d.Avg, $d.Min, $d.Max, $stages.Dns.Count)
        $t = _StageStats $stages.Tcp;   [void]$sb.AppendLine("TCP connect    last={0}  avg={1}  min={2}  max={3}  samples={4}" -f $t.Last, $t.Avg, $t.Min, $t.Max, $stages.Tcp.Count)
        $l = _StageStats $stages.Tls;   [void]$sb.AppendLine("TLS handshake  last={0}  avg={1}  min={2}  max={3}  samples={4}" -f $l.Last, $l.Avg, $l.Min, $l.Max, $stages.Tls.Count)
        $tot = _StageStats $stages.Total; [void]$sb.AppendLine("TOTAL          last={0}  avg={1}  min={2}  max={3}  samples={4}" -f $tot.Last, $tot.Avg, $tot.Min, $tot.Max, $stages.Total.Count)
        [void]$sb.AppendLine('')
        [void]$sb.AppendLine("Resolved IP:    $($probeInfo.ResolvedIp)")
        [void]$sb.AppendLine("Protocol:       $($probeInfo.Protocol)")
        [void]$sb.AppendLine("Cipher:         $($probeInfo.CipherAlgo) ($($probeInfo.CipherStrength)-bit)")
        [void]$sb.AppendLine("Key exchange:   $($probeInfo.KeyExchange)")
        [void]$sb.AppendLine("Hash:           $($probeInfo.HashAlgo)")
        if ($probeInfo.Cert) {
            $c = $probeInfo.Cert
            [void]$sb.AppendLine('')
            [void]$sb.AppendLine("Certificate Subject:    $($c.Subject)")
            [void]$sb.AppendLine("Certificate Issuer:     $($c.Issuer)")
            [void]$sb.AppendLine("Valid:                  $($c.NotBefore.ToString('o')) -> $($c.NotAfter.ToString('o'))")
            [void]$sb.AppendLine("Serial:                 $($c.SerialNumber)")
            [void]$sb.AppendLine("Thumbprint:             $($c.Thumbprint)")
            [void]$sb.AppendLine("Chain:                  $($probeInfo.ChainStatus)")
        }
        Invoke-CopyToClipboard $sb.ToString()
        $statusLine.Text = ('TLS report copied to clipboard at ' + (Get-Date -Format 'HH:mm:ss'))
    }.GetNewClosure())

    $w.FindName('CloseBtn').Add_Click({ $w.Close() }.GetNewClosure())

    # Run the first probe immediately on dialog load
    $w.Add_Loaded({ _RunTlsProbe }.GetNewClosure())

    $w.ShowDialog() | Out-Null
}

# ---------- Tier 32: Retransmit Investigator modal ----------
# Answers the question "are my retransmits actually a problem?" using the RATIO metric
# (% of segments retransmitted vs sent) instead of raw rate. Shows:
#   - Cumulative since boot (the long-term baseline)
#   - Last 60s rolling window (current state)
#   - Per-process attribution (reuses Sample-RetransOffenders)
#   - Education panel explaining when retransmits ARE normal
function Show-RetransInvestigatorDialog {
    [xml]$x = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="NetJump - Retransmit Investigator" Width="900" Height="780" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BrushWindowBg}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Segoe UI">
  <Grid Margin="14">
    <Grid.RowDefinitions>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="*"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
    </Grid.RowDefinitions>

    <TextBlock Grid.Row="0" Text="RETRANSMIT INVESTIGATOR" Foreground="#58a6ff" FontSize="11" FontWeight="Bold"/>
    <TextBlock Grid.Row="1" Text="The honest health metric is RATIO (% of segments retransmitted), not raw rate. 5/s on a busy 5000/s flow is fine; 5/s on a 50/s flow is broken. This dialog lets you compare your current state against your own baseline AND industry norms." Foreground="{DynamicResource BrushFgMuted}" FontSize="11" TextWrapping="Wrap" Margin="0,4,0,8"/>

    <!-- VERDICT card (the headline answer) -->
    <Border Grid.Row="2" x:Name="VerdictBorder" Background="#1f3a26" BorderBrush="#3fb950" BorderThickness="2" CornerRadius="6" Padding="14,10" Margin="0,0,0,8">
      <StackPanel>
        <TextBlock x:Name="VerdictHeadline" Text="--" FontSize="18" FontWeight="Bold"/>
        <TextBlock x:Name="VerdictDescription" Text="--" FontSize="12" TextWrapping="Wrap" Margin="0,4,0,0"/>
      </StackPanel>
    </Border>

    <!-- TWO-COLUMN STATS: cumulative since boot vs last-60s rolling -->
    <Grid Grid.Row="3" Margin="0,0,0,8">
      <Grid.ColumnDefinitions>
        <ColumnDefinition Width="*"/>
        <ColumnDefinition Width="*"/>
      </Grid.ColumnDefinitions>

      <!-- LEFT: cumulative since boot -->
      <Border Grid.Column="0" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="12,8" Margin="0,0,4,0">
        <StackPanel>
          <TextBlock Text="CUMULATIVE  (since system boot)" Foreground="#58a6ff" FontWeight="Bold" FontSize="10" Margin="0,0,0,6"/>
          <Grid>
            <Grid.ColumnDefinitions>
              <ColumnDefinition Width="130"/>
              <ColumnDefinition Width="*"/>
            </Grid.ColumnDefinitions>
            <Grid.RowDefinitions>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
            </Grid.RowDefinitions>
            <TextBlock Grid.Row="0" Grid.Column="0" Text="Segments sent"        Foreground="{DynamicResource BrushFgMuted}" FontSize="11"/>
            <TextBlock Grid.Row="0" Grid.Column="1" x:Name="CumSent"            Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11"/>
            <TextBlock Grid.Row="1" Grid.Column="0" Text="Segments retransmitted" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="1" Grid.Column="1" x:Name="CumResent"          Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="2" Grid.Column="0" Text="Ratio"                Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="2" Grid.Column="1" x:Name="CumRatio"           Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="13" FontWeight="Bold" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="3" Grid.Column="0" Text="Verdict"              Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="3" Grid.Column="1" x:Name="CumVerdict"         Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" FontWeight="Bold" Margin="0,2,0,0"/>
          </Grid>
        </StackPanel>
      </Border>

      <!-- RIGHT: last 60s rolling window -->
      <Border Grid.Column="1" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="12,8" Margin="4,0,0,0">
        <StackPanel>
          <TextBlock Text="LAST 60 SECONDS  (rolling window)" Foreground="#58a6ff" FontWeight="Bold" FontSize="10" Margin="0,0,0,6"/>
          <Grid>
            <Grid.ColumnDefinitions>
              <ColumnDefinition Width="130"/>
              <ColumnDefinition Width="*"/>
            </Grid.ColumnDefinitions>
            <Grid.RowDefinitions>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
            </Grid.RowDefinitions>
            <TextBlock Grid.Row="0" Grid.Column="0" Text="Avg retrans rate"   Foreground="{DynamicResource BrushFgMuted}" FontSize="11"/>
            <TextBlock Grid.Row="0" Grid.Column="1" x:Name="WinRate"          Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11"/>
            <TextBlock Grid.Row="1" Grid.Column="0" Text="Peak rate"          Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="1" Grid.Column="1" x:Name="WinPeak"          Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="2" Grid.Column="0" Text="Avg ratio"          Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="2" Grid.Column="1" x:Name="WinRatio"         Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="13" FontWeight="Bold" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="3" Grid.Column="0" Text="Verdict"            Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,2,0,0"/>
            <TextBlock Grid.Row="3" Grid.Column="1" x:Name="WinVerdict"       Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" FontWeight="Bold" Margin="0,2,0,0"/>
          </Grid>
        </StackPanel>
      </Border>
    </Grid>

    <!-- TREND row -->
    <Border Grid.Row="4" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="12,8" Margin="0,0,0,8">
      <StackPanel>
        <TextBlock Text="60-SAMPLE TREND  (sparkline shows ratio over recent heavy ticks)" Foreground="#58a6ff" FontWeight="Bold" FontSize="10" Margin="0,0,0,4"/>
        <Grid>
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="100"/>
            <ColumnDefinition Width="*"/>
          </Grid.ColumnDefinitions>
          <TextBlock Grid.Column="0" Text="Ratio (% sparkline)" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" VerticalAlignment="Center"/>
          <TextBlock Grid.Column="1" x:Name="TrendSpark" Text="" Foreground="#bf6dff" FontFamily="Consolas" FontSize="14"/>
        </Grid>
        <Grid Margin="0,4,0,0">
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="100"/>
            <ColumnDefinition Width="*"/>
          </Grid.ColumnDefinitions>
          <TextBlock Grid.Column="0" Text="Stability"   Foreground="{DynamicResource BrushFgMuted}" FontSize="11"/>
          <TextBlock Grid.Column="1" x:Name="TrendStability" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" TextWrapping="Wrap"/>
        </Grid>
      </StackPanel>
    </Border>

    <!-- PER-PROCESS attribution -->
    <Border Grid.Row="5" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="0">
      <Grid>
        <Grid.RowDefinitions>
          <RowDefinition Height="Auto"/>
          <RowDefinition Height="*"/>
        </Grid.RowDefinitions>
        <TextBlock Grid.Row="0" x:Name="OffenderHeader" Text="LIKELY-OFFENDER CONNECTIONS  (snapshot)" Foreground="#58a6ff" FontWeight="Bold" FontSize="10" Padding="12,8"/>
        <ScrollViewer Grid.Row="1" VerticalScrollBarVisibility="Auto" Padding="12,0,12,8">
          <ItemsControl x:Name="OffenderList">
            <ItemsControl.ItemTemplate>
              <DataTemplate>
                <Border BorderThickness="0,0,0,1" BorderBrush="{DynamicResource BrushBorder}" Padding="0,3">
                  <Grid>
                    <Grid.ColumnDefinitions>
                      <ColumnDefinition Width="80"/>
                      <ColumnDefinition Width="*"/>
                      <ColumnDefinition Width="Auto"/>
                    </Grid.ColumnDefinitions>
                    <Border Grid.Column="0" Background="{Binding SeverityBrush}" CornerRadius="2" Padding="4,1" HorizontalAlignment="Left" VerticalAlignment="Center">
                      <TextBlock Text="{Binding SeverityTag}" Foreground="#ffffff" FontSize="9" FontWeight="Bold"/>
                    </Border>
                    <TextBlock Grid.Column="1" Margin="8,0,0,0" Text="{Binding EndpointLabel}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" VerticalAlignment="Center" TextTrimming="CharacterEllipsis"/>
                    <TextBlock Grid.Column="2" Margin="8,0,0,0" Text="{Binding Reason}" Foreground="{DynamicResource BrushFgMuted}" FontSize="10" VerticalAlignment="Center"/>
                  </Grid>
                </Border>
              </DataTemplate>
            </ItemsControl.ItemTemplate>
          </ItemsControl>
        </ScrollViewer>
      </Grid>
    </Border>

    <!-- Tier 70: INVESTIGATION RESULT - pattern-matches offenders to specific root causes and lists
         actionable fixes. Replaces the previous static "education footer" with dynamic analysis. -->
    <Border Grid.Row="6" Background="{DynamicResource BrushDeepBg}" BorderBrush="#bf6dff" BorderThickness="2" CornerRadius="6" Padding="12,8" Margin="0,8,0,0">
      <StackPanel>
        <TextBlock Text="🔬 INVESTIGATION RESULT" Foreground="#bf6dff" FontWeight="Bold" FontSize="11" Margin="0,0,0,6"/>
        <TextBlock x:Name="InvestSummary" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" TextWrapping="Wrap" Margin="0,0,0,8"/>
        <!-- Tier 80: PERIODICITY card. Surfaces the answer to "why does this keep happening every N
             events?" - by sampling the LIVE EVENTS ring buffer for retrans-class entries, computing
             interval mean+stddev, and pattern-matching the cycle length against well-known Windows
             recurring intervals. The headline is one line; the hint expands into a wrapping body
             that reads like an investigator note. ProcAttribution adds the "and one process keeps
             showing up" angle when applicable. -->
        <Border x:Name="PeriodicityBorder" Background="{DynamicResource BrushCardBg}" BorderBrush="#79c0ff" BorderThickness="2,1,1,1" CornerRadius="4" Padding="10,6" Margin="0,0,0,8" Visibility="Collapsed">
          <StackPanel>
            <TextBlock Text="⏱ PATTERN ANALYSIS  (timing of retrans events in the LIVE EVENTS buffer)" Foreground="#79c0ff" FontWeight="Bold" FontSize="10" Margin="0,0,0,4"/>
            <TextBlock x:Name="PeriodicityHeadline" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontWeight="Bold" FontSize="11" Margin="0,0,0,4" TextWrapping="Wrap"/>
            <TextBlock x:Name="PeriodicityHint"     Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" Margin="0,0,0,4" TextWrapping="Wrap"/>
            <TextBlock x:Name="PeriodicityProc"     Text="--" Foreground="{DynamicResource BrushFgMuted}"   FontSize="11" Margin="0,0,0,0" TextWrapping="Wrap"/>
          </StackPanel>
        </Border>
        <ItemsControl x:Name="CausesList">
          <ItemsControl.ItemTemplate>
            <DataTemplate>
              <Border Background="{DynamicResource BrushCardBg}" BorderBrush="{Binding HexBrush}" BorderThickness="3,1,1,1" CornerRadius="6" Padding="10,8" Margin="0,0,0,6">
                <StackPanel>
                  <Grid>
                    <Grid.ColumnDefinitions>
                      <ColumnDefinition Width="*"/>
                      <ColumnDefinition Width="Auto"/>
                    </Grid.ColumnDefinitions>
                    <TextBlock Grid.Column="0" Text="{Binding Title}" Foreground="{Binding HexBrush}" FontWeight="Bold" FontSize="12" TextWrapping="Wrap"/>
                    <Border Grid.Column="1" Background="{Binding HexBrush}" CornerRadius="3" Padding="6,1" VerticalAlignment="Center" MinWidth="48">
                      <TextBlock Text="{Binding ConfidenceLabel}" Foreground="#ffffff" FontSize="10" FontWeight="Bold" HorizontalAlignment="Center"/>
                    </Border>
                  </Grid>
                  <TextBlock Text="{Binding Evidence}" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" TextWrapping="Wrap" Margin="0,4,0,0"/>
                  <TextBlock Text="{Binding Recommendation}" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" TextWrapping="Wrap" Margin="0,4,0,4" FontStyle="Italic"/>
                  <TextBlock Text="{Binding FixCountLabel}" Foreground="#3fb950" FontSize="10" FontWeight="SemiBold"/>
                </StackPanel>
              </Border>
            </DataTemplate>
          </ItemsControl.ItemTemplate>
        </ItemsControl>
      </StackPanel>
    </Border>

    <!-- Action toolbar - Tier 70: action buttons that target the diagnosed cause directly -->
    <WrapPanel Grid.Row="7" Orientation="Horizontal" HorizontalAlignment="Right" Margin="0,8,0,0">
      <Button x:Name="AutoFixBtn"     Content="🚀 Auto-fix SAFE" Padding="10,4" FontSize="11" FontWeight="Bold" Margin="0,0,6,0" Background="#15803d" Foreground="#ffffff" BorderBrush="#3fb950" ToolTip="Apply every SAFE-tier fix the investigator surfaced. MODERATE / DISRUPTIVE fixes still need manual review via the Fix Picker."/>
      <Button x:Name="FixPickerBtn"   Content="Open Fix Picker..." Padding="10,4" FontSize="11" Margin="0,0,6,0" ToolTip="Open the full Fix Picker dialog to review every fix (Safe / Moderate / Disruptive) and apply selectively."/>
      <Button x:Name="PathInspectBtn" Content="Path inspect top remote..." Padding="10,4" FontSize="11" Margin="0,0,6,0" ToolTip="Run a continuous traceroute to the most-frequent remote endpoint in the offender list. Spots which hop is dropping packets."/>
      <Button x:Name="MtuBtn"         Content="Probe MTU..." Padding="10,4" FontSize="11" Margin="0,0,6,0" ToolTip="DF-flagged ping probe to find the largest payload that survives the path. Reveals MTU black holes that cause silent retransmits."/>
      <Button x:Name="RefreshBtn"     Content="Refresh" Padding="10,4" FontSize="11" Margin="0,0,6,0" Background="#1f6feb" Foreground="#ffffff" BorderBrush="#2f7fff"/>
      <Button x:Name="CopyBtn"        Content="Copy report" Padding="10,4" FontSize="11" Margin="0,0,6,0"/>
      <Button x:Name="CloseBtn"       Content="Close" Padding="14,4" FontSize="11"/>
    </WrapPanel>
  </Grid>
</Window>
'@
    $rdr = New-Object System.Xml.XmlNodeReader $x
    $w = [Windows.Markup.XamlReader]::Load($rdr)
    if ($window) { $w.Owner = $window }
    Wire-DialogEscClose $w   # Tier 55: ESC closes the dialog
    Apply-ThemeToChild $w

    # Safe-stat helper: handles empty lists AND lists where Measure-Object -Average returns $null
    # (which can happen with List[double] in some PS5.1 enumeration paths).
    # Always returns a concrete double, even when the stat is genuinely 0 - so {0:N3} format never blanks.
    function script:_SafeStat {
        param($List, [string]$Stat = 'Average')
        if (-not $List) { return 0.0 }
        try {
            # Convert List[double] to a plain double[] - avoids enumerator weirdness with Measure-Object
            $arr = if ($List -is [System.Collections.Generic.List[double]]) { $List.ToArray() } else { @($List) }
            if ($arr.Count -eq 0) { return 0.0 }
            $m = $arr | Measure-Object -Average -Maximum -Minimum
            $v = switch ($Stat) {
                'Average' { $m.Average }
                'Maximum' { $m.Maximum }
                'Minimum' { $m.Minimum }
                default   { 0 }
            }
            if ($null -eq $v) { return 0.0 }
            return [double]$v
        } catch { return 0.0 }
    }

    # Tier 80: pattern-analysis dispatcher inside the dialog scope. Delegates to the top-level
    # Analyze-RetransPeriodicity function so the same logic is reachable from the heavy tick
    # auto-emit (which fires whether the dialog is open or not).
    function script:_AnalyzeRetransPeriodicity { Analyze-RetransPeriodicity }

    # Tier 70: pattern-matching analysis. Takes the offender snapshot + ratio sample, returns a
    # list of identified root-cause candidates with confidence + specific fixes. Each cause has:
    #   Title, Severity (HIGH/MEDIUM/LOW), Confidence (0-100), Hex (color), Evidence (what we saw),
    #   Recommendation (the why + how), Fixes = list of @{Description; Command} that auto-fix can run.
    function script:_AnalyzeRetransCauses {
        param($Offenders, $Sample, $RatioHistory)
        $causes = New-Object System.Collections.Generic.List[object]
        $aname = if ($script:State.Adapter) { $script:State.Adapter.Name } else { '' }
        $offenderList = @($Offenders)
        $offCount = $offenderList.Count

        # CAUSE 1: NetJump's own PID dominates -> upstream path issue, not local app
        $selfPidConns = @($offenderList | Where-Object { $_.Pid -eq $PID })
        if ($selfPidConns.Count -ge 2) {
            $fixes = New-Object System.Collections.Generic.List[object]
            [void]$fixes.Add(@{ Description='Flush DNS resolver cache (try fresh resolutions)'; Command='ipconfig /flushdns | Out-Null' })
            [void]$fixes.Add(@{ Description='Reset TCP autotuning to normal'; Command='netsh int tcp set global autotuninglevel=normal | Out-Null' })
            [void]$causes.Add([pscustomobject]@{
                Title           = "Upstream path issue (NetJump's own traffic is retransmitting)"
                Severity        = 'HIGH'
                Confidence      = 80
                ConfidenceLabel = '80% conf'
                Hex             = '#d29922'
                HexBrush        = (B '#d29922')
                Evidence        = ("NetJump's own pid {0} appears in {1} of the {2} suspect connection(s). Our outbound HTTPS calls (public-IP cache, threat-intel feeds) are seeing the same loss as everything else - this is path-level, not application-level." -f $PID, $selfPidConns.Count, $offCount)
                Recommendation  = "Run Path Inspect on the top remote to find which hop is degraded. If it's hop 1 or 2, replace cable / move closer to AP / restart router. If it's hop 3+, contact ISP."
                FixCountLabel   = "$($fixes.Count) SAFE fix(es) available"
                Fixes           = $fixes
            })
        }

        # CAUSE 2: STUCK-state cluster (CLOSE_WAIT / FIN_WAIT / LAST_ACK) -> server stopped responding
        $stuck = @($offenderList | Where-Object { $_.SeverityTag -eq 'STUCK' })
        if ($stuck.Count -ge 3) {
            $stuckPids = ($stuck | Group-Object Pid | Sort-Object Count -Descending | Select-Object -First 3 | ForEach-Object { "$($_.Group[0].ProcessName)(pid $($_.Name))" }) -join ', '
            $fixes = New-Object System.Collections.Generic.List[object]
            [void]$fixes.Add(@{ Description='Flush DNS resolver cache (in case stale resolution is sending us to a dead server)'; Command='ipconfig /flushdns | Out-Null' })
            [void]$causes.Add([pscustomobject]@{
                Title           = ("$($stuck.Count) STUCK connections - remote endpoints stopped ACKing")
                Severity        = 'HIGH'
                Confidence      = 85
                ConfidenceLabel = '85% conf'
                Hex             = '#f85149'
                HexBrush        = (B '#f85149')
                Evidence        = ("$($stuck.Count) connections in CLOSE_WAIT/FIN_WAIT/LAST_ACK across $stuckPids. The kernel is repeatedly resending FIN/ACK to remote endpoints that have gone silent.")
                Recommendation  = 'These are app-level half-closed sockets. Restart the offending process(es) - the connections are dead anyway. If many apps are affected, the underlying cause is probably an upstream firewall or NAT timing out long-lived connections; consider TCP keepalive tuning.'
                FixCountLabel   = "$($fixes.Count) SAFE fix(es) - app restart required (not auto-fixable)"
                Fixes           = $fixes
            })
        }

        # CAUSE 3: Single PID dominates -> application-level bug or misbehaving service
        $byPid = $offenderList | Group-Object Pid | Sort-Object Count -Descending
        if ($byPid -and $byPid[0].Count -ge 5 -and $byPid[0].Count -gt ($offCount * 0.5) -and $byPid[0].Group[0].Pid -ne $PID) {
            $top = $byPid[0]
            $causes.Add([pscustomobject]@{
                Title           = ("Single process dominates: $($top.Group[0].ProcessName) (pid $($top.Name)) -> $($top.Count) of $offCount suspect connections")
                Severity        = 'HIGH'
                Confidence      = 75
                ConfidenceLabel = '75% conf'
                Hex             = '#d29922'
                HexBrush        = (B '#d29922')
                Evidence        = ("$($top.Group[0].ProcessName) holds $($top.Count) suspect connections (>50% of the offender list). Either the app is overwhelming the link, or it's stuck in a tight retry loop talking to a degraded remote.")
                Recommendation  = "Right-click that process row in TOP RETRANS SUSPECTS -> Connection details... to see remotes. If the remotes look unhealthy, restart the process. If many remotes are slow simultaneously, the app is probably fine and the network is degraded."
                FixCountLabel   = "0 auto-fixes (process-specific intervention required)"
                Fixes           = (New-Object System.Collections.Generic.List[object])
            })
        }

        # CAUSE 4: streaming pattern - many connections to same remote
        $byRemote = $offenderList | Where-Object { $_.RemoteAddress } | Group-Object RemoteAddress | Sort-Object Count -Descending
        if ($byRemote -and $byRemote[0].Count -ge 4 -and $byRemote[0].Count -gt ($offCount * 0.4)) {
            $topRemote = $byRemote[0]
            $causes.Add([pscustomobject]@{
                Title           = ("Concentrated remote: $($topRemote.Count) connections all going to $($topRemote.Name)")
                Severity        = 'MEDIUM'
                Confidence      = 70
                ConfidenceLabel = '70% conf'
                Hex             = '#d29922'
                HexBrush        = (B '#d29922')
                Evidence        = ("$($topRemote.Count) of $offCount suspect connections share the same remote IP. This is the streaming-flow pattern: an app (browser, video player, sync client) opens parallel connections to one server.")
                Recommendation  = "If the streaming app is intentional (Netflix, Steam, screen-share), this is likely background loss with no real user impact. If it isn't, run Path Inspect to that IP to find the bad hop."
                FixCountLabel   = "Diagnostic-only (use Path Inspect to investigate path)"
                Fixes           = (New-Object System.Collections.Generic.List[object])
            })
        }

        # CAUSE 5: NIC power management / EEE - hardware-level retransmits.
        # We can't easily detect "EEE is on" without polling NIC properties (slow), so this cause is
        # ALWAYS offered as a candidate when sustained CRITICAL is observed. SAFE to apply blindly -
        # disabling EEE / power-mgmt has no downsides on a wired desktop with a flap problem.
        if ($Sample.CumRatio -ge 1.0 -or ($RatioHistory -and ($RatioHistory | Measure-Object -Maximum).Maximum -ge 2.0)) {
            $fixes = New-Object System.Collections.Generic.List[object]
            if ($aname) {
                [void]$fixes.Add(@{ Description="Disable NIC power management on '$aname'"; Command="Disable-NetAdapterPowerManagement -Name '$aname' -AllowComputerToTurnOffDevice -ErrorAction SilentlyContinue" })
                [void]$fixes.Add(@{ Description="Disable Energy-Efficient Ethernet on '$aname' (link-renegotiation drops)"; Command="Set-NetAdapterAdvancedProperty -Name '$aname' -DisplayName 'Energy-Efficient Ethernet' -DisplayValue 'Disabled' -ErrorAction SilentlyContinue" })
                [void]$fixes.Add(@{ Description="Disable Selective Suspend on '$aname'"; Command="Set-NetAdapterAdvancedProperty -Name '$aname' -DisplayName 'Selective Suspend' -DisplayValue 'Disabled' -ErrorAction SilentlyContinue" })
            }
            [void]$fixes.Add(@{ Description='Reset TCP autotuning to normal'; Command='netsh int tcp set global autotuninglevel=normal | Out-Null' })
            [void]$fixes.Add(@{ Description='Disable TCP timestamps (some middleboxes corrupt these)'; Command='netsh int tcp set global timestamps=disabled | Out-Null' })
            $causes.Add([pscustomobject]@{
                Title           = 'NIC / kernel-stack mitigations (always-safe baseline)'
                Severity        = 'MEDIUM'
                Confidence      = 60
                ConfidenceLabel = '60% conf'
                Hex             = '#3fb950'
                HexBrush        = (B '#3fb950')
                Evidence        = "Sustained retransmit ratio above the EXCELLENT (0.1%) threshold. Even when offenders look benign, a small set of always-safe NIC + kernel TCP knobs commonly improve retransmit baseline by 30-60%. These fixes are reversible and have no downside on a typical wired/Wi-Fi setup."
                Recommendation  = "Try Auto-fix SAFE first - if the ratio drops, you're done. If it persists, the cause is upstream (path / ISP / remote)."
                FixCountLabel   = "$($fixes.Count) SAFE fix(es) available - one-click via Auto-fix SAFE"
                Fixes           = $fixes
            })
        }

        # CAUSE 6: nothing notable, ratio is fine
        if ($causes.Count -eq 0) {
            $causes.Add([pscustomobject]@{
                Title           = 'No actionable cause identified'
                Severity        = 'LOW'
                Confidence      = 50
                ConfidenceLabel = '50% conf'
                Hex             = '#3fb950'
                HexBrush        = (B '#3fb950')
                Evidence        = "Retransmit ratio is within normal Internet baseline (cum: $('{0:N3}%' -f $Sample.CumRatio)). The TOP RETRANS SUSPECTS panel is showing transient losses that are common on real-world links - especially Wi-Fi, peak-hour ISP traffic, and high-throughput downloads."
                Recommendation  = 'No fix needed. Watch the trend sparkline above - if the ratio starts climbing or instability increases (std dev rising), come back to this dialog. The Refresh button re-runs the analysis.'
                FixCountLabel   = '0 fixes needed'
                Fixes           = (New-Object System.Collections.Generic.List[object])
            })
        }
        return $causes
    }

    function script:_RefreshInvestigator {
        # Pull a fresh sample so we have current cum + delta
        $sample = Sample-RetransRatio
        # Derive 60s rolling stats from history (averages of recent values).
        # Use _SafeStat so $null from Measure-Object can never sneak through into format strings.
        $rateHist  = $script:State.RetransHistory
        $ratioHist = $script:State.RetransRatioHistory
        $avgRate   = _SafeStat $rateHist  'Average'
        $peakRate  = _SafeStat $rateHist  'Maximum'
        $avgRatio  = _SafeStat $ratioHist 'Average'
        $minRatio  = _SafeStat $ratioHist 'Minimum'
        $maxRatio  = _SafeStat $ratioHist 'Maximum'
        $stdDev = 0
        if ($ratioHist.Count -gt 1) {
            $sumSq = 0
            foreach ($v in $ratioHist) { $sumSq += [Math]::Pow($v - $avgRatio, 2) }
            $stdDev = [Math]::Sqrt($sumSq / $ratioHist.Count)
        }

        # Cumulative card
        $w.FindName('CumSent').Text   = ('{0:N0}' -f $sample.CumSent)
        $w.FindName('CumResent').Text = ('{0:N0}' -f $sample.CumResent)
        $w.FindName('CumRatio').Text  = ('{0:N3}%' -f $sample.CumRatio)
        $cumV = Get-RetransVerdict -RatioPct $sample.CumRatio
        $w.FindName('CumVerdict').Text       = $cumV.Label
        $w.FindName('CumVerdict').Foreground = (B $cumV.Hex)

        # 60s window card
        $w.FindName('WinRate').Text   = ('{0:N1}/s' -f $avgRate)
        $w.FindName('WinPeak').Text   = ('{0:N1}/s' -f $peakRate)
        $w.FindName('WinRatio').Text  = ('{0:N3}%  (min {1:N3}, max {2:N3})' -f $avgRatio, $minRatio, $maxRatio)
        $winV = Get-RetransVerdict -RatioPct $avgRatio
        $w.FindName('WinVerdict').Text       = $winV.Label
        $w.FindName('WinVerdict').Foreground = (B $winV.Hex)

        # Headline verdict (the bigger of the two so user sees worst case)
        $headlineV = if ($winV.Label -eq 'CRITICAL' -or $cumV.Label -eq 'CRITICAL') {
            Get-RetransVerdict -RatioPct (([Math]::Max($sample.CumRatio, $avgRatio)) + 0.001)
        } elseif ($winV.Label -in 'HIGH','ELEVATED') { $winV } else { $cumV }
        $w.FindName('VerdictHeadline').Text = ('Verdict: {0}' -f $headlineV.Label)
        $w.FindName('VerdictHeadline').Foreground = (B $headlineV.Hex)
        $w.FindName('VerdictDescription').Text = $headlineV.Description
        $w.FindName('VerdictBorder').BorderBrush = (B $headlineV.Hex)
        $w.FindName('VerdictBorder').Background = (B $(switch ($headlineV.Label) {
            'EXCELLENT' { '#0e2a16' } 'NORMAL' { '#1f3a26' } 'ELEVATED' { '#3d2c0a' } 'HIGH' { '#3d2c0a' } default { '#3a0a0c' }
        }))

        # Trend
        $w.FindName('TrendSpark').Text = (Format-MiniSpark -Samples $ratioHist -Width 30)
        $stabilityLabel = if ($ratioHist.Count -lt 5) { 'Insufficient samples - wait ~30s for the heavy ticker to populate.' }
                          elseif ($stdDev -lt 0.05) { ('STABLE  ({0:N3}% baseline, std dev {1:N3}%) - whatever this number is, it''s your normal.' -f $avgRatio, $stdDev) }
                          elseif ($stdDev -lt 0.5)  { ('SLIGHTLY VARIABLE  (std dev {0:N3}%)' -f $stdDev) }
                          else                       { ('UNSTABLE  (std dev {0:N3}% - large swings indicate active link/path issues, not steady-state baseline)' -f $stdDev) }
        $w.FindName('TrendStability').Text = $stabilityLabel

        # Per-process offenders (snapshot)
        $offenders = @()
        try {
            $offenders = Sample-RetransOffenders
            $w.FindName('OffenderList').ItemsSource = $offenders
            $w.FindName('OffenderHeader').Text = if ($offenders.Count -eq 0) {
                'LIKELY-OFFENDER CONNECTIONS  (none right now - retransmits may be from short-lived flows)'
            } else {
                ('LIKELY-OFFENDER CONNECTIONS  ({0} suspect{1} - sorted by score)' -f $offenders.Count, $(if ($offenders.Count -eq 1) {''} else {'s'}))
            }
        } catch {
            $w.FindName('OffenderHeader').Text = ("LIKELY-OFFENDER CONNECTIONS  (error: {0})" -f $_.Exception.Message)
        }

        # Tier 70: pattern-match offenders + sample to specific causes, render with confidence chips
        try {
            $causes = _AnalyzeRetransCauses -Offenders $offenders -Sample $sample -RatioHistory $ratioHist
            $w.FindName('CausesList').ItemsSource = $causes
            $totalFixes = ($causes | ForEach-Object { $_.Fixes.Count } | Measure-Object -Sum).Sum
            $causeNames = ($causes | Where-Object { $_.Severity -in 'HIGH','MEDIUM' } | ForEach-Object { '"' + $_.Title.Substring(0, [Math]::Min(50, $_.Title.Length)) + '"' }) -join ', '
            $sumLine = if ($causes.Count -eq 1 -and $causes[0].Severity -eq 'LOW') {
                "Investigation complete: no actionable cause identified. The ratio is within normal baseline."
            } else {
                ("Investigation complete: {0} candidate cause(s) identified, {1} auto-applicable SAFE fix(es) available. Click 'Auto-fix SAFE' to apply them all in one shot." -f $causes.Count, $totalFixes)
            }
            $w.FindName('InvestSummary').Text = $sumLine
            $script:_LastInvestCauses = $causes   # stash for the Auto-fix / Copy report buttons
        } catch {
            $w.FindName('InvestSummary').Text = ('Analysis error: ' + $_.Exception.Message)
        }

        # Tier 80: pattern/periodicity analysis - shown only if we have enough samples to be useful.
        try {
            $pAnalysis = _AnalyzeRetransPeriodicity
            $pBorder = $w.FindName('PeriodicityBorder')
            if ($pAnalysis.Status -eq 'ok') {
                $w.FindName('PeriodicityHeadline').Text = [string]$pAnalysis.Headline
                $w.FindName('PeriodicityHint').Text     = [string]$pAnalysis.PatternHint
                $w.FindName('PeriodicityProc').Text     = [string]$pAnalysis.ProcAttribution
                if ($pBorder) { $pBorder.Visibility = 'Visible' }
                # Color code the border by regularity: clockwork = blue, irregular = gray.
                if ($pBorder) {
                    $pBorder.BorderBrush = switch ($pAnalysis.Regularity) {
                        'clockwork'        { (B '#79c0ff') }
                        'periodic'         { (B '#bf6dff') }
                        'loosely periodic' { (B '#d29922') }
                        default            { (B '#6a7380') }
                    }
                }
            } else {
                if ($pBorder) {
                    $pBorder.Visibility = 'Visible'
                    $w.FindName('PeriodicityHeadline').Text = ("INSUFFICIENT DATA - {0} retrans event(s) in buffer (need >=4)" -f [int]$pAnalysis.EventCount)
                    $w.FindName('PeriodicityHint').Text     = 'The pattern analyzer needs at least 4 retransmit events in the LIVE EVENTS buffer to compute interval and regularity. Wait for more events to accumulate, or trigger some traffic to surface them.'
                    $w.FindName('PeriodicityProc').Text     = ''
                }
            }
        } catch {
            # Pattern analysis is a nice-to-have; never let an exception kill the dialog refresh.
            try { Add-Event warn ("Retrans periodicity analysis failed: {0}" -f $_.Exception.Message) } catch {}
        }
    }

    $w.FindName('RefreshBtn').Add_Click({ _RefreshInvestigator }.GetNewClosure())
    # Tier 70: Auto-fix SAFE - merges every SAFE fix from the diagnosed causes + reuses the
    # main Invoke-ApplySafeFixes pipeline. Confirms with a preview before applying.
    $w.FindName('AutoFixBtn').Add_Click({
        if (-not $script:_LastInvestCauses -or $script:_LastInvestCauses.Count -eq 0) {
            [System.Windows.MessageBox]::Show($w, 'Nothing to apply yet - click Refresh first.', 'No analysis', 'OK', 'Information') | Out-Null
            return
        }
        # Merge cause fixes into the main RecommendedFixes list so Invoke-ApplySafeFixes picks them up
        if (-not $script:State.RecommendedFixes) { $script:State.RecommendedFixes = @() }
        $existingCmds = @{}; foreach ($f in $script:State.RecommendedFixes) { $existingCmds[[string]$f.Command] = $true }
        foreach ($c in $script:_LastInvestCauses) {
            foreach ($fx in $c.Fixes) {
                if (-not $existingCmds.ContainsKey([string]$fx.Command)) {
                    $script:State.RecommendedFixes += @{ Description = $fx.Description; Command = $fx.Command }
                    $existingCmds[[string]$fx.Command] = $true
                }
            }
        }
        $r = Invoke-ApplySafeFixes -Confirm -StartVerifyWatch
        if ($r.AppliedCount -gt 0) {
            [System.Windows.MessageBox]::Show($w, ("Applied {0} SAFE fix(es).{1}`n`n10-minute verify watch is running. Watch for the toast notification." -f $r.AppliedCount, $(if ($r.FailedCount -gt 0) { " {0} failed - see LIVE EVENTS for details." -f $r.FailedCount } else { '' })), 'Auto-fix done', 'OK', 'Information') | Out-Null
            _RefreshInvestigator
        }
    }.GetNewClosure())
    # Tier 70: open the full Fix Picker dialog
    $w.FindName('FixPickerBtn').Add_Click({
        try { Show-FixPickerDialog }
        catch { [System.Windows.MessageBox]::Show($w, "Fix picker failed:`n$_", 'Error', 'OK', 'Error') | Out-Null }
    }.GetNewClosure())
    # Tier 70: launch Path Inspection on the most-frequent remote IP in the offender list
    $w.FindName('PathInspectBtn').Add_Click({
        $target = $null
        try {
            $offenders = Sample-RetransOffenders
            if ($offenders -and $offenders.Count -gt 0) {
                $byRemote = $offenders | Where-Object { $_.RemoteAddress } | Group-Object RemoteAddress | Sort-Object Count -Descending
                if ($byRemote -and $byRemote[0]) { $target = $byRemote[0].Name }
            }
        } catch {}
        if (-not $target) { $target = '1.1.1.1' }
        try { Show-PathInspectionDialog -Target $target }
        catch { [System.Windows.MessageBox]::Show($w, "Path inspect failed:`n$_", 'Error', 'OK', 'Error') | Out-Null }
    }.GetNewClosure())
    # Tier 70: probe MTU - reuses the existing menu handler logic
    $w.FindName('MtuBtn').Add_Click({
        try {
            if ($controls.MenuMtu) {
                $controls.MenuMtu.RaiseEvent((New-Object System.Windows.RoutedEventArgs ([System.Windows.Controls.MenuItem]::ClickEvent)))
            }
        } catch { [System.Windows.MessageBox]::Show($w, "MTU probe failed:`n$_", 'Error', 'OK', 'Error') | Out-Null }
    }.GetNewClosure())
    $w.FindName('CopyBtn').Add_Click({
        $sample = Sample-RetransRatio
        # Use _SafeStat so format strings always get a real number, never $null (which would blank the output)
        $avgRate  = _SafeStat $script:State.RetransHistory      'Average'
        $peakRate = _SafeStat $script:State.RetransHistory      'Maximum'
        $avgRatio = _SafeStat $script:State.RetransRatioHistory 'Average'
        $sampleCount = if ($script:State.RetransRatioHistory) { $script:State.RetransRatioHistory.Count } else { 0 }
        $cumV = Get-RetransVerdict -RatioPct $sample.CumRatio
        $winV = Get-RetransVerdict -RatioPct $avgRatio
        $sb = New-Object System.Text.StringBuilder
        [void]$sb.AppendLine("RETRANSMIT INVESTIGATOR REPORT  ({0})" -f (Get-Date -Format 'yyyy-MM-dd HH:mm:ss'))
        [void]$sb.AppendLine('=' * 70)
        [void]$sb.AppendLine('CUMULATIVE since boot:')
        [void]$sb.AppendLine(('  Sent:           {0:N0}' -f $sample.CumSent))
        [void]$sb.AppendLine(('  Retransmitted:  {0:N0}' -f $sample.CumResent))
        [void]$sb.AppendLine(('  Ratio:          {0:N3}%   ({1})' -f $sample.CumRatio, $cumV.Label))
        [void]$sb.AppendLine('')
        [void]$sb.AppendLine('LAST 60 SECONDS rolling:')
        if ($sampleCount -lt 1) {
            [void]$sb.AppendLine('  (no samples yet - dashboard just started or RetransRatioHistory is empty)')
        } else {
            [void]$sb.AppendLine(('  Avg rate:       {0:N1}/s' -f $avgRate))
            [void]$sb.AppendLine(('  Peak rate:      {0:N1}/s' -f $peakRate))
            [void]$sb.AppendLine(('  Avg ratio:      {0:N3}%   ({1})' -f $avgRatio, $winV.Label))
            [void]$sb.AppendLine(('  Samples:        {0}' -f $sampleCount))
        }
        Invoke-CopyToClipboard $sb.ToString()
    }.GetNewClosure())
    $w.FindName('CloseBtn').Add_Click({ $w.Close() }.GetNewClosure())

    $w.Add_Loaded({ _RefreshInvestigator }.GetNewClosure())
    $w.ShowDialog() | Out-Null
}

function Show-EventsLogDialog {
    [xml]$x = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="NetJump Events Log" Width="900" Height="640" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BrushWindowBg}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Segoe UI">
  <Grid Margin="14">
    <Grid.RowDefinitions>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="*"/>
      <RowDefinition Height="Auto"/>
    </Grid.RowDefinitions>
    <TextBlock Grid.Row="0" Text="EVENTS LOG" Foreground="#58a6ff" FontSize="11" FontWeight="Bold" Margin="0,0,0,4"/>
    <Grid Grid.Row="1" Margin="0,0,0,8">
      <Grid.ColumnDefinitions>
        <ColumnDefinition Width="*"/>
        <ColumnDefinition Width="Auto"/>
      </Grid.ColumnDefinitions>
      <Border Grid.Column="0" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="8,4">
        <Grid>
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="*"/>
          </Grid.ColumnDefinitions>
          <TextBlock Grid.Column="0" Text="🔍" FontSize="12" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center" Margin="0,0,6,0"/>
          <TextBox Grid.Column="1" x:Name="EvFilterBox" BorderThickness="0" Background="Transparent" Foreground="{DynamicResource BrushFgPrimary}" CaretBrush="#58a6ff" FontSize="12" VerticalAlignment="Center" ToolTip="Filter events by text"/>
        </Grid>
      </Border>
      <TextBlock Grid.Column="1" x:Name="EvCountText" Text="" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" VerticalAlignment="Center" Margin="12,0,0,0"/>
    </Grid>
    <Border Grid.Row="2" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="4">
      <ScrollViewer x:Name="EvScroller" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Disabled" CanContentScroll="True">
        <ItemsControl x:Name="EvList"
                      VirtualizingStackPanel.IsVirtualizing="True"
                      VirtualizingStackPanel.VirtualizationMode="Recycling"
                      VirtualizingStackPanel.ScrollUnit="Pixel">
          <ItemsControl.ItemsPanel>
            <ItemsPanelTemplate>
              <VirtualizingStackPanel/>
            </ItemsPanelTemplate>
          </ItemsControl.ItemsPanel>
          <ItemsControl.ItemTemplate>
            <DataTemplate>
              <Grid Margin="10,4">
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="64"/>
                  <ColumnDefinition Width="*"/>
                </Grid.ColumnDefinitions>
                <TextBlock Grid.Column="0" Text="{Binding Time}" Foreground="{Binding Color}" FontFamily="Consolas" FontSize="11" VerticalAlignment="Top"/>
                <TextBlock Grid.Column="1" Text="{Binding Text}" Foreground="{DynamicResource BrushFgPrimary}" FontSize="12" TextWrapping="Wrap" Margin="8,0,0,0"/>
              </Grid>
            </DataTemplate>
          </ItemsControl.ItemTemplate>
        </ItemsControl>
      </ScrollViewer>
    </Border>
    <StackPanel Grid.Row="3" Orientation="Horizontal" HorizontalAlignment="Right" Margin="0,12,0,0">
      <Button x:Name="EvCopyBtn"  Content="Copy all" Padding="10,5" Margin="0,0,8,0" Background="{DynamicResource BrushBorder}" Foreground="{DynamicResource BrushFgPrimary}" BorderBrush="{DynamicResource BrushHoverBg}"/>
      <Button x:Name="EvSaveBtn"  Content="Save to file..." Padding="10,5" Margin="0,0,8,0" Background="{DynamicResource BrushBorder}" Foreground="{DynamicResource BrushFgPrimary}" BorderBrush="{DynamicResource BrushHoverBg}"/>
      <Button x:Name="EvCloseBtn" Content="Close" Padding="14,5" Background="#1f6feb" Foreground="#ffffff" BorderBrush="#2f7fff"/>
    </StackPanel>
  </Grid>
</Window>
'@
    $rdr = New-Object System.Xml.XmlNodeReader $x
    $w = [Windows.Markup.XamlReader]::Load($rdr)
    if ($window) { $w.Owner = $window }
    Wire-DialogEscClose $w   # Tier 55: ESC closes the dialog
    Apply-ThemeToChild $w

    $list = $w.FindName('EvList')
    $filterBox = $w.FindName('EvFilterBox')
    $countText = $w.FindName('EvCountText')
    $scroller = $w.FindName('EvScroller')

    # When filter is empty: bind DIRECTLY to $script:Events (the ObservableCollection) so the
    # dialog updates live as new events come in. When filter is non-empty: use a snapshot
    # filtered Where clause (won't auto-refresh, but the user is actively searching).
    $applyFilter = {
        try {
            $f = ([string]$filterBox.Text).Trim().ToLower()
            if (-not $f) {
                $list.ItemsSource = $script:Events
                $countText.Text = if (@($script:Events).Count -eq 0) {
                    'No events yet. Click RUN NET DIAGNOSTIC or use any tool to generate events.'
                } else {
                    ("{0} events (live)" -f @($script:Events).Count)
                }
            } else {
                $filtered = @($script:Events | Where-Object { ([string]$_.Text).ToLower().Contains($f) -or ([string]$_.Time).Contains($f) })
                $list.ItemsSource = $filtered
                $countText.Text = ("{0} of {1} events match '$f'" -f $filtered.Count, @($script:Events).Count)
            }
            try { $scroller.ScrollToBottom() } catch {}
        } catch {
            $countText.Text = "Filter error: $($_.Exception.Message)"
        }
    }.GetNewClosure()

    & $applyFilter
    $filterBox.Add_TextChanged({ & $applyFilter }.GetNewClosure())

    $w.FindName('EvCopyBtn').Add_Click({
        $text = ($script:Events | ForEach-Object { "[$($_.Time)] $($_.Text)" }) -join "`r`n"
        try {
            Set-Clipboard -Value $text
            $countText.Text = "Copied $($script:Events.Count) events to clipboard."
        } catch {
            [System.Windows.MessageBox]::Show($w, "Copy failed: $_", 'Error', 'OK', 'Error') | Out-Null
        }
    }.GetNewClosure())

    $w.FindName('EvSaveBtn').Add_Click({
        $reportsDir = Join-Path $PSScriptRoot 'Reports'
        if (-not (Test-Path $reportsDir)) { New-Item -ItemType Directory -Path $reportsDir | Out-Null }
        $path = Join-Path $reportsDir ("events-{0}.log" -f (Get-Date -Format 'yyyyMMdd-HHmmss'))
        try {
            $lines = $script:Events | ForEach-Object { "[$($_.Time)] $($_.Text)" }
            Set-Content -LiteralPath $path -Value $lines -Encoding UTF8 -ErrorAction Stop
            $countText.Text = "Saved to $(Split-Path $path -Leaf)"
            try { Add-Event info ("Events log saved: {0}" -f (Split-Path $path -Leaf)) } catch {}
        } catch {
            [System.Windows.MessageBox]::Show($w, "Save failed:`n$_", 'Error', 'OK', 'Error') | Out-Null
        }
    }.GetNewClosure())

    $w.FindName('EvCloseBtn').Add_Click({ $w.Close() })
    $w.ShowDialog() | Out-Null
}

function Show-ProcessTree {
    if (-not $script:Procs -or $script:Procs.Count -eq 0) {
        [System.Windows.MessageBox]::Show($window, 'Run a process scan first (PROCESSES tab -> Refresh).', 'No data', 'OK', 'Information') | Out-Null
        return
    }
    [xml]$x = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="NetJump - Process Tree" Width="900" Height="640" WindowStartupLocation="CenterOwner"
        Background="{DynamicResource BrushWindowBg}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Segoe UI">
    <Grid Margin="16">
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>
        <TextBlock Grid.Row="0" x:Name="ProcTreeHeader" Text="Process -> Remote endpoints" FontSize="13" FontWeight="SemiBold" Foreground="#58a6ff" Margin="0,0,0,12"/>
        <ScrollViewer Grid.Row="1" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Auto">
            <ItemsControl x:Name="ProcTreeList">
                <ItemsControl.ItemTemplate>
                    <DataTemplate>
                        <Border Background="{DynamicResource BrushCardBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="12,10" Margin="0,0,0,8">
                            <StackPanel>
                                <StackPanel Orientation="Horizontal">
                                    <Border Background="{Binding RiskColor}" CornerRadius="3" Padding="6,2" VerticalAlignment="Center" MinWidth="44">
                                        <TextBlock Text="{Binding Risk}" Foreground="White" FontWeight="Bold" FontSize="10" HorizontalAlignment="Center"/>
                                    </Border>
                                    <TextBlock Text="{Binding Name}" FontWeight="SemiBold" Foreground="{DynamicResource BrushFgPrimary}" Margin="10,0,8,0" VerticalAlignment="Center"/>
                                    <TextBlock Text="{Binding PidLabel}" Foreground="{DynamicResource BrushFgFaint}" FontSize="11" VerticalAlignment="Center"/>
                                    <TextBlock Text="{Binding ConnLabel}" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="10,0,0,0" VerticalAlignment="Center"/>
                                </StackPanel>
                                <TextBlock Text="{Binding Path}" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="0,4,0,2"/>
                                <ItemsControl ItemsSource="{Binding Remotes}" Margin="20,4,0,0">
                                    <ItemsControl.ItemTemplate>
                                        <DataTemplate>
                                            <StackPanel Orientation="Horizontal" Margin="0,2,0,0">
                                                <TextBlock Text="-->" Foreground="{DynamicResource BrushFgFaint}" FontSize="11" VerticalAlignment="Center" Margin="0,0,6,0"/>
                                                <TextBlock Text="{Binding Endpoint}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="12" VerticalAlignment="Center"/>
                                                <Border Background="#3a1f5c" BorderBrush="#bf6dff" BorderThickness="1" CornerRadius="3" Padding="5,1" Margin="8,0,0,0" Visibility="{Binding LabelVisibility}">
                                                    <TextBlock Text="{Binding Label}" Foreground="#bf6dff" FontSize="10" FontWeight="SemiBold"/>
                                                </Border>
                                            </StackPanel>
                                        </DataTemplate>
                                    </ItemsControl.ItemTemplate>
                                </ItemsControl>
                            </StackPanel>
                        </Border>
                    </DataTemplate>
                </ItemsControl.ItemTemplate>
            </ItemsControl>
        </ScrollViewer>
        <Button Grid.Row="2" x:Name="CloseBtn" Content="Close" Padding="14,5" HorizontalAlignment="Right" Margin="0,12,0,0" Background="{DynamicResource BrushBorder}" Foreground="{DynamicResource BrushFgPrimary}" BorderBrush="{DynamicResource BrushHoverBg}"/>
    </Grid>
</Window>
'@
    $rdr = New-Object System.Xml.XmlNodeReader $x
    $w = [Windows.Markup.XamlReader]::Load($rdr)
    $w.Owner = $window
    Wire-DialogEscClose $w   # Tier 55: ESC closes the dialog
    Apply-ThemeToChild $w

    # Build tree data: each process gets a Remotes list parsed from RemoteSummary
    $tree = @($script:Procs | ForEach-Object {
        $remotes = New-Object System.Collections.ArrayList
        if ($_.RemoteSummary -and $_.RemoteSummary -ne 'No external connections') {
            $rs = $_.RemoteSummary -replace '^Remote:\s*', ''
            $rs = $rs -replace '\s*\(\+\d+ more\)\s*$', ''
            foreach ($entry in ($rs -split ',\s*')) {
                if (-not $entry.Trim()) { continue }
                $endpoint = $entry; $label = ''
                if ($entry -match '^(\S+:\d+)\s*\[([^\]]+)\]') { $endpoint = $matches[1]; $label = $matches[2] }
                [void]$remotes.Add([pscustomobject]@{
                    Endpoint = $endpoint
                    Label    = $label
                    LabelVisibility = if ($label) { 'Visible' } else { 'Collapsed' }
                })
            }
        }
        [pscustomobject]@{
            Risk      = $_.Risk
            RiskColor = $_.RiskColor
            Name      = $_.Name
            PidLabel  = $_.PidLabel
            ConnLabel = $_.ConnLabel
            Path      = $_.Path
            Remotes   = $remotes
        }
    })
    $list = $w.FindName('ProcTreeList')
    $list.ItemsSource = $tree
    $w.FindName('ProcTreeHeader').Text = "Process -> Remote endpoints  ({0} processes, {1} have external connections)" -f $tree.Count, @($tree | Where-Object { $_.Remotes.Count -gt 0 }).Count
    $w.FindName('CloseBtn').Add_Click({ $w.Close() })
    $w.ShowDialog() | Out-Null
}

function Invoke-DisablePersistenceAction {
    param($Item)   # pscustomobject from $script:PersistItems with Source/Name/Command
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, 'Disabling persistence requires Administrator.', 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    $src = $Item.Source; $name = $Item.Name; $cmd = $Item.Command
    $action = $null
    $undo = $null
    switch -Wildcard ($src) {
        'HKLM\Run*'    { $action = "Remove-ItemProperty -Path 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Run' -Name '$name'"; $undo = "Set-ItemProperty -Path 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Run' -Name '$name' -Value '$cmd'" }
        'HKLM\RunOnce*'{ $action = "Remove-ItemProperty -Path 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\RunOnce' -Name '$name'"; $undo = "Set-ItemProperty -Path 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\RunOnce' -Name '$name' -Value '$cmd'" }
        'HKCU\Run*'    { $action = "Remove-ItemProperty -Path 'HKCU:\Software\Microsoft\Windows\CurrentVersion\Run' -Name '$name'"; $undo = "Set-ItemProperty -Path 'HKCU:\Software\Microsoft\Windows\CurrentVersion\Run' -Name '$name' -Value '$cmd'" }
        'HKCU\RunOnce*'{ $action = "Remove-ItemProperty -Path 'HKCU:\Software\Microsoft\Windows\CurrentVersion\RunOnce' -Name '$name'"; $undo = "Set-ItemProperty -Path 'HKCU:\Software\Microsoft\Windows\CurrentVersion\RunOnce' -Name '$name' -Value '$cmd'" }
        'Task'         { $action = "Disable-ScheduledTask -TaskName '$name'"; $undo = "Enable-ScheduledTask -TaskName '$name'" }
        'Service'      { $action = "Set-Service -Name '$name' -StartupType Disabled"; $undo = "Set-Service -Name '$name' -StartupType Automatic" }
        'AppInit_DLLs' { $action = "(see manual)"; $undo = "(re-add the DLL path to AppInit_DLLs)" }
        'IFEO Debugger'{ $action = "(remove HKLM:\...\Image File Execution Options\$name\Debugger)"; $undo = "(re-create with original value)" }
        'COM hijack'   { $action = "(restore original CLSID InprocServer32 default value)"; $undo = "(see audit log for original value)" }
        default        { }
    }
    if (-not $action) {
        [System.Windows.MessageBox]::Show($window, "I don't know how to disable items from source '$src'. Open the registry / Task Scheduler manually.", 'Unsupported', 'OK', 'Warning') | Out-Null
        return
    }
    $msg = "Disable persistence entry?`n`nSource: $src`nName: $name`nCommand: $cmd`n`nWill run:`n  $action`n`nUndo command (saved to action audit log):`n  $undo`n`nProceed?"
    $r = [System.Windows.MessageBox]::Show($window, $msg, 'Disable persistence', 'YesNo', 'Warning')
    if ($r -ne 'Yes') { return }
    try {
        Invoke-Expression $action
        Write-ActionAudit 'disable-persistence' "$src/$name" 'success' @{ command=$cmd; undo=$undo; runCmd=$action }
        Add-Event fix "Disabled: $src / $name"
        Show-Toast -Title 'NetJump: persistence disabled' -Message "$src / $name disabled. Undo command in action audit log." -Icon Info
    } catch {
        Write-ActionAudit 'disable-persistence' "$src/$name" 'failure' "$_"
        Add-Event warn "Disable failed: $_"
        [System.Windows.MessageBox]::Show($window, "Disable failed:`n$_", 'Error', 'OK', 'Error') | Out-Null
    }
}

# ---------- Tier 4: settings persistence ----------
$script:SettingsPath = Join-Path $PSScriptRoot 'Reports\settings.json'
$script:SessionsDir  = Join-Path $PSScriptRoot 'Reports\Sessions'
foreach ($d in (Split-Path $script:SettingsPath -Parent), $script:SessionsDir) {
    if (-not (Test-Path $d)) { New-Item -ItemType Directory -Path $d -Force | Out-Null }
}

function Load-Settings {
    if (Test-Path $script:SettingsPath) {
        try {
            return Get-Content $script:SettingsPath -Raw | ConvertFrom-Json
        } catch {
            # Settings file is corrupt (truncated, malformed JSON, etc). Stash a breadcrumb so the
            # init code can surface it to the events ribbon once $script:Events is available -
            # otherwise saved settings silently fall back to defaults and the user has no idea
            # why their custom feeds / suppressions / target list are gone.
            $script:_LoadSettingsError = "settings.json is corrupt, defaults loaded: $($_.Exception.Message)"
            try { Write-Host "Load-Settings: $script:_LoadSettingsError" } catch {}
        }
    }
    return [pscustomobject]@{
        Version       = 1
        CustomTarget  = ''
        LastAdapter   = ''
    }
}

# Per-session mutex (Local\ prefix - works for any user without SeCreateGlobalPrivilege).
# Wrapped in try/catch in case the runtime denies even the local creation.
try {
    $script:SettingsMutex = New-Object System.Threading.Mutex($false, 'Local\NetJump-Settings-Mutex')
} catch {
    $script:SettingsMutex = $null
    Write-Host "Settings mutex creation failed: $_ (concurrent writes will be unprotected)"
}
function Save-Settings {
    param($Settings)
    if (-not $Settings) { return }
    $acquired = $false
    try {
        # Serialize concurrent callers (theme switch, mute toggle, suppress menu, dialog Saves)
        # so they can't interleave and corrupt settings.json mid-write.
        if ($script:SettingsMutex) {
            try {
                $acquired = $script:SettingsMutex.WaitOne(2000)
            } catch [System.Threading.AbandonedMutexException] {
                # The previous owner crashed without releasing - we still own it now per docs.
                $acquired = $true
            }
        }
        # Depth 8: nested arrays like ThreatIntelFeedList + SuppressedFindings have property objects at depth 3+.
        # Default 2 silently truncates them to literal "@{Name=...}" strings.
        $json = $Settings | ConvertTo-Json -Depth 8
        # Atomic-ish write: write to a temp file first then move into place to avoid partial files
        # if the process is killed mid-write.
        $tmp = "$($script:SettingsPath).tmp"
        Set-Content -LiteralPath $tmp -Value $json -Encoding UTF8 -ErrorAction Stop
        Move-Item -LiteralPath $tmp -Destination $script:SettingsPath -Force -ErrorAction Stop
    } catch {
        # Surface to events ribbon instead of throwing so transient I/O hiccups don't crash callers.
        try { Add-Event warn ("Save-Settings failed: $($_.Exception.Message)") } catch {}
        Write-Host "Save-Settings failed: $_"
    } finally {
        if ($acquired -and $script:SettingsMutex) { try { $script:SettingsMutex.ReleaseMutex() } catch {} }
    }
}

# Tier 50: Set-Setting / Get-Setting unify the 9 inconsistent settings.json call sites that all
# previously did `$s | Add-Member ...; Save-Settings $s` ad-hoc. The helpers load fresh, mutate via
# Add-Member -Force, and persist - all wrapped under the existing mutex via Save-Settings. Use these
# instead of hand-rolling Add-Member/Save-Settings every time a single key needs to change.
#
# Get-Setting returns the value for $Key (or $DefaultValue if missing). Cheap enough to call in a
# Loaded handler - just reads the file once.
function Get-Setting {
    param([string]$Key, $DefaultValue = $null)
    $s = Load-Settings
    if ($s -and ($s.PSObject.Properties.Name -contains $Key)) { return $s.$Key }
    return $DefaultValue
}

# Set-Setting writes a single key. Loads current settings, mutates the named property, saves back.
# Idempotent and safe under the mutex. Pass any JSON-serializable value (string, int, bool, array,
# nested object). For multi-key bulk writes, use Save-Settings directly with a built-up object.
function Set-Setting {
    param(
        [Parameter(Mandatory)] [string]$Key,
        $Value
    )
    try {
        $s = Load-Settings
        if (-not $s) { $s = [pscustomobject]@{ Version = 1 } }
        $s | Add-Member -NotePropertyName $Key -NotePropertyValue $Value -Force
        Save-Settings $s
    } catch {
        try { Add-Event warn ("Set-Setting '$Key' failed: $($_.Exception.Message)") } catch {}
    }
}

# Set-Settings (plural) accepts a hashtable for atomic multi-key writes - loads once, applies all
# changes, saves once. Avoids races where two single-key writes interleave.
function Set-Settings {
    param([hashtable]$Map)
    if (-not $Map -or $Map.Count -eq 0) { return }
    try {
        $s = Load-Settings
        if (-not $s) { $s = [pscustomobject]@{ Version = 1 } }
        foreach ($k in $Map.Keys) {
            $s | Add-Member -NotePropertyName $k -NotePropertyValue $Map[$k] -Force
        }
        Save-Settings $s
    } catch {
        try { Add-Event warn ("Set-Settings bulk write failed: $($_.Exception.Message)") } catch {}
    }
}

# Tier 71: Save-LayoutSnapshot captures the user's current window geometry, splitter positions,
# column widths, retrans-panel state, selected left-tab, and live-event-feed checkbox states into
# settings.json in a single atomic write. Used both by the Closed-handler (auto-save on exit) and
# by the View > Save layout as default menu item (explicit on-demand snapshot). Returns $true on
# success so the caller can show a confirmation. Defensive against missing controls so it can be
# called early during startup or if the layout XAML changes.
function Save-LayoutSnapshot {
    [CmdletBinding()]
    param([switch]$Quiet)
    try {
        if (-not $window) {
            if (-not $Quiet) { try { Add-Event warn 'Save-LayoutSnapshot: window not available' } catch {} }
            return $false
        }
        $isMax = ($window.WindowState -eq 'Maximized')
        $saveLeft   = if ($isMax) { $window.RestoreBounds.Left   } else { $window.Left }
        $saveTop    = if ($isMax) { $window.RestoreBounds.Top    } else { $window.Top }
        $saveWidth  = if ($isMax) { $window.RestoreBounds.Width  } else { $window.ActualWidth }
        $saveHeight = if ($isMax) { $window.RestoreBounds.Height } else { $window.ActualHeight }
        $bag = @{
            WindowState = [pscustomobject]@{
                Left      = [double]$saveLeft
                Top       = [double]$saveTop
                Width     = [double]$saveWidth
                Height    = [double]$saveHeight
                Maximized = [bool]$isMax
            }
        }
        # Live-event-feed checkbox states (only saved if state object exists, which it always does
        # post-startup, but guarded for safety).
        if ($script:State) {
            $bag['EventFeeds'] = [pscustomobject]@{
                Dns         = [bool]$script:State.EventFeedDns
                Flows       = [bool]$script:State.EventFeedFlows
                Traffic     = [bool]$script:State.EventFeedTraffic
                Processes   = [bool]$script:State.EventFeedProcesses
                Persistence = [bool]$script:State.EventFeedPersistence
                System      = [bool]$script:State.EventFeedSystem
            }
        }
        # Splitter positions - row heights (Star + Pixel) AND column widths (Star + Pixel).
        # Tier 75: when GridSplitter is dragged, WPF writes pixel-magnitude star values (e.g.
        # GridLength(316, Star) where 316 is the actual pixel size). To keep the ratio meaningful
        # on restore, we MUST save BOTH sides of each splitter pair: PingCardRow + FindingsRow,
        # ChartRow + SparkBarRow. If only one side is saved, the other defaults to its XAML weight
        # and the restored ratio is wildly skewed (e.g. 316* vs 2* = Row 2 hogs 99% of the screen).
        $sp = [ordered]@{}
        if ($controls) {
            if ($controls.ChartRow      -and $controls.ChartRow.Height.IsStar)      { $sp.ChartRow      = [double]$controls.ChartRow.Height.Value }
            if ($controls.SparkBarRow   -and $controls.SparkBarRow.Height.IsStar)   { $sp.SparkBarRow   = [double]$controls.SparkBarRow.Height.Value }
            if ($controls.PingCardRow   -and $controls.PingCardRow.Height.IsStar)   { $sp.PingCardRow   = [double]$controls.PingCardRow.Height.Value }
            if ($controls.FindingsRow   -and $controls.FindingsRow.Height.IsStar)   { $sp.FindingsRow   = [double]$controls.FindingsRow.Height.Value }
            if ($controls.SplitColLeft  -and $controls.SplitColLeft.Width.IsStar)   { $sp.SplitColLeft  = [double]$controls.SplitColLeft.Width.Value }
            if ($controls.SplitColRight -and $controls.SplitColRight.Width.IsStar)  { $sp.SplitColRight = [double]$controls.SplitColRight.Width.Value }
            if ($controls.LocalInfoCol  -and $controls.LocalInfoCol.ActualWidth -gt 0) {
                $sp.LocalInfoColPx = [double]$controls.LocalInfoCol.ActualWidth
            }
            if ($controls.RetransOffendersBorder) {
                $sp.RetransVisible = ($controls.RetransOffendersBorder.Visibility -eq 'Visible')
                # Tier 76: save BOTH halves of the (RetransRow, LiveEventsRow) splitter pair so
                # the ratio is preserved on restore. Saving only one half hits the same WPF
                # GridSplitter pixel-magnitude-star bug as the main splitter did.
                if ($controls.RetransRow -and $controls.RetransRow.Height.IsStar) {
                    $sp.RetransRowStar = [double]$controls.RetransRow.Height.Value
                }
                if ($controls.LiveEventsRow -and $controls.LiveEventsRow.Height.IsStar) {
                    $sp.LiveEventsRowStar = [double]$controls.LiveEventsRow.Height.Value
                }
            }
        }
        if ($sp.Count -gt 0) { $bag['SplitterPositions'] = [pscustomobject]$sp }
        # Selected left-tab index
        if ($controls -and $controls.LeftTabs -and $controls.LeftTabs.SelectedIndex -ge 0) {
            $bag['SelectedLeftTab'] = [int]$controls.LeftTabs.SelectedIndex
        }
        Set-Settings $bag
        if (-not $Quiet) { try { Add-Event info "Layout snapshot saved (window + $($sp.Count) splitter fields)" } catch {} }
        return $true
    } catch {
        if (-not $Quiet) {
            try { Write-Host "Save-LayoutSnapshot failed: $_" } catch {}
            try { Add-Event warn ("Save-LayoutSnapshot failed: $($_.Exception.Message)") } catch {}
        }
        return $false
    }
}

# Tier 71: Reset-LayoutDefaults wipes only the layout-related keys from settings.json so that the
# next launch falls back to the XAML's hard-coded defaults. Theme, mute, and other prefs survive.
# Takes effect immediately for keys that re-read on demand; window/splitter/column positions take
# effect on the next launch since they're applied in the Loaded handler.
function Reset-LayoutDefaults {
    [CmdletBinding()]
    param()
    try {
        $s = Load-Settings
        if (-not $s) { return $true }   # nothing to reset
        $layoutKeys = @('WindowState','SplitterPositions','SelectedLeftTab','EventFeeds')
        $removed = 0
        foreach ($k in $layoutKeys) {
            if ($s.PSObject.Properties.Name -contains $k) {
                $s.PSObject.Properties.Remove($k)
                $removed++
            }
        }
        if ($removed -gt 0) {
            Save-Settings $s
            try { Add-Event info "Layout settings cleared ($removed keys removed). Restart applies factory defaults." } catch {}
        } else {
            try { Add-Event info 'Layout already at factory defaults (no saved keys to clear).' } catch {}
        }
        return $true
    } catch {
        try { Add-Event warn ("Reset-LayoutDefaults failed: $($_.Exception.Message)") } catch {}
        return $false
    }
}

# ---------- pktmon rolling capture ----------
$script:PktmonReportRoot = Join-Path $PSScriptRoot 'Reports'
$script:PktmonCurrentEtl = Join-Path $script:PktmonReportRoot 'pktmon-current.etl'
$script:FlapsRoot        = Join-Path $script:PktmonReportRoot 'Flaps'
foreach ($d in $script:PktmonReportRoot, $script:FlapsRoot) {
    if (-not (Test-Path $d)) { New-Item -ItemType Directory -Path $d | Out-Null }
}

function Start-PktmonCapture {
    if (-not $script:HasPktmon -or -not $script:IsAdmin) { return $false }
    # ensure clean start (ignore "no session" error if not running)
    & pktmon stop 2>&1 | Out-Null
    Start-Sleep -Milliseconds 200
    if (Test-Path $script:PktmonCurrentEtl) { Remove-Item $script:PktmonCurrentEtl -Force -ErrorAction SilentlyContinue }
    # 50 MB rolling buffer, 128-byte header capture (enough for L2/L3/L4 headers, small files)
    $pargs = @('start','--capture','--pkt-size','128','--file-size','50','--file-name',$script:PktmonCurrentEtl)
    & pktmon @pargs 2>&1 | Out-Null
    if ($LASTEXITCODE -eq 0) { return $true }
    # try alt syntax for older builds
    & pktmon start -c -p 128 -s 50 -f $script:PktmonCurrentEtl 2>&1 | Out-Null
    return ($LASTEXITCODE -eq 0)
}

function Stop-PktmonCapture {
    if (-not $script:HasPktmon -or -not $script:IsAdmin) { return }
    & pktmon stop 2>&1 | Out-Null
}

function Save-FlapDossier {
    param(
        [int]$FlapNumber,
        [string]$Reason = 'link-down'
    )
    $ts = Get-Date -Format 'yyyyMMdd-HHmmss'
    $dossierDir = Join-Path $script:FlapsRoot ("flap-{0:D3}-{1}" -f $FlapNumber, $ts)
    New-Item -ItemType Directory -Path $dossierDir -Force | Out-Null

    $manifest = [ordered]@{
        flapNumber = $FlapNumber
        timestamp  = (Get-Date).ToString('o')
        reason     = $Reason
        adapter    = $null
        files      = @{}
    }

    $a = $script:State.Adapter
    if ($a) {
        $manifest.adapter = @{
            Name        = $a.Name
            Description = $a.InterfaceDescription
            Status      = [string]$a.Status
            LinkSpeed   = $a.LinkSpeed
            DriverDate  = if ($a.DriverDate) { $a.DriverDate.ToString('o') } else { $null }
            DriverVer   = $a.DriverVersionString
        }
    }

    # 1. Stop pktmon and copy ETL
    if ($script:HasPktmon -and $script:IsAdmin) {
        Stop-PktmonCapture
        if (Test-Path $script:PktmonCurrentEtl) {
            $etlOut = Join-Path $dossierDir 'capture.etl'
            try {
                Move-Item $script:PktmonCurrentEtl $etlOut -Force
                $manifest.files.etl = (Split-Path $etlOut -Leaf)
                # convert to text + Wireshark-compatible pcapng in parallel; clean up old jobs first
                Get-Job | Where-Object { $_.State -in 'Completed','Failed','Stopped' } | Remove-Job -ErrorAction SilentlyContinue
                Start-Job -Name "NetJump-etl2txt-$FlapNumber" -ScriptBlock {
                    param($etl,$dir)
                    & pktmon etl2txt $etl --out (Join-Path $dir 'capture.txt') 2>&1 | Out-Null
                } -ArgumentList $etlOut, $dossierDir | Out-Null
                Start-Job -Name "NetJump-etl2pcap-$FlapNumber" -ScriptBlock {
                    param($etl,$dir)
                    & pktmon etl2pcap $etl --out (Join-Path $dir 'capture.pcapng') 2>&1 | Out-Null
                } -ArgumentList $etlOut, $dossierDir | Out-Null
                $manifest.files.txt    = 'capture.txt (generated async)'
                $manifest.files.pcapng = 'capture.pcapng (generated async; open in Wireshark)'
            } catch {
                $manifest.files.etlError = $_.Exception.Message
            }
        }
        # restart capture for next flap
        [void](Start-PktmonCapture)
    } else {
        $manifest.pktmonSkipped = if (-not $script:HasPktmon) { 'pktmon-not-installed' } else { 'not-elevated' }
    }

    # 2. Event log slice (-2 min to now)
    try {
        $since = (Get-Date).AddMinutes(-2)
        $evt = Get-WinEvent -FilterHashtable @{LogName='System'; StartTime=$since} -MaxEvents 100 -ErrorAction SilentlyContinue
        $evtPath = Join-Path $dossierDir 'events.txt'
        ($evt | ForEach-Object {
            "{0}  Lvl={1}  Id={2}  Src={3}`n  {4}`n" -f $_.TimeCreated, $_.LevelDisplayName, $_.Id, $_.ProviderName, ($_.Message -replace "`r?`n",' ')
        }) | Set-Content -Path $evtPath -Encoding UTF8
        $manifest.files.events = 'events.txt'
        $manifest.eventCount = $evt.Count
    } catch {}

    # 3. NIC counter snapshot
    try {
        $stats = Get-NetAdapterStatistics -Name $a.Name -ErrorAction SilentlyContinue
        $stats | Select-Object * | ConvertTo-Json -Depth 4 | Set-Content (Join-Path $dossierDir 'counters.json') -Encoding UTF8
        $manifest.files.counters = 'counters.json'
    } catch {}

    # 4. Process snapshot (top by working set, with paths)
    try {
        $procs = Get-Process | Sort-Object -Property WorkingSet64 -Descending | Select-Object -First 50 Id, ProcessName, @{n='WS_MB';e={[math]::Round($_.WorkingSet64/1MB,1)}}, Path, StartTime
        $procs | Export-Csv -Path (Join-Path $dossierDir 'processes.csv') -NoTypeInformation
        $manifest.files.processes = 'processes.csv'
    } catch {}

    # 5. CPU/mem state
    try {
        $cs = Get-CimInstance Win32_OperatingSystem
        $manifest.system = @{
            FreePhysicalMB  = [int]($cs.FreePhysicalMemory / 1024)
            TotalPhysicalMB = [int]($cs.TotalVisibleMemorySize / 1024)
            UptimeMin       = [int](((Get-Date) - $cs.LastBootUpTime).TotalMinutes)
        }
    } catch {}

    # 6. Manifest
    $manifest | ConvertTo-Json -Depth 6 | Set-Content (Join-Path $dossierDir 'dossier.json') -Encoding UTF8

    # housekeeping: keep only last 50 flap dossiers
    Get-ChildItem $script:FlapsRoot -Directory | Sort-Object LastWriteTime -Descending |
        Select-Object -Skip 50 | Remove-Item -Recurse -Force -ErrorAction SilentlyContinue

    return $dossierDir
}

# ---------- XAML ----------
[xml]$xaml = @'
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="NetJump HUD" Height="900" Width="1280" MinHeight="520" MinWidth="780"
        WindowStartupLocation="CenterScreen"
        Background="{DynamicResource BrushWindowBg}" Foreground="{DynamicResource BrushFgPrimary}"
        FontFamily="Segoe UI">
  <Window.Resources>
    <!-- Theme-aware brush resources. Apply-Theme swaps these via Window.Resources['BrushXxx'] = newBrush.
         These are the DARK-theme defaults baked in at parse time; light theme overrides at runtime. -->
    <SolidColorBrush x:Key="BrushWindowBg"  Color="#0f1420"/>
    <SolidColorBrush x:Key="BrushCardBg"    Color="#1a2030"/>
    <SolidColorBrush x:Key="BrushDeepBg"    Color="#0f1420"/>
    <SolidColorBrush x:Key="BrushBorder"    Color="#2a3142"/>
    <SolidColorBrush x:Key="BrushHoverBg"   Color="#3a4152"/>
    <SolidColorBrush x:Key="BrushFgPrimary" Color="#d7dde6"/>
    <SolidColorBrush x:Key="BrushFgMuted"   Color="#8b95a8"/>
    <SolidColorBrush x:Key="BrushFgFaint"   Color="#6a7380"/>
    <Style TargetType="Border" x:Key="Card">
      <Setter Property="Background" Value="{DynamicResource BrushCardBg}"/>
      <Setter Property="BorderBrush" Value="{DynamicResource BrushBorder}"/>
      <Setter Property="BorderThickness" Value="1"/>
      <Setter Property="CornerRadius" Value="6"/>
      <Setter Property="Padding" Value="10"/>
      <Setter Property="Margin" Value="0,0,0,6"/>
    </Style>
    <Style TargetType="Button">
      <Setter Property="Background" Value="{DynamicResource BrushBorder}"/>
      <Setter Property="Foreground" Value="{DynamicResource BrushFgPrimary}"/>
      <Setter Property="BorderBrush" Value="{DynamicResource BrushHoverBg}"/>
      <Setter Property="BorderThickness" Value="1"/>
      <Setter Property="Padding" Value="14,8"/>
      <Setter Property="Margin" Value="0,0,8,0"/>
      <Setter Property="FontSize" Value="13"/>
      <Setter Property="Cursor" Value="Hand"/>
      <Setter Property="Template">
        <Setter.Value>
          <ControlTemplate TargetType="Button">
            <Border Background="{TemplateBinding Background}"
                    BorderBrush="{TemplateBinding BorderBrush}"
                    BorderThickness="{TemplateBinding BorderThickness}"
                    CornerRadius="6" Padding="{TemplateBinding Padding}">
              <ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/>
            </Border>
            <ControlTemplate.Triggers>
              <Trigger Property="IsMouseOver" Value="True">
                <Setter Property="Background" Value="{DynamicResource BrushHoverBg}"/>
              </Trigger>
              <Trigger Property="IsEnabled" Value="False">
                <Setter Property="Opacity" Value="0.4"/>
              </Trigger>
            </ControlTemplate.Triggers>
          </ControlTemplate>
        </Setter.Value>
      </Setter>
    </Style>
    <Style TargetType="TextBlock" x:Key="Label">
      <Setter Property="Foreground" Value="{DynamicResource BrushFgMuted}"/>
      <Setter Property="FontSize" Value="11"/>
    </Style>
    <Style TargetType="TextBlock" x:Key="Value">
      <Setter Property="Foreground" Value="{DynamicResource BrushFgPrimary}"/>
      <Setter Property="FontSize" Value="18"/>
      <Setter Property="FontWeight" Value="SemiBold"/>
    </Style>
    <!-- dark ComboBox: full ControlTemplate so OS theme can't bleed through -->
    <Style TargetType="ComboBoxItem" x:Key="DarkComboItem">
      <Setter Property="Background" Value="{DynamicResource BrushCardBg}"/>
      <Setter Property="Foreground" Value="{DynamicResource BrushFgPrimary}"/>
      <Setter Property="Padding" Value="10,6"/>
      <Setter Property="Cursor" Value="Hand"/>
      <Setter Property="Template">
        <Setter.Value>
          <ControlTemplate TargetType="ComboBoxItem">
            <Border x:Name="ItemBorder" Background="{TemplateBinding Background}" Padding="{TemplateBinding Padding}">
              <ContentPresenter VerticalAlignment="Center"/>
            </Border>
            <ControlTemplate.Triggers>
              <Trigger Property="IsHighlighted" Value="True">
                <Setter TargetName="ItemBorder" Property="Background" Value="#1f6feb"/>
                <Setter Property="Foreground" Value="#ffffff"/>
              </Trigger>
              <Trigger Property="IsSelected" Value="True">
                <Setter TargetName="ItemBorder" Property="Background" Value="{DynamicResource BrushHoverBg}"/>
              </Trigger>
            </ControlTemplate.Triggers>
          </ControlTemplate>
        </Setter.Value>
      </Setter>
    </Style>

    <Style TargetType="ToggleButton" x:Key="DarkComboToggle">
      <Setter Property="Background" Value="{DynamicResource BrushDeepBg}"/>
      <Setter Property="Foreground" Value="{DynamicResource BrushFgPrimary}"/>
      <Setter Property="BorderBrush" Value="{DynamicResource BrushBorder}"/>
      <Setter Property="BorderThickness" Value="1"/>
      <Setter Property="Cursor" Value="Hand"/>
      <Setter Property="Template">
        <Setter.Value>
          <ControlTemplate TargetType="ToggleButton">
            <Border x:Name="TBorder" Background="{TemplateBinding Background}" BorderBrush="{TemplateBinding BorderBrush}" BorderThickness="{TemplateBinding BorderThickness}" CornerRadius="4">
              <Grid>
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="*"/>
                  <ColumnDefinition Width="22"/>
                </Grid.ColumnDefinitions>
                <ContentPresenter Grid.Column="0" Margin="8,4" VerticalAlignment="Center" HorizontalAlignment="Left"/>
                <Path Grid.Column="1" x:Name="Arrow" HorizontalAlignment="Center" VerticalAlignment="Center" Fill="{DynamicResource BrushFgMuted}" Data="M 0 0 L 4 4 L 8 0 Z"/>
              </Grid>
            </Border>
            <ControlTemplate.Triggers>
              <Trigger Property="IsMouseOver" Value="True">
                <Setter TargetName="TBorder" Property="Background" Value="{DynamicResource BrushCardBg}"/>
                <Setter TargetName="TBorder" Property="BorderBrush" Value="#58a6ff"/>
                <Setter TargetName="Arrow" Property="Fill" Value="#58a6ff"/>
              </Trigger>
              <Trigger Property="IsChecked" Value="True">
                <Setter TargetName="TBorder" Property="BorderBrush" Value="#58a6ff"/>
              </Trigger>
            </ControlTemplate.Triggers>
          </ControlTemplate>
        </Setter.Value>
      </Setter>
    </Style>

    <Style TargetType="ComboBox" x:Key="DarkCombo">
      <Setter Property="Background" Value="{DynamicResource BrushDeepBg}"/>
      <Setter Property="Foreground" Value="{DynamicResource BrushFgPrimary}"/>
      <Setter Property="BorderBrush" Value="{DynamicResource BrushBorder}"/>
      <Setter Property="BorderThickness" Value="1"/>
      <Setter Property="Padding" Value="8,4"/>
      <Setter Property="FontSize" Value="13"/>
      <Setter Property="Cursor" Value="Hand"/>
      <Setter Property="HorizontalContentAlignment" Value="Left"/>
      <Setter Property="VerticalContentAlignment" Value="Center"/>
      <Setter Property="ItemContainerStyle" Value="{StaticResource DarkComboItem}"/>
      <Setter Property="Template">
        <Setter.Value>
          <ControlTemplate TargetType="ComboBox">
            <!-- ToggleButton fills the box; ContentPresenter is a sibling overlay so it can bind text foreground correctly -->
            <Grid>
              <ToggleButton x:Name="ToggleBtn" Style="{StaticResource DarkComboToggle}"
                            Background="{TemplateBinding Background}" Foreground="{TemplateBinding Foreground}"
                            BorderBrush="{TemplateBinding BorderBrush}" BorderThickness="{TemplateBinding BorderThickness}"
                            IsChecked="{Binding IsDropDownOpen, RelativeSource={RelativeSource TemplatedParent}, Mode=TwoWay}"
                            Focusable="False"/>
              <ContentPresenter IsHitTestVisible="False"
                                Content="{TemplateBinding SelectionBoxItem}"
                                ContentTemplate="{TemplateBinding SelectionBoxItemTemplate}"
                                ContentStringFormat="{TemplateBinding SelectionBoxItemStringFormat}"
                                Margin="10,0,28,0"
                                VerticalAlignment="Center" HorizontalAlignment="Left"
                                TextElement.Foreground="{TemplateBinding Foreground}"
                                TextElement.FontFamily="{TemplateBinding FontFamily}"
                                TextElement.FontSize="{TemplateBinding FontSize}"
                                TextElement.FontWeight="{TemplateBinding FontWeight}"
                                TextBlock.Foreground="{TemplateBinding Foreground}"
                                TextBlock.FontFamily="{TemplateBinding FontFamily}"
                                TextBlock.FontSize="{TemplateBinding FontSize}"
                                TextBlock.FontWeight="{TemplateBinding FontWeight}"/>
              <Popup IsOpen="{TemplateBinding IsDropDownOpen}" Placement="Bottom" AllowsTransparency="True" Focusable="False" PopupAnimation="Slide">
                <Border Background="{DynamicResource BrushCardBg}" BorderBrush="#58a6ff" BorderThickness="1" CornerRadius="4" MinWidth="{TemplateBinding ActualWidth}" SnapsToDevicePixels="True">
                  <ScrollViewer MaxHeight="320" VerticalScrollBarVisibility="Auto">
                    <ItemsPresenter/>
                  </ScrollViewer>
                </Border>
              </Popup>
            </Grid>
          </ControlTemplate>
        </Setter.Value>
      </Setter>
    </Style>
    <Style TargetType="TextBox" x:Key="DarkTextBox">
      <Setter Property="Background" Value="{DynamicResource BrushDeepBg}"/>
      <Setter Property="Foreground" Value="{DynamicResource BrushFgPrimary}"/>
      <Setter Property="BorderBrush" Value="{DynamicResource BrushBorder}"/>
      <Setter Property="BorderThickness" Value="1"/>
      <Setter Property="Padding" Value="6,3"/>
      <Setter Property="CaretBrush" Value="#58a6ff"/>
      <Setter Property="FontSize" Value="12"/>
    </Style>
    <!-- dark dropdown menus: full template kills WPF default left icon-strip / 3D bevel -->
    <Style TargetType="ContextMenu">
      <Setter Property="Background" Value="{DynamicResource BrushCardBg}"/>
      <Setter Property="BorderBrush" Value="{DynamicResource BrushBorder}"/>
      <Setter Property="BorderThickness" Value="1"/>
      <Setter Property="Foreground" Value="{DynamicResource BrushFgPrimary}"/>
      <Setter Property="HasDropShadow" Value="True"/>
      <Setter Property="SnapsToDevicePixels" Value="True"/>
      <Setter Property="OverridesDefaultStyle" Value="True"/>
      <Setter Property="Template">
        <Setter.Value>
          <ControlTemplate TargetType="ContextMenu">
            <Border Background="{TemplateBinding Background}"
                    BorderBrush="{TemplateBinding BorderBrush}"
                    BorderThickness="{TemplateBinding BorderThickness}"
                    Padding="2"
                    SnapsToDevicePixels="True">
              <StackPanel IsItemsHost="True" KeyboardNavigation.DirectionalNavigation="Cycle"/>
            </Border>
          </ControlTemplate>
        </Setter.Value>
      </Setter>
    </Style>
    <Style TargetType="MenuItem">
      <Setter Property="Background" Value="Transparent"/>
      <Setter Property="Foreground" Value="{DynamicResource BrushFgPrimary}"/>
      <Setter Property="FontSize" Value="13"/>
      <Setter Property="Padding" Value="14,8"/>
      <Setter Property="Cursor" Value="Hand"/>
      <Setter Property="OverridesDefaultStyle" Value="True"/>
      <Setter Property="SnapsToDevicePixels" Value="True"/>
      <Setter Property="Template">
        <Setter.Value>
          <ControlTemplate TargetType="MenuItem">
            <Border x:Name="Bd" Background="{TemplateBinding Background}" Padding="{TemplateBinding Padding}" MinWidth="220">
              <Grid>
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="14"/>
                  <ColumnDefinition Width="*"/>
                </Grid.ColumnDefinitions>
                <Path x:Name="Check" Grid.Column="0" Width="10" Height="10" Stretch="Uniform"
                      Data="M 0 5 L 4 9 L 10 1" Stroke="#3fb950" StrokeThickness="2" Visibility="Collapsed" VerticalAlignment="Center"/>
                <ContentPresenter Grid.Column="1" ContentSource="Header" Margin="6,0,0,0" VerticalAlignment="Center"/>
              </Grid>
            </Border>
            <ControlTemplate.Triggers>
              <Trigger Property="IsHighlighted" Value="True">
                <Setter TargetName="Bd" Property="Background" Value="{DynamicResource BrushBorder}"/>
                <Setter Property="Foreground" Value="#58a6ff"/>
              </Trigger>
              <Trigger Property="IsCheckable" Value="True">
                <Setter Property="Padding" Value="2,8,14,8"/>
              </Trigger>
              <Trigger Property="IsChecked" Value="True">
                <Setter TargetName="Check" Property="Visibility" Value="Visible"/>
              </Trigger>
              <Trigger Property="IsEnabled" Value="False">
                <Setter Property="Foreground" Value="{DynamicResource BrushFgFaint}"/>
                <Setter Property="Opacity" Value="0.6"/>
              </Trigger>
            </ControlTemplate.Triggers>
          </ControlTemplate>
        </Setter.Value>
      </Setter>
    </Style>
    <Style TargetType="Separator">
      <Setter Property="Background" Value="{DynamicResource BrushBorder}"/>
      <Setter Property="Height" Value="1"/>
      <Setter Property="Margin" Value="6,4"/>
    </Style>
    <!-- shared finding-row DataTemplate (used by all 5 severity buckets) -->
    <DataTemplate x:Key="FindingItemTemplate">
      <Border BorderThickness="1" CornerRadius="6" Padding="12,10" Margin="0,0,0,6"
              ToolTip="{Binding Tip}" Cursor="Help">
        <Border.ContextMenu>
          <ContextMenu>
            <MenuItem Tag="finding-fix" Header="Apply this fix"/>
            <Separator/>
            <MenuItem Tag="finding-suppress-24h" Header="Suppress for 24 hours"/>
            <MenuItem Tag="finding-suppress-session" Header="Suppress until next launch"/>
            <MenuItem Tag="finding-suppress-permanent" Header="Suppress permanently"/>
            <Separator/>
            <MenuItem Tag="finding-unsuppress" Header="Un-suppress (mute -> active)"/>
            <Separator/>
            <MenuItem Tag="finding-copy" Header="Copy details to clipboard"/>
          </ContextMenu>
        </Border.ContextMenu>
        <Border.Style>
          <Style TargetType="Border">
            <Setter Property="Background" Value="{DynamicResource BrushDeepBg}"/>
            <Setter Property="BorderBrush" Value="{DynamicResource BrushBorder}"/>
            <Style.Triggers>
              <Trigger Property="IsMouseOver" Value="True">
                <Setter Property="Background" Value="{DynamicResource BrushCardBg}"/>
                <Setter Property="BorderBrush" Value="#58a6ff"/>
              </Trigger>
            </Style.Triggers>
          </Style>
        </Border.Style>
        <Border.Resources>
          <Style TargetType="ToolTip">
            <Setter Property="Background" Value="{DynamicResource BrushCardBg}"/>
            <Setter Property="Foreground" Value="{DynamicResource BrushFgPrimary}"/>
            <Setter Property="BorderBrush" Value="#58a6ff"/>
            <Setter Property="BorderThickness" Value="1"/>
            <Setter Property="Padding" Value="10,8"/>
            <Setter Property="MaxWidth" Value="380"/>
          </Style>
        </Border.Resources>
        <Grid>
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="*"/>
          </Grid.ColumnDefinitions>
          <Border Grid.Column="0" Background="{Binding LevelColor}" CornerRadius="3" Padding="6,2" VerticalAlignment="Center" MinWidth="44">
            <TextBlock Text="{Binding Level}" Foreground="White" FontWeight="Bold" FontSize="10" HorizontalAlignment="Center"/>
          </Border>
          <TextBlock Grid.Column="1" Text="{Binding Category}" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="10,0,10,0" VerticalAlignment="Center"/>
          <Border Grid.Column="2" Background="#3a1f5c" BorderBrush="#bf6dff" BorderThickness="1" CornerRadius="3" Padding="5,1" VerticalAlignment="Center" Margin="0,0,6,0" Visibility="{Binding MitreVisibility}">
            <TextBlock Text="{Binding MitreId}" Foreground="#bf6dff" FontSize="10" FontWeight="SemiBold"/>
          </Border>
          <Border Grid.Column="2" Background="#1f3a4a" BorderBrush="#58a6ff" BorderThickness="1" CornerRadius="3" Padding="5,1" VerticalAlignment="Center" Margin="62,0,10,0" Visibility="{Binding NewVisibility}">
            <TextBlock Text="NEW" Foreground="#58a6ff" FontSize="10" FontWeight="Bold"/>
          </Border>
          <StackPanel Grid.Column="3">
            <TextBlock Text="{Binding Message}" Foreground="{DynamicResource BrushFgPrimary}" TextWrapping="Wrap"/>
            <TextBlock Text="{Binding Fix}" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" TextWrapping="Wrap" Margin="0,3,0,0" Visibility="{Binding FixVisibility}"/>
          </StackPanel>
        </Grid>
      </Border>
    </DataTemplate>
    <!-- dark Expander for severity buckets -->
    <Style TargetType="Expander">
      <Setter Property="Background" Value="Transparent"/>
      <Setter Property="Foreground" Value="{DynamicResource BrushFgPrimary}"/>
      <Setter Property="BorderThickness" Value="0"/>
      <Setter Property="Margin" Value="0,0,0,6"/>
      <Setter Property="IsExpanded" Value="True"/>
      <Setter Property="Template">
        <Setter.Value>
          <ControlTemplate TargetType="Expander">
            <StackPanel>
              <ToggleButton x:Name="HeaderSite" IsChecked="{Binding Path=IsExpanded, RelativeSource={RelativeSource TemplatedParent}, Mode=TwoWay}"
                            Background="Transparent" BorderBrush="Transparent" Foreground="{TemplateBinding Foreground}"
                            HorizontalContentAlignment="Stretch" Cursor="Hand" Padding="6,4">
                <ToggleButton.Template>
                  <ControlTemplate TargetType="ToggleButton">
                    <Border Background="{TemplateBinding Background}" Padding="{TemplateBinding Padding}" CornerRadius="4">
                      <DockPanel>
                        <TextBlock x:Name="Chev" Text="v" FontSize="10" FontWeight="Bold" VerticalAlignment="Center" Margin="0,0,8,0" Foreground="{DynamicResource BrushFgMuted}"/>
                        <ContentPresenter VerticalAlignment="Center"/>
                      </DockPanel>
                    </Border>
                    <ControlTemplate.Triggers>
                      <Trigger Property="IsChecked" Value="False">
                        <Setter TargetName="Chev" Property="Text" Value="&gt;"/>
                      </Trigger>
                      <Trigger Property="IsMouseOver" Value="True">
                        <Setter Property="Background" Value="{DynamicResource BrushDeepBg}"/>
                      </Trigger>
                    </ControlTemplate.Triggers>
                  </ControlTemplate>
                </ToggleButton.Template>
                <ContentPresenter ContentSource="Header"/>
              </ToggleButton>
              <ContentPresenter x:Name="ExpandSite" Visibility="Collapsed" Margin="20,4,0,0"/>
            </StackPanel>
            <ControlTemplate.Triggers>
              <Trigger Property="IsExpanded" Value="True">
                <Setter TargetName="ExpandSite" Property="Visibility" Value="Visible"/>
              </Trigger>
            </ControlTemplate.Triggers>
          </ControlTemplate>
        </Setter.Value>
      </Setter>
    </Style>

    <!-- Tier 72: VirtList style turns a plain ItemsControl into a virtualizing one. The original
         pattern in this app was <ScrollViewer><ItemsControl>...</ItemsControl></ScrollViewer> which
         disabled virtualization entirely - the outer ScrollViewer was pixel-scrolled (default),
         and the inner ItemsControl's panel was a plain StackPanel with no virtualization, so every
         row was realized at all times. With 50-300 rows in PROCESSES / TRAFFIC / EVENTS, mouse-move
         hit-testing had to walk the entire visual tree on each frame, which is what caused the hover
         lag the user reported.

         Surgical fix: this style sets the ItemsPanel to a VirtualizingStackPanel and turns on the
         attached virtualization properties. To make it work end-to-end, the WRAPPING ScrollViewer
         must have CanContentScroll="True" so it scrolls in item-units. Recycling reuses container
         instances on scroll instead of allocating fresh ones.

         Result: with 200 rows but only ~15 visible at a time, only ~20 containers (visible + cache
         buffer) are realized. Hit-testing cost drops from O(rows) to O(visible). -->
    <Style x:Key="VirtList" TargetType="ItemsControl">
      <Setter Property="VirtualizingStackPanel.IsVirtualizing" Value="True"/>
      <Setter Property="VirtualizingStackPanel.VirtualizationMode" Value="Recycling"/>
      <Setter Property="VirtualizingStackPanel.ScrollUnit" Value="Pixel"/>
      <Setter Property="VirtualizingPanel.CacheLengthUnit" Value="Page"/>
      <Setter Property="VirtualizingPanel.CacheLength" Value="0.5,0.5"/>
      <Setter Property="ItemsPanel">
        <Setter.Value>
          <ItemsPanelTemplate>
            <VirtualizingStackPanel IsItemsHost="True"/>
          </ItemsPanelTemplate>
        </Setter.Value>
      </Setter>
    </Style>
  </Window.Resources>

  <Grid Margin="16">
    <!-- Top-level rows (every * row participates in splitter drag):
           0 Hero card             (* MinHeight=140 - flexes; ScrollViewer wraps content)
           1 Hero/Ping splitter    (5px - drag to resize Hero vs Ping)
           2 Ping chart card       (* MinHeight=180 - flexes; chart canvas inside also flexes)
           3 Ping/Findings splitter(5px - drag to resize Ping vs Findings/Events)
           4 Findings/Events       (3* MinHeight=200 - flexes)
           5 Action bar            (Auto - fixed)
           6 Kill-switch banner    (Auto, hidden until scan) -->
    <Grid.RowDefinitions>
      <RowDefinition Height="Auto" MinHeight="140" x:Name="HeroRow"/>
      <RowDefinition Height="5"/>
      <!-- Tier 74: PingCardRow MinHeight = 360 by default so the LOCAL NET INFO sidebar (header +
           11 info rows + RESET button group + status line, ~310px content) is fully visible without
           scrolling on first launch. The middle splitter therefore lands right below the RESET row
           by default - the user's "preset screen on loadout" arrangement - and the FINDINGS/EVENTS
           row gets the remaining vertical space. Above this floor the splitter is still freely
           draggable, and a saved layout (Tier 71) can override the default position. -->
      <RowDefinition Height="*" MinHeight="360" x:Name="PingCardRow"/>
      <RowDefinition Height="5"/>
      <!-- Tier 75: x:Name on Row 4 so we can save BOTH sides of the middle splitter pair. Without
           this, only PingCardRow was saved as a star value, but WPF GridSplitter writes
           pixel-magnitude stars (e.g. 316.0*) when dragged, and on restore Row 4 stayed at the
           XAML default 2* - giving Row 2 ~99% of the space and crushing Row 4 to MinHeight. -->
      <RowDefinition Height="2*" MinHeight="200" x:Name="FindingsRow"/>
      <RowDefinition Height="Auto"/>
      <RowDefinition Height="Auto"/>
      <!-- Tier 58: status bar row at the bottom (always visible, ~22px) -->
      <RowDefinition Height="Auto"/>
    </Grid.RowDefinitions>
    <!-- splitter 1: Hero vs Ping chart (drag down to grow Ping, up to grow Hero) -->
    <GridSplitter Grid.Row="1" Height="5" HorizontalAlignment="Stretch" VerticalAlignment="Center"
                  Background="{DynamicResource BrushBorder}" ShowsPreview="False"
                  ResizeBehavior="PreviousAndNext" ResizeDirection="Rows"
                  Cursor="SizeNS" ToolTip="Drag to resize Hero vs Ping chart"/>
    <!-- splitter 2: Ping chart vs Findings/Events -->
    <GridSplitter Grid.Row="3" Height="5" HorizontalAlignment="Stretch" VerticalAlignment="Center"
                  Background="{DynamicResource BrushBorder}" ShowsPreview="False"
                  ResizeBehavior="PreviousAndNext" ResizeDirection="Rows"
                  Cursor="SizeNS" ToolTip="Drag to resize Ping chart vs Findings/Events"/>

    <!-- HERO CARD: SINGLE compact row containing grade + adapter + 6 metric tiles + status dot + RUN.
         Activity ribbon sits below as the only secondary row. Compacted from 3 rows to 2.
         Tiles are inline (between adapter and status dot) so they sit at the same vertical level
         as the grade circle - the metric-tiles row that used to live below has been merged in. -->
    <Border Grid.Row="0" Style="{StaticResource Card}">
      <ScrollViewer VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Disabled" Background="Transparent">
      <Grid>
        <Grid.RowDefinitions>
          <RowDefinition Height="Auto"/>
          <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>

        <!-- Single compact top row: grade | adapter | tiles | status dot | RUN -->
        <Grid Grid.Row="0">
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="Auto"/>   <!-- 0: Grade circle -->
            <ColumnDefinition Width="Auto"/>   <!-- 1: Adapter info column -->
            <ColumnDefinition Width="*"/>      <!-- 2: 6 metric tiles fill remaining space -->
            <ColumnDefinition Width="Auto"/>   <!-- 3: Status dot -->
            <ColumnDefinition Width="Auto"/>   <!-- 4: RUN button -->
          </Grid.ColumnDefinitions>

          <!-- Grade circle - shrunk from 92x92 to 64x64 to fit the inlined tile strip -->
          <Border Grid.Column="0" x:Name="GradeBorder" Width="64" Height="64" CornerRadius="32" Background="#1a4a26" BorderBrush="#3fb950" BorderThickness="2" Margin="0,0,12,0" VerticalAlignment="Center">
            <StackPanel VerticalAlignment="Center" HorizontalAlignment="Center">
              <TextBlock x:Name="HealthGrade" Text="?" FontSize="28" FontWeight="Bold" Foreground="#3fb950" HorizontalAlignment="Center"/>
              <TextBlock x:Name="HealthScore" Text="--" FontSize="9" FontWeight="SemiBold" Foreground="#3fb950" HorizontalAlignment="Center"/>
            </StackPanel>
          </Border>

          <!-- Adapter info: combo + desc + verdict, narrower so tiles get more room -->
          <StackPanel Grid.Column="1" VerticalAlignment="Center" Margin="0,0,12,0" Width="260">
            <ComboBox x:Name="AdapterCombo" Style="{StaticResource DarkCombo}" HorizontalAlignment="Stretch" FontSize="13" FontWeight="Bold">
              <ComboBox.ItemTemplate>
                <DataTemplate>
                  <TextBlock Text="{Binding Name}" Foreground="{DynamicResource BrushFgPrimary}" Padding="2,0" VerticalAlignment="Center"/>
                </DataTemplate>
              </ComboBox.ItemTemplate>
            </ComboBox>
            <TextBlock x:Name="AdapterDesc" Text="..." FontSize="10" Foreground="{DynamicResource BrushFgMuted}" Margin="0,2,0,0" TextTrimming="CharacterEllipsis"/>
            <TextBlock x:Name="HealthVerdict" Text="..." FontSize="11" Foreground="{DynamicResource BrushFgPrimary}" Margin="0,3,0,0" FontWeight="SemiBold" TextTrimming="CharacterEllipsis"/>
          </StackPanel>

          <!-- 6 metric tiles INLINE (Status / Link Speed / Uptime / Flaps / Last Incident / Top Cause) -->
          <Grid Grid.Column="2" VerticalAlignment="Center">
            <Grid.ColumnDefinitions>
              <ColumnDefinition Width="*"/>
              <ColumnDefinition Width="*"/>
              <ColumnDefinition Width="*"/>
              <ColumnDefinition Width="*"/>
              <ColumnDefinition Width="*"/>
              <ColumnDefinition Width="*"/>
            </Grid.ColumnDefinitions>
            <Border Grid.Column="0" Background="{DynamicResource BrushDeepBg}" CornerRadius="4" Padding="8,5" Margin="0,0,3,0">
              <StackPanel>
                <TextBlock Style="{StaticResource Label}" Text="STATUS" FontSize="9"/>
                <TextBlock x:Name="StatusText" Text="--" Foreground="#3fb950" FontSize="13" FontWeight="SemiBold"/>
              </StackPanel>
            </Border>
            <Border Grid.Column="1" Background="{DynamicResource BrushDeepBg}" CornerRadius="4" Padding="8,5" Margin="3,0,3,0">
              <StackPanel>
                <TextBlock Style="{StaticResource Label}" Text="LINK SPEED" FontSize="9"/>
                <TextBlock x:Name="LinkSpeedText" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="13" FontWeight="SemiBold"/>
              </StackPanel>
            </Border>
            <Border Grid.Column="2" Background="{DynamicResource BrushDeepBg}" CornerRadius="4" Padding="8,5" Margin="3,0,3,0">
              <StackPanel>
                <TextBlock Style="{StaticResource Label}" Text="UPTIME" FontSize="9"/>
                <TextBlock x:Name="UptimeText" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="13" FontWeight="SemiBold"/>
              </StackPanel>
            </Border>
            <Border Grid.Column="3" Background="{DynamicResource BrushDeepBg}" CornerRadius="4" Padding="8,5" Margin="3,0,3,0">
              <StackPanel>
                <TextBlock Style="{StaticResource Label}" Text="FLAPS" FontSize="9"/>
                <StackPanel Orientation="Horizontal">
                  <TextBlock x:Name="FlapsText" Text="0" Foreground="{DynamicResource BrushFgPrimary}" FontSize="13" FontWeight="SemiBold"/>
                  <TextBlock x:Name="FlapsTrend" Text="" FontSize="11" FontWeight="Bold" Margin="4,1,0,0" VerticalAlignment="Center" Foreground="{DynamicResource BrushFgMuted}"/>
                </StackPanel>
              </StackPanel>
            </Border>
            <Border Grid.Column="4" Background="{DynamicResource BrushDeepBg}" CornerRadius="4" Padding="8,5" Margin="3,0,3,0">
              <StackPanel>
                <TextBlock Style="{StaticResource Label}" Text="LAST INCIDENT" FontSize="9"/>
                <TextBlock x:Name="LastIncidentText" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontWeight="SemiBold" TextTrimming="CharacterEllipsis"/>
              </StackPanel>
            </Border>
            <Border Grid.Column="5" Background="{DynamicResource BrushDeepBg}" CornerRadius="4" Padding="8,5" Margin="3,0,0,0">
              <StackPanel>
                <TextBlock Style="{StaticResource Label}" Text="TOP CAUSE" FontSize="9"/>
                <TextBlock x:Name="TopCauseText" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontWeight="SemiBold" TextTrimming="CharacterEllipsis" TextWrapping="NoWrap"/>
              </StackPanel>
            </Border>
          </Grid>

          <!-- Status dot (sized down to fit the compact row) -->
          <Grid Grid.Column="3" Width="56" Height="56" Margin="12,0,0,0" VerticalAlignment="Center">
            <Ellipse x:Name="DotGlow" Width="56" Height="56" Fill="#3fb950" Opacity="0.2"/>
            <Ellipse x:Name="Dot"     Width="36" Height="36" Fill="#3fb950" HorizontalAlignment="Center" VerticalAlignment="Center"/>
          </Grid>

          <!-- Tier 78: hero card simplified to just the RUN button. Auto-fix and Layout buttons
               removed - the only fix entry point is now "Apply Fixes" at the bottom of the window
               (next to Open Reports), which opens the picker dialog where the user can selectively
               apply fixes or click AUTO-APPLY ALL SAFE inside the dialog. Layout persistence still
               happens automatically on close via Save-LayoutSnapshot. -->
          <StackPanel Grid.Column="4" Orientation="Horizontal" VerticalAlignment="Center" Margin="12,0,0,0">
            <Button x:Name="RescanButton" Content="▶ RUN NET DIAGNOSTIC" FontWeight="Bold" Padding="14,8" FontSize="12"
                    Background="#3fb950" Foreground="#ffffff" BorderBrush="#5dd370"
                    VerticalAlignment="Center"
                    ToolTip="Run the full network + security diagnostic scan (hardening posture, threat-intel, beaconing, BYOVD, etc.). Review and apply fixes via the 'Apply Fixes' button at the bottom of the window."/>
          </StackPanel>
        </Grid>

        <!-- Activity ribbon (60-min event timeline). Height 28 fits the NOW/60m labels + baseline + event dots. -->
        <Border x:Name="ActivityRibbonBorder" Grid.Row="1" Background="{DynamicResource BrushDeepBg}" CornerRadius="4" Height="28" Margin="0,6,0,0">
          <Canvas x:Name="ActivityCanvas" ClipToBounds="True"/>
        </Border>
      </Grid>
      </ScrollViewer>
    </Border>

    <!-- PING CHART CARD - 3 columns: LOCAL NET INFO sidebar (left, flexes) | column splitter (5px) | chart content (right). Row=2. -->
    <Border Grid.Row="2" Style="{StaticResource Card}">
      <Grid>
        <Grid.ColumnDefinitions>
          <!-- Tier 71: x:Name added so the LocalNetInfo sidebar width is persistable across launches -->
          <ColumnDefinition Width="220" MinWidth="160" MaxWidth="380" x:Name="LocalInfoCol"/>
          <ColumnDefinition Width="5"/>
          <ColumnDefinition Width="*" MinWidth="240"/>
        </Grid.ColumnDefinitions>
        <!-- column splitter: drag horizontally to resize sidebar vs chart -->
        <GridSplitter Grid.Column="1" Width="5" HorizontalAlignment="Stretch" VerticalAlignment="Stretch"
                      Background="{DynamicResource BrushBorder}" ShowsPreview="False"
                      ResizeBehavior="PreviousAndNext" ResizeDirection="Columns"
                      Cursor="SizeWE" ToolTip="Drag to resize Local Net Info sidebar vs ping chart"/>

        <!-- LOCAL NET INFO sidebar (column 0) - Width attr removed; column controls width now.
             Inner StackPanel wrapped in a ScrollViewer so RESET buttons + status row stay reachable
             via vertical scroll if the ping-card is squeezed by the row splitter above it. -->
        <Border Grid.Column="0" x:Name="LocalInfoPanel" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="10,8" Margin="0,0,4,0" VerticalAlignment="Stretch">
          <ScrollViewer x:Name="LocalInfoScroll" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Disabled" Background="Transparent">
          <StackPanel>
            <Grid Margin="0,0,0,6">
              <Grid.ColumnDefinitions>
                <ColumnDefinition Width="*"/>
                <ColumnDefinition Width="Auto"/>
              </Grid.ColumnDefinitions>
              <TextBlock Grid.Column="0" Text="LOCAL NET INFO" Foreground="#58a6ff" FontWeight="Bold" FontSize="10" VerticalAlignment="Center"/>
              <Button Grid.Column="1" x:Name="LocalInfoRefreshBtn" Content="↻" FontSize="10" Padding="4,1" MinWidth="20" ToolTip="Re-read adapter info now"/>
            </Grid>

            <!-- Each row: small label + value column. FontSize 10/11 to fit 220px width. -->
            <Grid Margin="0,2,0,0">
              <Grid.ColumnDefinitions>
                <ColumnDefinition Width="58"/>
                <ColumnDefinition Width="*"/>
              </Grid.ColumnDefinitions>
              <Grid.RowDefinitions>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
              </Grid.RowDefinitions>
              <TextBlock Grid.Row="0" Grid.Column="0" Text="Adapter"  Foreground="{DynamicResource BrushFgMuted}" FontSize="10"/>
              <TextBlock Grid.Row="0" Grid.Column="1" x:Name="LocalAdapterText"  Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" TextTrimming="CharacterEllipsis" ToolTip="Adapter name"/>
              <TextBlock Grid.Row="1" Grid.Column="0" Text="IPv4"     Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,2,0,0"/>
              <TextBlock Grid.Row="1" Grid.Column="1" x:Name="LocalIpv4Text"     Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" Margin="0,2,0,0" ToolTip="Local IPv4 address"/>
              <TextBlock Grid.Row="2" Grid.Column="0" Text="Mask"     Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,2,0,0"/>
              <TextBlock Grid.Row="2" Grid.Column="1" x:Name="LocalMaskText"     Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" Margin="0,2,0,0" ToolTip="Subnet mask / prefix length"/>
              <TextBlock Grid.Row="3" Grid.Column="0" Text="Gateway"  Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,2,0,0"/>
              <TextBlock Grid.Row="3" Grid.Column="1" x:Name="LocalGwText"       Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" Margin="0,2,0,0" ToolTip="Default gateway"/>
              <TextBlock Grid.Row="4" Grid.Column="0" Text="MAC"      Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,2,0,0"/>
              <TextBlock Grid.Row="4" Grid.Column="1" x:Name="LocalMacText"      Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" Margin="0,2,0,0" ToolTip="Hardware MAC address"/>
              <TextBlock Grid.Row="5" Grid.Column="0" Text="DNS"      Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,2,0,0"/>
              <TextBlock Grid.Row="5" Grid.Column="1" x:Name="LocalDnsText"      Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" TextWrapping="Wrap" Margin="0,2,0,0" ToolTip="DNS servers in use"/>
              <TextBlock Grid.Row="6" Grid.Column="0" Text="DHCP"     Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,2,0,0"/>
              <TextBlock Grid.Row="6" Grid.Column="1" x:Name="LocalDhcpText"     Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" Margin="0,2,0,0" ToolTip="DHCP server (or 'static')"/>
              <TextBlock Grid.Row="7" Grid.Column="0" Text="Lease"    Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,2,0,0"/>
              <TextBlock Grid.Row="7" Grid.Column="1" x:Name="LocalLeaseText"    Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" Margin="0,2,0,0" ToolTip="DHCP lease time remaining"/>
              <TextBlock Grid.Row="8" Grid.Column="0" Text="Public"   Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,2,0,0"/>
              <TextBlock Grid.Row="8" Grid.Column="1" x:Name="LocalPublicIpText" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" Margin="0,2,0,0" ToolTip="Public IP as seen externally (resolved on demand)"/>
              <TextBlock Grid.Row="9" Grid.Column="0" Text="MTU"      Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,2,0,0"/>
              <!-- Tier 75: TextWrapping="Wrap" so values like "1500 link  (no path probe yet)" don't get clipped at the column edge -->
              <TextBlock Grid.Row="9" Grid.Column="1" x:Name="LocalMtuText"      Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" TextWrapping="Wrap" Margin="0,2,0,0" ToolTip="Link MTU (NIC interface) and last-probed Path MTU. Click 'Probe path MTU' to update."/>
              <TextBlock Grid.Row="10" Grid.Column="0" Text="MSS"     Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,2,0,0"/>
              <TextBlock Grid.Row="10" Grid.Column="1" x:Name="LocalMssText"     Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" TextWrapping="Wrap" Margin="0,2,0,0" ToolTip="TCP Maximum Segment Size = MTU - 40 (IP header 20 + TCP header 20). The largest single TCP payload on this link without fragmentation."/>
            </Grid>

            <!-- WIFI subgroup. Only visible when the active adapter is wireless (PhysicalMediaType
                 matches Wireless or 802.11). Populated from `netsh wlan show interfaces` via
                 Get-WifiInfo, refreshed on the same cadence as the rest of the sidebar. -->
            <Border x:Name="LocalWifiPanel" Background="{DynamicResource BrushCardBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="4" Padding="6,4" Margin="0,8,0,0" Visibility="Collapsed">
              <StackPanel>
                <TextBlock Text="WIFI" Foreground="#3fb950" FontSize="9" FontWeight="Bold" Margin="0,0,0,3"/>
                <Grid>
                  <Grid.ColumnDefinitions>
                    <ColumnDefinition Width="55"/>
                    <ColumnDefinition Width="*"/>
                  </Grid.ColumnDefinitions>
                  <Grid.RowDefinitions>
                    <RowDefinition Height="Auto"/>
                    <RowDefinition Height="Auto"/>
                    <RowDefinition Height="Auto"/>
                    <RowDefinition Height="Auto"/>
                    <RowDefinition Height="Auto"/>
                  </Grid.RowDefinitions>
                  <TextBlock Grid.Row="0" Grid.Column="0" Text="SSID"    Foreground="{DynamicResource BrushFgMuted}" FontSize="10"/>
                  <TextBlock Grid.Row="0" Grid.Column="1" x:Name="LocalWifiSsidText"   Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" TextTrimming="CharacterEllipsis" ToolTip="Connected network name"/>
                  <TextBlock Grid.Row="1" Grid.Column="0" Text="BSSID"   Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,2,0,0"/>
                  <TextBlock Grid.Row="1" Grid.Column="1" x:Name="LocalWifiBssidText"  Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" Margin="0,2,0,0" ToolTip="Access point MAC. Changes mean you've roamed to a different AP."/>
                  <TextBlock Grid.Row="2" Grid.Column="0" Text="Channel" Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,2,0,0"/>
                  <TextBlock Grid.Row="2" Grid.Column="1" x:Name="LocalWifiChanText"   Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" Margin="0,2,0,0" ToolTip="Channel number + 802.11 radio type (e.g., 36 / 802.11ac)"/>
                  <TextBlock Grid.Row="3" Grid.Column="0" Text="Signal"  Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,2,0,0"/>
                  <TextBlock Grid.Row="3" Grid.Column="1" x:Name="LocalWifiSignalText" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" Margin="0,2,0,0" ToolTip="Signal strength as percentage (rough dBm equivalent in parens). Below -75 dBm/~50% is marginal."/>
                  <TextBlock Grid.Row="4" Grid.Column="0" Text="Auth"    Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,2,0,0"/>
                  <TextBlock Grid.Row="4" Grid.Column="1" x:Name="LocalWifiAuthText"   Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" Margin="0,2,0,0" ToolTip="Authentication + cipher. Open or WEP = unsafe; WPA3-Personal AES-CCMP = current best."/>
                </Grid>
              </StackPanel>
            </Border>

            <!-- Reset row: 5 compact equal-width buttons side by side. Tooltips carry the full
                 explanation since the button labels are abbreviated. RESET column is red text
                 to flag it as the heavy/destructive option. -->
            <Border Background="{DynamicResource BrushCardBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="4" Padding="4,3" Margin="0,8,0,0">
              <StackPanel>
                <TextBlock Text="RESET" Foreground="#d29922" FontSize="9" FontWeight="Bold" Margin="0,0,0,3"/>
                <UniformGrid Rows="1" Columns="5">
                  <Button x:Name="LocalRenewBtn"    Content="DHCP"  FontSize="9" Padding="2,3" Margin="0,0,2,0" ToolTip="Renew DHCP lease (ipconfig /release + /renew). Brief disconnect ~2-5s."/>
                  <Button x:Name="LocalFlushDnsBtn" Content="DNS"   FontSize="9" Padding="2,3" Margin="1,0,1,0" ToolTip="Flush DNS resolver cache (ipconfig /flushdns)."/>
                  <Button x:Name="LocalArpFlushBtn" Content="ARP"   FontSize="9" Padding="2,3" Margin="1,0,1,0" ToolTip="Flush ARP table (netsh interface ip delete arpcache). Forces re-discovery of LAN neighbours."/>
                  <Button x:Name="LocalMtuBtn"      Content="MTU"   FontSize="9" Padding="2,3" Margin="1,0,1,0" ToolTip="Probe path MTU - DF-flagged pings of decreasing size to 1.1.1.1 to find the largest payload that survives the path. Result populates the MTU row above."/>
                  <Button x:Name="LocalResetIpBtn"  Content="STACK" FontSize="9" Padding="2,3" Margin="2,0,0,0" Foreground="#f85149" ToolTip="Reset TCP/IP stack (netsh int ip reset). HEAVY - requires reboot. Confirms first."/>
                </UniformGrid>
              </StackPanel>
            </Border>

            <TextBlock x:Name="LocalInfoStatus" Text="" Foreground="{DynamicResource BrushFgFaint}" FontSize="9" Margin="0,6,0,0" TextWrapping="Wrap"/>
          </StackPanel>
          </ScrollViewer>
        </Border>

        <!-- Chart content (column 2 because column 1 is the sidebar/chart splitter).
             Left margin breathes "LIVE PING" away from the splitter so it isn't flush against the sidebar. -->
        <Grid Grid.Column="2" Margin="8,0,0,0">
        <!-- Tier 38: chart-column rows are now adjustable. Two horizontal GridSplitters let the
             user resize chart vs sparkline-bar. Tier 61: retrans rows removed - the panel moved
             to a new location above LIVE EVENTS.
               Row 0 Auto                  - LIVE PING legend / GW / CF / loss / custom chips
               Row 1 3* MinHeight=80       - Chart canvas (flexes via splitter)
               Row 2 5                     - GridSplitter (chart vs sparkline bar)
               Row 3 0.5* MinHeight=44     - Merged sparkline bar (6 cells) -->
        <Grid.RowDefinitions>
          <RowDefinition Height="Auto"/>
          <RowDefinition Height="3*" MinHeight="80" x:Name="ChartRow"/>
          <RowDefinition Height="5"/>
          <RowDefinition Height="0.5*" MinHeight="44" x:Name="SparkBarRow"/>
        </Grid.RowDefinitions>
        <Grid Grid.Row="0" Margin="0,0,0,8">
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="*"/>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="Auto"/>
            <ColumnDefinition Width="Auto"/>
          </Grid.ColumnDefinitions>
          <!-- LIVE PING legend - wraps gracefully when narrow -->
          <WrapPanel Grid.Column="0" Orientation="Horizontal" VerticalAlignment="Center">
            <TextBlock Text="LIVE PING" Style="{StaticResource Label}" VerticalAlignment="Center" Margin="0,0,12,2"/>
            <StackPanel Orientation="Horizontal" Margin="0,0,16,2" VerticalAlignment="Center">
              <Rectangle Width="10" Height="10" Fill="#58a6ff" Margin="0,0,4,0" VerticalAlignment="Center"/>
              <TextBlock x:Name="GatewayLabel" Text="Gateway" FontSize="11" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center"/>
            </StackPanel>
            <StackPanel Orientation="Horizontal" Margin="0,0,16,2" VerticalAlignment="Center">
              <Rectangle Width="10" Height="10" Fill="#d29922" Margin="0,0,4,0" VerticalAlignment="Center"/>
              <TextBlock Text="1.1.1.1 (Cloudflare)" FontSize="11" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center"/>
            </StackPanel>
            <!-- 4 custom legend chips, each starts collapsed; populated from $script:State.CustomTargets -->
            <StackPanel x:Name="LegendChip0" Orientation="Horizontal" Margin="0,0,16,2" VerticalAlignment="Center" Visibility="Collapsed">
              <Rectangle x:Name="LegendDot0" Width="10" Height="10" Fill="#bf6dff" Margin="0,0,4,0" VerticalAlignment="Center"/>
              <TextBlock x:Name="LegendText0" Text="" FontSize="11" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center"/>
            </StackPanel>
            <StackPanel x:Name="LegendChip1" Orientation="Horizontal" Margin="0,0,16,2" VerticalAlignment="Center" Visibility="Collapsed">
              <Rectangle x:Name="LegendDot1" Width="10" Height="10" Fill="#7ee787" Margin="0,0,4,0" VerticalAlignment="Center"/>
              <TextBlock x:Name="LegendText1" Text="" FontSize="11" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center"/>
            </StackPanel>
            <StackPanel x:Name="LegendChip2" Orientation="Horizontal" Margin="0,0,16,2" VerticalAlignment="Center" Visibility="Collapsed">
              <Rectangle x:Name="LegendDot2" Width="10" Height="10" Fill="#ff9c40" Margin="0,0,4,0" VerticalAlignment="Center"/>
              <TextBlock x:Name="LegendText2" Text="" FontSize="11" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center"/>
            </StackPanel>
            <StackPanel x:Name="LegendChip3" Orientation="Horizontal" Margin="0,0,16,2" VerticalAlignment="Center" Visibility="Collapsed">
              <Rectangle x:Name="LegendDot3" Width="10" Height="10" Fill="#79c0ff" Margin="0,0,4,0" VerticalAlignment="Center"/>
              <TextBlock x:Name="LegendText3" Text="" FontSize="11" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center"/>
            </StackPanel>
            <Button x:Name="ManageTargetsBtn" Content="Targets..." Padding="10,3" FontSize="11" Margin="4,0,0,0" ToolTip="Add up to 4 custom ping targets"/>
          </WrapPanel>
          <StackPanel Grid.Column="1" Margin="16,0,0,0" MinWidth="68">
            <TextBlock Style="{StaticResource Label}" Text="GATEWAY"/>
            <TextBlock x:Name="GwLatencyText" FontSize="14" FontWeight="SemiBold" Text="--"/>
          </StackPanel>
          <StackPanel Grid.Column="2" Margin="16,0,0,0" MinWidth="78">
            <TextBlock Style="{StaticResource Label}" Text="CLOUDFLARE"/>
            <TextBlock x:Name="CfLatencyText" FontSize="14" FontWeight="SemiBold" Text="--"/>
          </StackPanel>
          <StackPanel Grid.Column="3" Margin="16,0,0,0" MinWidth="68">
            <TextBlock Style="{StaticResource Label}" Text="LOSS (60s)"/>
            <TextBlock x:Name="LossText" FontSize="14" FontWeight="SemiBold" Text="0%"/>
          </StackPanel>
          <StackPanel x:Name="CustomLatencyPanel0" Grid.Column="4" Margin="16,0,0,0" MinWidth="64" Visibility="Collapsed">
            <TextBlock x:Name="CustomLatencyLabel0" Style="{StaticResource Label}" Text="CUSTOM"/>
            <TextBlock x:Name="CustomLatencyText0" FontSize="14" FontWeight="SemiBold" Foreground="#bf6dff" Text="--"/>
          </StackPanel>
          <StackPanel x:Name="CustomLatencyPanel1" Grid.Column="5" Margin="16,0,0,0" MinWidth="64" Visibility="Collapsed">
            <TextBlock x:Name="CustomLatencyLabel1" Style="{StaticResource Label}" Text="CUSTOM 2"/>
            <TextBlock x:Name="CustomLatencyText1" FontSize="14" FontWeight="SemiBold" Foreground="#7ee787" Text="--"/>
          </StackPanel>
          <StackPanel x:Name="CustomLatencyPanel2" Grid.Column="6" Margin="16,0,0,0" MinWidth="64" Visibility="Collapsed">
            <TextBlock x:Name="CustomLatencyLabel2" Style="{StaticResource Label}" Text="CUSTOM 3"/>
            <TextBlock x:Name="CustomLatencyText2" FontSize="14" FontWeight="SemiBold" Foreground="#ff9c40" Text="--"/>
          </StackPanel>
          <StackPanel x:Name="CustomLatencyPanel3" Grid.Column="7" Margin="16,0,0,0" MinWidth="64" Visibility="Collapsed">
            <TextBlock x:Name="CustomLatencyLabel3" Style="{StaticResource Label}" Text="CUSTOM 4"/>
            <TextBlock x:Name="CustomLatencyText3" FontSize="14" FontWeight="SemiBold" Foreground="#79c0ff" Text="--"/>
          </StackPanel>
        </Grid>
        <!-- Chart canvas - row is "3*" so it grows with the ping-card height. MinHeight=80 prevents
             the GridSplitter below from collapsing it entirely. -->
        <Border Grid.Row="1" Background="{DynamicResource BrushDeepBg}" CornerRadius="4" MinHeight="80">
          <Canvas x:Name="ChartCanvas" ClipToBounds="True" Background="Transparent"/>
        </Border>

        <!-- Tier 38: GridSplitter row 2 - lets the user drag the boundary between the chart
             canvas (row 1) and the merged sparkline bar (row 3). Both adjacent rows are
             *-weighted so the splitter takes effect. -->
        <GridSplitter Grid.Row="2" Height="5" HorizontalAlignment="Stretch" VerticalAlignment="Center"
                      Background="{DynamicResource BrushBorder}" ShowsPreview="False"
                      ResizeBehavior="PreviousAndNext" ResizeDirection="Rows"
                      Cursor="SizeNS" ToolTip="Drag to resize chart vs sparkline bar"/>

        <!-- Tier 38: MERGED SPARKLINE BAR - 6 equal columns combining the two old sparkline rows
             plus a new MEMORY % cell. Each cell is its own Border so background/corner radius is
             per-cell. VerticalAlignment="Stretch" + MinHeight=36 lets the cells grow when the user
             drags the splitter above to give the sparkline row more vertical space. Cells:
               0: RX ERR/s        red   #f85149
               1: RX DISC/s       amber #d29922
               2: THROUGHPUT      green/blue (RX/TX)
               3: TCP RETRANS/s   purple #bf6dff
               4: MAX-CORE CPU%   green  #7ee787
               5: MEMORY %        teal   #56d4dd  (NEW in Tier 38) -->
        <Grid Grid.Row="3" Margin="0,6,0,0">
          <Grid.ColumnDefinitions>
            <ColumnDefinition Width="*"/>
            <ColumnDefinition Width="*"/>
            <ColumnDefinition Width="1.4*"/>
            <ColumnDefinition Width="*"/>
            <ColumnDefinition Width="*"/>
            <ColumnDefinition Width="*"/>
          </Grid.ColumnDefinitions>
          <!-- Cell 0: RX ERR/s -->
          <Border Grid.Column="0" Background="{DynamicResource BrushDeepBg}" CornerRadius="4" MinHeight="36" Margin="0,0,3,0">
            <Grid>
              <Grid.ColumnDefinitions>
                <ColumnDefinition Width="Auto"/>
                <ColumnDefinition Width="*"/>
              </Grid.ColumnDefinitions>
              <StackPanel Grid.Column="0" Margin="6,0,4,0" VerticalAlignment="Center">
                <TextBlock Style="{StaticResource Label}" Text="RX ERR/s" FontSize="9"/>
                <TextBlock x:Name="RxErrText" Foreground="#f85149" FontSize="11" FontWeight="SemiBold" Text="0"/>
              </StackPanel>
              <Canvas x:Name="RxErrSpark" Grid.Column="1" ClipToBounds="True" Background="Transparent" Margin="0,4"/>
            </Grid>
          </Border>
          <!-- Cell 1: RX DISC/s -->
          <Border Grid.Column="1" Background="{DynamicResource BrushDeepBg}" CornerRadius="4" MinHeight="36" Margin="3,0">
            <Grid>
              <Grid.ColumnDefinitions>
                <ColumnDefinition Width="Auto"/>
                <ColumnDefinition Width="*"/>
              </Grid.ColumnDefinitions>
              <StackPanel Grid.Column="0" Margin="6,0,4,0" VerticalAlignment="Center">
                <TextBlock Style="{StaticResource Label}" Text="RX DISC/s" FontSize="9"/>
                <TextBlock x:Name="RxDiscText" Foreground="#d29922" FontSize="11" FontWeight="SemiBold" Text="0"/>
              </StackPanel>
              <Canvas x:Name="RxDiscSpark" Grid.Column="1" ClipToBounds="True" Background="Transparent" Margin="0,4"/>
            </Grid>
          </Border>
          <!-- Cell 2: THROUGHPUT (1.4* width because it carries two values + dual color legend) -->
          <Border Grid.Column="2" Background="{DynamicResource BrushDeepBg}" CornerRadius="4" MinHeight="36" Margin="3,0">
            <Grid>
              <Grid.ColumnDefinitions>
                <ColumnDefinition Width="Auto"/>
                <ColumnDefinition Width="*"/>
              </Grid.ColumnDefinitions>
              <StackPanel Grid.Column="0" Margin="6,0,4,0" VerticalAlignment="Center">
                <StackPanel Orientation="Horizontal">
                  <TextBlock Style="{StaticResource Label}" Text="XPUT " FontSize="9"/>
                  <Rectangle Width="6" Height="6" Fill="#3fb950" Margin="0,0,2,0" VerticalAlignment="Center"/>
                  <TextBlock Text="RX" FontSize="9" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center"/>
                  <Rectangle Width="6" Height="6" Fill="#58a6ff" Margin="4,0,2,0" VerticalAlignment="Center"/>
                  <TextBlock Text="TX" FontSize="9" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center"/>
                </StackPanel>
                <TextBlock x:Name="ThroughputText" Foreground="{DynamicResource BrushFgPrimary}" FontSize="10" FontWeight="SemiBold" Text="RX 0 / TX 0 B/s"/>
              </StackPanel>
              <Canvas x:Name="ThroughputSpark" Grid.Column="1" ClipToBounds="True" Background="Transparent" Margin="0,4"/>
            </Grid>
          </Border>
          <!-- Cell 3: TCP RETRANS/s (was its own row before; now folded into the bar) -->
          <Border Grid.Column="3" Background="{DynamicResource BrushDeepBg}" CornerRadius="4" MinHeight="36" Margin="3,0">
            <Grid>
              <Grid.ColumnDefinitions>
                <ColumnDefinition Width="Auto"/>
                <ColumnDefinition Width="*"/>
              </Grid.ColumnDefinitions>
              <StackPanel Grid.Column="0" Margin="6,0,4,0" VerticalAlignment="Center">
                <TextBlock Style="{StaticResource Label}" Text="RETRANS/s" FontSize="9"/>
                <TextBlock x:Name="RetransText" Foreground="#bf6dff" FontSize="11" FontWeight="SemiBold" Text="0"/>
              </StackPanel>
              <Canvas x:Name="RetransSpark" Grid.Column="1" ClipToBounds="True" Background="Transparent" Margin="0,4"/>
            </Grid>
          </Border>
          <!-- Cell 4: MAX-CORE CPU% -->
          <Border Grid.Column="4" Background="{DynamicResource BrushDeepBg}" CornerRadius="4" MinHeight="36" Margin="3,0">
            <Grid>
              <Grid.ColumnDefinitions>
                <ColumnDefinition Width="Auto"/>
                <ColumnDefinition Width="*"/>
              </Grid.ColumnDefinitions>
              <StackPanel Grid.Column="0" Margin="6,0,4,0" VerticalAlignment="Center">
                <TextBlock Style="{StaticResource Label}" Text="CPU MAX%" FontSize="9"/>
                <TextBlock x:Name="CpuMaxText" Foreground="#7ee787" FontSize="11" FontWeight="SemiBold" Text="0%"/>
              </StackPanel>
              <Canvas x:Name="CpuMaxSpark" Grid.Column="1" ClipToBounds="True" Background="Transparent" Margin="0,4"/>
            </Grid>
          </Border>
          <!-- Cell 5: MEMORY % (Tier 38 NEW) -->
          <Border Grid.Column="5" Background="{DynamicResource BrushDeepBg}" CornerRadius="4" MinHeight="36" Margin="3,0,0,0"
                  ToolTip="System physical memory usage. Sampled from Win32_OperatingSystem (TotalVisibleMemorySize - FreePhysicalMemory).">
            <Grid>
              <Grid.ColumnDefinitions>
                <ColumnDefinition Width="Auto"/>
                <ColumnDefinition Width="*"/>
              </Grid.ColumnDefinitions>
              <StackPanel Grid.Column="0" Margin="6,0,4,0" VerticalAlignment="Center">
                <TextBlock Style="{StaticResource Label}" Text="MEM %" FontSize="9"/>
                <TextBlock x:Name="MemoryText" Foreground="#56d4dd" FontSize="11" FontWeight="SemiBold" Text="0%"/>
              </StackPanel>
              <Canvas x:Name="MemorySpark" Grid.Column="1" ClipToBounds="True" Background="Transparent" Margin="0,4"/>
            </Grid>
          </Border>
        </Grid>

        <!-- Tier 61: TOP RETRANS SUSPECTS panel + its splitter MOVED OUT of the chart column to
             a new home above the LIVE EVENTS panel (right side of the findings/events split).
             This frees the chart column to focus on actual chart data, and groups the retrans
             suspects with the events feed where retrans warnings ALSO surface as messages. -->
        </Grid>     <!-- /Grid Grid.Column="2" (chart-rows wrapper) -->
      </Grid>       <!-- /Grid outer (col-defs wrapper) -->
    </Border>       <!-- /Border ping chart card -->

    <!-- SPLIT: FINDINGS (LEFT) | [splitter] | EVENTS LOG (RIGHT)  (Row=4 now: 0 hero / 1 splitter / 2 ping / 3 splitter / 4 split / 5 action / 6 killswitch) -->
    <Grid Grid.Row="4">
      <Grid.ColumnDefinitions>
        <ColumnDefinition x:Name="SplitColLeft" Width="3*" MinWidth="320"/>
        <ColumnDefinition Width="6"/>
        <ColumnDefinition x:Name="SplitColRight" Width="2*" MinWidth="200"/>
      </Grid.ColumnDefinitions>
      <!-- draggable splitter - lets user resize findings/events split -->
      <GridSplitter Grid.Column="1" Width="6" HorizontalAlignment="Stretch" VerticalAlignment="Stretch"
                    Background="{DynamicResource BrushBorder}" ShowsPreview="False"
                    ResizeBehavior="PreviousAndNext" ResizeDirection="Columns"
                    Cursor="SizeWE" ToolTip="Drag to resize Diagnostics vs Events log"/>

      <!-- left card: tabbed (Diagnostics / Processes / Persistence / DNS) -->
      <Border Grid.Column="0" Style="{StaticResource Card}" Margin="0,0,3,0" Padding="0">
        <Grid>
        <TabControl x:Name="LeftTabs" Background="Transparent" BorderThickness="0" Padding="0">
          <TabControl.Template>
            <ControlTemplate TargetType="TabControl">
              <Grid Background="{DynamicResource BrushCardBg}">
                <Grid.RowDefinitions>
                  <RowDefinition Height="Auto"/>
                  <RowDefinition Height="*"/>
                </Grid.RowDefinitions>
                <Border Grid.Row="0" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="0,0,0,1">
                  <TabPanel x:Name="HeaderPanel" IsItemsHost="True" Background="Transparent" Margin="0" KeyboardNavigation.TabIndex="1"/>
                </Border>
                <Border Grid.Row="1" Background="{DynamicResource BrushCardBg}">
                  <ContentPresenter x:Name="PART_SelectedContentHost" ContentSource="SelectedContent" Margin="0"/>
                </Border>
              </Grid>
            </ControlTemplate>
          </TabControl.Template>
          <TabControl.Resources>
            <Style TargetType="TabItem">
              <Setter Property="Foreground" Value="{DynamicResource BrushFgMuted}"/>
              <Setter Property="Background" Value="Transparent"/>
              <Setter Property="FontSize" Value="11"/>
              <Setter Property="Cursor" Value="Hand"/>
              <Setter Property="Template">
                <Setter.Value>
                  <ControlTemplate TargetType="TabItem">
                    <Grid>
                      <Grid.RowDefinitions>
                        <RowDefinition Height="*"/>
                        <RowDefinition Height="2"/>
                      </Grid.RowDefinitions>
                      <ContentPresenter Grid.Row="0" ContentSource="Header" Margin="14,10" VerticalAlignment="Center"/>
                      <Rectangle x:Name="Underline" Grid.Row="1" Fill="Transparent"/>
                    </Grid>
                    <ControlTemplate.Triggers>
                      <Trigger Property="IsSelected" Value="True">
                        <Setter Property="Foreground" Value="#58a6ff"/>
                        <Setter TargetName="Underline" Property="Fill" Value="#58a6ff"/>
                      </Trigger>
                      <Trigger Property="IsMouseOver" Value="True">
                        <Setter Property="Foreground" Value="{DynamicResource BrushFgPrimary}"/>
                      </Trigger>
                    </ControlTemplate.Triggers>
                  </ControlTemplate>
                </Setter.Value>
              </Setter>
            </Style>
          </TabControl.Resources>

          <!-- TAB: DIAGNOSTICS (was findings panel) -->
          <TabItem Tag="DIAGNOSTICS">
            <TabItem.Header>
              <StackPanel Orientation="Horizontal">
                <Rectangle Width="6" Height="6" Fill="#6a7380" Margin="0,0,6,0" VerticalAlignment="Center"/>
                <TextBlock Text="DIAGNOSTICS" VerticalAlignment="Center"/>
                <TextBlock Text="" FontWeight="Bold" FontSize="11" Margin="6,0,0,0" VerticalAlignment="Center"/>
              </StackPanel>
            </TabItem.Header>
            <!-- 5 rows: scan status / filter / Causes (resizable) / SPLITTER / Findings (resizable).
                 Causes and Findings each take a *-weighted row so the GridSplitter can drag the boundary.
                 No more MaxHeight clamps — the user controls the split. -->
            <Grid Margin="10">
              <Grid.RowDefinitions>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="*" MinHeight="60"/>
                <RowDefinition Height="5"/>
                <RowDefinition Height="2*" MinHeight="120"/>
              </Grid.RowDefinitions>
              <Grid Grid.Row="0" Margin="0,0,0,6">
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="*"/>
                  <ColumnDefinition Width="Auto"/>
                </Grid.ColumnDefinitions>
                <StackPanel Grid.Column="0" Orientation="Horizontal">
                  <!-- Tier 54: indeterminate ProgressBar paired with ScanStatus. Visible only during
                       an active scan (Visibility=Collapsed by default). Fixed 14px height + 80px
                       width fits inline with the status text without dominating the row. -->
                  <ProgressBar x:Name="ScanProgressBar" Width="80" Height="6" IsIndeterminate="True"
                               Margin="0,0,8,0" VerticalAlignment="Center" Visibility="Collapsed"
                               Background="Transparent" Foreground="#58a6ff" BorderThickness="0"/>
                  <TextBlock x:Name="ScanStatus" Text="" FontSize="11" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center"/>
                </StackPanel>
                <TextBlock x:Name="AdminWarning" Grid.Column="1" Text="" FontSize="11" Foreground="#d29922" VerticalAlignment="Center"/>
              </Grid>

              <!-- TIER 21: filter row (moved above Causes so it's persistently reachable) -->
              <Grid Grid.Row="1" Margin="0,0,0,6">
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="*"/>
                  <ColumnDefinition Width="Auto"/>
                  <ColumnDefinition Width="Auto"/>
                </Grid.ColumnDefinitions>
                <Border Grid.Column="0" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="8,3">
                  <Grid>
                    <Grid.ColumnDefinitions>
                      <ColumnDefinition Width="Auto"/>
                      <ColumnDefinition Width="*"/>
                    </Grid.ColumnDefinitions>
                    <TextBlock Grid.Column="0" Text="🔍" FontSize="12" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center" Margin="0,0,6,0"/>
                    <TextBox Grid.Column="1" x:Name="FilterTextBox" BorderThickness="0" Background="Transparent" Foreground="{DynamicResource BrushFgPrimary}" CaretBrush="{DynamicResource BrushFgPrimary}" FontSize="12" VerticalAlignment="Center" ToolTip="Filter findings by message text"/>
                  </Grid>
                </Border>
                <CheckBox Grid.Column="1" x:Name="HideHealthyCheck" Content="Hide healthy" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" VerticalAlignment="Center" Margin="10,0,0,0" ToolTip="Collapse the HEALTHY bucket and hide passing-check noise"/>
                <StackPanel Grid.Column="2" Orientation="Horizontal" VerticalAlignment="Center" Margin="10,0,0,0">
                  <TextBlock Text="Diff:" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" VerticalAlignment="Center" Margin="0,0,4,0"/>
                  <ComboBox x:Name="DiffModeCombo" Width="92" Padding="4,1" FontSize="11" VerticalAlignment="Center" ToolTip="Filter by what changed since the previous scan. NEW = appeared this scan. RESOLVED = was flagged before but is gone now. CHANGED = both.">
                    <ComboBoxItem Content="All" IsSelected="True" Tag="all"/>
                    <ComboBoxItem Content="NEW only"      Tag="new"/>
                    <ComboBoxItem Content="RESOLVED only" Tag="resolved"/>
                    <ComboBoxItem Content="Changed"       Tag="changed"/>
                  </ComboBox>
                  <TextBlock x:Name="FilterStatus" Text="" Foreground="{DynamicResource BrushFgFaint}" FontSize="10" VerticalAlignment="Center" Margin="10,0,0,0"/>
                </StackPanel>
              </Grid>

              <!-- TIER 5: TOP CAUSES - now fills its allocated Grid.Row instead of capping at 240px.
                   The inner Grid + ScrollViewer Height="*" lets the card scale with the splitter. -->
              <Border Grid.Row="2" x:Name="CausesCard" Background="{DynamicResource BrushCardBg}" BorderBrush="#58a6ff" BorderThickness="1" CornerRadius="6" Padding="10,8">
                <Grid>
                  <Grid.RowDefinitions>
                    <RowDefinition Height="Auto"/>
                    <RowDefinition Height="*"/>
                  </Grid.RowDefinitions>
                  <Grid Grid.Row="0" Margin="0,0,0,6">
                    <Grid.ColumnDefinitions>
                      <ColumnDefinition Width="*"/>
                      <ColumnDefinition Width="Auto"/>
                    </Grid.ColumnDefinitions>
                    <TextBlock Grid.Column="0" Text="TOP LIKELY CAUSES" Foreground="#58a6ff" FontSize="11" FontWeight="Bold" VerticalAlignment="Center"/>
                    <TextBlock x:Name="CausesNote" Grid.Column="1" Text="" Foreground="{DynamicResource BrushFgFaint}" FontSize="10" VerticalAlignment="Center"/>
                  </Grid>
                  <ScrollViewer Grid.Row="1" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Disabled" Background="Transparent" Padding="0,0,4,0">
                    <ItemsControl x:Name="CausesList">
                      <ItemsControl.ItemTemplate>
                        <DataTemplate>
                          <Border Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="10,6" Margin="0,0,0,4">
                            <Grid>
                              <Grid.ColumnDefinitions>
                                <ColumnDefinition Width="Auto"/>
                                <ColumnDefinition Width="*"/>
                                <ColumnDefinition Width="Auto"/>
                              </Grid.ColumnDefinitions>
                              <Border Grid.Column="0" Background="{Binding ColorBrush}" CornerRadius="3" Padding="6,2" VerticalAlignment="Top" MinWidth="34">
                                <TextBlock Text="{Binding ConfidenceLabel}" Foreground="White" FontWeight="Bold" FontSize="11" HorizontalAlignment="Center"/>
                              </Border>
                              <StackPanel Grid.Column="1" Margin="10,0,8,0">
                                <TextBlock Text="{Binding Cause}" Foreground="{DynamicResource BrushFgPrimary}" FontWeight="SemiBold" TextWrapping="Wrap"/>
                                <TextBlock Text="{Binding Evidence}" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" TextWrapping="Wrap" Margin="0,2,0,0"/>
                                <TextBlock Text="{Binding Recommendation}" Foreground="#7ee787" FontSize="11" TextWrapping="Wrap" Margin="0,3,0,0"/>
                              </StackPanel>
                              <Button Grid.Column="2" Tag="cause-fix" Content="Fix" Padding="10,4" FontSize="11" FontWeight="SemiBold"
                                      Background="#1f6feb" Foreground="#ffffff" BorderBrush="#2f7fff"
                                      VerticalAlignment="Top"
                                      ToolTip="Apply any auto-fixable findings related to this cause."/>
                            </Grid>
                          </Border>
                        </DataTemplate>
                      </ItemsControl.ItemTemplate>
                    </ItemsControl>
                  </ScrollViewer>
                </Grid>
              </Border>

              <!-- Vertical splitter between CAUSES and FINDINGS (drag to resize) -->
              <GridSplitter Grid.Row="3" Height="5" HorizontalAlignment="Stretch" VerticalAlignment="Center"
                            Background="{DynamicResource BrushBorder}" ShowsPreview="False"
                            ResizeBehavior="PreviousAndNext" ResizeDirection="Rows"
                            Cursor="SizeNS" Margin="0,0,0,0"
                            ToolTip="Drag to resize Causes vs Findings"/>

              <!-- VerticalScrollBarVisibility=Visible means the scrollbar is ALWAYS drawn so the user has a draggable
                   handle even when nested controls absorb the mouse wheel. Padding right=4 reserves a gutter so the
                   scrollbar isn't visually hidden by content reaching the edge. Focusable=True lets PageUp/Down work. -->
              <ScrollViewer Grid.Row="4" x:Name="DiagScroller" VerticalScrollBarVisibility="Visible" HorizontalScrollBarVisibility="Disabled" Background="Transparent" CanContentScroll="False" Focusable="True" Padding="0,4,4,0">
                <StackPanel>
                  <Expander x:Name="ExpFail" IsExpanded="True">
                    <Expander.Header>
                      <StackPanel Orientation="Horizontal">
                        <Border Background="#f85149" CornerRadius="3" Padding="6,1" VerticalAlignment="Center" MinWidth="30"><TextBlock x:Name="FailCountText" Text="0" Foreground="White" FontWeight="Bold" FontSize="10" HorizontalAlignment="Center"/></Border>
                        <TextBlock Text="CRITICAL" FontWeight="Bold" Foreground="#f85149" FontSize="11" Margin="8,0,0,0" VerticalAlignment="Center"/>
                      </StackPanel>
                    </Expander.Header>
                    <StackPanel>
                      <ItemsControl x:Name="FindingsListFail" ItemTemplate="{StaticResource FindingItemTemplate}"/>
                      <TextBlock x:Name="EmptyFail" Text="✓ No critical issues" Foreground="#3fb950" FontStyle="Italic" FontSize="11" Margin="6,4,6,8" Visibility="Collapsed"/>
                    </StackPanel>
                  </Expander>
                  <Expander x:Name="ExpWarn" IsExpanded="True">
                    <Expander.Header>
                      <StackPanel Orientation="Horizontal">
                        <Border Background="#d29922" CornerRadius="3" Padding="6,1" VerticalAlignment="Center" MinWidth="30"><TextBlock x:Name="WarnCountText" Text="0" Foreground="White" FontWeight="Bold" FontSize="10" HorizontalAlignment="Center"/></Border>
                        <TextBlock Text="WARNINGS" FontWeight="Bold" Foreground="#d29922" FontSize="11" Margin="8,0,0,0" VerticalAlignment="Center"/>
                      </StackPanel>
                    </Expander.Header>
                    <StackPanel>
                      <ItemsControl x:Name="FindingsListWarn" ItemTemplate="{StaticResource FindingItemTemplate}"/>
                      <TextBlock x:Name="EmptyWarn" Text="✓ No warnings" Foreground="#3fb950" FontStyle="Italic" FontSize="11" Margin="6,4,6,8" Visibility="Collapsed"/>
                    </StackPanel>
                  </Expander>
                  <Expander x:Name="ExpInfo" IsExpanded="False">
                    <Expander.Header>
                      <StackPanel Orientation="Horizontal">
                        <Border Background="#58a6ff" CornerRadius="3" Padding="6,1" VerticalAlignment="Center" MinWidth="30"><TextBlock x:Name="InfoCountText" Text="0" Foreground="White" FontWeight="Bold" FontSize="10" HorizontalAlignment="Center"/></Border>
                        <TextBlock Text="INFO" FontWeight="Bold" Foreground="#58a6ff" FontSize="11" Margin="8,0,0,0" VerticalAlignment="Center"/>
                      </StackPanel>
                    </Expander.Header>
                    <StackPanel>
                      <ItemsControl x:Name="FindingsListInfo" ItemTemplate="{StaticResource FindingItemTemplate}"/>
                      <TextBlock x:Name="EmptyInfo" Text="No informational findings" Foreground="{DynamicResource BrushFgFaint}" FontStyle="Italic" FontSize="11" Margin="6,4,6,8" Visibility="Collapsed"/>
                    </StackPanel>
                  </Expander>
                  <Expander x:Name="ExpOk" IsExpanded="False">
                    <Expander.Header>
                      <StackPanel Orientation="Horizontal">
                        <Border Background="#3fb950" CornerRadius="3" Padding="6,1" VerticalAlignment="Center" MinWidth="30"><TextBlock x:Name="OkCountText" Text="0" Foreground="White" FontWeight="Bold" FontSize="10" HorizontalAlignment="Center"/></Border>
                        <TextBlock Text="HEALTHY (passing checks)" FontWeight="Bold" Foreground="#3fb950" FontSize="11" Margin="8,0,0,0" VerticalAlignment="Center"/>
                      </StackPanel>
                    </Expander.Header>
                    <StackPanel>
                      <ItemsControl x:Name="FindingsListOk" ItemTemplate="{StaticResource FindingItemTemplate}"/>
                      <TextBlock x:Name="EmptyOk" Text="No passing checks recorded yet" Foreground="{DynamicResource BrushFgFaint}" FontStyle="Italic" FontSize="11" Margin="6,4,6,8" Visibility="Collapsed"/>
                    </StackPanel>
                  </Expander>
                  <Expander x:Name="ExpMuted" IsExpanded="False" Visibility="Collapsed">
                    <Expander.Header>
                      <StackPanel Orientation="Horizontal">
                        <Border Background="#6e7681" CornerRadius="3" Padding="6,1" VerticalAlignment="Center" MinWidth="30"><TextBlock x:Name="MutedCountText" Text="0" Foreground="White" FontWeight="Bold" FontSize="10" HorizontalAlignment="Center"/></Border>
                        <TextBlock Text="MUTED (suppressed)" FontWeight="Bold" Foreground="#6e7681" FontSize="11" Margin="8,0,0,0" VerticalAlignment="Center"/>
                      </StackPanel>
                    </Expander.Header>
                    <ItemsControl x:Name="FindingsListMuted" ItemTemplate="{StaticResource FindingItemTemplate}"/>
                  </Expander>
                </StackPanel>
              </ScrollViewer>
            </Grid>
          </TabItem>

          <!-- TAB: PROCESSES (network connections w/ signature) -->
          <TabItem Tag="PROCESSES">
            <TabItem.Header>
              <StackPanel Orientation="Horizontal">
                <Rectangle Width="6" Height="6" Fill="#79c0ff" Margin="0,0,6,0" VerticalAlignment="Center"/>
                <TextBlock Text="PROCESSES" VerticalAlignment="Center"/>
                <TextBlock Text="" FontWeight="Bold" FontSize="11" Margin="6,0,0,0" VerticalAlignment="Center"/>
              </StackPanel>
            </TabItem.Header>
            <Grid Margin="16">
              <Grid.RowDefinitions>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="*"/>
              </Grid.RowDefinitions>
              <Grid Grid.Row="0" Margin="0,0,0,12">
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="*"/>
                  <ColumnDefinition Width="Auto"/>
                </Grid.ColumnDefinitions>
                <TextBlock x:Name="ProcStatus" Grid.Column="0" Text="Click 'Refresh' to enumerate network-active processes." FontSize="11" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center"/>
                <Button Grid.Column="1" x:Name="ProcRefreshButton" Content="Refresh" Padding="10,4" FontSize="11"/>
              </Grid>
              <ScrollViewer Grid.Row="1" VerticalScrollBarVisibility="Auto" Background="Transparent" CanContentScroll="True">
                <ItemsControl x:Name="ProcList" Style="{StaticResource VirtList}">
                  <ItemsControl.ItemTemplate>
                    <DataTemplate>
                      <Border Background="{DynamicResource BrushDeepBg}" BorderBrush="#79c0ff" BorderThickness="3,1,1,1" CornerRadius="6" Padding="12,10" Margin="0,0,0,6">
                        <Border.ContextMenu>
                          <ContextMenu>
                            <MenuItem Tag="proc-details" Header="Connection details..." FontWeight="Bold"/>
                            <Separator/>
                            <MenuItem Tag="proc-kill"  Header="Kill process"/>
                            <MenuItem Tag="proc-block" Header="Block remote IP at firewall"/>
                            <Separator/>
                            <MenuItem Tag="proc-open"  Header="Open binary location"/>
                            <MenuItem Tag="proc-copy"  Header="Copy details to clipboard"/>
                          </ContextMenu>
                        </Border.ContextMenu>
                        <Grid>
                          <Grid.ColumnDefinitions>
                            <ColumnDefinition Width="Auto"/>
                            <ColumnDefinition Width="*"/>
                            <ColumnDefinition Width="Auto"/>
                          </Grid.ColumnDefinitions>
                          <Border Grid.Column="0" Background="{Binding RiskColor}" CornerRadius="3" Padding="6,2" VerticalAlignment="Top" MinWidth="44">
                            <TextBlock Text="{Binding Risk}" Foreground="White" FontWeight="Bold" FontSize="10" HorizontalAlignment="Center"/>
                          </Border>
                          <StackPanel Grid.Column="1" Margin="10,0">
                            <StackPanel Orientation="Horizontal">
                              <TextBlock Text="{Binding Name}" FontWeight="SemiBold" Foreground="{DynamicResource BrushFgPrimary}"/>
                              <TextBlock Text="{Binding PidLabel}" Foreground="{DynamicResource BrushFgFaint}" FontSize="11" Margin="6,1,0,0"/>
                              <TextBlock Text="{Binding ConnLabel}" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" Margin="10,1,0,0"/>
                            </StackPanel>
                            <TextBlock Text="{Binding Path}" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" TextWrapping="Wrap" Margin="0,2,0,0"/>
                            <TextBlock Text="{Binding RemoteSummary}" Foreground="{DynamicResource BrushFgFaint}" FontSize="11" TextWrapping="Wrap" Margin="0,2,0,0"/>
                            <StackPanel Orientation="Horizontal" Margin="0,3,0,0" Visibility="{Binding AncestryVisibility}">
                              <TextBlock Text="↳" Foreground="{DynamicResource BrushFgFaint}" FontSize="10" Margin="0,0,4,0"/>
                              <TextBlock Text="{Binding Ancestry}" Foreground="{Binding ChainRiskColor}" FontSize="10" FontFamily="Consolas" TextTrimming="CharacterEllipsis" ToolTip="Process ancestry: parent chain walked via Win32_Process. Red = suspicious chain (e.g. cmd/powershell -> curl/certutil)"/>
                            </StackPanel>
                          </StackPanel>
                          <TextBlock Grid.Column="2" Text="{Binding SignerLabel}" Foreground="{Binding SignerColor}" FontSize="11" VerticalAlignment="Top"/>
                        </Grid>
                      </Border>
                    </DataTemplate>
                  </ItemsControl.ItemTemplate>
                </ItemsControl>
              </ScrollViewer>
            </Grid>
          </TabItem>

          <!-- TAB: TRAFFIC (Tier 25 - protocol breakdown + top talkers) -->
          <TabItem Tag="TRAFFIC">
            <TabItem.Header>
              <StackPanel Orientation="Horizontal">
                <Rectangle Width="6" Height="6" Fill="#d29922" Margin="0,0,6,0" VerticalAlignment="Center"/>
                <TextBlock Text="TRAFFIC" VerticalAlignment="Center"/>
                <TextBlock Text="" FontWeight="Bold" FontSize="11" Margin="6,0,0,0" VerticalAlignment="Center"/>
              </StackPanel>
            </TabItem.Header>
            <Grid Margin="10">
              <Grid.RowDefinitions>
                <RowDefinition Height="Auto"/>   <!-- 0: status line -->
                <RowDefinition Height="Auto"/>   <!-- 1: protocol + direction tiles -->
                <RowDefinition Height="*"/>      <!-- 2: top-talkers list -->
              </Grid.RowDefinitions>
              <!-- Tier 93: Start/Stop button row. Mirrors FLOWS pattern - default paused so user
                   controls when the heavy CIM sampling kicks in. When running, surfaces notable
                   traffic events (new top talker, protocol rate spike) into the LIVE EVENTS feed
                   so the user sees them in the unified log. -->
              <Grid Grid.Row="0" Margin="0,0,0,8">
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="*"/>
                  <ColumnDefinition Width="Auto"/>
                </Grid.ColumnDefinitions>
                <TextBlock Grid.Column="0" x:Name="TrafficStatus" Text="(paused - click Start to begin protocol-rate + top-talker sampling)" FontSize="11" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center"/>
                <Button Grid.Column="1" x:Name="TrafficPauseBtn" Content="▶ Start" Padding="10,4" FontSize="11" FontWeight="Bold" Background="#15803d" Foreground="#ffffff" BorderBrush="#3fb950" ToolTip="Click to begin sampling protocol rates + top talkers (every 2s on heavy tick). Notable events (new top talker, protocol spike) surface to LIVE EVENTS too. Click again to pause."/>
              </Grid>

              <!-- TILES ROW: protocol breakdown (left) + direction tile (right) -->
              <Grid Grid.Row="1" Margin="0,0,0,10">
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="3*"/>
                  <ColumnDefinition Width="2*"/>
                </Grid.ColumnDefinitions>

                <!-- Protocol breakdown card -->
                <Border Grid.Column="0" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="10,8" Margin="0,0,4,0">
                  <StackPanel>
                    <Grid Margin="0,0,0,6">
                      <Grid.ColumnDefinitions>
                        <ColumnDefinition Width="*"/>
                        <ColumnDefinition Width="Auto"/>
                      </Grid.ColumnDefinitions>
                      <TextBlock Grid.Column="0" Text="PROTOCOL BREAKDOWN  (packets/sec)" Foreground="#58a6ff" FontWeight="Bold" FontSize="10"/>
                      <TextBlock Grid.Column="1" x:Name="TrafficTotalRate" Text="--" Foreground="{DynamicResource BrushFgFaint}" FontSize="10"/>
                    </Grid>
                    <!-- Composite proportional bar - 3 wedges sized by % of total -->
                    <Grid Height="10" Margin="0,2,0,4">
                      <Grid.ColumnDefinitions>
                        <ColumnDefinition x:Name="TrafficTcpBar"  Width="1*"/>
                        <ColumnDefinition x:Name="TrafficUdpBar"  Width="0.001*"/>
                        <ColumnDefinition x:Name="TrafficIcmpBar" Width="0.001*"/>
                      </Grid.ColumnDefinitions>
                      <Border Grid.Column="0" Background="#58a6ff"/>
                      <Border Grid.Column="1" Background="#bf6dff"/>
                      <Border Grid.Column="2" Background="#7ee787"/>
                    </Grid>
                    <TextBlock x:Name="TrafficProtoText" Text="" Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,2,0,8"/>
                    <!-- Per-protocol rate rows + sparklines -->
                    <Grid Margin="0,0,0,3">
                      <Grid.ColumnDefinitions>
                        <ColumnDefinition Width="60"/>
                        <ColumnDefinition Width="50"/>
                        <ColumnDefinition Width="*"/>
                      </Grid.ColumnDefinitions>
                      <TextBlock Grid.Column="0" Text="TCP" Foreground="#58a6ff" FontSize="11" FontWeight="Bold" VerticalAlignment="Center"/>
                      <TextBlock Grid.Column="1" x:Name="TrafficTcpRate" Text="0" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" VerticalAlignment="Center"/>
                      <Border Grid.Column="2" Height="16">
                        <Canvas x:Name="TrafficTcpSpark" ClipToBounds="True" Background="Transparent" Margin="0,2"/>
                      </Border>
                    </Grid>
                    <Grid Margin="0,0,0,3">
                      <Grid.ColumnDefinitions>
                        <ColumnDefinition Width="60"/>
                        <ColumnDefinition Width="50"/>
                        <ColumnDefinition Width="*"/>
                      </Grid.ColumnDefinitions>
                      <TextBlock Grid.Column="0" Text="UDP" Foreground="#bf6dff" FontSize="11" FontWeight="Bold" VerticalAlignment="Center"/>
                      <TextBlock Grid.Column="1" x:Name="TrafficUdpRate" Text="0" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" VerticalAlignment="Center"/>
                      <Border Grid.Column="2" Height="16">
                        <Canvas x:Name="TrafficUdpSpark" ClipToBounds="True" Background="Transparent" Margin="0,2"/>
                      </Border>
                    </Grid>
                    <Grid Margin="0,0,0,3">
                      <Grid.ColumnDefinitions>
                        <ColumnDefinition Width="60"/>
                        <ColumnDefinition Width="50"/>
                        <ColumnDefinition Width="*"/>
                      </Grid.ColumnDefinitions>
                      <TextBlock Grid.Column="0" Text="ICMP" Foreground="#7ee787" FontSize="11" FontWeight="Bold" VerticalAlignment="Center"/>
                      <TextBlock Grid.Column="1" x:Name="TrafficIcmpRate" Text="0" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" FontFamily="Consolas" VerticalAlignment="Center"/>
                      <Border Grid.Column="2" Height="16">
                        <Canvas x:Name="TrafficIcmpSpark" ClipToBounds="True" Background="Transparent" Margin="0,2"/>
                      </Border>
                    </Grid>
                  </StackPanel>
                </Border>

                <!-- Direction (RX/TX) tile -->
                <Border Grid.Column="1" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="10,8" Margin="4,0,0,0">
                  <StackPanel>
                    <TextBlock Text="TRAFFIC DIRECTION  (NIC bytes/sec)" Foreground="#58a6ff" FontWeight="Bold" FontSize="10" Margin="0,0,0,6"/>
                    <Grid>
                      <Grid.ColumnDefinitions>
                        <ColumnDefinition Width="*"/>
                        <ColumnDefinition Width="*"/>
                      </Grid.ColumnDefinitions>
                      <StackPanel Grid.Column="0" Margin="0,0,4,0">
                        <TextBlock Text="↓ RX (download)" Foreground="#3fb950" FontSize="10" FontWeight="Bold"/>
                        <TextBlock x:Name="TrafficRxText" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="14" FontWeight="SemiBold" FontFamily="Consolas" Margin="0,2,0,0"/>
                      </StackPanel>
                      <StackPanel Grid.Column="1" Margin="4,0,0,0">
                        <TextBlock Text="↑ TX (upload)" Foreground="#58a6ff" FontSize="10" FontWeight="Bold"/>
                        <TextBlock x:Name="TrafficTxText" Text="--" Foreground="{DynamicResource BrushFgPrimary}" FontSize="14" FontWeight="SemiBold" FontFamily="Consolas" Margin="0,2,0,0"/>
                      </StackPanel>
                    </Grid>
                    <TextBlock x:Name="TrafficDirText" Text="" Foreground="{DynamicResource BrushFgMuted}" FontSize="10" Margin="0,8,0,0"/>
                    <TextBlock Text="(Tip: total NIC bytes - apportions across all processes; per-process net bytes need ETW.)" FontSize="9" Foreground="{DynamicResource BrushFgFaint}" Margin="0,8,0,0" TextWrapping="Wrap"/>
                  </StackPanel>
                </Border>
              </Grid>

              <!-- TOP TALKERS LIST -->
              <Border Grid.Row="2" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="0">
                <Grid>
                  <Grid.RowDefinitions>
                    <RowDefinition Height="Auto"/>
                    <RowDefinition Height="*"/>
                  </Grid.RowDefinitions>
                  <Grid Grid.Row="0" Background="{DynamicResource BrushCardBg}" Margin="0">
                    <Grid.ColumnDefinitions>
                      <ColumnDefinition Width="50"/>
                      <ColumnDefinition Width="*"/>
                      <ColumnDefinition Width="120"/>
                      <ColumnDefinition Width="160"/>
                      <ColumnDefinition Width="170"/>
                    </Grid.ColumnDefinitions>
                    <TextBlock Grid.Column="0" Text="LVL"   FontSize="10" FontWeight="Bold" Foreground="{DynamicResource BrushFgMuted}" Padding="10,6"/>
                    <TextBlock Grid.Column="1" Text="PROCESS"   FontSize="10" FontWeight="Bold" Foreground="{DynamicResource BrushFgMuted}" Padding="0,6"/>
                    <TextBlock Grid.Column="2" Text="I/O B/s"   FontSize="10" FontWeight="Bold" Foreground="{DynamicResource BrushFgMuted}" Padding="0,6"/>
                    <TextBlock Grid.Column="3" Text="CONNECTIONS" FontSize="10" FontWeight="Bold" Foreground="{DynamicResource BrushFgMuted}" Padding="0,6"/>
                    <TextBlock Grid.Column="4" Text="REMOTE (sample)" FontSize="10" FontWeight="Bold" Foreground="{DynamicResource BrushFgMuted}" Padding="0,6,8,6"/>
                  </Grid>
                  <ScrollViewer Grid.Row="1" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Disabled" Padding="0,0,4,0" CanContentScroll="True">
                    <ItemsControl x:Name="TrafficList" Style="{StaticResource VirtList}">
                      <ItemsControl.ItemTemplate>
                        <DataTemplate>
                          <Border BorderThickness="3,0,0,1" BorderBrush="#d29922" Padding="10,6" Margin="0,0,0,1">
                            <Border.ContextMenu>
                              <ContextMenu>
                                <MenuItem Tag="traffic-details" Header="Connection details..." FontWeight="Bold"/>
                                <Separator/>
                                <MenuItem Tag="traffic-tree"   Header="Show process tree..."/>
                                <MenuItem Tag="traffic-kill"   Header="Kill process"/>
                                <MenuItem Tag="traffic-block"  Header="Block primary remote IP at firewall"/>
                                <Separator/>
                                <MenuItem Tag="traffic-open"   Header="Open binary location"/>
                                <MenuItem Tag="traffic-copy"   Header="Copy details to clipboard"/>
                              </ContextMenu>
                            </Border.ContextMenu>
                            <Grid>
                              <Grid.ColumnDefinitions>
                                <ColumnDefinition Width="50"/>
                                <ColumnDefinition Width="*"/>
                                <ColumnDefinition Width="120"/>
                                <ColumnDefinition Width="160"/>
                                <ColumnDefinition Width="170"/>
                              </Grid.ColumnDefinitions>
                              <Border Grid.Column="0" Background="{Binding RiskColor}" CornerRadius="3" Padding="5,1" HorizontalAlignment="Left" VerticalAlignment="Center" MinWidth="34">
                                <TextBlock Text="{Binding Risk}" Foreground="#ffffff" FontSize="9" FontWeight="Bold" HorizontalAlignment="Center"/>
                              </Border>
                              <StackPanel Grid.Column="1">
                                <StackPanel Orientation="Horizontal">
                                  <TextBlock Text="{Binding Name}" Foreground="{DynamicResource BrushFgPrimary}" FontWeight="SemiBold" FontSize="11"/>
                                  <TextBlock Text="(pid " Foreground="{DynamicResource BrushFgFaint}" FontSize="10" Margin="6,1,0,0"/>
                                  <TextBlock Text="{Binding Pid}" Foreground="{DynamicResource BrushFgFaint}" FontSize="10" Margin="0,1,0,0"/>
                                  <TextBlock Text=")" Foreground="{DynamicResource BrushFgFaint}" FontSize="10" Margin="0,1,0,0"/>
                                </StackPanel>
                                <TextBlock Text="{Binding Path}" Foreground="{DynamicResource BrushFgFaint}" FontSize="10" TextWrapping="NoWrap" TextTrimming="CharacterEllipsis"/>
                              </StackPanel>
                              <TextBlock Grid.Column="2" Text="{Binding IoLabel}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" VerticalAlignment="Center"/>
                              <TextBlock Grid.Column="3" Text="{Binding ConnLabel}" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" VerticalAlignment="Center"/>
                              <TextBlock Grid.Column="4" Text="{Binding PrimaryRemote}" Foreground="{DynamicResource BrushFgMuted}" FontFamily="Consolas" FontSize="10" VerticalAlignment="Center" TextTrimming="CharacterEllipsis"/>
                            </Grid>
                          </Border>
                        </DataTemplate>
                      </ItemsControl.ItemTemplate>
                    </ItemsControl>
                  </ScrollViewer>
                </Grid>
              </Border>
            </Grid>
          </TabItem>

          <!-- TAB: FLOWS (Tier 28 - live socket-level event stream NEW/CLOSED/STATE) -->
          <TabItem Tag="FLOWS">
            <TabItem.Header>
              <StackPanel Orientation="Horizontal">
                <Rectangle Width="6" Height="6" Fill="#58a6ff" Margin="0,0,6,0" VerticalAlignment="Center"/>
                <TextBlock Text="FLOWS" VerticalAlignment="Center"/>
                <TextBlock Text="" FontWeight="Bold" FontSize="11" Margin="6,0,0,0" VerticalAlignment="Center"/>
              </StackPanel>
            </TabItem.Header>
            <Grid Margin="10">
              <Grid.RowDefinitions>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="*"/>
              </Grid.RowDefinitions>
              <TextBlock Grid.Row="0" Text="Live socket-level events. NEW = new connection opened; CLOSED = connection closed; STATE = TCP state changed (e.g., ESTABLISHED -> CLOSE_WAIT). Sampled every ~2s. Right-click any row for actions." FontSize="11" Foreground="{DynamicResource BrushFgMuted}" TextWrapping="Wrap" Margin="0,0,0,8"/>

              <!-- Filter + controls bar (row 1) -->
              <Grid Grid.Row="1" Margin="0,0,0,4">
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="*"/>
                  <ColumnDefinition Width="Auto"/>
                </Grid.ColumnDefinitions>
                <Border Grid.Column="0" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="8,4">
                  <Grid>
                    <Grid.ColumnDefinitions>
                      <ColumnDefinition Width="Auto"/>
                      <ColumnDefinition Width="*"/>
                    </Grid.ColumnDefinitions>
                    <TextBlock Grid.Column="0" Text="🔍" FontSize="12" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center" Margin="0,0,6,0"/>
                    <TextBox Grid.Column="1" x:Name="FlowFilterBox" BorderThickness="0" Background="Transparent" Foreground="{DynamicResource BrushFgPrimary}" CaretBrush="#58a6ff" FontSize="12" VerticalAlignment="Center" ToolTip="Filter incoming flow events by text - applies to NEW events only (existing list is preserved). Examples: 'chrome', '443', 'CLOSE_WAIT'"/>
                  </Grid>
                </Border>
                <StackPanel Grid.Column="1" Orientation="Horizontal" VerticalAlignment="Center" Margin="8,0,0,0">
                  <Button x:Name="FlowPauseBtn" Content="▶ Start" Padding="10,4" FontSize="11" FontWeight="Bold" Margin="0,0,4,0" Background="#15803d" Foreground="#ffffff" BorderBrush="#3fb950" ToolTip="Click to begin sampling socket-level events (NEW/CLOSED/STATE/HB). Sample-Flows runs every 2s. Click again to pause."/>
                  <Button x:Name="FlowClearBtn" Content="Clear"    Padding="10,4" FontSize="11" Margin="0,0,4,0" ToolTip="Empty the flow event list"/>
                  <Button x:Name="FlowSaveBtn"  Content="Save..."  Padding="10,4" FontSize="11" ToolTip="Save current flow log to a file"/>
                </StackPanel>
              </Grid>

              <!-- Tier 55: tooltip explains the "tick #N (heavy/light)" diagnostic format. Users
                   reported confusion about what those mean - this surfaces the cadence semantics. -->
              <TextBlock Grid.Row="2" x:Name="FlowCount" Text="0 events" FontSize="10" Foreground="{DynamicResource BrushFgFaint}" Margin="0,0,0,6" TextWrapping="Wrap"
                         ToolTip="Heartbeat for the FLOWS sampler. Shows tick number + cadence (LIGHT every ~2s = cheap UI updates only; HEAVY every other tick = full Sample-Flows pass that compares socket state to the previous snapshot and emits NEW/CLOSED/STATE-CHANGE events). If this counter never advances, the dispatcher timer is stalled. If it advances but events stay flat, Sample-Flows is the problem."/>

              <!-- Streaming list (row 3) - converted to ListView + GridView for native column resize.
                   GridViewColumn supports drag-resize via the gripper between header columns. Each
                   column has a CellTemplate so we keep all the source-color styling. ListView/Item
                   templates are overridden to fit the dark-theme look (no native chrome). -->
              <Border Grid.Row="3" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="0">
                <ListView x:Name="FlowList" Background="Transparent" BorderThickness="0" Foreground="{DynamicResource BrushFgPrimary}" ScrollViewer.HorizontalScrollBarVisibility="Auto" ScrollViewer.VerticalScrollBarVisibility="Auto">
                  <!-- Tier 91: ContextMenu moved off ItemContainerStyle to ListView root. The
                       Style-setter approach was getting absorbed when right-clicks landed on the
                       inner cell TextBlocks (visual-tree lookup didn't always reach the
                       ListViewItem ancestor). With the menu attached at ListView level, every
                       right-click anywhere inside the list pops it. The dispatcher reads the row
                       from ListView.SelectedItem (forced-selected by the PreviewMouseRightButtonDown
                       handler in code-behind). -->
                  <ListView.ContextMenu>
                    <ContextMenu x:Name="FlowListContextMenu">
                      <MenuItem Tag="flow-details"      Header="Connection details..." FontWeight="Bold"/>
                      <Separator/>
                      <MenuItem Tag="flow-filter-proc"  Header="Filter list to this process"/>
                      <MenuItem Tag="flow-filter-clear" Header="Clear filter"/>
                      <Separator/>
                      <MenuItem Tag="flow-copy"         Header="Copy event line"/>
                    </ContextMenu>
                  </ListView.ContextMenu>
                  <ListView.ItemContainerStyle>
                    <Style TargetType="ListViewItem">
                      <Setter Property="Background" Value="Transparent"/>
                      <Setter Property="Foreground" Value="{DynamicResource BrushFgPrimary}"/>
                      <Setter Property="HorizontalContentAlignment" Value="Stretch"/>
                      <Setter Property="Padding" Value="0"/>
                      <Setter Property="BorderThickness" Value="3,0,0,1"/>
                      <Setter Property="BorderBrush" Value="#58a6ff"/>
                      <Style.Triggers>
                        <Trigger Property="IsMouseOver" Value="True">
                          <Setter Property="Background" Value="{DynamicResource BrushHoverBg}"/>
                        </Trigger>
                      </Style.Triggers>
                    </Style>
                  </ListView.ItemContainerStyle>
                  <ListView.View>
                    <GridView>
                      <GridView.ColumnHeaderContainerStyle>
                        <Style TargetType="GridViewColumnHeader">
                          <Setter Property="Background" Value="{DynamicResource BrushCardBg}"/>
                          <Setter Property="Foreground" Value="{DynamicResource BrushFgMuted}"/>
                          <Setter Property="FontSize" Value="10"/>
                          <Setter Property="FontWeight" Value="Bold"/>
                          <Setter Property="Padding" Value="6,4"/>
                          <Setter Property="HorizontalContentAlignment" Value="Left"/>
                          <Setter Property="BorderBrush" Value="{DynamicResource BrushBorder}"/>
                          <Setter Property="BorderThickness" Value="0,0,1,1"/>
                        </Style>
                      </GridView.ColumnHeaderContainerStyle>
                      <GridViewColumn Header="TIME"  Width="80">
                        <GridViewColumn.CellTemplate>
                          <DataTemplate>
                            <TextBlock Text="{Binding Time}" Foreground="{DynamicResource BrushFgFaint}" FontFamily="Consolas" FontSize="11" VerticalAlignment="Center"/>
                          </DataTemplate>
                        </GridViewColumn.CellTemplate>
                      </GridViewColumn>
                      <GridViewColumn Header="EVENT" Width="80">
                        <GridViewColumn.CellTemplate>
                          <DataTemplate>
                            <Border Background="{Binding TypeColor}" CornerRadius="3" Padding="6,2" HorizontalAlignment="Left" VerticalAlignment="Center" MinWidth="56">
                              <TextBlock Text="{Binding Type}" Foreground="#ffffff" FontSize="10" FontWeight="Bold" HorizontalAlignment="Center"/>
                            </Border>
                          </DataTemplate>
                        </GridViewColumn.CellTemplate>
                      </GridViewColumn>
                      <GridViewColumn Header="PROTO" Width="60">
                        <GridViewColumn.CellTemplate>
                          <DataTemplate>
                            <TextBlock Text="{Binding Proto}" Foreground="{Binding ProtoColor}" FontWeight="Bold" FontSize="11" VerticalAlignment="Center"/>
                          </DataTemplate>
                        </GridViewColumn.CellTemplate>
                      </GridViewColumn>
                      <GridViewColumn Header="PROCESS" Width="180">
                        <GridViewColumn.CellTemplate>
                          <DataTemplate>
                            <TextBlock Text="{Binding Process}" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" VerticalAlignment="Center" TextTrimming="CharacterEllipsis"/>
                          </DataTemplate>
                        </GridViewColumn.CellTemplate>
                      </GridViewColumn>
                      <GridViewColumn Header="ENDPOINT" Width="320">
                        <GridViewColumn.CellTemplate>
                          <DataTemplate>
                            <TextBlock Text="{Binding Endpoint}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="11" VerticalAlignment="Center" TextTrimming="CharacterEllipsis"/>
                          </DataTemplate>
                        </GridViewColumn.CellTemplate>
                      </GridViewColumn>
                      <GridViewColumn Header="STATE" Width="180">
                        <GridViewColumn.CellTemplate>
                          <DataTemplate>
                            <TextBlock Text="{Binding State}" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" VerticalAlignment="Center" TextTrimming="CharacterEllipsis"/>
                          </DataTemplate>
                        </GridViewColumn.CellTemplate>
                      </GridViewColumn>
                    </GridView>
                  </ListView.View>
                </ListView>
              </Border>
            </Grid>
          </TabItem>

          <!-- TAB: PERSISTENCE -->
          <TabItem Tag="PERSISTENCE">
            <TabItem.Header>
              <StackPanel Orientation="Horizontal">
                <Rectangle Width="6" Height="6" Fill="#ff9c40" Margin="0,0,6,0" VerticalAlignment="Center"/>
                <TextBlock Text="PERSISTENCE" VerticalAlignment="Center"/>
                <TextBlock Text="" FontWeight="Bold" FontSize="11" Margin="6,0,0,0" VerticalAlignment="Center"/>
              </StackPanel>
            </TabItem.Header>
            <Grid Margin="16">
              <Grid.RowDefinitions>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="*"/>
              </Grid.RowDefinitions>
              <Grid Grid.Row="0" Margin="0,0,0,12">
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="*"/>
                  <ColumnDefinition Width="Auto"/>
                </Grid.ColumnDefinitions>
                <TextBlock x:Name="PersistStatus" Grid.Column="0" Text="Click 'Refresh' to enumerate autorun + scheduled tasks." FontSize="11" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center"/>
                <Button Grid.Column="1" x:Name="PersistRefreshButton" Content="Refresh" Padding="10,4" FontSize="11"/>
              </Grid>
              <ScrollViewer Grid.Row="1" VerticalScrollBarVisibility="Auto" Background="Transparent" CanContentScroll="True">
                <ItemsControl x:Name="PersistList" Style="{StaticResource VirtList}">
                  <ItemsControl.ItemTemplate>
                    <DataTemplate>
                      <Border Background="{DynamicResource BrushDeepBg}" BorderBrush="#ff9c40" BorderThickness="3,1,1,1" CornerRadius="6" Padding="12,10" Margin="0,0,0,6">
                        <Border.ContextMenu>
                          <ContextMenu>
                            <MenuItem Tag="persist-disable" Header="Disable this persistence entry"/>
                            <Separator/>
                            <MenuItem Tag="persist-open"    Header="Open binary location"/>
                            <MenuItem Tag="persist-copy"    Header="Copy command to clipboard"/>
                          </ContextMenu>
                        </Border.ContextMenu>
                        <Grid>
                          <Grid.ColumnDefinitions>
                            <ColumnDefinition Width="Auto"/>
                            <ColumnDefinition Width="Auto"/>
                            <ColumnDefinition Width="*"/>
                          </Grid.ColumnDefinitions>
                          <Border Grid.Column="0" Background="{Binding RiskColor}" CornerRadius="3" Padding="6,2" VerticalAlignment="Top" MinWidth="44">
                            <TextBlock Text="{Binding Risk}" Foreground="White" FontWeight="Bold" FontSize="10" HorizontalAlignment="Center"/>
                          </Border>
                          <!-- Source type chip - colored by autorun source (orange=persistence theme, white text) -->
                          <Border Grid.Column="1" Background="#ff9c40" CornerRadius="3" Padding="6,2" Margin="8,0,10,0" VerticalAlignment="Top" MinWidth="80">
                            <TextBlock Text="{Binding Source}" Foreground="White" FontWeight="Bold" FontSize="10" HorizontalAlignment="Center" TextTrimming="CharacterEllipsis"/>
                          </Border>
                          <StackPanel Grid.Column="2">
                            <TextBlock Text="{Binding Name}" FontWeight="SemiBold" Foreground="{DynamicResource BrushFgPrimary}" TextWrapping="Wrap"/>
                            <TextBlock Text="{Binding Command}" Foreground="{DynamicResource BrushFgMuted}" FontSize="11" TextWrapping="Wrap" Margin="0,2,0,0"/>
                            <TextBlock Text="{Binding SignerLabel}" Foreground="{Binding SignerColor}" FontSize="11" Margin="0,2,0,0"/>
                          </StackPanel>
                        </Grid>
                      </Border>
                    </DataTemplate>
                  </ItemsControl.ItemTemplate>
                </ItemsControl>
              </ScrollViewer>
            </Grid>
          </TabItem>

          <!-- TAB: HISTORY -->
          <TabItem Tag="HISTORY">
            <TabItem.Header>
              <StackPanel Orientation="Horizontal">
                <Rectangle Width="6" Height="6" Fill="#3fb950" Margin="0,0,6,0" VerticalAlignment="Center"/>
                <TextBlock Text="HISTORY" VerticalAlignment="Center"/>
                <TextBlock Text="" FontWeight="Bold" FontSize="11" Margin="6,0,0,0" VerticalAlignment="Center"/>
              </StackPanel>
            </TabItem.Header>
            <Grid Margin="16">
              <Grid.RowDefinitions>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="*"/>
              </Grid.RowDefinitions>
              <Grid Grid.Row="0" Margin="0,0,0,12">
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="*"/>
                  <ColumnDefinition Width="Auto"/>
                </Grid.ColumnDefinitions>
                <TextBlock x:Name="HistoryStatus" Grid.Column="0" Text="Aggregated flap times across past sessions." FontSize="11" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center"/>
                <Button Grid.Column="1" x:Name="HistoryRefreshButton" Content="Refresh" Padding="10,4" FontSize="11"/>
              </Grid>

              <!-- Summary stats card (Tier 36 - HISTORY analysis) -->
              <Border Grid.Row="1" Background="{DynamicResource BrushDeepBg}" BorderBrush="#3fb950" BorderThickness="3,1,1,1" CornerRadius="6" Padding="12,8" Margin="0,0,0,8">
                <StackPanel>
                  <TextBlock Text="SESSION SUMMARY (last 7 days)" Foreground="#3fb950" FontWeight="Bold" FontSize="10" Margin="0,0,0,6"/>
                  <Grid>
                    <Grid.ColumnDefinitions>
                      <ColumnDefinition Width="*"/>
                      <ColumnDefinition Width="*"/>
                      <ColumnDefinition Width="*"/>
                      <ColumnDefinition Width="*"/>
                      <ColumnDefinition Width="*"/>
                    </Grid.ColumnDefinitions>
                    <StackPanel Grid.Column="0">
                      <TextBlock Text="SESSIONS"      FontSize="9" Foreground="{DynamicResource BrushFgMuted}"/>
                      <TextBlock x:Name="HistorySumSessions"  Text="--" FontSize="16" FontWeight="SemiBold" Foreground="{DynamicResource BrushFgPrimary}"/>
                    </StackPanel>
                    <StackPanel Grid.Column="1">
                      <TextBlock Text="TOTAL FLAPS"   FontSize="9" Foreground="{DynamicResource BrushFgMuted}"/>
                      <TextBlock x:Name="HistorySumFlaps"     Text="--" FontSize="16" FontWeight="SemiBold" Foreground="{DynamicResource BrushFgPrimary}"/>
                    </StackPanel>
                    <StackPanel Grid.Column="2">
                      <TextBlock Text="AVG / SESSION" FontSize="9" Foreground="{DynamicResource BrushFgMuted}"/>
                      <TextBlock x:Name="HistorySumAvg"       Text="--" FontSize="16" FontWeight="SemiBold" Foreground="{DynamicResource BrushFgPrimary}"/>
                    </StackPanel>
                    <StackPanel Grid.Column="3">
                      <TextBlock Text="CLEAN SESSIONS" FontSize="9" Foreground="{DynamicResource BrushFgMuted}"/>
                      <TextBlock x:Name="HistorySumClean"     Text="--" FontSize="16" FontWeight="SemiBold" Foreground="#3fb950"/>
                    </StackPanel>
                    <StackPanel Grid.Column="4">
                      <TextBlock Text="WORST"        FontSize="9" Foreground="{DynamicResource BrushFgMuted}"/>
                      <TextBlock x:Name="HistorySumWorst"     Text="--" FontSize="16" FontWeight="SemiBold" Foreground="#f85149"/>
                    </StackPanel>
                  </Grid>
                </StackPanel>
              </Border>

              <!-- heatmap card. Tier 55: tooltip + explicit data-range / legend semantics added -->
              <Border Grid.Row="2" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="6" Padding="14" Margin="0,0,0,12"
                      ToolTip="Aggregates flaps from up to 100 most recent sessions (Reports\Sessions\session-*.json). Each cell is one HOUR x one DAY-OF-WEEK bucket; deeper red = more flaps in that bucket across all loaded sessions. Use to spot patterns - e.g. flaps clustered Monday 8-9am may correlate with a known network event.">
                <StackPanel>
                  <Grid Margin="0,0,0,8">
                    <Grid.ColumnDefinitions>
                      <ColumnDefinition Width="*"/>
                      <ColumnDefinition Width="Auto"/>
                    </Grid.ColumnDefinitions>
                    <TextBlock Grid.Column="0" Text="Flap heatmap (hour-of-day x day-of-week)" Style="{StaticResource Label}"/>
                    <TextBlock Grid.Column="1" Text="rows = Mon-Sun  |  cols = 0:00-23:00 (left to right)" FontSize="9" Foreground="{DynamicResource BrushFgFaint}" VerticalAlignment="Center"/>
                  </Grid>
                  <Canvas x:Name="HeatmapCanvas" Height="160" Background="Transparent"/>
                  <StackPanel Orientation="Horizontal" Margin="0,8,0,0">
                    <TextBlock Text="Less" FontSize="9" Foreground="{DynamicResource BrushFgFaint}" VerticalAlignment="Center" Margin="0,0,4,0"/>
                    <Rectangle Width="14" Height="10" Fill="{DynamicResource BrushCardBg}" Margin="0,0,2,0" ToolTip="0 flaps in this bucket"/>
                    <Rectangle Width="14" Height="10" Fill="#5a2228" Margin="0,0,2,0" ToolTip="1 flap"/>
                    <Rectangle Width="14" Height="10" Fill="#8c2a32" Margin="0,0,2,0" ToolTip="2-3 flaps"/>
                    <Rectangle Width="14" Height="10" Fill="#bf3d48" Margin="0,0,2,0" ToolTip="4-7 flaps"/>
                    <Rectangle Width="14" Height="10" Fill="#f85149" Margin="0,0,4,0" ToolTip="8+ flaps (worst)"/>
                    <TextBlock Text="More flaps" FontSize="9" Foreground="{DynamicResource BrushFgFaint}" VerticalAlignment="Center"/>
                    <TextBlock Text="  -  Hover any cell for hour:flap-count detail" FontSize="9" Foreground="{DynamicResource BrushFgFaint}" VerticalAlignment="Center" Margin="12,0,0,0"/>
                  </StackPanel>
                </StackPanel>
              </Border>

              <!-- session list (row 3 now - row 2 holds the heatmap card; row 1 holds the new summary stats) -->
              <ScrollViewer Grid.Row="3" VerticalScrollBarVisibility="Auto" Background="Transparent" CanContentScroll="True">
                <ItemsControl x:Name="SessionList" Style="{StaticResource VirtList}">
                  <ItemsControl.ItemTemplate>
                    <DataTemplate>
                      <Border Background="{DynamicResource BrushDeepBg}" BorderBrush="#3fb950" BorderThickness="3,1,1,1" CornerRadius="6" Padding="12,8" Margin="0,0,0,4">
                        <Grid>
                          <Grid.ColumnDefinitions>
                            <ColumnDefinition Width="Auto"/>
                            <ColumnDefinition Width="*"/>
                            <ColumnDefinition Width="Auto"/>
                          </Grid.ColumnDefinitions>
                          <TextBlock Grid.Column="0" Text="{Binding When}" Foreground="{DynamicResource BrushFgMuted}" FontFamily="Consolas" FontSize="11" VerticalAlignment="Center"/>
                          <TextBlock Grid.Column="1" Text="{Binding Detail}" Foreground="{DynamicResource BrushFgPrimary}" FontSize="12" Margin="14,0,0,0" VerticalAlignment="Center"/>
                          <Border Grid.Column="2" Background="{Binding FlapColor}" CornerRadius="3" Padding="6,2" VerticalAlignment="Center" MinWidth="36">
                            <TextBlock Text="{Binding FlapCount}" Foreground="White" FontWeight="Bold" FontSize="11" HorizontalAlignment="Center"/>
                          </Border>
                        </Grid>
                      </Border>
                    </DataTemplate>
                  </ItemsControl.ItemTemplate>
                </ItemsControl>
              </ScrollViewer>
            </Grid>
          </TabItem>

          <!-- TAB: DNS CACHE -->
          <TabItem Tag="DNS">
            <TabItem.Header>
              <StackPanel Orientation="Horizontal">
                <Rectangle Width="6" Height="6" Fill="#bf6dff" Margin="0,0,6,0" VerticalAlignment="Center"/>
                <TextBlock Text="DNS" VerticalAlignment="Center"/>
                <TextBlock Text="" FontWeight="Bold" FontSize="11" Margin="6,0,0,0" VerticalAlignment="Center"/>
              </StackPanel>
            </TabItem.Header>
            <Grid Margin="16">
              <Grid.RowDefinitions>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="Auto"/>
                <RowDefinition Height="*"/>
              </Grid.RowDefinitions>
              <Grid Grid.Row="0" Margin="0,0,0,8">
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="*"/>
                  <ColumnDefinition Width="Auto"/>
                </Grid.ColumnDefinitions>
                <TextBlock x:Name="DnsStatus" Grid.Column="0" Text="Recent DNS lookups, with risk heuristics (high-entropy / new-TLD / digit-heavy). Right-click any row for actions." FontSize="11" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center" TextWrapping="Wrap"/>
                <Button Grid.Column="1" x:Name="DnsRefreshButton" Content="Refresh" Padding="10,4" FontSize="11"/>
              </Grid>
              <!-- DNS tab-level toolbar -->
              <StackPanel Grid.Row="1" Orientation="Horizontal" Margin="0,0,0,10">
                <Button x:Name="DnsFlushButton"     Content="Flush cache"        Padding="8,3" FontSize="11" Margin="0,0,6,0" ToolTip="ipconfig /flushdns - clears the Windows DNS resolver cache"/>
                <Button x:Name="DnsHostsButton"     Content="Open hosts file"   Padding="8,3" FontSize="11" Margin="0,0,6,0" ToolTip="Open Windows hosts file in Notepad (admin only)"/>
                <Button x:Name="DnsBlocklistButton" Content="View blocklist"     Padding="8,3" FontSize="11" Margin="0,0,6,0" ToolTip="View domains currently blocked via the hosts file"/>
                <Button x:Name="DnsCopyAllButton"   Content="Copy all"           Padding="8,3" FontSize="11" ToolTip="Copy the full DNS list to the clipboard"/>
              </StackPanel>
              <ScrollViewer Grid.Row="2" VerticalScrollBarVisibility="Auto" Background="Transparent" CanContentScroll="True">
                <ItemsControl x:Name="DnsList" Style="{StaticResource VirtList}">
                  <ItemsControl.ItemTemplate>
                    <DataTemplate>
                      <Border Background="{DynamicResource BrushDeepBg}" BorderBrush="#bf6dff" BorderThickness="3,1,1,1" CornerRadius="6" Padding="10,6" Margin="0,0,0,4" Cursor="Hand" ToolTip="Right-click for actions">
                        <Border.ContextMenu>
                          <ContextMenu>
                            <MenuItem Tag="dns-time"      Header="Time DNS query (re-resolve to measure RTT)..." FontWeight="Bold"/>
                            <MenuItem Tag="dns-trace"     Header="Trace path to this host..."/>
                            <MenuItem Tag="dns-tls"       Header="TLS probe (port 443)..."/>
                            <Separator/>
                            <MenuItem Tag="dns-block"     Header="Block this domain (add to hosts file)..."/>
                            <MenuItem Tag="dns-unblock"   Header="Unblock (remove from hosts)..."/>
                            <Separator/>
                            <MenuItem Tag="dns-process"   Header="Find which process is hitting this..."/>
                            <MenuItem Tag="dns-browse"    Header="Open in browser"/>
                            <MenuItem Tag="dns-whois"     Header="WHOIS lookup (who.is)"/>
                            <MenuItem Tag="dns-virustotal" Header="VirusTotal lookup"/>
                            <Separator/>
                            <MenuItem Tag="dns-copy"      Header="Copy domain to clipboard"/>
                          </ContextMenu>
                        </Border.ContextMenu>
                        <Grid>
                          <Grid.ColumnDefinitions>
                            <ColumnDefinition Width="Auto"/>   <!-- Risk badge -->
                            <ColumnDefinition Width="Auto"/>   <!-- Type chip -->
                            <ColumnDefinition Width="*"/>      <!-- Name + Detail + History -->
                            <ColumnDefinition Width="Auto"/>   <!-- RTT -->
                            <ColumnDefinition Width="Auto"/>   <!-- Why -->
                          </Grid.ColumnDefinitions>
                          <Border Grid.Column="0" Background="{Binding RiskColor}" CornerRadius="3" Padding="6,2" VerticalAlignment="Center" MinWidth="44">
                            <TextBlock Text="{Binding Risk}" Foreground="White" FontWeight="Bold" FontSize="10" HorizontalAlignment="Center"/>
                          </Border>
                          <Border Grid.Column="1" Background="{Binding TypeBgBrush}" CornerRadius="3" Padding="5,2" Margin="6,0,0,0" VerticalAlignment="Center" MinWidth="40" ToolTip="DNS record type">
                            <TextBlock Text="{Binding Type}" Foreground="{Binding TypeFgBrush}" FontWeight="Bold" FontSize="9" HorizontalAlignment="Center"/>
                          </Border>
                          <StackPanel Grid.Column="2" Margin="10,0,0,0">
                            <TextBlock Text="{Binding Name}" Foreground="{DynamicResource BrushFgPrimary}" FontFamily="Consolas" FontSize="12"/>
                            <TextBlock Text="{Binding Detail}" Foreground="{DynamicResource BrushFgFaint}" FontSize="10"/>
                            <TextBlock Text="{Binding History}" Foreground="#79c0ff" FontSize="9" Margin="0,1,0,0"/>
                          </StackPanel>
                          <StackPanel Grid.Column="3" Margin="10,0,0,0" VerticalAlignment="Center" MinWidth="60">
                            <TextBlock Text="RTT" Foreground="{DynamicResource BrushFgMuted}" FontSize="8" HorizontalAlignment="Right"/>
                            <TextBlock Text="{Binding RttLabel}" Foreground="{Binding RttColorBrush}" FontFamily="Consolas" FontSize="11" FontWeight="SemiBold" HorizontalAlignment="Right" ToolTip="Last measured DNS resolution RTT (right-click 'Time DNS query' to populate)"/>
                          </StackPanel>
                          <TextBlock Grid.Column="4" Text="{Binding Why}" Foreground="#d29922" FontSize="11" VerticalAlignment="Center" Margin="10,0,0,0"/>
                        </Grid>
                      </Border>
                    </DataTemplate>
                  </ItemsControl.ItemTemplate>
                </ItemsControl>
              </ScrollViewer>
            </Grid>
          </TabItem>
        </TabControl>
          <!-- floating Pop-out button on the top-right of the tab strip -->
          <Button x:Name="PopOutBtn" Content="⧉ Pop out" Padding="8,3" FontSize="10"
                  HorizontalAlignment="Right" VerticalAlignment="Top" Margin="0,5,8,0"
                  Background="{DynamicResource BrushCardBg}" Foreground="{DynamicResource BrushFgMuted}" BorderBrush="{DynamicResource BrushBorder}"
                  ToolTip="Open the current tab in its own floating window so you can view multiple tabs at once."/>
        </Grid>
      </Border>

      <!-- live events card (column 2 because column 1 is the GridSplitter) -->
      <!-- Tier 61: right-column wrapper with vertical layout: TOP RETRANS SUSPECTS at top, draggable
           splitter in the middle, LIVE EVENTS card at bottom. The retrans row is sized 0 by default
           and flips to 1.5* when Set-RetransPanelVisible $true. The splitter row flips 0px<->5px
           in lockstep so the drag handle is invisible until the panel reveals. -->
      <Grid Grid.Column="2" Margin="3,0,0,0">
        <Grid.RowDefinitions>
          <RowDefinition Height="0" x:Name="RetransRow"/>
          <RowDefinition Height="0" x:Name="RetransSplitterRow"/>
          <!-- Tier 76: x:Name on LIVE EVENTS row + default 6* weight. Default ratio when retrans
               is shown is RetransRow=1*:LiveEventsRow=6*, so live events takes ~86% of the right
               column (1/7 vs 6/7). Naming this row also lets Tier 75's save/restore capture both
               halves of the (RetransRow, LiveEventsRow) splitter pair - without it, dragging the
               splitter and saving would only persist RetransRow's pixel-magnitude star, leading
               to the same 99%-takes-everything bug the main splitter had. -->
          <RowDefinition Height="6*" x:Name="LiveEventsRow"/>
        </Grid.RowDefinitions>
        <!-- TOP RETRANS SUSPECTS - moved here from the chart-column area. Visibility="Collapsed" by
             default; Set-RetransPanelVisible flips RetransRow.Height between 0 and 1.5* and toggles
             this Border's Visibility in lockstep so it never claims layout space when hidden. -->
        <Border x:Name="RetransOffendersBorder" Grid.Row="0" Background="{DynamicResource BrushDeepBg}" BorderBrush="#3a1518" BorderThickness="1" CornerRadius="4" Padding="8,6" Margin="0,0,0,0" Visibility="Collapsed">
          <Grid>
            <Grid.RowDefinitions>
              <RowDefinition Height="Auto"/>              <!-- header -->
              <RowDefinition Height="*" MinHeight="40"/>  <!-- list -->
              <RowDefinition Height="Auto"/>              <!-- hint -->
            </Grid.RowDefinitions>
            <Grid Grid.Row="0">
              <Grid.ColumnDefinitions>
                <ColumnDefinition Width="*"/>
                <ColumnDefinition Width="Auto"/>
              </Grid.ColumnDefinitions>
              <StackPanel Grid.Column="0" Orientation="Horizontal" VerticalAlignment="Center"
                          ToolTip="Lists TCP connections with high retransmit counts, ranked by severity. STUCK (red) = remote stopped responding (CLOSE_WAIT/FIN_WAIT/LAST_ACK). FLAPPING (red) = remote IP correlates with link probes that are failing. PEND (amber) = SYN handshake stalled. EST (blue) = established connection still retransmitting (path loss, MTU, or remote slow ACK). COOL (green) = TIME_WAIT cooldown only. Right-click any row for kill / block / WHOIS / VirusTotal / AbuseIPDB lookups.">
                <TextBlock Text="⚠ TOP RETRANS SUSPECTS" Foreground="#bf6dff" FontWeight="Bold" FontSize="10" VerticalAlignment="Center"/>
                <TextBlock Text="(?)" Foreground="{DynamicResource BrushFgFaint}" FontSize="10" Margin="4,0,0,0" VerticalAlignment="Center" Cursor="Help"/>
                <TextBlock x:Name="RetransOffendersStatus" Margin="10,0,0,0" Text="" Foreground="{DynamicResource BrushFgFaint}" FontSize="10" VerticalAlignment="Center"/>
              </StackPanel>
              <StackPanel Grid.Column="1" Orientation="Horizontal" VerticalAlignment="Center">
                <Button x:Name="RetransInvestigateBtn" Content="🔬 investigate" Padding="6,2" FontSize="10" Margin="0,0,4,0" Background="#1f3a26" Foreground="#3fb950" BorderBrush="#3fb950" ToolTip="Open the Retransmit Investigator - shows ratio (% of segments) instead of raw rate, with verdict, trend, and per-process attribution. Tells you if this is actually a problem or just normal background loss."/>
                <Button x:Name="RetransRefreshBtn" Content="↻ refresh" Padding="6,2" FontSize="10" Margin="0,0,4,0" ToolTip="Re-sample current TCP connections"/>
                <Button x:Name="RetransHideBtn"    Content="hide"     Padding="6,2" FontSize="10" ToolTip="Hide this panel until next retransmit spike"/>
              </StackPanel>
            </Grid>
            <ScrollViewer x:Name="RetransOffendersScroll" Grid.Row="1" Margin="0,4,0,0"
                          VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Disabled" CanContentScroll="True">
              <ItemsControl x:Name="RetransOffendersList" Style="{StaticResource VirtList}">
                <ItemsControl.ItemTemplate>
                  <DataTemplate>
                    <Border BorderThickness="0,0,0,1" BorderBrush="{DynamicResource BrushBorder}" Padding="2,3">
                      <Grid>
                        <Grid.ColumnDefinitions>
                          <ColumnDefinition Width="80"/>
                          <ColumnDefinition Width="*"/>
                          <ColumnDefinition Width="Auto"/>
                        </Grid.ColumnDefinitions>
                        <Border Grid.Column="0" Background="{Binding SeverityBrush}" CornerRadius="2" Padding="5,1" HorizontalAlignment="Left" VerticalAlignment="Center">
                          <TextBlock Text="{Binding SeverityTag}" Foreground="{DynamicResource BrushFgPrimary}" FontSize="9" FontWeight="Bold"/>
                        </Border>
                        <TextBlock Grid.Column="1" Margin="8,0,0,0" Text="{Binding EndpointLabel}" Foreground="{DynamicResource BrushFgPrimary}" FontSize="11" VerticalAlignment="Center" TextTrimming="CharacterEllipsis"/>
                        <TextBlock Grid.Column="2" Margin="8,0,0,0" Text="{Binding Reason}" Foreground="{DynamicResource BrushFgMuted}" FontSize="10" VerticalAlignment="Center"/>
                        <Grid.ContextMenu>
                          <ContextMenu>
                            <MenuItem Header="Connection details..."   Tag="retrans-details" FontWeight="Bold"/>
                            <Separator/>
                            <MenuItem Header="Kill process"            Tag="retrans-kill"/>
                            <MenuItem Header="Block remote IP (firewall)" Tag="retrans-block"/>
                            <Separator/>
                            <MenuItem Header="WHOIS remote"            Tag="retrans-whois"/>
                            <MenuItem Header="VirusTotal lookup"       Tag="retrans-vt"/>
                            <MenuItem Header="AbuseIPDB lookup"        Tag="retrans-abuse"/>
                            <Separator/>
                            <MenuItem Header="Copy remote IP"          Tag="retrans-copy-ip"/>
                            <MenuItem Header="Copy connection details" Tag="retrans-copy-conn"/>
                          </ContextMenu>
                        </Grid.ContextMenu>
                      </Grid>
                    </Border>
                  </DataTemplate>
                </ItemsControl.ItemTemplate>
              </ItemsControl>
            </ScrollViewer>
            <TextBlock x:Name="RetransOffendersHint" Grid.Row="2" FontSize="10" Foreground="{DynamicResource BrushFgFaint}" Margin="0,6,0,0" TextWrapping="Wrap"
                       Text="Heuristic ranking by TCP state + flap correlation. STUCK = remote stopped responding (CLOSE_WAIT/FIN_WAIT/LAST_ACK). FLAPPING = remote IP matches a host failing probes. Right-click a row for actions. Drag the bar below to resize this panel vs LIVE EVENTS."/>
          </Grid>
        </Border>
        <!-- Splitter between TOP RETRANS SUSPECTS and LIVE EVENTS. Default Height=0 (hidden);
             flipped to 5 when retrans is shown. ResizeBehavior PreviousAndNext lets the user drag
             the boundary between the two panels. -->
        <GridSplitter x:Name="RetransSplitter" Grid.Row="1" Height="5" HorizontalAlignment="Stretch" VerticalAlignment="Center"
                      Background="{DynamicResource BrushBorder}" ShowsPreview="False"
                      ResizeBehavior="PreviousAndNext" ResizeDirection="Rows"
                      Cursor="SizeNS" ToolTip="Drag to resize Top Retrans Suspects vs LIVE EVENTS"/>
      <Border x:Name="EventsCard" Grid.Row="2" Style="{StaticResource Card}" Margin="0">
        <Grid>
          <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
          </Grid.RowDefinitions>
          <Grid Grid.Row="0" Margin="0,0,0,8">
            <Grid.RowDefinitions>
              <RowDefinition Height="Auto"/>
              <RowDefinition Height="Auto"/>
            </Grid.RowDefinitions>
            <!-- Top line: title + Start/Stop + Clear -->
            <Grid Grid.Row="0">
              <Grid.ColumnDefinitions>
                <ColumnDefinition Width="*"/>
                <ColumnDefinition Width="Auto"/>
                <ColumnDefinition Width="Auto"/>
              </Grid.ColumnDefinitions>
              <!-- Tier 59: title + live count badge. EventsCountText updates every tick from Tick().
                   Format: "LIVE EVENTS (N)" where N is the current $script:Events count. Empty when 0
                   so the title doesn't read "(0)" before the user clicks Start. -->
              <StackPanel Grid.Column="0" Orientation="Horizontal" VerticalAlignment="Center">
                <TextBlock Text="LIVE EVENTS" Style="{StaticResource Label}" VerticalAlignment="Center"/>
                <TextBlock x:Name="EventsCountText" Text="" FontSize="10" Foreground="{DynamicResource BrushFgFaint}" Margin="6,0,0,0" VerticalAlignment="Center"
                           ToolTip="Current event count in the visible log (capped at 500). Resets when you click Clear."/>
              </StackPanel>
              <Button Grid.Column="1" x:Name="EventsPauseButton" Content="▶ Start" Padding="8,3" FontSize="11" Margin="0,0,4,0" Background="#15803d" Foreground="#ffffff" BorderBrush="#3fb950" ToolTip="Click to begin streaming events into this log. Click again to pause."/>
              <Button Grid.Column="2" x:Name="ClearEventsButton" Content="Clear" Padding="8,3" FontSize="11"/>
            </Grid>
            <!-- Feed selector row: which event sources to show in the log.
                 Tier 57: + inline text filter at the end. Uses *-weight so it stretches to fill any
                 remaining horizontal space. Filter matches case-insensitive substring against the
                 event row's body text. Empty = show all (feed-checkbox filtering still applies). -->
            <Grid Grid.Row="1" Margin="0,4,0,0">
              <Grid.ColumnDefinitions>
                <ColumnDefinition Width="Auto"/>
                <ColumnDefinition Width="*"/>
              </Grid.ColumnDefinitions>
              <StackPanel Grid.Column="0" Orientation="Horizontal">
                <TextBlock Text="Feeds:" FontSize="9" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center" Margin="0,0,8,0"/>
                <CheckBox x:Name="EventFeedDnsBox"         Content="DNS"         FontSize="10" IsChecked="True" Margin="0,0,8,0" VerticalAlignment="Center" Foreground="#bf6dff" ToolTip="Show DNS events: new resolutions, cache refreshes, blocks/unblocks, RTT timings"/>
                <CheckBox x:Name="EventFeedFlowsBox"       Content="Flows"       FontSize="10" IsChecked="True" Margin="0,0,8,0" VerticalAlignment="Center" Foreground="#58a6ff" ToolTip="Show FLOWS events: connection state changes, UDP listener openings, sampler init"/>
                <CheckBox x:Name="EventFeedTrafficBox"     Content="Traffic"     FontSize="10" IsChecked="True" Margin="0,0,8,0" VerticalAlignment="Center" Foreground="#d29922" ToolTip="Show TRAFFIC tab events (top-talker sampling, protocol rate alerts)"/>
                <CheckBox x:Name="EventFeedProcessesBox"   Content="Processes"   FontSize="10" IsChecked="True" Margin="0,0,8,0" VerticalAlignment="Center" Foreground="#79c0ff" ToolTip="Show PROCESSES events: scan results, kills, blocks, HIGH-risk flags"/>
                <CheckBox x:Name="EventFeedPersistenceBox" Content="Persistence" FontSize="10" IsChecked="True" Margin="0,0,8,0" VerticalAlignment="Center" Foreground="#ff9c40" ToolTip="Show PERSISTENCE events: scan results, autorun changes, scheduled-task additions"/>
                <CheckBox x:Name="EventFeedSystemBox"      Content="System"      FontSize="10" IsChecked="True" VerticalAlignment="Center" Foreground="{DynamicResource BrushFgMuted}" ToolTip="Show system events (link flaps, TCP retransmits, RX errors, kill-switch). Uncheck to mute the loudest feed."/>
              </StackPanel>
              <Grid Grid.Column="1" Margin="12,0,0,0">
                <Grid.ColumnDefinitions>
                  <ColumnDefinition Width="*"/>
                  <ColumnDefinition Width="Auto"/>
                </Grid.ColumnDefinitions>
                <TextBox x:Name="EventFilterBox" Grid.Column="0" Padding="6,2" FontSize="11"
                         Background="{DynamicResource BrushDeepBg}" Foreground="{DynamicResource BrushFgPrimary}"
                         BorderBrush="{DynamicResource BrushBorder}"
                         ToolTip="Filter events by message text (case-insensitive substring). Feed checkboxes still apply. Clear to show all matching events."/>
                <Button Grid.Column="1" x:Name="EventFilterClearBtn" Content="x" Padding="4,2" FontSize="10" Margin="2,0,0,0"
                        ToolTip="Clear text filter"/>
              </Grid>
            </Grid>
          </Grid>
          <!-- Tier 79: LIVE EVENTS rebuilt as a ListView/GridView (mirrors the FLOWS tab pattern).
               Four columns: TIME | TYPE | LEVEL | DESCRIPTION. Each column drag-resizable; click
               the header to sort. The TYPE cell carries the source color (DNS=purple, FLOWS=cyan,
               etc.) and the LEVEL cell carries the severity color (CRITICAL=red, HIGH=red-orange,
               LOW=orange, OK=green). Body text is neutral so the two color cells are the only
               places where color appears - no row tint, no pills, no emojis competing.
               Built-in ListView virtualization handles the 500-event cap without realizing all rows
               at once, so hover/scroll stays responsive. -->
          <ListView x:Name="EventsList" Grid.Row="1" Background="Transparent" BorderThickness="0"
                    Foreground="{DynamicResource BrushFgPrimary}"
                    ScrollViewer.HorizontalScrollBarVisibility="Auto"
                    ScrollViewer.VerticalScrollBarVisibility="Auto">
            <!-- Tier 92: ContextMenu moved off ItemContainerStyle to ListView root - same fix as
                 Tier 91's FlowList. The Style-setter approach was getting absorbed when right-clicks
                 landed on the inner cell TextBlocks (visual-tree ContextMenu lookup didn't always
                 reach the ListViewItem ancestor). With the menu attached at ListView level, every
                 right-click anywhere inside the list pops it. PreviewMouseRightButtonDown handler
                 in code-behind selects the clicked row so the dispatcher resolves it via
                 ListView.SelectedItem (Tier 91 dispatcher path). -->
            <ListView.ContextMenu>
              <ContextMenu x:Name="EventsListContextMenu">
                <MenuItem Header="Copy event line"        Tag="event-copy" FontWeight="Bold"/>
                <Separator/>
                <MenuItem Header="Filter to this source"   Tag="event-filter-source"/>
                <MenuItem Header="Filter to this severity" Tag="event-filter-severity"/>
                <MenuItem Header="Clear filter"            Tag="event-filter-clear"/>
              </ContextMenu>
            </ListView.ContextMenu>
            <ListView.ItemContainerStyle>
              <Style TargetType="ListViewItem">
                <Setter Property="Background" Value="Transparent"/>
                <Setter Property="Foreground" Value="{DynamicResource BrushFgPrimary}"/>
                <Setter Property="HorizontalContentAlignment" Value="Stretch"/>
                <Setter Property="Padding" Value="0"/>
                <Setter Property="BorderThickness" Value="0,0,0,1"/>
                <Setter Property="BorderBrush" Value="{DynamicResource BrushBorder}"/>
                <Style.Triggers>
                  <Trigger Property="IsMouseOver" Value="True">
                    <Setter Property="Background" Value="{DynamicResource BrushHoverBg}"/>
                  </Trigger>
                </Style.Triggers>
              </Style>
            </ListView.ItemContainerStyle>
            <ListView.View>
              <GridView>
                <GridView.ColumnHeaderContainerStyle>
                  <Style TargetType="GridViewColumnHeader">
                    <Setter Property="Background" Value="{DynamicResource BrushCardBg}"/>
                    <Setter Property="Foreground" Value="{DynamicResource BrushFgMuted}"/>
                    <Setter Property="FontSize" Value="10"/>
                    <Setter Property="FontWeight" Value="Bold"/>
                    <Setter Property="Padding" Value="6,4"/>
                    <Setter Property="HorizontalContentAlignment" Value="Left"/>
                    <Setter Property="BorderBrush" Value="{DynamicResource BrushBorder}"/>
                    <Setter Property="BorderThickness" Value="0,0,1,1"/>
                    <Setter Property="Cursor" Value="Hand"/>
                  </Style>
                </GridView.ColumnHeaderContainerStyle>
                <GridViewColumn Header="TIME" Width="75">
                  <GridViewColumn.CellTemplate>
                    <DataTemplate>
                      <TextBlock Text="{Binding Time}" Foreground="{DynamicResource BrushFgFaint}" FontFamily="Consolas" FontSize="11" VerticalAlignment="Center"/>
                    </DataTemplate>
                  </GridViewColumn.CellTemplate>
                </GridViewColumn>
                <GridViewColumn Header="TYPE" Width="90">
                  <GridViewColumn.CellTemplate>
                    <DataTemplate>
                      <Border Background="{Binding SourceColor}" CornerRadius="3" Padding="6,2" HorizontalAlignment="Stretch" VerticalAlignment="Center">
                        <TextBlock Text="{Binding SourceLabel}" Foreground="{DynamicResource BrushFgPrimary}" FontSize="10" FontWeight="Bold" HorizontalAlignment="Center"/>
                      </Border>
                    </DataTemplate>
                  </GridViewColumn.CellTemplate>
                </GridViewColumn>
                <GridViewColumn Header="LEVEL" Width="90">
                  <GridViewColumn.CellTemplate>
                    <DataTemplate>
                      <Border Background="{Binding SeverityColor}" CornerRadius="3" Padding="6,2" HorizontalAlignment="Stretch" VerticalAlignment="Center" Visibility="{Binding SeverityVisibility}">
                        <TextBlock Text="{Binding Severity}" Foreground="{DynamicResource BrushFgPrimary}" FontSize="10" FontWeight="Bold" HorizontalAlignment="Center"/>
                      </Border>
                    </DataTemplate>
                  </GridViewColumn.CellTemplate>
                </GridViewColumn>
                <GridViewColumn Header="DESCRIPTION" Width="600">
                  <GridViewColumn.CellTemplate>
                    <DataTemplate>
                      <StackPanel VerticalAlignment="Center">
                        <TextBlock Text="{Binding Text}" Foreground="{DynamicResource BrushFgPrimary}" TextWrapping="Wrap" FontSize="12"/>
                        <TextBlock Text="{Binding Detail}" Foreground="{DynamicResource BrushFgFaint}" TextWrapping="Wrap" FontSize="10" FontStyle="Italic" Margin="0,1,0,0" Visibility="{Binding DetailVisibility}"/>
                      </StackPanel>
                    </DataTemplate>
                  </GridViewColumn.CellTemplate>
                </GridViewColumn>
              </GridView>
            </ListView.View>
          </ListView>
        </Grid>
      </Border>
      </Grid>   <!-- /Grid Grid.Column="2" wrapper - Tier 61 retrans+splitter+events stack -->
    </Grid>

    <!-- ACTION BAR: menus + badges + primary actions, single row  (Row=5 after Hero/Ping splitter insertion) -->
    <Border Grid.Row="5" Style="{StaticResource Card}" Margin="0">
      <Grid>
        <Grid.ColumnDefinitions>
          <ColumnDefinition Width="Auto"/>   <!-- 0: DiagnoseMenuButton -->
          <ColumnDefinition Width="Auto"/>   <!-- 1: RemediateMenuButton -->
          <ColumnDefinition Width="Auto"/>   <!-- 2: ExportMenuButton -->
          <ColumnDefinition Width="Auto"/>   <!-- 3: ViewMenuButton -->
          <ColumnDefinition Width="Auto"/>   <!-- 4: GlossaryButton -->
          <ColumnDefinition Width="*"/>      <!-- 5: badges StackPanel (filler) -->
          <ColumnDefinition Width="Auto"/>   <!-- 6: OpenReportsButton -->
          <ColumnDefinition Width="Auto"/>   <!-- 7: FixButton -->
        </Grid.ColumnDefinitions>

        <!-- Diagnose menu -->
        <Button Grid.Column="0" x:Name="DiagnoseMenuButton" Content="Diagnose v">
          <Button.ContextMenu>
            <ContextMenu>
              <MenuItem x:Name="MenuMtu"      Header="Probe MTU"/>
              <MenuItem x:Name="MenuDefender" Header="Run Defender quick scan"/>
              <MenuItem x:Name="MenuTlsInspect" Header="Inspect TLS certs of active 443 connections..."
                        ToolTip="Pulls the TLS certificate chain from every currently-established outbound 443 connection. Shows issuer, expiry, hostname mismatch, and self-signed flags. Useful when a man-in-the-middle / corp proxy is suspected of intercepting HTTPS."/>
              <MenuItem x:Name="MenuTlsProbe"  Header="TLS probe (single host)..."
                        ToolTip="Asks for a hostname, then makes a fresh TLS handshake to that host on port 443 (or any port you specify). Reports the served cert, cipher suite, protocol version, and any handshake errors. Good for verifying a specific service before running a wider probe."/>
              <MenuItem x:Name="MenuPathInspect" Header="Path inspection (traceroute with sparklines)..."
                        ToolTip="Traceroute that runs continuously and renders each hop's latency as a sparkline. Spots which hop along the path is degraded. Each hop also gets a verdict (FAST / SLOW / LOSSY / DOWN). Useful when latency is bad but you don't know whether it's the LAN, your ISP, or the destination."/>
              <MenuItem x:Name="MenuThreatRefresh" Header="Refresh threat-intel feeds"
                        ToolTip="Re-fetches all enabled threat-intel feeds (FireHOL Level 1, Spamhaus DROP, etc. - configurable in Settings). Threat-intel CIDR ranges are checked when enriching connection ledger entries. Most users don't need to refresh manually - the cache auto-loads on startup."/>
              <Separator/>
              <MenuItem x:Name="MenuConnMap"   Header="Show connection map..."
                        ToolTip="Visualizes all current outbound TCP connections grouped by remote IP, with country/ASN labels. Quick way to see who you're talking to right now."/>
              <MenuItem x:Name="MenuFlapTimeline" Header="Flap-capture timeline viewer..."
                        ToolTip="If pktmon is installed and admin rights granted, NetJump auto-captures network packets around each flap event. This viewer parses the saved capture.txt and shows ARP / DHCP / DNS / ICMP / TCP-RST counts on a scrubbable timeline so you can pinpoint what triggered the flap."/>
              <MenuItem x:Name="MenuRescan2"  Header="Re-scan diagnostics  (Ctrl+R)"/>
            </ContextMenu>
          </Button.ContextMenu>
        </Button>

        <!-- Remediate menu -->
        <Button Grid.Column="1" x:Name="RemediateMenuButton" Content="Remediate v">
          <Button.ContextMenu>
            <ContextMenu>
              <MenuItem x:Name="MenuDriver"   Header="NIC driver versions..."/>
              <MenuItem x:Name="MenuNetReset" Header="Network reset bundle..."/>
              <MenuItem x:Name="MenuIpv6"     Header="Toggle IPv6..."/>
              <Separator/>
              <MenuItem x:Name="MenuLockdownOn"  Header="Enable lockdown mode (panic)..."/>
              <MenuItem x:Name="MenuLockdownOff" Header="Disable lockdown..."/>
              <Separator/>
              <MenuItem x:Name="MenuMonitorInstall"   Header="Install background monitor (run at logon)..."/>
              <MenuItem x:Name="MenuMonitorUninstall" Header="Uninstall background monitor"/>
            </ContextMenu>
          </Button.ContextMenu>
        </Button>

        <!-- Export menu -->
        <Button Grid.Column="2" x:Name="ExportMenuButton" Content="Export v">
          <Button.ContextMenu>
            <ContextMenu>
              <MenuItem x:Name="MenuSaveHtml"  Header="Save HTML report  (Ctrl+S)"
                        ToolTip="One-shot HTML snapshot of the current findings + events. Best for sharing 'here's what I see right now' without sending the whole reports folder."/>
              <MenuItem x:Name="MenuExportCsv" Header="Export current tab as CSV  (Ctrl+E)"
                        ToolTip="Exports the rows visible in whichever tab is currently active (Diagnostics, Processes, Persistence, DNS, Traffic, History). For piping into Excel / SIEM / etc."/>
              <MenuItem x:Name="MenuExportLedger" Header="Export connection ledger as CSV"
                        ToolTip="Dumps the long-running beacon/connection ledger - every (process, remote IP, port) combination NetJump has seen, with first/last-seen and sample count. Survives across launches; pruned to 7 days."/>
              <MenuItem x:Name="MenuExportStix"   Header="Export STIX 2.1 bundle (SOC handoff)"
                        ToolTip="Builds a STIX 2.1 JSON bundle of suspicious indicators (HIGH-risk processes, beaconing connections, threat-intel hits) suitable for ingest into a SOAR/SIEM platform. STIX is the structured-threat-info standard MITRE / CISA use."/>
              <MenuItem x:Name="MenuDigest"    Header="Build daily digest"
                        ToolTip="Generates a one-page summary HTML for today's session(s): flap count, top causes, fixes applied, key events. Useful as an end-of-day status update."/>
              <MenuItem x:Name="MenuBundle"    Header="Build send-bundle zip"
                        ToolTip="Packages everything an IT helper would need - HTML report + recent flap dossiers (capture.txt + timeline.md) + ledger CSV + settings - into a single .zip. Drop this in a ticket and the recipient has all forensic context."/>
              <Separator/>
              <MenuItem x:Name="MenuOpenReports" Header="Open reports folder"
                        ToolTip="Opens NetJump's Reports\ folder in Explorer. Contains HTML reports, flap dossiers (per-flap subfolders), session JSONs, and exported CSVs."/>
              <MenuItem x:Name="MenuOpenRules"   Header="Open custom detection rules folder"
                        ToolTip="Custom YARA-style rule files (process-name + remote IP/port patterns) live here. NetJump auto-loads any *.rules file on startup. Add your own to flag specific binaries / domains as HIGH-risk."/>
              <Separator/>
              <MenuItem x:Name="MenuReplaySnapshot" Header="Replay snapshot..."
                        ToolTip="Re-load a previous scan's findings into the UI. Each scan auto-saves a snapshot to Reports\Snapshots\snapshot-*.json (kept rolling at 30). Useful for testing what a fix recommendation would do against historical data without recreating the original conditions."/>
            </ContextMenu>
          </Button.ContextMenu>
        </Button>

        <!-- View menu -->
        <Button Grid.Column="3" x:Name="ViewMenuButton" Content="View v">
          <Button.ContextMenu>
            <ContextMenu>
              <MenuItem x:Name="MenuTheme" Header="Theme: dark"/>
              <MenuItem x:Name="MenuMute"  Header="Notifications: ON"/>
              <Separator/>
              <MenuItem x:Name="MenuProcTree"   Header="Show process tree..."/>
              <MenuItem x:Name="MenuViewEvents"  Header="View events log..."/>
              <MenuItem x:Name="MenuClearEvents" Header="Clear events log  (Ctrl+L)"/>
              <Separator/>
              <MenuItem x:Name="MenuSettings"   Header="Settings..."/>
            </ContextMenu>
          </Button.ContextMenu>
        </Button>

        <!-- Glossary as standalone (lookup, not action) -->
        <Button Grid.Column="4" x:Name="GlossaryButton" Content="?  glossary"/>

        <!-- badges (centered-left of right buttons) -->
        <StackPanel Grid.Column="5" Orientation="Horizontal" HorizontalAlignment="Right" VerticalAlignment="Center" Margin="16,0,0,0">
          <Border x:Name="CaptureBadge" Background="{DynamicResource BrushCardBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="4" Padding="8,4" Margin="0,0,8,0">
            <StackPanel Orientation="Horizontal">
              <Ellipse x:Name="CaptureDot" Width="8" Height="8" Fill="{DynamicResource BrushFgFaint}" VerticalAlignment="Center" Margin="0,0,6,0"/>
              <TextBlock x:Name="CaptureText" Text="capture: off" FontSize="11" Foreground="{DynamicResource BrushFgMuted}" VerticalAlignment="Center"/>
            </StackPanel>
          </Border>
          <Border x:Name="VerifyBadge" Background="{DynamicResource BrushCardBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="4" Padding="8,4" Margin="0,0,8,0" Visibility="Collapsed">
            <StackPanel Orientation="Horizontal">
              <Ellipse Width="8" Height="8" Fill="#1f6feb" VerticalAlignment="Center" Margin="0,0,6,0"/>
              <TextBlock x:Name="VerifyText" Text="verifying..." FontSize="11" Foreground="#58a6ff" VerticalAlignment="Center"/>
            </StackPanel>
          </Border>
          <Border x:Name="DefenderBadge" Background="{DynamicResource BrushCardBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="1" CornerRadius="4" Padding="8,4" Visibility="Collapsed">
            <StackPanel Orientation="Horizontal">
              <Ellipse Width="8" Height="8" Fill="#7ee787" VerticalAlignment="Center" Margin="0,0,6,0"/>
              <TextBlock x:Name="DefenderText" Text="defender scanning..." FontSize="11" Foreground="#7ee787" VerticalAlignment="Center"/>
            </StackPanel>
          </Border>
          <Border x:Name="LockdownBadge" Background="#5a1018" BorderBrush="#f85149" BorderThickness="1" CornerRadius="4" Padding="8,4" Margin="8,0,0,0" Visibility="Collapsed">
            <StackPanel Orientation="Horizontal">
              <Ellipse Width="8" Height="8" Fill="#f85149" VerticalAlignment="Center" Margin="0,0,6,0"/>
              <TextBlock x:Name="LockdownText" Text="LOCKDOWN ACTIVE" FontSize="11" FontWeight="Bold" Foreground="#f85149" VerticalAlignment="Center"/>
            </StackPanel>
          </Border>
        </StackPanel>

        <!-- primary actions (RescanButton was moved to the hero card top-right corner) -->
        <Button Grid.Column="6" x:Name="OpenReportsButton" Content="Open reports"/>
        <Button Grid.Column="7" x:Name="FixButton" Content="Apply Fixes" Background="#1f6feb" BorderBrush="#2f7fff" ToolTip="Open the fix picker dialog. Pick which recommendations to apply, or click AUTO-APPLY ALL SAFE inside the dialog to apply every SAFE-tier fix at once. Requires Administrator."/>
      </Grid>
    </Border>

    <!-- ========================================================================
         TIER 23 (compacted Tier 34): NETWORK KILL-SWITCH STRIP
         Always visible. ~1/4 the height of the previous banner. Three states:
           * GREYED  - HasScanned=false. Disabled, "Run a scan to arm" hint.
           * RED ARM - HasScanned=true, kill switch off. Button enabled, red.
           * GREEN   - kill switch active. REVERT button enabled, green.
         All three states share a single compact row layout - tooltips carry the long-form
         explanation. Update-KillSwitchUI flips visuals based on $script:State.HasScanned
         and the killswitch-active.json marker.
         ======================================================================== -->
    <Border Grid.Row="6" x:Name="KillSwitchPanel" Margin="0,6,0,0" Padding="0" Visibility="Visible">
      <Grid>
        <!-- ARM strip: compact single-row layout (greyed when no scan, red when armed) -->
        <Border x:Name="KillSwitchArmHost" Background="#1a1a1a" BorderBrush="#3a3a3a" BorderThickness="1" CornerRadius="4" Padding="8,4">
          <Grid>
            <Grid.ColumnDefinitions>
              <ColumnDefinition Width="Auto"/>
              <ColumnDefinition Width="Auto"/>
              <ColumnDefinition Width="*"/>
              <ColumnDefinition Width="Auto"/>
            </Grid.ColumnDefinitions>
            <TextBlock Grid.Column="0" x:Name="KillSwitchIcon" Text="⚠" Foreground="#6a7380" FontSize="16" FontWeight="Bold" VerticalAlignment="Center" Margin="2,0,8,0"/>
            <TextBlock Grid.Column="1" x:Name="KillSwitchLabel" Text="KILL-SWITCH" Foreground="#6a7380" FontSize="11" FontWeight="Bold" VerticalAlignment="Center"/>
            <TextBlock Grid.Column="2" x:Name="KillSwitchSubtext" Text="Run a diagnostic scan first to arm" Foreground="#6a7380" FontSize="10" VerticalAlignment="Center" Margin="10,0,0,0"/>
            <Button Grid.Column="3" x:Name="KillSwitchArmBtn"
                    Content="🛑 ENGAGE"
                    FontSize="11" FontWeight="Bold"
                    Padding="10,4"
                    Background="#3a3a3a" Foreground="#6a7380" BorderBrush="#4a4a4a" BorderThickness="1"
                    IsEnabled="False"
                    VerticalAlignment="Center"
                    ToolTip="Cuts ALL network traffic instantly: disables every active adapter and sets Windows Firewall to BLOCK on all profiles. Active VPN/SSH/RDP sessions will drop. Reversible via REVERT button (~2-5 sec). Requires Administrator. Run a diagnostic scan first to arm this button."/>
          </Grid>
        </Border>
        <!-- REVERT strip: shown when kill switch is active. Same compact dimensions. -->
        <Border x:Name="KillSwitchRevertHost" Background="#1f1a14" BorderBrush="#d29922" BorderThickness="1" CornerRadius="4" Padding="8,4" Visibility="Collapsed">
          <Grid>
            <Grid.ColumnDefinitions>
              <ColumnDefinition Width="Auto"/>
              <ColumnDefinition Width="Auto"/>
              <ColumnDefinition Width="*"/>
              <ColumnDefinition Width="Auto"/>
            </Grid.ColumnDefinitions>
            <TextBlock Grid.Column="0" Text="🔌" FontSize="14" VerticalAlignment="Center" Margin="2,0,8,0"/>
            <TextBlock Grid.Column="1" Text="KILL-SWITCH ACTIVE" Foreground="#d29922" FontSize="11" FontWeight="Bold" VerticalAlignment="Center"/>
            <TextBlock Grid.Column="2" x:Name="KillSwitchRevertSubtext" Text="" Foreground="#bfaa70" FontSize="10" VerticalAlignment="Center" Margin="10,0,0,0" TextTrimming="CharacterEllipsis"/>
            <Button Grid.Column="3" x:Name="KillSwitchRevertBtn"
                    Content="✓ DISENGAGE"
                    FontSize="11" FontWeight="Bold"
                    Padding="10,4"
                    Background="#15803d" Foreground="#ffffff" BorderBrush="#3fb950" BorderThickness="1"
                    Cursor="Hand"
                    VerticalAlignment="Center"
                    ToolTip="Disengage kill-switch: re-enable all network adapters that were disabled and restore firewall ruleset from backup. Restores everything that the kill-switch shut off."/>
          </Grid>
        </Border>
      </Grid>
    </Border>
    <!-- Tier 58: persistent status bar at the bottom of the main window. Surfaces the small set of
         counters that previously you had to look up across multiple tabs. Updated on every Tick(). -->
    <Border Grid.Row="7" Background="{DynamicResource BrushDeepBg}" BorderBrush="{DynamicResource BrushBorder}" BorderThickness="0,1,0,0" Padding="10,3" Margin="0,4,0,0">
      <Grid>
        <Grid.ColumnDefinitions>
          <ColumnDefinition Width="Auto"/>
          <ColumnDefinition Width="Auto"/>
          <ColumnDefinition Width="Auto"/>
          <ColumnDefinition Width="Auto"/>
          <ColumnDefinition Width="Auto"/>
          <ColumnDefinition Width="*"/>
          <ColumnDefinition Width="Auto"/>
        </Grid.ColumnDefinitions>
        <TextBlock Grid.Column="0" x:Name="StatusBarSession" FontFamily="Consolas" FontSize="10" Foreground="{DynamicResource BrushFgFaint}" VerticalAlignment="Center" ToolTip="Time since the dashboard was launched"/>
        <TextBlock Grid.Column="1" Text=" | " FontSize="10" Foreground="{DynamicResource BrushFgFaint}" VerticalAlignment="Center" Margin="6,0"/>
        <TextBlock Grid.Column="2" x:Name="StatusBarTick"    FontFamily="Consolas" FontSize="10" Foreground="{DynamicResource BrushFgFaint}" VerticalAlignment="Center" ToolTip="Total tick count + heartbeat - if it stops advancing the dispatcher timer is dead"/>
        <TextBlock Grid.Column="3" Text=" | " FontSize="10" Foreground="{DynamicResource BrushFgFaint}" VerticalAlignment="Center" Margin="6,0"/>
        <TextBlock Grid.Column="4" x:Name="StatusBarFlaps"   FontFamily="Consolas" FontSize="10" Foreground="{DynamicResource BrushFgFaint}" VerticalAlignment="Center" ToolTip="Total flaps detected this session, total events emitted"/>
        <TextBlock Grid.Column="5" Text="" FontSize="10"/>
        <TextBlock Grid.Column="6" x:Name="StatusBarMode"    FontFamily="Consolas" FontSize="10" Foreground="{DynamicResource BrushFgFaint}" VerticalAlignment="Center" ToolTip="Admin / non-admin context + monitor task status"/>
      </Grid>
    </Border>
  </Grid>
</Window>
'@

$reader = New-Object System.Xml.XmlNodeReader $xaml
$window = [Windows.Markup.XamlReader]::Load($reader)

# Global safety net: any unhandled exception that bubbles out of a click handler, async dispatcher
# operation, or animation completion would otherwise terminate the WPF app. Mark it Handled and log.
$script:_UnhandledLogged = @{}
$window.Dispatcher.add_UnhandledException({
    param($sender, $e)
    try {
        $msg = "$($e.Exception.GetType().Name): $($e.Exception.Message)"
        if (-not $script:_UnhandledLogged.ContainsKey($msg)) {
            $script:_UnhandledLogged[$msg] = $true
            try { Add-Event warn ("Unhandled: $msg") } catch {}
            try { Write-Host "Unhandled dispatcher exception: $($e.Exception)`n$($e.Exception.StackTrace)" } catch {}
        }
        $e.Handled = $true
    } catch {}
})

