if (-not $script:IsAdmin) {
    $controls.AdminWarning.Text = 'Not elevated - fix button disabled'
    $controls.FixButton.IsEnabled = $false
}

# Tier 69: background sampler runspace - moves the slowest CIM operations off the dispatcher.
# The dispatcher thread is responsible for all WPF UI updates, so any synchronous CIM call there
# directly translates to "frozen UI". This runspace lives for the lifetime of the dashboard and
# accepts script blocks via Invoke-BackgroundSample. Results come back via Receive-BackgroundSample
# at the next tick poll.
#
# Why not Start-Job: spawns a separate process with 200-500 ms startup cost, defeats the purpose.
# Why not Start-ThreadJob: requires the ThreadJob module which isn't shipped on PS 5.1 by default.
# Why a single runspace with shared in-flight handle: cheap to create, predictable, no pool sizing.
$script:_BgRunspace = $null
$script:_BgSamplers = @{}   # name -> @{ Powershell; AsyncResult; StartedAt }
try {
    $script:_BgRunspace = [runspacefactory]::CreateRunspace()
    $script:_BgRunspace.ApartmentState = 'STA'
    $script:_BgRunspace.ThreadOptions  = 'ReuseThread'
    $script:_BgRunspace.Open()
} catch {
    # If runspace creation fails (rare), the Tick code falls back to synchronous sampling.
    $script:_BgRunspace = $null
    try { Write-Host "BgRunspace init failed: $_" } catch {}
}

# Start a sampler. $Name is a string key (e.g. 'retrans-offenders') used to track the in-flight
# handle. $ScriptBlock is the work to do on the background thread - it must be self-contained and
# return its results via the pipeline (the runspace inherits no script-scope state). Returns $true
# if started, $false if a previous one is still running (don't double-submit).
function Invoke-BackgroundSample {
    param(
        [Parameter(Mandatory)] [string]$Name,
        [Parameter(Mandatory)] [scriptblock]$ScriptBlock
    )
    if (-not $script:_BgRunspace) { return $false }
    if ($script:_BgSamplers.ContainsKey($Name)) {
        $existing = $script:_BgSamplers[$Name]
        if ($existing -and $existing.AsyncResult -and -not $existing.AsyncResult.IsCompleted) {
            # Sanity timeout: a sampler that's been running >30 s is almost certainly stuck. Drop it.
            $age = ((Get-Date) - $existing.StartedAt).TotalSeconds
            if ($age -gt 30) {
                try { $existing.Powershell.Stop() } catch {}
                try { $existing.Powershell.Dispose() } catch {}
                $script:_BgSamplers.Remove($Name)
            } else {
                return $false   # still running, don't double-submit
            }
        }
    }
    try {
        $ps = [powershell]::Create()
        $ps.Runspace = $script:_BgRunspace
        [void]$ps.AddScript($ScriptBlock)
        $async = $ps.BeginInvoke()
        $script:_BgSamplers[$Name] = @{ Powershell = $ps; AsyncResult = $async; StartedAt = (Get-Date) }
        return $true
    } catch { return $false }
}

# Check if a named sampler completed. Returns $null if no result available yet (still running or
# never started); returns the result object on completion. Cleans up resources after harvesting.
function Receive-BackgroundSample {
    param([Parameter(Mandatory)] [string]$Name)
    if (-not $script:_BgSamplers.ContainsKey($Name)) { return $null }
    $entry = $script:_BgSamplers[$Name]
    if (-not $entry -or -not $entry.AsyncResult.IsCompleted) { return $null }
    $result = $null
    try { $result = $entry.Powershell.EndInvoke($entry.AsyncResult) } catch {}
    try { $entry.Powershell.Dispose() } catch {}
    $script:_BgSamplers.Remove($Name)
    # PowerShell pipelines wrap single-object returns in a Collection; unwrap to the actual value.
    if ($result -is [System.Collections.IList] -and $result.Count -eq 1) { return $result[0] }
    return $result
}

# ---------- brushes cache ----------
$script:Brushes = @{}
function B($hex) {
    if ($script:CliMode) { return $hex }   # CLI mode -> raw hex string
    if (-not $script:Brushes.ContainsKey($hex)) {
        $br = New-Object System.Windows.Media.SolidColorBrush([System.Windows.Media.ColorConverter]::ConvertFromString($hex))
        # Tier 48: freeze the brush so it's immutable + thread-safe + renderable cross-thread.
        # Without freezing, brushes created on a non-dispatcher thread (e.g. from job continuations
        # that hop into Add-Event) can fail to render when WPF tries to use them on the UI thread.
        # That manifested as transparent row backgrounds even though the brush object was non-null.
        try { if ($br.CanFreeze) { $br.Freeze() } } catch {}
        $script:Brushes[$hex] = $br
    }
    $script:Brushes[$hex]
}

# Tier 55: Wire-DialogEscClose adds an Esc-key handler that closes a modal dialog. WPF doesn't
# trigger window close on Escape by default - users had to click the X or Close button on every
# dialog. This adds the keyboard convention people expect. PreviewKeyDown rather than KeyDown so
# the handler fires before any focused input control consumes the key.
function Wire-DialogEscClose {
    param($Window)
    if (-not $Window) { return }
    try {
        $Window.Add_PreviewKeyDown({
            param($s, $e)
            if ($e.Key -eq [System.Windows.Input.Key]::Escape) {
                try { $s.Close() } catch {}
                $e.Handled = $true
            }
        })
    } catch {}
}

# ---------- multi-target ping slots ----------
# Up to 4 user-defined ping targets. Each slot has its own color so chart + legend stay readable.
$script:CustomTargetMaxSlots = 4
$script:CustomTargetColors   = @('#bf6dff','#7ee787','#ff9c40','#79c0ff')

function New-CustomTargetSlot {
    param([int]$Index)
    [pscustomobject]@{
        Index       = $Index
        Host        = ''
        Port        = 0       # 0 = ICMP ping, >0 = TCP-connect probe to that port
        Color       = $script:CustomTargetColors[$Index]
        Ping        = New-Object System.Net.NetworkInformation.Ping
        Task        = $null   # ICMP Ping async task
        TcpAsync    = $null   # TCP connect IAsyncResult
        TcpClient   = $null
        TcpStart    = $null   # Stopwatch for measuring TCP connect time
        History     = New-Object System.Collections.Generic.List[object]
        LossStreak  = 0
        LossWarned  = $false
    }
}

# Parse a user input like "google.com", "google.com:443", "8.8.8.8:53",
# "https://example.com/path", "http://host.com:8080" into @{Host=...; Port=...}.
function Parse-TargetSpec {
    param([string]$Raw)
    $r = @{ Host = ''; Port = 0 }
    if (-not $Raw) { return $r }
    $s = $Raw.Trim()
    # URL with scheme (http/https) - extract host+port; if no port, infer from scheme
    if ($s -match '^(https?)://([^/:\s]+)(?::(\d+))?') {
        $r.Host = $matches[2]
        if ($matches[3]) { $r.Port = [int]$matches[3] }
        elseif ($matches[1] -eq 'https') { $r.Port = 443 }
        else { $r.Port = 80 }
        return $r
    }
    # IPv4 / hostname with optional :port
    if ($s -match '^([^/:\s]+)(?::(\d+))?$') {
        $r.Host = $matches[1]
        if ($matches[2]) { $r.Port = [int]$matches[2] }
        return $r
    }
    # last resort - take whatever was given as host
    $r.Host = $s
    return $r
}

function Format-TargetSpec {
    param($Slot)
    if (-not $Slot -or -not $Slot.Host) { return '' }
    if ($Slot.Port -gt 0) { return ("{0}:{1}" -f $Slot.Host, $Slot.Port) }
    return [string]$Slot.Host
}

function Init-CustomTargetSlots {
    $arr = New-Object System.Collections.Generic.List[object]
    for ($i = 0; $i -lt $script:CustomTargetMaxSlots; $i++) { [void]$arr.Add((New-CustomTargetSlot -Index $i)) }
    $script:State.CustomTargets = $arr
}
# (Init-CustomTargetSlots is invoked after $script:State is created, below)

function Get-ActiveCustomTargets { return @($script:State.CustomTargets | Where-Object { $_.Host -and $_.Host.Trim() }) }

function Save-CustomTargetsToSettings {
    if (-not $script:State.Settings) { return }
    # Settings stores the human-readable spec (e.g. "google.com:443"), so it round-trips intact.
    $arr = @($script:State.CustomTargets | ForEach-Object { Format-TargetSpec $_ })
    $first = ($arr | Where-Object { $_ } | Select-Object -First 1)
    $script:State.Settings | Add-Member -NotePropertyName CustomTargetList -NotePropertyValue $arr -Force
    $script:State.Settings | Add-Member -NotePropertyName CustomTarget     -NotePropertyValue ([string]$first) -Force
    Save-Settings $script:State.Settings
}

function Load-CustomTargetsFromSettings {
    if (-not $script:State -or -not $script:State.Settings) { return }
    $listed = @()
    if ($script:State.Settings.CustomTargetList) {
        $listed = @($script:State.Settings.CustomTargetList | ForEach-Object { [string]$_ })
    } elseif ($script:State.Settings.CustomTarget) {
        # migrate legacy single-target setting
        $listed = @([string]$script:State.Settings.CustomTarget)
    }
    for ($i = 0; $i -lt $script:CustomTargetMaxSlots; $i++) {
        $raw = if ($i -lt $listed.Count) { [string]$listed[$i] } else { '' }
        $parsed = Parse-TargetSpec $raw
        $script:State.CustomTargets[$i].Host = $parsed.Host
        $script:State.CustomTargets[$i].Port = $parsed.Port
    }
    # Use Add-Member -Force so this works even if the NoteProperty was stripped from $script:State.
    $first = if ($script:State.CustomTargets.Count -gt 0) { [string]$script:State.CustomTargets[0].Host } else { '' }
    $script:State | Add-Member -NotePropertyName CustomTarget -NotePropertyValue $first -Force
}

