    LastPathMtu      = $null   # @{ Mtu = 1500; Payload = 1472; When = DateTime; Success = $true }

    # Tier 32: retransmit RATIO tracking (% of segments retransmitted vs sent, per window)
    # Ratio is the right metric (vs raw rate) - 5/s on a 5000/s flow = 0.1% (fine), 5/s on a 50/s flow = 10% (broken)
    PrevSegmentsSent     = $null
    PrevSegmentsResent   = $null
    RetransRatioHistory  = New-Object System.Collections.Generic.List[double]
    LastRetransSample    = $null   # @{ DeltaSent; DeltaResent; Ratio; CumSent; CumResent; CumRatio; When }

    # Tier 33: streak counter for HIGH/CRITICAL retrans verdicts. When sustained (>=3 ticks), inject
    # a synthetic cause + safe fixes so Apply Recommended Fixes has something concrete to do.
    RetransHighStreak    = 0
    RetransCauseInjected = $false

    # Tier 34: live-events pause flag. When true, Add-Event silently no-ops so the events ribbon
    # stops accumulating. Existing events stay visible. Toggled by the LIVE EVENTS Start/Stop button.
    # Tier 86: default-paused; user explicitly clicks Start to begin streaming. Symmetric with
    # FlowPaused so both feeds wait for explicit user action.
    EventsPaused         = $true
    # Rate-limit warn-tier events feeding into the activity ribbon (one alert mark per 30s max,
    # so a 5/s retransmit storm doesn't paint the ribbon solid amber).
    LastWarnMarkAt       = [DateTime]::MinValue
    # Tier 35: per-feed event filters. Each Add-Event call carries a -Source tag.
    # Sources: system / dns / flows / traffic / processes / persistence.
    # All default-enabled; user unchecks to mute noisy sources.
    EventFeedSystem      = $true
    EventFeedDns         = $true
    EventFeedFlows       = $true
    EventFeedTraffic     = $true
    EventFeedProcesses   = $true
    EventFeedPersistence = $true
    # Tier 57: text filter state - case-insensitive substring matched against the event Text field.
    # Empty = show all. Stored separately from feed checkboxes so they can be combined.
    EventTextFilter      = ''
    # Tier 36: auto-poll cadence trackers - so feeds emit autonomously instead of needing manual triggers
    LastDnsAutoPoll      = [DateTime]::MinValue   # DNS cache rescan every ~10s
    LastFlowSummary      = [DateTime]::MinValue   # FLOWS summary every ~30s
    LastTrafficSummary   = [DateTime]::MinValue   # TRAFFIC top-talker summary every ~30s
    LastSystemSummary    = [DateTime]::MinValue   # SYSTEM throughput/cpu/retrans summary every ~60s
    PrevTopTalker        = $null                  # detect top-talker changes for traffic events
    # Tier 93: TRAFFIC tab pause flag, mirrors FlowPaused. Default-paused so user clicks Start
    # before the heavy CIM-based protocol-rate + top-talker sampling kicks in.
    TrafficPaused        = $true
    LastTrafficNotableAt = [DateTime]::MinValue   # rate-limit "notable" events to LIVE EVENTS

    # Tier 28: FLOWS tab - live connection-level event stream
    # PrevFlowSnapshot key = "Proto|LocalAddr:LocalPort|RemoteAddr:RemotePort", value = @{ State; CreationTime; Pid; Proto }
    PrevFlowSnapshot = $null
    FlowFilter       = ''
    FlowPaused       = $true   # Default-paused on app open. User clicks Start (▶) to begin sampling.
                               # Tier 86: reverted Tier 85's default-running; explicit Start click is
                               # the correct UX so the user controls when CIM-heavy sampling kicks in.
    FlowMaxEvents    = 500
    LastFlowSampleStatus = '(paused - click Start)'
}

