$script:Procs       = New-Object 'System.Collections.ObjectModel.ObservableCollection[object]'
$script:PersistItems = New-Object 'System.Collections.ObjectModel.ObservableCollection[object]'
$script:DnsItems    = New-Object 'System.Collections.ObjectModel.ObservableCollection[object]'
