# Tier 92: walk the visual tree from the right-click target up to the ListViewItem and select it
# so the ListView-level ContextMenu (Tier 92) knows which row was clicked. Mirrors Tier 91's
# FlowList fix - PreviewMouseRightButtonDown fires on the down-stroke before the up-stroke pops
# the menu, so SelectedItem is correct by the time the dispatcher reads it.
$controls.EventsList.Add_PreviewMouseRightButtonDown({
    param($sender, $e)
    try {
        $node = $e.OriginalSource
        while ($node -and -not ($node -is [System.Windows.Controls.ListViewItem])) {
            $node = [System.Windows.Media.VisualTreeHelper]::GetParent($node)
        }
        if ($node -is [System.Windows.Controls.ListViewItem]) {
            $node.IsSelected = $true
        }
    } catch {}
})

# Tier 79: sortable column headers on the LIVE EVENTS GridView. Click TIME/TYPE/LEVEL/DESCRIPTION
# to sort; click again to reverse; third click clears (back to insertion-order = oldest->newest).
# State lives on the ListView itself so we don't need a script-scope global.
$controls.EventsList.Tag = @{ SortColumn = ''; SortDirection = 'Ascending' }
$controls.EventsList.AddHandler(
    [System.Windows.Controls.GridViewColumnHeader]::ClickEvent,
    [System.Windows.RoutedEventHandler]{
        param($sender, $e)
        $hdr = $e.OriginalSource
        if (-not ($hdr -is [System.Windows.Controls.GridViewColumnHeader])) { return }
        $colTitle = [string]$hdr.Content
        if ([string]::IsNullOrWhiteSpace($colTitle)) { return }
        # Map header title -> bound property on the event object.
        $sortField = switch ($colTitle) {
            'TIME'        { 'Time' }
            'TYPE'        { 'SourceLabel' }
            'LEVEL'       { 'Severity' }
            'DESCRIPTION' { 'Text' }
            default       { $null }
        }
        if (-not $sortField) { return }
        $state = $sender.Tag
        $view = [System.Windows.Data.CollectionViewSource]::GetDefaultView($sender.ItemsSource)
        if (-not $view) { return }
        # Tri-state cycle: same-column ascending -> descending -> cleared.
        if ($state.SortColumn -eq $sortField) {
            if ($state.SortDirection -eq 'Ascending') {
                $state.SortDirection = 'Descending'
                $view.SortDescriptions.Clear()
                $view.SortDescriptions.Add((New-Object System.ComponentModel.SortDescription $sortField, 'Descending'))
            } else {
                $state.SortColumn = ''
                $view.SortDescriptions.Clear()
            }
        } else {
            $state.SortColumn = $sortField
            $state.SortDirection = 'Ascending'
            $view.SortDescriptions.Clear()
            $view.SortDescriptions.Add((New-Object System.ComponentModel.SortDescription $sortField, 'Ascending'))
        }
    }
)
$controls.ProcList.ItemsSource     = $script:Procs
$controls.PersistList.ItemsSource  = $script:PersistItems
$controls.DnsList.ItemsSource      = $script:DnsItems
$controls.SessionList.ItemsSource  = $script:Sessions
$controls.CausesList.ItemsSource   = $script:Causes
if ($controls.RetransOffendersList) { $controls.RetransOffendersList.ItemsSource = $script:RetransOffenders }
if ($controls.TrafficList) { $controls.TrafficList.ItemsSource = $script:TrafficRows }
if ($controls.FlowList) {
    $controls.FlowList.ItemsSource = $script:FlowEvents
    # Defensive: ensure filter is empty at startup so all events surface initially
    if ($controls.FlowFilterBox) { $controls.FlowFilterBox.Text = '' }
    $script:State.FlowFilter = ''
    # Tier 62: prime the FLOWS list with a synthetic "ready" row directly into FlowEvents.
    # This serves two purposes: (1) confirms the ListView binding is alive on startup (if this
    # row never shows, the binding is broken); (2) gives the user a visible cue that the FLOWS
    # tab is set up and waiting for them to click Start. Bypasses Add-FlowEvent's FlowPaused
    # short-circuit since this is initialization, not a sampled event.
    try {
        $script:FlowEvents.Add([pscustomobject]@{
            Time          = (Get-Date).ToString('HH:mm:ss')
            Type          = 'READY'
            TypeColor     = (B '#bf6dff')
            Proto         = 'SYS'
            ProtoColor    = (B '#bf6dff')
            Process       = 'NetJump'
            Pid           = [int]$PID
            Name          = 'NetJump'
            Endpoint      = 'flow-sampler-ready'
            Local         = ''
            Remote        = ''
            RemoteAddress = ''
            State         = 'click Start (top right) to begin sampling TCP/UDP flow events. Double-click any row to open Connection details.'
        })
    } catch {}

    # Tier 91: walk the visual tree from the right-click target up to the ListViewItem and select
    # it. This way the ListView-level ContextMenu (Tier 91) knows which row was clicked via
    # ListView.SelectedItem - critical because right-click in WPF doesn't auto-select.
    # PreviewMouseRightButtonDown fires on the down-stroke (before the up-stroke that pops the
    # menu), so by the time the menu opens, SelectedItem is already correct.
    $controls.FlowList.Add_PreviewMouseRightButtonDown({
        param($sender, $e)
        try {
            $node = $e.OriginalSource
            while ($node -and -not ($node -is [System.Windows.Controls.ListViewItem])) {
                $node = [System.Windows.Media.VisualTreeHelper]::GetParent($node)
            }
            if ($node -is [System.Windows.Controls.ListViewItem]) {
                $node.IsSelected = $true
                try { Add-Event info ("FlowList right-click selected row Type='{0}' Pid={1}" -f [string]$node.DataContext.Type, [string]$node.DataContext.Pid) -Source 'flows' } catch {}
            } else {
                try { Add-Event info "FlowList right-click did not land on a ListViewItem (probably the column header or empty space)" -Source 'flows' } catch {}
            }
        } catch {
            try { Add-Event warn ("FlowList right-click row-select failed: {0}" -f $_.Exception.Message) -Source 'flows' } catch {}
        }
    })

    # Tier 90: double-click any row to open Connection details. Belt-and-braces fallback in case
    # the right-click ContextMenu chain breaks for any reason - double-click always works because
    # we don't rely on a popup. Also ensures the user has a visible breadcrumb in LIVE EVENTS
    # showing what fired and what row was hit.
    $controls.FlowList.Add_MouseDoubleClick({
        param($sender, $e)
        try {
            $row = $sender.SelectedItem
            try { Add-Event info ("FlowList double-click: row='{0}' Type='{1}' Pid={2} Name='{3}' Remote='{4}'" -f $(if ($row) { 'present' } else { 'NULL' }), [string]$row.Type, [string]$row.Pid, [string]$row.Name, [string]$row.RemoteAddress) -Source 'flows' } catch {}
            if (-not $row) { return }

            # Same Tier 88 guard as the right-click path: synthetic rows have Pid=$PID and Proto=SYS.
            $synthTypes = @('TICK','TRACE','HB','INIT','START','KICKSTART','READY')
            if (([string]$row.Type -in $synthTypes) -or ([string]$row.Proto -eq 'SYS')) {
                [System.Windows.MessageBox]::Show(
                    $window,
                    ("This is a sampler-status row ({0}), not a real network connection.`n`nDouble-click a green NEW row, an amber CLOSED row, a cyan STATE row, or a light-blue NOW row to see real connection details." -f [string]$row.Type),
                    'Sampler row - no connection to inspect',
                    'OK',
                    'Information'
                ) | Out-Null
                return
            }

            if (-not $row.Pid -or [int]$row.Pid -le 0) {
                [System.Windows.MessageBox]::Show($window, "This row has no process ID.", 'No PID', 'OK', 'Information') | Out-Null
                return
            }

            $detailRow = [pscustomobject]@{
                Pid             = $row.Pid
                Name            = $row.Name
                PrimaryRemoteIp = $row.RemoteAddress
            }
            try { Add-Event info ("FlowList double-click: opening dialog for {0} (pid {1}) -> {2}" -f $row.Name, $row.Pid, $row.RemoteAddress) -Source 'flows' } catch {}
            try {
                Show-ConnectionDetailsDialog -Row $detailRow
                try { Add-Event info ("FlowList double-click: dialog closed") -Source 'flows' } catch {}
            } catch {
                try { Add-Event warn ("FlowList double-click: dialog THREW: {0}" -f $_.Exception.Message) -Source 'flows' } catch {}
                [System.Windows.MessageBox]::Show($window, ("Failed to open connection details:`n`n{0}`n`n{1}" -f $_.Exception.Message, $_.ScriptStackTrace), 'Connection details error', 'OK', 'Error') | Out-Null
            }
        } catch {
            try { Add-Event warn ("FlowList double-click handler crashed: {0}" -f $_.Exception.Message) -Source 'flows' } catch {}
        }
    })
}

# ---------- mouse-wheel forwarding ----------
# WPF's nested Expander + ItemsControl absorb MouseWheel events before they reach the parent
# ScrollViewer. We attach a PreviewMouseWheel handler with handledEventsToo=$true so it runs even
# for events the inner controls have already marked Handled. The capture also targets the bubbling
# MouseWheel on the inner StackPanel so any path that doesn't go through Preview also gets caught.
if ($controls.DiagScroller) {
    $forwardWheel = [System.Windows.Input.MouseWheelEventHandler]{
        param($sender, $e)
        $sv = $controls.DiagScroller
        if (-not $sv) { return }
        $delta = [double]$e.Delta
        if ($delta -eq 0) { return }
        $step = ($delta / 120.0) * 48.0   # ~3 lines per notch at ~16px line height
        $sv.ScrollToVerticalOffset([Math]::Max(0, $sv.VerticalOffset - $step))
        $e.Handled = $true
    }
    $controls.DiagScroller.AddHandler(
        [System.Windows.UIElement]::PreviewMouseWheelEvent,
        $forwardWheel,
        $true   # handledEventsToo - run even if a child marked the event Handled
    )
    # Also catch the bubbling event in case some child uses MouseWheel (not Preview)
    $controls.DiagScroller.AddHandler(
        [System.Windows.UIElement]::MouseWheelEvent,
        $forwardWheel,
        $true
    )
}

# Tier 79: auto-scroll uses ListView.ScrollIntoView since the EventsList ListView now owns its own
# internal ScrollViewer (no more outer wrapping ScrollViewer). Wrapped in try because the new item
# isn't always immediately bound to a ListViewItem container by the time CollectionChanged fires;
# ScrollIntoView still works on the underlying item identity in that case.
$script:Events.Add_CollectionChanged({
    param($sender, $e)
    if ($e.Action -eq 'Add' -and $controls -and $controls.EventsList -and $script:Events.Count -gt 0) {
        try {
            $last = $script:Events[$script:Events.Count - 1]
            $controls.EventsList.ScrollIntoView($last)
        } catch {}
    }
})

function Add-Event {
    param(
        [ValidateSet('info','flap-down','flap-up','loss','recovery','fix','scan','warn')]
        [string]$Type,
        [string]$Text,
        [ValidateSet('system','dns','flows','traffic','processes','persistence')]
        [string]$Source = 'system',
        [string]$Detail = '',   # Optional second line (italic, muted, smaller font) for richer context
        [ValidateSet('','CRITICAL','HIGH','LOW','OK','MEDIUM')]   # Tier 79: 4-tier display (CRITICAL/HIGH/LOW/OK); MEDIUM still accepted for back-compat and is silently remapped to LOW.
        [string]$Severity = ''
    )
    # Use $null -eq for the existence check, NOT '-not'.
    # PowerShell's '-not' coerces collections to bool by Count, so an EMPTY ObservableCollection
    # returns $true for '-not', meaning Add-Event silently returned for every call when the
    # collection was empty - which meant the very first event never got added, and no events
    # ever appeared in the ribbon or the events log dialog.
    if ($script:CliMode) { return }
    if ($null -eq $script:Events) { return }
    # Tier 34: respect the user-toggled pause flag from the LIVE EVENTS Start/Stop button.
    # When paused, no new events are added (existing list is preserved).
    if ($script:State -and $script:State.EventsPaused) { return }
    # Tier 41: when caller didn't pass -Source explicitly (it defaulted to 'system'), auto-infer
    # the source from the message text so each event self-tags to the right feed instead of all
    # falling through to the gray "SYS" default. This is what makes events visually color-coordinate
    # with their tabs - a "DNS resolver flushed" message picks up the purple DNS color, a "TCP
    # connection established" message picks up cyan FLOWS, etc. Strong-keyword regex only - ambiguous
    # text stays 'system'.
    if ($Source -eq 'system') {
        if     ($Text -match '(?i)\bDNS\b|\bresolv|\bnslookup\b|\bhosts file\b|\bNRPT\b|\bipconfig /flushdns\b') { $Source = 'dns' }
        elseif ($Text -match '(?i)\bflow\b|\bnew conn(ection)?\b|\bTCP\s+(conn|connection)|\bUDP\s+(conn|connection)|\b(close_wait|fin_wait|syn_sent|syn_received|established|listen)\b|TCP retrans|TCP/IP stack') { $Source = 'flows' }
        elseif ($Text -match '(?i)\bthroughput\b|\bbandwidth\b|\bRX/TX\b|\btop talker\b|\b(kbps|mbps|gbps|bytes/s)\b|\bprotocol mix\b') { $Source = 'traffic' }
        elseif ($Text -match '(?i)\bkill(ed)? (pid|process)\b|\bcmdline\b|\borphan(ed)?( process)?\b|\bsuspicious (process|exe(cutable)?)\b|\bprocess scan\b|\bkilled process\b') { $Source = 'processes' }
        elseif ($Text -match '(?i)\bpersistence\b|\brun\s?key\b|\bregistry autorun\b|\bscheduled task\b|\bautorun\b|\bstartup item\b|\bservice install\b|\bauto-?start\b') { $Source = 'persistence' }
        # else: stays 'system' (gray) - genuine diagnostic / scan / kill-switch / ARP / fix-bundle events
    }

    # Tier 35: respect per-feed filter flags. Each event carries a Source tag; events whose source
    # has been unchecked in the LIVE EVENTS feed selector silently no-op.
    if ($script:State) {
        $allowed = switch ($Source) {
            'dns'         { $script:State.EventFeedDns }
            'flows'       { $script:State.EventFeedFlows }
            'traffic'     { $script:State.EventFeedTraffic }
            'processes'   { $script:State.EventFeedProcesses }
            'persistence' { $script:State.EventFeedPersistence }
            default       { $script:State.EventFeedSystem }
        }
        if (-not $allowed) { return }
        # Tier 57: text filter - if user has typed something into EventFilterBox, only events whose
        # Text field matches the substring (case-insensitive) get added. Source label is appended so
        # filtering by "DNS" or "FLW" works too. Empty filter (the default) admits everything.
        $tf = [string]$script:State.EventTextFilter
        if ($tf) {
            $haystack = "$Source $Text"
            if (-not ($haystack -like ("*" + $tf + "*"))) { return }
        }
    }
    # Severity color (Type) drives the left-edge bar
    $color = switch ($Type) {
        'flap-down' { '#f85149' }
        'flap-up'   { '#3fb950' }
        'loss'      { '#d29922' }
        'recovery'  { '#3fb950' }
        'fix'       { '#58a6ff' }
        'scan'      { '#8b95a8' }
        'warn'      { '#d29922' }
        default     { '#8b95a8' }
    }
    # Tier 79: Source color (used as the TYPE column cell background in the new ListView/GridView
    # layout). Same palette as before - color is the user-confirmed coordination signal. Source
    # label is now medium-length plain text (no emoji prefix), centered inside the colored cell.
    $sourceHex = switch ($Source) {
        'dns'         { '#bf6dff' }   # purple
        'flows'       { '#58a6ff' }   # cyan
        'traffic'     { '#d29922' }   # amber
        'processes'   { '#79c0ff' }   # light blue
        'persistence' { '#ff9c40' }   # orange
        default       { '#6a7380' }   # neutral gray for system
    }
    $sourceLabel = switch ($Source) {
        'dns'         { 'DNS' }
        'flows'       { 'FLOWS' }
        'traffic'     { 'TRAFC' }
        'processes'   { 'PROCS' }
        'persistence' { 'PERSI' }
        default       { 'SYSTM' }
    }
    # Severity tier - either explicitly set via -Severity, auto-detected from text keywords, or
    # inferred from event Type. Tier 41 changes:
    #   1. Severity is now also auto-derived from Type (flap-down=HIGH, warn=MEDIUM, fix=OK, etc.)
    #      so warn/flap rows reliably get their tier color even when the message body doesn't
    #      include the literal severity word.
    #   2. Palette redone to a traffic-light ramp: LOW is YELLOW (was green), MEDIUM is ORANGE
    #      (was amber), HIGH is RED-ORANGE so it's clearly hotter than MEDIUM, CRITICAL is RED,
    #      OK stays GREEN.
    # Tier 79: 4-tier severity (CRITICAL / HIGH / LOW / OK). MEDIUM was the noisy middle - merged
    # into LOW so warn/loss-class events that aren't outright HIGH still get a colored level cell.
    # Severity keyword scan in the body text still fires - any of the legacy MEDIUM synonyms
    # (MEDIUM/ELEVATED/MODERATE) AND the bare LOW/NORMAL all map to LOW so existing call-sites
    # continue to work.
    $sev = $Severity
    if ($sev -eq 'MEDIUM') { $sev = 'LOW' }   # back-compat for explicit -Severity 'MEDIUM' calls
    if (-not $sev) {
        if ($Text -match '\b(CRITICAL)\b') { $sev = 'CRITICAL' }
        elseif ($Text -match '\b(HIGH)\b') { $sev = 'HIGH' }
        elseif ($Text -match '\b(MEDIUM|ELEVATED|MODERATE|LOW|NORMAL)\b') { $sev = 'LOW' }
        elseif ($Text -match '\b(OK|EXCELLENT|HEALTHY)\b') { $sev = 'OK' }
        # Type-derived defaults when neither -Severity nor a keyword in the body specified one
        if (-not $sev) {
            $sev = switch ($Type) {
                'flap-down' { 'HIGH' }
                'flap-up'   { 'OK' }
                'recovery'  { 'OK' }
                'fix'       { 'OK' }
                'loss'      { 'LOW' }
                'warn'      { 'LOW' }
                default     { '' }   # info / scan stay unspecified
            }
        }
    }
    $sevHex = switch ($sev) {
        'CRITICAL' { '#f85149' }   # red
        'HIGH'     { '#ff6b35' }   # red-orange
        'LOW'      { '#ff9c40' }   # orange (former MEDIUM color - LOW absorbed it)
        'OK'       { '#3fb950' }   # green
        default    { '' }
    }
    # Tier 79: streamlined event object for the new ListView/GridView layout.
    # Properties consumed by the GridView CellTemplates:
    #   Time              -> TIME column
    #   SourceLabel       -> TYPE column text (e.g. "DNS", "FLOWS")
    #   SourceColor       -> TYPE column cell background
    #   Severity          -> LEVEL column text (e.g. "CRITICAL", "HIGH", "LOW", "OK")
    #   SeverityColor     -> LEVEL column cell background
    #   SeverityVisibility-> hides the LEVEL pill for events without a severity (info / scan)
    #   Text              -> DESCRIPTION column primary line
    #   Detail            -> DESCRIPTION column secondary italic line
    #   DetailVisibility  -> hides Detail line when not provided
    # Properties retained but no longer rendered (legacy / right-click handler / CSV export):
    #   Source, Color (Type-derived left-bar color from the old design)
    $script:Events.Add([pscustomobject]@{
        Time              = (Get-Date).ToString('HH:mm:ss')
        Color             = (B $color)
        Text              = $Text
        Source            = $Source
        SourceLabel       = $sourceLabel
        SourceColor       = (B $sourceHex)
        Detail            = $Detail
        DetailVisibility  = if ($Detail) { 'Visible' } else { 'Collapsed' }
        Severity          = $sev
        SeverityColor     = if ($sevHex) { (B $sevHex) } else { (B '#6a7380') }
        SeverityVisibility = if ($sev) { 'Visible' } else { 'Collapsed' }
    })
    # cap at 500 entries
    while ($script:Events.Count -gt 500) { $script:Events.RemoveAt(0) }

    # Tier 34: feed warn-tier events into the activity ribbon as 'alert' dots so the 60m timeline
    # is populated even between flaps/scans. Rate-limited: at most one mark per 30s for a given
    # warn signal class so a 5/s retransmit storm doesn't paint the ribbon solid amber.
    if ($Type -eq 'warn') {
        try {
            if (-not $script:State.LastWarnMarkAt) { $script:State.LastWarnMarkAt = [DateTime]::MinValue }
            if (((Get-Date) - $script:State.LastWarnMarkAt).TotalSeconds -ge 30) {
                Add-ActivityMark alert
                $script:State.LastWarnMarkAt = Get-Date
            }
        } catch {}
    }
}

function Add-Finding {
    param($Level,$Category,$Message,$Fix='',$Detail='',$Mitre='')
    $color = switch ($Level) {
        'OK'   { '#3fb950' }
        'INFO' { '#58a6ff' }
        'WARN' { '#d29922' }
        'FAIL' { '#f85149' }
        default { '#8b95a8' }
    }
    $vis = if ($Fix) { 'Visible' } else { 'Collapsed' }
    # ATT&CK lookup
    $attack = Get-AttackTag $Mitre
    $mitreId = if ($attack) { $attack.Id }   else { '' }
    $mitreName = if ($attack) { $attack.Name } else { '' }
    $mitreVis = if ($attack) { 'Visible' }   else { 'Collapsed' }
    # tooltip = explanation + fix + ATT&CK (visible on hover only)
    $tip = ''
    if ($Detail)  { $tip = $Detail }
    if ($attack)  { if ($tip) { $tip += "`n`n" } ; $tip += "ATT&CK: $($attack.Id) - $($attack.Name)" }
    if ($Fix)     { if ($tip) { $tip += "`n`nFix: $Fix" } else { $tip = "Fix: $Fix" } }
    if (-not $tip) { $tip = "$Category - $Message" }
    [pscustomobject]@{
        Level        = $Level
        Category     = $Category
        Message      = $Message
        Fix          = if ($Fix) { "Fix: $Fix" } else { '' }
        Detail       = $Detail
        Tip          = $tip
        LevelColor   = (B $color)
        FixVisibility = $vis
        MitreId       = $mitreId
        MitreName     = $mitreName
        MitreVisibility = $mitreVis
    }
}

# ---------- diagnostics ----------
function Invoke-Diagnostics {
    $findings = New-Object System.Collections.Generic.List[object]
    $fixes    = New-Object System.Collections.Generic.List[object]

    $adapter = $script:State.Adapter
    if (-not $adapter) {
        $findings.Add((Add-Finding 'FAIL' 'Adapter' 'No ethernet adapter found.'))
        return @{ Findings = $findings; Fixes = $fixes }
    }

    # Per-section try/catches so any single check failing can't wipe out the rest.
    # $diagStage holds the name of whatever section is currently running so the
    # outer warn-breadcrumb tells us exactly which one threw.
    $diagStage = 'init'

    $diagStage = 'link state'
    try {
        if ($adapter.Status -eq 'Up') {
            $findings.Add((Add-Finding 'OK' 'Link' ("{0} is UP at {1}" -f $adapter.Name, $adapter.LinkSpeed)))
        } else {
            $findings.Add((Add-Finding 'FAIL' 'Link' ("{0} is {1}" -f $adapter.Name, $adapter.Status) 'Check the cable, try another port.'))
        }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    $diagStage = 'advanced power-saving'
    $props = $null
    try { $props = Get-NetAdapterAdvancedProperty -Name $adapter.Name -ErrorAction SilentlyContinue }
    catch { try { Add-Event warn ("Diag '$diagStage' query failed: $($_.Exception.Message)") } catch {} }
    try {
    $culprits = @(
        @{ Match='Energy.*Efficient|^EEE|Ultra\s*Low\s*Power'; Friendly='Energy-Efficient Ethernet'; Detail='IEEE 802.3az / EEE puts the link into a low-power idle state when traffic is light. Bugs in the wake-up handshake between the NIC and switch are a leading cause of repeated link flaps on Windows. Disabling forces full-power mode and almost always stops EEE-induced flaps.' }
        @{ Match='Green\s*Ethernet';                           Friendly='Green Ethernet';            Detail='A driver-level power-saving feature similar to EEE that drops link state on detected idle. Realtek and Intel NICs with this enabled are notorious for short, repeated drops.' }
        @{ Match='Power\s*Saving\s*Mode';                      Friendly='Power Saving Mode';         Detail='Generic NIC power-saving option. Disable for a wired desktop where saving 0.1W is not worth random drops.' }
        @{ Match='Gigabit\s*Lite';                             Friendly='Gigabit Lite';              Detail='A power-saving mode that downshifts a 1 Gbps link to 100 Mbps when idle. Negotiation back up to 1 Gbps can fail under load and cause drops; better to force constant 1 Gbps.' }
        @{ Match='Advanced\s*EEE';                             Friendly='Advanced EEE';              Detail='Vendor-specific extended EEE feature. Same reasoning as EEE - disable on flap-prone setups.' }
    )
    $enabledCount = 0
    foreach ($c in $culprits) {
        $hit = $props | Where-Object { ($_.DisplayName -match $c.Match -or $_.RegistryKeyword -match $c.Match) -and $_.DisplayValue -match 'Enabled|On' }
        foreach ($h in $hit) {
            $enabledCount++
            $findings.Add((Add-Finding 'WARN' 'Power' ("{0} = {1}" -f $h.DisplayName, $h.DisplayValue) 'Driver power-saving feature. Common cause of flapping.' $c.Detail))
            $fixes.Add([pscustomobject]@{
                Description = "Disable '$($h.DisplayName)' on $($adapter.Name)"
                Command     = "Set-NetAdapterAdvancedProperty -Name '$($adapter.Name)' -DisplayName '$($h.DisplayName)' -DisplayValue 'Disabled'"
            })
        }
    }
    if ($enabledCount -eq 0 -and $props) {
        $findings.Add((Add-Finding 'OK' 'Power' 'All driver power-saving features are disabled.'))
    }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    # --- device-manager power management ---
    $diagStage = 'power-management'
    try {
    $pm = Get-NetAdapterPowerManagement -Name $adapter.Name -ErrorAction SilentlyContinue
    if ($pm -and $pm.AllowComputerToTurnOffDevice -eq 'Enabled') {
        $findings.Add((Add-Finding 'WARN' 'Power' "Windows is allowed to power down the NIC." `
            "Uncheck 'Allow the computer to turn off this device' in Device Manager." `
            "When this is enabled, Windows can selectively suspend the NIC to save power. On wake, the link must renegotiate which often manifests as a brief flap. The setting lives in Device Manager - Network adapters - <NIC> - Properties - Power Management. Reversal: Enable-NetAdapterPowerManagement -Name '$($adapter.Name)' -AllowComputerToTurnOffDevice"))
        $fixes.Add([pscustomobject]@{
            Description = "Prevent Windows from powering down '$($adapter.Name)'"
            Command     = "Disable-NetAdapterPowerManagement -Name '$($adapter.Name)' -AllowComputerToTurnOffDevice"
        })
    } elseif ($pm) {
        $findings.Add((Add-Finding 'OK' 'Power' 'Windows cannot power down the NIC.'))
    }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    # --- driver age ---
    $diagStage = 'driver age'
    try {
    $dd = $null
    if ($adapter.DriverDate) {
        try { $dd = [datetime]$adapter.DriverDate } catch { try { $dd = Get-Date $adapter.DriverDate } catch {} }
    }
    if ($adapter.DriverDate -and $dd) {
        $age = ((Get-Date) - $dd).TotalDays / 365.25
        $driverDetail = "Outdated NIC drivers are a top cause of intermittent ethernet issues, especially on Realtek and Intel I219/I225/I226 chipsets. Windows Update often serves an older 'best match' driver - go directly to the chipset manufacturer's download page (Intel, Realtek, Killer/Rivet, etc.) to get the latest. Match the driver to your specific NIC model, not just the generic family."
        if ($age -gt 3) {
            $findings.Add((Add-Finding 'WARN' 'Driver' ("Driver is {0:N1} years old ({1})." -f $age, $adapter.DriverVersionString) "Update from vendor site (chipset: $($adapter.InterfaceDescription))" $driverDetail))
        } elseif ($age -gt 1.5) {
            $findings.Add((Add-Finding 'INFO' 'Driver' ("Driver is {0:N1} years old." -f $age) '' $driverDetail))
        } else {
            $findings.Add((Add-Finding 'OK' 'Driver' ("Driver age {0:N1} years ({1})." -f $age, $adapter.DriverVersionString)))
        }
    }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    # --- error counters ---
    $diagStage = 'error counters'
    $s = $null
    try { $s = Get-NetAdapterStatistics -Name $adapter.Name -ErrorAction SilentlyContinue }
    catch { try { Add-Event warn ("Diag '$diagStage' query failed: $($_.Exception.Message)") } catch {} }
    try {
    if ($s) {
        $rxErr = [int64]$s.ReceivedDiscardedPackets + [int64]$s.ReceivedPacketErrors
        $rxPkts = [int64]$s.ReceivedUnicastPackets + [int64]$s.ReceivedMulticastPackets + [int64]$s.ReceivedBroadcastPackets
        $ratio = if ($rxPkts -gt 0) { $rxErr / $rxPkts } else { 0 }
        if ($ratio -gt 0.001) {
            $findings.Add((Add-Finding 'FAIL' 'Counters' ("RX error rate {0:P3} - physical layer issue." -f $ratio) 'Swap the cable and try a different port on the switch/router.'))
        } elseif ($rxErr -gt 100) {
            $findings.Add((Add-Finding 'WARN' 'Counters' ("{0} RX errors/discards accumulated." -f $rxErr)))
        } else {
            $findings.Add((Add-Finding 'OK' 'Counters' 'RX error counters clean.'))
        }
    }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    # --- event log flap history (72h) ---
    $diagStage = 'flap history'
    try {
    $since = (Get-Date).AddHours(-72)
    $events = Get-WinEvent -FilterHashtable @{LogName='System'; StartTime=$since} -MaxEvents 500 -ErrorAction SilentlyContinue |
              Where-Object { $_.Message -match 'disconnect|link\s+down|media.*disconnected' }
    if ($events.Count -ge 5) {
        $findings.Add((Add-Finding 'FAIL' 'History' ("{0} link-down events in last 72h - flapping confirmed." -f $events.Count) 'Fix power-saving first (button below), then swap the cable if it continues.'))
    } elseif ($events.Count -gt 0) {
        $findings.Add((Add-Finding 'WARN' 'History' ("{0} link-down event(s) in last 72h." -f $events.Count)))
    } else {
        $findings.Add((Add-Finding 'OK' 'History' 'No link-down events in System log (72h).'))
    }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    # --- NDIS filter drivers (VPN / AV / malware) ---
    $diagStage = 'NDIS filters'
    try {
    $knownGood = @('ms_msclient','ms_pacer','ms_server','ms_lldp','ms_rspndr','ms_lltdio',
        'ms_tcpip6','ms_tcpip','ms_implat','ms_ndisuio','ms_wfplwfs','ms_wfplwf_upper','ms_wfplwf_lower',
        'ms_netbios','ms_bridgemp','ms_ndiscap','ms_hypernet')
    $oddBind = Get-NetAdapterBinding -Name $adapter.Name -ErrorAction SilentlyContinue |
               Where-Object { $_.Enabled -and $_.ComponentID -notin $knownGood }
    if ($oddBind) {
        foreach ($b in $oddBind) {
            $findings.Add((Add-Finding 'INFO' 'Filters' ("Non-standard NDIS filter: {0} ({1})" -f $b.DisplayName, $b.ComponentID) 'Usually a VPN or AV. Disable temporarily if flapping persists after fixes.'))
        }
    } else {
        $findings.Add((Add-Finding 'OK' 'Filters' 'No non-standard NDIS filters attached.'))
    }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    # --- DNS ---
    $diagStage = 'DNS resolution'
    try {
    $dnsTest = 'www.cloudflare.com'
    $sw = [Diagnostics.Stopwatch]::StartNew()
    $r = Resolve-DnsName $dnsTest -Type A -ErrorAction SilentlyContinue | Select-Object -First 1
    $sw.Stop()
    if ($r) {
        $ms = $sw.ElapsedMilliseconds
        if ($ms -gt 500) {
            $findings.Add((Add-Finding 'WARN' 'DNS' ("Slow DNS resolve: {0}ms ({1})" -f $ms, $dnsTest)))
        } else {
            $findings.Add((Add-Finding 'OK' 'DNS' ("Resolved {0} in {1}ms" -f $dnsTest, $ms)))
        }
    } else {
        $findings.Add((Add-Finding 'FAIL' 'DNS' ("Cannot resolve {0}" -f $dnsTest) 'Run: ipconfig /flushdns. If still broken, set DNS to 1.1.1.1.'))
    }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    # --- services ---
    $diagStage = 'services'
    try {
    $mustRun = @('Dhcp','Dnscache','nsi')
    $badSvc = @()
    foreach ($svc in $mustRun) {
        $s = Get-Service $svc -ErrorAction SilentlyContinue
        if ($s -and $s.Status -ne 'Running') { $badSvc += "$($s.DisplayName) ($svc)" }
    }
    if ($badSvc) {
        $findings.Add((Add-Finding 'WARN' 'Services' ("Stopped: {0}" -f ($badSvc -join ', ')) "Start-Service $($badSvc[0])"))
    } else {
        $findings.Add((Add-Finding 'OK' 'Services' 'Core network services running.'))
    }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    # --- ARP sanity ---
    $diagStage = 'ARP'
    try {
    $arp = Get-NetNeighbor -AddressFamily IPv4 -ErrorAction SilentlyContinue |
        Where-Object {
            $_.State -in 'Reachable','Stale','Permanent' -and
            $_.LinkLayerAddress -and
            $_.LinkLayerAddress -ne '00-00-00-00-00-00' -and
            $_.LinkLayerAddress -ne 'FF-FF-FF-FF-FF-FF' -and
            $_.LinkLayerAddress -notmatch '^(01-00-5E|33-33)' -and
            $_.IPAddress -notmatch '^(224\.|225\.|226\.|227\.|228\.|229\.|23\d\.|255\.)'
        }
    $dupMac = $arp | Group-Object LinkLayerAddress | Where-Object Count -gt 1
    if ($dupMac) {
        foreach ($g in $dupMac) {
            $findings.Add((Add-Finding 'WARN' 'ARP' ("MAC {0} has multiple IPs" -f $g.Name) 'Possible VM bridge, or ARP spoofing on the LAN.' '' 'arp-spoof'))
        }
    } else {
        $findings.Add((Add-Finding 'OK' 'ARP' ("ARP table clean ({0} unicast entries)" -f $arp.Count)))
    }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    # --- recent Windows updates ---
    $diagStage = 'hotfix'
    try {
    # Get-HotFix's InstalledOn can be DateTime, string, or null depending on the KB. Comparing
    # 'string -gt DateTime' throws "Argument types do not match" in PowerShell. Coerce safely.
    $cutoff = (Get-Date).AddDays(-14)
    $hotfix = Get-HotFix -ErrorAction SilentlyContinue | Where-Object {
        try {
            $when = $null
            if ($_.InstalledOn -is [datetime]) { $when = $_.InstalledOn }
            elseif ($_.InstalledOn) { $when = [datetime]::Parse([string]$_.InstalledOn) }
            $when -and $when -gt $cutoff
        } catch { $false }
    }
    if ($hotfix) {
        $findings.Add((Add-Finding 'INFO' 'Updates' ("{0} Windows update(s) in last 14 days." -f $hotfix.Count) 'If flapping started right after an update, roll back the NIC driver in Device Manager.'))
    }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    # --- Tier 6: Wi-Fi survey (only if a Wi-Fi adapter is up) ---
    $diagStage = 'wifi survey'
    try {
    $wifi = Get-WiFiSurvey
    if ($wifi) {
        $wifiMsg = "Wi-Fi: {0}" -f $wifi.SSID
        $detail = New-Object System.Collections.ArrayList
        if ($wifi.Signal)  { [void]$detail.Add("signal $($wifi.Signal)%") }
        if ($wifi.Channel) { [void]$detail.Add("ch $($wifi.Channel)") }
        if ($wifi.Radio)   { [void]$detail.Add($wifi.Radio) }
        if ($wifi.RxMbps)  { [void]$detail.Add("$($wifi.RxMbps) Mbps") }
        if ($detail.Count) { $wifiMsg += " (" + ($detail -join ', ') + ")" }
        $level = if ($wifi.Signal -and $wifi.Signal -lt 40) { 'WARN' } else { 'INFO' }
        $findings.Add((Add-Finding $level 'WiFi' $wifiMsg `
            $(if ($level -eq 'WARN') { 'Move closer to the AP or check for interference.' } else { '' }) `
            "Wi-Fi info shown for context only - your primary issue is on the wired adapter. But shared 2.4 GHz RF (microwave, BT pairing) and combo Wi-Fi/Ethernet chips can cause USB resets that affect both."))
    }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    # --- Tier 2: switch / upstream device vendor (gateway MAC OUI lookup) ---
    $diagStage = 'gateway vendor'
    try {
    if ($script:State.Gateway) {
        $gwNeighbor = Get-NetNeighbor -IPAddress $script:State.Gateway -ErrorAction SilentlyContinue |
                      Where-Object { $_.LinkLayerAddress -and $_.LinkLayerAddress -ne '00-00-00-00-00-00' } |
                      Select-Object -First 1
        if ($gwNeighbor) {
            $vendor = Get-VendorFromMac $gwNeighbor.LinkLayerAddress
            if ($vendor) {
                $findings.Add((Add-Finding 'INFO' 'Upstream' ("Gateway is probably a {0} device (MAC {1})" -f $vendor, $gwNeighbor.LinkLayerAddress) "Check that vendor's documentation / firmware page if flapping persists after fixing power-saving."))
            } else {
                $findings.Add((Add-Finding 'INFO' 'Upstream' ("Gateway MAC {0} (vendor unknown to local OUI table)" -f $gwNeighbor.LinkLayerAddress)))
            }
        }
    }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    # --- Tier 2: cable health score (synthesized from speed / errors / flaps) ---
    $diagStage = 'cable health'
    try {
    if ($adapter -and $adapter.Status -eq 'Up') {
        $score = 100
        $reasons = New-Object System.Collections.Generic.List[string]

        # speed downgrade
        $desc = $adapter.InterfaceDescription.ToLower()
        $speed = [int64]$adapter.Speed
        $is25g  = ($desc -match '2\.5\s*g|2500|i225|i226|rtl812|rtl813')
        $is1g   = ($desc -match 'gigabit|1000|gbe|gb-e|i210|i211|i217|i218|i219|i225|i226|rtl811|rtl812|rtl813')
        if ($is25g  -and $speed -gt 0 -and $speed -lt 2500000000) {
            $score -= 30; $reasons.Add("speed negotiated $($adapter.LinkSpeed) on a 2.5G NIC")
        } elseif ($is1g -and $speed -gt 0 -and $speed -lt 1000000000) {
            $score -= 30; $reasons.Add("speed negotiated $($adapter.LinkSpeed) on a 1G NIC (broken pair?)")
        }

        # error counters
        if ($s) {
            if ($s.ReceivedPacketErrors -gt 100)    { $score -= 25; $reasons.Add("$($s.ReceivedPacketErrors) RX errors") }
            elseif ($s.ReceivedPacketErrors -gt 10) { $score -= 10; $reasons.Add("$($s.ReceivedPacketErrors) RX errors") }
            if ($s.ReceivedDiscardedPackets -gt 1000)    { $score -= 15; $reasons.Add("$($s.ReceivedDiscardedPackets) RX discards") }
            elseif ($s.ReceivedDiscardedPackets -gt 100) { $score -= 5;  $reasons.Add("$($s.ReceivedDiscardedPackets) RX discards") }
        }

        # 72h flap count
        if ($events.Count -ge 5)   { $score -= 20; $reasons.Add("$($events.Count) flaps in 72h") }
        elseif ($events.Count -gt 0) { $score -= 5; $reasons.Add("$($events.Count) flap(s) in 72h") }

        if ($score -lt 0) { $score = 0 }
        $level = if ($score -ge 80) { 'OK' } elseif ($score -ge 50) { 'WARN' } else { 'FAIL' }
        $msg = if ($reasons.Count) { "Cable health: {0}/100 ({1})" -f $score, ($reasons -join '; ') } else { "Cable health: {0}/100" -f $score }
        $fix = if ($score -lt 80) { 'Swap to a known-good Cat5e/Cat6 cable, try a different switch port. Re-check after.' } else { '' }
        $cableDetail = "Score is synthesized from: negotiated speed vs NIC capability (a 1 Gbps NIC running at 100 Mbps usually means a broken cable pair), accumulated RX errors and discards, and link-down events in the Windows System log over 72h. A score below 80 with any of those flags warrants a physical layer test - swap to a fresh Cat5e/Cat6 cable and try a different port."
        $findings.Add((Add-Finding $level 'Cable' $msg $fix $cableDetail))
    }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    # --- malware indicators ---
    $diagStage = 'malware indicators'
    try {
    $hostsPath = "$env:SystemRoot\System32\drivers\etc\hosts"
    $hostsLines = Get-Content $hostsPath -ErrorAction SilentlyContinue | Where-Object { $_ -and $_ -notmatch '^\s*#' -and $_.Trim() }
    if ($hostsLines) {
        $findings.Add((Add-Finding 'WARN' 'Malware' ("{0} active entries in hosts file" -f $hostsLines.Count) "Open $hostsPath to review." '' 'hosts-tamper'))
    } else {
        $findings.Add((Add-Finding 'OK' 'Malware' 'Hosts file clean.'))
    }
    $px = Get-ItemProperty 'HKCU:\Software\Microsoft\Windows\CurrentVersion\Internet Settings' -ErrorAction SilentlyContinue
    if ($px -and $px.ProxyEnable -eq 1 -and $px.ProxyServer) {
        $findings.Add((Add-Finding 'WARN' 'Malware' ("System proxy set: {0}" -f $px.ProxyServer) 'Disable in Settings > Network > Proxy if you did not set it.' '' 'proxy-hijack'))
    } else {
        $findings.Add((Add-Finding 'OK' 'Malware' 'No system proxy hijack detected.'))
    }
    $mp = Get-MpComputerStatus -ErrorAction SilentlyContinue
    if ($mp) {
        if (-not $mp.RealTimeProtectionEnabled) {
            $findings.Add((Add-Finding 'WARN' 'Malware' 'Defender real-time protection OFF.' '' '' 'defender-off'))
        } elseif ($mp.AntivirusSignatureAge -gt 7) {
            $findings.Add((Add-Finding 'WARN' 'Malware' ("Defender signatures {0} days old." -f $mp.AntivirusSignatureAge) 'Update-MpSignature'))
        } else {
            $findings.Add((Add-Finding 'OK' 'Malware' ("Defender healthy (sigs {0}d old)" -f $mp.AntivirusSignatureAge)))
        }
    }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    # --- summary at top ---
    $diagStage = 'summary'
    try {
    if ($fixes.Count -eq 0) {
        $findings.Insert(0, (Add-Finding 'OK' 'Summary' 'No auto-fixable issues. If flapping continues, swap the ethernet cable next.'))
    } else {
        $findings.Insert(0, (Add-Finding 'INFO' 'Summary' ("Found {0} power-saving setting(s). Click 'Apply recommended fixes' to disable." -f $fixes.Count)))
    }
    } catch { try { Add-Event warn ("Diag '$diagStage' failed: $($_.Exception.Message)") } catch {} }

    return @{ Findings = $findings; Fixes = $fixes }
}

function Update-HeroVisuals {
    if (-not $controls -or -not $controls.HealthGrade) { return }
    $h = Compute-HealthScore
    $controls.HealthGrade.Text   = $h.Grade
    $controls.HealthScore.Text   = "$($h.Score) / 100"
    $controls.HealthVerdict.Text = $h.Verdict
    $controls.HealthGrade.Foreground = (B $h.Color)
    $controls.HealthScore.Foreground = (B $h.Color)
    $controls.GradeBorder.Background = (B $h.Glow)
    $controls.GradeBorder.BorderBrush = (B $h.Color)
    # top-cause tile
    if ($script:Causes -and $script:Causes.Count -gt 0) {
        $top = $script:Causes[0]
        $controls.TopCauseText.Text = ("{0}  {1}" -f $top.ConfidenceLabel, ($top.Cause -split ' \(')[0])
    } else {
        $controls.TopCauseText.Text = 'no signal yet'
    }
    # flap trend arrow vs last 60 sec of GwHistory loss markers
    if ($script:State.GwHistory.Count -ge 6) {
        $lossSeries = New-Object System.Collections.Generic.List[double]
        foreach ($v in $script:State.GwHistory) { [void]$lossSeries.Add($(if ($null -eq $v) { 1.0 } else { 0.0 })) }
        $arrow = Get-TrendArrow $lossSeries 0.2
        $controls.FlapsTrend.Text = $arrow
        $controls.FlapsTrend.Foreground = (B (Get-TrendColor $arrow $true))
    }
}

function Pulse-Hero {
    param([string]$Hex = '#f85149')
    if (-not $controls.DotGlow) { return }
    try {
        $brush = (B $hex)
        $controls.DotGlow.Fill     = $brush
        $controls.GradeBorder.BorderBrush = $brush
        $a1 = New-Object System.Windows.Media.Animation.DoubleAnimation(0.85, 0.2, [TimeSpan]::FromMilliseconds(800))
        $a1.AutoReverse = $true
        $a1.RepeatBehavior = [System.Windows.Media.Animation.RepeatBehavior]::new(2)
        $controls.DotGlow.BeginAnimation([System.Windows.Shapes.Ellipse]::OpacityProperty, $a1)
    } catch {}
}

$script:_ScanInProgress = $false
$script:_ScanStartedAt   = $null

# Dispatcher-yield: lets the UI repaint between heavy synchronous sections of the scan so
# Status text updates and ping bar refreshes are visible during a long scan (would otherwise
# freeze for 20-60s while CIM/registry/feature queries run inline on the dispatcher).
# Also tracks the last-set status as a stage marker so the catch-block can pinpoint the failing section.
$script:_ScanStage = ''

# Wrap a scan-section in try/catch + log-on-failure so a single section can't kill the whole scan.
# Returns whatever the script block returned, or $null if it threw.
function _ScanSection {
    param([string]$Name, [scriptblock]$Body)
    try {
        & $Body
    } catch {
        try { Add-Event warn ("Scan section '{0}' failed: {1}" -f $Name, $_.Exception.Message) } catch {}
        try { Write-Host "Scan section '$Name' failed: $_`n$($_.ScriptStackTrace)" } catch {}
        return $null
    }
}

function _ScanYield {
    param([string]$Status)
    if ($Status) { $script:_ScanStage = $Status }
    if ($Status -and $controls.ScanStatus) {
        try { $controls.ScanStatus.Text = $Status } catch {}
    }
    try {
        $frame = New-Object System.Windows.Threading.DispatcherFrame
        $window.Dispatcher.BeginInvoke([System.Windows.Threading.DispatcherPriority]::Background, [Action]{ $frame.Continue = $false }) | Out-Null
        [System.Windows.Threading.Dispatcher]::PushFrame($frame)
    } catch {}
}

function Update-Findings {
    # Re-entrancy guard: this function can be triggered from RescanButton, F5, Ctrl+R, after-fix verify,
    # adapter-switch, and post-flap rescan. Two overlapping invocations would race on $script:Findings,
    # the per-bucket ObservableCollections, and the RecommendedFixes list.
    if ($script:_ScanInProgress) {
        # Stuck-flag detection: if a previous scan has been "in progress" for >120 sec it's almost
        # certainly stuck (or the finally{} never ran due to an unhandled exception type). Auto-clear
        # so the user can keep working instead of being permanently locked out of re-scanning.
        $stuckSec = if ($script:_ScanStartedAt) { ((Get-Date) - $script:_ScanStartedAt).TotalSeconds } else { 999 }
        if ($stuckSec -gt 120) {
            try { Add-Event warn ("Previous scan appears stuck (>{0:N0}s) - resetting and starting fresh." -f $stuckSec) } catch {}
            $script:_ScanInProgress = $false
        } else {
            try { Add-Event scan ('Re-scan ignored - scan in progress for {0:N0}s.' -f $stuckSec) } catch {}
            return
        }
    }
    $script:_ScanInProgress = $true
    $script:_ScanStartedAt  = Get-Date
    # Diagnostic breadcrumb to confirm Update-Findings is actually running.
    # If users don't see this in the events ribbon when they click RUN, the click handler
    # isn't reaching this function (different problem entirely).
    try { Add-Event scan ('--- Update-Findings called at {0} ---' -f (Get-Date -Format 'HH:mm:ss')) } catch {}
    try {
      try {
        _ScanYield 'Scanning: collecting baseline...'

        # ALIVE-CHECK: insert a synthetic finding before any scan logic, then immediately
        # apply the filter. If the user sees this row appear in HEALTHY immediately after
        # clicking RUN, we've proven that:
        #   (a) Update-Findings is being invoked
        #   (b) $script:Findings.Add() works
        #   (c) The bucket pipeline (AllFindings + Apply-FindingsFilter + ItemsSource binding) works
        # If they DON'T see it, the problem is upstream of the scan logic entirely.
        try {
            $script:Findings.Clear()
            $aliveMsg = "Scan started at {0}. If you see this row, the diagnostic pipeline is working." -f (Get-Date -Format 'HH:mm:ss')
            $script:Findings.Add((Add-Finding 'OK' 'Scan' $aliveMsg))
            if (-not $script:AllFindings) { $script:AllFindings = New-Object System.Collections.Generic.List[object] }
            $script:AllFindings.Clear()
            foreach ($f in $script:Findings) { [void]$script:AllFindings.Add($f) }
            Apply-FindingsFilter
            try { Add-Event scan ("Alive-check: pushed 1 finding -> Healthy bucket count={0}" -f $script:FindingsOk.Count) } catch {}
        } catch {
            try { Add-Event warn ("Alive-check failed: $($_.Exception.GetType().Name) - $($_.Exception.Message)") } catch {}
        }

        # Helper: rebuild AllFindings from $script:Findings + run Apply-FindingsFilter.
        # Called after every major section so the user sees buckets populate INCREMENTALLY
        # (instead of all-or-nothing at the end). Wrapped in try/catch so any single
        # rebuild failure can't kill the rest of the scan.
        function script:_RebuildAndFilter {
            try {
                if (-not $script:AllFindings -or -not $script:Findings) { return }
                $script:AllFindings.Clear()
                foreach ($f in $script:Findings) {
                    try {
                        $f | Add-Member -NotePropertyName IsNew -NotePropertyValue $false -Force -ErrorAction SilentlyContinue
                        $f | Add-Member -NotePropertyName NewVisibility -NotePropertyValue 'Collapsed' -Force -ErrorAction SilentlyContinue
                    } catch {}
                    try { [void]$script:AllFindings.Add($f) } catch {}
                }
                try { Apply-FindingsFilter } catch {}
            } catch {}
        }
        # Tier 21: capture previous findings keys BEFORE we clear, so we can diff
        $prevKeys = @{}
        foreach ($pf in $script:Findings) {
            $k = Get-FindingKey $pf
            if ($k -and -not $prevKeys.ContainsKey($k)) { $prevKeys[$k] = $true }
        }

        _ScanYield 'Scanning: adapter + power settings...'
        # Default empty result so subsequent sections can run even if Invoke-Diagnostics blows up
        $result = $null
        try { $result = Invoke-Diagnostics } catch {
            try { Add-Event warn ("Section 'adapter+power' failed: $($_.Exception.Message)") } catch {}
        }
        if (-not $result) { $result = @{ Findings = @(); Fixes = @() } }
        # Use Add-Member -Force to bypass NoteProperty element-type coercion. Direct assignment
        # via $script:State.RecommendedFixes = @(...) raises "Argument types do not match" when
        # the new array's element type differs from the property's inferred type. -Force replaces
        # the entire NoteProperty so the type can change freely.
        try {
            $script:State | Add-Member -NotePropertyName RecommendedFixes -NotePropertyValue @($result.Fixes) -Force
        } catch {
            try { Add-Event warn ("Failed to set RecommendedFixes: $($_.Exception.Message)") } catch {}
        }
        $script:Findings.Clear()
        foreach ($f in $result.Findings) {
            try { $script:Findings.Add($f) } catch {}
        }
        _RebuildAndFilter   # buckets now show adapter+power findings

    # Tier 5: NIC driver crash dump scan
    _ScanYield 'Scanning: BSOD crash dumps...'
    $crashHits = @()
    try { $crashHits = @(Get-NicDriverCrashes) } catch {
        try { Add-Event warn ("Section 'BSOD crashes' failed: $($_.Exception.Message)") } catch {}
    }
    if ($crashHits.Count -gt 0) {
        $latest = $crashHits | Sort-Object Time -Descending | Select-Object -First 1
        $script:Findings.Add((Add-Finding 'FAIL' 'Crashes' ("{0} BSOD(s) reference NIC driver in last 30d (latest: {1} - {2})" -f $crashHits.Count, $latest.Driver, $latest.Time) `
            'Roll back the driver in Device Manager. If the bug check is recent, consider safe-mode networking to confirm.' `
            'A kernel-mode crash dump that names the NIC driver is strong evidence the driver is unstable. Check C:\Windows\Minidump\ for the .dmp files; tools like WinDbg can give you the exact bug check code (DRIVER_IRQL_NOT_LESS_OR_EQUAL etc). Bring-your-own-vulnerable-driver (BYOVD) attacks also surface here.' `
            'driver-bsod'))
    }

    # Tier 5: periodicity (combine session history + current session flap times)
    $period = $null
    try {
        $allTimes = New-Object System.Collections.ArrayList
        if ($script:HistoryFlapTimes) { foreach ($t in $script:HistoryFlapTimes) { [void]$allTimes.Add($t) } }
        foreach ($f in $script:State.SessionFlaps) {
            try { [void]$allTimes.Add([datetime]$f.time) } catch {}
        }
        if ($allTimes.Count -ge 4) { $period = Get-FlapPeriodicity -Times $allTimes.ToArray() }
        if ($period) {
            $script:Findings.Add((Add-Finding 'INFO' 'Pattern' ("Flap timestamps cluster every {0} (tightness {1}%)" -f $period.Label, [int]($period.Tightness*100)) `
                "Match the interval to scheduled tasks (Task Scheduler), DHCP T1 (Comcast = ~47 min), or backup/cron jobs." `
                "Periodicity is computed by checking variance of flap timestamps modulo each candidate period. A tightness above 85% is significant - random flaps would not cluster like this."))
        }
    } catch { try { Add-Event warn ("Section 'periodicity' failed: $($_.Exception.Message)") } catch {} }

    # Tier 12: hardening posture checks (SLOWEST single section: Get-WindowsOptionalFeature can take 5-30s)
    _ScanYield 'Scanning: hardening posture (this is the slowest part - up to 30s)...'
    try {
        foreach ($f in (Invoke-HardeningChecks)) { $script:Findings.Add($f) }
    } catch { try { Add-Event warn ("Section 'hardening' failed: $($_.Exception.Message)") } catch {} }
    _RebuildAndFilter

    # Tier 13: auth-event findings
    _ScanYield 'Scanning: auth events...'
    try {
        foreach ($f in (Get-AuthFindings)) { $script:Findings.Add($f) }
    } catch { try { Add-Event warn ("Section 'auth' failed: $($_.Exception.Message)") } catch {} }

    # Tier 16: user-defined custom detection rules
    _ScanYield 'Scanning: custom rules...'
    try {
        foreach ($f in (Invoke-CustomRules)) { $script:Findings.Add($f) }
    } catch { try { Add-Event warn ("Section 'custom rules' failed: $($_.Exception.Message)") } catch {} }

    # Tier 18: threat-intel cross-reference against ledger
    _ScanYield 'Scanning: threat-intel cross-reference...'
    try {
    if ($script:State.ThreatIntelLoaded -and ($script:ThreatIntelRanges.Count + $script:ThreatIntelHashSet.Count) -gt 0) {
        $hits = New-Object System.Collections.Generic.List[object]
        foreach ($v in $script:Ledger.Values) {
            $src = Test-IpThreat $v.ip
            if ($src) { [void]$hits.Add(@{ Proc=$v.proc; Ip=$v.ip; Port=$v.port; Source=$src; Samples=$v.samples }) }
        }
        if ($hits.Count -gt 0) {
            $byProc = $hits | Group-Object Proc
            foreach ($g in $byProc) {
                $first = $g.Group[0]
                $msg = "Threat-intel hit: {0} -> {1}:{2} matches '{3}' ({4} samples)" -f $g.Name, $first.Ip, $first.Port, $first.Source, $first.Samples
                $script:Findings.Add((Add-Finding 'FAIL' 'ThreatIntel' $msg `
                    "Block the IP at firewall (right-click in PROCESSES tab) and verify the process. Capture pcap if not already." `
                    "The remote IP appeared in a public threat-intel feed (FireHOL Level1 = aggregate of widely-trusted blocklists; Feodo Tracker = active C2/botnet IPs). Hits warrant immediate action." `
                    'threat-intel'))
            }
        } else {
            $script:Findings.Add((Add-Finding 'OK' 'ThreatIntel' ("Threat-intel: no hits across {0} ledger entries (vs {1} ranges + {2} IPs)" -f $script:Ledger.Count, $script:ThreatIntelRanges.Count, $script:ThreatIntelHashSet.Count)))
        }
    } elseif (-not ($script:State.Settings -and $script:State.Settings.ThreatIntelEnabled)) {
        $script:Findings.Add((Add-Finding 'INFO' 'ThreatIntel' 'Threat-intel feeds disabled. Enable in Settings to cross-reference outbound IPs against public blocklists.'))
    }
    } catch { try { Add-Event warn ("Section 'threat-intel' failed: $($_.Exception.Message)") } catch {} }

    # Tier 15: DNS-over-HTTPS by non-browser processes
    _ScanYield 'Scanning: DNS-over-HTTPS detection...'
    try {
    $doh = @(Detect-DohConnections)
    if ($doh.Count -gt 0) {
        $byProc = $doh | Group-Object Process
        foreach ($g in $byProc) {
            $first = $g.Group[0]
            $providers = ($g.Group | ForEach-Object { $_.Provider } | Select-Object -Unique) -join ', '
            $msg = "DoH from non-browser: {0} -> {1} ({2})" -f $g.Name, $first.Ip, $providers
            $script:Findings.Add((Add-Finding 'WARN' 'DoH' $msg `
                "Verify the process. If unexpected, kill it (right-click in PROCESSES tab) and block the IP at the firewall." `
                'DNS-over-HTTPS by browsers is normal. By svchost it is the Windows resolver. By any other binary it is suspicious - DoH lets a process resolve domains while bypassing corporate DNS monitoring/filtering, which is exactly why C2 implants increasingly use it.' `
                'doh-evasion'))
        }
    }
    } catch { try { Add-Event warn ("Section 'doh' failed: $($_.Exception.Message)") } catch {} }

    # Tier 14: process baseline diff
    _ScanYield 'Scanning: process baseline diff...'
    try {
    $newProcs = @(Get-NewSinceBaseline)
    if ($newProcs.Count -gt 0) {
        $userWrt = @($newProcs | Where-Object UserWritable)
        if ($userWrt.Count -gt 0) {
            $names = ($userWrt | ForEach-Object { $_.Name } | Select-Object -Unique -First 5) -join ', '
            $script:Findings.Add((Add-Finding 'WARN' 'Baseline' ("{0} new process(es) since baseline running from user-writable paths: {1}" -f $userWrt.Count, $names) `
                'Verify each. Right-click in PROCESSES tab to inspect signers and remote endpoints.' `
                'Daily process snapshots over the last 14 days form the baseline. A process whose (name + path) tuple has never appeared in any prior snapshot is "new". User-writable paths (AppData, Temp, ProgramData) are where malware persistence typically lives.' `
                'unsigned-temp'))
        } else {
            $script:Findings.Add((Add-Finding 'INFO' 'Baseline' ("{0} new process(es) since baseline (all from system paths)." -f $newProcs.Count)))
        }
    } else {
        $script:Findings.Add((Add-Finding 'OK' 'Baseline' 'No new processes since last 14-day baseline.'))
    }
    } catch { try { Add-Event warn ("Section 'baseline' failed: $($_.Exception.Message)") } catch {} }
    _RebuildAndFilter

    # Tier 14: Sysmon integration
    _ScanYield 'Scanning: Sysmon status...'
    try {
    $sm = Get-SysmonStatus
    if ($sm) {
        if ($sm.Status -eq 'Running') {
            $cnt = @(Get-RecentSysmonEvents -Minutes 5 -Max 200).Count
            $script:Findings.Add((Add-Finding 'OK' 'Sysmon' ("Sysmon ({0}) running - {1} events in last 5 min." -f $sm.Name, $cnt) '' `
                'Sysmon provides high-fidelity process create / network connection / DNS / image-load / registry events. Microsoft-Windows-Sysmon/Operational log. Tune with a config like SwiftOnSecurity/sysmon-config or Olaf Hartong/sysmon-modular.'))
        } else {
            $script:Findings.Add((Add-Finding 'WARN' 'Sysmon' ("Sysmon installed but {0}." -f $sm.Status) "Start-Service $($sm.Name)"))
        }
    } else {
        $script:Findings.Add((Add-Finding 'INFO' 'Sysmon' 'Sysmon not installed.' `
            'Install from sysinternals.com/downloads/sysmon - dramatically richer Windows telemetry than the default audit logs.' `
            'Sysmon writes detailed events to Microsoft-Windows-Sysmon/Operational. Pair it with a config from SwiftOnSecurity or Olaf Hartong - the HUD will surface its events here once both are present.'))
    }
    } catch { try { Add-Event warn ("Section 'sysmon' failed: $($_.Exception.Message)") } catch {} }

    # Tier 12: BYOVD vulnerable driver scan (CIM Win32_SystemDriver query - can be slow)
    _ScanYield 'Scanning: kernel drivers (BYOVD)...'
    $byovd = @()
    try { $byovd = @(Scan-ByovdDrivers) } catch { try { Add-Event warn ("Section 'BYOVD' failed: $($_.Exception.Message)") } catch {} }
    try {
    foreach ($h in $byovd) {
        $msg = "Vulnerable driver loaded: {0} ({1}) - {2}" -f $h.DriverName, $h.Info.Vendor, $h.Info.Note
        $script:Findings.Add((Add-Finding 'FAIL' 'BYOVD' $msg `
            "Stop the service that loads it, then remove the driver. Microsoft maintains a kernel blocklist - https://aka.ms/VulnerableDriverBlockList" `
            "$($h.DriverName) is on Microsoft's known-vulnerable driver list ($($h.Info.CVE)). It is signed (so Windows accepts it) but contains primitives like read/write MSRs that ransomware and rootkits abuse to disable EDR and elevate privileges. BYOVD = Bring-Your-Own-Vulnerable-Driver." `
            'byovd'))
    }
    } catch { try { Add-Event warn ("Section 'BYOVD finding emit' failed: $($_.Exception.Message)") } catch {} }
    _RebuildAndFilter

    # Tier 10: beaconing detection
    _ScanYield 'Scanning: beaconing patterns...'
    $beacons = @()
    try { $beacons = @(Detect-Beacons) } catch { try { Add-Event warn ("Section 'beacons' failed: $($_.Exception.Message)") } catch {} }
    try {
    foreach ($b in $beacons) {
        $msg = "Beaconing: {0} (pid {1}) -> {2}:{3} every ~{4}s (+/-{5}s, {6} samples)" -f $b.ProcessName, $b.Pid, $b.IP, $b.Port, $b.Period, $b.Jitter, $b.Samples
        $detail = "Periodic outbound connection with low jitter (CV {0:N2}) is the signature of a Command-and-Control callback. Coefficient-of-variation < 0.25 means the timing is too consistent to be human-driven traffic. Period {1}s suggests $(if ($b.Period -lt 60) {'fast beacon (active C2)'} elseif ($b.Period -lt 600) {'standard beacon'} else {'slow beacon (long-term implant)'})." -f $b.CV, $b.Period
        $script:Findings.Add((Add-Finding 'WARN' 'Beacon' $msg "Verify the process and remote endpoint. If suspicious, kill the process and block the remote IP at the firewall." $detail 'beaconing'))
        if (-not $script:BeaconAlerted.ContainsKey($b.Key)) {
            Add-Event warn $msg
            $script:BeaconAlerted[$b.Key] = $true
        }
    }
    } catch { try { Add-Event warn ("Section 'beacon emit' failed: $($_.Exception.Message)") } catch {} }

    # Tier 5: flap correlation summary
    $corrs = $null
    try {
        $corrs = Get-FlapCorrelations
        if ($corrs) {
            foreach ($c in ($corrs | Select-Object -First 2)) {
                $script:Findings.Add((Add-Finding 'INFO' 'Pattern' ("'{0}' observed in {1}/{2} of recent flaps ({3:P0})" -f $c.Tag, $c.Hits, $c.Total, $c.Share) `
                    '' `
                    "Correlation analysis tracks tags around each flap (RX errors, ping loss, speed change, capture rotation, Defender activity). When a tag shows up before 60% or more of flaps, it is flagged as a candidate trigger."))
            }
        }
    } catch { try { Add-Event warn ("Section 'correlations' failed: $($_.Exception.Message)") } catch {} }

    # Tier 5: compute top causes
    $causes = @()
    try {
        $flapCount72h = 0
        $f = $script:Findings | Where-Object { $_.Category -eq 'History' -and $_.Message -match '(\d+) link-down' } | Select-Object -First 1
        if ($f -and $f.Message -match '(\d+) link-down') { $flapCount72h = [int]$matches[1] }

        $causes = @(Compute-RootCauses -Adapter $script:State.Adapter -Findings $script:Findings -CrashHits $crashHits -Periodicity $period -Correlations $corrs -FlapCount72h $flapCount72h)
    } catch { try { Add-Event warn ("Section 'causes' failed: $($_.Exception.Message)") } catch {} }
    $script:Causes.Clear()
    foreach ($c in $causes) { $script:Causes.Add($c) }
    if ($causes.Count -eq 0) {
        $script:Causes.Add([pscustomobject]@{
            Cause = 'No actionable causes inferred yet.'
            Evidence = 'Either everything is healthy, or there is too little signal to rank.'
            Recommendation = 'Leave the HUD running through the next flap; we will refine the ranking.'
            ConfidenceLabel = '--'
            ColorBrush = (B '#3fb950')
        })
        $controls.CausesNote.Text = ''
    } else {
        $controls.CausesNote.Text = ("ranked from {0} signal(s)" -f ($causes | Measure-Object).Count)
    }

    _ScanYield 'Scanning: synthesizing report...'
    try {
        $elapsed = if ($script:_ScanStartedAt) { ((Get-Date) - $script:_ScanStartedAt).TotalSeconds } else { 0 }
        $controls.ScanStatus.Text = ("Last scan: {0} ({1:N0}s)" -f (Get-Date -Format 'HH:mm:ss'), $elapsed)
        $controls.ScanStatus.Foreground = (B '#3fb950')
        $fixCount = if ($result -and $result.Fixes) { @($result.Fixes).Count } else { 0 }
        $controls.FixButton.IsEnabled = ($fixCount -gt 0 -and $script:IsAdmin)
        if ($fixCount -gt 0 -and $script:IsAdmin) {
            $controls.FixButton.Content = "Apply Fixes ($fixCount)"
        } else {
            $controls.FixButton.Content = $(if ($fixCount -eq 0) { 'All clean' } else { 'Apply Fixes' })
        }
        $topLabel = if ($causes -and $causes.Count -gt 0) { ($causes[0].Cause -split ' \(')[0] } else { 'none' }
        Add-Event scan ("Scan complete - {0} fix(es) recommended; top cause: {1}" -f $fixCount, $topLabel)
        Add-ActivityMark scan
    } catch { try { Add-Event warn ("Section 'synthesize' failed: $($_.Exception.Message)") } catch {} }

    # Tier 21: build master $script:AllFindings with NEW tagging, then run filter
    $script:AllFindings.Clear()
    $currentKeys = @{}
    $newCount = 0
    foreach ($f in $script:Findings) {
        $k = Get-FindingKey $f
        $isNew = ($k -and (-not $prevKeys.ContainsKey($k)) -and ($prevKeys.Count -gt 0))
        if ($isNew) { $newCount++ }
        $vis = if ($isNew) { 'Visible' } else { 'Collapsed' }
        $f | Add-Member -NotePropertyName IsNew -NotePropertyValue $isNew -Force
        $f | Add-Member -NotePropertyName NewVisibility -NotePropertyValue $vis -Force
        [void]$script:AllFindings.Add($f)
        if ($k) { $currentKeys[$k] = $true }
    }
    # detect RESOLVED (in prev but not current) and emit recovery events.
    # Wrapped in its own try/catch so a malformed key string can never block Apply-FindingsFilter
    # below - that's what was leaving the buckets empty when this section threw.
    try {
        $script:ResolvedFindings.Clear()
        if ($prevKeys.Count -gt 0) {
            $resolvedCount = 0
            foreach ($pk in $prevKeys.Keys) {
                if (-not $currentKeys.ContainsKey($pk)) {
                    $resolvedCount++
                    $parts = $pk -split '\|',2
                    $cat = if ($parts.Count -gt 0) { $parts[0] } else { '?' }
                    $msg = if ($parts.Count -gt 1) { $parts[1] } else { $pk }
                    if ($msg.Length -gt 80) { $msg = $msg.Substring(0,77) + '...' }
                    # was 'Add-Event ok' which throws ParameterValidationError - 'ok' isn't in the ValidateSet.
                    # 'recovery' renders green (same intent) and is a valid type.
                    Add-Event recovery ("RESOLVED [{0}]: {1}" -f $cat, $msg)
                    # Build a ghost finding so Apply-FindingsFilter can show it under DiffMode 'resolved'.
                    # Pulls richer metadata from $script:PrevFindingsByKey if we have the full prior object.
                    $prev = if ($script:PrevFindingsByKey.ContainsKey($pk)) { $script:PrevFindingsByKey[$pk] } else { $null }
                    $ghostFix    = if ($prev) { [string]$prev.Fix }    else { '' }
                    $ghostDetail = if ($prev) { [string]$prev.Detail } else { '' }
                    $ghostMitre  = if ($prev) { [string]$prev.MitreId } else { '' }
                    $ghostName   = if ($prev) { [string]$prev.MitreName } else { '' }
                    $ghost = [pscustomobject]@{
                        Level           = 'OK'
                        Category        = "RESOLVED [$cat]"
                        Message         = $msg
                        Fix             = ''
                        Detail          = if ($ghostDetail) { $ghostDetail } else { ("Previously flagged. No longer detected in this scan." + $(if ($ghostFix) { "  Prior fix: $ghostFix" } else { '' })) }
                        Tip             = ("RESOLVED since last scan." + $(if ($ghostFix) { "  Prior fix: $ghostFix" } else { '' }))
                        LevelColor      = (B '#3fb950')
                        FixVisibility   = 'Collapsed'
                        MitreId         = $ghostMitre
                        MitreName       = $ghostName
                        MitreVisibility = if ($ghostMitre) { 'Visible' } else { 'Collapsed' }
                        IsNew           = $false
                        NewVisibility   = 'Collapsed'
                    }
                    [void]$script:ResolvedFindings.Add($ghost)
                }
            }
            if ($resolvedCount -gt 0 -and $controls.FilterStatus) {
                $controls.FilterStatus.Text = ("{0} new / {1} resolved" -f $newCount, $resolvedCount)
            } elseif ($newCount -gt 0 -and $controls.FilterStatus) {
                $controls.FilterStatus.Text = ("{0} new finding(s)" -f $newCount)
            } elseif ($controls.FilterStatus) {
                $controls.FilterStatus.Text = ''
            }
        }
    } catch {
        try { Add-Event warn ("Resolved-detection failed: $($_.Exception.Message)") } catch {}
    }
    # snapshot keys + full findings for next scan
    $script:PrevFindingKeys = $currentKeys
    $script:PrevFindingsByKey = @{}
    foreach ($f in $script:Findings) {
        try {
            $k = Get-FindingKey $f
            if ($k) { $script:PrevFindingsByKey[$k] = $f }
        } catch {}
    }

    # rebuild the 5 buckets via filter+suppression aware function
    Apply-FindingsFilter

    # Diagnostic breadcrumbs so we can confirm the scan is actually populating buckets.
    # Visible in the Events ribbon - if buckets look empty in the UI but counts here are non-zero,
    # the issue is binding/visual; if they're zero, the issue is upstream in scan/filter.
    try {
        $byLevel = @{}
        foreach ($f in $script:AllFindings) { $lvl = [string]$f.Level; if ($lvl) { $byLevel[$lvl] = ([int]$byLevel[$lvl] + 1) } }
        $brk = ($byLevel.GetEnumerator() | Sort-Object Name | ForEach-Object { ("{0}={1}" -f $_.Key, $_.Value) }) -join ', '
        Add-Event scan ("Scan results: {0} total findings ({1}) - buckets: FAIL={2} WARN={3} INFO={4} OK={5} MUTED={6}" -f `
            $script:AllFindings.Count, $brk, `
            $script:FindingsFail.Count, $script:FindingsWarn.Count, $script:FindingsInfo.Count, `
            $script:FindingsOk.Count, $(if ($script:FindingsMuted) { $script:FindingsMuted.Count } else { 0 }))
    } catch {}

    # auto-expand FAIL+WARN if any; collapse if zero
    if ($controls.ExpFail) { $controls.ExpFail.IsExpanded = ($script:FindingsFail.Count -gt 0) }
    if ($controls.ExpWarn) { $controls.ExpWarn.IsExpanded = ($script:FindingsWarn.Count -gt 0) }

    Update-HeroVisuals
    Update-TabBadges

    # Force the diagnostics scroll viewer to recompute its content extent now that the buckets
    # have been repopulated. Without this, WPF sometimes caches stale scroll bounds and the
    # scrollbar doesn't reach the bottom of the new content.
    if ($controls.DiagScroller) {
        try {
            $controls.DiagScroller.UpdateLayout()
            $controls.DiagScroller.InvalidateScrollInfo()
            $controls.DiagScroller.ScrollToTop()
        } catch {}
    }
      } catch {
        # Catch ANY exception inside Update-Findings before it escapes back to InvokeAsync,
        # which would otherwise propagate as an unobserved task exception and could terminate the app.
        $stageStr = if ($script:_ScanStage) { $script:_ScanStage } else { '(unknown stage)' }
        $msg = $_.Exception.Message
        $type = $_.Exception.GetType().Name
        # Pull the most-relevant stack frame: first user-code line in the trace
        $topFrame = ''
        try {
            $trace = [string]$_.ScriptStackTrace
            $line = ($trace -split "`n" | Where-Object { $_ -match 'NetJump-Dashboard\.ps1' } | Select-Object -First 1)
            if ($line) { $topFrame = " | $($line.Trim())" }
        } catch {}
        # Extract just the line number out of the topmost frame for the visible status line
        $lineNum = ''
        try {
            if ($topFrame -match 'line (\d+)') { $lineNum = "line $($matches[1]) " }
        } catch {}
        try { Add-Event warn ("Scan error [$type] at [$stageStr]: $msg$topFrame") } catch {}
        try { Write-Host "Update-Findings error at [$stageStr]: $type - $msg`n$($_.ScriptStackTrace)" } catch {}
        try {
            $controls.ScanStatus.Text      = "Scan failed at [$stageStr] ($type, $lineNum): $msg"
            $controls.ScanStatus.Foreground = (B '#f85149')
        } catch {}
        # ALSO populate the buckets with whatever we got - even on error, we want any partial
        # findings to show. Apply-FindingsFilter uses $script:AllFindings, but we may not have
        # populated that yet if the throw happened mid-scan. So rebuild from $script:Findings here.
        try {
            if ($script:AllFindings -and $script:Findings) {
                $script:AllFindings.Clear()
                foreach ($f in $script:Findings) {
                    try {
                        $f | Add-Member -NotePropertyName IsNew -NotePropertyValue $false -Force
                        $f | Add-Member -NotePropertyName NewVisibility -NotePropertyValue 'Collapsed' -Force
                    } catch {}
                    [void]$script:AllFindings.Add($f)
                }
            }
            Apply-FindingsFilter
            if ($script:AllFindings) {
                Add-Event warn ("Partial scan saved: AllFindings={0} FAIL={1} WARN={2} INFO={3} OK={4}" -f `
                    $script:AllFindings.Count, $script:FindingsFail.Count, $script:FindingsWarn.Count, `
                    $script:FindingsInfo.Count, $script:FindingsOk.Count)
            }
        } catch {}
      }
    } finally {
        $script:_ScanInProgress = $false
        # Tier 23: latch HasScanned so the kill-switch banner reveals on first completion
        $script:State.HasScanned = $true
        try { Update-KillSwitchUI } catch {}
        # Tier 54: restore the busy-state UI no matter how the scan ended (success, exception,
        # cancelled, etc.). Without this in finally, an unhandled exception would leave the button
        # disabled and the progress bar spinning forever.
        try {
            if ($controls -and $controls.RescanButton) {
                $controls.RescanButton.IsEnabled = $true
                if ($script:_RescanButtonOrigContent) {
                    $controls.RescanButton.Content = $script:_RescanButtonOrigContent
                } else {
                    $controls.RescanButton.Content = 'Re-scan'
                }
            }
            if ($controls -and $controls.ScanProgressBar) {
                $controls.ScanProgressBar.Visibility = 'Collapsed'
            }
            if ($controls -and $controls.ScanStatus) {
                $controls.ScanStatus.Foreground = $window.Resources['BrushFgMuted']
                # Stamp completion time + duration so the user sees "Scan complete in X.Xs (HH:mm:ss)"
                $dur = if ($script:_ScanStartedAt) { ((Get-Date) - $script:_ScanStartedAt).TotalSeconds } else { 0 }
                $controls.ScanStatus.Text = ("Scan complete in {0:N1}s ({1})" -f $dur, (Get-Date -Format 'HH:mm:ss'))
            }
            # Tier 59: scan-complete toast notification with finding-count breakdown. Tray-icon balloon
            # so the user gets feedback even if NetJump is not the foreground window. Icon flips to
            # Warning when there are FAIL/WARN findings, Info otherwise. Respects the global mute flag
            # via Show-Toast (which short-circuits if NotificationsMuted).
            try {
                $failN = if ($script:FindingsFail) { $script:FindingsFail.Count } else { 0 }
                $warnN = if ($script:FindingsWarn) { $script:FindingsWarn.Count } else { 0 }
                $infoN = if ($script:FindingsInfo) { $script:FindingsInfo.Count } else { 0 }
                $okN   = if ($script:FindingsOk)   { $script:FindingsOk.Count   } else { 0 }
                $dur2  = if ($script:_ScanStartedAt) { ((Get-Date) - $script:_ScanStartedAt).TotalSeconds } else { 0 }
                $msg   = ("CRITICAL {0} | WARNINGS {1} | INFO {2} | HEALTHY {3}   ({4:N1}s)" -f $failN, $warnN, $infoN, $okN, $dur2)
                $icon  = if ($failN -gt 0 -or $warnN -gt 0) { 'Warning' } else { 'Info' }
                Show-Toast -Title 'NetJump scan complete' -Message $msg -Icon $icon
            } catch {}
            # Tier 67: if Invoke-ScanAndAutoFix set PendingAutoApply, run the SAFE-fix pipeline now.
            # Headless (no dialog) - the user already opted in by clicking the Auto-fix button. After
            # applying, we trigger a re-scan and start the 10-min verify watch via Invoke-ApplySafeFixes.
            try {
                if ($script:State.PendingAutoApply) {
                    $script:State.PendingAutoApply = $false   # one-shot, clear before running
                    Add-Event fix '--- Auto-fix workflow: scan complete, applying SAFE fixes ---'
                    $autoResult = Invoke-ApplySafeFixes -StartVerifyWatch
                    if ($autoResult.AppliedCount -gt 0) {
                        $autoMsg = ("Auto-fix: {0} applied" -f $autoResult.AppliedCount)
                        if ($autoResult.FailedCount -gt 0) { $autoMsg += (" / {0} failed" -f $autoResult.FailedCount) }
                        Show-Toast -Title 'NetJump auto-fix done' -Message ($autoMsg + ' - 10-min verify watch active') -Icon Info
                    } elseif ($autoResult.SafeFound -eq 0 -and -not $autoResult.Cancelled) {
                        Show-Toast -Title 'NetJump auto-fix' -Message 'No SAFE fixes recommended after scan - nothing to apply.' -Icon Info
                    }
                }
            } catch {
                try { Add-Event warn ("Auto-fix workflow error: $($_.Exception.Message)") } catch {}
            }
            # Snapshot save - every scan persists its full state for the Replay feature.
            try {
                $snapPath = Save-ScanSnapshot
                if ($snapPath) {
                    Add-Event info ("Snapshot saved: {0} (Diagnose menu -> Replay snapshot...)" -f (Split-Path $snapPath -Leaf))
                }
            } catch {
                try { Add-Event warn ("Snapshot save failed: $($_.Exception.Message)") } catch {}
            }
            # Scheduled-scan digest writer. _PendingScheduledDigest is latched by the Tick scheduler
            # right before it dispatches Update-Findings; we clear it here regardless of success so
            # a write failure doesn't loop.
            try {
                if ($script:_PendingScheduledDigest) {
                    $script:_PendingScheduledDigest = $false
                    $written = Write-ScheduledScanDigest
                    if ($written) {
                        $script:State.LastScheduledDigestAt = Get-Date
                        Add-Event recovery ("Scheduled digest written: {0} ({1} findings)" -f (Split-Path $written.Html -Leaf), $written.Shown)
                    }
                }
            } catch {
                try { Add-Event warn ("Scheduled-digest hook error: $($_.Exception.Message)") } catch {}
            }
        } catch {}
        # GUARANTEED bucket population: regardless of success/failure path above, always rebuild
        # AllFindings from whatever's in $script:Findings and run the filter. This is the last
        # chance to make sure CRITICAL/WARNINGS/INFO/HEALTHY reflect the current scan state.
        try {
            if ($script:AllFindings -ne $null -and $script:Findings -ne $null) {
                # Only rebuild if AllFindings is empty/stale relative to Findings (success path
                # populates AllFindings already; this catches partial-failure cases)
                if ($script:AllFindings.Count -lt $script:Findings.Count -or $script:AllFindings.Count -eq 0) {
                    $script:AllFindings.Clear()
                    foreach ($f in $script:Findings) {
                        try {
                            $f | Add-Member -NotePropertyName IsNew -NotePropertyValue $false -Force -ErrorAction SilentlyContinue
                            $f | Add-Member -NotePropertyName NewVisibility -NotePropertyValue 'Collapsed' -Force -ErrorAction SilentlyContinue
                        } catch {}
                        try { [void]$script:AllFindings.Add($f) } catch {}
                    }
                }
                try { Apply-FindingsFilter } catch {}
                try { Update-HeroVisuals } catch {}
                try { Update-TabBadges } catch {}
                # Final breadcrumb so the user always knows what populated
                try {
                    Add-Event scan ("Buckets: All={0} FAIL={1} WARN={2} INFO={3} OK={4} (Findings={5})" -f `
                        $script:AllFindings.Count, $script:FindingsFail.Count, $script:FindingsWarn.Count, `
                        $script:FindingsInfo.Count, $script:FindingsOk.Count, $script:Findings.Count)
                } catch {}
            }
        } catch {}
    }
}

# ---------- Tier 3: process->network scanner (async) ----------
$script:ProcScanScript = {
    $tcp = Get-NetTCPConnection -State Established -ErrorAction SilentlyContinue
    $udp = Get-NetUDPEndpoint -ErrorAction SilentlyContinue

    $byPid = @{}
    foreach ($c in $tcp) {
        $k = $c.OwningProcess
        if (-not $byPid.ContainsKey($k)) { $byPid[$k] = @{ Tcp = New-Object System.Collections.ArrayList; Udp = New-Object System.Collections.ArrayList } }
        [void]$byPid[$k].Tcp.Add($c)
    }
    foreach ($c in $udp) {
        $k = $c.OwningProcess
        if (-not $byPid.ContainsKey($k)) { $byPid[$k] = @{ Tcp = New-Object System.Collections.ArrayList; Udp = New-Object System.Collections.ArrayList } }
        [void]$byPid[$k].Udp.Add($c)
    }

    # EDR-style parent-chain map: Win32_Process gives ProcessId + ParentProcessId + Name in one
    # CIM call. We build a pid -> {Name, ParentPid, User, Domain} dictionary so the per-process
    # ancestry walk below is O(depth) without further CIM queries.
    $pidMap = @{}
    try {
        $allProc = Get-CimInstance Win32_Process -ErrorAction SilentlyContinue
        foreach ($wp in $allProc) {
            $pidMap[[int]$wp.ProcessId] = @{
                Name      = [string]$wp.Name
                ParentPid = [int]$wp.ParentProcessId
            }
        }
    } catch {}
    function _Walk-Ancestry { param([int]$Pid, $Map)
        $chain = New-Object System.Collections.ArrayList
        $cur = $Pid
        $depth = 0
        $seen = @{}
        while ($cur -gt 0 -and $depth -lt 6 -and $Map.ContainsKey($cur) -and -not $seen.ContainsKey($cur)) {
            $seen[$cur] = $true
            $e = $Map[$cur]
            $name = $e.Name
            if ($name -match '\.exe$') { $name = $name.Substring(0, $name.Length - 4) }
            [void]$chain.Add("$name($cur)")
            $cur = [int]$e.ParentPid
            $depth++
        }
        return ($chain.ToArray())
    }

    $sigCache = @{}
    $results = New-Object System.Collections.ArrayList
    foreach ($pidKey in $byPid.Keys) {
        $p = Get-Process -Id $pidKey -ErrorAction SilentlyContinue
        if (-not $p) { continue }

        $path = $p.Path
        $sigStatus = 'unknown'
        $signer = '(no path)'
        if ($path) {
            if ($sigCache.ContainsKey($path)) {
                $sig = $sigCache[$path]
            } else {
                $sig = Get-AuthenticodeSignature -FilePath $path -ErrorAction SilentlyContinue
                $sigCache[$path] = $sig
            }
            if ($sig) {
                $sigStatus = [string]$sig.Status
                if ($sig.Status -eq 'Valid' -and $sig.SignerCertificate) {
                    $cn = ($sig.SignerCertificate.Subject -split ',' | Where-Object { $_ -match '^\s*CN=' } | Select-Object -First 1) -replace '^\s*CN=',''
                    if ($cn) { $signer = $cn.Trim() } else { $signer = 'signed' }
                } elseif ($sig.Status -eq 'NotSigned') {
                    $signer = '(unsigned)'
                } else {
                    $signer = "sig: $sigStatus"
                }
            }
        }

        $isInUserPath = $path -and ($path -match '\\AppData\\Local\\Temp\\|\\AppData\\Roaming\\|\\Windows\\Temp\\|\\Users\\Public\\|\\ProgramData\\')
        $isInTemp     = $path -and ($path -match '\\Temp\\')
        $isUnsigned   = ($sigStatus -ne 'Valid') -and ($sigStatus -ne 'unknown' -or -not $path)
        $extConns = @($byPid[$pidKey].Tcp | Where-Object {
            $_.RemoteAddress -and $_.RemoteAddress -ne '127.0.0.1' -and
            $_.RemoteAddress -notmatch '^192\.168\.|^10\.|^172\.(1[6-9]|2\d|3[01])\.|^::1|^fe80:|^0\.0\.0\.0' })
        $hasExternal = $extConns.Count -gt 0

        if     ($isUnsigned -and $isInTemp -and $hasExternal) { $risk = 'HIGH';  $riskHex = '#f85149' }
        elseif ($isUnsigned -and $hasExternal)                { $risk = 'WARN';  $riskHex = '#d29922' }
        elseif ($isInUserPath -and $hasExternal)              { $risk = 'WARN';  $riskHex = '#d29922' }
        elseif ($hasExternal)                                 { $risk = 'INFO';  $riskHex = '#58a6ff' }
        else                                                  { $risk = 'OK';    $riskHex = '#3fb950' }

        $signerHex = if ($sigStatus -eq 'Valid') { '#3fb950' } elseif ($sigStatus -eq 'NotSigned') { '#d29922' } else { '#8b95a8' }

        $remotes = $extConns | ForEach-Object { "$($_.RemoteAddress):$($_.RemotePort)" } | Select-Object -Unique -First 4
        $remoteSummary = if ($remotes) { 'Remote: ' + ($remotes -join ', ') + $(if ($extConns.Count -gt 4) { " (+$($extConns.Count - 4) more)" } else { '' }) } else { 'No external connections' }
        $primaryIp = if ($extConns.Count -gt 0) { [string]$extConns[0].RemoteAddress } else { '' }

        # Ancestry: walk up the parent chain. Shows as "explorer(1) -> svchost(820) -> ..."
        # Reverse so the OLDEST ancestor is on the left (most-natural reading order).
        $ancestryChain = @()
        try {
            $a = _Walk-Ancestry -Pid ([int]$pidKey) -Map $pidMap
            if ($a -and $a.Count -gt 1) {
                [array]::Reverse($a)
                $ancestryChain = $a
            }
        } catch {}
        $ancestryStr = if ($ancestryChain.Count -gt 0) { ($ancestryChain -join ' -> ') } else { '' }
        $parentName = if ($ancestryChain.Count -ge 2) { $ancestryChain[$ancestryChain.Count - 2] } else { '(none)' }

        # Suspicion chain heuristic: a process whose parent looks normal (explorer, services) is
        # less suspicious than one whose parent is cmd/powershell/wscript/cscript spawned via a
        # script-host pattern. Add a "ChainRisk" flag for the UI to highlight.
        $chainRisk = $false
        try {
            $lower = $ancestryStr.ToLower()
            if ($lower -match '(cmd|powershell|wscript|cscript|mshta|rundll32)\(.*?->.*?(curl|wget|certutil|bitsadmin|powershell|nc|netcat|cscript)') {
                $chainRisk = $true
            }
        } catch {}

        [void]$results.Add([pscustomobject]@{
            Risk            = $risk
            RiskHex         = $riskHex
            Name            = $p.ProcessName
            Pid             = [int]$pidKey
            PidLabel        = "(pid $pidKey)"
            ConnLabel       = "$($byPid[$pidKey].Tcp.Count) TCP / $($byPid[$pidKey].Udp.Count) UDP"
            Path            = if ($path) { $path } else { '(path unavailable)' }
            RemoteSummary   = $remoteSummary
            PrimaryRemoteIp = $primaryIp
            SignerLabel     = $signer
            SignerHex       = $signerHex
            ParentName      = $parentName
            Ancestry        = $ancestryStr
            AncestryVisibility = if ($ancestryStr) { 'Visible' } else { 'Collapsed' }
            ChainRisk       = $chainRisk
            ChainRiskColor  = if ($chainRisk) { '#f85149' } else { '#8b95a8' }
        })
    }

    # sort by risk priority
    $results | Sort-Object @{Expression={
        switch ($_.Risk) { 'HIGH'{0} 'WARN'{1} 'INFO'{2} default{3} }
    }}, Name
}

function Start-ProcessScanAsync {
    if ($script:State.ProcJob) { return }
    $script:State.ProcJob = Start-Job -Name 'NetJump-Procs' -ScriptBlock $script:ProcScanScript
    $controls.ProcStatus.Text = 'Scanning... (Authenticode signature checks may take 5-10s)'
    $controls.ProcRefreshButton.IsEnabled = $false
    $controls.ProcRefreshButton.Content = 'Scanning...'
}

# ---------- Tier 3: persistence inventory (async) ----------
$script:PersistScanScript = {
    $items = New-Object System.Collections.ArrayList
    $sigCache = @{}

    function Get-Sig($path, $cache) {
        if (-not $path) { return $null }
        if ($cache.ContainsKey($path)) { return $cache[$path] }
        $s = Get-AuthenticodeSignature -FilePath $path -ErrorAction SilentlyContinue
        $cache[$path] = $s
        return $s
    }

    function Resolve-ExePath($cmd) {
        if (-not $cmd) { return $null }
        $cmd = $cmd.Trim('"').Trim()
        if ($cmd -match '^"([^"]+)"') { return $matches[1] }
        if ($cmd -match '^(\S+\.exe)') { return $matches[1] }
        return $null
    }

    $runKeys = @(
        @{Path='HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Run';     Source='HKLM\Run'},
        @{Path='HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\RunOnce'; Source='HKLM\RunOnce'},
        @{Path='HKCU:\Software\Microsoft\Windows\CurrentVersion\Run';     Source='HKCU\Run'},
        @{Path='HKCU:\Software\Microsoft\Windows\CurrentVersion\RunOnce'; Source='HKCU\RunOnce'},
        @{Path='HKLM:\SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Run'; Source='HKLM\Run (32)'}
    )
    foreach ($k in $runKeys) {
        $p = Get-ItemProperty -Path $k.Path -ErrorAction SilentlyContinue
        if (-not $p) { continue }
        $p.PSObject.Properties | Where-Object { $_.Name -notmatch '^PS' } | ForEach-Object {
            $exe = Resolve-ExePath $_.Value
            $sig = Get-Sig $exe ([ref]$sigCache).Value
            $sigStatus = if ($sig) { [string]$sig.Status } else { 'unknown' }
            $isUserPath = $exe -and ($exe -match '\\AppData\\|\\Users\\Public\\|\\ProgramData\\|\\Temp\\')
            $signerLabel = if ($sig -and $sig.Status -eq 'Valid' -and $sig.SignerCertificate) {
                ($sig.SignerCertificate.Subject -split ',' | Where-Object { $_ -match '^\s*CN=' } | Select-Object -First 1) -replace '^\s*CN=',''
            } elseif ($sigStatus -eq 'NotSigned') { '(unsigned)' } else { "sig: $sigStatus" }
            if ($sigStatus -eq 'Valid' -and -not $isUserPath) { $risk='OK'; $riskHex='#3fb950' }
            elseif ($sigStatus -eq 'Valid' -and $isUserPath)  { $risk='INFO'; $riskHex='#58a6ff' }
            elseif ($sigStatus -eq 'NotSigned' -and $isUserPath) { $risk='HIGH'; $riskHex='#f85149' }
            elseif ($sigStatus -eq 'NotSigned') { $risk='WARN'; $riskHex='#d29922' }
            else { $risk='INFO'; $riskHex='#58a6ff' }
            $signerHex = if ($sigStatus -eq 'Valid') { '#3fb950' } elseif ($sigStatus -eq 'NotSigned') { '#d29922' } else { '#8b95a8' }
            [void]$items.Add([pscustomobject]@{
                Risk=$risk; RiskHex=$riskHex; Source=$k.Source
                Name=$_.Name; Command=[string]$_.Value
                SignerLabel=$signerLabel; SignerHex=$signerHex
            })
        }
    }

    # startup folders
    $folders = @(
        @{Path=[Environment]::GetFolderPath('Startup');       Source='User Startup'},
        @{Path=[Environment]::GetFolderPath('CommonStartup'); Source='All Users Startup'}
    )
    foreach ($f in $folders) {
        if (-not (Test-Path $f.Path)) { continue }
        Get-ChildItem $f.Path -ErrorAction SilentlyContinue | ForEach-Object {
            $exe = $null
            if ($_.Extension -eq '.lnk') {
                try {
                    $sh = New-Object -ComObject WScript.Shell
                    $lnk = $sh.CreateShortcut($_.FullName)
                    $exe = $lnk.TargetPath
                } catch {}
            } else { $exe = $_.FullName }
            $sig = Get-Sig $exe $sigCache
            $sigStatus = if ($sig) { [string]$sig.Status } else { 'unknown' }
            $isUserPath = $exe -and ($exe -match '\\AppData\\|\\Users\\Public\\|\\ProgramData\\|\\Temp\\')
            $signerLabel = if ($sig -and $sig.Status -eq 'Valid' -and $sig.SignerCertificate) {
                ($sig.SignerCertificate.Subject -split ',' | Where-Object { $_ -match '^\s*CN=' } | Select-Object -First 1) -replace '^\s*CN=',''
            } elseif ($sigStatus -eq 'NotSigned') { '(unsigned)' } else { "sig: $sigStatus" }
            if ($sigStatus -eq 'NotSigned' -and $isUserPath) { $risk='HIGH'; $riskHex='#f85149' }
            elseif ($sigStatus -eq 'NotSigned') { $risk='WARN'; $riskHex='#d29922' }
            elseif ($isUserPath) { $risk='INFO'; $riskHex='#58a6ff' }
            else { $risk='OK'; $riskHex='#3fb950' }
            $signerHex = if ($sigStatus -eq 'Valid') { '#3fb950' } elseif ($sigStatus -eq 'NotSigned') { '#d29922' } else { '#8b95a8' }
            [void]$items.Add([pscustomobject]@{
                Risk=$risk; RiskHex=$riskHex; Source=$f.Source
                Name=$_.Name; Command=$exe
                SignerLabel=$signerLabel; SignerHex=$signerHex
            })
        }
    }

    # scheduled tasks running from user-writable paths
    Get-ScheduledTask -ErrorAction SilentlyContinue | ForEach-Object {
        $task = $_
        foreach ($act in @($task.Actions)) {
            $exe = $act.Execute
            if (-not $exe) { continue }
            $exe = $exe.Trim('"')
            $isUserPath = $exe -match '\\AppData\\|\\Users\\Public\\|\\ProgramData\\|\\Temp\\'
            if (-not $isUserPath) { continue }   # only show interesting ones to keep list short
            $resolved = if (Test-Path $exe -ErrorAction SilentlyContinue) { $exe } else { $null }
            $sig = Get-Sig $resolved $sigCache
            $sigStatus = if ($sig) { [string]$sig.Status } else { 'unknown' }
            $signerLabel = if ($sig -and $sig.Status -eq 'Valid' -and $sig.SignerCertificate) {
                ($sig.SignerCertificate.Subject -split ',' | Where-Object { $_ -match '^\s*CN=' } | Select-Object -First 1) -replace '^\s*CN=',''
            } elseif ($sigStatus -eq 'NotSigned') { '(unsigned)' } else { "sig: $sigStatus" }
            if ($sigStatus -eq 'NotSigned') { $risk='HIGH'; $riskHex='#f85149' }
            else { $risk='INFO'; $riskHex='#58a6ff' }
            $signerHex = if ($sigStatus -eq 'Valid') { '#3fb950' } elseif ($sigStatus -eq 'NotSigned') { '#d29922' } else { '#8b95a8' }
            [void]$items.Add([pscustomobject]@{
                Risk=$risk; RiskHex=$riskHex; Source='Task'
                Name="$($task.TaskPath)$($task.TaskName)"
                Command="$exe $($act.Arguments)"
                SignerLabel=$signerLabel; SignerHex=$signerHex
            })
        }
    }

    # auto-start services in user-writable paths
    Get-CimInstance Win32_Service -ErrorAction SilentlyContinue |
        Where-Object { $_.StartMode -eq 'Auto' -and $_.PathName } |
        ForEach-Object {
            $cmd = $_.PathName.Trim('"')
            if ($cmd -match '^"([^"]+)"') { $exe = $matches[1] }
            elseif ($cmd -match '^(\S+\.exe)') { $exe = $matches[1] }
            else { $exe = $cmd }
            if (-not ($exe -match '\\AppData\\|\\Users\\Public\\|\\ProgramData\\|\\Temp\\')) { return }
            $sig = Get-Sig $exe $sigCache
            $sigStatus = if ($sig) { [string]$sig.Status } else { 'unknown' }
            $signerLabel = if ($sig -and $sig.Status -eq 'Valid' -and $sig.SignerCertificate) {
                ($sig.SignerCertificate.Subject -split ',' | Where-Object { $_ -match '^\s*CN=' } | Select-Object -First 1) -replace '^\s*CN=',''
            } elseif ($sigStatus -eq 'NotSigned') { '(unsigned)' } else { "sig: $sigStatus" }
            if ($sigStatus -eq 'NotSigned') { $risk='HIGH'; $riskHex='#f85149' }
            else { $risk='WARN'; $riskHex='#d29922' }
            $signerHex = if ($sigStatus -eq 'Valid') { '#3fb950' } elseif ($sigStatus -eq 'NotSigned') { '#d29922' } else { '#8b95a8' }
            [void]$items.Add([pscustomobject]@{
                Risk=$risk; RiskHex=$riskHex; Source='Service'
                Name=$_.Name; Command=$_.PathName
                SignerLabel=$signerLabel; SignerHex=$signerHex
            })
        }

    # ---- Tier 11: deeper persistence sweep ----

    # AppInit_DLLs (HKLM\Software\Microsoft\Windows NT\CurrentVersion\Windows\AppInit_DLLs)
    foreach ($k in 'HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Windows','HKLM:\SOFTWARE\WOW6432Node\Microsoft\Windows NT\CurrentVersion\Windows') {
        $p = Get-ItemProperty -Path $k -Name AppInit_DLLs -ErrorAction SilentlyContinue
        if ($p -and $p.AppInit_DLLs -and ($p.AppInit_DLLs -as [string]).Trim()) {
            $val = $p.AppInit_DLLs
            $loadAll = (Get-ItemProperty -Path $k -Name LoadAppInit_DLLs -ErrorAction SilentlyContinue).LoadAppInit_DLLs
            $risk = if ($loadAll -eq 1) { 'HIGH' } else { 'WARN' }
            $riskHex = if ($risk -eq 'HIGH') { '#f85149' } else { '#d29922' }
            [void]$items.Add([pscustomobject]@{
                Risk=$risk; RiskHex=$riskHex; Source='AppInit_DLLs'
                Name=(Split-Path $k -Leaf); Command=$val
                SignerLabel=if ($loadAll -eq 1) { 'LoadAppInit_DLLs=1 (active)' } else { 'LoadAppInit_DLLs=0 (inactive but listed)' }
                SignerHex=if ($loadAll -eq 1) { '#f85149' } else { '#d29922' }
            })
        }
    }

    # Image File Execution Options - Debugger hijacks (silent process replacement)
    $ifeoRoot = 'HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Image File Execution Options'
    Get-ChildItem -Path $ifeoRoot -ErrorAction SilentlyContinue | ForEach-Object {
        $dbg = (Get-ItemProperty -Path $_.PSPath -Name Debugger -ErrorAction SilentlyContinue).Debugger
        if ($dbg) {
            # Microsoft signs a few legit ones (e.g. wbem entries point at WerFault/legit binaries)
            $exe = $null
            if ($dbg -match '^"?([^"]+\.exe)"?') { $exe = $matches[1] }
            $sig = Get-Sig $exe $sigCache
            $sigStatus = if ($sig) { [string]$sig.Status } else { 'unknown' }
            $signerLabel = if ($sig -and $sig.Status -eq 'Valid' -and $sig.SignerCertificate) {
                ($sig.SignerCertificate.Subject -split ',' | Where-Object { $_ -match '^\s*CN=' } | Select-Object -First 1) -replace '^\s*CN=',''
            } elseif ($sigStatus -eq 'NotSigned') { '(unsigned)' } else { "sig: $sigStatus" }
            if ($sigStatus -eq 'NotSigned') { $risk='HIGH'; $riskHex='#f85149' }
            else { $risk='WARN'; $riskHex='#d29922' }
            $signerHex = if ($sigStatus -eq 'Valid') { '#3fb950' } elseif ($sigStatus -eq 'NotSigned') { '#d29922' } else { '#8b95a8' }
            [void]$items.Add([pscustomobject]@{
                Risk=$risk; RiskHex=$riskHex; Source='IFEO Debugger'
                Name=$_.PSChildName; Command=$dbg
                SignerLabel=$signerLabel; SignerHex=$signerHex
            })
        }
    }

    # COM hijacks: HKCU\Software\Classes\CLSID\<guid>\InprocServer32 (user-writable, classic hijack vector)
    $clsidRoot = 'HKCU:\Software\Classes\CLSID'
    if (Test-Path $clsidRoot) {
        Get-ChildItem -Path $clsidRoot -ErrorAction SilentlyContinue | ForEach-Object {
            $inproc = "$($_.PSPath)\InprocServer32"
            if (Test-Path $inproc) {
                $val = (Get-ItemProperty -Path $inproc -Name '(default)' -ErrorAction SilentlyContinue).'(default)'
                if ($val) {
                    $exe = $val.Trim('"')
                    $sig = Get-Sig $exe $sigCache
                    $sigStatus = if ($sig) { [string]$sig.Status } else { 'unknown' }
                    $signerLabel = if ($sig -and $sig.Status -eq 'Valid' -and $sig.SignerCertificate) {
                        ($sig.SignerCertificate.Subject -split ',' | Where-Object { $_ -match '^\s*CN=' } | Select-Object -First 1) -replace '^\s*CN=',''
                    } elseif ($sigStatus -eq 'NotSigned') { '(unsigned)' } else { "sig: $sigStatus" }
                    # HKCU CLSID overrides HKLM - this is the hijack mechanism
                    if ($sigStatus -eq 'NotSigned') { $risk='HIGH'; $riskHex='#f85149' }
                    else { $risk='WARN'; $riskHex='#d29922' }
                    $signerHex = if ($sigStatus -eq 'Valid') { '#3fb950' } elseif ($sigStatus -eq 'NotSigned') { '#d29922' } else { '#8b95a8' }
                    [void]$items.Add([pscustomobject]@{
                        Risk=$risk; RiskHex=$riskHex; Source='COM hijack'
                        Name=$_.PSChildName; Command=$val
                        SignerLabel=$signerLabel; SignerHex=$signerHex
                    })
                }
            }
        }
    }

    $items | Sort-Object @{Expression={
        switch ($_.Risk) { 'HIGH'{0} 'WARN'{1} 'INFO'{2} default{3} }
    }}, Source, Name
}

function Start-PersistScanAsync {
    if ($script:State.PersistJob) { return }
    $script:State.PersistJob = Start-Job -Name 'NetJump-Persist' -ScriptBlock $script:PersistScanScript
    $controls.PersistStatus.Text = 'Enumerating Run keys, startup folders, services, scheduled tasks...'
    $controls.PersistRefreshButton.IsEnabled = $false
    $controls.PersistRefreshButton.Content = 'Scanning...'
}

# ---------- Tier 3: DNS cache view (sync; cheap) ----------
$script:SuspiciousTlds = @(
    'tk','ml','ga','cf','top','xyz','icu','work','click','download','stream',
    'review','country','gq','fit','loan','win','men','bid','party','science',
    'pw','su','best','live','rest','support','fyi'
)

function Update-DnsCache {
    $script:DnsItems.Clear()
    $now = Get-Date

    # Determine current resolver(s) so each row can show "via 1.1.1.1, 8.8.8.8" etc.
    $resolverLabel = '?'
    try {
        if ($script:State.Adapter) {
            $cfg = Get-NetIPConfiguration -InterfaceIndex $script:State.Adapter.ifIndex -ErrorAction SilentlyContinue
            if ($cfg -and $cfg.DNSServer) {
                $rs = @($cfg.DNSServer | Where-Object { $_.AddressFamily -eq 2 } | ForEach-Object { $_.ServerAddresses } | Where-Object { $_ })
                if ($rs.Count -eq 0) { $rs = @($cfg.DNSServer | ForEach-Object { $_.ServerAddresses } | Where-Object { $_ -match '^\d+\.\d+\.\d+\.\d+$' }) }
                if ($rs.Count -gt 0) { $resolverLabel = ($rs -join ', ') }
            }
        }
    } catch {}

    $entries = Get-DnsClientCache -ErrorAction SilentlyContinue |
        Where-Object { $_.Type -in 1, 5, 28 -and $_.Name -and $_.Name -notmatch '^\d+\.' } |
        Group-Object Name | ForEach-Object { $_.Group | Select-Object -First 1 } |
        Sort-Object TimeToLive -Descending |
        Select-Object -First 80
    foreach ($e in $entries) {
        $name = $e.Name.TrimEnd('.')
        $typeNum = [int]$e.Type
        $typeLabel = switch ($typeNum) {
            1   { 'A' }
            5   { 'CNAME' }
            12  { 'PTR' }
            15  { 'MX' }
            16  { 'TXT' }
            28  { 'AAAA' }
            33  { 'SRV' }
            257 { 'CAA' }
            default { "type$typeNum" }
        }
        $ttl = [int]$e.TimeToLive

        # ---- Risk heuristics (existing logic preserved) ----
        $reasons = New-Object System.Collections.ArrayList
        $tld = ($name -split '\.')[-1].ToLower()
        if ($script:SuspiciousTlds -contains $tld) { [void]$reasons.Add("suspicious .$tld TLD") }
        if ($name -like 'xn--*') { [void]$reasons.Add('punycode') }
        $label = ($name -split '\.')[0]
        $digits = ([regex]::Matches($label,'\d')).Count
        if ($digits -ge 4 -and $label.Length -ge 6) { [void]$reasons.Add("$digits digits") }
        if ($label -match '[bcdfghjklmnpqrstvwxz]{7,}') { [void]$reasons.Add('7+ consonants run') }
        $unique = ($label.ToCharArray() | Select-Object -Unique).Count
        if ($label.Length -ge 12 -and $unique / $label.Length -gt 0.85) { [void]$reasons.Add('high char-uniqueness') }

        if ($reasons.Count -ge 2)     { $risk='HIGH'; $hex='#f85149' }
        elseif ($reasons.Count -eq 1) { $risk='WARN'; $hex='#d29922' }
        else                          { $risk='OK';   $hex='#3fb950' }

        # ---- History tracking (Tier 27) ----
        $isNewName = $false
        $isCacheRefresh = $false
        if (-not $script:DnsHistoryByName.ContainsKey($name)) {
            $isNewName = $true
            $script:DnsHistoryByName[$name] = @{
                FirstSeen   = $now
                LastSeen    = $now
                HitCount    = 1
                LastTtl     = $ttl
                LastRtt     = $null
                LastRttWhen = $null
                LastResolver = $resolverLabel
            }
        } else {
            $h = $script:DnsHistoryByName[$name]
            # If TTL went UP since last poll, the cache was refreshed (a new resolution happened).
            # Standard behavior: TTL counts down each second in the cache. Going up = re-resolved.
            if ($ttl -gt $h.LastTtl + 1) {
                $h.HitCount++
                $isCacheRefresh = $true
            }
            $h.LastTtl = $ttl
            $h.LastSeen = $now
            $h.LastResolver = $resolverLabel
        }
        # Tier 35: surface DNS resolution events into LIVE EVENTS (tagged Source='dns').
        # Only for new names (first appearance) and explicit cache refreshes (resolver actually queried again).
        # Skip every-poll cache reads to avoid flooding.
        if ($isNewName -and $script:State.HasScanned) {
            # Skip noise during initial scan-baseline DNS sweep - only surface once dashboard is steady-state
            try { Add-Event info ("DNS resolved: {0}" -f $name) -Source 'dns' -Detail ("type={0}  ttl={1}s  via={2}" -f $typeLabel, $ttl, $resolverLabel) } catch {}
        } elseif ($isCacheRefresh) {
            try { Add-Event info ("DNS re-resolved: {0}" -f $name) -Source 'dns' -Detail ("ttl reset to {0}s  hit #{1}  via={2}" -f $ttl, $script:DnsHistoryByName[$name].HitCount, $resolverLabel) } catch {}
        }
        $h = $script:DnsHistoryByName[$name]

        # Format the "history" label compactly: "47 hits  •  first 12m ago  •  last 3s ago"
        $firstAgo = ($now - $h.FirstSeen).TotalSeconds
        $lastAgo  = ($now - $h.LastSeen).TotalSeconds
        function script:_AgoStr([double]$s) {
            if ($s -lt 1)    { return 'now' }
            if ($s -lt 60)   { return ('{0:N0}s' -f $s) }
            if ($s -lt 3600) { return ('{0:N0}m' -f ($s/60)) }
            if ($s -lt 86400){ return ('{0:N0}h' -f ($s/3600)) }
            return ('{0:N0}d' -f ($s/86400))
        }
        $historyLabel = ("{0} hit{1}  -  first {2} ago  -  last {3} ago" -f $h.HitCount, $(if ($h.HitCount -eq 1) {''} else {'s'}), (_AgoStr $firstAgo), (_AgoStr $lastAgo))

        # Format RTT (-- if never timed; "12ms" if recently timed; "12ms (45s ago)" if older)
        $rttLabel = '--'
        $rttFg = '#6a7380'   # faint
        if ($h.LastRtt -ne $null) {
            $rttAgoSec = ($now - $h.LastRttWhen).TotalSeconds
            $rttLabel = if ($rttAgoSec -lt 60) { ('{0}ms' -f $h.LastRtt) } else { ('{0}ms ({1} ago)' -f $h.LastRtt, (_AgoStr $rttAgoSec)) }
            # Color by latency band: <30ms green, <100ms amber, else red
            if ($h.LastRtt -lt 30)        { $rttFg = '#3fb950' }
            elseif ($h.LastRtt -lt 100)   { $rttFg = '#d29922' }
            else                          { $rttFg = '#f85149' }
        }

        # Type chip color: A=blue, AAAA=purple, CNAME=green, others=gray
        $typeBg = switch ($typeLabel) {
            'A'     { '#1a2a40' }
            'AAAA'  { '#2a1a40' }
            'CNAME' { '#0e2a16' }
            default { '#1a1a1a' }
        }
        $typeFg = switch ($typeLabel) {
            'A'     { '#79c0ff' }
            'AAAA'  { '#bf6dff' }
            'CNAME' { '#3fb950' }
            default { '#8b95a8' }
        }

        $script:DnsItems.Add([pscustomobject]@{
            Risk            = $risk
            RiskColor       = (B $hex)
            Name            = $name
            Type            = $typeLabel
            TypeBgBrush     = (B $typeBg)
            TypeFgBrush     = (B $typeFg)
            Detail          = "ttl=${ttl}s  status=$($e.Status)  via=$resolverLabel"
            History         = $historyLabel
            RttLabel        = $rttLabel
            RttColorBrush   = (B $rttFg)
            Why             = ($reasons -join ', ')
        })
    }
    $controls.DnsStatus.Text = "$($script:DnsItems.Count) cached lookup(s) ($($script:DnsHistoryByName.Count) tracked) - $((Get-Date).ToString('HH:mm:ss'))"
}

# Tier 27: actively re-resolve a name and time it with a Stopwatch.
# Updates the history map and refreshes the DNS list so the new RTT shows immediately.
function Invoke-DnsTime {
    param([string]$Name)
    if (-not $Name) { return }
    Add-Event scan ("Timing DNS resolution: {0}" -f $Name) -Source 'dns'
    try {
        $sw = [System.Diagnostics.Stopwatch]::StartNew()
        # -DnsOnly bypasses LLMNR / NetBIOS / hosts file - we want the real DNS RTT
        # -NoHostsFile prevents the local hosts file from short-circuiting
        $resolved = Resolve-DnsName -Name $Name -DnsOnly -NoHostsFile -ErrorAction Stop
        $sw.Stop()
        $rtt = [int]$sw.ElapsedMilliseconds
        if (-not $script:DnsHistoryByName.ContainsKey($Name)) {
            $script:DnsHistoryByName[$Name] = @{
                FirstSeen   = (Get-Date)
                LastSeen    = (Get-Date)
                HitCount    = 1
                LastTtl     = 0
                LastRtt     = $rtt
                LastRttWhen = (Get-Date)
                LastResolver = '?'
            }
        } else {
            $script:DnsHistoryByName[$Name].LastRtt = $rtt
            $script:DnsHistoryByName[$Name].LastRttWhen = (Get-Date)
        }
        $answers = @($resolved | Where-Object { $_.IPAddress }).Count
        Add-Event info ("DNS '{0}' resolved in {1} ms ({2} answer{3})" -f $Name, $rtt, $answers, $(if ($answers -eq 1) {''} else {'s'})) -Source 'dns'
        Update-DnsCache
    } catch {
        Add-Event warn ("DNS time failed for '{0}': {1}" -f $Name, $_.Exception.Message) -Source 'dns'
        try {
            [System.Windows.MessageBox]::Show($window, ("Resolve-DnsName failed for '{0}':`n{1}" -f $Name, $_.Exception.Message), 'DNS time failed', 'OK', 'Warning') | Out-Null
        } catch {}
    }
}

# ---------- Tier 4: session persistence + heatmap ----------
function Save-CurrentSession {
    if (-not $script:State.SessionFile) { return }
    $payload = [pscustomobject]@{
        start    = $script:State.SessionStart.ToString('o')
        end      = (Get-Date).ToString('o')
        adapter  = if ($script:State.Adapter) { $script:State.Adapter.Name } else { '' }
        flaps    = $script:State.SessionFlaps.ToArray()
    }
    try {
        $payload | ConvertTo-Json -Depth 5 | Set-Content $script:State.SessionFile -Encoding UTF8
    } catch {
        # Tier 51: silent failure here would lose the entire session record (start/end/adapter/flaps)
        # which feeds the History heatmap + 7-day stats. Surface so the user knows why History is
        # missing the current session. Rate-limited to once per launch via $script:_SessionSaveErrShown
        # to avoid spamming if the disk is locked.
        try {
            if (-not $script:_SessionSaveErrShown) {
                $script:_SessionSaveErrShown = $true
                Add-Event warn ("Session save failed (history/heatmap won't update): {0}" -f $_.Exception.Message)
            }
        } catch {}
    }
}

function Load-Sessions {
    $script:Sessions.Clear()
    $files = Get-ChildItem $script:SessionsDir -Filter 'session-*.json' -ErrorAction SilentlyContinue |
             Sort-Object LastWriteTime -Descending | Select-Object -First 100
    $allFlaps = New-Object System.Collections.ArrayList
    foreach ($f in $files) {
        try {
            $s = Get-Content $f.FullName -Raw | ConvertFrom-Json
            $start = [datetime]$s.start
            $end = if ($s.end) { [datetime]$s.end } else { $start }
            $count = if ($s.flaps) { @($s.flaps).Count } else { 0 }
            $color = if ($count -ge 5) { '#f85149' } elseif ($count -gt 0) { '#d29922' } else { '#3fb950' }
            $dur = ($end - $start)
            $detail = "{0} on {1}  -  duration {2:hh\:mm\:ss}" -f ($(if ($s.adapter) { $s.adapter } else { '?' })), $start.ToString('yyyy-MM-dd'), $dur
            $script:Sessions.Add([pscustomobject]@{
                When      = $start.ToString('yyyy-MM-dd HH:mm')
                Detail    = $detail
                FlapCount = [string]$count
                FlapColor = (B $color)
            })
            if ($s.flaps) {
                foreach ($fl in $s.flaps) {
                    try { [void]$allFlaps.Add([datetime]$fl.time) } catch {}
                }
            }
        } catch {}
    }
    $script:HistoryFlapTimes = $allFlaps
    $controls.HistoryStatus.Text = ("{0} session(s), {1} flap(s) total" -f $files.Count, $allFlaps.Count)
}

function Redraw-Heatmap {
    $c = $controls.HeatmapCanvas
    $c.Children.Clear()
    $w = [double]$c.ActualWidth;  if ($w -le 0) { return }
    $h = [double]$c.ActualHeight; if ($h -le 0) { return }

    # build 24x7 grid (hour x dayOfWeek where Monday=0..Sunday=6 for nicer order)
    $grid = New-Object 'object[,]' 7,24
    for ($d=0; $d -lt 7; $d++) { for ($hr=0; $hr -lt 24; $hr++) { $grid[$d,$hr] = 0 } }
    if ($script:HistoryFlapTimes) {
        foreach ($t in $script:HistoryFlapTimes) {
            $dow = ([int]$t.DayOfWeek + 6) % 7   # 0 = Monday
            $hr  = $t.Hour
            $grid[$dow,$hr] = [int]$grid[$dow,$hr] + 1
        }
    }
    $maxCount = 0
    for ($d=0; $d -lt 7; $d++) { for ($hr=0; $hr -lt 24; $hr++) { if ($grid[$d,$hr] -gt $maxCount) { $maxCount = $grid[$d,$hr] } } }
    if ($maxCount -le 0) { $maxCount = 1 }

    $marginLeft = 32
    $cellW = ($w - $marginLeft) / 24
    $cellH = $h / 7 - 2

    $days = 'Mon','Tue','Wed','Thu','Fri','Sat','Sun'
    for ($d=0; $d -lt 7; $d++) {
        $dl = New-Object System.Windows.Controls.TextBlock
        $dl.Text = $days[$d]
        $dl.Foreground = [System.Windows.Media.Brushes]::DimGray
        $dl.FontSize = 10
        [System.Windows.Controls.Canvas]::SetLeft($dl, 0)
        [System.Windows.Controls.Canvas]::SetTop($dl, $d * ($cellH + 2) + 2)
        [void]$c.Children.Add($dl)
        for ($hr=0; $hr -lt 24; $hr++) {
            $val = [int]$grid[$d,$hr]
            $intensity = $val / $maxCount
            $hex = if ($val -le 0) { '#1a2030' }
                   elseif ($intensity -lt 0.25) { '#5a2228' }
                   elseif ($intensity -lt 0.5)  { '#8c2a32' }
                   elseif ($intensity -lt 0.75) { '#bf3d48' }
                   else                          { '#f85149' }
            $rect = New-Object System.Windows.Shapes.Rectangle -Property @{
                Width = [Math]::Max(2, $cellW - 2)
                Height = $cellH
                Fill = (B $hex)
            }
            if ($val -gt 0) { $rect.ToolTip = ("{0} {1:D2}:00 - {2} flap(s)" -f $days[$d], $hr, $val) }
            [System.Windows.Controls.Canvas]::SetLeft($rect, $marginLeft + $hr * $cellW)
            [System.Windows.Controls.Canvas]::SetTop($rect, $d * ($cellH + 2))
            [void]$c.Children.Add($rect)
        }
    }
    # hour ticks every 6h
    foreach ($hr in 0,6,12,18) {
        $tk = New-Object System.Windows.Controls.TextBlock
        $tk.Text = ("{0:D2}" -f $hr)
        $tk.Foreground = [System.Windows.Media.Brushes]::DimGray
        $tk.FontSize = 9
        [System.Windows.Controls.Canvas]::SetLeft($tk, $marginLeft + $hr * $cellW)
        [System.Windows.Controls.Canvas]::SetTop($tk, 7 * ($cellH + 2) - 2)
        [void]$c.Children.Add($tk)
    }
}

function Refresh-History {
    Load-Sessions
    Redraw-Heatmap
    Update-HistorySummary
}

# Tier 36: compute summary stats from $script:Sessions and populate the HISTORY summary card.
# Stats: total sessions, total flaps, avg flaps/session, clean-session count, worst session.
function Update-HistorySummary {
    if (-not $controls -or -not $controls.HistorySumSessions) { return }
    try {
        $total = if ($script:Sessions) { @($script:Sessions).Count } else { 0 }
        $flapCounts = @()
        if ($script:Sessions) {
            foreach ($s in $script:Sessions) {
                try { $flapCounts += [int]$s.FlapCount } catch {}
            }
        }
        $totalFlaps = if ($flapCounts.Count -gt 0) { ($flapCounts | Measure-Object -Sum).Sum } else { 0 }
        $avgFlaps = if ($total -gt 0) { [Math]::Round($totalFlaps / $total, 1) } else { 0 }
        $cleanCount = @($flapCounts | Where-Object { $_ -eq 0 }).Count
        $worstFlaps = if ($flapCounts.Count -gt 0) { ($flapCounts | Measure-Object -Maximum).Maximum } else { 0 }

        $controls.HistorySumSessions.Text = ('{0}' -f $total)
        $controls.HistorySumFlaps.Text    = ('{0}' -f $totalFlaps)
        $controls.HistorySumAvg.Text      = ('{0:N1}' -f $avgFlaps)
        $controls.HistorySumClean.Text    = ('{0}' -f $cleanCount)
        $controls.HistorySumWorst.Text    = ('{0}' -f $worstFlaps)

        # Color the AVG number: green if low, amber if medium, red if high
        $controls.HistorySumAvg.Foreground = (B $(
            if ($avgFlaps -ge 5) { '#f85149' }
            elseif ($avgFlaps -ge 1) { '#d29922' }
            else { '#3fb950' }
        ))
    } catch {}
}

# ---------- Tier 5: NIC driver crash-dump / BugCheck scanner ----------
$script:NicDriverPatterns = @(
    'e1[a-z0-9]+\.sys',     # Intel e1d68x64 etc.
    'igbn?\.sys',
    'rt[a-z0-9]+\.sys',     # Realtek
    'netr[a-z0-9]+\.sys',   # generic NDIS
    'killer[a-z0-9]*\.sys',
    'qcamain[0-9]*\.sys',   # Qualcomm
    'nicdrvr.sys',
    'tcpip\.sys',           # rare but possible
    'ndis\.sys'
)

function Get-NicDriverCrashes {
    $since = (Get-Date).AddDays(-30)
    # Each Get-WinEvent FilterHashtable can throw a terminating exception ("The parameter is incorrect")
    # if the named provider isn't registered on this machine, OR if no matching events exist
    # (Get-WinEvent specifically raises "No events were found..." which is non-terminating, but
    # "Provider not found" is terminating regardless of -ErrorAction). Wrap each call individually.
    $events = New-Object System.Collections.Generic.List[object]
    $filters = @(
        @{LogName='System'; ProviderName='Microsoft-Windows-WER-SystemErrorReporting'; StartTime=$since}
        @{LogName='System'; Id=1001; StartTime=$since}
        @{LogName='System'; ProviderName='BugCheck'; StartTime=$since}
    )
    foreach ($flt in $filters) {
        try {
            $batch = Get-WinEvent -FilterHashtable $flt -MaxEvents 50 -ErrorAction Stop
            foreach ($ev in @($batch)) { if ($ev) { [void]$events.Add($ev) } }
        } catch {
            # Provider missing, no matching events, or insufficient permissions - skip silently.
        }
    }
    $hits = New-Object System.Collections.ArrayList
    foreach ($e in $events) {
        if (-not $e -or -not $e.Message) { continue }
        $msg = $e.Message
        foreach ($pat in $script:NicDriverPatterns) {
            try {
                $m = [regex]::Match($msg, $pat, 'IgnoreCase')
                if ($m.Success) {
                    $cleaned = ($msg -replace "`r?`n",' ') -replace '\s+',' '
                    $snippet = if ($cleaned.Length -gt 140) { $cleaned.Substring(0, 140) } else { $cleaned }
                    [void]$hits.Add([pscustomobject]@{
                        Time    = $e.TimeCreated
                        Driver  = $m.Value.ToLower()
                        Source  = $e.ProviderName
                        Snippet = $snippet
                    })
                    break
                }
            } catch {}
        }
    }
    return $hits
}

# ---------- Tier 5: flap periodicity detector ----------
function Get-FlapPeriodicity {
    param([datetime[]]$Times)
    if (-not $Times -or $Times.Count -lt 4) { return $null }
    $sorted = $Times | Sort-Object
    $candidates = @(
        @{ Sec=60;       Label='~1 min'   }
        @{ Sec=300;      Label='~5 min'   }
        @{ Sec=600;      Label='~10 min'  }
        @{ Sec=900;      Label='~15 min'  }
        @{ Sec=1800;     Label='~30 min'  }
        @{ Sec=2820;     Label='~47 min'  }   # DHCP T1 default
        @{ Sec=3600;     Label='~1 hour'  }
        @{ Sec=7200;     Label='~2 hours' }
        @{ Sec=14400;    Label='~4 hours' }
        @{ Sec=21600;    Label='~6 hours' }
        @{ Sec=43200;    Label='~12 hours' }
        @{ Sec=86400;    Label='~24 hours' }
    )
    $best = $null
    foreach ($c in $candidates) {
        $p = $c.Sec
        $mods = @($sorted | ForEach-Object { ($_.Subtract([datetime]'1970-01-01').TotalSeconds) % $p })
        # circular distance: pick a phase that minimizes spread
        $sorted_m = $mods | Sort-Object
        # find tightest cluster (min spread treating mod axis as circular)
        $spread = ($sorted_m | Measure-Object -Maximum).Maximum - ($sorted_m | Measure-Object -Minimum).Minimum
        $rotated = @()
        for ($i=0; $i -lt $sorted_m.Count; $i++) { $rotated += ($sorted_m[$i] + $p - $sorted_m[0]) % $p }
        $spreadRot = ($rotated | Measure-Object -Maximum).Maximum - ($rotated | Measure-Object -Minimum).Minimum
        $minSpread = [Math]::Min($spread, $spreadRot)
        $tightness = 1 - ($minSpread / $p)
        if (-not $best -or $tightness -gt $best.Tightness) {
            $best = [pscustomobject]@{ Period = $c.Sec; Label = $c.Label; Tightness = $tightness }
        }
    }
    if ($best -and $best.Tightness -ge 0.85) { return $best }
    return $null
}

# ---------- Tier 5: per-flap context tracker (for correlation engine) ----------
$script:FlapContexts = New-Object System.Collections.Generic.List[object]

function Capture-FlapContext {
    param([int]$FlapNumber)
    # snapshot the events in the last 30 seconds
    $cutoff = (Get-Date).AddSeconds(-30)
    $recentEvents = @($script:Events | Where-Object {
        try { [datetime]::ParseExact($_.Time, 'HH:mm:ss', $null) } catch { return $false }
        # comparing time-of-day; close enough for window detection
        $true
    } | Select-Object -Last 30)
    # also capture counter snapshot at flap moment
    $rxErr  = if ($script:State.RxErrHistory.Count -gt 0)  { $script:State.RxErrHistory[$script:State.RxErrHistory.Count - 1]  } else { 0 }
    $rxDisc = if ($script:State.RxDiscHistory.Count -gt 0) { $script:State.RxDiscHistory[$script:State.RxDiscHistory.Count - 1] } else { 0 }
    $gwLost = ($script:State.LossWarnedGw)
    $cfLost = ($script:State.LossWarnedCf)
    # event-type tags from recent events panel text
    $tags = @()
    foreach ($e in $recentEvents) {
        $t = [string]$e.Text
        if ($t -match 'RX errors spiking')   { $tags += 'rx-error-spike' }
        if ($t -match 'ping lost|ping LOST') { $tags += 'ping-loss' }
        if ($t -match 'Speed change')        { $tags += 'speed-change' }
        if ($t -match 'Defender')            { $tags += 'defender-active' }
        if ($t -match 'pktmon|capture')      { $tags += 'capture-event' }
    }
    if ($rxErr -ge 5)  { $tags += 'rx-error-spike' }
    if ($rxDisc -ge 5) { $tags += 'rx-discard-spike' }
    if ($gwLost) { $tags += 'gateway-lost' }
    if ($cfLost) { $tags += 'cloudflare-lost' }

    # Tier 6 tags: LAN fan-out + retransmit/CPU spikes
    if ($script:State.LastLanResults) {
        $lan = $script:State.LastLanResults
        if ($lan.Total -gt 0) {
            if ($lan.Reachable -eq 0)               { $tags += 'lan-isolated' }
            elseif ($lan.Reachable -eq $lan.Total)  { $tags += 'lan-only-me' }
            else                                    { $tags += 'lan-partial' }
        }
    }
    $recentRetrans = if ($script:State.RetransHistory.Count -gt 0) { $script:State.RetransHistory[$script:State.RetransHistory.Count - 1] } else { 0 }
    if ($recentRetrans -ge 5) { $tags += 'tcp-retrans-spike' }
    $recentCpu = if ($script:State.CpuMaxHistory.Count -gt 0) { $script:State.CpuMaxHistory[$script:State.CpuMaxHistory.Count - 1] } else { 0 }
    if ($recentCpu -ge 95) { $tags += 'cpu-pinned' }

    $tags = $tags | Select-Object -Unique
    $script:FlapContexts.Add([pscustomobject]@{
        FlapNumber = $FlapNumber
        Time       = Get-Date
        Tags       = $tags
        RxErr      = $rxErr
        RxDisc     = $rxDisc
        LanReachable = if ($script:State.LastLanResults) { $script:State.LastLanResults.Reachable } else { 0 }
        LanTotal     = if ($script:State.LastLanResults) { $script:State.LastLanResults.Total } else { 0 }
    })
    while ($script:FlapContexts.Count -gt 30) { $script:FlapContexts.RemoveAt(0) }
}

function Get-FlapCorrelations {
    if ($script:FlapContexts.Count -lt 3) { return $null }
    $tagCounts = @{}
    foreach ($ctx in $script:FlapContexts) {
        foreach ($t in $ctx.Tags) {
            if ($tagCounts.ContainsKey($t)) { $tagCounts[$t]++ } else { $tagCounts[$t] = 1 }
        }
    }
    $total = $script:FlapContexts.Count
    $significant = @()
    foreach ($k in $tagCounts.Keys) {
        $share = $tagCounts[$k] / $total
        if ($share -ge 0.6) {
            $significant += [pscustomobject]@{ Tag = $k; Hits = $tagCounts[$k]; Total = $total; Share = $share }
        }
    }
    if ($significant.Count -eq 0) { return $null }
    return ($significant | Sort-Object Share -Descending)
}

# ---------- Tier 5: pktmon ETL timeline parser ----------
function Parse-PktmonTimeline {
    param([string]$TxtPath, [string]$OutPath)
    if (-not (Test-Path $TxtPath)) { return $null }
    $lines = Get-Content $TxtPath -ErrorAction SilentlyContinue -Tail 5000
    if (-not $lines) { return $null }
    $buckets = @{}    # key=second, value=hashtable of counts
    $rxArp = 0; $rxDhcp = 0; $rxDns = 0; $rxRst = 0; $rxIcmp = 0
    foreach ($l in $lines) {
        # pktmon etl2txt format varies; look for common markers
        $isArp  = $l -match '\b(ARP|0x0806)\b'
        $isDhcp = $l -match '\b(DHCP|bootp|0x0044|0x0043|port (67|68))\b' -or $l -match '\b(67|68)\s*->\s*(67|68)\b'
        $isDns  = $l -match '\bDNS\b' -or $l -match '\bport 53\b' -or $l -match '\b53\s*->\b'
        $isIcmp = $l -match '\bICMP\b' -or $l -match '\b0x0001\b'
        $isRst  = $l -match '\bTCP\b.*\bR(ST)?\b' -or $l -match '\[RST\]'
        if ($isArp)  { $rxArp++  }
        if ($isDhcp) { $rxDhcp++ }
        if ($isDns)  { $rxDns++  }
        if ($isIcmp) { $rxIcmp++ }
        if ($isRst)  { $rxRst++  }
    }
    $sb = New-Object System.Text.StringBuilder
    [void]$sb.AppendLine("# Flap capture timeline summary")
    [void]$sb.AppendLine("# Generated $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')")
    [void]$sb.AppendLine("# Source: $TxtPath")
    [void]$sb.AppendLine('')
    [void]$sb.AppendLine("Lines analyzed (last 5000): $($lines.Count)")
    [void]$sb.AppendLine("Protocol observations:")
    [void]$sb.AppendLine("  ARP frames     : $rxArp")
    [void]$sb.AppendLine("  DHCP frames    : $rxDhcp")
    [void]$sb.AppendLine("  DNS frames     : $rxDns")
    [void]$sb.AppendLine("  ICMP frames    : $rxIcmp")
    [void]$sb.AppendLine("  TCP RST frames : $rxRst")
    [void]$sb.AppendLine('')
    if ($rxArp -gt 50)  { [void]$sb.AppendLine("[NOTE] High ARP volume - possible ARP storm or scanner activity.") }
    if ($rxDhcp -gt 5)  { [void]$sb.AppendLine("[NOTE] DHCP activity around flap - lease renew or full DISCOVER cycle.") }
    if ($rxRst -gt 20)  { [void]$sb.AppendLine("[NOTE] Many TCP resets - upstream may have dropped connections during flap.") }
    if ($rxIcmp -gt 30) { [void]$sb.AppendLine("[NOTE] High ICMP traffic - could be ping floods or unreachable replies.") }
    $text = $sb.ToString()
    if ($OutPath) {
        try { $text | Set-Content $OutPath -Encoding UTF8 } catch {}
    }
    return [pscustomobject]@{
        Arp = $rxArp; Dhcp = $rxDhcp; Dns = $rxDns; Icmp = $rxIcmp; Rst = $rxRst
        Summary = $text
    }
}

# ---------- Tier 33: synthetic cause for sustained high TCP retransmits ----------
# When the heavy-tick block detects sustained high retransmits but no scan-derived cause exists,
# inject a cause row carrying known-good SAFE fixes (NIC power mgmt off, offload toggles, etc).
# This way the Apply Recommended Fixes picker has something concrete to do for the retrans case.
# Idempotent: replaces the previous synthetic-retrans cause if one exists.
function Inject-RetransCause {
    param([double]$RatioPct, [double]$RatePerSec, [string]$VerdictLabel)
    if (-not $script:Causes) { return }
    $aname = if ($script:State.Adapter) { $script:State.Adapter.Name } else { '' }
    if (-not $aname) { return }

    # Build the SAFE fix list - all reversible, all known-good for this symptom class.
    # Each fix has Description / Command. Risk classification happens in Show-FixPickerDialog._FixRisk.
    $fixes = New-Object System.Collections.Generic.List[object]
    [void]$fixes.Add(@{
        Description = "Disable NIC power management on '$aname' (most common cause of laptop/Wi-Fi retransmit storms)"
        Command     = "Disable-NetAdapterPowerManagement -Name '$aname' -AllowComputerToTurnOffDevice -ErrorAction SilentlyContinue"
    })
    [void]$fixes.Add(@{
        Description = "Disable Selective Suspend on '$aname' (stops the OS from sleeping the NIC mid-flow)"
        Command     = "Set-NetAdapterAdvancedProperty -Name '$aname' -DisplayName 'Selective Suspend' -DisplayValue 'Disabled' -ErrorAction SilentlyContinue"
    })
    [void]$fixes.Add(@{
        Description = 'Flush DNS resolver cache (clears any stale records that might be steering to a degraded server)'
        Command     = 'ipconfig /flushdns | Out-Null'
    })
    [void]$fixes.Add(@{
        Description = "Disable NIC Energy-Efficient Ethernet on '$aname' (link-renegotiation can cause brief drops)"
        Command     = "Set-NetAdapterAdvancedProperty -Name '$aname' -DisplayName 'Energy-Efficient Ethernet' -DisplayValue 'Disabled' -ErrorAction SilentlyContinue"
    })
    [void]$fixes.Add(@{
        Description = 'Reset TCP autotuning to "normal" (forces sane window scaling - some routers handle aggressive scaling poorly)'
        Command     = 'netsh int tcp set global autotuninglevel=normal | Out-Null'
    })
    [void]$fixes.Add(@{
        Description = 'Disable TCP timestamps (some middleboxes / NATs corrupt these and cause retransmits)'
        Command     = 'netsh int tcp set global timestamps=disabled | Out-Null'
    })

    # Cause row matching the existing schema (Cause / Evidence / Recommendation / ConfidenceLabel / ColorBrush + Fixes)
    $confidence = if ($VerdictLabel -eq 'CRITICAL') { 75 } elseif ($VerdictLabel -eq 'HIGH') { 60 } else { 40 }
    $hex = if ($VerdictLabel -eq 'CRITICAL') { '#f85149' } else { '#d29922' }
    $causeRow = [pscustomobject]@{
        Cause           = ("Sustained TCP retransmits ({0})" -f $VerdictLabel)
        Evidence        = ("{0:N1}/s sustained ({1:N2}% ratio) - kernel TCP stack is repeatedly resending segments. Common drivers: NIC power-mgmt sleeping during low-activity bursts, Wi-Fi interference, buggy offloads (LSO/RSS), or path MTU black holes." -f $RatePerSec, $RatioPct)
        Recommendation  = 'Try the SAFE fixes first (power-mgmt off, EEE off, autotuning=normal). If retransmits persist, run path-MTU probe and check the TOP RETRANS SUSPECTS list for one process dominating.'
        Confidence      = $confidence
        ConfidenceLabel = ("{0}%" -f $confidence)
        Color           = $hex
        ColorBrush      = (B $hex)
        Fixes           = $fixes
    }

    # Idempotent insert: remove any prior synthetic retrans cause, prepend the new one
    $existing = @($script:Causes | Where-Object { $_.Cause -like 'Sustained TCP retransmits*' })
    foreach ($e in $existing) { [void]$script:Causes.Remove($e) }
    # Insert at the top so it dominates the causes list (it's the most pressing actionable item)
    if ($script:Causes.Count -gt 0) {
        $script:Causes.Insert(0, $causeRow)
    } else {
        $script:Causes.Add($causeRow)
    }
    if ($controls -and $controls.CausesNote) {
        $controls.CausesNote.Text = ("synthetic retrans cause injected (verdict: {0})" -f $VerdictLabel)
    }
}

# ---------- Tier 5: root-cause synthesizer ----------
function Compute-RootCauses {
    param($Adapter, $Findings, $CrashHits, $Periodicity, $Correlations, $FlapCount72h)

    $candidates = @()
    $adapterName = if ($Adapter) { $Adapter.Name } else { '' }

    # Helper: build per-cause auto-fix command lists. Each fix is @{Description; Command}.
    # The Cause card's Fix button reads $cause.Fixes directly, so these are deterministic
    # (no fuzzy matching against $RecommendedFixes).
    function _PowerSavingFixes {
        param($Findings, $aname)
        $out = @()
        $powerFindings = @($Findings | Where-Object { $_.Category -eq 'Power' -and $_.Level -in 'WARN','FAIL' })
        foreach ($pf in $powerFindings) {
            # Power finding messages are formatted "DisplayName = DisplayValue"
            if ($pf.Message -match '^([^=]+?)\s*=\s*(.+?)$') {
                $dispName = $matches[1].Trim()
                if ($dispName -eq 'Windows is allowed to power down the NIC.') {
                    $out += @{ Description = "Prevent Windows from powering down '$aname'"
                               Command     = "Disable-NetAdapterPowerManagement -Name '$aname' -AllowComputerToTurnOffDevice -ErrorAction Stop" }
                } else {
                    $out += @{ Description = "Disable '$dispName' on $aname"
                               Command     = "Set-NetAdapterAdvancedProperty -Name '$aname' -DisplayName '$dispName' -DisplayValue 'Disabled' -ErrorAction Stop" }
                }
            } elseif ($pf.Message -match 'power down') {
                $out += @{ Description = "Prevent Windows from powering down '$aname'"
                           Command     = "Disable-NetAdapterPowerManagement -Name '$aname' -AllowComputerToTurnOffDevice -ErrorAction Stop" }
            }
        }
        return $out
    }

    function _NdisFilterFixes {
        param($Findings, $aname)
        $out = @()
        $filterFindings = @($Findings | Where-Object { $_.Category -eq 'Filters' -and $_.Level -eq 'INFO' })
        foreach ($ff in $filterFindings) {
            # Message format: "Non-standard NDIS filter: DisplayName (ComponentID)"
            if ($ff.Message -match '\(([^)]+)\)\s*$') {
                $cid = $matches[1].Trim()
                $disp = if ($ff.Message -match ':\s*(.+?)\s*\(') { $matches[1].Trim() } else { $cid }
                $out += @{ Description = "Disable NDIS binding '$disp' on $aname (re-enable: Enable-NetAdapterBinding -Name '$aname' -ComponentID '$cid')"
                           Command     = "Disable-NetAdapterBinding -Name '$aname' -ComponentID '$cid' -ErrorAction Stop" }
            }
        }
        return $out
    }

    function _UpstreamFixes {
        param($aname)
        return @(
            @{ Description = 'Flush DNS resolver cache'
               Command     = 'ipconfig /flushdns | Out-Null' }
            @{ Description = "Release + renew DHCP lease on '$aname'"
               Command     = "ipconfig /release '$aname' | Out-Null; Start-Sleep -Milliseconds 500; ipconfig /renew '$aname' | Out-Null" }
            @{ Description = "Set DNS servers to Cloudflare (1.1.1.1, 1.0.0.1) on '$aname' - re-enable DHCP via: Set-DnsClientServerAddress -InterfaceAlias '$aname' -ResetServerAddresses"
               Command     = "Set-DnsClientServerAddress -InterfaceAlias '$aname' -ServerAddresses '1.1.1.1','1.0.0.1' -ErrorAction Stop" }
        )
    }

    function _MalwareFixes {
        return @(
            @{ Description = 'Run Defender quick scan in background'
               Command     = 'Start-MpScan -ScanType QuickScan -AsJob | Out-Null' }
            @{ Description = "Disable system proxy (re-enable: Set-ItemProperty 'HKCU:\Software\Microsoft\Windows\CurrentVersion\Internet Settings' ProxyEnable 1)"
               Command     = "Set-ItemProperty 'HKCU:\Software\Microsoft\Windows\CurrentVersion\Internet Settings' -Name ProxyEnable -Value 0 -ErrorAction SilentlyContinue" }
            @{ Description = 'Update Defender signatures'
               Command     = 'Update-MpSignature -ErrorAction SilentlyContinue' }
        )
    }

    # gather signal counts from findings
    $powerFlags = @($Findings | Where-Object { $_.Category -eq 'Power' -and $_.Level -eq 'WARN' }).Count
    $cableHealth = ($Findings | Where-Object Category -eq 'Cable' | Select-Object -First 1)
    $cableScore = 100
    if ($cableHealth -and $cableHealth.Message -match 'Cable health: (\d+)/100') { $cableScore = [int]$matches[1] }
    $driverWarn = @($Findings | Where-Object { $_.Category -eq 'Driver' -and $_.Level -in 'WARN','FAIL' }).Count
    $rxErrFail  = @($Findings | Where-Object { $_.Category -eq 'Counters' -and $_.Level -eq 'FAIL' }).Count
    $ndisInfo   = @($Findings | Where-Object { $_.Category -eq 'Filters' -and $_.Level -eq 'INFO' }).Count
    $dnsFail    = @($Findings | Where-Object { $_.Category -eq 'DNS' -and $_.Level -in 'WARN','FAIL' }).Count
    $malWarn    = @($Findings | Where-Object { $_.Category -eq 'Malware' -and $_.Level -eq 'WARN' }).Count
    $crashHit   = @($CrashHits).Count
    $hasUpdate  = [bool]($Findings | Where-Object { $_.Category -eq 'Updates' -and $_.Level -eq 'INFO' })
    $cableFail  = $cableScore -lt 50

    # 1. Driver power-saving
    $score = 0
    $ev = New-Object System.Collections.ArrayList
    if ($powerFlags -gt 0) {
        $score += [Math]::Min(80, $powerFlags * 25)
        [void]$ev.Add("$powerFlags power-saving flag(s) enabled")
    }
    if ($FlapCount72h -ge 5 -and $powerFlags -gt 0) {
        $score += 20; [void]$ev.Add("$FlapCount72h flaps in 72h correlate with the flags")
    }
    if ($score -gt 0) {
        $psFixes = _PowerSavingFixes $Findings $adapterName
        $candidates += [pscustomobject]@{
            Cause          = 'Driver power-saving features (EEE / Green Ethernet / Power Saving)'
            Score          = $score
            Evidence       = ($ev -join '; ')
            Recommendation = if ($psFixes.Count -gt 0) { "$($psFixes.Count) auto-fix(es) available - click Fix to apply." } else { "Click 'Apply recommended fixes' below." }
            Color          = '#f85149'
            Fixes          = $psFixes
        }
    }

    # 2. Physical layer (cable / port)
    $score = 0; $ev = New-Object System.Collections.ArrayList
    if ($cableScore -lt 80) { $score += (80 - $cableScore); [void]$ev.Add("cable health $cableScore/100") }
    if ($rxErrFail -gt 0)   { $score += 35; [void]$ev.Add('high RX error rate') }
    if ($cableFail)         { $score += 25 }
    if ($FlapCount72h -ge 5 -and $powerFlags -eq 0) { $score += 30; [void]$ev.Add("$FlapCount72h flaps + no power-saving culprit") }
    if ($score -gt 0) {
        $candidates += [pscustomobject]@{
            Cause          = 'Physical layer (bad cable, switch port, or NIC hardware)'
            Score          = $score
            Evidence       = ($ev -join '; ')
            Recommendation = 'Swap to a known-good Cat5e/Cat6 cable; try a different port on the switch/router. (No software auto-fix - this is a hardware action.)'
            Color          = '#d29922'
            Fixes          = @()   # cable swaps are physical
        }
    }

    # 3. Buggy / outdated driver
    $score = 0; $ev = New-Object System.Collections.ArrayList
    if ($driverWarn -gt 0) { $score += 35; [void]$ev.Add('driver flagged as old') }
    if ($crashHit -gt 0)   { $score += 50; [void]$ev.Add("$crashHit BSOD(s) reference NIC driver in last 30d") }
    if ($hasUpdate -and $FlapCount72h -gt 0) { $score += 25; [void]$ev.Add('recent Windows update + new flaps') }
    if ($score -gt 0) {
        $candidates += [pscustomobject]@{
            Cause          = 'NIC driver bug or version regression'
            Score          = $score
            Evidence       = ($ev -join '; ')
            Recommendation = "Use Diagnose menu - 'NIC driver versions...' to roll back or pick a different driver. Then update from chipset vendor (not Windows Update)."
            Color          = '#d29922'
            Fixes          = @(
                @{ Description = 'Open Diagnose menu - NIC driver versions... to choose a driver'
                   Command     = 'Invoke-DriverPicker' }
            )
        }
    }

    # 4. NDIS / 3rd-party network filter
    $score = 0; $ev = New-Object System.Collections.ArrayList
    if ($ndisInfo -gt 0) { $score += $ndisInfo * 20; [void]$ev.Add("$ndisInfo non-Microsoft NDIS filter(s)") }
    if ($ndisInfo -gt 0 -and $powerFlags -eq 0 -and $cableScore -ge 80) {
        $score += 15; [void]$ev.Add('no other obvious cause flagged')
    }
    if ($score -gt 0) {
        $ndisFixes = _NdisFilterFixes $Findings $adapterName
        $candidates += [pscustomobject]@{
            Cause          = 'Third-party NDIS filter (VPN / antivirus / endpoint product)'
            Score          = $score
            Evidence       = ($ev -join '; ')
            Recommendation = if ($ndisFixes.Count -gt 0) { "$($ndisFixes.Count) NDIS binding(s) can be auto-disabled - click Fix to apply." } else { 'Temporarily disable VPN clients / endpoint protection and re-test.' }
            Color          = '#58a6ff'
            Fixes          = $ndisFixes
        }
    }

    # 5. Upstream (ISP / router)
    $score = 0; $ev = New-Object System.Collections.ArrayList
    if ($dnsFail -gt 0) { $score += 30; [void]$ev.Add('DNS issues observed') }
    # if cable + power look fine, suspect upstream
    if ($cableScore -ge 80 -and $powerFlags -eq 0 -and $FlapCount72h -ge 5) {
        $score += 25; [void]$ev.Add('flaps with healthy local NIC')
    }
    if ($score -gt 0) {
        $upFixes = _UpstreamFixes $adapterName
        $candidates += [pscustomobject]@{
            Cause          = 'Upstream device (router / ISP)'
            Score          = $score
            Evidence       = ($ev -join '; ')
            Recommendation = "$($upFixes.Count) DNS/DHCP auto-fixes available. If drops continue after, reboot the router; if only Cloudflare/Google ping fails, contact ISP."
            Color          = '#58a6ff'
            Fixes          = $upFixes
        }
    }

    # 6. Possible malware
    $score = 0; $ev = New-Object System.Collections.ArrayList
    if ($malWarn -gt 0) { $score += $malWarn * 20; [void]$ev.Add("$malWarn malware indicator(s)") }
    if ($score -gt 0) {
        $mwFixes = _MalwareFixes
        $candidates += [pscustomobject]@{
            Cause          = 'Possible compromise / unwanted software'
            Score          = $score
            Evidence       = ($ev -join '; ')
            Recommendation = "$($mwFixes.Count) auto-fixes available (Defender scan + proxy clear + sig update). Then review PROCESSES + PERSISTENCE tabs."
            Color          = '#f85149'
            Fixes          = $mwFixes
        }
    }

    # apply correlation boost
    if ($Correlations) {
        foreach ($corr in $Correlations) {
            $boost = [int]($corr.Share * 15)
            switch -Regex ($corr.Tag) {
                'rx-error|rx-discard'  { $candidates | Where-Object Cause -match 'Physical' | ForEach-Object { $_.Score += $boost } }
                'defender'             { $candidates | Where-Object Cause -match 'malware|3rd|compromise' | ForEach-Object { $_.Score += $boost } }
                'tcp-retrans-spike'    { $candidates | Where-Object Cause -match 'Physical|Upstream' | ForEach-Object { $_.Score += $boost } }
                'cpu-pinned'           { $candidates | Where-Object Cause -match 'Driver|filter' | ForEach-Object { $_.Score += [int]($boost * 1.5) } }
                'lan-only-me'          { $candidates | Where-Object Cause -match 'Physical|Driver' | ForEach-Object { $_.Score += [int]($boost * 2) } }
                'lan-isolated'         { $candidates | Where-Object Cause -match 'Upstream' | ForEach-Object { $_.Score += [int]($boost * 2) } }
            }
        }
    }
    if ($Periodicity) {
        # periodicity often points at scheduled jobs / DHCP
        $candidates += [pscustomobject]@{
            Cause          = "Periodic trigger ($($Periodicity.Label))"
            Score          = [int]($Periodicity.Tightness * 100)
            Evidence       = "flap timestamps cluster at $($Periodicity.Label) intervals (tightness $([int]($Periodicity.Tightness*100))%)"
            Recommendation = 'Match interval to scheduled tasks (Task Scheduler), DHCP T1/T2, or ISP billing cycles. ~47 min on Comcast = DHCP T1. (Diagnostic only - no auto-fix.)'
            Color          = '#bf6dff'
            Fixes          = @()    # diagnostic only
        }
    }

    # normalize: clamp, sort, take top 3, compute confidence %
    $sorted = $candidates | Sort-Object Score -Descending
    $top = @($sorted | Select-Object -First 3)
    $sumTop = ($top | Measure-Object -Property Score -Sum).Sum
    if ($sumTop -le 0) { return @() }
    foreach ($c in $top) {
        $c | Add-Member -NotePropertyName Confidence -NotePropertyValue ([int](100 * $c.Score / [Math]::Max($sumTop,1))) -Force
        $c | Add-Member -NotePropertyName ConfidenceLabel -NotePropertyValue ("{0}%" -f $c.Confidence) -Force
        $c | Add-Member -NotePropertyName ColorBrush -NotePropertyValue (B $c.Color) -Force
    }
    return $top
}

# ---------- Tier 6: TCP retransmits + per-core CPU sampling (FAST .NET-native) ----------
# TCP retransmits via IPGlobalProperties (~1ms vs 50-200ms for Get-Counter)
function Sample-TcpRetransmits {
    try {
        $tcp = [System.Net.NetworkInformation.IPGlobalProperties]::GetIPGlobalProperties().GetTcpIPv4Statistics()
        $cur = [double]$tcp.SegmentsResent
        if ($null -ne $script:State.PrevRetransSeg) {
            $delta = $cur - $script:State.PrevRetransSeg
            $script:State.PrevRetransSeg = $cur
            if ($delta -lt 0) { return 0 }
            return $delta
        }
        $script:State.PrevRetransSeg = $cur
    } catch {}
    return 0
}

# ---------- Tier 32: retransmit RATIO sampler ----------
# The honest health metric is ratio (% of segments retransmitted), NOT raw rate.
# Returns deltas + ratios for the current sample window AND the cumulative since boot.
# Stores the result in $script:State.LastRetransSample so the investigator dialog can read it.
function Sample-RetransRatio {
    $result = @{
        DeltaSent   = 0; DeltaResent = 0; Ratio    = 0
        CumSent     = 0; CumResent   = 0; CumRatio = 0
        When        = Get-Date
    }
    try {
        $tcp = [System.Net.NetworkInformation.IPGlobalProperties]::GetIPGlobalProperties().GetTcpIPv4Statistics()
        $curSent   = [double]$tcp.SegmentsSent
        $curResent = [double]$tcp.SegmentsResent
        $result.CumSent   = $curSent
        $result.CumResent = $curResent
        $result.CumRatio  = if ($curSent -gt 0) { ($curResent / $curSent) * 100 } else { 0 }
        if ($null -ne $script:State.PrevSegmentsSent -and $null -ne $script:State.PrevSegmentsResent) {
            $dSent   = $curSent   - $script:State.PrevSegmentsSent
            $dResent = $curResent - $script:State.PrevSegmentsResent
            if ($dSent -lt 0)   { $dSent = 0 }
            if ($dResent -lt 0) { $dResent = 0 }
            $result.DeltaSent   = $dSent
            $result.DeltaResent = $dResent
            $result.Ratio = if ($dSent -gt 0) { ($dResent / $dSent) * 100 } else { 0 }
        }
        $script:State.PrevSegmentsSent   = $curSent
        $script:State.PrevSegmentsResent = $curResent
    } catch {}
    $script:State.LastRetransSample = $result
    return $result
}

# Verdict helper - returns @{ Label; Hex } based on a ratio value.
function Get-RetransVerdict {
    param([double]$RatioPct)
    if ($RatioPct -lt 0.1)  { return @{ Label='EXCELLENT';   Hex='#3fb950'; Description='Quiet wired LAN level. Nothing to investigate.' } }
    if ($RatioPct -lt 0.5)  { return @{ Label='NORMAL';      Hex='#3fb950'; Description='Within typical Internet baseline. Some loss is expected over public networks.' } }
    if ($RatioPct -lt 2.0)  { return @{ Label='ELEVATED';    Hex='#d29922'; Description='Connections may feel sluggish. Common during peak hours or on Wi-Fi with mild interference.' } }
    if ($RatioPct -lt 5.0)  { return @{ Label='HIGH';        Hex='#d29922'; Description='Actively degrading user experience. Streaming will buffer; uploads will stall.' } }
    return                  @{ Label='CRITICAL';    Hex='#f85149'; Description='Link is unstable - flap likely imminent. Investigate immediately.' }
}

# ---------- Tier 22: per-connection retransmit attribution ----------
# Windows does not expose per-connection retransmit counts via PowerShell without P/Invoke
# (GetPerTcpConnectionEStats requires SetPerTcpConnectionEStats first to enable, plus elevation).
# Instead this builds a "top suspects" view by scoring active TCP connections against several
# signals known to correlate with the kernel's TCP-retransmit counter:
#   1) STUCK STATES - CloseWait/FinWait1/FinWait2/LastAck connections are literally retransmitting
#      until they finally die. CloseWait especially indicates the remote stopped responding mid-flow.
#   2) FLAP CORRELATION - if the connection's RemoteAddress matches a host that's currently
#      failing ICMP/TCP probes in our latency tracker, retransmits to that host are very likely.
#   3) PROCESS HOTNESS  - established connections owned by processes with high I/O byte rates
#      are statistically more likely to be the ones experiencing retransmits.
# Output: PSCustomObjects with Pid/ProcessName/Endpoint/State/Reason/Severity for the offender panel.
function Sample-RetransOffenders {
    $rows = New-Object System.Collections.Generic.List[object]
    try {
        $conns = Get-NetTCPConnection -ErrorAction SilentlyContinue
        if (-not $conns) { return @() }

        # Build flap-host set from custom-target failure tracking + latency probe state
        $flapHosts = @{}
        try {
            foreach ($t in $script:State.CustomTargets) {
                if (-not $t -or -not $t.Spec) { continue }
                $hostPart = ($t.Spec -split ':')[0]
                if ($hostPart -match '^\d+\.\d+\.\d+\.\d+$') {
                    if ($t.PSObject.Properties['LastFailed'] -and $t.LastFailed) { $flapHosts[$hostPart] = $t.Spec }
                }
            }
        } catch {}
        # Add gateway + cloudflare to flap set if their recent loss is high
        try {
            if ($script:State.PingHistory -and $script:State.PingHistory.Count -ge 5) {
                $recent = @($script:State.PingHistory | Select-Object -Last 10)
                $gwTimeouts = @($recent | Where-Object { -not $_.GatewayMs -or $_.GatewayMs -le 0 }).Count
                $cfTimeouts = @($recent | Where-Object { -not $_.CfMs -or $_.CfMs -le 0 }).Count
                if ($gwTimeouts -ge 3 -and $script:State.Gateway) { $flapHosts[$script:State.Gateway] = 'gateway-flapping' }
                if ($cfTimeouts -ge 3) { $flapHosts['1.1.1.1'] = 'cloudflare-flapping' }
            }
        } catch {}

        # Build PID -> process metadata map for the connections we'll score
        # (NB: `$pid` is a PS automatic variable, hence `$ownerPid`)
        $procMap = @{}
        try {
            $owningPids = $conns | Where-Object { $_.OwningProcess -gt 4 } | Select-Object -ExpandProperty OwningProcess -Unique
            foreach ($ownerPid in $owningPids) {
                try {
                    $p = Get-Process -Id $ownerPid -ErrorAction Stop
                    $procMap[[int]$ownerPid] = @{ Name = $p.ProcessName; Path = $p.Path }
                } catch {
                    $procMap[[int]$ownerPid] = @{ Name = '?'; Path = '' }
                }
            }
        } catch {}

        # Pre-pass: count remote-IP frequency per process. Streaming-style flows have many connections
        # to the same remote IP. That pattern is itself a signal worth surfacing in fallback mode.
        $remoteIpFreqByPid = @{}   # pid -> hashtable of remoteIP -> count
        foreach ($c in $conns) {
            if ([string]$c.State -ne 'Established') { continue }
            $r = [string]$c.RemoteAddress
            if (-not $r -or $r -in '0.0.0.0','::','127.0.0.1','::1') { continue }
            $p = [int]$c.OwningProcess
            if ($p -le 4) { continue }
            if (-not $remoteIpFreqByPid.ContainsKey($p)) { $remoteIpFreqByPid[$p] = @{} }
            $remoteIpFreqByPid[$p][$r] = ($remoteIpFreqByPid[$p][$r] + 1)
        }

        foreach ($c in $conns) {
            $remote = [string]$c.RemoteAddress
            if (-not $remote -or $remote -eq '0.0.0.0' -or $remote -eq '::' -or $remote -eq '127.0.0.1' -or $remote -eq '::1') { continue }

            $score = 0
            $reasons = New-Object System.Collections.Generic.List[string]
            $sevHex = '#58a6ff'
            $sevTag = 'INFO'
            $pidKey = [int]$c.OwningProcess

            switch ([string]$c.State) {
                'CloseWait'    { $score += 100; [void]$reasons.Add('CLOSE_WAIT (remote stopped ACKing)'); $sevHex = '#f85149'; $sevTag = 'STUCK' }
                'LastAck'      { $score += 95;  [void]$reasons.Add('LAST_ACK (awaiting final FIN)');     $sevHex = '#f85149'; $sevTag = 'STUCK' }
                'FinWait1'     { $score += 90;  [void]$reasons.Add('FIN_WAIT_1 (FIN not ACKed)');         $sevHex = '#f85149'; $sevTag = 'STUCK' }
                'FinWait2'     { $score += 75;  [void]$reasons.Add('FIN_WAIT_2 (half-closed)');           $sevHex = '#d29922'; $sevTag = 'STUCK' }
                'Closing'      { $score += 80;  [void]$reasons.Add('CLOSING (simultaneous close)');       $sevHex = '#d29922'; $sevTag = 'STUCK' }
                'TimeWait'     { $score += 25;  [void]$reasons.Add('TIME_WAIT (cooldown)');               $sevHex = '#3fb950'; $sevTag = 'COOL' }
                'Established'  { $score += 15;  [void]$reasons.Add('ESTABLISHED');                         $sevHex = '#58a6ff'; $sevTag = 'EST' }
                'SynSent'      { $score += 60;  [void]$reasons.Add('SYN_SENT (handshake stalled)');        $sevHex = '#d29922'; $sevTag = 'PEND' }
                'SynReceived'  { $score += 50;  [void]$reasons.Add('SYN_RCVD (handshake stalled)');        $sevHex = '#d29922'; $sevTag = 'PEND' }
                default        { $score += 10 }
            }

            if ($flapHosts.ContainsKey($remote)) {
                $score += 60
                [void]$reasons.Add('flap-correlated')
                $sevHex = '#f85149'
                $sevTag = 'FLAPPING'
            }

            # Tier 33: streaming-pattern signal - if this PID has multiple connections to the same remote IP,
            # boost the Established score so it can clear the 50 threshold. This catches Claude-style streaming
            # HTTPS, video calls, file syncs etc that are retransmitting due to path loss (not stuck states).
            if ([string]$c.State -eq 'Established' -and $pidKey -gt 4 -and $remoteIpFreqByPid.ContainsKey($pidKey)) {
                $sameRemoteCount = [int]$remoteIpFreqByPid[$pidKey][$remote]
                if ($sameRemoteCount -ge 3) {
                    $score += 35
                    [void]$reasons.Add(("streaming pattern ({0} conns to same remote)" -f $sameRemoteCount))
                    $sevHex = '#d29922'
                    $sevTag = 'STREAM'
                } elseif ($sameRemoteCount -ge 2) {
                    $score += 20
                    [void]$reasons.Add(("multi-conn to same remote ({0})" -f $sameRemoteCount))
                }
            }

            $procName = '?'
            if ($c.OwningProcess -and $procMap.ContainsKey([int]$c.OwningProcess)) {
                $procName = $procMap[[int]$c.OwningProcess].Name
            }

            # Tier 33: lower noise floor when retransmits are sustained AND no stuck offenders exist.
            # The default 50 floor was tuned for stuck states; with path-loss-on-Established we need to surface
            # anything reasonable (>= 30) so the panel isn't silent during real retransmit storms.
            $effectiveFloor = 50
            if ($script:State.RetransHighStreak -ge 2) { $effectiveFloor = 30 }
            if ($score -lt $effectiveFloor) { continue }

            $endpoint = ('{0}:{1}  ->  {2}:{3}' -f $procName, $c.LocalPort, $remote, $c.RemotePort)
            $geo = ''
            try { $geo = Get-IpLabel $remote } catch {}

            [void]$rows.Add([pscustomobject]@{
                Score          = $score
                SeverityTag    = $sevTag
                SeverityBrush  = (B $sevHex)
                ProcessLabel   = ('{0} (pid {1})' -f $procName, $c.OwningProcess)
                EndpointLabel  = ('{0}:{1} -> {2}:{3}{4}' -f $procName, $c.LocalPort, $remote, $c.RemotePort, $(if ($geo) { " [$geo]" } else { '' }))
                Reason         = ($reasons -join ' + ')
                State          = [string]$c.State
                Pid            = [int]$c.OwningProcess
                ProcessName    = $procName
                LocalPort      = [int]$c.LocalPort
                RemoteAddress  = $remote
                RemotePort     = [int]$c.RemotePort
            })
        }
    } catch {
        # Don't spam events on transient query failures
        return @()
    }
    # Top 6 by score
    return @($rows | Sort-Object Score -Descending | Select-Object -First 6)
}

# ---------- Tier 25: TRAFFIC tab samplers ----------
# Per-protocol packet rates via IPGlobalProperties (no admin required, ~1ms).
# Returns @{ TcpPps; UdpPps; IcmpPps; TotalPps } - packets/sec deltas since last sample.
# Note: IPGlobalProperties exposes SEGMENTS/DATAGRAMS/MESSAGES, not bytes. We surface these as
# packet rates and let the user interpret. (For exact bytes you'd need ETW/pktmon - heavier.)
function Sample-ProtocolRates {
    $now = Get-Date
    $result = @{ TcpPps = 0; UdpPps = 0; IcmpPps = 0; TotalPps = 0; ElapsedSec = 0; Error = '' }
    # Tier 95: previous version had a single try/catch wrapping BOTH the IPGlobalProperties calls
    # AND the state assignments at the end. If GetTcpIPv4Statistics threw (rare but happens with
    # some endpoint-protection products that hook the IP stack), the catch swallowed the error
    # AND the PrevTcpStats assignments were skipped - so PrevTcpStats stayed $null forever and
    # the TRAFFIC tab was stuck on "initializing baseline" indefinitely. Now we capture stats
    # in a local block, then assign state OUTSIDE that block so the second call always has the
    # baseline. Plus we return the error message so the caller can surface it.
    $tcpCum = $null; $udpCum = $null; $icmpCum = $null
    try {
        $gp = [System.Net.NetworkInformation.IPGlobalProperties]::GetIPGlobalProperties()
        $tcp  = $gp.GetTcpIPv4Statistics()
        $udp  = $gp.GetUdpIPv4Statistics()
        $icmp = $gp.GetIcmpV4Statistics()
        $tcpCum  = [double]($tcp.SegmentsSent  + $tcp.SegmentsReceived)
        $udpCum  = [double]($udp.DatagramsSent + $udp.DatagramsReceived)
        $icmpCum = [double]($icmp.MessagesSent + $icmp.MessagesReceived)
    } catch {
        $result.Error = "IPGlobalProperties failed: $($_.Exception.Message)"
        return $result
    }

    # Compute deltas if we have a previous baseline.
    if ($script:State.PrevTcpStats -ne $null -and $script:State.PrevTrafficSampleTime) {
        $dt = ($now - $script:State.PrevTrafficSampleTime).TotalSeconds
        if ($dt -gt 0.1) {
            $result.ElapsedSec = $dt
            $result.TcpPps  = [Math]::Max(0, ($tcpCum  - $script:State.PrevTcpStats)  / $dt)
            $result.UdpPps  = [Math]::Max(0, ($udpCum  - $script:State.PrevUdpStats)  / $dt)
            $result.IcmpPps = [Math]::Max(0, ($icmpCum - $script:State.PrevIcmpStats) / $dt)
            $result.TotalPps = $result.TcpPps + $result.UdpPps + $result.IcmpPps
        }
    }

    # ALWAYS save the baseline so the next call can compute deltas. Done outside the try/catch
    # so a state-assignment failure surfaces (it won't, but on principle).
    $script:State | Add-Member -NotePropertyName PrevTcpStats           -NotePropertyValue $tcpCum  -Force
    $script:State | Add-Member -NotePropertyName PrevUdpStats           -NotePropertyValue $udpCum  -Force
    $script:State | Add-Member -NotePropertyName PrevIcmpStats          -NotePropertyValue $icmpCum -Force
    $script:State | Add-Member -NotePropertyName PrevTrafficSampleTime  -NotePropertyValue $now     -Force
    return $result
}

# Top talkers - per-process I/O byte rates + active connection counts.
# Data source: Win32_PerfFormattedData_PerfProc_Process gives per-process IOReadBytesPerSec and
# IOWriteBytesPerSec already-formatted as rates (no manual delta calculation needed). One CIM
# query covers all processes, ~100-150ms.
# Caveat: those counters are TOTAL I/O (disk + named pipes + network), not network-only. The
# UI labels the column "I/O B/s" so the user knows it's not net-only. For exact per-process
# network bytes you'd need ETW Microsoft-Windows-TCPIP provider (heavier; deferred).
# Returns up to $TopN PSCustomObjects sorted by combined I/O rate descending, filtered to PIDs
# that EITHER have an active TCP/UDP endpoint OR are doing >50KB/s of I/O.
function Sample-TopTalkers {
    param([int]$TopN = 12)
    # Snapshot all TCP+UDP endpoints, group by OwningProcess
    $connsByPid = @{}
    try {
        Get-NetTCPConnection -ErrorAction SilentlyContinue | ForEach-Object {
            $pidKey = [int]$_.OwningProcess
            if ($pidKey -le 4) { return }
            if (-not $connsByPid.ContainsKey($pidKey)) {
                $connsByPid[$pidKey] = @{ Tcp = 0; Udp = 0; Remotes = @{} }
            }
            $connsByPid[$pidKey].Tcp++
            $r = [string]$_.RemoteAddress
            if ($r -and $r -notin '0.0.0.0','::','127.0.0.1','::1') {
                $connsByPid[$pidKey].Remotes[$r] = $true
            }
        }
        Get-NetUDPEndpoint -ErrorAction SilentlyContinue | ForEach-Object {
            $pidKey = [int]$_.OwningProcess
            if ($pidKey -le 4) { return }
            if (-not $connsByPid.ContainsKey($pidKey)) {
                $connsByPid[$pidKey] = @{ Tcp = 0; Udp = 0; Remotes = @{} }
            }
            $connsByPid[$pidKey].Udp++
        }
    } catch {}

    # Per-process I/O rates from PerfFormattedData (already-formatted rates - no delta needed)
    $perfByPid = @{}
    try {
        $perf = Get-CimInstance -ClassName Win32_PerfFormattedData_PerfProc_Process -ErrorAction SilentlyContinue |
            Where-Object { $_.Name -ne '_Total' -and $_.Name -ne 'Idle' -and $_.IDProcess -gt 4 }
        foreach ($p in $perf) {
            $pidKey = [int]$p.IDProcess
            $perfByPid[$pidKey] = @{
                Read  = [double]$p.IOReadBytesPersec
                Write = [double]$p.IOWriteBytesPersec
                Other = [double]$p.IOOtherBytesPersec
            }
        }
    } catch {}

    # Build process metadata map (path + name) for PIDs we care about
    $rows = New-Object System.Collections.Generic.List[object]
    $candidatePids = New-Object System.Collections.Generic.HashSet[int]
    foreach ($k in $connsByPid.Keys) { [void]$candidatePids.Add([int]$k) }
    foreach ($k in $perfByPid.Keys) {
        $rate = $perfByPid[$k].Read + $perfByPid[$k].Write
        if ($rate -ge 50000) { [void]$candidatePids.Add([int]$k) }
    }

    foreach ($pidKey in $candidatePids) {
        try {
            $proc = Get-Process -Id $pidKey -ErrorAction SilentlyContinue
            if (-not $proc) { continue }
            $rate = 0.0
            if ($perfByPid.ContainsKey($pidKey)) {
                $rate = $perfByPid[$pidKey].Read + $perfByPid[$pidKey].Write
            }
            $tcpN = if ($connsByPid.ContainsKey($pidKey)) { $connsByPid[$pidKey].Tcp } else { 0 }
            $udpN = if ($connsByPid.ContainsKey($pidKey)) { $connsByPid[$pidKey].Udp } else { 0 }
            $remoteCount = if ($connsByPid.ContainsKey($pidKey)) { @($connsByPid[$pidKey].Remotes.Keys).Count } else { 0 }
            $primaryRemote = $null
            if ($remoteCount -gt 0) { $primaryRemote = @($connsByPid[$pidKey].Remotes.Keys)[0] }

            [void]$rows.Add([pscustomobject]@{
                Pid           = $pidKey
                Name          = $proc.ProcessName
                Path          = $proc.Path
                TcpConns      = $tcpN
                UdpConns      = $udpN
                RemoteCount   = $remoteCount
                IoBytesPerSec = $rate
                IoLabel       = (Format-Bytes $rate) + '/s'
                ConnLabel     = ("{0} TCP / {1} UDP / {2} remote" -f $tcpN, $udpN, $remoteCount)
                PrimaryRemote = $primaryRemote
                PrimaryRemoteIp = $primaryRemote   # alias matches existing proc-block dispatcher contract
                # Severity - HOT: >5MB/s, MED: >500KB/s, LOW: anything below
                Risk          = if ($rate -gt 5000000) { 'HOT' } elseif ($rate -gt 500000) { 'MED' } else { 'LOW' }
                RiskColor     = if ($rate -gt 5000000) { (B '#f85149') } elseif ($rate -gt 500000) { (B '#d29922') } else { (B '#3fb950') }
            })
        } catch {}
    }

    return @($rows | Sort-Object IoBytesPerSec -Descending | Select-Object -First $TopN)
}

# Refresh the TRAFFIC tab labels + ObservableCollection. Heavy-tick only.
function Update-TrafficTab {
    if (-not $controls -or -not $controls.TrafficProtoText) { return }
    # Tier 93: respect the TRAFFIC Start/Stop toggle. When paused, leave existing tile values
    # in place but skip the heavy CIM sampling so the dispatcher stays responsive.
    if ($script:State.TrafficPaused) {
        if ($controls.TrafficStatus) {
            $controls.TrafficStatus.Text = '(paused - click Start to begin protocol-rate + top-talker sampling)'
        }
        return
    }
    # Tier 96: track per-tick call count + last-sample stats so the TrafficStatus line proves the
    # function is firing every 2s. If TrafficStatus is frozen on the same tick number, we know
    # the dispatcher tick isn't reaching us.
    if (-not $script:State.PSObject.Properties['TrafficSampleCount']) {
        $script:State | Add-Member -NotePropertyName TrafficSampleCount -NotePropertyValue 0 -Force
    }
    $script:State.TrafficSampleCount++
    # Sample protocol rates. Tier 94: the FIRST call after Start has PrevTcpStats=$null so deltas
    # can't be computed - rates come back as zero. We detect that explicitly BEFORE the call so
    # we can show an "initializing" state instead of "0 pkt/s".
    # Tier 95: also surface IPGlobalProperties errors (rare but happens with some endpoint-
    # protection products). $r.Error is populated by Sample-ProtocolRates if the underlying call
    # threw, in which case the tile shows the error rather than a misleading zero.
    $isFirstSample = ($null -eq $script:State.PrevTcpStats)
    $r = Sample-ProtocolRates
    $controls.TrafficTcpRate.Text  = ("{0:N0}" -f $r.TcpPps)
    $controls.TrafficUdpRate.Text  = ("{0:N0}" -f $r.UdpPps)
    $controls.TrafficIcmpRate.Text = ("{0:N0}" -f $r.IcmpPps)
    $controls.TrafficTotalRate.Text = ("{0:N0} pkt/s total" -f $r.TotalPps)

    if ($r.Error) {
        # Sampling failed - report the error so the user knows why everything reads zero.
        $controls.TrafficProtoText.Text = ("ERROR: {0}" -f $r.Error)
        if ($controls.TrafficStatus) {
            $controls.TrafficStatus.Text = ("Sampling error - check LIVE EVENTS for details. Retrying every 2s...")
        }
        try { Add-Event warn ("TRAFFIC sampling: {0}" -f $r.Error) -Source 'traffic' } catch {}
        return
    }

    # Update protocol bars (proportional widths) - re-using a single Grid with proportional ColumnDefinitions
    if ($isFirstSample) {
        $controls.TrafficProtoText.Text = '(initializing baseline... real protocol rates appear at the next heavy tick, ~2s)'
    } elseif ($r.TotalPps -gt 0) {
        $tcpW  = [Math]::Round(($r.TcpPps  / $r.TotalPps) * 100, 1)
        $udpW  = [Math]::Round(($r.UdpPps  / $r.TotalPps) * 100, 1)
        $icmpW = [Math]::Round(($r.IcmpPps / $r.TotalPps) * 100, 1)
        $controls.TrafficTcpBar.Width  = New-Object System.Windows.GridLength ([Math]::Max($tcpW,  0.001), 'Star')
        $controls.TrafficUdpBar.Width  = New-Object System.Windows.GridLength ([Math]::Max($udpW,  0.001), 'Star')
        $controls.TrafficIcmpBar.Width = New-Object System.Windows.GridLength ([Math]::Max($icmpW, 0.001), 'Star')
        $controls.TrafficProtoText.Text = ("TCP {0:N1}%   UDP {1:N1}%   ICMP {2:N1}%" -f $tcpW, $udpW, $icmpW)
    } else {
        $controls.TrafficProtoText.Text = '(network is idle - no TCP/UDP/ICMP packets in the last sample window)'
    }

    # Track histories for sparklines
    $script:State.TcpPpsHistory.Add([double]$r.TcpPps)
    $script:State.UdpPpsHistory.Add([double]$r.UdpPps)
    $script:State.IcmpPpsHistory.Add([double]$r.IcmpPps)
    while ($script:State.TcpPpsHistory.Count  -gt 60) { $script:State.TcpPpsHistory.RemoveAt(0) }
    while ($script:State.UdpPpsHistory.Count  -gt 60) { $script:State.UdpPpsHistory.RemoveAt(0) }
    while ($script:State.IcmpPpsHistory.Count -gt 60) { $script:State.IcmpPpsHistory.RemoveAt(0) }
    if ($controls.TrafficTcpSpark)  { Redraw-Sparkline -Canvas $controls.TrafficTcpSpark  -Data $script:State.TcpPpsHistory  -ColorHex '#58a6ff' -AutoMin 50 }
    if ($controls.TrafficUdpSpark)  { Redraw-Sparkline -Canvas $controls.TrafficUdpSpark  -Data $script:State.UdpPpsHistory  -ColorHex '#bf6dff' -AutoMin 50 }
    if ($controls.TrafficIcmpSpark) { Redraw-Sparkline -Canvas $controls.TrafficIcmpSpark -Data $script:State.IcmpPpsHistory -ColorHex '#7ee787' -AutoMin 5 }

    # Update direction tile from existing NIC counter history
    if ($controls.TrafficRxText -and $script:State.RxByteHistory -and $script:State.RxByteHistory.Count -gt 0) {
        $rxLast = [double]$script:State.RxByteHistory[$script:State.RxByteHistory.Count - 1]
        $txLast = if ($script:State.TxByteHistory -and $script:State.TxByteHistory.Count -gt 0) { [double]$script:State.TxByteHistory[$script:State.TxByteHistory.Count - 1] } else { 0 }
        $controls.TrafficRxText.Text = (Format-Bytes $rxLast) + '/s'
        $controls.TrafficTxText.Text = (Format-Bytes $txLast) + '/s'
        $tot = $rxLast + $txLast
        if ($tot -gt 0) {
            $controls.TrafficDirText.Text = ("RX {0:N0}%   TX {1:N0}%" -f (($rxLast/$tot)*100), (($txLast/$tot)*100))
        } else {
            $controls.TrafficDirText.Text = '(idle)'
        }
    }

    # Top talkers - rebuild ObservableCollection
    try {
        $talkers = Sample-TopTalkers -TopN 15
        $script:TrafficRows.Clear()
        foreach ($t in $talkers) { [void]$script:TrafficRows.Add($t) }
        # Tier 96: verbose status line shows sample count + timestamp + raw rates so the user can
        # see "the sampler is alive and producing X TCP/s, Y UDP/s, Z ICMP/s" - if rates are
        # genuinely 0 then the network is idle (not a bug); if the sample count never advances
        # then Update-TrafficTab isn't being called by the dispatcher tick.
        if ($controls.TrafficStatus) {
            $controls.TrafficStatus.Text = ("sample #{0} at {1}  |  {2} active procs  |  TCP {3:N0}/s  UDP {4:N0}/s  ICMP {5:N0}/s  |  total {6:N0} pkt/s" -f `
                $script:State.TrafficSampleCount, (Get-Date).ToString('HH:mm:ss'), $script:TrafficRows.Count, $r.TcpPps, $r.UdpPps, $r.IcmpPps, $r.TotalPps)
        }
    } catch {
        if ($controls.TrafficStatus) { $controls.TrafficStatus.Text = "Top-talker sampling error: $($_.Exception.Message)" }
    }
}

# ---------- Tier 28: FLOWS tab samplers ----------
# Live connection-level event stream. Snapshots TCP+UDP endpoints every heavy tick (~2s) and
# diffs against the previous snapshot to emit NEW / CLOSED / STATE-CHANGE events. This is a
# socket-level stream (NOT a packet stream) - we miss connections that open and close inside
# a single 2s window, but for "what just connected and what just closed" it's exactly right
# and needs no admin / no npcap / no ETW provider enablement.
function Add-FlowEvent {
    param(
        [string]$Type,        # NEW / CLOSED / STATE
        $Conn,                # @{ Proto; State; Pid; Local; Remote; CreationTime }
        [string]$OldState = ''
    )
    if (-not $script:FlowEvents) { return }
    if ($script:State.FlowPaused) { return }

    # Tier 68: cache pid -> process name. On a busy machine, Sample-Flows can produce 30+ events per
    # heavy tick, each previously calling Get-Process (5-10 ms each) = 150-300 ms of synchronous
    # work per tick. Cache lives for 60 s to balance freshness vs perf.
    if (-not $script:_ProcNameCache) { $script:_ProcNameCache = @{} }
    if (-not $script:_ProcNameCacheLastClear) { $script:_ProcNameCacheLastClear = Get-Date }
    if (((Get-Date) - $script:_ProcNameCacheLastClear).TotalSeconds -gt 60) {
        $script:_ProcNameCache.Clear()
        $script:_ProcNameCacheLastClear = Get-Date
    }
    $procName = '?'
    if ($Conn.Pid -and $Conn.Pid -gt 0) {
        $pidKey = [int]$Conn.Pid
        if ($script:_ProcNameCache.ContainsKey($pidKey)) {
            $procName = $script:_ProcNameCache[$pidKey]
        } else {
            try {
                $p = Get-Process -Id $pidKey -ErrorAction SilentlyContinue
                if ($p) { $procName = $p.ProcessName }
            } catch {}
            $script:_ProcNameCache[$pidKey] = $procName
        }
    }

    # Type colors
    $typeHex = switch ($Type) {
        'NEW'    { '#3fb950' }
        'CLOSED' { '#d29922' }
        'STATE'  { '#58a6ff' }
        'INIT'   { '#bf6dff' }   # synthetic baseline marker, fired once on first sample
        'NOW'    { '#79c0ff' }   # Tier 83: connection that EXISTS at sampler-start (vs NEW = appeared since last tick)
        'HB'     { '#6a7380' }   # Tier 84: heartbeat row - continuous "sampler is alive" pulse on quiet ticks
        'TRACE'  { '#6a7380' }   # Tier 86: per-tick proof-of-life row, always fires after Sample-Flows diff
        default  { '#6a7380' }
    }

    # Endpoint label - omit ":0" on listening UDP for readability
    $endpointLabel = if ($Conn.Remote -and $Conn.Remote -ne '0.0.0.0:0' -and $Conn.Remote -ne ':::0') {
        ('{0}  ->  {1}' -f $Conn.Local, $Conn.Remote)
    } else {
        ('{0}  (listen)' -f $Conn.Local)
    }
    $stateLabel = if ($Type -eq 'STATE') { ('{0} -> {1}' -f $OldState, $Conn.State) } else { [string]$Conn.State }

    $row = [pscustomobject]@{
        Time          = (Get-Date).ToString('HH:mm:ss')
        Type          = $Type
        TypeColor     = (B $typeHex)
        Proto         = [string]$Conn.Proto
        ProtoColor    = if ($Conn.Proto -eq 'TCP') { (B '#79c0ff') } else { (B '#bf6dff') }
        Process       = ('{0} ({1})' -f $procName, $Conn.Pid)
        Pid           = [int]$Conn.Pid
        Name          = $procName
        Endpoint      = $endpointLabel
        Local         = [string]$Conn.Local
        Remote        = [string]$Conn.Remote
        RemoteAddress = if ($Conn.Remote) { ($Conn.Remote -split ':')[0] } else { '' }
        State         = $stateLabel
    }

    # Apply filter (case-insensitive substring match across all visible text)
    if ($script:State.FlowFilter) {
        $f = $script:State.FlowFilter.ToLower()
        $combined = ('{0} {1} {2} {3} {4} {5}' -f $row.Type, $row.Proto, $row.Process, $row.Endpoint, $row.State, $row.Time).ToLower()
        if (-not $combined.Contains($f)) { return }
    }

    # Append to ObservableCollection - with ring-buffer trim from the front
    $script:FlowEvents.Add($row)
    while ($script:FlowEvents.Count -gt $script:State.FlowMaxEvents) {
        $script:FlowEvents.RemoveAt(0)
    }

    # Tier 35: also surface notable flow events into LIVE EVENTS (tagged Source='flows').
    # Filter heavily to avoid flooding - on a busy machine NEW events fire 5-20 times per second.
    # Rules: emit ALL INIT, ALL STATE changes (rare and important), ALL UDP listen-port openings
    # (server starting), but only TCP NEWs to remote ports we don't see often. Skip TCP CLOSEDs
    # entirely from the live log (use FLOWS tab to see those).
    $shouldSurface = $false
    $headline = ''
    $detail = ''
    switch ($Type) {
        'INIT' {
            $shouldSurface = $true
            $headline = ('Flow sampler online: {0}' -f $Conn.State)
            $detail = 'Subsequent NEW/CLOSED/STATE events appear in the FLOWS tab; notable ones (state changes, listen-port openings) also surface here.'
        }
        'STATE' {
            $shouldSurface = $true
            $headline = ('TCP state change: {0} {1}' -f $procName, $stateLabel)
            $detail = ('connection: {0}  pid {1}' -f $endpointLabel, $Conn.Pid)
        }
        'NEW' {
            if ($Conn.Proto -eq 'UDP') {
                # Listen port opening - server starting up
                $shouldSurface = $true
                $headline = ('UDP listener opened: {0} on {1}' -f $procName, $Conn.Local)
                $detail = ('pid {0}' -f $Conn.Pid)
            }
            # Skip TCP NEW - too noisy. FLOWS tab carries them.
        }
        # Skip CLOSED - also noisy (every keepalive timeout, every browser tab close)
        # Tier 83: skip NOW entirely - dumping 250 entries to LIVE EVENTS would flood it.
        # The full list lives in FlowList only.
        # Tier 84: skip HB entirely - heartbeat fires every 2s on quiet ticks; flooding LIVE
        # EVENTS with these would defeat the purpose of the LIVE EVENTS feed (which is for
        # noteworthy network signals).
    }
    if ($shouldSurface) {
        try { Add-Event info $headline -Source 'flows' -Detail $detail } catch {}
    }
}

# Sample current TCP+UDP endpoints, diff against previous snapshot, emit flow events for changes.
function Sample-Flows {
    if ($script:State.FlowPaused) {
        $script:State.LastFlowSampleStatus = ('paused at {0}' -f (Get-Date -Format 'HH:mm:ss'))
        return
    }
    $current = @{}
    $tcpCount = 0
    $udpCount = 0
    $sampleErr = ''
    try {
        Get-NetTCPConnection -ErrorAction SilentlyContinue | ForEach-Object {
            $key = ('TCP|{0}:{1}|{2}:{3}' -f $_.LocalAddress, $_.LocalPort, $_.RemoteAddress, $_.RemotePort)
            $current[$key] = @{
                Proto        = 'TCP'
                State        = [string]$_.State
                CreationTime = $_.CreationTime
                Pid          = [int]$_.OwningProcess
                Local        = ('{0}:{1}' -f $_.LocalAddress, $_.LocalPort)
                Remote       = ('{0}:{1}' -f $_.RemoteAddress, $_.RemotePort)
            }
            $tcpCount++
        }
    } catch { $sampleErr += "TCP enum: $($_.Exception.Message); " }
    try {
        Get-NetUDPEndpoint -ErrorAction SilentlyContinue | ForEach-Object {
            $key = ('UDP|{0}:{1}|listen' -f $_.LocalAddress, $_.LocalPort)
            $current[$key] = @{
                Proto        = 'UDP'
                State        = 'Listen'
                CreationTime = $_.CreationTime
                Pid          = [int]$_.OwningProcess
                Local        = ('{0}:{1}' -f $_.LocalAddress, $_.LocalPort)
                Remote       = ''
            }
            $udpCount++
        }
    } catch { $sampleErr += "UDP enum: $($_.Exception.Message); " }

    # Diagnostic - record what we saw so the FLOWS tab status line can show "we're alive"
    $newCount = 0; $closedCount = 0; $stateCount = 0

    # Tier 83: on the FIRST sample after Start (or after an unpause that cleared PrevFlowSnapshot),
    # don't just stash a silent baseline + emit one INIT marker. Instead, dump a NOW row for
    # EVERY current TCP+UDP endpoint so the user immediately sees the full state of their machine
    # ("listen to everything"). On subsequent ticks Sample-Flows reverts to diff-only mode (NEW /
    # CLOSED / STATE rows). Capped at $script:State.FlowMaxEvents (default 500) inside Add-FlowEvent
    # so a flood doesn't swamp the ring buffer; the OLDEST rows of the dump get trimmed first if
    # over cap, leaving the most recent connections + future diff stream visible.
    if (-not $script:State.PrevFlowSnapshot) {
        $script:State.PrevFlowSnapshot = $current
        # Header marker first so it's visible at the top of the dump
        Add-FlowEvent -Type 'INIT' -Conn @{
            Proto = 'SYS'
            State = ('baseline captured: {0} TCP + {1} UDP - listing each below as NOW rows' -f $tcpCount, $udpCount)
            Pid   = $PID
            Local = 'flows-sampler:0'
            Remote = ''
        }
        # Dump every current connection as a NOW row (new event type). NOW differs from NEW: NEW
        # means "appeared between two ticks" (real change), NOW means "present at sampler-start
        # snapshot". Sort by proto + local addr so the dump is deterministic and groups by listener.
        $sortedKeys = @($current.Keys | Sort-Object {
            $c = $current[$_]
            ('{0}|{1}' -f $c.Proto, $c.Local)
        })
        $dumped = 0
        foreach ($k in $sortedKeys) {
            Add-FlowEvent -Type 'NOW' -Conn $current[$k]
            $dumped++
            # Hard ceiling within the dump so we don't add 1000+ rows in one go and starve the
            # heavy-tick budget. 250 is plenty to convey "everything that's open right now"; the
            # ring buffer trim handles overflow naturally.
            if ($dumped -ge 250) { break }
        }
        $script:State.LastFlowSampleStatus = ('Baseline at {0}: {1} TCP + {2} UDP listed as NOW rows ({3} dumped)' -f (Get-Date -Format 'HH:mm:ss'), $tcpCount, $udpCount, $dumped)
        return
    }

    # NEW + STATE-CHANGE
    foreach ($k in $current.Keys) {
        if (-not $script:State.PrevFlowSnapshot.ContainsKey($k)) {
            Add-FlowEvent -Type 'NEW' -Conn $current[$k]
            $newCount++
        } elseif ($current[$k].State -ne $script:State.PrevFlowSnapshot[$k].State) {
            Add-FlowEvent -Type 'STATE' -Conn $current[$k] -OldState $script:State.PrevFlowSnapshot[$k].State
            $stateCount++
        }
    }
    # CLOSED
    foreach ($k in $script:State.PrevFlowSnapshot.Keys) {
        if (-not $current.ContainsKey($k)) {
            Add-FlowEvent -Type 'CLOSED' -Conn $script:State.PrevFlowSnapshot[$k]
            $closedCount++
        }
    }
    $prevSize = if ($script:State.PrevFlowSnapshot) { $script:State.PrevFlowSnapshot.Count } else { 0 }
    $script:State.PrevFlowSnapshot = $current
    $script:State.LastFlowSampleStatus = ('{0}: {1} TCP + {2} UDP active. Diff: +{3} new, -{4} closed, {5} state-change. Err: {6}' -f (Get-Date -Format 'HH:mm:ss'), $tcpCount, $udpCount, $newCount, $closedCount, $stateCount, $(if ($sampleErr) { $sampleErr } else { 'none' }))

    # Tier 86: TRACE row fires on EVERY Sample-Flows call (not just idle ticks). This guarantees
    # the FlowList shows continuous proof-of-life that the sampler is iterating and what its diff
    # is producing. If the user sees TRACE rows ticking but no NEW/CLOSED/STATE alongside, then
    # the diff genuinely found nothing changed. If TRACE rows STOP appearing, the dispatcher tick
    # isn't firing. Replaces the previous Tier 84 HB-on-idle-only behavior because users couldn't
    # distinguish "no activity ever happens" from "sampler is dead". TRACE is gray so it doesn't
    # dominate visually; real diff rows (green/cyan/amber) still pop.
    Add-FlowEvent -Type 'TRACE' -Conn @{
        Proto = 'SYS'
        State = ('tick #{0} | {1} TCP + {2} UDP active (was {3}) | +{4} new, -{5} closed, {6} state{7}' -f `
                 ($script:State.TickCount), $tcpCount, $udpCount, $prevSize, $newCount, $closedCount, $stateCount, `
                 (if ($sampleErr) { ' | ERR: ' + $sampleErr } else { '' }))
        Pid   = $PID
        Local = ('flows-sampler:tick-{0}' -f $script:State.TickCount)
        Remote = ''
    }
}

# Per-core CPU via cached PerformanceCounter instances (~1ms each, primed at startup).
$script:CpuCountersInited = $false
function Init-CpuCounters {
    if ($script:CpuCountersInited) { return }
    $script:State.CpuCounters = New-Object System.Collections.ArrayList
    try {
        $n = [Environment]::ProcessorCount
        for ($i = 0; $i -lt $n; $i++) {
            $pc = New-Object System.Diagnostics.PerformanceCounter 'Processor','% Processor Time',"$i",$true
            [void]$pc.NextValue()   # prime - first call always returns 0
            [void]$script:State.CpuCounters.Add($pc)
        }
        $script:CpuCountersInited = $true
    } catch {}
}

function Sample-CpuMax {
    if (-not $script:CpuCountersInited) { Init-CpuCounters }
    if (-not $script:State.CpuCounters -or $script:State.CpuCounters.Count -eq 0) {
        return @{ Max = 0; CoreId = -1 }
    }
    $max = 0.0; $coreId = -1
    for ($i = 0; $i -lt $script:State.CpuCounters.Count; $i++) {
        try {
            $v = [double]$script:State.CpuCounters[$i].NextValue()
            if ($v -gt $max) { $max = $v; $coreId = $i }
        } catch {}
    }
    return @{ Max = $max; CoreId = $coreId }
}

# Tier 38: Sample physical memory usage as a percentage. Uses Win32_OperatingSystem because it's
# already cached by CIM and gives us total + free in KB - one read, ~30-60ms. Returns @{Pct=<0..100>;
# UsedMB=<int>; TotalMB=<int>}. Falls back to {0,0,0} on any failure - the tile just shows 0%.
function Sample-MemoryUsage {
    try {
        $os = Get-CimInstance Win32_OperatingSystem -ErrorAction Stop
        $totalKB = [double]$os.TotalVisibleMemorySize
        $freeKB  = [double]$os.FreePhysicalMemory
        if ($totalKB -le 0) { return @{ Pct = 0.0; UsedMB = 0; TotalMB = 0 } }
        $usedKB = $totalKB - $freeKB
        $pct = ($usedKB / $totalKB) * 100.0
        if ($pct -lt 0)   { $pct = 0.0 }
        if ($pct -gt 100) { $pct = 100.0 }
        return @{
            Pct     = [Math]::Round($pct, 1)
            UsedMB  = [int]([Math]::Round($usedKB / 1024.0, 0))
            TotalMB = [int]([Math]::Round($totalKB / 1024.0, 0))
        }
    } catch {
        return @{ Pct = 0.0; UsedMB = 0; TotalMB = 0 }
    }
}

# Tier 61: TOP RETRANS SUSPECTS panel relocated. Was in the chart-column grid (rows 4 + 5);
# now lives in the right-column wrapper above LIVE EVENTS. Same RetransRow / RetransSplitterRow
# names so this helper still works - they just point at the new wrapper Grid's rows. The
# PingCardRow MinHeight bump is no longer needed since retrans isn't in the ping card anymore.
# When visible, retrans row gets 1.5* and the splitter row gets 5px; when hidden, both go to 0.
function Set-RetransPanelVisible {
    param([bool]$Visible)
    if (-not $controls -or -not $controls.RetransOffendersBorder) { return }
    if ($Visible) {
        $controls.RetransOffendersBorder.Visibility = 'Visible'
        if ($controls.RetransRow) {
            # Tier 76: 1* retrans vs 6* live events = 1/7 retrans, 6/7 live events.
            # Was 1.5* (gave retrans ~60% of right column - too dominant).
            $controls.RetransRow.Height    = New-Object System.Windows.GridLength(1, [System.Windows.GridUnitType]::Star)
            # MinHeight=130 floor: header(24) + list MinHeight(40) + minimal wrapped hint(~50) + padding(12)
            # + border(2) + small slack. Lowered from 170 so the 1:6 ratio is actually achievable on
            # a typical right-column height (~600px gives retrans = ~86px target, MinHeight 130 still
            # acts as a usability floor). Drag splitter freely above this.
            $controls.RetransRow.MinHeight = 130
        }
        if ($controls.RetransSplitterRow) {
            $controls.RetransSplitterRow.Height = New-Object System.Windows.GridLength(5, [System.Windows.GridUnitType]::Pixel)
        }
    } else {
        $controls.RetransOffendersBorder.Visibility = 'Collapsed'
        if ($controls.RetransRow) {
            $controls.RetransRow.Height    = New-Object System.Windows.GridLength(0)
            $controls.RetransRow.MinHeight = 0
        }
        if ($controls.RetransSplitterRow) {
            $controls.RetransSplitterRow.Height = New-Object System.Windows.GridLength(0)
        }
    }
}

# ---------- Tier 6: LAN fan-out probe ----------
function Get-LanProbeTargets {
    # pick up to 3 reachable, non-multicast, non-gateway, non-broadcast hosts
    $excludeGw = $script:State.Gateway
    $hosts = Get-NetNeighbor -AddressFamily IPv4 -ErrorAction SilentlyContinue |
        Where-Object {
            $_.State -in 'Reachable','Stale','Permanent' -and
            $_.LinkLayerAddress -and
            $_.LinkLayerAddress -ne '00-00-00-00-00-00' -and
            $_.LinkLayerAddress -ne 'FF-FF-FF-FF-FF-FF' -and
            $_.LinkLayerAddress -notmatch '^(01-00-5E|33-33)' -and
            $_.IPAddress -ne $excludeGw -and
            $_.IPAddress -notmatch '^(224\.|225\.|226\.|227\.|228\.|229\.|23\d\.|255\.|169\.254\.)' -and
            ($_.IPAddress -match '^(10\.|192\.168\.|172\.(1[6-9]|2\d|3[01])\.)')
        }
    return @($hosts | Sort-Object IPAddress -Unique | Select-Object -First 3 -ExpandProperty IPAddress)
}

function Probe-LanFanout {
    if ($script:State.LanProbes.Count -eq 0) {
        return [pscustomobject]@{ Total = 0; Reachable = 0; Hosts = @() }
    }
    $reachable = 0
    $hosts = New-Object System.Collections.ArrayList
    foreach ($ip in $script:State.LanProbes) {
        $ok = $false
        try {
            $r = $script:State.Ping.Send($ip, 350)
            if ($r.Status -eq 'Success') { $ok = $true }
        } catch {}
        if ($ok) { $reachable++ }
        [void]$hosts.Add([pscustomobject]@{ Ip = $ip; Reachable = $ok })
    }
    return [pscustomobject]@{
        Total     = $script:State.LanProbes.Count
        Reachable = $reachable
        Hosts     = $hosts
    }
}

# ---------- Tier 10: beaconing detector ----------
# Tracks per-tuple (pid, remoteIP, remotePort) connection timestamps.
# A C2 beacon shows up as periodic outbound connections with low inter-arrival jitter.
$script:BeaconSamples = @{}        # key="pid|ip|port" -> List[datetime]
$script:BeaconAlerted = @{}        # key -> $true once we've alerted

function Sample-Beacons {
    # called from heavy Tick. Captures current establishing/established TCP connections.
    try {
        $now = Get-Date
        $tcps = Get-NetTCPConnection -State Established,SynSent -ErrorAction SilentlyContinue |
                Where-Object { $_.RemoteAddress -and
                    $_.RemoteAddress -notmatch '^(127\.|::1|0\.0\.0\.0|192\.168\.|10\.|172\.(1[6-9]|2\d|3[01])\.|169\.254\.|fe80:)' }
        foreach ($c in $tcps) {
            $key = "{0}|{1}|{2}" -f $c.OwningProcess, $c.RemoteAddress, $c.RemotePort
            if (-not $script:BeaconSamples.ContainsKey($key)) {
                $script:BeaconSamples[$key] = New-Object System.Collections.Generic.List[datetime]
            }
            # only record the first sighting in this tick (avoids dup-counting same connection)
            $list = $script:BeaconSamples[$key]
            if ($list.Count -eq 0 -or ($now - $list[$list.Count - 1]).TotalSeconds -gt 1.5) {
                [void]$list.Add($now)
            }
        }
        # housekeep: drop tuples older than 30 min, trim long lists
        $cutoff = $now.AddMinutes(-30)
        $stale = New-Object System.Collections.Generic.List[string]
        foreach ($k in $script:BeaconSamples.Keys) {
            $l = $script:BeaconSamples[$k]
            while ($l.Count -gt 0 -and $l[0] -lt $cutoff) { $l.RemoveAt(0) }
            if ($l.Count -eq 0) { [void]$stale.Add($k) }
            elseif ($l.Count -gt 60) { $l.RemoveRange(0, $l.Count - 60) }
        }
        foreach ($k in $stale) {
            [void]$script:BeaconSamples.Remove($k)
            [void]$script:BeaconAlerted.Remove($k)
        }
    } catch {}
}

# ---------- Replay mode: snapshot save / load ----------
# At the end of every scan we serialize the full findings + causes + counter histories to
# Reports\Snapshots\snapshot-{stamp}.json. The Replay menu lets the user pick any snapshot and
# re-load it into the UI - findings are tagged with [REPLAY] and the Retransmit Investigator
# can be re-opened against the snapshotted retrans series. Useful for testing fix recommendations
# against historical scans without having to recreate the conditions that produced them.
$script:SnapshotsDir = Join-Path $PSScriptRoot 'Reports\Snapshots'
if (-not (Test-Path $script:SnapshotsDir)) { New-Item -ItemType Directory -Path $script:SnapshotsDir -Force | Out-Null }
$script:ReplayActive = $false   # latched while a replay is loaded; UI shows a banner

function Save-ScanSnapshot {
    # Called from Update-Findings' finally block. Best-effort - never throws back to caller.
    try {
        $stamp = (Get-Date).ToString('yyyyMMdd-HHmmss')
        $path  = Join-Path $script:SnapshotsDir ("snapshot-$stamp.json")
        $a = $script:State.Adapter
        $payload = [ordered]@{
            schemaVersion = 1
            timestamp     = (Get-Date).ToString('o')
            host          = $env:COMPUTERNAME
            adapter       = if ($a) { @{ name=[string]$a.Name; status=[string]$a.Status; linkSpeed=[string]$a.LinkSpeed; description=[string]$a.InterfaceDescription } } else { $null }
            findings      = @($script:AllFindings | Select-Object Level, Category, Message, Fix, Detail, MitreId, MitreName)
            causes        = @($script:Causes | Select-Object Cause, ConfidenceLabel, Confidence, Evidence, Recommendation)
            retransHistory = @($script:State.RetransHistory)
            rxErrHistory   = @($script:State.RxErrHistory)
            cpuMaxHistory  = @($script:State.CpuMaxHistory)
            memoryHistory  = @($script:State.MemoryHistory)
            flapCount      = $script:State.FlapCount
            sessionStart   = $script:State.SessionStart.ToString('o')
        }
        $payload | ConvertTo-Json -Depth 6 | Set-Content -LiteralPath $path -Encoding UTF8
        # Keep only last 30 snapshots so the dir doesn't grow forever.
        $old = @(Get-ChildItem $script:SnapshotsDir -Filter 'snapshot-*.json' | Sort-Object LastWriteTime -Descending | Select-Object -Skip 30)
        foreach ($f in $old) { try { Remove-Item $f.FullName -Force -ErrorAction SilentlyContinue } catch {} }
        return $path
    } catch {
        try { Add-Event warn ("Snapshot save failed: $($_.Exception.Message)") } catch {}
        return $null
    }
}

function Load-ScanSnapshot {
    # Loads a snapshot JSON into the live UI. Findings get prefixed with [REPLAY] and the page
    # title gets a banner so the user can't confuse replayed data with a real current scan.
    param([Parameter(Mandatory)] [string]$Path)
    if (-not (Test-Path $Path)) { Add-Event warn "Replay: snapshot not found at $Path"; return $false }
    try {
        $snap = Get-Content -LiteralPath $Path -Raw | ConvertFrom-Json
    } catch { Add-Event warn ("Replay: snapshot parse failed: $($_.Exception.Message)"); return $false }
    try {
        $script:AllFindings.Clear()
        foreach ($f in @($snap.findings)) {
            $color = switch ([string]$f.Level) { 'FAIL' {'#f85149'} 'WARN' {'#d29922'} 'INFO' {'#58a6ff'} default {'#3fb950'} }
            $ghost = [pscustomobject]@{
                Level           = [string]$f.Level
                Category        = "[REPLAY] $([string]$f.Category)"
                Message         = [string]$f.Message
                Fix             = [string]$f.Fix
                Detail          = [string]$f.Detail
                Tip             = "Replayed finding from snapshot $(Split-Path $Path -Leaf)"
                LevelColor      = (B $color)
                FixVisibility   = if ($f.Fix) { 'Visible' } else { 'Collapsed' }
                MitreId         = [string]$f.MitreId
                MitreName       = [string]$f.MitreName
                MitreVisibility = if ($f.MitreId) { 'Visible' } else { 'Collapsed' }
                IsNew           = $false
                NewVisibility   = 'Collapsed'
            }
            [void]$script:AllFindings.Add($ghost)
        }
        # Restore causes for the TOP CAUSES card.
        if ($snap.causes -and $script:Causes) {
            $script:Causes.Clear()
            foreach ($c in @($snap.causes)) {
                [void]$script:Causes.Add([pscustomobject]@{
                    Cause           = "[REPLAY] $([string]$c.Cause)"
                    ConfidenceLabel = [string]$c.ConfidenceLabel
                    Confidence      = [int]$c.Confidence
                    Evidence        = [string]$c.Evidence
                    Recommendation  = [string]$c.Recommendation
                })
            }
        }
        $script:ReplayActive = $true
        Apply-FindingsFilter
        $tsLabel = if ($snap.timestamp) { ([datetime]$snap.timestamp).ToString('yyyy-MM-dd HH:mm:ss') } else { '?' }
        Add-Event info ("REPLAY loaded: {0} findings from snapshot taken at {1}." -f @($snap.findings).Count, $tsLabel)
        if ($controls.ScanStatus) {
            $controls.ScanStatus.Text = ("REPLAY: {0}  (re-scan to clear)" -f (Split-Path $Path -Leaf))
            $controls.ScanStatus.Foreground = (B '#bf6dff')
        }
        return $true
    } catch {
        Add-Event warn ("Replay load failed: $($_.Exception.Message)")
        return $false
    }
}

function Show-ReplaySnapshotDialog {
    # Modeless file picker rooted at Reports\Snapshots. Returns the chosen path or empty string.
    Add-Type -AssemblyName System.Windows.Forms
    $dlg = New-Object System.Windows.Forms.OpenFileDialog
    $dlg.InitialDirectory = $script:SnapshotsDir
    $dlg.Filter           = 'NetJump snapshot (*.json)|snapshot-*.json|All files (*.*)|*.*'
    $dlg.Title            = 'Replay snapshot'
    if ($dlg.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) {
        Load-ScanSnapshot -Path $dlg.FileName | Out-Null
    }
}

# ---------- DNS sinkhole (hosts-file blocklist subscription) ----------
# Subscribes to a public hosts-format blocklist (default: StevenBlack/hosts unified) and maintains
# a NetJump-managed section in the system hosts file. Resolves blocked domains to 0.0.0.0 so the
# browser/process can't reach them. Reversible (Clear-DnsSinkhole strips the managed section);
# every modification is preceded by a timestamped backup under Reports\Sinkhole\.
$script:HostsSinkholePath  = Join-Path $env:SystemRoot 'System32\drivers\etc\hosts'
$script:SinkholeDir        = Join-Path $PSScriptRoot 'Reports\Sinkhole'
$script:SinkholeDefaultUrl = 'https://raw.githubusercontent.com/StevenBlack/hosts/master/hosts'
$script:SinkholeBeginMark  = '# === NetJump DNS sinkhole BEGIN (auto-managed; do not edit) ==='
$script:SinkholeEndMark    = '# === NetJump DNS sinkhole END ==='
if (-not (Test-Path $script:SinkholeDir)) { New-Item -ItemType Directory -Path $script:SinkholeDir -Force | Out-Null }

function Get-DnsSinkholeStatus {
    # Returns @{Active=bool;Entries=int;UpdatedAt=string;Url=string;Backup=string} based on current hosts file.
    $result = @{ Active=$false; Entries=0; UpdatedAt=$null; Url=$null; Backup=$null }
    if (-not (Test-Path $script:HostsSinkholePath)) { return $result }
    try {
        $content = Get-Content -LiteralPath $script:HostsSinkholePath -Raw -ErrorAction Stop
        if ($content -notmatch [regex]::Escape($script:SinkholeBeginMark)) { return $result }
        $result.Active = $true
        if ($content -match '(?ms)' + [regex]::Escape($script:SinkholeBeginMark) + '(.*?)' + [regex]::Escape($script:SinkholeEndMark)) {
            $block = $matches[1]
            if ($block -match 'Last updated:\s*(.+)') { $result.UpdatedAt = $matches[1].Trim() }
            if ($block -match 'Source:\s*(.+)')       { $result.Url = $matches[1].Trim() }
            $result.Entries = @($block -split "`n" | Where-Object { $_ -match '^\s*0\.0\.0\.0\s+\S+' }).Count
        }
        $latest = Get-ChildItem $script:SinkholeDir -Filter 'hosts-backup-*' -ErrorAction SilentlyContinue | Sort-Object LastWriteTime -Descending | Select-Object -First 1
        if ($latest) { $result.Backup = $latest.FullName }
    } catch {}
    return $result
}

function _Backup-HostsFile {
    try {
        $stamp = (Get-Date).ToString('yyyyMMdd-HHmmss')
        $dest  = Join-Path $script:SinkholeDir ("hosts-backup-$stamp")
        Copy-Item -LiteralPath $script:HostsSinkholePath -Destination $dest -Force -ErrorAction Stop
        # Keep only the 10 most-recent backups so the dir doesn't grow forever.
        $old = @(Get-ChildItem $script:SinkholeDir -Filter 'hosts-backup-*' | Sort-Object LastWriteTime -Descending | Select-Object -Skip 10)
        foreach ($f in $old) { try { Remove-Item $f.FullName -Force -ErrorAction SilentlyContinue } catch {} }
        return $dest
    } catch { return $null }
}

function _Write-HostsAtomic {
    # Write the new hosts file atomically: write next to it, then Move-Item to overwrite. Verify
    # the new file has the canonical "127.0.0.1 localhost" entry before committing - protects
    # against catastrophic empty-hosts-file outcomes.
    param([Parameter(Mandatory)] [string]$Content)
    if ($Content -notmatch '127\.0\.0\.1\s+localhost') {
        throw 'New hosts content missing 127.0.0.1 localhost - refusing to write (would break local DNS).'
    }
    $tmp = "$($script:HostsSinkholePath).netjump-tmp"
    Set-Content -LiteralPath $tmp -Value $Content -Encoding ASCII -ErrorAction Stop -Force
    Move-Item -LiteralPath $tmp -Destination $script:HostsSinkholePath -Force -ErrorAction Stop
    # Defender Real-Time Protection may briefly lock hosts after the move; flush the DNS cache so
    # the new blocks take effect immediately.
    try { & ipconfig /flushdns | Out-Null } catch {}
}

function Update-DnsSinkhole {
    # Async fetch + write. Requires admin (hosts file is owned by SYSTEM with restricted ACL).
    if (-not $script:IsAdmin) {
        Add-Event warn 'DNS sinkhole update requires Administrator. Re-launch via Run-NetJump.bat.'
        return
    }
    if ($script:State.SinkholeJob) {
        Add-Event scan 'DNS sinkhole update already in progress.'
        return
    }
    $url = if ($script:State.Settings.DnsSinkholeUrl) { [string]$script:State.Settings.DnsSinkholeUrl } else { $script:SinkholeDefaultUrl }
    Add-Event scan ("DNS sinkhole: fetching blocklist from {0}..." -f $url)
    $job = Start-Job -Name 'NetJump-Sinkhole' -ScriptBlock {
        param($Url)
        try {
            $r = Invoke-WebRequest -Uri $Url -TimeoutSec 60 -UseBasicParsing -ErrorAction Stop
            # Parse hosts-format lines: "0.0.0.0 domain.com" or "127.0.0.1 domain.com".
            # Strip comments, blank lines, and the standard localhost entries that the source
            # files usually include.
            $domains = New-Object System.Collections.Generic.HashSet[string]
            $skip = @('localhost','localhost.localdomain','local','broadcasthost','ip6-localhost','ip6-loopback','ip6-localnet','ip6-mcastprefix','ip6-allnodes','ip6-allrouters','ip6-allhosts')
            foreach ($line in ($r.Content -split "`r?`n")) {
                $l = $line.Trim()
                if (-not $l -or $l.StartsWith('#')) { continue }
                if ($l -match '^(0\.0\.0\.0|127\.0\.0\.1)\s+(\S+)') {
                    $dom = $matches[2].ToLower()
                    if ($skip -contains $dom) { continue }
                    if ($dom -match '^[a-z0-9\.\-]+$' -and $dom.Length -le 253) {
                        [void]$domains.Add($dom)
                    }
                }
            }
            return @{ Ok=$true; Count=$domains.Count; Domains=([string[]]$domains); Url=$Url }
        } catch {
            return @{ Ok=$false; Error="$_" }
        }
    } -ArgumentList $url
    $script:State.SinkholeJob = $job
}

function Apply-DnsSinkhole {
    # Called from Tick when the SinkholeJob finishes. Writes the new managed section.
    param([Parameter(Mandatory)] $JobResult)
    if (-not $JobResult.Ok) {
        Add-Event warn ("DNS sinkhole fetch failed: $($JobResult.Error)")
        return
    }
    if (-not $JobResult.Domains -or $JobResult.Domains.Count -eq 0) {
        Add-Event warn 'DNS sinkhole: blocklist parsed but contained zero usable domains. Aborting write.'
        return
    }
    try {
        $existing = Get-Content -LiteralPath $script:HostsSinkholePath -Raw -ErrorAction Stop
    } catch {
        Add-Event warn ("DNS sinkhole: cannot read hosts file: $($_.Exception.Message)")
        return
    }
    # Strip any prior NetJump-managed section before appending the fresh one.
    $stripped = $existing
    $pattern = '(?ms)' + [regex]::Escape($script:SinkholeBeginMark) + '.*?' + [regex]::Escape($script:SinkholeEndMark) + '\s*'
    $stripped = [regex]::Replace($stripped, $pattern, '')
    if (-not $stripped.EndsWith("`r`n") -and -not $stripped.EndsWith("`n")) { $stripped += "`r`n" }
    # Build new managed section.
    $sb = New-Object System.Text.StringBuilder
    [void]$sb.AppendLine($script:SinkholeBeginMark)
    [void]$sb.AppendLine(("# Last updated: {0}" -f (Get-Date).ToString('yyyy-MM-dd HH:mm:ss')))
    [void]$sb.AppendLine(("# Source: {0}" -f $JobResult.Url))
    [void]$sb.AppendLine(("# Entries: {0}" -f $JobResult.Count))
    foreach ($d in $JobResult.Domains) { [void]$sb.AppendLine("0.0.0.0 $d") }
    [void]$sb.AppendLine($script:SinkholeEndMark)
    $newContent = $stripped + $sb.ToString()
    # Backup first, then atomic write.
    $backup = _Backup-HostsFile
    try {
        _Write-HostsAtomic -Content $newContent
        $backupLeaf = if ($backup) { Split-Path $backup -Leaf } else { 'n/a' }
        Add-Event recovery ("DNS sinkhole applied: {0} domains blocked. Backup: {1}" -f $JobResult.Count, $backupLeaf)
    } catch {
        Add-Event warn ("DNS sinkhole write failed: $($_.Exception.Message). Backup at: $backup")
    }
}

function Clear-DnsSinkhole {
    if (-not $script:IsAdmin) { Add-Event warn 'Clearing DNS sinkhole requires Administrator.'; return }
    try {
        $existing = Get-Content -LiteralPath $script:HostsSinkholePath -Raw -ErrorAction Stop
    } catch { Add-Event warn ("DNS sinkhole clear: cannot read hosts: $($_.Exception.Message)"); return }
    if ($existing -notmatch [regex]::Escape($script:SinkholeBeginMark)) {
        Add-Event info 'DNS sinkhole: no managed section present, nothing to clear.'
        return
    }
    $pattern = '(?ms)' + [regex]::Escape($script:SinkholeBeginMark) + '.*?' + [regex]::Escape($script:SinkholeEndMark) + '\s*'
    $cleaned = [regex]::Replace($existing, $pattern, '')
    $backup = _Backup-HostsFile
    try {
        _Write-HostsAtomic -Content $cleaned
        $backupLeaf = if ($backup) { Split-Path $backup -Leaf } else { 'n/a' }
        Add-Event recovery ("DNS sinkhole cleared. Backup: {0}" -f $backupLeaf)
    } catch { Add-Event warn ("DNS sinkhole clear failed: $($_.Exception.Message)") }
}

function Detect-Beacons {
    # Returns @[{Key, Pid, ProcessName, IP, Port, Period, Jitter, Samples, CV, MADRatio, AutoCorr1, Detection}].
    # Three orthogonal detectors are run; a beacon is flagged when ANY of them triggers.
    #   1. CV-based  (original):   stddev/mean < 0.25  - catches CLOCKWORK beacons.
    #   2. MAD-based (jitter-tol): MAD/median < 0.4 with >=8 samples  - catches BEACONS WITH JITTER
    #      (Cobalt Strike / Sliver style: 30s base interval +/- 20% randomized).
    #   3. AutoCorr1 (consistency): lag-1 autocorrelation of intervals > 0.5 with >=10 samples -
    #      catches beacons where the period is consistent even if individual gaps vary.
    # The Detection field carries which method(s) fired so the user can interpret confidence.
    $hits = New-Object System.Collections.ArrayList
    foreach ($k in $script:BeaconSamples.Keys) {
        $list = $script:BeaconSamples[$k]
        if ($list.Count -lt 5) { continue }
        # Inter-arrival times in seconds.
        $intervals = New-Object System.Collections.Generic.List[double]
        for ($i = 1; $i -lt $list.Count; $i++) { [void]$intervals.Add(([double]($list[$i] - $list[$i-1]).TotalSeconds)) }
        $n = $intervals.Count
        $mean = ($intervals | Measure-Object -Average).Average
        if ($mean -lt 5)    { continue }   # too fast to be a beacon (likely legitimate streaming)
        if ($mean -gt 1800) { continue }   # too slow, won't accumulate enough evidence

        # Detector 1: CV (stddev / mean)
        $variance = 0.0
        foreach ($v in $intervals) { $variance += ($v - $mean) * ($v - $mean) }
        $stddev = [Math]::Sqrt($variance / $n)
        $cv = if ($mean -gt 0) { $stddev / $mean } else { 1 }

        # Detector 2: MAD / median (robust to outliers; catches jittered beacons that defeat CV)
        $sorted = @($intervals | Sort-Object)
        $median = if ($n % 2) { $sorted[[int](($n - 1) / 2)] } else { ($sorted[[int](($n / 2) - 1)] + $sorted[[int]($n / 2)]) / 2.0 }
        $abs = New-Object System.Collections.Generic.List[double]
        foreach ($v in $intervals) { [void]$abs.Add([Math]::Abs($v - $median)) }
        $absSorted = @($abs | Sort-Object)
        $mad = if ($n % 2) { $absSorted[[int](($n - 1) / 2)] } else { ($absSorted[[int](($n / 2) - 1)] + $absSorted[[int]($n / 2)]) / 2.0 }
        $madRatio = if ($median -gt 0) { $mad / $median } else { 1 }

        # Detector 3: lag-1 autocorrelation of the interval series
        $autoCorr1 = 0.0
        if ($n -ge 10) {
            $num = 0.0; $den = 0.0
            for ($i = 0; $i -lt $n; $i++) {
                $d = $intervals[$i] - $mean
                $den += $d * $d
                if ($i -gt 0) { $num += ($intervals[$i] - $mean) * ($intervals[$i-1] - $mean) }
            }
            if ($den -gt 0) { $autoCorr1 = $num / $den }
        }

        $fired = @()
        if ($cv -lt 0.25)                              { $fired += 'CV' }
        if ($n -ge 8  -and $madRatio  -lt 0.4)         { $fired += 'MAD' }
        if ($n -ge 10 -and $autoCorr1 -gt 0.5)         { $fired += 'AutoCorr' }
        if ($fired.Count -eq 0) { continue }

        $parts = $k -split '\|'
        $procName = '?'
        try {
            $p = Get-Process -Id ([int]$parts[0]) -ErrorAction SilentlyContinue
            if ($p) { $procName = $p.ProcessName }
        } catch {}
        [void]$hits.Add([pscustomobject]@{
            Key         = $k
            Pid         = [int]$parts[0]
            ProcessName = $procName
            IP          = $parts[1]
            Port        = [int]$parts[2]
            Period      = [int]$mean
            Jitter      = [int]$stddev
            Samples     = $list.Count
            CV          = [Math]::Round($cv, 3)
            MADRatio    = [Math]::Round($madRatio, 3)
            AutoCorr1   = [Math]::Round($autoCorr1, 3)
            Detection   = ($fired -join '+')
        })
    }
    return $hits
}

# ---------- Tier 14: persistent connection ledger ----------
# Long-term record of every (process, remoteIP, remotePort) tuple seen.
# Persisted to disk so it survives reboots; pruned to last 7 days.
$script:LedgerDir   = Join-Path $PSScriptRoot 'Reports\Ledger'
$script:LedgerFile  = Join-Path $script:LedgerDir 'connections.json'
$script:Ledger      = @{}     # key="proc|ip|port" -> entry hashtable
$script:LedgerLastSave = $null
$script:LedgerDirty = $false
foreach ($d in $script:LedgerDir) { if (-not (Test-Path $d)) { New-Item -ItemType Directory -Path $d -Force | Out-Null } }

function Load-Ledger {
    if (-not (Test-Path $script:LedgerFile)) { return }
    try {
        $arr = Get-Content $script:LedgerFile -Raw | ConvertFrom-Json
        foreach ($e in $arr) {
            $script:Ledger[$e.key] = @{
                proc      = $e.proc
                ip        = $e.ip
                port      = $e.port
                firstSeen = $e.firstSeen
                lastSeen  = $e.lastSeen
                samples   = [int]$e.samples
                label     = $e.label
            }
        }
    } catch {}
}

function Save-Ledger {
    if (-not $script:LedgerDirty) { return }
    try {
        # prune entries with lastSeen older than 7 days
        $cutoff = (Get-Date).AddDays(-7)
        $stale = New-Object System.Collections.Generic.List[string]
        foreach ($k in $script:Ledger.Keys) {
            try {
                if (([datetime]$script:Ledger[$k].lastSeen) -lt $cutoff) { [void]$stale.Add($k) }
            } catch {}
        }
        foreach ($k in $stale) { [void]$script:Ledger.Remove($k) }

        $arr = @($script:Ledger.GetEnumerator() | ForEach-Object {
            $v = $_.Value
            [pscustomobject]@{
                key=$_.Key; proc=$v.proc; ip=$v.ip; port=$v.port
                firstSeen=$v.firstSeen; lastSeen=$v.lastSeen
                samples=$v.samples; label=$v.label
            }
        })
        $arr | ConvertTo-Json -Depth 4 | Set-Content $script:LedgerFile -Encoding UTF8
        $script:LedgerDirty = $false
        $script:LedgerLastSave = Get-Date
    } catch {
        # Tier 51: silent ledger save failure means beacon/connection history is lost permanently
        # on next launch. Save-Ledger runs every ~5min from the heavy tick AND on close - if this
        # fails repeatedly, tons of forensic data evaporates. Rate-limited to once per 10 minutes.
        try {
            if (-not $script:_LedgerSaveErrAt -or ((Get-Date) - $script:_LedgerSaveErrAt).TotalMinutes -gt 10) {
                $script:_LedgerSaveErrAt = Get-Date
                Add-Event warn ("Ledger save failed (beacon/connection history not persisting): {0}" -f $_.Exception.Message)
            }
        } catch {}
    }
}

function Update-Ledger {
    # Called from Sample-Beacons - we already have $script:BeaconSamples updated.
    $now = Get-Date
    $nowStr = $now.ToString('o')
    foreach ($k in $script:BeaconSamples.Keys) {
        # key is pid|ip|port; ledger groups by procName instead so we resolve pid -> name once
        $parts = $k -split '\|'
        if ($parts.Count -ne 3) { continue }
        $procName = '?'
        try {
            $p = Get-Process -Id ([int]$parts[0]) -ErrorAction SilentlyContinue
            if ($p) { $procName = $p.ProcessName }
        } catch {}
        $lkey = "{0}|{1}|{2}" -f $procName, $parts[1], $parts[2]
        if (-not $script:Ledger.ContainsKey($lkey)) {
            $script:Ledger[$lkey] = @{
                proc=$procName; ip=$parts[1]; port=[int]$parts[2]
                firstSeen=$nowStr; lastSeen=$nowStr; samples=1
                label = (Get-IpLabel $parts[1])
            }
        } else {
            $script:Ledger[$lkey].lastSeen = $nowStr
            $script:Ledger[$lkey].samples  = [int]$script:Ledger[$lkey].samples + 1
            if (-not $script:Ledger[$lkey].label) { $script:Ledger[$lkey].label = (Get-IpLabel $parts[1]) }
        }
    }
    $script:LedgerDirty = $true
    # auto-save every 5 min
    if (-not $script:LedgerLastSave -or ($now - $script:LedgerLastSave).TotalSeconds -ge 300) {
        Save-Ledger
    }
}

# ---------- Tier 14: daily process baseline + diff ----------
$script:BaselinesDir = Join-Path $PSScriptRoot 'Reports\Baselines'
if (-not (Test-Path $script:BaselinesDir)) { New-Item -ItemType Directory -Path $script:BaselinesDir -Force | Out-Null }

function Capture-DailyBaseline {
    $today = (Get-Date).ToString('yyyyMMdd')
    $path = Join-Path $script:BaselinesDir "baseline-$today.json"
    if (Test-Path $path) { return $null }   # already captured today
    try {
        $procs = @(Get-Process | Where-Object { $_.Path } | Select-Object @{n='Name'; e={$_.ProcessName}}, Path | Sort-Object Path -Unique)
        $procs | ConvertTo-Json -Depth 3 | Set-Content $path -Encoding UTF8
        # prune baselines older than 30 days
        Get-ChildItem $script:BaselinesDir -Filter 'baseline-*.json' -ErrorAction SilentlyContinue |
            Where-Object { $_.LastWriteTime -lt (Get-Date).AddDays(-30) } |
            Remove-Item -Force -ErrorAction SilentlyContinue
        return $path
    } catch { return $null }
}

function Get-NewSinceBaseline {
    # Collect known (name|path) tuples from last 14 days of baselines
    $known = @{}
    Get-ChildItem $script:BaselinesDir -Filter 'baseline-*.json' -ErrorAction SilentlyContinue |
        Sort-Object LastWriteTime -Descending | Select-Object -First 14 | ForEach-Object {
            try {
                $arr = Get-Content $_.FullName -Raw | ConvertFrom-Json
                foreach ($p in $arr) { $known["{0}|{1}" -f $p.Name, $p.Path] = $true }
            } catch {}
        }
    if ($known.Count -eq 0) { return @() }   # no baselines yet
    $current = @(Get-Process | Where-Object { $_.Path } | Select-Object @{n='Name'; e={$_.ProcessName}}, Path | Sort-Object Path -Unique)
    $new = @()
    foreach ($c in $current) {
        $key = "{0}|{1}" -f $c.Name, $c.Path
        if (-not $known.ContainsKey($key)) {
            $isUserWritable = $c.Path -match '\\AppData\\|\\Users\\Public\\|\\ProgramData\\|\\Temp\\'
            $new += [pscustomobject]@{
                Name = $c.Name
                Path = $c.Path
                UserWritable = $isUserWritable
            }
        }
    }
    return $new
}

# ---------- Tier 14: Sysmon integration ----------
function Get-SysmonStatus {
    foreach ($n in 'Sysmon64','Sysmon') {
        $svc = Get-Service -Name $n -ErrorAction SilentlyContinue
        if ($svc) { return @{ Name=$svc.Name; Status=[string]$svc.Status; Service=$svc } }
    }
    return $null
}

function Get-RecentSysmonEvents {
    param([int]$Minutes = 5, [int]$Max = 50)
    try {
        $since = (Get-Date).AddMinutes(-$Minutes)
        Get-WinEvent -FilterHashtable @{LogName='Microsoft-Windows-Sysmon/Operational'; StartTime=$since} -MaxEvents $Max -ErrorAction SilentlyContinue
    } catch { @() }
}

# ---------- Tier 6: Wi-Fi survey (lightweight) ----------
function Get-WiFiSurvey {
    $wifi = Get-NetAdapter | Where-Object { $_.PhysicalMediaType -match 'Wireless|802\.11' -and $_.Status -eq 'Up' } | Select-Object -First 1
    if (-not $wifi) { return $null }
    $info = @{ Adapter = $wifi.Name; Description = $wifi.InterfaceDescription }
    try {
        $out = & netsh wlan show interfaces 2>&1 | Out-String
        if ($out -match 'SSID\s*:\s*(\S.*)') { $info.SSID = $matches[1].Trim() }
        if ($out -match 'Signal\s*:\s*(\d+)\s*%') { $info.Signal = [int]$matches[1] }
        if ($out -match 'Radio type\s*:\s*(\S.*)') { $info.Radio = $matches[1].Trim() }
        if ($out -match 'Channel\s*:\s*(\d+)') { $info.Channel = [int]$matches[1] }
        if ($out -match 'Receive rate \(Mbps\)\s*:\s*([\d\.]+)') { $info.RxMbps = [double]$matches[1] }
    } catch {}
    return [pscustomobject]$info
}

# ---------- Tier 7: NIC driver versions in store ----------
function Get-NicDriversInStore {
    try {
        $all = Get-WindowsDriver -Online -All -ErrorAction Stop |
               Where-Object { $_.ClassName -eq 'Net' -and $_.OriginalFileName }
        $rows = foreach ($d in $all) {
            $isActive = $false
            try { $isActive = ($d.Version -eq $script:State.Adapter.DriverVersionString) } catch {}
            [pscustomobject]@{
                Active        = if ($isActive) { '*' } else { '' }
                ProviderName  = $d.ProviderName
                Version       = $d.Version
                Date          = if ($d.Date) { $d.Date.ToString('yyyy-MM-dd') } else { '' }
                ClassName     = $d.ClassName
                INF           = (Split-Path $d.OriginalFileName -Leaf)
                FullPath      = $d.OriginalFileName
                Driver        = $d.Driver
            }
        }
        return @($rows | Sort-Object @{Expression='Active'; Descending=$true}, @{Expression='Date'; Descending=$true})
    } catch {
        return @()
    }
}

function Invoke-DriverPicker {
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, 'Driver install requires Administrator. Re-launch via Run-NetJump.bat.', 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    Add-Event scan 'Enumerating NIC drivers in store...'
    $rows = Get-NicDriversInStore
    if ($rows.Count -eq 0) {
        [System.Windows.MessageBox]::Show($window, 'No Net-class drivers found in the driver store (Get-WindowsDriver returned nothing).', 'Empty store', 'OK', 'Information') | Out-Null
        return
    }
    $picked = $rows | Out-GridView -Title 'NetJump - pick a NIC driver to install (* = active). Cancel to abort.' -PassThru
    if (-not $picked) { Add-Event scan 'Driver picker cancelled.'; return }
    if ($picked -is [array]) { $picked = $picked[0] }
    $msg = "Install / re-install:`n`n  $($picked.INF)  v$($picked.Version)  ($($picked.Date))  by $($picked.ProviderName)`n`nCommand:`n  pnputil /add-driver `"$($picked.FullPath)`" /install`n`nThe link will bounce while drivers reload. The HUD will run a 10-minute verify watch after."
    $r = [System.Windows.MessageBox]::Show($window, $msg, 'Confirm driver install', 'YesNo', 'Question')
    if ($r -ne 'Yes') { Add-Event scan 'Driver install cancelled.'; return }
    Add-Event fix "Installing driver: $($picked.INF) v$($picked.Version)"
    try {
        $out = & pnputil /add-driver "$($picked.FullPath)" /install 2>&1 | Out-String
        Add-Event fix "pnputil result: $($out.Trim() -replace "`r?`n",' ' | ForEach-Object { if ($_.Length -gt 200) { $_.Substring(0,200) } else { $_ } })"
    } catch {
        Add-Event warn "Driver install failed: $_"
        [System.Windows.MessageBox]::Show($window, "pnputil failed:`n$_", 'Error', 'OK', 'Error') | Out-Null
        return
    }
    Show-Toast -Title 'NetJump: driver installed' -Message "Installed $($picked.INF) v$($picked.Version). Verifying for 10 min." -Icon Info
    # kick verify mode
    $script:State.VerifyMode     = $true
    $script:State.VerifyEndTime  = (Get-Date).AddMinutes(10)
    $script:State.VerifyBaseline = $script:State.FlapCount
    $controls.VerifyBadge.Visibility = 'Visible'
    $controls.VerifyText.Text = 'verifying driver install... 600s left'
}

# ---------- Tier 7: network reset bundle ----------
function Invoke-NetworkResetBundle {
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, 'Network reset requires Administrator.', 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    $cmds = @(
        @{ Cmd = 'netsh winsock reset';   Why = 'resets Winsock catalog (removes 3rd-party LSPs)' }
        @{ Cmd = 'netsh int ip reset';    Why = 'resets TCP/IP stack to defaults' }
        @{ Cmd = 'ipconfig /release';     Why = 'releases current DHCP lease' }
        @{ Cmd = 'ipconfig /renew';       Why = 'requests a fresh DHCP lease' }
        @{ Cmd = 'ipconfig /flushdns';    Why = 'clears DNS resolver cache' }
    )
    $detail = ($cmds | ForEach-Object { "  * {0,-22} - {1}" -f $_.Cmd, $_.Why }) -join "`n"
    $msg = "This will run the following commands in order:`n`n$detail`n`nA REBOOT is recommended after for the Winsock + IP reset to fully take effect.`n`nYou will lose your current connection briefly. Proceed?"
    $r = [System.Windows.MessageBox]::Show($window, $msg, 'Network reset bundle', 'YesNo', 'Warning')
    if ($r -ne 'Yes') { return }
    Add-Event fix 'Network reset bundle starting...'
    foreach ($c in $cmds) {
        try {
            $out = Invoke-Expression "& $($c.Cmd)" 2>&1 | Out-String
            $first = ($out -split "`r?`n" | Where-Object { $_ -match '\S' } | Select-Object -First 1)
            Add-Event fix ("Ran: {0}  ->  {1}" -f $c.Cmd, ($first -replace '\s+',' '))
        } catch {
            Add-Event warn ("Failed: {0}  ->  {1}" -f $c.Cmd, $_)
        }
    }
    Add-Event recovery 'Network reset complete.'
    Show-Toast -Title 'NetJump: network reset done' -Message 'Reboot recommended for Winsock + IP reset to fully apply.' -Icon Warning
    # kick verify mode
    $script:State.VerifyMode     = $true
    $script:State.VerifyEndTime  = (Get-Date).AddMinutes(10)
    $script:State.VerifyBaseline = $script:State.FlapCount
    $controls.VerifyBadge.Visibility = 'Visible'
    $controls.VerifyText.Text = 'verifying network reset... 600s left'
}

# ---------- Tier 7: IPv6 toggle ----------
function Get-Ipv6Enabled {
    if (-not $script:State.Adapter) { return $null }
    $b = Get-NetAdapterBinding -Name $script:State.Adapter.Name -ComponentID 'ms_tcpip6' -ErrorAction SilentlyContinue
    if (-not $b) { return $null }
    return [bool]$b.Enabled
}

function Update-Ipv6Button {
    # Updates the Remediate menu item (no standalone button since Tier 11 reorg)
    $mi = $controls.MenuIpv6
    if (-not $mi) { return }
    $cur = Get-Ipv6Enabled
    if ($null -eq $cur) {
        $mi.Header = 'Toggle IPv6...  (state unknown)'
        $mi.IsEnabled = $false
        return
    }
    $mi.IsEnabled = $script:IsAdmin
    if ($cur) {
        $mi.Header = 'Toggle IPv6: currently ON  (click to disable)'
    } else {
        $mi.Header = 'Toggle IPv6: currently OFF  (click to enable)'
    }
}

function Invoke-Ipv6Toggle {
    if (-not $script:IsAdmin) {
        [System.Windows.MessageBox]::Show($window, 'IPv6 toggle requires Administrator.', 'Not elevated', 'OK', 'Warning') | Out-Null
        return
    }
    $cur = Get-Ipv6Enabled
    if ($null -eq $cur) { return }
    $verb = if ($cur) { 'DISABLE' } else { 'ENABLE' }
    $r = [System.Windows.MessageBox]::Show($window, "$verb IPv6 (ms_tcpip6) on '$($script:State.Adapter.Name)'?`n`nDisabling IPv6 resolves a surprising number of weird flaps with consumer routers. Fully reversible.", 'Toggle IPv6', 'YesNo', 'Question')
    if ($r -ne 'Yes') { return }
    try {
        if ($cur) {
            Disable-NetAdapterBinding -Name $script:State.Adapter.Name -ComponentID 'ms_tcpip6' -ErrorAction Stop
            Add-Event fix "IPv6 disabled on $($script:State.Adapter.Name)"
        } else {
            Enable-NetAdapterBinding -Name $script:State.Adapter.Name -ComponentID 'ms_tcpip6' -ErrorAction Stop
            Add-Event fix "IPv6 enabled on $($script:State.Adapter.Name)"
        }
    } catch {
        Add-Event warn "IPv6 toggle failed: $_"
        [System.Windows.MessageBox]::Show($window, "Toggle failed:`n$_", 'Error', 'OK', 'Error') | Out-Null
        return
    }
    Update-Ipv6Button
    # quick verify watch
    $script:State.VerifyMode     = $true
    $script:State.VerifyEndTime  = (Get-Date).AddMinutes(10)
    $script:State.VerifyBaseline = $script:State.FlapCount
    $controls.VerifyBadge.Visibility = 'Visible'
    $controls.VerifyText.Text = 'verifying IPv6 toggle... 600s left'
}

# ---------- Tier 8: HTTP status server (runspace + synchronized snapshot) ----------
$script:HttpSnapshot = [hashtable]::Synchronized(@{})
$script:HttpRunspace = $null
$script:HttpPS       = $null
$script:HttpPort     = 0

function Update-HttpSnapshot {
    $a = $script:State.Adapter
    $script:HttpSnapshot['ts']            = (Get-Date).ToString('o')
    $script:HttpSnapshot['host']          = $env:COMPUTERNAME
    $script:HttpSnapshot['adapter']       = if ($a) { @{name=$a.Name; status=[string]$a.Status; linkSpeed=$a.LinkSpeed; description=$a.InterfaceDescription} } else { $null }
    $script:HttpSnapshot['gateway']       = $script:State.Gateway
    $script:HttpSnapshot['flapsSession']  = $script:State.FlapCount
    $script:HttpSnapshot['sessionStart']  = $script:State.SessionStart.ToString('o')
    $script:HttpSnapshot['latencyGwMs']   = if ($script:State.GwHistory.Count -gt 0)  { $script:State.GwHistory[-1] }  else { $null }
    $script:HttpSnapshot['latencyCfMs']   = if ($script:State.CfHistory.Count -gt 0)  { $script:State.CfHistory[-1] }  else { $null }
    $script:HttpSnapshot['rxErrPerSec']   = if ($script:State.RxErrHistory.Count -gt 0) { $script:State.RxErrHistory[-1] } else { 0 }
    $script:HttpSnapshot['retransPerSec'] = if ($script:State.RetransHistory.Count -gt 0) { $script:State.RetransHistory[-1] } else { 0 }
    $script:HttpSnapshot['cpuMaxPct']     = if ($script:State.CpuMaxHistory.Count -gt 0) { $script:State.CpuMaxHistory[-1] } else { 0 }
    # Tier 38: physical RAM use % (last sample) for the HTTP/JSON snapshot consumers.
    $script:HttpSnapshot['memoryPct']     = if ($script:State.MemoryHistory -and $script:State.MemoryHistory.Count -gt 0) { $script:State.MemoryHistory[-1] } else { 0 }
    $script:HttpSnapshot['findings']      = @($script:Findings | Select-Object Level, Category, Message, Fix, MitreId, MitreName)
    $script:HttpSnapshot['causes']        = @($script:Causes | Select-Object Cause, ConfidenceLabel, Confidence, Evidence, Recommendation)
    # Tier 14: ledger - top 50 by samples, last 7d window already pruned
    $script:HttpSnapshot['ledger']        = @($script:Ledger.Values | Sort-Object -Property samples -Descending | Select-Object -First 50)

    # ---------- Prometheus-friendly fields ----------
    # link speed parsed to bits/second (e.g. "1 Gbps" -> 1e9). 0 when unknown.
    $linkBps = 0
    if ($a -and $a.LinkSpeed) {
        $ls = [string]$a.LinkSpeed
        if ($ls -match '^\s*([\d.]+)\s*(Gbps|Mbps|Kbps|bps)') {
            $n = [double]$matches[1]
            switch ($matches[2]) {
                'Gbps' { $linkBps = [long]($n * 1e9) }
                'Mbps' { $linkBps = [long]($n * 1e6) }
                'Kbps' { $linkBps = [long]($n * 1e3) }
                'bps'  { $linkBps = [long]$n }
            }
        }
    }
    $script:HttpSnapshot['linkSpeedBps']  = $linkBps
    $script:HttpSnapshot['adapterUp']     = if ($a -and $a.Status -eq 'Up') { 1 } else { 0 }
    $script:HttpSnapshot['uptimeSec']     = [int]((Get-Date) - $script:State.SessionStart).TotalSeconds

    # Per-severity finding counts (gauge).
    $sev = @{ OK=0; INFO=0; WARN=0; FAIL=0 }
    foreach ($f in @($script:Findings)) {
        $lvl = [string]$f.Level
        if ($sev.ContainsKey($lvl)) { $sev[$lvl]++ }
    }
    $script:HttpSnapshot['findingCounts'] = $sev

    # Threat-intel sizes (v4 + v6).
    $script:HttpSnapshot['intelV4Ranges'] = if ($script:ThreatIntelRanges)    { @($script:ThreatIntelRanges).Count }    else { 0 }
    $script:HttpSnapshot['intelV4Ips']    = if ($script:ThreatIntelHashSet)   { $script:ThreatIntelHashSet.Count }      else { 0 }
    $script:HttpSnapshot['intelV6Ranges'] = if ($script:ThreatIntelRangesV6)  { @($script:ThreatIntelRangesV6).Count }  else { 0 }
    $script:HttpSnapshot['intelV6Ips']    = if ($script:ThreatIntelHashSetV6) { $script:ThreatIntelHashSetV6.Count }    else { 0 }
    $script:HttpSnapshot['vulnDriverCount'] = if ($script:VulnDriverDynamic)  { $script:VulnDriverDynamic.Count }       else { 0 }

    # Cache ages (seconds). -1 if cache file missing.
    $script:HttpSnapshot['intelCacheAgeSec']    = -1
    $script:HttpSnapshot['vulnCacheAgeSec']     = -1
    try { if (Test-Path $script:ThreatIntelCache) { $script:HttpSnapshot['intelCacheAgeSec'] = [int]((Get-Date) - (Get-Item $script:ThreatIntelCache).LastWriteTime).TotalSeconds } } catch {}
    try { if (Test-Path $script:VulnDriverCache)  { $script:HttpSnapshot['vulnCacheAgeSec']  = [int]((Get-Date) - (Get-Item $script:VulnDriverCache).LastWriteTime).TotalSeconds } } catch {}

    # Live tile counters (ledger + beacons + events for SOC-style alerting).
    $script:HttpSnapshot['ledgerEntries'] = if ($script:Ledger)        { $script:Ledger.Count }        else { 0 }
    $script:HttpSnapshot['beaconCount']   = if ($script:BeaconAlerted) { $script:BeaconAlerted.Count } else { 0 }
}

function Start-HttpServer {
    $port = if ($script:State.Settings -and $script:State.Settings.HttpPort) { [int]$script:State.Settings.HttpPort } else { 8765 }
    $script:HttpPort = $port
    $rs = [runspacefactory]::CreateRunspace()
    $rs.Open()
    $rs.SessionStateProxy.SetVariable('snap', $script:HttpSnapshot)
    $rs.SessionStateProxy.SetVariable('port', $port)
    $ps = [PowerShell]::Create()
    $ps.Runspace = $rs
    [void]$ps.AddScript({
        $listener = New-Object System.Net.HttpListener
        $listener.Prefixes.Add("http://localhost:$port/")
        try { $listener.Start() } catch { return @{error="$_"} }
        while ($listener.IsListening) {
            try {
                $ctx = $listener.GetContext()
            } catch { break }
            try {
                $req = $ctx.Request
                $res = $ctx.Response
                $body = ''
                $contentType = 'application/json'
                $code = 200
                switch -Wildcard ($req.Url.AbsolutePath) {
                    '/status.json' { $body = $snap | ConvertTo-Json -Depth 5 }
                    '/health' {
                        $up = ($snap['adapter'] -and $snap['adapter'].status -eq 'Up')
                        $body = if ($up) { 'OK' } else { 'DOWN' }
                        $code = if ($up) { 200 } else { 503 }
                        $contentType = 'text/plain'
                    }
                    '/findings.json' { $body = ($snap['findings'] | ConvertTo-Json -Depth 4) }
                    '/causes.json'   { $body = ($snap['causes']   | ConvertTo-Json -Depth 4) }
                    '/ledger.json'   { $body = ($snap['ledger']   | ConvertTo-Json -Depth 4) }
                    '/metrics' {
                        # Prometheus exposition format (text/plain; version=0.0.4). Standard scrape
                        # path. Update-HttpSnapshot keeps the source fields fresh on every tick.
                        $sb = New-Object System.Text.StringBuilder
                        $host_ = if ($snap['host']) { [string]$snap['host'] } else { 'unknown' }
                        $hostEsc = $host_ -replace '\\','\\\\' -replace '"','\"'
                        $emit = {
                            param($name, $help, $type, $value, $labels = '')
                            [void]$sb.AppendLine("# HELP $name $help")
                            [void]$sb.AppendLine("# TYPE $name $type")
                            $lbl = "host=`"$hostEsc`""
                            if ($labels) { $lbl = $lbl + ',' + $labels }
                            [void]$sb.AppendLine("$name{$lbl} $value")
                        }
                        # Link state
                        & $emit 'netjump_adapter_up' 'Adapter operational state (1=Up, 0=other)' 'gauge' ([int]$snap['adapterUp'])
                        & $emit 'netjump_link_speed_bits_per_second' 'Link speed in bits per second (0 if unknown)' 'gauge' ([long]$snap['linkSpeedBps'])
                        & $emit 'netjump_flap_count' 'Link-state flaps observed this session' 'counter' ([int]$snap['flapsSession'])
                        & $emit 'netjump_session_uptime_seconds' 'Seconds since the HUD session started' 'gauge' ([int]$snap['uptimeSec'])
                        # Latency
                        $gw = $snap['latencyGwMs']; $cf = $snap['latencyCfMs']
                        if ($null -ne $gw) { & $emit 'netjump_ping_rtt_milliseconds' 'Ping RTT (ms)' 'gauge' ([double]$gw) 'target="gateway"' }
                        if ($null -ne $cf) { & $emit 'netjump_ping_rtt_milliseconds' 'Ping RTT (ms)' 'gauge' ([double]$cf) 'target="cloudflare"' }
                        # Counters / sparklines
                        & $emit 'netjump_rx_errors_per_second' 'NIC RX error rate (last sample)' 'gauge' ([double]$snap['rxErrPerSec'])
                        & $emit 'netjump_tcp_retransmits_per_second' 'TCP retransmit rate (last sample)' 'gauge' ([double]$snap['retransPerSec'])
                        & $emit 'netjump_cpu_max_core_percent' 'Highest single-core CPU usage (%)' 'gauge' ([double]$snap['cpuMaxPct'])
                        & $emit 'netjump_memory_percent' 'Physical memory usage (%)' 'gauge' ([double]$snap['memoryPct'])
                        # Findings per severity
                        $fc = if ($snap.ContainsKey('findingCounts')) { $snap['findingCounts'] } else { @{} }
                        foreach ($lvl in @('OK','INFO','WARN','FAIL')) {
                            $n = if ($fc.ContainsKey($lvl)) { [int]$fc[$lvl] } else { 0 }
                            & $emit 'netjump_findings' 'Last-scan finding count per severity' 'gauge' $n "severity=`"$lvl`""
                        }
                        # Threat intel + vuln driver
                        & $emit 'netjump_threat_intel_ranges' 'Threat-intel CIDR ranges loaded' 'gauge' ([int]$snap['intelV4Ranges']) 'family="v4"'
                        & $emit 'netjump_threat_intel_ranges' 'Threat-intel CIDR ranges loaded' 'gauge' ([int]$snap['intelV6Ranges']) 'family="v6"'
                        & $emit 'netjump_threat_intel_ips' 'Threat-intel individual IPs loaded' 'gauge' ([int]$snap['intelV4Ips']) 'family="v4"'
                        & $emit 'netjump_threat_intel_ips' 'Threat-intel individual IPs loaded' 'gauge' ([int]$snap['intelV6Ips']) 'family="v6"'
                        & $emit 'netjump_threat_intel_cache_age_seconds' 'Seconds since threat-intel cache was last written (-1 if no cache)' 'gauge' ([int]$snap['intelCacheAgeSec'])
                        & $emit 'netjump_vulnerable_driver_entries' 'Vulnerable-driver list size (loldrivers.io + curated)' 'gauge' ([int]$snap['vulnDriverCount'])
                        & $emit 'netjump_vulnerable_driver_cache_age_seconds' 'Seconds since vuln-driver cache was last written' 'gauge' ([int]$snap['vulnCacheAgeSec'])
                        # Ledger + beacons
                        & $emit 'netjump_ledger_entries' 'Connection-ledger entry count' 'gauge' ([int]$snap['ledgerEntries'])
                        & $emit 'netjump_beacon_alerts' 'Beacons detected and alerted this session' 'gauge' ([int]$snap['beaconCount'])
                        $body = $sb.ToString()
                        $contentType = 'text/plain; version=0.0.4; charset=utf-8'
                    }
                    '/' {
                        $body = @'
<!doctype html><html lang="en"><head>
<meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover">
<meta name="theme-color" content="#0f1420">
<title>NetJump HUD</title>
<style>
:root{--bg:#0f1420;--card:#1a2030;--bd:#2a3142;--fg:#d7dde6;--muted:#8b95a8;--ok:#3fb950;--warn:#d29922;--fail:#f85149;--info:#58a6ff;--accent:#bf6dff}
*{box-sizing:border-box}
body{font:14px/1.45 -apple-system,Segoe UI,system-ui,sans-serif;background:var(--bg);color:var(--fg);margin:0;padding:14px;padding-bottom:max(14px,env(safe-area-inset-bottom));max-width:760px;margin:auto}
.card{background:var(--card);border:1px solid var(--bd);border-radius:14px;padding:16px;margin:0 0 12px 0}
h1{margin:0 0 4px 0;font-size:22px}
.sub{color:var(--muted);font-size:12px}
.row{display:flex;flex-wrap:wrap;gap:12px}
.cell{flex:1 1 30%;min-width:120px}
.l{color:var(--muted);font-size:10px;letter-spacing:.5px;text-transform:uppercase;margin-bottom:2px}
.v{font-size:20px;font-weight:600}
.dot{display:inline-block;width:14px;height:14px;border-radius:50%;vertical-align:middle;margin-right:8px}
.up{background:var(--ok);box-shadow:0 0 0 4px rgba(63,185,80,.18)}
.dn{background:var(--fail);box-shadow:0 0 0 4px rgba(248,81,73,.2)}
.un{background:var(--warn);box-shadow:0 0 0 4px rgba(210,153,34,.18)}
.find,.cause{padding:10px 12px;border:1px solid var(--bd);border-radius:8px;margin:0 0 6px 0;background:#0f1420}
.chip{display:inline-block;padding:1px 6px;border-radius:4px;font-size:10px;font-weight:700;color:#fff;margin-right:8px}
.OK{background:var(--ok)}.INFO{background:var(--info)}.WARN{background:var(--warn)}.FAIL{background:var(--fail)}
.cat{color:var(--muted);font-size:11px;margin-right:8px}
.mitre{display:inline-block;background:#3a1f5c;border:1px solid var(--accent);color:var(--accent);font-size:9px;font-weight:600;padding:0 4px;border-radius:3px;margin-right:6px}
.bar{display:flex;align-items:center;justify-content:space-between;padding:6px 10px;border-radius:7px;background:#0f1420;border:1px solid var(--bd)}
.pct{font-weight:700}
.ago{color:var(--muted);font-size:10px;margin-top:6px}
.foot{color:var(--muted);font-size:10px;text-align:center;margin-top:14px}
a{color:var(--info)}
</style></head><body>
<div class="card">
  <h1><span id="dot" class="dot un"></span><span id="adapter">loading...</span></h1>
  <div class="sub" id="desc"></div>
  <div class="row" style="margin-top:12px">
    <div class="cell"><div class="l">Status</div><div class="v" id="status">--</div></div>
    <div class="cell"><div class="l">Speed</div><div class="v" id="speed">--</div></div>
    <div class="cell"><div class="l">Flaps</div><div class="v" id="flaps">--</div></div>
  </div>
  <div class="row" style="margin-top:12px">
    <div class="cell"><div class="l">Gateway</div><div class="v" id="gwms">--</div></div>
    <div class="cell"><div class="l">Cloudflare</div><div class="v" id="cfms">--</div></div>
    <div class="cell"><div class="l">Max core CPU</div><div class="v" id="cpu">--</div></div>
  </div>
  <div class="row" style="margin-top:12px">
    <div class="cell"><div class="l">RX errors/s</div><div class="v" id="rxerr">0</div></div>
    <div class="cell"><div class="l">TCP retrans/s</div><div class="v" id="retrans">0</div></div>
    <div class="cell"><div class="l">Host</div><div class="v" id="host" style="font-size:13px">--</div></div>
  </div>
  <div class="ago" id="updated"></div>
</div>

<div class="card">
