  <div id="causes" style="margin-top:8px"></div>
</div>

<div class="card">
  <div class="l">Findings (top 10)</div>
  <div id="findings" style="margin-top:8px"></div>
</div>

<div class="foot">NetJump HUD - <a href="/status.json">status.json</a> - <a href="/findings.json">findings.json</a> - <a href="/causes.json">causes.json</a> - <a href="/health">health</a> - <a href="/metrics">metrics</a></div>

<script>
const fmt = ms => (ms===null||ms===undefined) ? 'LOST' : (ms+'ms');
const txt = (id,v) => { const e=document.getElementById(id); if (e) e.textContent = (v===null||v===undefined||v==='')?'--':v; };
async function refresh(){
  try {
    const r = await fetch('/status.json',{cache:'no-store'});
    if (!r.ok) return;
    const s = await r.json();
    const a = s.adapter || {};
    txt('adapter', a.name || 'no adapter');
    txt('desc', a.description || '');
    txt('status', (a.status||'--').toUpperCase());
    txt('speed', a.linkSpeed || '--');
    txt('flaps', s.flapsSession);
    txt('gwms', fmt(s.latencyGwMs));
    txt('cfms', fmt(s.latencyCfMs));
    txt('cpu', s.cpuMaxPct ? Math.round(s.cpuMaxPct)+'%' : '0%');
    txt('rxerr', s.rxErrPerSec ? Math.round(s.rxErrPerSec) : 0);
    txt('retrans', s.retransPerSec ? Math.round(s.retransPerSec*10)/10 : 0);
    txt('host', s.host);
    const dot = document.getElementById('dot');
    if (a.status === 'Up') dot.className = 'dot up';
    else if (a.status === 'Disconnected' || a.status === 'Down') dot.className = 'dot dn';
    else dot.className = 'dot un';
    document.getElementById('updated').textContent = 'updated ' + new Date().toLocaleTimeString();

    const c = document.getElementById('causes');
    c.innerHTML = '';
    (s.causes||[]).forEach(x => {
      const div = document.createElement('div'); div.className='cause';
      div.innerHTML = '<div class="bar"><span>'+escapeHtml(x.Cause||'')+'</span><span class="pct">'+escapeHtml(x.ConfidenceLabel||'')+'</span></div>'+
        (x.Evidence ? '<div class="sub" style="margin-top:6px">'+escapeHtml(x.Evidence)+'</div>' : '')+
        (x.Recommendation ? '<div style="color:#7ee787;font-size:12px;margin-top:4px">'+escapeHtml(x.Recommendation)+'</div>' : '');
      c.appendChild(div);
    });
    if (!c.children.length) c.innerHTML = '<div class="sub">no actionable causes ranked yet</div>';

    const f = document.getElementById('findings');
    f.innerHTML = '';
    (s.findings||[]).filter(x => x.Level !== 'OK').slice(0,10).forEach(x => {
      const div = document.createElement('div'); div.className='find';
      div.innerHTML = '<span class="chip '+x.Level+'">'+x.Level+'</span>'+
        '<span class="cat">'+escapeHtml(x.Category||'')+'</span>'+
        (x.MitreId ? '<span class="mitre">'+escapeHtml(x.MitreId)+'</span>' : '')+
        '<span>'+escapeHtml(x.Message||'')+'</span>';
      f.appendChild(div);
    });
    if (!f.children.length) f.innerHTML = '<div class="sub">all clear</div>';
  } catch(e){}
}
function escapeHtml(s){return String(s).replace(/[&<>"']/g, c=>({"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]))}
refresh(); setInterval(refresh, 5000);
</script>
</body></html>
