# --- menu open helper + open-on-click bindings ---
function Open-DropMenu($btn) {
    $cm = $btn.ContextMenu
    if (-not $cm) { return }
    $cm.PlacementTarget = $btn
    $cm.Placement = [System.Windows.Controls.Primitives.PlacementMode]::Bottom
    $cm.IsOpen = $true
}

# ---------- Tab pop-out: detach a tab into its own floating Window ----------
$script:PoppedOutTabs = @{}    # tab header (string) -> Window

function PopOut-Tab {
    param($TabItem)
    if (-not $TabItem) { return }
    $name = [string]$TabItem.Header
    if ($script:PoppedOutTabs.ContainsKey($name)) {
        try { $script:PoppedOutTabs[$name].Activate() } catch {}
        return
    }
    $content = $TabItem.Content
    if (-not $content) { return }
    # detach content from the TabItem (must be done before re-parenting)
    $TabItem.Content = $null
    $TabItem.Visibility = 'Collapsed'

    $w = New-Object System.Windows.Window
    $w.Title = "NetJump - $name"
    $w.Width  = 980
    $w.Height = 720
    $w.WindowStartupLocation = 'Manual'
    # offset from main window so multiple pop-outs cascade
    try {
        $idx = $script:PoppedOutTabs.Count
        $w.Left = [Math]::Max(40, $window.Left + 60 + ($idx * 32))
        $w.Top  = [Math]::Max(40, $window.Top  + 60 + ($idx * 32))
    } catch {}
    $w.Background = $window.Resources['BrushWindowBg']
    $w.Foreground = $window.Resources['BrushFgPrimary']
    $w.FontFamily = 'Segoe UI'
    Apply-ThemeToChild $w

    $grid = New-Object System.Windows.Controls.Grid
    $r1 = New-Object System.Windows.Controls.RowDefinition; $r1.Height = 'Auto'
    $r2 = New-Object System.Windows.Controls.RowDefinition; $r2.Height = New-Object System.Windows.GridLength 1, 'Star'
    [void]$grid.RowDefinitions.Add($r1)
    [void]$grid.RowDefinitions.Add($r2)

    # header bar with title + Dock back
    $headerBar = New-Object System.Windows.Controls.Border
    $headerBar.Background  = $window.Resources['BrushDeepBg']
    $headerBar.BorderBrush = $window.Resources['BrushBorder']
    $headerBar.BorderThickness = '0,0,0,1'
    $headerBar.Padding = '12,8'
    [System.Windows.Controls.Grid]::SetRow($headerBar, 0)
    $hgrid = New-Object System.Windows.Controls.Grid
    $hc1 = New-Object System.Windows.Controls.ColumnDefinition; $hc1.Width = New-Object System.Windows.GridLength 1, 'Star'
    $hc2 = New-Object System.Windows.Controls.ColumnDefinition; $hc2.Width = 'Auto'
    [void]$hgrid.ColumnDefinitions.Add($hc1)
    [void]$hgrid.ColumnDefinitions.Add($hc2)
    $titleBlk = New-Object System.Windows.Controls.TextBlock
    $titleBlk.Text = "$name (popped out)"
    $titleBlk.FontSize = 13
    $titleBlk.FontWeight = 'Bold'
    $titleBlk.Foreground = (B '#58a6ff')
    $titleBlk.VerticalAlignment = 'Center'
    [System.Windows.Controls.Grid]::SetColumn($titleBlk, 0)
    [void]$hgrid.Children.Add($titleBlk)
    $dockBtn = New-Object System.Windows.Controls.Button
    $dockBtn.Content = '⤴ Dock back into HUD'
    $dockBtn.Padding = '10,4'
    $dockBtn.FontSize = 11
    [System.Windows.Controls.Grid]::SetColumn($dockBtn, 1)
    [void]$hgrid.Children.Add($dockBtn)
    $headerBar.Child = $hgrid
    [void]$grid.Children.Add($headerBar)

    # content host
    $hostBorder = New-Object System.Windows.Controls.ContentControl
    $hostBorder.Content = $content
    [System.Windows.Controls.Grid]::SetRow($hostBorder, 1)
    [void]$grid.Children.Add($hostBorder)

    $w.Content = $grid

    $dockBack = {
        try { $hostBorder.Content = $null } catch {}
        try { $TabItem.Content = $content } catch {}
        try { $TabItem.Visibility = 'Visible' } catch {}
        try { [void]$script:PoppedOutTabs.Remove($name) } catch {}
    }.GetNewClosure()
    $dockBtn.Add_Click({ $w.Close() }.GetNewClosure())
    $w.Add_Closed({ & $dockBack }.GetNewClosure())

    $script:PoppedOutTabs[$name] = $w
    $w.Show()
    Add-Event info ("Popped out tab '{0}' into a floating window." -f $name)
}

$controls.PopOutBtn.Add_Click({
    $sel = $controls.LeftTabs.SelectedItem
    if (-not $sel) { return }
    PopOut-Tab -TabItem $sel
    # auto-select the next visible tab so the main window doesn't show a blank pane
    foreach ($it in $controls.LeftTabs.Items) {
        if ($it.Visibility -ne 'Collapsed') { $controls.LeftTabs.SelectedItem = $it; break }
    }
}.GetNewClosure())
